def _build_host_sparse_direct_factor_from_matvec(
    *,
    matvec: Callable[[jnp.ndarray], jnp.ndarray],
    n: int,
    dtype: jnp.dtype,
    factor_dtype: np.dtype,
    pattern=None,
    emit: Callable[[int, str], None] | None = None,
    default_diag_pivot_thresh: float = 1.0,
    default_permc_spec: str = "COLAMD",
):
    factor_dtype_np = np.dtype(factor_dtype)
    block_cols_env = os.environ.get("SFINCS_JAX_EXPLICIT_SPARSE_BLOCK_COLS", "").strip()
    dense_max_env = os.environ.get("SFINCS_JAX_EXPLICIT_SPARSE_DENSE_MAX_MB", "").strip()
    csr_max_env = os.environ.get("SFINCS_JAX_EXPLICIT_SPARSE_CSR_MAX_MB", "").strip()
    drop_tol_env = os.environ.get("SFINCS_JAX_EXPLICIT_SPARSE_DROP_TOL", "").strip()
    try:
        block_cols = int(block_cols_env) if block_cols_env else 32
    except ValueError:
        block_cols = 32
    try:
        dense_max_mb = float(dense_max_env) if dense_max_env else 128.0
    except ValueError:
        dense_max_mb = 128.0
    try:
        csr_max_mb = float(csr_max_env) if csr_max_env else 512.0
    except ValueError:
        csr_max_mb = 512.0
    try:
        drop_tol = float(drop_tol_env) if drop_tol_env else 0.0
    except ValueError:
        drop_tol = 0.0
    factor_kind_env = os.environ.get("SFINCS_JAX_EXPLICIT_SPARSE_FACTOR_KIND", "").strip().lower()
    factor_kind = "ilu" if factor_kind_env in {"ilu", "spilu"} else "lu"
    ilu_fill_env = os.environ.get("SFINCS_JAX_EXPLICIT_SPARSE_ILU_FILL_FACTOR", "").strip()
    ilu_drop_env = os.environ.get("SFINCS_JAX_EXPLICIT_SPARSE_ILU_DROP_TOL", "").strip()
    default_permc_spec_use = str(default_permc_spec).strip().upper()
    if default_permc_spec_use not in {"NATURAL", "MMD_ATA", "MMD_AT_PLUS_A", "COLAMD"}:
        default_permc_spec_use = "COLAMD"
    permc_env = os.environ.get("SFINCS_JAX_EXPLICIT_SPARSE_PERMC_SPEC", "").strip().upper()
    pivot_env = os.environ.get("SFINCS_JAX_EXPLICIT_SPARSE_DIAG_PIVOT_THRESH", "").strip()
    try:
        ilu_fill_factor = float(ilu_fill_env) if ilu_fill_env else 10.0
    except ValueError:
        ilu_fill_factor = 10.0
    try:
        ilu_drop_tol = float(ilu_drop_env) if ilu_drop_env else 1.0e-4
    except ValueError:
        ilu_drop_tol = 1.0e-4
    if permc_env not in {"NATURAL", "MMD_ATA", "MMD_AT_PLUS_A", "COLAMD"}:
        permc_env = default_permc_spec_use
    try:
        diag_pivot_thresh = float(pivot_env) if pivot_env else float(default_diag_pivot_thresh)
    except ValueError:
        diag_pivot_thresh = float(default_diag_pivot_thresh)

    def _matvec_np(x_np: np.ndarray) -> np.ndarray:
        return np.asarray(matvec(jnp.asarray(x_np, dtype=dtype)), dtype=np.float64)

    def _matmat_np(cols_np: np.ndarray) -> np.ndarray:
        cols = jnp.asarray(cols_np, dtype=dtype)
        out = jax.vmap(matvec, in_axes=1, out_axes=1)(cols)
        return np.asarray(out, dtype=np.float64)

    if pattern is None:
        operator_bundle = build_operator_from_matvec(
            _matvec_np,
            n=int(n),
            dtype=factor_dtype_np,
            backend=jax.default_backend(),
            block_cols=int(block_cols),
            dense_max_mb=float(dense_max_mb),
            csr_max_mb=float(csr_max_mb),
            prefer_sparse_on_gpu=True,
            drop_tol=float(drop_tol),
            matmat=_matmat_np,
            allow_operator_only=False,
        )
    else:
        operator_bundle = build_operator_from_pattern(
            _matvec_np,
            pattern=pattern,
            dtype=factor_dtype_np,
            backend=jax.default_backend(),
            csr_max_mb=float(csr_max_mb),
            drop_tol=float(drop_tol),
            allow_operator_only=False,
        )
    if emit is not None:
        emit(
            1,
            "explicit_sparse: "
            f"storage={operator_bundle.metadata.storage_kind} "
            f"reason={operator_bundle.metadata.reason} factor_kind={factor_kind} "
            f"factor_dtype={factor_dtype_np.name} "
            f"permc={permc_env} diag_pivot={float(diag_pivot_thresh):.3g}",
        )
    factor_bundle = factorize_host_sparse_operator(
        operator_bundle,
        kind=factor_kind,
        fill_factor=float(ilu_fill_factor),
        drop_tol=float(ilu_drop_tol),
        permc_spec=permc_env,
        diag_pivot_thresh=float(diag_pivot_thresh),
    )
    return operator_bundle, factor_bundle


def _rhsmode1_explicit_sparse_pattern_probe_enabled() -> bool:
    env = os.environ.get("SFINCS_JAX_RHSMODE1_EXPLICIT_SPARSE_PATTERN", "").strip().lower()
    return env in {"1", "true", "yes", "on", "pattern"}


def _rhsmode1_sparse_pc_default_permc_spec(
    *,
    constrained_pas_pc: bool,
    tokamak_pas_er_pc: bool,
    n_species: int,
) -> str:
    """Return the measured SuperLU column-ordering default for sparse-PC RHSMode=1.

    Constrained PAS systems usually benefit from ``MMD_ATA``. The measured
    exception kept as a default is the tokamak PAS+Er full-trajectory window,
    where ``MMD_AT_PLUS_A`` lowers fill and runtime on both CPU and one-GPU
    validation runs.
    """
    return _solver_path_policy.rhsmode1_sparse_pc_default_permc_spec(
        constrained_pas_pc=constrained_pas_pc,
        tokamak_pas_er_pc=tokamak_pas_er_pc,
        n_species=n_species,
    )


def _rhsmode1_sparse_pc_default_restart(
    *,
    requested_restart: int,
    restart_env_value: str,
    tokamak_pas_er_pc: bool,
    n_species: int,
) -> int:
    """Return the sparse-PC GMRES restart after scoped production caps.

    The one-species tokamak PAS+Er production row is memory dominated on GPUs.
    A restart cap of 40 preserved output parity in CPU/GPU sweeps while lowering
    GPU resident memory and slightly reducing time-to-solution. Keep all other
    sparse-PC rows on their requested restart, and always respect an explicit
    user environment override.
    """
    return _solver_path_policy.rhsmode1_sparse_pc_default_restart(
        requested_restart=requested_restart,
        restart_env_value=restart_env_value,
        tokamak_pas_er_pc=tokamak_pas_er_pc,
        n_species=n_species,
    )


def _maybe_rhsmode1_full_sparse_pattern(op: V3FullSystemOperator, emit: Callable[[int, str], None] | None = None):
    if not _rhsmode1_explicit_sparse_pattern_probe_enabled():
        return None
    pattern = v3_full_system_conservative_sparsity_pattern(op)
    if emit is not None:
        summary = summarize_v3_sparse_pattern(op, pattern)
        emit(
            1,
            "explicit_sparse_pattern: "
            f"shape={summary.shape} nnz={summary.nnz} "
            f"avg_row_nnz={summary.avg_row_nnz:.3g} max_row_nnz={summary.max_row_nnz}",
        )
    return pattern


