def _rhsmode1_sparse_cache_key(
    op: V3FullSystemOperator,
    *,
    kind: str,
    active_size: int,
    use_active_dof_mode: bool,
    use_pas_projection: bool,
    drop_tol: float,
    drop_rel: float,
    ilu_drop_tol: float,
    fill_factor: float,
) -> tuple[object, ...]:
    return (
        *_rhsmode1_precond_cache_key(op, kind),
        int(active_size),
        int(bool(use_active_dof_mode)),
        int(bool(use_pas_projection)),
        float(drop_tol),
        float(drop_rel),
        float(ilu_drop_tol),
        float(fill_factor),
    )


def _build_sparse_ilu_from_matvec(
    *,
    matvec: Callable[[jnp.ndarray], jnp.ndarray],
    n: int,
    dtype: jnp.dtype,
    cache_key: tuple[object, ...],
    factor_dtype: np.dtype | None = None,
    drop_tol: float,
    drop_rel: float,
    ilu_drop_tol: float,
    fill_factor: float,
    build_dense_factors: bool,
    build_jax_factors: bool,
    build_ilu: bool,
    store_dense: bool,
    factorization: str = "ilu",
    row_nnz_cap: int | None = None,
    emit: Callable[[int, str], None] | None = None,
) -> tuple[object, object, object | None, np.ndarray | None, np.ndarray | None, np.ndarray | None, bool]:
    cached = _RHSMODE1_SPARSE_ILU_CACHE.get(cache_key)
    if cached is not None:
        if build_ilu and cached.ilu is not None:
            need_dense = bool(build_dense_factors) and (cached.l_dense is None or cached.u_dense is None)
            need_jax = bool(build_jax_factors) and (
                cached.perm_r is None
                or cached.inv_perm_c is None
                or cached.lower_idx is None
                or cached.upper_idx is None
            )
            if need_dense or need_jax:
                ilu = cached.ilu
                assert ilu is not None
                l_dense = cached.l_dense
                u_dense = cached.u_dense
                l_unit_diag = cached.l_unit_diag
                perm_r_jnp = cached.perm_r
                inv_perm_c_jnp = cached.inv_perm_c
                lower_idx_jnp = cached.lower_idx
                lower_val_jnp = cached.lower_val
                lower_diag_jnp = cached.lower_diag
                upper_idx_jnp = cached.upper_idx
                upper_val_jnp = cached.upper_val
                upper_diag_jnp = cached.upper_diag

                if need_dense:
                    l_dense = np.asarray(ilu.L.todense(), dtype=np.float64)
                    u_dense = np.asarray(ilu.U.todense(), dtype=np.float64)
                    diag_l = np.diag(l_dense)
                    l_unit_diag = bool(np.allclose(diag_l, 1.0))

                if need_jax:
                    perm_r = np.asarray(ilu.perm_r, dtype=np.int32, copy=True)
                    perm_c = np.asarray(ilu.perm_c, dtype=np.int32, copy=True)
                    inv_perm_c = np.argsort(perm_c).astype(np.int32, copy=False)
                    l_csr = ilu.L.tocsr()
                    u_csr = ilu.U.tocsr()

                    if row_nnz_cap is None:
                        row_nnz_cap_env = os.environ.get("SFINCS_JAX_RHSMODE1_SPARSE_ILU_ROW_NNZ_MAX", "").strip()
                        try:
                            # Cap the padded-row width to keep JAX triangular-solve preconditioner
                            # application cheap. SuperLU ILU factors can be quite dense in a few
                            # rows, so without a cap the padded representation can become
                            # expensive (and can dominate runtime).
                            row_nnz_cap_use = int(row_nnz_cap_env) if row_nnz_cap_env else 256
                        except ValueError:
                            row_nnz_cap_use = 256
                    else:
                        row_nnz_cap_use = int(row_nnz_cap)
                    row_nnz_cap_use = max(0, int(row_nnz_cap_use))

                    lower_diag = np.asarray(l_csr.diagonal(), dtype=np.float64)
                    lower_diag = np.where(lower_diag != 0.0, lower_diag, 1.0)
                    upper_diag = np.asarray(u_csr.diagonal(), dtype=np.float64)
                    upper_diag = np.where(np.isfinite(upper_diag) & (upper_diag != 0.0), upper_diag, 1.0)

                    # Strict lower.
                    lower_cols: list[np.ndarray] = []
                    lower_vals: list[np.ndarray] = []
                    max_lower = 0
                    for i in range(int(n)):
                        rs = int(l_csr.indptr[i])
                        re = int(l_csr.indptr[i + 1])
                        cols = l_csr.indices[rs:re]
                        vals = l_csr.data[rs:re]
                        mask = cols < i
                        cols = cols[mask].astype(np.int32, copy=False)
                        vals = vals[mask].astype(np.float64, copy=False)
                        if row_nnz_cap_use > 0 and int(cols.size) > row_nnz_cap_use:
                            sel = np.argpartition(np.abs(vals), -row_nnz_cap_use)[-row_nnz_cap_use:]
                            cols = cols[sel]
                            vals = vals[sel]
                        if cols.size:
                            order = np.argsort(cols)
                            cols = cols[order]
                            vals = vals[order]
                        lower_cols.append(cols)
                        lower_vals.append(vals)
                        max_lower = max(max_lower, int(cols.size))
                    lower_idx = -np.ones((int(n), max_lower), dtype=np.int32)
                    lower_val = np.zeros((int(n), max_lower), dtype=np.float64)
                    for i in range(int(n)):
                        k = int(lower_cols[i].size)
                        if k:
                            lower_idx[i, :k] = lower_cols[i]
                            lower_val[i, :k] = lower_vals[i]

                    # Strict upper.
                    upper_cols: list[np.ndarray] = []
                    upper_vals: list[np.ndarray] = []
                    max_upper = 0
                    for i in range(int(n)):
                        rs = int(u_csr.indptr[i])
                        re = int(u_csr.indptr[i + 1])
                        cols = u_csr.indices[rs:re]
                        vals = u_csr.data[rs:re]
                        mask = cols > i
                        cols_u = cols[mask].astype(np.int32, copy=False)
                        vals_u = vals[mask].astype(np.float64, copy=False)
                        if row_nnz_cap_use > 0 and int(cols_u.size) > row_nnz_cap_use:
                            sel = np.argpartition(np.abs(vals_u), -row_nnz_cap_use)[-row_nnz_cap_use:]
                            cols_u = cols_u[sel]
                            vals_u = vals_u[sel]
                        if cols_u.size:
                            order = np.argsort(cols_u)
                            cols_u = cols_u[order]
                            vals_u = vals_u[order]
                        upper_cols.append(cols_u)
                        upper_vals.append(vals_u)
                        max_upper = max(max_upper, int(cols_u.size))
                    upper_idx = -np.ones((int(n), max_upper), dtype=np.int32)
                    upper_val = np.zeros((int(n), max_upper), dtype=np.float64)
                    for i in range(int(n)):
                        k = int(upper_cols[i].size)
                        if k:
                            upper_idx[i, :k] = upper_cols[i]
                            upper_val[i, :k] = upper_vals[i]

                    perm_r_jnp = jnp.asarray(perm_r, dtype=jnp.int32)
                    inv_perm_c_jnp = jnp.asarray(inv_perm_c, dtype=jnp.int32)
                    lower_idx_jnp = jnp.asarray(lower_idx, dtype=jnp.int32)
                    lower_val_jnp = jnp.asarray(lower_val, dtype=jnp.float64)
                    lower_diag_jnp = jnp.asarray(lower_diag, dtype=jnp.float64)
                    upper_idx_jnp = jnp.asarray(upper_idx, dtype=jnp.int32)
                    upper_val_jnp = jnp.asarray(upper_val, dtype=jnp.float64)
                    upper_diag_jnp = jnp.asarray(upper_diag, dtype=jnp.float64)

                    if emit is not None:
                        emit(
                            1,
                            "sparse_ilu: cached JAX factors "
                            f"(max_lower={int(max_lower)} max_upper={int(max_upper)} cap={int(row_nnz_cap_use)})",
                        )

                _RHSMODE1_SPARSE_ILU_CACHE[cache_key] = _SparseILUCache(
                    a_csr_full=cached.a_csr_full,
                    a_csr_drop=cached.a_csr_drop,
                    ilu=ilu,
                    a_dense=cached.a_dense,
                    l_dense=l_dense,
                    u_dense=u_dense,
                    l_unit_diag=bool(l_unit_diag),
                    perm_r=perm_r_jnp,
                    inv_perm_c=inv_perm_c_jnp,
                    lower_idx=lower_idx_jnp,
                    lower_val=lower_val_jnp,
                    lower_diag=lower_diag_jnp,
                    upper_idx=upper_idx_jnp,
                    upper_val=upper_val_jnp,
                    upper_diag=upper_diag_jnp,
                )
                cached = _RHSMODE1_SPARSE_ILU_CACHE[cache_key]
        return (
            cached.a_csr_full,
            cached.a_csr_drop,
            cached.ilu,
            cached.a_dense,
            cached.l_dense,
            cached.u_dense,
            cached.l_unit_diag,
        )

    factorization_use = str(factorization).strip().lower()
    exact_lu = factorization_use == "lu"
    log_tag = "sparse_lu" if exact_lu else "sparse_ilu"
    factor_dtype_use = np.dtype(np.float64 if factor_dtype is None else factor_dtype)

    sparse_block_env = os.environ.get("SFINCS_JAX_RHSMODE1_SPARSE_ASSEMBLE_BLOCK", "").strip()
    sparse_block_min_env = os.environ.get("SFINCS_JAX_RHSMODE1_SPARSE_ASSEMBLE_BLOCK_MIN", "").strip()
    try:
        sparse_block = int(sparse_block_env) if sparse_block_env else 0
    except ValueError:
        sparse_block = 0
    try:
        sparse_block_min = int(sparse_block_min_env) if sparse_block_min_env else 8000
    except ValueError:
        sparse_block_min = 8000
    if sparse_block == 0 and int(n) >= max(1, int(sparse_block_min)) and (not store_dense):
        sparse_block = 128

    struct_tol = _sparse_structural_tol()
    a_dense = None
    a_np_full = None

    import scipy.sparse as sp  # noqa: PLC0415
    from scipy.sparse.linalg import spilu, splu  # noqa: PLC0415

    if sparse_block > 0:
        if emit is not None:
            emit(1, f"{log_tag}: assembling sparse operator in column blocks (n={n} block={int(sparse_block)})")

        jit_env = os.environ.get("SFINCS_JAX_DENSE_ASSEMBLE_JIT", "").strip().lower()
        if jit_env:
            use_jit = jit_env not in {"0", "false", "no", "off"}
        else:
            use_jit = int(n) > 800

        def _assemble(block_cols: jnp.ndarray) -> jnp.ndarray:
            return jax.vmap(matvec, in_axes=1, out_axes=1)(block_cols)

        assemble_fn = jax.jit(_assemble) if use_jit else _assemble
        rows_parts: list[np.ndarray] = []
        cols_parts: list[np.ndarray] = []
        data_parts: list[np.ndarray] = []
        max_abs = 0.0
        work_dtype = np.dtype(np.float64)
        for start in range(0, int(n), int(sparse_block)):
            width = min(int(sparse_block), int(n) - int(start))
            block_cols_np = np.zeros((int(n), int(width)), dtype=work_dtype)
            block_cols_np[np.arange(int(start), int(start) + int(width)), np.arange(int(width))] = 1.0
            chunk = np.array(assemble_fn(jnp.asarray(block_cols_np, dtype=dtype)), dtype=np.float64, copy=True)
            if struct_tol > 0.0 and chunk.size:
                chunk[np.abs(chunk) <= struct_tol] = 0.0
            if chunk.size:
                max_abs = max(max_abs, float(np.max(np.abs(chunk))))
                row_idx, col_local = np.nonzero(chunk)
                if row_idx.size:
                    rows_parts.append(row_idx.astype(np.int32, copy=False))
                    cols_parts.append((col_local + int(start)).astype(np.int32, copy=False))
                    data_parts.append(chunk[row_idx, col_local].astype(factor_dtype_use, copy=False))
        if rows_parts:
            rows = np.concatenate(rows_parts, axis=0)
            cols = np.concatenate(cols_parts, axis=0)
            data = np.concatenate(data_parts, axis=0)
        else:
            rows = np.zeros((0,), dtype=np.int32)
            cols = np.zeros((0,), dtype=np.int32)
            data = np.zeros((0,), dtype=factor_dtype_use)
        a_csr_full = sp.csr_matrix((data, (rows, cols)), shape=(int(n), int(n)))
        a_csr_full.eliminate_zeros()
    else:
        if emit is not None:
            emit(1, f"{log_tag}: assembling dense operator (n={n})")
        a_dense = assemble_dense_matrix_from_matvec(matvec=matvec, n=int(n), dtype=dtype)
        a_np_full = np.array(a_dense, dtype=factor_dtype_use, copy=True)
        if struct_tol > 0.0 and a_np_full.size:
            a_np_full[np.abs(a_np_full) <= struct_tol] = 0.0
        max_abs = float(np.max(np.abs(a_np_full))) if a_np_full.size else 0.0
        a_csr_full = sp.csr_matrix(a_np_full)
        a_csr_full.eliminate_zeros()

    thresh0 = 0.0 if exact_lu else max(float(drop_tol), float(drop_rel) * max_abs)
    reg_env = os.environ.get("SFINCS_JAX_RHSMODE1_SPARSE_ILU_REG", "").strip()
    try:
        reg = float(reg_env) if reg_env else (1.0e-12 * max_abs)
    except ValueError:
        reg = 1.0e-12 * max_abs
    reg = max(0.0, float(reg))
    attempts_env = os.environ.get("SFINCS_JAX_RHSMODE1_SPARSE_ILU_ATTEMPTS", "").strip()
    try:
        attempts = int(attempts_env) if attempts_env else 3
    except ValueError:
        attempts = 3
    attempts = max(1, int(attempts))

    a_csr_drop = None
    ilu = None
    ilu_drop_tol_eff = float(ilu_drop_tol)
    fill_factor_eff = float(fill_factor)
    last_exc: Exception | None = None
    for attempt in range(int(attempts if build_ilu else 1)):
        thresh = float(thresh0) * (0.1 ** int(attempt))
        if sparse_block > 0:
            a_csr_drop = a_csr_full.copy()
            if thresh > 0.0:
                if emit is not None:
                    emit(1, f"sparse_ilu: dropping entries |a| < {thresh:.3e}")
                data = a_csr_drop.data
                data[np.abs(data) < thresh] = 0.0
            if int(n) > 0 and reg != 0.0:
                diag_idx = np.arange(int(n), dtype=np.int32)
                a_csr_drop = a_csr_drop.tolil(copy=False)
                diag_vals = (
                    np.asarray(a_csr_drop[diag_idx, diag_idx].toarray(), dtype=factor_dtype_use).reshape((-1,))
                    + factor_dtype_use.type(reg)
                )
                a_csr_drop[diag_idx, diag_idx] = diag_vals
                a_csr_drop = a_csr_drop.tocsr()
        else:
            if thresh > 0.0:
                if emit is not None:
                    emit(1, f"sparse_ilu: dropping entries |a| < {thresh:.3e}")
                a_np_drop = a_np_full.copy()
                a_np_drop[np.abs(a_np_drop) < thresh] = 0.0
            elif reg != 0.0:
                a_np_drop = a_np_full.copy()
            else:
                a_np_drop = a_np_full

            # Preserve the diagonal and add a small regularization to avoid exact
            # zero pivots in the incomplete factorization.
            if int(n) > 0 and reg != 0.0:
                diag_idx = np.arange(int(n), dtype=np.int32)
                a_np_drop[diag_idx, diag_idx] = a_np_full[diag_idx, diag_idx] + factor_dtype_use.type(reg)

            a_csr_drop = sp.csr_matrix(a_np_drop)
        a_csr_drop.eliminate_zeros()
        if emit is not None:
            nnz = int(a_csr_drop.nnz)
            emit(1, f"{log_tag}: nnz={nnz} ({nnz / max(1, n * n):.3e} density)")
        if not build_ilu:
            break
        try:
            if exact_lu:
                ilu = splu(a_csr_drop.tocsc(), permc_spec="COLAMD")
            else:
                ilu = spilu(
                    a_csr_drop.tocsc(),
                    drop_tol=float(ilu_drop_tol_eff),
                    fill_factor=float(fill_factor_eff),
                    permc_spec="COLAMD",
                )
            last_exc = None
            break
        except Exception as exc:  # noqa: BLE001
            last_exc = exc
            msg = str(exc).lower()
            if emit is not None:
                emit(
                    1,
                    f"{log_tag}: factorization failed "
                    f"(attempt={attempt + 1}/{int(attempts)} "
                    f"thresh={thresh:.3e} drop_tol={ilu_drop_tol_eff:.1e} fill={fill_factor_eff:.1f}) "
                    f"({type(exc).__name__}: {exc})",
                )
            if exact_lu:
                if ("singular" in msg) or ("pivot" in msg) or ("dpivot" in msg) or ("zero" in msg):
                    reg = max(float(reg), max(1.0e-12, 1.0e-10 * max_abs))
                    continue
                raise
            if ("singular" in msg) or ("pivot" in msg) or ("dpivot" in msg) or ("zero" in msg):
                # Retry with a denser sparsification and stronger (less dropping) ILU.
                ilu_drop_tol_eff = max(0.0, float(ilu_drop_tol_eff) * 0.1)
                fill_factor_eff = max(float(fill_factor_eff), float(fill_factor) * 2.0, 20.0)
                continue
            raise
    if a_csr_drop is None:
        a_csr_drop = a_csr_full.copy()
        a_csr_drop.eliminate_zeros()
    if build_ilu and ilu is None and last_exc is not None:
        raise RuntimeError(
            f"{log_tag}: factorization failed after {int(attempts)} attempts ({type(last_exc).__name__}: {last_exc})"
        )
    if store_dense:
        if a_np_full is not None:
            a_dense = a_np_full
        elif int(n) <= 4000:
            a_dense = np.asarray(a_csr_full.toarray(), dtype=np.float64)
        else:
            a_dense = None
    l_dense = None
    u_dense = None
    l_unit_diag = True
    perm_r_jnp = None
    inv_perm_c_jnp = None
    lower_idx_jnp = None
    lower_val_jnp = None
    lower_diag_jnp = None
    upper_idx_jnp = None
    upper_val_jnp = None
    upper_diag_jnp = None
    if build_dense_factors and ilu is not None:
        l_dense = np.asarray(ilu.L.todense(), dtype=np.float64)
        u_dense = np.asarray(ilu.U.todense(), dtype=np.float64)
        diag_l = np.diag(l_dense)
        l_unit_diag = bool(np.allclose(diag_l, 1.0))
    if build_jax_factors and ilu is not None:
        perm_r = np.asarray(ilu.perm_r, dtype=np.int32, copy=True)
        perm_c = np.asarray(ilu.perm_c, dtype=np.int32, copy=True)
        inv_perm_c = np.argsort(perm_c).astype(np.int32, copy=False)
        l_csr = ilu.L.tocsr()
        u_csr = ilu.U.tocsr()

        if row_nnz_cap is None:
            row_nnz_cap_env = os.environ.get("SFINCS_JAX_RHSMODE1_SPARSE_ILU_ROW_NNZ_MAX", "").strip()
            try:
                row_nnz_cap_use = int(row_nnz_cap_env) if row_nnz_cap_env else 256
            except ValueError:
                row_nnz_cap_use = 256
        else:
            row_nnz_cap_use = int(row_nnz_cap)
        row_nnz_cap_use = max(0, int(row_nnz_cap_use))

        lower_diag = np.asarray(l_csr.diagonal(), dtype=np.float64)
        lower_diag = np.where(lower_diag != 0.0, lower_diag, 1.0)
        upper_diag = np.asarray(u_csr.diagonal(), dtype=np.float64)
        upper_diag = np.where(np.isfinite(upper_diag) & (upper_diag != 0.0), upper_diag, 1.0)

        lower_cols: list[np.ndarray] = []
        lower_vals: list[np.ndarray] = []
        max_lower = 0
        for i in range(int(n)):
            rs = int(l_csr.indptr[i])
            re = int(l_csr.indptr[i + 1])
            cols = l_csr.indices[rs:re]
            vals = l_csr.data[rs:re]
            mask = cols < i
            cols = cols[mask].astype(np.int32, copy=False)
            vals = vals[mask].astype(np.float64, copy=False)
            if row_nnz_cap_use > 0 and int(cols.size) > row_nnz_cap_use:
                sel = np.argpartition(np.abs(vals), -row_nnz_cap_use)[-row_nnz_cap_use:]
                cols = cols[sel]
                vals = vals[sel]
            if cols.size:
                order = np.argsort(cols)
                cols = cols[order]
                vals = vals[order]
            lower_cols.append(cols)
            lower_vals.append(vals)
            max_lower = max(max_lower, int(cols.size))
        lower_idx = -np.ones((int(n), max_lower), dtype=np.int32)
        lower_val = np.zeros((int(n), max_lower), dtype=np.float64)
        for i in range(int(n)):
            k = int(lower_cols[i].size)
            if k:
                lower_idx[i, :k] = lower_cols[i]
                lower_val[i, :k] = lower_vals[i]

        upper_cols: list[np.ndarray] = []
        upper_vals: list[np.ndarray] = []
        max_upper = 0
        for i in range(int(n)):
            rs = int(u_csr.indptr[i])
            re = int(u_csr.indptr[i + 1])
            cols = u_csr.indices[rs:re]
            vals = u_csr.data[rs:re]
            mask = cols > i
            cols_u = cols[mask].astype(np.int32, copy=False)
            vals_u = vals[mask].astype(np.float64, copy=False)
            if row_nnz_cap_use > 0 and int(cols_u.size) > row_nnz_cap_use:
                sel = np.argpartition(np.abs(vals_u), -row_nnz_cap_use)[-row_nnz_cap_use:]
                cols_u = cols_u[sel]
                vals_u = vals_u[sel]
            if cols_u.size:
                order = np.argsort(cols_u)
                cols_u = cols_u[order]
                vals_u = vals_u[order]
            upper_cols.append(cols_u)
            upper_vals.append(vals_u)
            max_upper = max(max_upper, int(cols_u.size))
        upper_idx = -np.ones((int(n), max_upper), dtype=np.int32)
        upper_val = np.zeros((int(n), max_upper), dtype=np.float64)
        for i in range(int(n)):
            k = int(upper_cols[i].size)
            if k:
                upper_idx[i, :k] = upper_cols[i]
                upper_val[i, :k] = upper_vals[i]

        perm_r_jnp = jnp.asarray(perm_r, dtype=jnp.int32)
        inv_perm_c_jnp = jnp.asarray(inv_perm_c, dtype=jnp.int32)
        lower_idx_jnp = jnp.asarray(lower_idx, dtype=jnp.int32)
        lower_val_jnp = jnp.asarray(lower_val, dtype=jnp.float64)
        lower_diag_jnp = jnp.asarray(lower_diag, dtype=jnp.float64)
        upper_idx_jnp = jnp.asarray(upper_idx, dtype=jnp.int32)
        upper_val_jnp = jnp.asarray(upper_val, dtype=jnp.float64)
        upper_diag_jnp = jnp.asarray(upper_diag, dtype=jnp.float64)
        if emit is not None:
            emit(
                1,
                "sparse_ilu: built JAX factors "
                f"(max_lower={int(max_lower)} max_upper={int(max_upper)} cap={int(row_nnz_cap_use)})",
            )
    _RHSMODE1_SPARSE_ILU_CACHE[cache_key] = _SparseILUCache(
        a_csr_full=a_csr_full,
        a_csr_drop=a_csr_drop,
        ilu=ilu,
        a_dense=a_dense,
        l_dense=l_dense,
        u_dense=u_dense,
        l_unit_diag=l_unit_diag,
        perm_r=perm_r_jnp,
        inv_perm_c=inv_perm_c_jnp,
        lower_idx=lower_idx_jnp,
        lower_val=lower_val_jnp,
        lower_diag=lower_diag_jnp,
        upper_idx=upper_idx_jnp,
        upper_val=upper_val_jnp,
        upper_diag=upper_diag_jnp,
    )
    return a_csr_full, a_csr_drop, ilu, a_dense, l_dense, u_dense, l_unit_diag


def _factorize_sparse_matrix_csr_host(
    *,
    a_csr_full,
    cache_key: tuple[object, ...],
    drop_tol: float,
    drop_rel: float,
    ilu_drop_tol: float,
    fill_factor: float,
    factorization: str = "ilu",
    emit: Callable[[int, str], None] | None = None,
) -> tuple[object, object, object]:
    cached = _RHSMODE1_SPARSE_ILU_CACHE.get(cache_key)
    if cached is not None and cached.ilu is not None:
        return cached.a_csr_full, cached.a_csr_drop, cached.ilu

    import scipy.sparse as sp  # noqa: PLC0415
    from scipy.sparse.linalg import spilu, splu  # noqa: PLC0415

    factorization_use = str(factorization).strip().lower()
    exact_lu = factorization_use == "lu"
    log_tag = "sparse_lu" if exact_lu else "sparse_ilu"

    a_csr_full = a_csr_full.tocsr()
    a_csr_full.eliminate_zeros()
    max_abs = float(np.max(np.abs(a_csr_full.data))) if int(a_csr_full.nnz) > 0 else 0.0
    thresh0 = 0.0 if exact_lu else max(float(drop_tol), float(drop_rel) * max_abs)

    reg_env = os.environ.get("SFINCS_JAX_RHSMODE1_SPARSE_ILU_REG", "").strip()
    try:
        reg = float(reg_env) if reg_env else (1.0e-12 * max_abs)
    except ValueError:
        reg = 1.0e-12 * max_abs
    reg = max(0.0, float(reg))

    attempts_env = os.environ.get("SFINCS_JAX_RHSMODE1_SPARSE_ILU_ATTEMPTS", "").strip()
    try:
        attempts = int(attempts_env) if attempts_env else 3
    except ValueError:
        attempts = 3
    attempts = max(1, int(attempts))

    ilu = None
    a_csr_drop = None
    ilu_drop_tol_eff = float(ilu_drop_tol)
    fill_factor_eff = float(fill_factor)
    last_exc: Exception | None = None

    for attempt in range(int(attempts)):
        thresh = float(thresh0) * (0.1 ** int(attempt))
        a_csr_drop = a_csr_full.copy()
        if thresh > 0.0 and int(a_csr_drop.nnz) > 0:
            if emit is not None:
                emit(1, f"{log_tag}: dropping entries |a| < {thresh:.3e}")
            data = a_csr_drop.data
            data[np.abs(data) < thresh] = 0.0
        if int(a_csr_drop.shape[0]) > 0 and reg != 0.0:
            diag_idx = np.arange(int(a_csr_drop.shape[0]), dtype=np.int32)
            a_csr_drop = a_csr_drop.tolil(copy=False)
            diag_vals = np.asarray(a_csr_drop[diag_idx, diag_idx].toarray(), dtype=np.float64).reshape((-1,)) + reg
            a_csr_drop[diag_idx, diag_idx] = diag_vals
            a_csr_drop = a_csr_drop.tocsr()
        a_csr_drop.eliminate_zeros()
        if emit is not None:
            nnz = int(a_csr_drop.nnz)
            n = int(a_csr_drop.shape[0])
            emit(1, f"{log_tag}: nnz={nnz} ({nnz / max(1, n * n):.3e} density)")
        try:
            if exact_lu:
                ilu = splu(a_csr_drop.tocsc(), permc_spec="COLAMD")
            else:
                ilu = spilu(
                    a_csr_drop.tocsc(),
                    drop_tol=float(ilu_drop_tol_eff),
                    fill_factor=float(fill_factor_eff),
                    permc_spec="COLAMD",
                )
            last_exc = None
            break
        except Exception as exc:  # noqa: BLE001
            last_exc = exc
            msg = str(exc).lower()
            if emit is not None:
                emit(
                    1,
                    f"{log_tag}: factorization failed "
                    f"(attempt={attempt + 1}/{int(attempts)} "
                    f"thresh={thresh:.3e} drop_tol={ilu_drop_tol_eff:.1e} fill={fill_factor_eff:.1f}) "
                    f"({type(exc).__name__}: {exc})",
                )
            if exact_lu:
                if ("singular" in msg) or ("pivot" in msg) or ("dpivot" in msg) or ("zero" in msg):
                    reg = max(float(reg), max(1.0e-12, 1.0e-10 * max_abs))
                    continue
                raise
            if ("singular" in msg) or ("pivot" in msg) or ("dpivot" in msg) or ("zero" in msg):
                ilu_drop_tol_eff = max(0.0, float(ilu_drop_tol_eff) * 0.1)
                fill_factor_eff = max(float(fill_factor_eff), float(fill_factor) * 2.0, 20.0)
                continue
            raise

    if ilu is None:
        if last_exc is not None:
            raise RuntimeError(
                f"{log_tag}: factorization failed after {int(attempts)} attempts "
                f"({type(last_exc).__name__}: {last_exc})"
            )
        raise RuntimeError(f"{log_tag}: factorization failed with no exception detail")

    _RHSMODE1_SPARSE_ILU_CACHE[cache_key] = _SparseILUCache(
        a_csr_full=a_csr_full,
        a_csr_drop=a_csr_drop,
        ilu=ilu,
        a_dense=None,
        l_dense=None,
        u_dense=None,
        l_unit_diag=True,
    )
    cached = _RHSMODE1_SPARSE_ILU_CACHE[cache_key]
    assert cached.ilu is not None
    return cached.a_csr_full, cached.a_csr_drop, cached.ilu


def _rhsmode1_host_factor_probe_ok(*, factor: object | None, block_size: int) -> bool:
    return _rhs1_host_factor_probe_ok_impl(factor=factor, block_size=int(block_size))


def _assemble_selected_theta_tz_operator(*, dd_plus: np.ndarray, dd_minus: np.ndarray, use_plus: np.ndarray):
    import scipy.sparse as sp  # noqa: PLC0415

    n_theta, n_zeta = use_plus.shape
    n_tz = int(n_theta * n_zeta)
    struct_tol = _sparse_structural_tol()
    rows: list[np.ndarray] = []
    cols: list[np.ndarray] = []
    data: list[np.ndarray] = []
    for it in range(n_theta):
        row_plus = np.asarray(dd_plus[it, :], dtype=np.float64)
        row_minus = np.asarray(dd_minus[it, :], dtype=np.float64)
        if struct_tol > 0.0:
            row_plus = row_plus.copy()
            row_minus = row_minus.copy()
            row_plus[np.abs(row_plus) <= struct_tol] = 0.0
            row_minus[np.abs(row_minus) <= struct_tol] = 0.0
        nz_plus = np.flatnonzero(row_plus)
        nz_minus = np.flatnonzero(row_minus)
        for iz in range(n_zeta):
            row = int(it * n_zeta + iz)
            nz = nz_plus if bool(use_plus[it, iz]) else nz_minus
            row_vals = row_plus if bool(use_plus[it, iz]) else row_minus
            if int(nz.size) == 0:
                continue
            rows.append(np.full((int(nz.size),), row, dtype=np.int32))
            cols.append((nz.astype(np.int32, copy=False) * int(n_zeta)) + int(iz))
            data.append(np.asarray(row_vals[nz], dtype=np.float64))
    if not data:
        return sp.csr_matrix((n_tz, n_tz), dtype=np.float64)
    row_idx = np.concatenate(rows)
    col_idx = np.concatenate(cols)
    values = np.concatenate(data)
    return sp.csr_matrix((values, (row_idx, col_idx)), shape=(n_tz, n_tz), dtype=np.float64)


def _assemble_selected_zeta_tz_operator(*, dd_plus: np.ndarray, dd_minus: np.ndarray, use_plus: np.ndarray):
    import scipy.sparse as sp  # noqa: PLC0415

    n_theta, n_zeta = use_plus.shape
    n_tz = int(n_theta * n_zeta)
    struct_tol = _sparse_structural_tol()
    rows: list[np.ndarray] = []
    cols: list[np.ndarray] = []
    data: list[np.ndarray] = []
    for it in range(n_theta):
        for iz in range(n_zeta):
            row = int(it * n_zeta + iz)
            row_vals = np.asarray(dd_plus[iz, :] if bool(use_plus[it, iz]) else dd_minus[iz, :], dtype=np.float64)
            if struct_tol > 0.0:
                row_vals = row_vals.copy()
                row_vals[np.abs(row_vals) <= struct_tol] = 0.0
            nz = np.flatnonzero(row_vals)
            if int(nz.size) == 0:
                continue
            rows.append(np.full((int(nz.size),), row, dtype=np.int32))
            cols.append((int(it) * int(n_zeta)) + nz.astype(np.int32, copy=False))
            data.append(np.asarray(row_vals[nz], dtype=np.float64))
    if not data:
        return sp.csr_matrix((n_tz, n_tz), dtype=np.float64)
    row_idx = np.concatenate(rows)
    col_idx = np.concatenate(cols)
    values = np.concatenate(data)
    return sp.csr_matrix((values, (row_idx, col_idx)), shape=(n_tz, n_tz), dtype=np.float64)


def _get_rhsmode1_fp_xblock_assembled_host_cache(*, op: V3FullSystemOperator) -> _RHSMode1FPXBlockAssembledHostCache:
    import scipy.sparse as sp  # noqa: PLC0415

    cache_key = _rhsmode1_precond_cache_key(op, "fp_xblock_assembled_host")
    cached = _RHSMODE1_FP_XBLOCK_ASSEMBLED_HOST_CACHE.get(cache_key)
    if cached is not None:
        return cached

    colless = op.fblock.collisionless
    fp = op.fblock.fp
    if colless is None or fp is None:
        raise ValueError("assembled FP x-block host cache requires collisionless and FP operators")

    n_species = int(op.n_species)
    n_x = int(op.n_x)
    n_l = int(op.n_xi)
    n_theta = int(op.n_theta)
    n_zeta = int(op.n_zeta)
    n_tz = int(n_theta * n_zeta)

    x = np.asarray(colless.x, dtype=np.float64).reshape((n_x,))
    z_s = np.asarray(op.z_s, dtype=np.float64).reshape((n_species,))
    identity_shift = float(np.asarray(op.fblock.identity_shift, dtype=np.float64).reshape(()))
    fp_diag_sxl = np.zeros((n_species, n_x, n_l), dtype=np.float64)
    for s in range(n_species):
        for ix in range(n_x):
            fp_diag_sxl[s, ix, :] = np.asarray(fp.mat[s, s, :, ix, ix], dtype=np.float64)

    struct_tol = _sparse_structural_tol()
    ddtheta = np.asarray(colless.ddtheta, dtype=np.float64)
    ddzeta = np.asarray(colless.ddzeta, dtype=np.float64)
    if struct_tol > 0.0:
        ddtheta = ddtheta.copy()
        ddzeta = ddzeta.copy()
        ddtheta[np.abs(ddtheta) <= struct_tol] = 0.0
        ddzeta[np.abs(ddzeta) <= struct_tol] = 0.0
    n_tz_eye = sp.eye(n_tz, format="csr", dtype=np.float64)
    dtheta_tz = sp.kron(sp.csr_matrix(ddtheta), sp.eye(n_zeta, format="csr", dtype=np.float64), format="csr")
    dzeta_tz = sp.kron(sp.eye(n_theta, format="csr", dtype=np.float64), sp.csr_matrix(ddzeta), format="csr")

    b_hat = np.asarray(colless.b_hat, dtype=np.float64)
    b_hat_sup_theta = np.asarray(colless.b_hat_sup_theta, dtype=np.float64)
    b_hat_sup_zeta = np.asarray(colless.b_hat_sup_zeta, dtype=np.float64)
    db_hat_dtheta = np.asarray(colless.db_hat_dtheta, dtype=np.float64)
    db_hat_dzeta = np.asarray(colless.db_hat_dzeta, dtype=np.float64)
    t_hats = np.asarray(colless.t_hats, dtype=np.float64).reshape((n_species,))
    m_hats = np.asarray(colless.m_hats, dtype=np.float64).reshape((n_species,))
    sqrt_t_over_m = np.sqrt(t_hats / m_hats)

    stream_tz_by_species: list[object] = []
    mirror_diag_by_species: list[object] = []
    v_theta = b_hat_sup_theta / b_hat
    v_zeta = b_hat_sup_zeta / b_hat
    mirror_geom = b_hat_sup_theta * db_hat_dtheta + b_hat_sup_zeta * db_hat_dzeta
    for s in range(n_species):
        stream_tz = sp.diags((sqrt_t_over_m[s] * v_theta).reshape((-1,)), 0, format="csr") @ dtheta_tz
        stream_tz = stream_tz + (sp.diags((sqrt_t_over_m[s] * v_zeta).reshape((-1,)), 0, format="csr") @ dzeta_tz)
        mirror_factor = (-sqrt_t_over_m[s] * mirror_geom / (2.0 * (b_hat**2))).reshape((-1,))
        stream_tz_by_species.append(stream_tz.tocsr())
        mirror_diag_by_species.append(sp.diags(mirror_factor, 0, format="csr"))

    exb_op_tz = None
    exb_theta = op.fblock.exb_theta
    exb_zeta = op.fblock.exb_zeta
    if exb_theta is not None:
        denom = (
            float(np.asarray(exb_theta.fsab_hat2, dtype=np.float64).reshape(()))
            if bool(getattr(exb_theta, "use_dkes_exb_drift", False))
            else None
        )
        coef = np.asarray(exb_theta.d_hat * exb_theta.b_hat_sub_zeta, dtype=np.float64)
        coef = coef / denom if denom is not None else coef / (np.asarray(exb_theta.b_hat, dtype=np.float64) ** 2)
        factor = float(np.asarray(exb_theta.alpha * exb_theta.delta * 0.5 * exb_theta.dphi_hat_dpsi_hat, dtype=np.float64).reshape(()))
        exb_op_tz = sp.diags((factor * coef).reshape((-1,)), 0, format="csr") @ dtheta_tz
    if exb_zeta is not None:
        denom = (
            float(np.asarray(exb_zeta.fsab_hat2, dtype=np.float64).reshape(()))
            if bool(getattr(exb_zeta, "use_dkes_exb_drift", False))
            else None
        )
        coef = np.asarray(exb_zeta.d_hat * exb_zeta.b_hat_sub_theta, dtype=np.float64)
        coef = coef / denom if denom is not None else coef / (np.asarray(exb_zeta.b_hat, dtype=np.float64) ** 2)
        factor = float(np.asarray(-exb_zeta.alpha * exb_zeta.delta * 0.5 * exb_zeta.dphi_hat_dpsi_hat, dtype=np.float64).reshape(()))
        exb_term = sp.diags((factor * coef).reshape((-1,)), 0, format="csr") @ dzeta_tz
        exb_op_tz = exb_term if exb_op_tz is None else (exb_op_tz + exb_term)
    if exb_op_tz is not None:
        exb_op_tz = exb_op_tz.tocsr()

    mag_theta_m1_tz_by_species = None
    mag_theta_m2_tz_by_species = None
    mag_theta = op.fblock.magdrift_theta
    if mag_theta is not None:
        gf1 = np.asarray(
            mag_theta.b_hat_sub_zeta * mag_theta.db_hat_dpsi_hat - mag_theta.b_hat_sub_psi * mag_theta.db_hat_dzeta,
            dtype=np.float64,
        )
        gf2 = np.asarray(
            2.0 * mag_theta.b_hat * (mag_theta.db_hat_sub_psi_dzeta - mag_theta.db_hat_sub_zeta_dpsi_hat),
            dtype=np.float64,
        )
        base = np.asarray(
            mag_theta.delta * mag_theta.t_hat * mag_theta.d_hat / (2.0 * mag_theta.z * (mag_theta.b_hat**3)),
            dtype=np.float64,
        )
        d_hat_ref = float(np.asarray(mag_theta.d_hat, dtype=np.float64).reshape((-1,))[0])
        mag_theta_m1_tz_by_species = []
        mag_theta_m2_tz_by_species = []
        for s in range(n_species):
            use_plus = (gf1 * d_hat_ref / float(z_s[s])) > 0.0
            dtheta_used_tz = _assemble_selected_theta_tz_operator(
                dd_plus=np.asarray(mag_theta.ddtheta_plus, dtype=np.float64),
                dd_minus=np.asarray(mag_theta.ddtheta_minus, dtype=np.float64),
                use_plus=np.asarray(use_plus, dtype=bool),
            )
            mag_theta_m1_tz_by_species.append(
                (sp.diags((base * gf1).reshape((-1,)), 0, format="csr") @ dtheta_used_tz).tocsr()
            )
            mag_theta_m2_tz_by_species.append(
                (sp.diags((base * gf2).reshape((-1,)), 0, format="csr") @ dtheta_used_tz).tocsr()
            )
        mag_theta_m1_tz_by_species = tuple(mag_theta_m1_tz_by_species)
        mag_theta_m2_tz_by_species = tuple(mag_theta_m2_tz_by_species)

    mag_zeta_m1_tz_by_species = None
    mag_zeta_m2_tz_by_species = None
    mag_zeta = op.fblock.magdrift_zeta
    if mag_zeta is not None:
        gf1 = np.asarray(
            mag_zeta.b_hat_sub_psi * mag_zeta.db_hat_dtheta - mag_zeta.b_hat_sub_theta * mag_zeta.db_hat_dpsi_hat,
            dtype=np.float64,
        )
        gf2 = np.asarray(
            2.0 * mag_zeta.b_hat * (mag_zeta.db_hat_sub_theta_dpsi_hat - mag_zeta.db_hat_sub_psi_dtheta),
            dtype=np.float64,
        )
        base = np.asarray(
            mag_zeta.delta * mag_zeta.t_hat * mag_zeta.d_hat / (2.0 * mag_zeta.z * (mag_zeta.b_hat**3)),
            dtype=np.float64,
        )
        d_hat_ref = float(np.asarray(mag_zeta.d_hat, dtype=np.float64).reshape((-1,))[0])
        mag_zeta_m1_tz_by_species = []
        mag_zeta_m2_tz_by_species = []
        for s in range(n_species):
            use_plus = (gf1 * d_hat_ref / float(z_s[s])) > 0.0
            dzeta_used_tz = _assemble_selected_zeta_tz_operator(
                dd_plus=np.asarray(mag_zeta.ddzeta_plus, dtype=np.float64),
                dd_minus=np.asarray(mag_zeta.ddzeta_minus, dtype=np.float64),
                use_plus=np.asarray(use_plus, dtype=bool),
            )
            mag_zeta_m1_tz_by_species.append(
                (sp.diags((base * gf1).reshape((-1,)), 0, format="csr") @ dzeta_used_tz).tocsr()
            )
            mag_zeta_m2_tz_by_species.append(
                (sp.diags((base * gf2).reshape((-1,)), 0, format="csr") @ dzeta_used_tz).tocsr()
            )
        mag_zeta_m1_tz_by_species = tuple(mag_zeta_m1_tz_by_species)
        mag_zeta_m2_tz_by_species = tuple(mag_zeta_m2_tz_by_species)

    mag_xidot_factor_flat = None
    mag_xidot = op.fblock.magdrift_xidot
    if mag_xidot is not None:
        temp = np.asarray(
            (mag_xidot.db_hat_sub_psi_dzeta - mag_xidot.db_hat_sub_zeta_dpsi_hat) * mag_xidot.db_hat_dtheta
            + (mag_xidot.db_hat_sub_theta_dpsi_hat - mag_xidot.db_hat_sub_psi_dtheta) * mag_xidot.db_hat_dzeta,
            dtype=np.float64,
        )
        mag_xidot_factor_flat = np.asarray(
            (-(mag_xidot.delta * mag_xidot.t_hat) * mag_xidot.d_hat / (2.0 * mag_xidot.z * (mag_xidot.b_hat**3)) * temp),
            dtype=np.float64,
        ).reshape((-1,))

    er_xidot_factor_flat = None
    er_xidot = op.fblock.er_xidot
    if er_xidot is not None:
        temp = np.asarray(
            er_xidot.b_hat_sub_zeta * er_xidot.db_hat_dtheta - er_xidot.b_hat_sub_theta * er_xidot.db_hat_dzeta,
            dtype=np.float64,
        )
        er_xidot_factor_flat = np.asarray(
            er_xidot.alpha
            * er_xidot.delta
            * er_xidot.dphi_hat_dpsi_hat
            / (4.0 * (er_xidot.b_hat**3))
            * er_xidot.d_hat
            * temp,
            dtype=np.float64,
        ).reshape((-1,))

    er_xdot_factor_flat = None
    ddx_plus_diag = None
    ddx_minus_diag = None
    er_xdot = op.fblock.er_xdot
    if er_xdot is not None:
        factor0 = float(np.asarray(-(er_xdot.alpha * er_xdot.delta * er_xdot.dphi_hat_dpsi_hat) / 4.0, dtype=np.float64).reshape(()))
        er_xdot_factor_flat = np.asarray(
            factor0
            * er_xdot.d_hat
            / (er_xdot.b_hat**3)
            * (er_xdot.b_hat_sub_theta * er_xdot.db_hat_dzeta - er_xdot.b_hat_sub_zeta * er_xdot.db_hat_dtheta),
            dtype=np.float64,
        ).reshape((-1,))
        ddx_plus_diag = np.asarray(np.diag(np.asarray(er_xdot.ddx_plus, dtype=np.float64)), dtype=np.float64)
        ddx_minus_diag = np.asarray(np.diag(np.asarray(er_xdot.ddx_minus, dtype=np.float64)), dtype=np.float64)

    cached = _RHSMode1FPXBlockAssembledHostCache(
        x=x,
        z_s=z_s,
        fp_diag_sxl=fp_diag_sxl,
        n_tz_eye=n_tz_eye,
        stream_tz_by_species=tuple(stream_tz_by_species),
        mirror_diag_by_species=tuple(mirror_diag_by_species),
        exb_op_tz=exb_op_tz,
        mag_theta_m1_tz_by_species=mag_theta_m1_tz_by_species,
        mag_theta_m2_tz_by_species=mag_theta_m2_tz_by_species,
        mag_zeta_m1_tz_by_species=mag_zeta_m1_tz_by_species,
        mag_zeta_m2_tz_by_species=mag_zeta_m2_tz_by_species,
        mag_xidot_factor_flat=mag_xidot_factor_flat,
        er_xidot_factor_flat=er_xidot_factor_flat,
        er_xdot_factor_flat=er_xdot_factor_flat,
        ddx_plus_diag=ddx_plus_diag,
        ddx_minus_diag=ddx_minus_diag,
        identity_shift=identity_shift,
    )
    _RHSMODE1_FP_XBLOCK_ASSEMBLED_HOST_CACHE[cache_key] = cached
    return cached


def _assemble_rhsmode1_fp_xblock_tz_sparse_matrix(
    *,
    op: V3FullSystemOperator,
    species: int,
    ix: int,
    preconditioner_xi: int,
    host_cache: _RHSMode1FPXBlockAssembledHostCache | None = None,
):
    import scipy.sparse as sp  # noqa: PLC0415

    if op.fblock.fp is None:
        raise ValueError("assembled FP x-block matrix requires an FP operator")
    if int(preconditioner_xi) != 1:
        raise ValueError("assembled FP x-block matrix currently requires preconditioner_xi=1")
    if bool(op.point_at_x0):
        raise ValueError("assembled FP x-block matrix currently requires pointAtX0=false")

    colless = op.fblock.collisionless
    host = host_cache if host_cache is not None else _get_rhsmode1_fp_xblock_assembled_host_cache(op=op)
    mag_theta = op.fblock.magdrift_theta
    mag_zeta = op.fblock.magdrift_zeta

    n_theta = int(op.n_theta)
    n_zeta = int(op.n_zeta)
    n_lx = int(np.asarray(colless.n_xi_for_x, dtype=np.int32)[int(ix)])
    if n_lx <= 0:
        return sp.csc_matrix((0, 0), dtype=np.float64)

    n_l = int(op.n_xi)
    x_val = float(host.x[int(ix)])
    z_val = float(host.z_s[int(species)])

    diag_vals = float(host.identity_shift) + host.fp_diag_sxl[int(species), int(ix), :n_lx]
    a = sp.kron(sp.diags(diag_vals, 0, format="csr"), host.n_tz_eye, format="csc")
    stream_tz = host.stream_tz_by_species[int(species)]
    mirror_diag = host.mirror_diag_by_species[int(species)]

    l = np.arange(n_lx, dtype=np.float64)
    coef_plus = x_val * (l + 1.0) / (2.0 * l + 3.0)
    coef_minus = np.where(l > 0, x_val * l / (2.0 * l - 1.0), 0.0)
    coef_mirror_plus = x_val * (l + 1.0) * (l + 2.0) / (2.0 * l + 3.0)
    coef_mirror_minus = np.where(l > 1, -x_val * l * (l - 1.0) / (2.0 * l - 1.0), 0.0)
    if n_lx > 1:
        c_stream = sp.diags(
            [coef_minus[1:], coef_plus[:-1]],
            offsets=[-1, 1],
            shape=(n_lx, n_lx),
            format="csr",
            dtype=np.float64,
        )
        c_mirror = sp.diags(
            [coef_mirror_minus[1:], coef_mirror_plus[:-1]],
            offsets=[-1, 1],
            shape=(n_lx, n_lx),
            format="csr",
            dtype=np.float64,
        )
        a = a + sp.kron(c_stream, stream_tz, format="csc") + sp.kron(c_mirror, mirror_diag, format="csc")

    if host.exb_op_tz is not None:
        a = a + sp.kron(sp.eye(n_lx, format="csr", dtype=np.float64), host.exb_op_tz, format="csc")

    if mag_theta is not None:
        assert host.mag_theta_m1_tz_by_species is not None
        assert host.mag_theta_m2_tz_by_species is not None
        m1 = (x_val * x_val) * host.mag_theta_m1_tz_by_species[int(species)]
        m2 = (x_val * x_val) * host.mag_theta_m2_tz_by_species[int(species)]
        denom = (2.0 * l + 3.0) * (2.0 * l - 1.0)
        c1 = 2.0 * (3.0 * l * l + 3.0 * l - 2.0) / denom
        c2 = (2.0 * l * l + 2.0 * l - 1.0) / denom
        a = a + sp.kron(sp.diags(c1, 0, format="csr"), m1, format="csc")
        a = a + sp.kron(sp.diags(c2, 0, format="csr"), m2, format="csc")

    if mag_zeta is not None:
        assert host.mag_zeta_m1_tz_by_species is not None
        assert host.mag_zeta_m2_tz_by_species is not None
        m1 = (x_val * x_val) * host.mag_zeta_m1_tz_by_species[int(species)]
        m2 = (x_val * x_val) * host.mag_zeta_m2_tz_by_species[int(species)]
        denom = (2.0 * l + 3.0) * (2.0 * l - 1.0)
        c1 = 2.0 * (3.0 * l * l + 3.0 * l - 2.0) / denom
        c2 = (2.0 * l * l + 2.0 * l - 1.0) / denom
        a = a + sp.kron(sp.diags(c1, 0, format="csr"), m1, format="csc")
        a = a + sp.kron(sp.diags(c2, 0, format="csr"), m2, format="csc")

    if host.mag_xidot_factor_flat is not None:
        diag_c = np.where(l > 0, (l + 1.0) * l / ((2.0 * l - 1.0) * (2.0 * l + 3.0)), 0.0)
        a = a + sp.kron(
            sp.diags(diag_c, 0, format="csr"),
            sp.diags((x_val * x_val * host.mag_xidot_factor_flat).reshape((-1,)), 0, format="csr"),
            format="csc",
        )

    if host.er_xidot_factor_flat is not None:
        diag_c = np.where(l > 0, (l + 1.0) * l / ((2.0 * l - 1.0) * (2.0 * l + 3.0)), 0.0)
        a = a + sp.kron(
            sp.diags(diag_c, 0, format="csr"),
            sp.diags((x_val * x_val * host.er_xidot_factor_flat).reshape((-1,)), 0, format="csr"),
            format="csc",
        )

    if host.er_xdot_factor_flat is not None and host.ddx_plus_diag is not None and host.ddx_minus_diag is not None:
        use_plus = host.er_xdot_factor_flat > 0.0
        xdiag = x_val * np.where(use_plus, host.ddx_plus_diag[int(ix)], host.ddx_minus_diag[int(ix)])
        denom = (2.0 * l + 3.0) * (2.0 * l - 1.0)
        diag_coef = 2.0 * (3.0 * l * l + 3.0 * l - 2.0) / denom
        xdot_diag = sp.diags((xdiag * host.er_xdot_factor_flat).reshape((-1,)), 0, format="csr")
        a = a + sp.kron(sp.diags(diag_coef, 0, format="csr"), xdot_diag, format="csc")

    a = a.tocsc()
    a.eliminate_zeros()
    return a


def _build_sparse_jax_preconditioner_from_matvec(
    *,
    matvec: Callable[[jnp.ndarray], jnp.ndarray],
    n: int,
    dtype: jnp.dtype,
    cache_key: tuple[object, ...],
    drop_tol: float,
    drop_rel: float,
    reg: float,
    omega: float,
    sweeps: int,
    emit: Callable[[int, str], None] | None = None,
) -> Callable[[jnp.ndarray], jnp.ndarray]:
    cached = _RHSMODE1_SPARSE_JAX_CACHE.get(cache_key)
    if cached is not None:
        a_sp = cached.a_sp
        d_inv = cached.d_inv
        omega = cached.omega
        sweeps = cached.sweeps
    else:
        if emit is not None:
            emit(1, f"sparse_jax: assembling dense operator (n={n})")
        a_dense = assemble_dense_matrix_from_matvec(matvec=matvec, n=int(n), dtype=dtype)
        a_dense = jnp.asarray(a_dense, dtype=dtype)
        max_abs = jnp.max(jnp.abs(a_dense)) if int(n) > 0 else jnp.asarray(0.0, dtype=dtype)
        thresh = jnp.maximum(jnp.asarray(drop_tol, dtype=dtype), jnp.asarray(drop_rel, dtype=dtype) * max_abs)
        if drop_tol > 0.0 or drop_rel > 0.0:
            a_drop = jnp.where(jnp.abs(a_dense) >= thresh, a_dense, jnp.zeros_like(a_dense))
        else:
            a_drop = a_dense
        diag_idx = jnp.arange(int(n), dtype=jnp.int32)
        diag = a_dense[diag_idx, diag_idx]
        diag_safe = diag + jnp.asarray(reg, dtype=dtype)
        a_drop = a_drop.at[diag_idx, diag_idx].set(diag_safe)
        d_inv = jnp.where(diag_safe != 0, 1.0 / diag_safe, jnp.asarray(0.0, dtype=dtype))
        try:
            from jax.experimental import sparse as jsparse  # noqa: PLC0415

            a_sp = jsparse.BCOO.fromdense(a_drop)
        except Exception as exc:  # noqa: BLE001
            if emit is not None:
                emit(1, f"sparse_jax: failed to build BCOO ({type(exc).__name__}: {exc})")
            a_sp = None
        if a_sp is None:
            raise RuntimeError("sparse_jax: failed to build sparse operator")
        _RHSMODE1_SPARSE_JAX_CACHE[cache_key] = _SparseJaxPrecondCache(
            a_sp=a_sp,
            d_inv=jnp.asarray(d_inv, dtype=dtype),
            omega=float(omega),
            sweeps=int(sweeps),
        )

    def _apply(v: jnp.ndarray) -> jnp.ndarray:
        v = jnp.asarray(v, dtype=d_inv.dtype)
        x0 = jnp.zeros_like(v)

        def _body(i, x):
            r = v - a_sp @ x
            return x + omega * d_inv * r

        x = jax.lax.fori_loop(0, int(sweeps), _body, x0)
        return jnp.asarray(x, dtype=jnp.float64)

    return _apply


@dataclass(frozen=True)
class _TransportPrecondCache:
    inv_diag_f: jnp.ndarray


@dataclass(frozen=True)
class _TransportXBlockPrecondCache:
    inv_xblock: jnp.ndarray


@dataclass(frozen=True)
class _LowRankXBlockPrecondCache:
    d_inv: jnp.ndarray
    d_inv_u: jnp.ndarray
    v: jnp.ndarray
    m_inv: jnp.ndarray


@dataclass(frozen=True)
class _TransportXmgPrecondCache:
    inv_diag_f: jnp.ndarray
    coarse_inv: jnp.ndarray
    coarse_idx: jnp.ndarray
    coarse_inv_lblock: jnp.ndarray | None = None
    lblock: int = 0


@dataclass(frozen=True)
class _XUpwindPrecondCache:
    """Cached factors for a simple x-upwind (bidiagonal) preconditioner."""

    diag: jnp.ndarray  # (S, X, L)
    sub: jnp.ndarray  # (S, X, L) with sub[:, 0, :] ignored
    lblock: int = 0
    block_inv: jnp.ndarray | None = None  # (S, X, Lb, Lb)
    block_sub: jnp.ndarray | None = None  # (S, X, Lb, Lb)


@dataclass(frozen=True)
class _TransportTzFftPrecondCache:
    subdiag: jnp.ndarray  # (S,X,T,Z,L) complex (subdiag[0] ignored)
    diag: jnp.ndarray  # (S,X,T,Z,L) complex
    superdiag: jnp.ndarray  # (S,X,T,Z,L) complex (superdiag[-1] ignored)


@dataclass(frozen=True)
class _TransportFpTzFftPrecondCache:
    inv_mode: jnp.ndarray  # (T,Z,L*S*X,L*S*X) complex inverse per Fourier mode
    n_block: int


@dataclass(frozen=True)
class _SparseJaxPrecondCache:
    a_sp: object
    d_inv: jnp.ndarray
    omega: float
    sweeps: int


@dataclass(frozen=True)
class _PasTokamakThetaPrecondCache:
    """Cached factors for PAS tokamak (Nzeta=1) theta/L block-tridiagonal preconditioning.

    Notes
    -----
    This cache stores the block-Thomas factors for the (theta,L) coupling within each x.
    It is intended for the stiff PAS-only tokamak branch (no drift terms) where x-coupling
    is absent and theta-line blocks over the full x-grid are prohibitively large.
    """

    inv_a01: jnp.ndarray  # (S, X, 2*T, 2*T) effective inverse for the (L=0,1) combined block
    g01: jnp.ndarray  # (S, X, 2*T, T) block-Thomas factor coupling (L=0,1) block to L=2
    inv_a: jnp.ndarray  # (S, X, L-2, T, T) approximate inverse of effective diagonal blocks for L>=2
    g: jnp.ndarray  # (S, X, max(L-3,0), T, T) block-Thomas factors for back-substitution for L>=2
    c_stream: jnp.ndarray  # (X, L) scalar streaming coupling (row L from col L-1)
    c_mirror: jnp.ndarray  # (X, L) scalar mirror coupling (row L from col L-1)
    m_theta: jnp.ndarray  # (S, T, T) row-scaled theta-derivative matrix
    mirror_factor: jnp.ndarray  # (S, T) diagonal mirror factor in theta
    mask_active: jnp.ndarray  # (X, L) float mask (1.0 active, 0.0 inactive)
    n_l_build: int  # L truncation used for the preconditioner
    tail_factors: tuple[tuple[object | None, ...], ...] | None = None


@dataclass(frozen=True)
class _PasTzPrecondCache:
    """Cached factors for PAS 3D (theta,zeta)/L block-tridiagonal preconditioning.

    Notes
    -----
    This cache stores block-Thomas factors for a per-(species,x) block-tridiagonal-in-L
    approximation with blocks over the full (theta,zeta) plane.

    This is intended for PAS-only RHSMode=1 cases in 3D (Ntheta*Nzeta>1) where building
    dense per-x (theta,zeta,L) blocks (e.g. `xblock_tz`) is prohibitively expensive.
    """

    inv_a01: jnp.ndarray  # (S, X, 2*TZ, 2*TZ) effective inverse for the (L=0,1) combined block
    g01: jnp.ndarray  # (S, X, 2*TZ, TZ) block-Thomas factor coupling (L=0,1) block to L=2
    inv_a: jnp.ndarray  # (S, X, L-2, TZ, TZ) approximate inverse of effective diagonal blocks for L>=2
    g: jnp.ndarray  # (S, X, max(L-3,0), TZ, TZ) block-Thomas factors for back-substitution for L>=2
    c_stream: jnp.ndarray  # (X, L) scalar streaming coupling (row L from col L-1)
    c_mirror: jnp.ndarray  # (X, L) scalar mirror coupling (row L from col L-1)
    m_tz: jnp.ndarray  # (S, TZ, TZ) row-scaled (theta,zeta)-derivative matrix
    mirror_factor: jnp.ndarray  # (S, TZ) diagonal mirror factor in (theta,zeta)
    mask_active: jnp.ndarray  # (X, L) float mask (1.0 active, 0.0 inactive)
    diag_inv: jnp.ndarray  # (S, X, L) diagonal inverse for cheap high-L fallback
    n_l_use: int  # Number of L modes used in the block-tridiagonal approximation


_TRANSPORT_PRECOND_CACHE: dict[tuple[object, ...], _TransportPrecondCache] = {}
_RHSMODE1_DIAG_PRECOND_CACHE: dict[tuple[object, ...], _TransportPrecondCache] = {}
_RHSMODE1_XBLOCK_PRECOND_CACHE: dict[tuple[object, ...], _TransportXBlockPrecondCache] = {}
_RHSMODE1_SCHUR_CACHE: dict[tuple[object, ...], jnp.ndarray] = {}
