_RHSMODE1_PAS_TOKAMAK_THETA_CACHE: dict[tuple[object, ...], _PasTokamakThetaPrecondCache] = {}
_RHSMODE1_PAS_TZ_CACHE: dict[tuple[object, ...], _PasTzPrecondCache] = {}


def _precond_chunk_cols(total_size: int, n_cols: int) -> int:
    env_cols = os.environ.get("SFINCS_JAX_PRECOND_CHUNK", "").strip()
    if env_cols:
        try:
            cols = int(env_cols)
            if cols > 0:
                return min(cols, n_cols)
        except ValueError:
            pass
    env_max_mb = os.environ.get("SFINCS_JAX_PRECOND_MAX_MB", "").strip()
    try:
        max_mb = float(env_max_mb) if env_max_mb else 256.0
    except ValueError:
        max_mb = 256.0
    if max_mb <= 0:
        return n_cols
    bytes_per_row = int(total_size) * 8
    if bytes_per_row <= 0:
        return n_cols
    max_cols = max(1, int((max_mb * 1e6) // bytes_per_row))
    return min(n_cols, max_cols)


def _matvec_submatrix(
    op_pc: V3FullSystemOperator,
    *,
    col_idx: np.ndarray,
    row_idx: np.ndarray,
    total_size: int,
    chunk_cols: int,
) -> np.ndarray:
    col_idx = np.asarray(col_idx, dtype=np.int32)
    row_idx_jnp = jnp.asarray(row_idx, dtype=jnp.int32)
    blocks: list[np.ndarray] = []
    for start in range(0, int(col_idx.shape[0]), int(chunk_cols)):
        idx = col_idx[start : start + int(chunk_cols)]
        basis = jax.nn.one_hot(jnp.asarray(idx, dtype=jnp.int32), total_size, dtype=jnp.float64)
        y = jax.vmap(lambda v: apply_v3_full_system_operator_cached(op_pc, v))(basis)
        y_sub = y[:, row_idx_jnp]
        blocks.append(np.asarray(y_sub, dtype=np.float64))
    if len(blocks) == 1:
        return blocks[0]
    return np.concatenate(blocks, axis=0)


def _inverse_permutation(p: np.ndarray) -> np.ndarray:
    """Return the inverse permutation of `p` (0-based)."""
    p = np.asarray(p, dtype=np.int32).reshape((-1,))
    inv = np.empty_like(p)
    inv[p] = np.arange(int(p.size), dtype=np.int32)
    return inv


def _triangular_solve_lower_padded(
    *,
    lower_idx: jnp.ndarray,
    lower_val: jnp.ndarray,
    b: jnp.ndarray,
) -> jnp.ndarray:
    """Solve a unit-lower-triangular system `L y = b` in JAX.

    `lower_idx`/`lower_val` define the strictly-lower entries per row, padded with -1.
    """
    b = jnp.asarray(b, dtype=jnp.float64)
    n = int(b.shape[0])
    y = jnp.zeros_like(b)
    if lower_idx.size == 0:
        return b

    def _body(i, y_vec):
        idx = lower_idx[i]
        val = lower_val[i]
        mask = idx >= 0
        idx_safe = jnp.where(mask, idx, 0)
        contrib = jnp.sum(jnp.where(mask, val * y_vec[idx_safe], 0.0))
        yi = b[i] - contrib
        return y_vec.at[i].set(yi, unique_indices=True)

    return jax.lax.fori_loop(0, n, _body, y)


def _triangular_solve_upper_padded(
    *,
    upper_idx: jnp.ndarray,
    upper_val: jnp.ndarray,
    upper_diag: jnp.ndarray,
    b: jnp.ndarray,
) -> jnp.ndarray:
    """Solve an upper-triangular system `U x = b` in JAX.

    `upper_idx`/`upper_val` define strictly-upper entries per row, padded with -1.
    """
    b = jnp.asarray(b, dtype=jnp.float64)
    n = int(b.shape[0])
    x = jnp.zeros_like(b)
    if upper_idx.size == 0:
        return b / upper_diag

    def _body(i, x_vec):
        row = n - 1 - i
        idx = upper_idx[row]
        val = upper_val[row]
        mask = idx >= 0
        idx_safe = jnp.where(mask, idx, 0)
        contrib = jnp.sum(jnp.where(mask, val * x_vec[idx_safe], 0.0))
        xi = (b[row] - contrib) / upper_diag[row]
        return x_vec.at[row].set(xi, unique_indices=True)

    return jax.lax.fori_loop(0, n, _body, x)


def _hash_array(arr: jnp.ndarray | np.ndarray) -> str:
    arr_np = np.asarray(arr, dtype=np.float64)
    return hashlib.blake2b(arr_np.tobytes(), digest_size=8).hexdigest()


def _rhsmode1_dense_fallback_max(op: V3FullSystemOperator) -> int:
    return _rhs1_dense_fallback_max_impl(op)


def _rhsmode1_precond_cache_key(op: V3FullSystemOperator, kind: str) -> tuple[object, ...]:
    nxi_for_x = np.asarray(op.fblock.collisionless.n_xi_for_x, dtype=np.int32)
    precond_dtype = str(_precond_dtype())
    # RHS-only gradients do not affect the operator; omit them so preconditioners
    # can be reused across whichRHS/scan points.
    return (
        kind,
        precond_dtype,
        int(op.rhs_mode),
        int(op.n_species),
        int(op.n_x),
        int(op.n_xi),
        int(op.n_theta),
        int(op.n_zeta),
        int(op.constraint_scheme),
        int(op.quasineutrality_option),
        bool(op.include_phi1),
        bool(op.include_phi1_in_kinetic),
        bool(op.with_adiabatic),
        float(op.alpha),
        float(op.delta),
        float(op.dphi_hat_dpsi_hat),
        _hash_array(op.adiabatic_z),
        _hash_array(op.adiabatic_nhat),
        _hash_array(op.adiabatic_that),
        _hash_array(op.z_s),
        _hash_array(op.m_hat),
        _hash_array(op.t_hat),
        _hash_array(op.n_hat),
        _hash_array(op.theta_weights),
        _hash_array(op.zeta_weights),
        _hash_array(op.b_hat),
        _hash_array(op.d_hat),
        _hash_array(op.b_hat_sub_theta),
        _hash_array(op.b_hat_sub_zeta),
        _hash_array(op.x),
        _hash_array(op.x_weights),
        tuple(nxi_for_x.tolist()),
    )


def _transport_precond_cache_key(op: V3FullSystemOperator, kind: str) -> tuple[object, ...]:
    nxi_for_x = np.asarray(op.fblock.collisionless.n_xi_for_x, dtype=np.int32)
    pas = op.fblock.pas
    fp = op.fblock.fp
    precond_dtype = str(_precond_dtype())
    return (
        kind,
        precond_dtype,
        int(op.n_species),
        int(op.n_x),
        int(op.n_xi),
        int(op.n_theta),
        int(op.n_zeta),
        float(op.fblock.identity_shift),
        bool(pas is not None),
        float(pas.nu_n) if pas is not None else None,
        float(pas.krook) if pas is not None else None,
        _hash_array(pas.nu_d_hat) if pas is not None else None,
        bool(fp is not None),
        _hash_array(fp.mat) if fp is not None else None,
        tuple(nxi_for_x.tolist()),
    )


def _build_rhsmode23_collision_preconditioner(
    *,
    op: V3FullSystemOperator,
    reduce_full: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
    expand_reduced: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
) -> Callable[[jnp.ndarray], jnp.ndarray]:
    """Cheap diagonal preconditioner for RHSMode=2/3 transport solves.

    Uses analytic diagonal contributions from the collision operator (PAS or FP) plus
    the identity shift, and is diagonal in (theta, zeta).
    """
    cache_key = _transport_precond_cache_key(op, "collision_diag")
    precond_dtype = _precond_dtype()
    cached = _TRANSPORT_PRECOND_CACHE.get(cache_key)
    if cached is None:
        f_shape = op.fblock.f_shape
        n_species, n_x, n_l, _, _ = f_shape
        diag = jnp.zeros(f_shape, dtype=jnp.float64)

        # Identity shift contribution.
        if float(op.fblock.identity_shift) != 0.0:
            diag = diag + jnp.asarray(op.fblock.identity_shift, dtype=jnp.float64)

        # Pitch-angle scattering diagonal term.
        if op.fblock.pas is not None:
            pas = op.fblock.pas
            l = jnp.arange(n_l, dtype=jnp.float64)
            factor_l = 0.5 * (l * (l + 1.0) + 2.0 * pas.krook)
            pas_diag = pas.nu_n * pas.nu_d_hat[:, :, None] * factor_l[None, None, :]
            diag = diag + pas_diag[:, :, :, None, None]

        # Fokker-Planck diagonal term (self-species, diagonal in x).
        if op.fblock.fp is not None:
            mat = op.fblock.fp.mat  # (S,S,L,X,X)
            diag_x = jnp.diagonal(mat, axis1=3, axis2=4)  # (S,S,L,X)
            diag_self = jnp.diagonal(diag_x, axis1=0, axis2=1)  # (L,X,S)
            diag_self = jnp.transpose(diag_self, (2, 1, 0))  # (S,X,L)
            diag = diag + diag_self[:, :, :, None, None]

        # Mask out inactive L-modes.
        nxi_for_x = op.fblock.collisionless.n_xi_for_x.astype(jnp.int32)
        mask = jnp.arange(n_l, dtype=jnp.int32)[None, :] < nxi_for_x[:, None]  # (X,L)
        mask = mask[None, :, :, None, None]  # (1,X,L,1,1)
        diag = jnp.where(mask, diag, jnp.asarray(1.0, dtype=jnp.float64))

        reg_env = os.environ.get("SFINCS_JAX_TRANSPORT_PRECOND_REG", "").strip()
        try:
            reg = float(reg_env) if reg_env else 1e-10
        except ValueError:
            reg = 1e-10
        inv_diag_f = 1.0 / (diag + float(reg))
        cached = _TransportPrecondCache(inv_diag_f=jnp.asarray(inv_diag_f, dtype=precond_dtype))
        _TRANSPORT_PRECOND_CACHE[cache_key] = cached

    inv_diag_f = cached.inv_diag_f

    def _apply_full(r_full: jnp.ndarray) -> jnp.ndarray:
        r_full = jnp.asarray(r_full, dtype=precond_dtype)
        f = r_full[: op.f_size].reshape(op.fblock.f_shape)
        z_f = f * inv_diag_f
        tail = r_full[op.f_size :]
        z_full = jnp.concatenate([z_f.reshape((-1,)), tail], axis=0)
        return jnp.asarray(z_full, dtype=jnp.float64)

    if reduce_full is None or expand_reduced is None:
        return _apply_full

    def _apply_reduced(r_reduced: jnp.ndarray) -> jnp.ndarray:
        z_full = _apply_full(expand_reduced(r_reduced))
        return reduce_full(z_full)

    return _apply_reduced


def _build_rhsmode23_sxblock_preconditioner(
    *,
    op: V3FullSystemOperator,
    reduce_full: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
    expand_reduced: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
) -> Callable[[jnp.ndarray], jnp.ndarray]:
    """Lightweight block-Jacobi preconditioner for RHSMode=2/3 using species/x blocks.

    Builds per-L blocks across species and x from the collision operator (PAS/FP) plus
    identity shift. This avoids matvec-based assembly while capturing cross-species/x
    coupling in the FP operator.
    """
    if op.fblock.fp is None:
        return _build_rhsmode23_collision_preconditioner(op=op, reduce_full=reduce_full, expand_reduced=expand_reduced)

    low_rank_env = os.environ.get("SFINCS_JAX_TRANSPORT_FP_LOW_RANK_K", "").strip()
    if not low_rank_env:
        low_rank_env = os.environ.get("SFINCS_JAX_FP_LOW_RANK_K", "").strip()
    low_rank_env = low_rank_env.strip().lower()
    low_rank_auto = low_rank_env in {"", "auto"}
    if low_rank_env and low_rank_env != "auto":
        try:
            low_rank_k = int(low_rank_env)
        except ValueError:
            low_rank_k = 0
    else:
        low_rank_k = 0

    f_shape = op.fblock.f_shape
    n_species, n_x, n_l, _, _ = f_shape
    n_block = n_species * n_x
    if low_rank_auto and low_rank_k <= 0 and n_block >= 24:
        low_rank_k = min(8, n_block)

    precond_dtype = _precond_dtype()
    if low_rank_k > 0:
        rank_k = min(int(low_rank_k), int(n_block))
        cache_key = _transport_precond_cache_key(op, f"collision_sxblock_lr_{rank_k}")
        cached_lr = _TRANSPORT_SXBLOCK_LR_PRECOND_CACHE.get(cache_key)
        if cached_lr is None:
            mat = np.asarray(op.fblock.fp.mat, dtype=np.float64)  # (S,S,L,X,X)
            reg_env = os.environ.get("SFINCS_JAX_TRANSPORT_PRECOND_REG", "").strip()
            try:
                reg = float(reg_env) if reg_env else 1e-10
            except ValueError:
                reg = 1e-10
            identity_shift = float(op.fblock.identity_shift)
            pas_diag = None
            if op.fblock.pas is not None:
                pas = op.fblock.pas
                l_arr = np.arange(n_l, dtype=np.float64)
                factor_l = 0.5 * (l_arr * (l_arr + 1.0) + 2.0 * float(pas.krook))
                pas_diag = float(pas.nu_n) * np.asarray(pas.nu_d_hat, dtype=np.float64)[:, :, None] * factor_l[None, None, :]

            nxi_for_x = np.asarray(op.fblock.collisionless.n_xi_for_x, dtype=np.int32)
            d_inv = np.zeros((n_l, n_block), dtype=np.float64)
            d_inv_u = np.zeros((n_l, n_block, rank_k), dtype=np.float64)
            v_lr = np.zeros((n_l, rank_k, n_block), dtype=np.float64)
            m_inv = np.zeros((n_l, rank_k, rank_k), dtype=np.float64)

            for l in range(n_l):
                a_fp = np.array(mat[:, :, l, :, :], dtype=np.float64, copy=True)  # (S,S,X,X)
                a_fp = a_fp.transpose(0, 2, 1, 3).reshape((n_block, n_block))
                diag = np.full((n_block,), identity_shift + reg, dtype=np.float64)
                if pas_diag is not None:
                    diag += pas_diag[:, :, l].reshape((n_block,))
                inactive_x = np.where(nxi_for_x <= l)[0]
                if inactive_x.size:
                    for ix in inactive_x:
                        for s in range(n_species):
                            idx = s * n_x + int(ix)
                            a_fp[idx, :] = 0.0
                            a_fp[:, idx] = 0.0
                            diag[idx] = 1.0
                d_inv_l = 1.0 / diag
                d_inv[l, :] = d_inv_l
                if rank_k > 0:
                    try:
                        u, svals, vt = np.linalg.svd(a_fp, full_matrices=False)
                    except np.linalg.LinAlgError:
                        u, svals, vt = np.linalg.svd(a_fp + 1e-12 * np.eye(n_block), full_matrices=False)
                    k_use = min(rank_k, int(svals.shape[0]))
                    if k_use > 0:
                        u = u[:, :k_use]
                        svals = svals[:k_use]
                        vt = vt[:k_use, :]
                        s_sqrt = np.sqrt(np.maximum(svals, 0.0))
                        u_lr = u * s_sqrt[None, :]
                        v_lr_l = s_sqrt[:, None] * vt
                        d_inv_u_l = d_inv_l[:, None] * u_lr
                        m = np.eye(k_use, dtype=np.float64) + v_lr_l @ d_inv_u_l
                        try:
                            m_inv_l = np.linalg.inv(m)
                        except np.linalg.LinAlgError:
                            m_inv_l = np.linalg.pinv(m, rcond=1e-12)
                        if not np.all(np.isfinite(m_inv_l)):
                            m_inv_l = np.linalg.pinv(m, rcond=1e-12)
                        d_inv_u[l, :, :k_use] = d_inv_u_l
                        v_lr[l, :k_use, :] = v_lr_l
                        m_inv[l, :k_use, :k_use] = m_inv_l

            cached_lr = _LowRankXBlockPrecondCache(
                d_inv=jnp.asarray(d_inv, dtype=precond_dtype),
                d_inv_u=jnp.asarray(d_inv_u, dtype=precond_dtype),
                v=jnp.asarray(v_lr, dtype=precond_dtype),
                m_inv=jnp.asarray(m_inv, dtype=precond_dtype),
            )
            _TRANSPORT_SXBLOCK_LR_PRECOND_CACHE[cache_key] = cached_lr

        d_inv = cached_lr.d_inv
        d_inv_u = cached_lr.d_inv_u
        v_lr = cached_lr.v
        m_inv = cached_lr.m_inv

        def _apply_full(r_full: jnp.ndarray) -> jnp.ndarray:
            r_full = jnp.asarray(r_full, dtype=precond_dtype)
            f = r_full[: op.f_size].reshape(op.fblock.f_shape)  # (S,X,L,T,Z)
            f_l = jnp.transpose(f, (2, 0, 1, 3, 4))  # (L,S,X,T,Z)
            f_l = f_l.reshape((int(op.n_xi), int(op.n_species) * int(op.n_x), int(op.n_theta), int(op.n_zeta)))
            d_r = d_inv[:, :, None, None] * f_l
            if rank_k > 0:
                tmp = jnp.einsum("lkn,lntz->lktz", v_lr, d_r)
                tmp2 = jnp.einsum("lkm,lmtz->lktz", m_inv, tmp)
                corr = jnp.einsum("lnk,lktz->lntz", d_inv_u, tmp2)
                z_l = d_r - corr
            else:
                z_l = d_r
            z_l = z_l.reshape((int(op.n_xi), int(op.n_species), int(op.n_x), int(op.n_theta), int(op.n_zeta)))
            z_f = jnp.transpose(z_l, (1, 2, 0, 3, 4))  # (S,X,L,T,Z)
            tail = r_full[op.f_size :]
            z_full = jnp.concatenate([z_f.reshape((-1,)), tail], axis=0)
            return jnp.asarray(z_full, dtype=jnp.float64)

        if reduce_full is None or expand_reduced is None:
            return _apply_full

        def _apply_reduced(r_reduced: jnp.ndarray) -> jnp.ndarray:
            z_full = _apply_full(expand_reduced(r_reduced))
            return reduce_full(z_full)

        return _apply_reduced

    cache_key = _transport_precond_cache_key(op, "collision_sxblock")
    cached = _TRANSPORT_SXBLOCK_PRECOND_CACHE.get(cache_key)
    if cached is None:
        f_shape = op.fblock.f_shape
        n_species, n_x, n_l, _, _ = f_shape
        n_block = n_species * n_x
        inv_block = np.zeros((n_l, n_block, n_block), dtype=np.float64)
        mat = np.asarray(op.fblock.fp.mat, dtype=np.float64)  # (S,S,L,X,X)

        reg_env = os.environ.get("SFINCS_JAX_TRANSPORT_PRECOND_REG", "").strip()
        try:
            reg = float(reg_env) if reg_env else 1e-10
        except ValueError:
            reg = 1e-10

        identity_shift = float(op.fblock.identity_shift)
        pas_diag = None
        if op.fblock.pas is not None:
            pas = op.fblock.pas
            l_arr = np.arange(n_l, dtype=np.float64)
            factor_l = 0.5 * (l_arr * (l_arr + 1.0) + 2.0 * float(pas.krook))
            pas_diag = float(pas.nu_n) * np.asarray(pas.nu_d_hat, dtype=np.float64)[:, :, None] * factor_l[None, None, :]

        nxi_for_x = np.asarray(op.fblock.collisionless.n_xi_for_x, dtype=np.int32)
        for l in range(n_l):
            a = np.array(mat[:, :, l, :, :], dtype=np.float64, copy=True)  # (S,S,X,X)
            a = a.transpose(0, 2, 1, 3).reshape((n_block, n_block))
            if identity_shift != 0.0:
                a[np.arange(n_block), np.arange(n_block)] += identity_shift
            if pas_diag is not None:
                diag_add = pas_diag[:, :, l].reshape((n_block,))
                a[np.arange(n_block), np.arange(n_block)] += diag_add
            if reg != 0.0:
                a[np.arange(n_block), np.arange(n_block)] += reg

            inactive_x = np.where(nxi_for_x <= l)[0]
            if inactive_x.size:
                for ix in inactive_x:
                    for s in range(n_species):
                        idx = s * n_x + int(ix)
                        a[idx, :] = 0.0
                        a[:, idx] = 0.0
                        a[idx, idx] = 1.0

            try:
                inv = np.linalg.inv(a)
            except np.linalg.LinAlgError:
                inv = np.linalg.pinv(a, rcond=1e-12)
            if not np.all(np.isfinite(inv)):
                inv = np.linalg.pinv(a, rcond=1e-12)
            inv_block[l, :, :] = inv

        cached = _TransportXBlockPrecondCache(inv_xblock=jnp.asarray(inv_block, dtype=precond_dtype))
        _TRANSPORT_SXBLOCK_PRECOND_CACHE[cache_key] = cached

    inv_block = cached.inv_xblock  # (L, S*X, S*X)

    def _apply_full(r_full: jnp.ndarray) -> jnp.ndarray:
        r_full = jnp.asarray(r_full, dtype=precond_dtype)
        f = r_full[: op.f_size].reshape(op.fblock.f_shape)  # (S,X,L,T,Z)
        f_l = jnp.transpose(f, (2, 0, 1, 3, 4))  # (L,S,X,T,Z)
        f_l = f_l.reshape((int(op.n_xi), int(op.n_species) * int(op.n_x), int(op.n_theta), int(op.n_zeta)))
        z_l = jnp.einsum("lmn,lntz->lmtz", inv_block, f_l)
        z_l = z_l.reshape((int(op.n_xi), int(op.n_species), int(op.n_x), int(op.n_theta), int(op.n_zeta)))
        z_f = jnp.transpose(z_l, (1, 2, 0, 3, 4))  # (S,X,L,T,Z)
        tail = r_full[op.f_size :]
        z_full = jnp.concatenate([z_f.reshape((-1,)), tail], axis=0)
        return jnp.asarray(z_full, dtype=jnp.float64)

    if reduce_full is None or expand_reduced is None:
        return _apply_full

    def _apply_reduced(r_reduced: jnp.ndarray) -> jnp.ndarray:
        z_full = _apply_full(expand_reduced(r_reduced))
        return reduce_full(z_full)

    return _apply_reduced


def _build_rhsmode23_xmg_preconditioner(
    *,
    op: V3FullSystemOperator,
    reduce_full: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
    expand_reduced: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
) -> Callable[[jnp.ndarray], jnp.ndarray]:
    """Two-level additive x-grid preconditioner for RHSMode=2/3 collision operators.

    Applies a fine-grid diagonal inverse plus a coarse-grid correction on the speed grid.
    The coarse solve is block-diagonal in species and L, ignoring cross-species coupling.
    """
    stride_env = os.environ.get("SFINCS_JAX_XMG_STRIDE", "").strip()
    try:
        stride = int(stride_env) if stride_env else 2
    except ValueError:
        stride = 2
    stride = max(1, stride)
    cache_key = _transport_precond_cache_key(op, f"xmg_{stride}")
    precond_dtype = _precond_dtype()
    cached = _TRANSPORT_XMG_PRECOND_CACHE.get(cache_key)
    if cached is None:
        f_shape = op.fblock.f_shape
        n_species, n_x, n_l, _, _ = f_shape
        coarse_idx = np.arange(0, n_x, stride, dtype=np.int32)
        n_coarse = int(coarse_idx.shape[0])
        coarse_map = {int(ix): int(i) for i, ix in enumerate(coarse_idx)}

        diag = np.zeros(f_shape, dtype=np.float64)
        if float(op.fblock.identity_shift) != 0.0:
            diag = diag + float(op.fblock.identity_shift)
        if op.fblock.pas is not None:
            pas = op.fblock.pas
            l_arr = np.arange(n_l, dtype=np.float64)
            factor_l = 0.5 * (l_arr * (l_arr + 1.0) + 2.0 * float(pas.krook))
            pas_diag = float(pas.nu_n) * np.asarray(pas.nu_d_hat, dtype=np.float64)[:, :, None] * factor_l[None, None, :]
            diag = diag + pas_diag[:, :, :, None, None]
        if op.fblock.fp is not None:
            mat = np.asarray(op.fblock.fp.mat, dtype=np.float64)  # (S,S,L,X,X)
            diag_x = np.diagonal(mat, axis1=3, axis2=4)  # (S,S,L,X)
            diag_self = np.diagonal(diag_x, axis1=0, axis2=1)  # (L,X,S)
            diag_self = np.transpose(diag_self, (2, 1, 0))  # (S,X,L)
            diag = diag + diag_self[:, :, :, None, None]

        nxi_for_x = np.asarray(op.fblock.collisionless.n_xi_for_x, dtype=np.int32)
        mask = np.arange(n_l, dtype=np.int32)[None, :] < nxi_for_x[:, None]  # (X,L)
        mask = mask[None, :, :, None, None]
        diag = np.where(mask, diag, 1.0)

        reg_env = os.environ.get("SFINCS_JAX_TRANSPORT_PRECOND_REG", "").strip()
        try:
            reg = float(reg_env) if reg_env else 1e-10
        except ValueError:
            reg = 1e-10
        inv_diag_f = 1.0 / (diag + float(reg))

        coarse_inv = np.zeros((n_species, n_l, n_coarse, n_coarse), dtype=np.float64)
        mat_fp = None
        if op.fblock.fp is not None:
            mat_fp = np.asarray(op.fblock.fp.mat, dtype=np.float64)  # (S,S,L,X,X)
        identity_shift = float(op.fblock.identity_shift)
        pas_diag = None
        if op.fblock.pas is not None:
            pas = op.fblock.pas
            l_arr = np.arange(n_l, dtype=np.float64)
            factor_l = 0.5 * (l_arr * (l_arr + 1.0) + 2.0 * float(pas.krook))
            pas_diag = float(pas.nu_n) * np.asarray(pas.nu_d_hat, dtype=np.float64)[:, :, None] * factor_l[None, None, :]

        for s in range(n_species):
            for l in range(n_l):
                if mat_fp is None:
                    a = np.zeros((n_x, n_x), dtype=np.float64)
                else:
                    a = np.array(mat_fp[s, s, l, :, :], dtype=np.float64, copy=True)
                a = a[np.ix_(coarse_idx, coarse_idx)]
                diag_vec = np.full((n_coarse,), identity_shift + reg, dtype=np.float64)
                if pas_diag is not None:
                    diag_vec += pas_diag[s, coarse_idx, l]
                a[np.arange(n_coarse), np.arange(n_coarse)] += diag_vec

                inactive_x = np.where(nxi_for_x <= l)[0]
                if inactive_x.size:
                    for ix in inactive_x:
                        j = coarse_map.get(int(ix))
                        if j is not None:
                            a[j, :] = 0.0
                            a[:, j] = 0.0
                            a[j, j] = 1.0

                try:
                    inv = np.linalg.inv(a)
                except np.linalg.LinAlgError:
                    inv = np.linalg.pinv(a, rcond=1e-12)
                if not np.all(np.isfinite(inv)):
                    inv = np.linalg.pinv(a, rcond=1e-12)
                coarse_inv[s, l, :, :] = inv

        cached = _TransportXmgPrecondCache(
            inv_diag_f=jnp.asarray(inv_diag_f, dtype=precond_dtype),
            coarse_inv=jnp.asarray(coarse_inv, dtype=precond_dtype),
            coarse_idx=jnp.asarray(coarse_idx, dtype=jnp.int32),
        )
        _TRANSPORT_XMG_PRECOND_CACHE[cache_key] = cached

    inv_diag_f = cached.inv_diag_f
    coarse_inv = cached.coarse_inv
    coarse_idx = cached.coarse_idx

    def _apply_full(r_full: jnp.ndarray) -> jnp.ndarray:
        r_full = jnp.asarray(r_full, dtype=precond_dtype)
        f = r_full[: op.f_size].reshape(op.fblock.f_shape)  # (S,X,L,T,Z)
        z_f = f * inv_diag_f
        f_sl = jnp.transpose(f, (0, 2, 1, 3, 4))  # (S,L,X,T,Z)
        f_coarse = f_sl[:, :, coarse_idx, :, :]
        z_coarse = jnp.einsum("slij,sljtz->slitz", coarse_inv, f_coarse)
        corr_sl = jnp.zeros_like(f_sl)
        corr_sl = corr_sl.at[:, :, coarse_idx, :, :].set(z_coarse)
        corr = jnp.transpose(corr_sl, (0, 2, 1, 3, 4))
        z_f = z_f + corr
        tail = r_full[op.f_size :]
        z_full = jnp.concatenate([z_f.reshape((-1,)), tail], axis=0)
        return jnp.asarray(z_full, dtype=jnp.float64)

    if reduce_full is None or expand_reduced is None:
        return _apply_full

    def _apply_reduced(r_reduced: jnp.ndarray) -> jnp.ndarray:
        z_full = _apply_full(expand_reduced(r_reduced))
        return reduce_full(z_full)

    return _apply_reduced


def _build_rhsmode1_xmg_preconditioner(
    *,
    op: V3FullSystemOperator,
    reduce_full: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
    expand_reduced: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
    stride_override: int | None = None,
) -> Callable[[jnp.ndarray], jnp.ndarray]:
    """Two-level additive x-grid preconditioner for RHSMode=1 collision operators.

    Uses the same coarse-x correction as the transport x-multigrid preconditioner,
    but applies it to the RHSMode=1 operator (including PAS/FP diagonals).
    """
    # For PAS+Er systems, inverting dense x-blocks derived from ddx matrices can be
    # extremely ill-conditioned. Use a stable x-upwind solve instead.
    if op.fblock.pas is not None and op.fblock.fp is None and op.fblock.er_xdot is not None:
        return _build_rhsmode1_xupwind_preconditioner(
            op=op, reduce_full=reduce_full, expand_reduced=expand_reduced
        )
    stride_env = os.environ.get("SFINCS_JAX_RHSMODE1_XMG_STRIDE", "").strip()
    if not stride_env:
        stride_env = os.environ.get("SFINCS_JAX_XMG_STRIDE", "").strip()
    try:
        if stride_override is not None:
            stride = int(stride_override)
        elif stride_env:
            stride = int(stride_env)
        else:
            # Large FP systems benefit from a slightly coarser x-grid in the default
            # xmg preconditioner: it improves conditioning of the coarse correction and
            # lowers setup/apply cost enough to keep large CPU runs within practical
            # wall-clock limits.
            if (
                op.fblock.fp is not None
                and op.fblock.pas is None
                and int(op.total_size) >= 120000
            ):
                stride = 4
            else:
                stride = 2
    except ValueError:
        stride = 2
    stride = max(1, stride)
    cache_key = _rhsmode1_precond_cache_key(op, f"xmg_{stride}")
    precond_dtype = _precond_dtype()
    cached = _RHSMODE1_XMG_PRECOND_CACHE.get(cache_key)
    if cached is None:
        f_shape = op.fblock.f_shape
        n_species, n_x, n_l, _, _ = f_shape
        coarse_idx = np.arange(0, n_x, stride, dtype=np.int32)
        n_coarse = int(coarse_idx.shape[0])
        coarse_map = {int(ix): int(i) for i, ix in enumerate(coarse_idx)}

        diag = np.zeros(f_shape, dtype=np.float64)
        if float(op.fblock.identity_shift) != 0.0:
            diag = diag + float(op.fblock.identity_shift)
        if op.fblock.pas is not None:
            pas = op.fblock.pas
            l_arr = np.arange(n_l, dtype=np.float64)
            factor_l = 0.5 * (l_arr * (l_arr + 1.0) + 2.0 * float(pas.krook))
            pas_diag = float(pas.nu_n) * np.asarray(pas.nu_d_hat, dtype=np.float64)[:, :, None] * factor_l[None, None, :]
            diag = diag + pas_diag[:, :, :, None, None]
        if op.fblock.fp is not None:
            mat = np.asarray(op.fblock.fp.mat, dtype=np.float64)  # (S,S,L,X,X)
            diag_x = np.diagonal(mat, axis1=3, axis2=4)  # (S,S,L,X)
            diag_self = np.diagonal(diag_x, axis1=0, axis2=1)  # (L,X,S)
            diag_self = np.transpose(diag_self, (2, 1, 0))  # (S,X,L)
            diag = diag + diag_self[:, :, :, None, None]

        nxi_for_x = np.asarray(op.fblock.collisionless.n_xi_for_x, dtype=np.int32)
        mask = np.arange(n_l, dtype=np.int32)[None, :] < nxi_for_x[:, None]  # (X,L)
        mask = mask[None, :, :, None, None]
        diag = np.where(mask, diag, 1.0)

        reg_env = os.environ.get("SFINCS_JAX_RHSMODE1_PRECOND_REG", "").strip()
        try:
            reg = float(reg_env) if reg_env else 1e-10
        except ValueError:
            reg = 1e-10
        reg_l0 = float(reg)
        if op.fblock.pas is not None and op.fblock.fp is None and op.fblock.er_xdot is not None:
            # The PAS operator can have an exactly-zero L=0 diagonal (krook=0). With Er xDot enabled,
            # the x-coupled block can be near-singular if we only add an extremely small regularization,
            # leading to huge preconditioner entries and GMRES blow-up. Use a modest L=0 shift here to
            # keep the xmg inverse numerically stable.
            reg_l0 = max(reg_l0, 1.0)
        reg_by_l = np.full((n_l,), float(reg), dtype=np.float64)
        if n_l > 0:
            reg_by_l[0] = reg_l0
        inv_diag_f = 1.0 / (diag + reg_by_l[None, None, :, None, None])

        coarse_inv = np.zeros((n_species, n_l, n_coarse, n_coarse), dtype=np.float64)
        mat_fp = None
        if op.fblock.fp is not None:
            mat_fp = np.asarray(op.fblock.fp.mat, dtype=np.float64)  # (S,S,L,X,X)
        identity_shift = float(op.fblock.identity_shift)
        pas_diag = None
        if op.fblock.pas is not None:
            pas = op.fblock.pas
            l_arr = np.arange(n_l, dtype=np.float64)
            factor_l = 0.5 * (l_arr * (l_arr + 1.0) + 2.0 * float(pas.krook))
            pas_diag = float(pas.nu_n) * np.asarray(pas.nu_d_hat, dtype=np.float64)[:, :, None] * factor_l[None, None, :]

        # Optional dense-x coupling from the v3 Er xDot term.
        #
        # For PAS-only systems, the collision operator is diagonal in x, so the x-multigrid
        # preconditioner is otherwise ineffective. The Er xDot term introduces dense ddx
        # coupling in x (see `apply_er_xdot_v3`), so we include a flux-surface-averaged
        # diagonal-in-L approximation here to recover useful x-coupling at low cost.
        xdot_x_part: np.ndarray | None = None  # (Xc,Xc)
        xdot_coef_l: np.ndarray | None = None  # (L,)
        xdot_rms = 0.0
        if op.fblock.er_xdot is not None:
            try:
                er = op.fblock.er_xdot
                alpha = float(np.asarray(er.alpha, dtype=np.float64).reshape(()))
                delta = float(np.asarray(er.delta, dtype=np.float64).reshape(()))
                dphi = float(np.asarray(er.dphi_hat_dpsi_hat, dtype=np.float64).reshape(()))
                d_hat = np.asarray(er.d_hat, dtype=np.float64)  # (T,Z)
                b_hat = np.asarray(er.b_hat, dtype=np.float64)  # (T,Z)
                b_sub_theta = np.asarray(er.b_hat_sub_theta, dtype=np.float64)  # (T,Z)
                b_sub_zeta = np.asarray(er.b_hat_sub_zeta, dtype=np.float64)  # (T,Z)
                db_dtheta = np.asarray(er.db_hat_dtheta, dtype=np.float64)  # (T,Z)
                db_dzeta = np.asarray(er.db_hat_dzeta, dtype=np.float64)  # (T,Z)

                factor0 = -(alpha * delta * dphi) / 4.0  # adjointFactor=1
                xdot_factor = factor0 * d_hat / (b_hat**3) * (b_sub_theta * db_dzeta - b_sub_zeta * db_dtheta)  # (T,Z)

                theta_w = np.asarray(op.theta_weights, dtype=np.float64)
                zeta_w = np.asarray(op.zeta_weights, dtype=np.float64)
                d_hat_full = np.asarray(op.d_hat, dtype=np.float64)
                fs_factor = (theta_w[:, None] * zeta_w[None, :]) / d_hat_full  # (T,Z), un-normalized
                # Signed flux-surface averages of xdot_factor can cancel (common for tokamak-like
                # geometries), which would incorrectly eliminate dense-x coupling from the
                # preconditioner. Use an RMS magnitude instead to capture the typical scale.
                fs_sum = float(np.sum(fs_factor))
                if fs_sum > 0.0:
                    xdot_rms = float(np.sqrt(np.sum(fs_factor * (xdot_factor * xdot_factor)) / fs_sum))
                else:
                    xdot_rms = 0.0

                l_vec = np.arange(n_l, dtype=np.float64)
                denom = (2.0 * l_vec + 3.0) * (2.0 * l_vec - 1.0)
                diag_coef = 2.0 * (3.0 * l_vec * l_vec + 3.0 * l_vec - 2.0) / denom
                # force0RadialCurrentInEquilibrium=.true. (v3 default) -> xdotFactor2 = 0.
                xdot_coef_l = diag_coef * xdot_rms

                x_arr = np.asarray(er.x, dtype=np.float64)
                ddx = np.asarray(er.ddx_plus, dtype=np.float64)
                x_part = x_arr[:, None] * ddx  # (X,X)
                xdot_x_part = x_part[np.ix_(coarse_idx, coarse_idx)]
            except Exception:  # noqa: BLE001
                xdot_x_part = None
                xdot_coef_l = None
                xdot_rms = 0.0

        # If PAS+Er includes ΔL=±2 xDot coupling, build a small coupled (L,x) coarse inverse
        # for low Legendre modes. This is much stronger than per-L coarse inverses, while still
        # cheap: we only couple a few low-L modes and only on the coarse x grid.
        coarse_inv_lblock: np.ndarray | None = None  # (S, Lb*Xc, Lb*Xc)
        lblock = 0
        pinv_env = os.environ.get("SFINCS_JAX_RHSMODE1_XMG_PINV_RCOND", "").strip()
        try:
            pinv_rcond = float(pinv_env) if pinv_env else 1e-12
        except ValueError:
            pinv_rcond = 1e-12
        if (
            xdot_x_part is not None
            and xdot_coef_l is not None
            and float(xdot_rms) != 0.0
            and op.fblock.pas is not None
            and mat_fp is None
            and n_l >= 3
        ):
            # Default to a small block that captures the first few ΔL=±2 couplings.
            # L is small (Nxi is usually O(10)), so a block of size 6 is still cheap.
            lblock = int(min(int(n_l), 6))
            n_block = int(lblock * n_coarse)
            coarse_inv_lblock = np.zeros((n_species, n_block, n_block), dtype=np.float64)

            # Coefficients for ΔL=±2 couplings in `apply_er_xdot_v3`:
            #   row L gets col L+2 with coef sup2[L]
            #   row L gets col L-2 with coef sub2[L]
            l_vec = np.arange(n_l, dtype=np.float64)
            sup2 = np.zeros((n_l,), dtype=np.float64)
            sub2 = np.zeros((n_l,), dtype=np.float64)
            if n_l >= 3:
                l0 = l_vec[:-2]
                sup2[:-2] = (l0 + 1.0) * (l0 + 2.0) / ((2.0 * l0 + 5.0) * (2.0 * l0 + 3.0))
                l2 = l_vec[2:]
                sub2[2:] = l2 * (l2 - 1.0) / ((2.0 * l2 - 3.0) * (2.0 * l2 - 1.0))

            for s in range(n_species):
                a = np.zeros((n_block, n_block), dtype=np.float64)
                # Base diagonal blocks (PAS + identity shift + regularization).
                for l in range(lblock):
                    i0 = int(l * n_coarse)
                    i1 = i0 + n_coarse
                    block = np.zeros((n_coarse, n_coarse), dtype=np.float64)
                    reg_eff = reg_l0 if l == 0 else float(reg)
                    diag_vec = np.full((n_coarse,), identity_shift + reg_eff, dtype=np.float64)
                    if pas_diag is not None:
                        diag_vec = diag_vec + pas_diag[s, coarse_idx, l]
                    block[np.arange(n_coarse), np.arange(n_coarse)] += diag_vec
                    a[i0:i1, i0:i1] += block

                # Add xDot dense-x coupling (diagonal + ΔL=±2 couplings) using an RMS magnitude.
                for l in range(lblock):
                    i0 = int(l * n_coarse)
                    i1 = i0 + n_coarse
                    a[i0:i1, i0:i1] += float(xdot_coef_l[l]) * xdot_x_part
                    if l + 2 < lblock:
                        j0 = int((l + 2) * n_coarse)
                        j1 = j0 + n_coarse
                        a[i0:i1, j0:j1] += float(sup2[l] * xdot_rms) * xdot_x_part
                    if l - 2 >= 0:
                        j0 = int((l - 2) * n_coarse)
                        j1 = j0 + n_coarse
                        a[i0:i1, j0:j1] += float(sub2[l] * xdot_rms) * xdot_x_part

                # Identity rows/cols for inactive (x,L) combinations.
                for l in range(lblock):
                    inactive_x = np.where(nxi_for_x <= l)[0]
                    if not inactive_x.size:
                        continue
                    for ix in inactive_x:
                        idx = coarse_map.get(int(ix))
                        if idx is None:
                            continue
                        p = int(l * n_coarse + idx)
                        a[p, :] = 0.0
                        a[:, p] = 0.0
                        a[p, p] = 1.0

                inv = np.linalg.pinv(a, rcond=pinv_rcond)
                if not np.all(np.isfinite(inv)):
                    inv = np.linalg.pinv(a, rcond=pinv_rcond)
                coarse_inv_lblock[s, :, :] = inv

        for s in range(n_species):
            for l in range(n_l):
                if mat_fp is None:
                    a = np.zeros((n_x, n_x), dtype=np.float64)
                else:
                    a = np.array(mat_fp[s, s, l, :, :], dtype=np.float64, copy=True)
                a = a[np.ix_(coarse_idx, coarse_idx)]
                reg_eff = reg_l0 if l == 0 else float(reg)
                diag_vec = np.full((n_coarse,), identity_shift + reg_eff, dtype=np.float64)
                if pas_diag is not None:
                    diag_vec += pas_diag[s, coarse_idx, l]
                a[np.arange(n_coarse), np.arange(n_coarse)] += diag_vec
                if xdot_x_part is not None and xdot_coef_l is not None:
                    a = a + float(xdot_coef_l[l]) * xdot_x_part

                inactive_x = np.where(nxi_for_x <= l)[0]
                if inactive_x.size:
                    for ix in inactive_x:
                        idx = coarse_map.get(int(ix))
                        if idx is None:
                            continue
                        a[idx, :] = 0.0
                        a[:, idx] = 0.0
                        a[idx, idx] = 1.0

                use_pinv = bool(xdot_x_part is not None and xdot_coef_l is not None and l == 0 and mat_fp is None)
                if use_pinv:
                    inv = np.linalg.pinv(a, rcond=pinv_rcond)
                else:
                    try:
                        inv = np.linalg.inv(a)
                    except np.linalg.LinAlgError:
                        inv = np.linalg.pinv(a, rcond=pinv_rcond)
                if not np.all(np.isfinite(inv)):
                    inv = np.linalg.pinv(a, rcond=pinv_rcond)
                coarse_inv[s, l, :, :] = inv

        cached = _TransportXmgPrecondCache(
            inv_diag_f=jnp.asarray(inv_diag_f, dtype=precond_dtype),
            coarse_inv=jnp.asarray(coarse_inv, dtype=precond_dtype),
            coarse_idx=jnp.asarray(coarse_idx, dtype=jnp.int32),
            coarse_inv_lblock=(
                None if coarse_inv_lblock is None else jnp.asarray(coarse_inv_lblock, dtype=precond_dtype)
            ),
            lblock=int(lblock),
        )
        _RHSMODE1_XMG_PRECOND_CACHE[cache_key] = cached

    inv_diag_f = cached.inv_diag_f
    coarse_inv = cached.coarse_inv
    coarse_idx = cached.coarse_idx
    coarse_inv_lblock = cached.coarse_inv_lblock
    lblock = int(cached.lblock)

    def _apply_full(r_full: jnp.ndarray) -> jnp.ndarray:
        r_full = jnp.asarray(r_full, dtype=precond_dtype)
        f = r_full[: op.f_size].reshape(op.fblock.f_shape)  # (S,X,L,T,Z)
        z_f = f * inv_diag_f
        f_sl = jnp.transpose(f, (0, 2, 1, 3, 4))  # (S,L,X,T,Z)
        corr_sl = jnp.zeros_like(f_sl)
        if coarse_inv_lblock is not None and lblock > 0:
            n_coarse = int(coarse_idx.shape[0])
            lblock_use = int(min(lblock, int(f_sl.shape[1])))
            f_block = f_sl[:, :lblock_use, coarse_idx, :, :].reshape((f_sl.shape[0], lblock_use * n_coarse) + f_sl.shape[3:])
            z_block = jnp.einsum("sij,sjtz->sitz", coarse_inv_lblock, f_block)
            z_block = z_block.reshape((f_sl.shape[0], lblock_use, n_coarse) + f_sl.shape[3:])
            corr_sl = corr_sl.at[:, :lblock_use, coarse_idx, :, :].set(z_block)
            if lblock_use < int(f_sl.shape[1]):
                f_high = f_sl[:, lblock_use:, coarse_idx, :, :]
                z_high = jnp.einsum("slij,sljtz->slitz", coarse_inv[:, lblock_use:, :, :], f_high)
                corr_sl = corr_sl.at[:, lblock_use:, coarse_idx, :, :].set(z_high)
        else:
            f_coarse = f_sl[:, :, coarse_idx, :, :]
            z_coarse = jnp.einsum("slij,sljtz->slitz", coarse_inv, f_coarse)
            corr_sl = corr_sl.at[:, :, coarse_idx, :, :].set(z_coarse)
        corr = jnp.transpose(corr_sl, (0, 2, 1, 3, 4))
        z_f = z_f + corr
        tail = r_full[op.f_size :]
        z_full = jnp.concatenate([z_f.reshape((-1,)), tail], axis=0)
        return jnp.asarray(z_full, dtype=jnp.float64)

    if reduce_full is None or expand_reduced is None:
        return _apply_full

    def _apply_reduced(r_reduced: jnp.ndarray) -> jnp.ndarray:
        z_full = _apply_full(expand_reduced(r_reduced))
        return reduce_full(z_full)

    return _apply_reduced


def _build_rhsmode1_xupwind_preconditioner(
    *,
    op: V3FullSystemOperator,
    reduce_full: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
    expand_reduced: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
) -> Callable[[jnp.ndarray], jnp.ndarray]:
    """x-upwind preconditioner for PAS+Er RHSMode=1 systems.

    Motivation
    ----------
    The v3 Er xDot operator applies a dense ddx matvec that is effectively a first-order
    advection operator in x. On realistic x grids, explicitly inverting dense x blocks
    (as done by the xmg coarse correction) can be extremely ill-conditioned and produce
    enormous preconditioner factors.

    This preconditioner instead approximates the xDot coupling using a *bidiagonal*
    first-order upwind operator on the x grid, yielding a stable forward-substitution
    solve along x for each (species, L, theta, zeta) slice.

    Notes
    -----
    - Designed for PAS-only systems with Er xDot enabled (FP absent).
    - Uses a flux-surface RMS magnitude of xdotFactor to obtain a single scalar strength,
      and ignores the θ/ζ sign variation and ΔL=±2 couplings (handled elsewhere).
    - Fully JAX-native and differentiable; safe under `custom_linear_solve`.
    """
    if op.fblock.fp is not None or op.fblock.er_xdot is None:
        return _build_rhsmode1_xmg_preconditioner(op=op, reduce_full=reduce_full, expand_reduced=expand_reduced)

    precond_dtype = _precond_dtype()
    lblock_env = os.environ.get("SFINCS_JAX_RHSMODE1_XUPWIND_LBLOCK", "").strip()
    try:
        lblock_req = int(lblock_env) if lblock_env else 8
    except ValueError:
        lblock_req = 8
    lblock_req = max(0, int(lblock_req))
    cache_key = _rhsmode1_precond_cache_key(op, f"xupwind_lb{lblock_req}")
    cached = _RHSMODE1_XUPWIND_PRECOND_CACHE.get(cache_key)
    if cached is None:
        f_shape = op.fblock.f_shape
        n_species, n_x, n_l, _, _ = f_shape

        diag_base = np.zeros((n_species, n_x, n_l), dtype=np.float64)
        if float(op.fblock.identity_shift) != 0.0:
            diag_base = diag_base + float(op.fblock.identity_shift)

        if op.fblock.pas is not None:
            pas = op.fblock.pas
            l_arr = np.arange(n_l, dtype=np.float64)
            factor_l = 0.5 * (l_arr * (l_arr + 1.0) + 2.0 * float(pas.krook))
            pas_diag = float(pas.nu_n) * np.asarray(pas.nu_d_hat, dtype=np.float64)[:, :, None] * factor_l[None, None, :]
            diag_base = diag_base + pas_diag

        reg_env = os.environ.get("SFINCS_JAX_RHSMODE1_PRECOND_REG", "").strip()
        try:
            reg = float(reg_env) if reg_env else 1e-10
        except ValueError:
            reg = 1e-10
        reg_l0 = float(reg)
        if op.fblock.pas is not None and op.fblock.fp is None and op.fblock.er_xdot is not None:
            reg_l0 = max(reg_l0, 1.0)
        reg_by_l = np.full((n_l,), float(reg), dtype=np.float64)
        if n_l > 0:
            reg_by_l[0] = reg_l0
        diag_base = diag_base + reg_by_l[None, None, :]

        nxi_for_x = np.asarray(op.fblock.collisionless.n_xi_for_x, dtype=np.int32)
        active = (np.arange(n_l, dtype=np.int32)[None, :] < nxi_for_x[:, None])  # (X,L)
        for ix in range(n_x):
            for l in range(n_l):
                if not bool(active[ix, l]):
                    diag_base[:, ix, l] = 1.0

        # Flux-surface RMS magnitude of xdotFactor.
        xdot_rms = 0.0
        try:
            er = op.fblock.er_xdot
            alpha = float(np.asarray(er.alpha, dtype=np.float64).reshape(()))
            delta = float(np.asarray(er.delta, dtype=np.float64).reshape(()))
            dphi = float(np.asarray(er.dphi_hat_dpsi_hat, dtype=np.float64).reshape(()))
            d_hat = np.asarray(er.d_hat, dtype=np.float64)
            b_hat = np.asarray(er.b_hat, dtype=np.float64)
            b_sub_theta = np.asarray(er.b_hat_sub_theta, dtype=np.float64)
            b_sub_zeta = np.asarray(er.b_hat_sub_zeta, dtype=np.float64)
            db_dtheta = np.asarray(er.db_hat_dtheta, dtype=np.float64)
            db_dzeta = np.asarray(er.db_hat_dzeta, dtype=np.float64)
            factor0 = -(alpha * delta * dphi) / 4.0
            xdot_factor = factor0 * d_hat / (b_hat**3) * (b_sub_theta * db_dzeta - b_sub_zeta * db_dtheta)
            theta_w = np.asarray(op.theta_weights, dtype=np.float64)
            zeta_w = np.asarray(op.zeta_weights, dtype=np.float64)
            d_hat_full = np.asarray(op.d_hat, dtype=np.float64)
            fs_factor = (theta_w[:, None] * zeta_w[None, :]) / d_hat_full
            fs_sum = float(np.sum(fs_factor))
            if fs_sum > 0.0:
                xdot_rms = float(np.sqrt(np.sum(fs_factor * (xdot_factor * xdot_factor)) / fs_sum))
        except Exception:  # noqa: BLE001
            xdot_rms = 0.0

        l_vec = np.arange(n_l, dtype=np.float64)
        denom = (2.0 * l_vec + 3.0) * (2.0 * l_vec - 1.0)
        diag_coef = 2.0 * (3.0 * l_vec * l_vec + 3.0 * l_vec - 2.0) / denom
        c_l = diag_coef * float(xdot_rms)  # (L,)
        sup2 = np.zeros((n_l,), dtype=np.float64)
        sub2 = np.zeros((n_l,), dtype=np.float64)
        if n_l >= 3:
            l0 = l_vec[:-2]
            sup2[:-2] = (l0 + 1.0) * (l0 + 2.0) / ((2.0 * l0 + 5.0) * (2.0 * l0 + 3.0))
            l2 = l_vec[2:]
            sub2[2:] = l2 * (l2 - 1.0) / ((2.0 * l2 - 3.0) * (2.0 * l2 - 1.0))

        x_arr = np.asarray(op.fblock.er_xdot.x, dtype=np.float64)
        dx = np.diff(x_arr)
        x_over_dx = np.zeros((n_x,), dtype=np.float64)
        if n_x >= 2:
            x_over_dx[1:] = x_arr[1:] / np.where(dx != 0, dx, 1.0)

        # Lower-bidiagonal coefficients for (diag + c_l * x * d/dx_upwind).
        sub = -(x_over_dx[:, None] * c_l[None, :])  # (X,L), sub[0]=0
        diag = diag_base + (x_over_dx[:, None] * c_l[None, :])  # (S,X,L)
        sub = np.broadcast_to(sub[None, :, :], (n_species, n_x, n_l)).copy()

        # Inactive (x,L): identity.
        for ix in range(n_x):
            for l in range(n_l):
                if not bool(active[ix, l]):
                    sub[:, ix, l] = 0.0

        lblock = int(min(max(0, lblock_req), n_l))
        block_inv: np.ndarray | None = None
        block_sub: np.ndarray | None = None
        if lblock >= 3 and float(xdot_rms) != 0.0:
            block_inv = np.zeros((n_species, n_x, lblock, lblock), dtype=np.float64)
            block_sub = np.zeros((n_species, n_x, lblock, lblock), dtype=np.float64)
            pinv_env = os.environ.get("SFINCS_JAX_RHSMODE1_XUPWIND_PINV_RCOND", "").strip()
            try:
                pinv_rcond = float(pinv_env) if pinv_env else 1e-12
            except ValueError:
                pinv_rcond = 1e-12
            for s in range(n_species):
                for ix in range(n_x):
                    c_x = float(x_over_dx[ix])
                    a0 = np.zeros((lblock, lblock), dtype=np.float64)
                    a1 = np.zeros((lblock, lblock), dtype=np.float64)
                    for l in range(lblock):
                        a0[l, l] = float(diag_base[s, ix, l]) + c_x * float(c_l[l])
                        a1[l, l] = -c_x * float(c_l[l])
                        if l + 2 < lblock:
                            v = c_x * float(sup2[l] * xdot_rms)
                            a0[l, l + 2] += v
                            a1[l, l + 2] -= v
                        if l - 2 >= 0:
                            v = c_x * float(sub2[l] * xdot_rms)
                            a0[l, l - 2] += v
                            a1[l, l - 2] -= v
                    n_active = int(min(max(0, int(nxi_for_x[ix])), lblock))
                    if n_active < lblock:
                        for l in range(n_active, lblock):
                            a0[l, :] = 0.0
                            a0[:, l] = 0.0
                            a0[l, l] = 1.0
                            a1[l, :] = 0.0
                            a1[:, l] = 0.0
                    try:
                        inv = np.linalg.inv(a0)
                    except np.linalg.LinAlgError:
                        inv = np.linalg.pinv(a0, rcond=pinv_rcond)
                    if not np.all(np.isfinite(inv)):
                        inv = np.linalg.pinv(a0, rcond=pinv_rcond)
                    block_inv[s, ix, :, :] = inv
                    block_sub[s, ix, :, :] = a1

        cached = _XUpwindPrecondCache(
            diag=jnp.asarray(diag, dtype=precond_dtype),
            sub=jnp.asarray(sub, dtype=precond_dtype),
            lblock=int(lblock),
            block_inv=(None if block_inv is None else jnp.asarray(block_inv, dtype=precond_dtype)),
            block_sub=(None if block_sub is None else jnp.asarray(block_sub, dtype=precond_dtype)),
        )
        _RHSMODE1_XUPWIND_PRECOND_CACHE[cache_key] = cached
        alias_key = _rhsmode1_precond_cache_key(op, "xupwind")
        if alias_key not in _RHSMODE1_XUPWIND_PRECOND_CACHE:
            _RHSMODE1_XUPWIND_PRECOND_CACHE[alias_key] = cached

    diag = cached.diag  # (S,X,L)
    sub = cached.sub  # (S,X,L)
    lblock = int(cached.lblock)
    block_inv = cached.block_inv
    block_sub = cached.block_sub

    def _apply_full(r_full: jnp.ndarray) -> jnp.ndarray:
        r_full = jnp.asarray(r_full, dtype=precond_dtype)
        f = r_full[: op.f_size].reshape(op.fblock.f_shape)  # (S,X,L,T,Z)
        f_x = jnp.transpose(f, (1, 0, 2, 3, 4))  # (X,S,L,T,Z)
        diag_x = jnp.transpose(diag, (1, 0, 2))  # (X,S,L)
        sub_x = jnp.transpose(sub, (1, 0, 2))  # (X,S,L)
        use_block = bool(block_inv is not None and block_sub is not None and lblock > 0)
        if use_block:
            block_inv_x = jnp.transpose(block_inv, (1, 0, 2, 3))  # (X,S,Lb,Lb)
            block_sub_x = jnp.transpose(block_sub, (1, 0, 2, 3))  # (X,S,Lb,Lb)
        else:
            block_inv_x = jnp.zeros((f_x.shape[0], f_x.shape[1], 0, 0), dtype=precond_dtype)
            block_sub_x = jnp.zeros((f_x.shape[0], f_x.shape[1], 0, 0), dtype=precond_dtype)

        def _step(z_prev, inp):
            rhs_i, diag_i, sub_i, binv_i, bsub_i = inp
            diag_b = diag_i[..., None, None]
            sub_b = sub_i[..., None, None]
            if (not use_block) or lblock <= 0:
                z_i = (rhs_i - sub_b * z_prev) / diag_b
                return z_i, z_i

            rhs_lo = rhs_i[:, :lblock, :, :]
            zprev_lo = z_prev[:, :lblock, :, :]
            rhs_lo = rhs_lo - jnp.einsum("sij,sjtz->sitz", bsub_i, zprev_lo)
            z_lo = jnp.einsum("sij,sjtz->sitz", binv_i, rhs_lo)
            if rhs_i.shape[1] > lblock:
                rhs_hi = rhs_i[:, lblock:, :, :]
                zprev_hi = z_prev[:, lblock:, :, :]
                z_hi = (rhs_hi - sub_b[:, lblock:, :, :] * zprev_hi) / diag_b[:, lblock:, :, :]
                z_i = jnp.concatenate([z_lo, z_hi], axis=1)
            else:
                z_i = z_lo
            return z_i, z_i

        z0 = jnp.zeros_like(f_x[0])
        _, z_x = jax.lax.scan(_step, z0, (f_x, diag_x, sub_x, block_inv_x, block_sub_x))
        z_f = jnp.transpose(z_x, (1, 0, 2, 3, 4))  # (S,X,L,T,Z)
        tail = r_full[op.f_size :]
        z_full = jnp.concatenate([z_f.reshape((-1,)), tail], axis=0)
        return jnp.asarray(z_full, dtype=jnp.float64)

    if reduce_full is None or expand_reduced is None:
        return _apply_full

    def _apply_reduced(r_reduced: jnp.ndarray) -> jnp.ndarray:
        z_full = _apply_full(expand_reduced(r_reduced))
        return reduce_full(z_full)

    return _apply_reduced


def _build_rhsmode23_tzfft_preconditioner(
    *,
    op: V3FullSystemOperator,
    reduce_full: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
    expand_reduced: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
) -> Callable[[jnp.ndarray], jnp.ndarray]:
    """FFT-based tridiagonal-in-L preconditioner for collisionless RHSMode=2/3 systems.

    This preconditioner targets the collisionless streaming+mirror operator, which couples
    Legendre modes (L) off-diagonally and is local in x and species. We approximate geometry
    coefficients by a flux-surface average, diagonalize theta/zeta derivative stencils in
    Fourier space (valid for periodic finite-difference matrices), and solve an (L,L) tridiagonal
    system independently for each (k_theta, k_zeta) mode.

    Notes
    -----
    - Designed for collisionless / monoenergetic transport solves, where x-multigrid does not help
      (often Nx=1) and Krylov can stagnate without an angular preconditioner.
    - Fully JAX-native and differentiable; safe to use under `custom_linear_solve`.
    """
    if op.fblock.collisionless is None:
        return _build_rhsmode23_collision_preconditioner(op=op, reduce_full=reduce_full, expand_reduced=expand_reduced)

    reg_env = os.environ.get("SFINCS_JAX_TRANSPORT_TZFFT_REG", "").strip()
    try:
        reg = float(reg_env) if reg_env else 1e-8
    except ValueError:
        reg = 1e-8
    # For PAS+Er systems (RHSMode=1 constraintScheme=2 branch), the L=0 diagonal can be
    # exactly zero (krook=0) while the streaming/mirror operator has a constant-mode
    # nullspace in Fourier space. A very small `reg` can therefore produce enormous
    # tridiagonal-solve factors and cause Krylov divergence when this preconditioner is
    # used as part of a PAS hybrid. Use a more conservative L=0 lift in that branch.
    reg_l0 = float(reg)
    if op.fblock.pas is not None and op.fblock.fp is None and (
        op.fblock.er_xdot is not None or op.fblock.er_xidot is not None
    ):
        reg_l0 = max(reg_l0, 1.0)

    precond_dtype = _precond_dtype()
    complex_dtype = jnp.complex64 if precond_dtype == jnp.float32 else jnp.complex128
    cache_key = _transport_precond_cache_key(op, "tzfft") + (float(reg), str(complex_dtype))
    cached = _TRANSPORT_TZFFT_PRECOND_CACHE.get(cache_key)
    if cached is None:
        cl = op.fblock.collisionless
        n_species = int(op.n_species)
        n_x = int(op.n_x)
        n_l = int(op.n_xi)
        n_l_build = n_l
        n_l_build = n_l
        n_theta = int(op.n_theta)
        n_zeta = int(op.n_zeta)

        # Circulant FD derivative matrices: eigenvalues are FFT of first column.
        ddtheta0 = jnp.asarray(cl.ddtheta[:, 0], dtype=complex_dtype)
        ddzeta0 = jnp.asarray(cl.ddzeta[:, 0], dtype=complex_dtype)
        eig_theta = jnp.fft.fft(ddtheta0)  # (T,)
        eig_zeta = jnp.fft.fft(ddzeta0)  # (Z,)

        factor = _fs_average_factor(op.theta_weights, op.zeta_weights, op.d_hat)  # (T,Z)
        wsum = jnp.sum(factor)
        wsum = jnp.where(wsum != 0, wsum, jnp.asarray(1.0, dtype=jnp.float64))

        v_theta = jnp.sum(factor * (op.b_hat_sup_theta / op.b_hat)) / wsum
        v_zeta = jnp.sum(factor * (op.b_hat_sup_zeta / op.b_hat)) / wsum
        mirror_geom = op.b_hat_sup_theta * op.db_hat_dtheta + op.b_hat_sup_zeta * op.db_hat_dzeta
        mirror_base = jnp.sum(factor * (mirror_geom / (2.0 * (op.b_hat**2)))) / wsum

        sqrt_t_over_m = jnp.sqrt(op.t_hat / op.m_hat)  # (S,)
        v_theta_s = jnp.asarray(sqrt_t_over_m * v_theta, dtype=jnp.float64)  # (S,)
        v_zeta_s = jnp.asarray(sqrt_t_over_m * v_zeta, dtype=jnp.float64)  # (S,)
        mirror_factor_s = jnp.asarray(-sqrt_t_over_m * mirror_base, dtype=jnp.float64)  # (S,)

        d_symbol = (
            v_theta_s[:, None, None] * eig_theta[None, :, None]
            + v_zeta_s[:, None, None] * eig_zeta[None, None, :]
        )  # (S,T,Z) complex

        l = jnp.arange(n_l, dtype=jnp.float64)
        coef_plus = (l + 1.0) / (2.0 * l + 3.0)  # (L,)
        coef_minus = jnp.where(l > 0, l / (2.0 * l - 1.0), 0.0)  # (L,)
        coef_mirror_plus = (l + 1.0) * (l + 2.0) / (2.0 * l + 3.0)  # (L,)
        coef_mirror_minus = jnp.where(l > 1, -l * (l - 1.0) / (2.0 * l - 1.0), 0.0)  # (L,)

        coef_plus_x = op.x[:, None] * coef_plus[None, :]  # (X,L)
        coef_minus_x = op.x[:, None] * coef_minus[None, :]
        coef_mirror_plus_x = op.x[:, None] * coef_mirror_plus[None, :]
        coef_mirror_minus_x = op.x[:, None] * coef_mirror_minus[None, :]

        # Tridiagonal coefficients over L for each (s,x,theta,zeta).
        sup = d_symbol[:, None, :, :, None] * coef_plus_x[None, :, None, None, :-1]  # (S,X,T,Z,L-1)
        sup = sup + (mirror_factor_s[:, None, None, None, None] * coef_mirror_plus_x[None, :, None, None, :-1]).astype(complex_dtype)
        sub = d_symbol[:, None, :, :, None] * coef_minus_x[None, :, None, None, 1:]  # (S,X,T,Z,L-1)
        sub = sub + (mirror_factor_s[:, None, None, None, None] * coef_mirror_minus_x[None, :, None, None, 1:]).astype(complex_dtype)

        diag_base = jnp.asarray(float(op.fblock.identity_shift) + float(reg), dtype=jnp.float64)
        diag = jnp.full((n_species, n_x, n_theta, n_zeta, n_l), diag_base, dtype=complex_dtype)
        if n_l > 0 and reg_l0 != float(reg):
            diag = diag.at[..., 0].add(jnp.asarray(reg_l0 - float(reg), dtype=complex_dtype))

        # Add diagonal collision/exb contributions that are diagonal in L.
        if op.fblock.pas is not None:
            pas = op.fblock.pas
            l_arr = jnp.arange(n_l, dtype=jnp.float64)
            factor_l = 0.5 * (l_arr * (l_arr + 1.0) + 2.0 * pas.krook)
            pas_diag = pas.nu_n * pas.nu_d_hat[:, :, None] * factor_l[None, None, :]  # (S,X,L)
            diag = diag + pas_diag[:, :, None, None, :].astype(complex_dtype)

        if op.fblock.fp is not None:
            mat = op.fblock.fp.mat  # (S,S,L,X,X)
            diag_x = jnp.diagonal(mat, axis1=3, axis2=4)  # (S,S,L,X)
            diag_self = jnp.diagonal(diag_x, axis1=0, axis2=1)  # (L,X,S)
            diag_self = jnp.transpose(diag_self, (2, 1, 0))  # (S,X,L)
            diag = diag + diag_self[:, :, None, None, :].astype(complex_dtype)

        # Approximate ExB drift using a flux-surface-averaged coefficient so it is diagonal in Fourier space.
        if op.fblock.exb_theta is not None or op.fblock.exb_zeta is not None:
            use_dkes_exb = bool(getattr(op.fblock.exb_theta, "use_dkes_exb_drift", False)) if op.fblock.exb_theta is not None else bool(getattr(op.fblock.exb_zeta, "use_dkes_exb_drift", False))
            if use_dkes_exb:
                denom = jnp.asarray(op.fsab_hat2, dtype=jnp.float64)
                denom = jnp.where(denom != 0, denom, jnp.asarray(1.0, dtype=jnp.float64))
                coef_theta = (op.d_hat * op.b_hat_sub_zeta) / denom
                coef_zeta = (op.d_hat * op.b_hat_sub_theta) / denom
            else:
                denom = op.b_hat**2
                coef_theta = (op.d_hat * op.b_hat_sub_zeta) / denom
                coef_zeta = (op.d_hat * op.b_hat_sub_theta) / denom
            coef_theta_avg = jnp.sum(factor * coef_theta) / wsum
            coef_zeta_avg = jnp.sum(factor * coef_zeta) / wsum
            exb_factor = float(op.alpha) * float(op.delta) * 0.5 * float(op.dphi_hat_dpsi_hat)
            exb_theta_symbol = jnp.asarray(exb_factor * coef_theta_avg, dtype=complex_dtype) * eig_theta  # (T,)
            exb_zeta_symbol = jnp.asarray(-exb_factor * coef_zeta_avg, dtype=complex_dtype) * eig_zeta  # (Z,)
            diag_exb = exb_theta_symbol[None, None, :, None, None] + exb_zeta_symbol[None, None, None, :, None]
            diag = diag + diag_exb

        # Mask invalid L modes per x.
        nxi_for_x = op.fblock.collisionless.n_xi_for_x.astype(jnp.int32)
        active = jnp.arange(n_l, dtype=jnp.int32)[None, :] < nxi_for_x[:, None]  # (X,L)
        active_s = active[None, :, None, None, :]  # (1,X,1,1,L)
        diag = jnp.where(active_s, diag, jnp.asarray(1.0 + 0.0j, dtype=complex_dtype))
        link_active = active[:, :-1] & active[:, 1:]  # (X,L-1)
        link_s = link_active[None, :, None, None, :]  # (1,X,1,1,L-1)
        sup = jnp.where(link_s, sup, jnp.asarray(0.0 + 0.0j, dtype=complex_dtype))
        sub = jnp.where(link_s, sub, jnp.asarray(0.0 + 0.0j, dtype=complex_dtype))

        # `lax.linalg.tridiagonal_solve` expects all three diagonals to have the same shape (..., n),
        # with subdiag[..., 0] and superdiag[..., -1] ignored.
        z0 = jnp.zeros((n_species, n_x, n_theta, n_zeta, 1), dtype=complex_dtype)
        sub_full = jnp.concatenate([z0, sub], axis=-1)  # (..., L)
        sup_full = jnp.concatenate([sup, z0], axis=-1)  # (..., L)

        cached = _TransportTzFftPrecondCache(
            subdiag=jnp.asarray(sub_full, dtype=complex_dtype),
            diag=jnp.asarray(diag, dtype=complex_dtype),
            superdiag=jnp.asarray(sup_full, dtype=complex_dtype),
        )
        _TRANSPORT_TZFFT_PRECOND_CACHE[cache_key] = cached

    subdiag = cached.subdiag
    diag = cached.diag
    superdiag = cached.superdiag

    def _apply_full(r_full: jnp.ndarray) -> jnp.ndarray:
        r_full = jnp.asarray(r_full, dtype=jnp.float64)
        f = r_full[: op.f_size].reshape(op.fblock.f_shape)  # (S,X,L,T,Z)
        f_hat = jnp.fft.fftn(f.astype(complex_dtype), axes=(-2, -1))  # (S,X,L,T,Z)
        rhs = jnp.transpose(f_hat, (0, 1, 3, 4, 2))  # (S,X,T,Z,L)
        rhs = rhs[..., None]  # (S,X,T,Z,L,1)
        sol = jax.lax.linalg.tridiagonal_solve(subdiag, diag, superdiag, rhs)
        sol = sol[..., 0]  # (S,X,T,Z,L)
        sol = jnp.transpose(sol, (0, 1, 4, 2, 3))  # (S,X,L,T,Z)
        z_f = jnp.fft.ifftn(sol, axes=(-2, -1)).real.astype(jnp.float64)
        tail = r_full[op.f_size :]
        z_full = jnp.concatenate([z_f.reshape((-1,)), tail], axis=0)
        return jnp.asarray(z_full, dtype=jnp.float64)

    if reduce_full is None or expand_reduced is None:
        return _apply_full

    def _apply_reduced(r_reduced: jnp.ndarray) -> jnp.ndarray:
        z_full = _apply_full(expand_reduced(r_reduced))
        return reduce_full(z_full)

    return _apply_reduced


def _build_rhsmode1_pas_tokamak_theta_preconditioner(
    *,
    op: V3FullSystemOperator,
    reduce_full: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
    expand_reduced: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
) -> Callable[[jnp.ndarray], jnp.ndarray]:
    """PAS tokamak (Nzeta=1) theta/L block-tridiagonal preconditioner for RHSMode=1.

    This preconditioner targets the stiff PAS-only tokamak branch (no drifts) where:
    - x-coupling is absent (block-diagonal in x),
    - the dominant couplings are along theta (streaming) and in Legendre index L,
    - full theta-line blocks over *all* x are far too large to factor.

    Approach:
    - Build a block-tridiagonal-in-L approximation for each x with blocks of size Ntheta.
    - Precompute block-Thomas factors (approximate inverses of effective diagonal blocks + G factors).
    - Apply in O(Nx * Nxi * Ntheta^2) per Krylov iteration.
    """
    if not _pas_tokamak_theta_preconditioner_applicable(op):
        return _build_rhsmode1_block_preconditioner(op=op, reduce_full=reduce_full, expand_reduced=expand_reduced)

    n_x = int(op.n_x)
    n_l_total = int(op.n_xi)
    n_theta = int(op.n_theta)
    n_l_build = n_l_total
    lmax_env = os.environ.get("SFINCS_JAX_PAS_TOKAMAK_LMAX", "").strip()
    if lmax_env:
        try:
            n_l_build = max(2, int(lmax_env))
        except ValueError:
            n_l_build = n_l_total
    n_l_build = max(2, min(n_l_total, n_l_build))

    cache_key = _rhsmode1_precond_cache_key(op, f"pas_tokamak_theta_l{int(n_l_build)}")
    precond_dtype = _precond_dtype()
    cached = _RHSMODE1_PAS_TOKAMAK_THETA_CACHE.get(cache_key)
    if cached is None:
        cl = op.fblock.collisionless
        pas = op.fblock.pas
        assert cl is not None
        assert pas is not None

        n_species = int(op.n_species)

        if n_theta <= 1:
            return _build_rhsmode1_block_preconditioner(op=op, reduce_full=reduce_full, expand_reduced=expand_reduced)
        if n_l_total < 2:
            # The (L,theta) block-tridiagonal structure requires at least L=0,1.
            return _build_rhsmode1_block_preconditioner(op=op, reduce_full=reduce_full, expand_reduced=expand_reduced)

        x = np.asarray(cl.x, dtype=np.float64)  # (X,)
        ddtheta = np.asarray(cl.ddtheta, dtype=np.float64)  # (T,T)
        b_hat = np.asarray(cl.b_hat, dtype=np.float64)[:, 0]  # (T,)
        b_sup_theta = np.asarray(cl.b_hat_sup_theta, dtype=np.float64)[:, 0]  # (T,)
        b_sup_zeta = np.asarray(cl.b_hat_sup_zeta, dtype=np.float64)[:, 0]  # (T,)
        db_dtheta = np.asarray(cl.db_hat_dtheta, dtype=np.float64)[:, 0]  # (T,)
        db_dzeta = np.asarray(cl.db_hat_dzeta, dtype=np.float64)[:, 0]  # (T,)
        t_hats = np.asarray(cl.t_hats, dtype=np.float64)  # (S,)
        m_hats = np.asarray(cl.m_hats, dtype=np.float64)  # (S,)
        nxi_for_x = np.asarray(cl.n_xi_for_x, dtype=np.int32)  # (X,)

        l_arr = np.arange(n_l_build, dtype=np.float64)
        coef_plus = (l_arr + 1.0) / (2.0 * l_arr + 3.0)
        coef_minus = np.where(l_arr > 0, l_arr / (2.0 * l_arr - 1.0), 0.0)
        coef_mirror_plus = (l_arr + 1.0) * (l_arr + 2.0) / (2.0 * l_arr + 3.0)
        coef_mirror_minus = np.where(l_arr > 1, -l_arr * (l_arr - 1.0) / (2.0 * l_arr - 1.0), 0.0)

        coef_plus_x = x[:, None] * coef_plus[None, :]  # (X,L)
        coef_minus_x = x[:, None] * coef_minus[None, :]  # (X,L)
        coef_mirror_plus_x = x[:, None] * coef_mirror_plus[None, :]  # (X,L)
        coef_mirror_minus_x = x[:, None] * coef_mirror_minus[None, :]  # (X,L)

        mask_active_full = (np.arange(n_l_total, dtype=np.int32)[None, :] < nxi_for_x[:, None]).astype(np.float64)
        mask_active = mask_active_full[:, :n_l_build]  # (X,L_build)
        mask_plus = (mask_active[:, :-1] * mask_active[:, 1:]).astype(np.float64)  # (X,L_build-1)
        mask_minus = mask_plus  # same condition, just shifted in index

        b_stream = np.zeros((n_x, n_l_build), dtype=np.float64)
        b_mirror = np.zeros((n_x, n_l_build), dtype=np.float64)
        c_stream = np.zeros((n_x, n_l_build), dtype=np.float64)
        c_mirror = np.zeros((n_x, n_l_build), dtype=np.float64)
        b_stream[:, :-1] = coef_plus_x[:, :-1] * mask_plus
        b_mirror[:, :-1] = coef_mirror_plus_x[:, :-1] * mask_plus
        c_stream[:, 1:] = coef_minus_x[:, 1:] * mask_minus
        c_mirror[:, 1:] = coef_mirror_minus_x[:, 1:] * mask_minus

        # Preconditioner regularization:
        # For PAS tokamak-like systems, the L=0 diagonal can be exactly 0 (krook=0), while
        # the theta derivative operator has a constant-mode nullspace. A naive block-Thomas
        # factorization that inverts the L=0 diagonal block can therefore be unstable.
        #
        # We keep a *tiny* diagonal regularization to protect against true singularities,
        # and we avoid the large L=0 "lift" heuristic by using a combined (L=0,1) block
        # as the first elimination step (below). This yields a much tighter approximation
        # and typically reduces Krylov iterations dramatically.
        reg_env = os.environ.get("SFINCS_JAX_RHSMODE1_PAS_TOKAMAK_REG", "").strip()
        try:
            reg = float(reg_env) if reg_env else 1e-12
        except ValueError:
            reg = 1e-12
        reg = max(float(reg), 0.0)

        pas_coef = np.asarray(pas.coef, dtype=np.float64)[:, :, :n_l_build]  # (S,X,L_build)
        identity_shift = float(op.fblock.identity_shift)
        diag_vals = pas_coef + identity_shift + reg  # (S,X,L_build)
        # For inactive (x,L), decouple by setting diag=1 and couplings=0 (handled above).
        diag_vals = diag_vals * mask_active[None, :, :] + (1.0 - mask_active)[None, :, :]

        # Geometry-dependent base matrices (per species).
        v_theta = b_sup_theta / b_hat  # (T,)
        sqrt_t_over_m = np.sqrt(t_hats / m_hats)  # (S,)
        v_theta_s = sqrt_t_over_m[:, None] * v_theta[None, :]  # (S,T)
        m_theta = v_theta_s[:, :, None] * ddtheta[None, :, :]  # (S,T,T) row-scaled ddtheta

        mirror_geom = b_sup_theta * db_dtheta + b_sup_zeta * db_dzeta  # (T,)
        mirror_factor = -sqrt_t_over_m[:, None] * mirror_geom[None, :] / (2.0 * (b_hat * b_hat)[None, :])  # (S,T)
        mirror_diag = np.zeros((n_species, n_theta, n_theta), dtype=np.float64)
        for s in range(n_species):
            mirror_diag[s, :, :] = np.diag(mirror_factor[s, :])

        eye_t = np.eye(n_theta, dtype=np.float64)
        # Factorization with a combined (L=0,1) block (size 2*Ntheta) followed by standard
        # block-Thomas elimination for L>=2 (size Ntheta).
        twot = 2 * n_theta
        inv_a01 = np.zeros((n_species, n_x, twot, twot), dtype=np.float64)
        g01 = np.zeros((n_species, n_x, twot, n_theta), dtype=np.float64)
        inv_a = np.zeros((n_species, n_x, max(0, n_l_build - 2), n_theta, n_theta), dtype=np.float64)
        g = np.zeros((n_species, n_x, max(0, n_l_build - 3), n_theta, n_theta), dtype=np.float64)
        structured_tail_env = os.environ.get("SFINCS_JAX_PAS_TOKAMAK_STRUCTURED", "").strip().lower()
        # Keep the structured tail available for experiments, but do not enable it by default:
        # on the current shipped tokamak PAS examples, the legacy tail is both faster and lower-RSS.
        structured_tail_enabled = structured_tail_env in {"1", "true", "yes", "on"}
        tail_factors_build: list[list[object | None]] | None = (
            [[None for _ in range(n_x)] for _ in range(n_species)] if structured_tail_enabled and n_l_build > 2 else None
        )

        for s in range(n_species):
            m_s = m_theta[s, :, :]
            mir_s = mirror_diag[s, :, :]
            for ix in range(n_x):
                # Build and factor the combined (L=0,1) block.
                a0 = float(diag_vals[s, ix, 0])
                a1 = float(diag_vals[s, ix, 1])
                a0_blk = a0 * eye_t
                a1_blk = a1 * eye_t
                b0 = float(b_stream[ix, 0]) * m_s + float(b_mirror[ix, 0]) * mir_s
                c1 = float(c_stream[ix, 1]) * m_s + float(c_mirror[ix, 1]) * mir_s
                a01 = np.zeros((twot, twot), dtype=np.float64)
                a01[:n_theta, :n_theta] = a0_blk
                a01[:n_theta, n_theta:] = b0
                a01[n_theta:, :n_theta] = c1
                a01[n_theta:, n_theta:] = a1_blk
                try:
                    inv01 = np.linalg.inv(a01)
                except np.linalg.LinAlgError:
                    inv01 = np.linalg.pinv(a01, rcond=1e-12)
                if not np.all(np.isfinite(inv01)):
                    inv01 = np.linalg.pinv(a01, rcond=1e-12)
                inv_a01[s, ix, :, :] = inv01

                if n_l_build == 2:
                    continue

                # G01 = inv(A01) @ B_tilde, where B_tilde couples f2 into the L=1 equation only.
                b1 = float(b_stream[ix, 1]) * m_s + float(b_mirror[ix, 1]) * mir_s
                b_tilde = np.zeros((twot, n_theta), dtype=np.float64)
                b_tilde[n_theta:, :] = b1
                g01_loc = inv01 @ b_tilde  # (2T,T)
                g01[s, ix, :, :] = g01_loc

                # Eliminate L>=2 using standard block-Thomas with previous G having shape (2T,T) for l=2.
                g_prev = g01_loc
                for l in range(2, n_l_build):
                    a_diag = float(diag_vals[s, ix, l])
                    if l == 2:
                        c2 = float(c_stream[ix, l]) * m_s + float(c_mirror[ix, l]) * mir_s
                        c_tilde = np.zeros((n_theta, twot), dtype=np.float64)
                        c_tilde[:, n_theta:] = c2
                        a_eff = a_diag * eye_t - c_tilde @ g_prev
                    else:
                        c_l = float(c_stream[ix, l]) * m_s + float(c_mirror[ix, l]) * mir_s
                        a_eff = a_diag * eye_t - c_l @ g_prev
                    try:
                        a_inv = np.linalg.inv(a_eff)
                    except np.linalg.LinAlgError:
                        a_inv = np.linalg.pinv(a_eff, rcond=1e-12)
                    if not np.all(np.isfinite(a_inv)):
                        a_inv = np.linalg.pinv(a_eff, rcond=1e-12)
                    inv_a[s, ix, l - 2, :, :] = a_inv
                    if l < n_l_build - 1:
                        b_l = float(b_stream[ix, l]) * m_s + float(b_mirror[ix, l]) * mir_s
                        g_l = a_inv @ b_l
                        g[s, ix, l - 2, :, :] = g_l
                        g_prev = g_l

                if tail_factors_build is not None:
                    n_tail = n_l_build - 2
                    diag_tail = np.zeros((n_tail, n_theta, n_theta), dtype=np.float64)
                    lower_tail = np.zeros((max(0, n_tail - 1), n_theta, n_theta), dtype=np.float64)
                    upper_tail = np.zeros((max(0, n_tail - 1), n_theta, n_theta), dtype=np.float64)
                    for l in range(2, n_l_build):
                        diag_tail[l - 2, :, :] = float(diag_vals[s, ix, l]) * eye_t
                        if l < n_l_build - 1:
                            upper_tail[l - 2, :, :] = float(b_stream[ix, l]) * m_s + float(b_mirror[ix, l]) * mir_s
                        if l > 2:
                            lower_tail[l - 3, :, :] = float(c_stream[ix, l]) * m_s + float(c_mirror[ix, l]) * mir_s
                    tail_factors_build[s][ix] = factor_block_tridiagonal(
                        jnp.asarray(diag_tail, dtype=precond_dtype),
                        jnp.asarray(lower_tail, dtype=precond_dtype),
                        jnp.asarray(upper_tail, dtype=precond_dtype),
                    )

        cached = _PasTokamakThetaPrecondCache(
            inv_a01=jnp.asarray(inv_a01, dtype=precond_dtype),
            g01=jnp.asarray(g01, dtype=precond_dtype),
            inv_a=jnp.asarray(inv_a, dtype=precond_dtype),
            g=jnp.asarray(g, dtype=precond_dtype),
            c_stream=jnp.asarray(c_stream, dtype=precond_dtype),
            c_mirror=jnp.asarray(c_mirror, dtype=precond_dtype),
            m_theta=jnp.asarray(m_theta, dtype=precond_dtype),
            mirror_factor=jnp.asarray(mirror_factor, dtype=precond_dtype),
            mask_active=jnp.asarray(mask_active_full, dtype=precond_dtype),
            n_l_build=int(n_l_build),
            tail_factors=None if tail_factors_build is None else tuple(tuple(row) for row in tail_factors_build),
        )
        _RHSMODE1_PAS_TOKAMAK_THETA_CACHE[cache_key] = cached

    inv_a01 = cached.inv_a01
    g01 = cached.g01
    inv_a = cached.inv_a
    g = cached.g
    c_stream = cached.c_stream
    c_mirror = cached.c_mirror
    m_theta = cached.m_theta
    mirror_factor = cached.mirror_factor
    mask_active = cached.mask_active
    n_l_build = int(cached.n_l_build)
    tail_factors = cached.tail_factors

    f_shape = op.fblock.f_shape  # (S,X,L,T,Z)
    n_l_total = int(f_shape[2])
    n_theta = int(f_shape[3])
    n_zeta = int(f_shape[4])

    def _apply_full(r_full: jnp.ndarray) -> jnp.ndarray:
        r_full = jnp.asarray(r_full, dtype=jnp.float64)
        f_rhs_full = r_full[: op.f_size].reshape(f_shape)  # (S,X,L,T,Z)
        f_rhs_full = jnp.asarray(f_rhs_full, dtype=precond_dtype)
        f_rhs_full = f_rhs_full * mask_active[None, :, :, None, None]

        if n_zeta == 1:
            f_rhs_full = f_rhs_full[:, :, :, :, 0]  # (S,X,L,T)
            f_rhs = f_rhs_full[:, :, :n_l_build, :]
            f_rhs_high = f_rhs_full[:, :, n_l_build:, :]
            rhs0 = f_rhs[:, :, 0, :]  # (S,X,T)
            rhs1 = f_rhs[:, :, 1, :]  # (S,X,T)
            rhs01 = jnp.concatenate([rhs0, rhs1], axis=-1)  # (S,X,2T)
            d01 = jnp.einsum("sxij,sxj->sxi", inv_a01, rhs01)  # (S,X,2T)

            if n_l_build == 2:
                f0 = d01[:, :, :n_theta]
                f1 = d01[:, :, n_theta:]
                f_all = jnp.concatenate([f0[:, :, None, :], f1[:, :, None, :]], axis=2)  # (S,X,2,T)
            elif tail_factors is not None:
                f_rest_rows: list[list[jnp.ndarray]] = []
                for s in range(int(op.n_species)):
                    species_rows: list[jnp.ndarray] = []
                    for ix in range(int(op.n_x)):
                        factor = tail_factors[s][ix]
                        assert factor is not None
                        rhs_tail = jnp.asarray(f_rhs[s, ix, 2:n_l_build, :], dtype=precond_dtype)
                        d_prev = d01[s, ix, n_theta:]
                        corr2 = c_stream[ix, 2] * (m_theta[s] @ d_prev)
                        corr2 = corr2 + c_mirror[ix, 2] * (mirror_factor[s] * d_prev)
                        rhs_tail = rhs_tail.at[0, :].add(-corr2)
                        sol_tail = factor.solve(rhs_tail)
                        species_rows.append(jnp.asarray(sol_tail, dtype=precond_dtype))
                    f_rest_rows.append(jnp.stack(species_rows, axis=0))
                f_rest_all = jnp.stack(f_rest_rows, axis=0)  # (S,X,L-2,T)
                f2 = f_rest_all[:, :, 0, :]
                u01 = d01 - jnp.einsum("sxij,sxj->sxi", g01, f2)
                f0 = u01[:, :, :n_theta]
                f1 = u01[:, :, n_theta:]
                f_all = jnp.concatenate(
                    [f0[:, :, None, :], f1[:, :, None, :], f_rest_all],
                    axis=2,
                )
            else:
                d_prev = d01[:, :, n_theta:]  # (S,X,T)

                inv_a_l = jnp.transpose(inv_a, (2, 0, 1, 3, 4))  # (L-2,S,X,T,T)
                rhs_l = jnp.transpose(f_rhs[:, :, 2:, :], (2, 0, 1, 3))  # (L-2,S,X,T)
                c_stream_l = jnp.transpose(c_stream[:, 2:], (1, 0))  # (L-2,X)
                c_mirror_l = jnp.transpose(c_mirror[:, 2:], (1, 0))  # (L-2,X)

                def _fwd_step(d_prev: jnp.ndarray, inputs):
                    inv_block, rhs_block, cs, cm = inputs
                    corr_stream = jnp.einsum("sij,sxj->sxi", m_theta, d_prev) * cs[None, :, None]
                    corr_mirror = (mirror_factor[:, None, :] * d_prev) * cm[None, :, None]
                    rhs_eff = rhs_block - (corr_stream + corr_mirror)
                    d = jnp.einsum("sxij,sxj->sxi", inv_block, rhs_eff)
                    return d, d

                _, d_out = jax.lax.scan(_fwd_step, d_prev, (inv_a_l, rhs_l, c_stream_l, c_mirror_l))
                d_rest = jnp.transpose(d_out, (1, 2, 0, 3))  # (S,X,L-2,T)

                f_last = d_rest[:, :, -1, :]  # (S,X,T)
                if n_l_build > 3:
                    g_l = jnp.transpose(g, (2, 0, 1, 3, 4))  # (L-3,S,X,T,T)
                    d_rev = jnp.transpose(d_rest[:, :, :-1, :], (2, 0, 1, 3))[::-1]  # (L-3,S,X,T)
                    g_rev = g_l[::-1]

                    def _bwd_step(f_next: jnp.ndarray, inputs):
                        g_block, d_block = inputs
                        f_l = d_block - jnp.einsum("sxij,sxj->sxi", g_block, f_next)
                        return f_l, f_l

                    _, f_rev = jax.lax.scan(_bwd_step, f_last, (g_rev, d_rev))
                    f_prefix = f_rev[::-1]  # (L-3,S,X,T)
                    f_mid = jnp.transpose(f_prefix, (1, 2, 0, 3))  # (S,X,L-3,T)
                    f2 = f_mid[:, :, 0, :]  # L=2
                    f_rest_all = jnp.concatenate([f_mid, f_last[:, :, None, :]], axis=2)  # (S,X,L-2,T)
                else:
                    f2 = f_last
                    f_rest_all = f_last[:, :, None, :]  # (S,X,1,T)

                u01 = d01 - jnp.einsum("sxij,sxj->sxi", g01, f2)  # (S,X,2T)
                f0 = u01[:, :, :n_theta]
                f1 = u01[:, :, n_theta:]
                f_all = jnp.concatenate(
                    [f0[:, :, None, :], f1[:, :, None, :], f_rest_all],
                    axis=2,
                )  # (S,X,L,T)

            if n_l_build < n_l_total:
                f_all = jnp.concatenate([f_all, f_rhs_high], axis=2)
            f_all = f_all * mask_active[None, :, :, None]
            f_all = jnp.asarray(f_all, dtype=jnp.float64)
            z_f = f_all[:, :, :, :, None].reshape((-1,))
        else:
            # Apply the same theta/L preconditioner independently to each zeta plane.
            f_rhs_z_full = jnp.transpose(f_rhs_full, (4, 0, 1, 2, 3))  # (Z,S,X,L,T)
            f_rhs_z = f_rhs_z_full[:, :, :, :n_l_build, :]
            f_rhs_z_high = f_rhs_z_full[:, :, :, n_l_build:, :]
            rhs0 = f_rhs_z[:, :, :, 0, :]  # (Z,S,X,T)
            rhs1 = f_rhs_z[:, :, :, 1, :]  # (Z,S,X,T)
            rhs01 = jnp.concatenate([rhs0, rhs1], axis=-1)  # (Z,S,X,2T)
            d01 = jnp.einsum("sxij,zsxj->zsxi", inv_a01, rhs01)  # (Z,S,X,2T)

            if n_l_build == 2:
                f0 = d01[:, :, :, :n_theta]
                f1 = d01[:, :, :, n_theta:]
                f_all = jnp.concatenate([f0[:, :, :, None, :], f1[:, :, :, None, :]], axis=3)  # (Z,S,X,2,T)
            elif tail_factors is not None:
                z_rows: list[list[list[jnp.ndarray]]] = []
                for iz in range(n_zeta):
                    z_species: list[list[jnp.ndarray]] = []
                    for s in range(int(op.n_species)):
                        species_rows: list[jnp.ndarray] = []
                        for ix in range(int(op.n_x)):
                            factor = tail_factors[s][ix]
                            assert factor is not None
                            rhs_tail = jnp.asarray(f_rhs_z[iz, s, ix, 2:n_l_build, :], dtype=precond_dtype)
                            d_prev = d01[iz, s, ix, n_theta:]
                            corr2 = c_stream[ix, 2] * (m_theta[s] @ d_prev)
                            corr2 = corr2 + c_mirror[ix, 2] * (mirror_factor[s] * d_prev)
                            rhs_tail = rhs_tail.at[0, :].add(-corr2)
                            sol_tail = factor.solve(rhs_tail)
                            species_rows.append(jnp.asarray(sol_tail, dtype=precond_dtype))
                        z_species.append(species_rows)
                    z_rows.append(z_species)
                f_rest_all = jnp.asarray(z_rows, dtype=precond_dtype)  # (Z,S,X,L-2,T)
                f2 = f_rest_all[:, :, :, 0, :]
                u01 = d01 - jnp.einsum("sxij,zsxj->zsxi", g01, f2)
                f0 = u01[:, :, :, :n_theta]
                f1 = u01[:, :, :, n_theta:]
                f_all = jnp.concatenate(
                    [f0[:, :, :, None, :], f1[:, :, :, None, :], f_rest_all],
                    axis=3,
                )
            else:
                d_prev = d01[:, :, :, n_theta:]  # (Z,S,X,T)

                inv_a_l = jnp.transpose(inv_a, (2, 0, 1, 3, 4))  # (L-2,S,X,T,T)
                rhs_l = jnp.transpose(f_rhs_z[:, :, :, 2:, :], (3, 0, 1, 2, 4))  # (L-2,Z,S,X,T)
                c_stream_l = jnp.transpose(c_stream[:, 2:], (1, 0))  # (L-2,X)
                c_mirror_l = jnp.transpose(c_mirror[:, 2:], (1, 0))  # (L-2,X)

                def _fwd_step(d_prev: jnp.ndarray, inputs):
                    inv_block, rhs_block, cs, cm = inputs  # inv: (S,X,T,T), rhs: (Z,S,X,T)
                    corr_stream = jnp.einsum("sij,zsxj->zsxi", m_theta, d_prev) * cs[None, None, :, None]
                    corr_mirror = (mirror_factor[None, :, None, :] * d_prev) * cm[None, None, :, None]
                    rhs_eff = rhs_block - (corr_stream + corr_mirror)
                    d = jnp.einsum("sxij,zsxj->zsxi", inv_block, rhs_eff)
                    return d, d

                _, d_out = jax.lax.scan(_fwd_step, d_prev, (inv_a_l, rhs_l, c_stream_l, c_mirror_l))
                d_rest = jnp.transpose(d_out, (1, 2, 3, 0, 4))  # (Z,S,X,L-2,T)

                f_last = d_rest[:, :, :, -1, :]  # (Z,S,X,T)
                if n_l_build > 3:
                    g_l = jnp.transpose(g, (2, 0, 1, 3, 4))  # (L-3,S,X,T,T)
                    d_rev = jnp.transpose(d_rest[:, :, :, :-1, :], (3, 0, 1, 2, 4))[::-1]  # (L-3,Z,S,X,T)
                    g_rev = g_l[::-1]

                    def _bwd_step(f_next: jnp.ndarray, inputs):
                        g_block, d_block = inputs
                        f_l = d_block - jnp.einsum("sxij,zsxj->zsxi", g_block, f_next)
                        return f_l, f_l

                    _, f_rev = jax.lax.scan(_bwd_step, f_last, (g_rev, d_rev))
                    f_prefix = f_rev[::-1]  # (L-3,Z,S,X,T)
                    f_mid = jnp.transpose(f_prefix, (1, 2, 3, 0, 4))  # (Z,S,X,L-3,T)
                    f2 = f_mid[:, :, :, 0, :]  # L=2
                    f_rest_all = jnp.concatenate([f_mid, f_last[:, :, :, None, :]], axis=3)  # (Z,S,X,L-2,T)
                else:
                    f2 = f_last
                    f_rest_all = f_last[:, :, :, None, :]  # (Z,S,X,1,T)

                u01 = d01 - jnp.einsum("sxij,zsxj->zsxi", g01, f2)  # (Z,S,X,2T)
                f0 = u01[:, :, :, :n_theta]
                f1 = u01[:, :, :, n_theta:]
                f_all = jnp.concatenate(
                    [f0[:, :, :, None, :], f1[:, :, :, None, :], f_rest_all],
                    axis=3,
                )  # (Z,S,X,L,T)

            if n_l_build < n_l_total:
                f_all = jnp.concatenate([f_all, f_rhs_z_high], axis=3)
            f_all = f_all * mask_active[None, None, :, :, None]
            f_all = jnp.asarray(f_all, dtype=jnp.float64)
            f_all = jnp.transpose(f_all, (1, 2, 3, 4, 0))  # (S,X,L,T,Z)
            z_f = f_all.reshape((-1,))

        tail = r_full[op.f_size :]
        return jnp.concatenate([z_f, tail], axis=0)

    if reduce_full is None or expand_reduced is None:
        return _apply_full

    def _apply_reduced(r_reduced: jnp.ndarray) -> jnp.ndarray:
        z_full = _apply_full(expand_reduced(r_reduced))
        return reduce_full(z_full)

    return _apply_reduced


def _build_rhsmode1_pas_tz_preconditioner(
    *,
    op: V3FullSystemOperator,
    reduce_full: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
    expand_reduced: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
) -> Callable[[jnp.ndarray], jnp.ndarray]:
    """PAS 3D (theta,zeta)/L block-tridiagonal preconditioner for RHSMode=1.

    This preconditioner targets PAS-only 3D cases for which building dense per-x
    (theta,zeta,L) blocks (e.g. `xblock_tz`) is extremely expensive in both time and
    memory. We exploit the collisionless streaming+mirror structure, which couples
    only L<->L±1, to build a block-tridiagonal-in-L approximation with blocks of size
    Ntheta*Nzeta.

    The block-Thomas factors are precomputed once per operator signature and applied
    in O(Nx * Nxi * (Ntheta*Nzeta)^2) per Krylov iteration.
    """
    if not _pas_tz_preconditioner_applicable(op):
        return _build_rhsmode1_pas_hybrid_preconditioner(op=op, reduce_full=reduce_full, expand_reduced=expand_reduced)
    if not _pas_tz_preconditioner_memory_safe(op):
        return build_pas_tz_memory_fallback(
            op=op,
            matvec_shard_axis=_matvec_shard_axis,
            device_count=jax.device_count,
            theta_schwarz_builder=_build_rhsmode1_theta_schwarz_preconditioner,
            zeta_schwarz_builder=_build_rhsmode1_zeta_schwarz_preconditioner,
            hybrid_builder=_build_rhsmode1_pas_hybrid_preconditioner,
            collision_builder=_build_rhsmode1_collision_preconditioner,
            tzfft_builder=_build_rhsmode23_tzfft_preconditioner,
            reduce_full=reduce_full,
            expand_reduced=expand_reduced,
        )

    precond_dtype = _precond_dtype()
    cl = op.fblock.collisionless
    pas = op.fblock.pas
    assert cl is not None
    assert pas is not None

    n_species = int(op.n_species)
    n_x = int(op.n_x)
    n_l_full = int(op.n_xi)
    n_theta = int(op.n_theta)
    n_zeta = int(op.n_zeta)
    n_tz = int(n_theta * n_zeta)

    if n_tz <= 1 or n_l_full < 2:
        return _build_rhsmode1_pas_hybrid_preconditioner(
            op=op, reduce_full=reduce_full, expand_reduced=expand_reduced
        )

    pas_tz_lmax_env = os.environ.get("SFINCS_JAX_RHSMODE1_PAS_TZ_LMAX", "").strip()
    try:
        pas_tz_lmax = int(pas_tz_lmax_env) if pas_tz_lmax_env else 0
    except ValueError:
        pas_tz_lmax = 0
    if pas_tz_lmax <= 0:
        # Keep the PAS TZ preconditioner inexpensive for large angular grids, but for
        # moderate (theta,zeta) sizes we can afford the full L coupling to improve convergence.
        if n_tz <= 192:
            pas_tz_lmax = n_l_full
        elif n_tz >= 256:
            pas_tz_lmax = 6
        elif n_tz >= 128:
            pas_tz_lmax = 8
        else:
            pas_tz_lmax = 12
        if op.fblock.exb_theta is None and op.fblock.exb_zeta is None and op.fblock.magdrift_theta is None and op.fblock.magdrift_zeta is None and op.fblock.magdrift_xidot is None and op.fblock.er_xdot is None and op.fblock.er_xidot is None:
            # Pure PAS (no drift/Er) systems are block-diagonal in x; use full-L coupling
            # to reduce Krylov iterations even on moderately sized angular grids.
            if n_tz <= 256:
                pas_tz_lmax = n_l_full
    if n_l_full >= 2:
        n_l_use = min(n_l_full, max(2, int(pas_tz_lmax)))
    else:
        n_l_use = n_l_full

    cache_key = _rhsmode1_precond_cache_key(op, f"pas_tz_l{n_l_use}")
    cached = _RHSMODE1_PAS_TZ_CACHE.get(cache_key)
    if cached is None:
        n_l = n_l_full

        x = np.asarray(cl.x, dtype=np.float64)  # (X,)
        ddtheta = np.asarray(cl.ddtheta, dtype=np.float64)  # (T,T)
        ddzeta = np.asarray(cl.ddzeta, dtype=np.float64)  # (Z,Z)
        b_hat = np.asarray(cl.b_hat, dtype=np.float64)  # (T,Z)
        b_sup_theta = np.asarray(cl.b_hat_sup_theta, dtype=np.float64)  # (T,Z)
        b_sup_zeta = np.asarray(cl.b_hat_sup_zeta, dtype=np.float64)  # (T,Z)
        db_dtheta = np.asarray(cl.db_hat_dtheta, dtype=np.float64)  # (T,Z)
        db_dzeta = np.asarray(cl.db_hat_dzeta, dtype=np.float64)  # (T,Z)
        t_hats = np.asarray(cl.t_hats, dtype=np.float64)  # (S,)
        m_hats = np.asarray(cl.m_hats, dtype=np.float64)  # (S,)
        nxi_for_x = np.asarray(cl.n_xi_for_x, dtype=np.int32)  # (X,)

        l_arr = np.arange(n_l, dtype=np.float64)
        coef_plus = (l_arr + 1.0) / (2.0 * l_arr + 3.0)
        coef_minus = np.where(l_arr > 0, l_arr / (2.0 * l_arr - 1.0), 0.0)
        coef_mirror_plus = (l_arr + 1.0) * (l_arr + 2.0) / (2.0 * l_arr + 3.0)
        coef_mirror_minus = np.where(l_arr > 1, -l_arr * (l_arr - 1.0) / (2.0 * l_arr - 1.0), 0.0)

        coef_plus_x = x[:, None] * coef_plus[None, :]  # (X,L)
        coef_minus_x = x[:, None] * coef_minus[None, :]  # (X,L)
        coef_mirror_plus_x = x[:, None] * coef_mirror_plus[None, :]  # (X,L)
        coef_mirror_minus_x = x[:, None] * coef_mirror_minus[None, :]  # (X,L)

        mask_active = (np.arange(n_l, dtype=np.int32)[None, :] < nxi_for_x[:, None]).astype(np.float64)  # (X,L)
        mask_plus = (mask_active[:, :-1] * mask_active[:, 1:]).astype(np.float64)  # (X,L-1)
        mask_minus = mask_plus

        b_stream = np.zeros((n_x, n_l), dtype=np.float64)
        b_mirror = np.zeros((n_x, n_l), dtype=np.float64)
        c_stream = np.zeros((n_x, n_l), dtype=np.float64)
        c_mirror = np.zeros((n_x, n_l), dtype=np.float64)
        b_stream[:, :-1] = coef_plus_x[:, :-1] * mask_plus
        b_mirror[:, :-1] = coef_mirror_plus_x[:, :-1] * mask_plus
        c_stream[:, 1:] = coef_minus_x[:, 1:] * mask_minus
        c_mirror[:, 1:] = coef_mirror_minus_x[:, 1:] * mask_minus

        reg_env = os.environ.get("SFINCS_JAX_RHSMODE1_PAS_TZ_REG", "").strip()
        try:
            reg = float(reg_env) if reg_env else 1e-12
        except ValueError:
            reg = 1e-12
        reg = max(float(reg), 0.0)

        pas_coef = np.asarray(pas.coef, dtype=np.float64)  # (S,X,L)
        identity_shift = float(op.fblock.identity_shift)
        diag_vals = pas_coef + identity_shift + reg  # (S,X,L)
        # Inactive (x,L) decouple to identity.
        diag_vals = diag_vals * mask_active[None, :, :] + (1.0 - mask_active)[None, :, :]
        diag_inv = 1.0 / diag_vals

        i_zeta = np.eye(n_zeta, dtype=np.float64)
        i_theta = np.eye(n_theta, dtype=np.float64)
        dtheta_tz = np.kron(ddtheta, i_zeta)  # (TZ,TZ) zeta-fast layout
        dzeta_tz = np.kron(i_theta, ddzeta)  # (TZ,TZ)

        v_theta = b_sup_theta / b_hat  # (T,Z)
        v_zeta = b_sup_zeta / b_hat  # (T,Z)
        sqrt_t_over_m = np.sqrt(t_hats / m_hats)  # (S,)
        mirror_geom = b_sup_theta * db_dtheta + b_sup_zeta * db_dzeta  # (T,Z)
        mirror_base = mirror_geom / (2.0 * (b_hat * b_hat))  # (T,Z)

        m_tz = np.zeros((n_species, n_tz, n_tz), dtype=np.float64)
        mirror_factor = np.zeros((n_species, n_tz), dtype=np.float64)
        for s in range(n_species):
            v_theta_s = (sqrt_t_over_m[s] * v_theta).reshape((-1,))  # (TZ,)
            v_zeta_s = (sqrt_t_over_m[s] * v_zeta).reshape((-1,))  # (TZ,)
            m_tz[s, :, :] = v_theta_s[:, None] * dtheta_tz + v_zeta_s[:, None] * dzeta_tz
            mirror_factor[s, :] = (-sqrt_t_over_m[s] * mirror_base).reshape((-1,))

        exb_op_tz = np.zeros((n_tz, n_tz), dtype=np.float64)
        if op.fblock.exb_theta is not None:
            exb_theta = op.fblock.exb_theta
            alpha = float(np.asarray(exb_theta.alpha, dtype=np.float64).reshape(()))
            delta = float(np.asarray(exb_theta.delta, dtype=np.float64).reshape(()))
            dphi = float(np.asarray(exb_theta.dphi_hat_dpsi_hat, dtype=np.float64).reshape(()))
            if getattr(exb_theta, "use_dkes_exb_drift", False):
                denom = float(np.asarray(exb_theta.fsab_hat2, dtype=np.float64).reshape(()))
                coef = np.asarray(exb_theta.d_hat * exb_theta.b_hat_sub_zeta, dtype=np.float64) / denom
            else:
                b2 = np.asarray(exb_theta.b_hat, dtype=np.float64) ** 2
                coef = np.asarray(exb_theta.d_hat * exb_theta.b_hat_sub_zeta, dtype=np.float64) / b2
            factor = alpha * delta * 0.5 * dphi
            coef_flat = (factor * coef).reshape((-1,))
            exb_op_tz = exb_op_tz + coef_flat[:, None] * dtheta_tz
        if op.fblock.exb_zeta is not None:
            exb_zeta = op.fblock.exb_zeta
            alpha = float(np.asarray(exb_zeta.alpha, dtype=np.float64).reshape(()))
            delta = float(np.asarray(exb_zeta.delta, dtype=np.float64).reshape(()))
            dphi = float(np.asarray(exb_zeta.dphi_hat_dpsi_hat, dtype=np.float64).reshape(()))
            if getattr(exb_zeta, "use_dkes_exb_drift", False):
                denom = float(np.asarray(exb_zeta.fsab_hat2, dtype=np.float64).reshape(()))
                coef = np.asarray(exb_zeta.d_hat * exb_zeta.b_hat_sub_theta, dtype=np.float64) / denom
            else:
                b2 = np.asarray(exb_zeta.b_hat, dtype=np.float64) ** 2
                coef = np.asarray(exb_zeta.d_hat * exb_zeta.b_hat_sub_theta, dtype=np.float64) / b2
            factor = -alpha * delta * 0.5 * dphi
            coef_flat = (factor * coef).reshape((-1,))
            exb_op_tz = exb_op_tz + coef_flat[:, None] * dzeta_tz

        tz = int(n_tz)
        twotz = int(2 * tz)
        eye_tz = np.eye(tz, dtype=np.float64)

        n_l_build = int(n_l_use)
        inv_a01 = np.zeros((n_species, n_x, twotz, twotz), dtype=np.float64)
        g01 = np.zeros((n_species, n_x, twotz, tz), dtype=np.float64)
        inv_a = np.zeros((n_species, n_x, max(n_l_build - 2, 0), tz, tz), dtype=np.float64)
        g = np.zeros((n_species, n_x, max(n_l_build - 3, 0), tz, tz), dtype=np.float64)
        b_stream_use = b_stream[:, :n_l_build]
        b_mirror_use = b_mirror[:, :n_l_build]
        c_stream_use = c_stream[:, :n_l_build]
        c_mirror_use = c_mirror[:, :n_l_build]
        mask_active_use = mask_active[:, :n_l_build]

        for s in range(n_species):
            m_s = m_tz[s, :, :]  # (TZ,TZ)
            mir_vec = mirror_factor[s, :]  # (TZ,)
            mir_s = mir_vec[:, None] * eye_tz  # diagonal matrix
            for ix in range(n_x):
                # Combined (L=0,1) block to avoid L=0 singularities.
                active0 = float(mask_active_use[ix, 0])
                active1 = float(mask_active_use[ix, 1])
                a0 = float(diag_vals[s, ix, 0])
                a1 = float(diag_vals[s, ix, 1])
                a0_blk = a0 * eye_tz + active0 * exb_op_tz
                a1_blk = a1 * eye_tz + active1 * exb_op_tz
                b0 = float(b_stream_use[ix, 0]) * m_s + float(b_mirror_use[ix, 0]) * mir_s
                c1 = float(c_stream_use[ix, 1]) * m_s + float(c_mirror_use[ix, 1]) * mir_s
                a01 = np.zeros((twotz, twotz), dtype=np.float64)
                a01[:tz, :tz] = a0_blk
                a01[:tz, tz:] = b0
                a01[tz:, :tz] = c1
                a01[tz:, tz:] = a1_blk
                try:
                    inv01 = np.linalg.inv(a01)
                except np.linalg.LinAlgError:
                    inv01 = np.linalg.pinv(a01, rcond=1e-12)
                if not np.all(np.isfinite(inv01)):
                    inv01 = np.linalg.pinv(a01, rcond=1e-12)
                inv_a01[s, ix, :, :] = inv01

                if n_l == 2:
                    continue

                # G01 = inv(A01) @ B_tilde, where B_tilde couples f2 into the L=1 equation only.
                b1 = float(b_stream_use[ix, 1]) * m_s + float(b_mirror_use[ix, 1]) * mir_s
                b_tilde = np.zeros((twotz, tz), dtype=np.float64)
                b_tilde[tz:, :] = b1
                g01_loc = inv01 @ b_tilde
                g01[s, ix, :, :] = g01_loc

                g_prev = g01_loc
                for l in range(2, n_l_build):
                    active_l = float(mask_active_use[ix, l])
                    a_diag = float(diag_vals[s, ix, l])
                    a_blk = a_diag * eye_tz + active_l * exb_op_tz
                    if l == 2:
                        c2 = float(c_stream_use[ix, l]) * m_s + float(c_mirror_use[ix, l]) * mir_s
                        c_tilde = np.zeros((tz, twotz), dtype=np.float64)
                        c_tilde[:, tz:] = c2
                        a_eff = a_blk - c_tilde @ g_prev
                    else:
                        c_l = float(c_stream_use[ix, l]) * m_s + float(c_mirror_use[ix, l]) * mir_s
                        a_eff = a_blk - c_l @ g_prev
                    try:
                        a_inv = np.linalg.inv(a_eff)
                    except np.linalg.LinAlgError:
                        a_inv = np.linalg.pinv(a_eff, rcond=1e-12)
                    if not np.all(np.isfinite(a_inv)):
                        a_inv = np.linalg.pinv(a_eff, rcond=1e-12)
                    inv_a[s, ix, l - 2, :, :] = a_inv
                    if l < n_l_build - 1:
                        b_l = float(b_stream_use[ix, l]) * m_s + float(b_mirror_use[ix, l]) * mir_s
                        g_l = a_inv @ b_l
                        g[s, ix, l - 2, :, :] = g_l
                        g_prev = g_l

        cached = _PasTzPrecondCache(
            inv_a01=jnp.asarray(inv_a01, dtype=precond_dtype),
            g01=jnp.asarray(g01, dtype=precond_dtype),
            inv_a=jnp.asarray(inv_a, dtype=precond_dtype),
            g=jnp.asarray(g, dtype=precond_dtype),
            c_stream=jnp.asarray(c_stream_use, dtype=precond_dtype),
            c_mirror=jnp.asarray(c_mirror_use, dtype=precond_dtype),
            m_tz=jnp.asarray(m_tz, dtype=precond_dtype),
            mirror_factor=jnp.asarray(mirror_factor, dtype=precond_dtype),
            mask_active=jnp.asarray(mask_active, dtype=precond_dtype),
            diag_inv=jnp.asarray(diag_inv, dtype=precond_dtype),
            n_l_use=int(n_l_use),
        )
        _RHSMODE1_PAS_TZ_CACHE[cache_key] = cached

    inv_a01 = cached.inv_a01
    g01 = cached.g01
    inv_a = cached.inv_a
    g = cached.g
    c_stream = cached.c_stream
    c_mirror = cached.c_mirror
    m_tz = cached.m_tz
    mirror_factor = cached.mirror_factor
    mask_active = cached.mask_active
    diag_inv = cached.diag_inv
    n_l_use = int(cached.n_l_use)

    f_shape = op.fblock.f_shape  # (S,X,L,T,Z)
    n_species = int(f_shape[0])
    n_x = int(f_shape[1])
    n_l_full = int(f_shape[2])
    n_theta = int(f_shape[3])
    n_zeta = int(f_shape[4])
    tz = int(n_theta * n_zeta)
    n_l_use = max(0, min(int(n_l_use), n_l_full))

    def _apply_full(r_full: jnp.ndarray) -> jnp.ndarray:
        r_full = jnp.asarray(r_full, dtype=jnp.float64)
        f_rhs = r_full[: op.f_size].reshape(f_shape).reshape((n_species, n_x, n_l_full, tz))  # (S,X,L,TZ)
        f_rhs = jnp.asarray(f_rhs, dtype=precond_dtype)
        f_rhs = f_rhs * mask_active[None, :, :, None]
        if n_l_use <= 1:
            f_use = f_rhs[:, :, :n_l_use, :]
            f_high = f_rhs[:, :, n_l_use:, :]
            f_use = f_use * diag_inv[:, :, :n_l_use, None]
            f_high = f_high * diag_inv[:, :, n_l_use:, None]
            f_all = jnp.concatenate([f_use, f_high], axis=2)
            f_all = f_all * mask_active[None, :, :, None]
            f_all = jnp.asarray(f_all, dtype=jnp.float64).reshape((n_species, n_x, n_l_full, n_theta, n_zeta))
            z_f = f_all.reshape((-1,))
            tail = r_full[op.f_size :]
            return jnp.concatenate([z_f, tail], axis=0)

        f_rhs_use = f_rhs[:, :, :n_l_use, :]

        rhs0 = f_rhs_use[:, :, 0, :]  # (S,X,TZ)
        rhs1 = f_rhs_use[:, :, 1, :]  # (S,X,TZ)
        rhs01 = jnp.concatenate([rhs0, rhs1], axis=-1)  # (S,X,2TZ)
        d01 = jnp.einsum("sxij,sxj->sxi", inv_a01, rhs01)  # (S,X,2TZ)

        if n_l_use == 2:
            f0 = d01[:, :, :tz]
            f1 = d01[:, :, tz:]
            f_all = jnp.concatenate([f0[:, :, None, :], f1[:, :, None, :]], axis=2)  # (S,X,2,TZ)
        else:
            d_prev = d01[:, :, tz:]  # (S,X,TZ)

            inv_a_l = jnp.transpose(inv_a, (2, 0, 1, 3, 4))  # (L-2,S,X,TZ,TZ) for L>=2
            rhs_l = jnp.transpose(f_rhs_use[:, :, 2:, :], (2, 0, 1, 3))  # (L-2,S,X,TZ)
            c_stream_l = jnp.transpose(c_stream[:, 2:], (1, 0))  # (L-2,X)
            c_mirror_l = jnp.transpose(c_mirror[:, 2:], (1, 0))  # (L-2,X)

            def _fwd_step(d_prev: jnp.ndarray, inputs):
                inv_block, rhs_block, cs, cm = inputs
                corr_stream = jnp.einsum("sij,sxj->sxi", m_tz, d_prev) * cs[None, :, None]
                corr_mirror = (mirror_factor[:, None, :] * d_prev) * cm[None, :, None]
                rhs_eff = rhs_block - (corr_stream + corr_mirror)
                d = jnp.einsum("sxij,sxj->sxi", inv_block, rhs_eff)
                return d, d

            _, d_out = jax.lax.scan(_fwd_step, d_prev, (inv_a_l, rhs_l, c_stream_l, c_mirror_l))
            d_rest = jnp.transpose(d_out, (1, 2, 0, 3))  # (S,X,L-2,TZ)

            f_last = d_rest[:, :, -1, :]  # (S,X,TZ) corresponds to L=n_l-1
            if n_l_use > 3:
                g_l = jnp.transpose(g, (2, 0, 1, 3, 4))  # (L-3,S,X,TZ,TZ) for L=2..n_l-2
                d_rev = jnp.transpose(d_rest[:, :, :-1, :], (2, 0, 1, 3))[::-1]  # (L-3,S,X,TZ)
                g_rev = g_l[::-1]

                def _bwd_step(f_next: jnp.ndarray, inputs):
                    g_block, d_block = inputs
                    f_l = d_block - jnp.einsum("sxij,sxj->sxi", g_block, f_next)
                    return f_l, f_l

                _, f_rev = jax.lax.scan(_bwd_step, f_last, (g_rev, d_rev))
                f_prefix = f_rev[::-1]  # (L-3,S,X,TZ)
                f_mid = jnp.transpose(f_prefix, (1, 2, 0, 3))  # (S,X,L-3,TZ) for L=2..n_l-2
                f2 = f_mid[:, :, 0, :]  # L=2
                f_rest_all = jnp.concatenate([f_mid, f_last[:, :, None, :]], axis=2)  # (S,X,L-2,TZ)
            else:
                f2 = f_last
                f_rest_all = f_last[:, :, None, :]  # (S,X,1,TZ)

            u01 = d01 - jnp.einsum("sxij,sxj->sxi", g01, f2)  # (S,X,2TZ)
            f0 = u01[:, :, :tz]
            f1 = u01[:, :, tz:]
            f_all = jnp.concatenate([f0[:, :, None, :], f1[:, :, None, :], f_rest_all], axis=2)  # (S,X,L_use,TZ)

        if n_l_use < n_l_full:
            f_high = f_rhs[:, :, n_l_use:, :] * diag_inv[:, :, n_l_use:, None]
            f_all = jnp.concatenate([f_all, f_high], axis=2)
        f_all = f_all * mask_active[None, :, :, None]
        f_all = jnp.asarray(f_all, dtype=jnp.float64).reshape((n_species, n_x, n_l_full, n_theta, n_zeta))
        z_f = f_all.reshape((-1,))
        tail = r_full[op.f_size :]
        return jnp.concatenate([z_f, tail], axis=0)

    if reduce_full is None or expand_reduced is None:
        return _apply_full

    def _apply_reduced(r_reduced: jnp.ndarray) -> jnp.ndarray:
        z_full = _apply_full(expand_reduced(r_reduced))
        return reduce_full(z_full)

    return _apply_reduced


def _build_rhsmode1_collision_preconditioner(
    *,
    op: V3FullSystemOperator,
    reduce_full: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
    expand_reduced: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
) -> Callable[[jnp.ndarray], jnp.ndarray]:
    """Cheap collision-based preconditioner for RHSMode=1 solves (BiCGStab-friendly)."""
    use_xblock = False
    use_sxblock = False
    precond_dtype = _precond_dtype()
    kind_env = os.environ.get("SFINCS_JAX_RHSMODE1_COLLISION_PRECOND_KIND", "").strip().lower()
    if kind_env in {"xblock", "block_x", "x"}:
        use_xblock = True
    elif kind_env in {"sxblock", "species_block", "block"}:
        use_sxblock = True
    elif kind_env in {"", "auto"} and op.fblock.fp is not None:
        f_shape = op.fblock.f_shape
        n_species, n_x, _, _, _ = f_shape
        n_block = int(n_species) * int(n_x)
        sxblock_max_env = os.environ.get("SFINCS_JAX_RHSMODE1_COLLISION_SXBLOCK_MAX", "").strip()
        try:
            sxblock_max = int(sxblock_max_env) if sxblock_max_env else 64
        except ValueError:
            sxblock_max = 64
        xblock_max_env = os.environ.get("SFINCS_JAX_RHSMODE1_COLLISION_XBLOCK_MAX", "").strip()
        try:
            xblock_max = int(xblock_max_env) if xblock_max_env else 256
        except ValueError:
            xblock_max = 256
        if sxblock_max >= 0 and n_block <= sxblock_max:
            use_sxblock = True
        elif xblock_max >= 0 and int(n_x) <= xblock_max:
            use_xblock = True

    if use_sxblock and op.fblock.fp is not None:
        low_rank_env = os.environ.get("SFINCS_JAX_RHSMODE1_FP_LOW_RANK_K", "").strip()
        if not low_rank_env:
            low_rank_env = os.environ.get("SFINCS_JAX_FP_LOW_RANK_K", "").strip()
        low_rank_env = low_rank_env.strip().lower()
        low_rank_auto = low_rank_env in {"", "auto"}
        if low_rank_env and low_rank_env != "auto":
            try:
                low_rank_k = int(low_rank_env)
            except ValueError:
                low_rank_k = 0
        else:
            low_rank_k = 0
        f_shape = op.fblock.f_shape
        n_species, n_x, n_l, _, _ = f_shape
        n_block = n_species * n_x
        if low_rank_auto and low_rank_k <= 0 and n_block >= 24:
            low_rank_k = min(8, n_block)

        if low_rank_k > 0:
            rank_k = min(int(low_rank_k), int(n_block))
            cache_key = _transport_precond_cache_key(op, f"rhs1_collision_sxblock_lr_{rank_k}")
            cached_lr = _RHSMODE1_SXBLOCK_LR_PRECOND_CACHE.get(cache_key)
            if cached_lr is None:
                mat = np.asarray(op.fblock.fp.mat, dtype=np.float64)  # (S,S,L,X,X)
                reg_env = os.environ.get("SFINCS_JAX_RHSMODE1_BICGSTAB_PRECOND_REG", "").strip()
                try:
                    reg = float(reg_env) if reg_env else 1e-10
                except ValueError:
                    reg = 1e-10
                identity_shift = float(op.fblock.identity_shift)
                pas_diag = None
                if op.fblock.pas is not None:
                    pas = op.fblock.pas
                    l_arr = np.arange(n_l, dtype=np.float64)
                    factor_l = 0.5 * (l_arr * (l_arr + 1.0) + 2.0 * float(pas.krook))
                    pas_diag = float(pas.nu_n) * np.asarray(pas.nu_d_hat, dtype=np.float64)[:, :, None] * factor_l[None, None, :]

                nxi_for_x = np.asarray(op.fblock.collisionless.n_xi_for_x, dtype=np.int32)
                d_inv = np.zeros((n_l, n_block), dtype=np.float64)
                d_inv_u = np.zeros((n_l, n_block, rank_k), dtype=np.float64)
                v_lr = np.zeros((n_l, rank_k, n_block), dtype=np.float64)
                m_inv = np.zeros((n_l, rank_k, rank_k), dtype=np.float64)

                for l in range(n_l):
                    a_fp = np.array(mat[:, :, l, :, :], dtype=np.float64, copy=True)  # (S,S,X,X)
                    a_fp = a_fp.transpose(0, 2, 1, 3).reshape((n_block, n_block))
                    diag = np.full((n_block,), identity_shift + reg, dtype=np.float64)
                    if pas_diag is not None:
                        diag += pas_diag[:, :, l].reshape((n_block,))
                    inactive_x = np.where(nxi_for_x <= l)[0]
                    if inactive_x.size:
                        for ix in inactive_x:
                            for s in range(n_species):
                                idx = s * n_x + int(ix)
                                a_fp[idx, :] = 0.0
                                a_fp[:, idx] = 0.0
                                diag[idx] = 1.0
                    d_inv_l = 1.0 / diag
                    d_inv[l, :] = d_inv_l
                    if rank_k > 0:
                        try:
                            u, svals, vt = np.linalg.svd(a_fp, full_matrices=False)
                        except np.linalg.LinAlgError:
                            u, svals, vt = np.linalg.svd(a_fp + 1e-12 * np.eye(n_block), full_matrices=False)
                        k_use = min(rank_k, int(svals.shape[0]))
                        if k_use > 0:
                            u = u[:, :k_use]
                            svals = svals[:k_use]
                            vt = vt[:k_use, :]
                            s_sqrt = np.sqrt(np.maximum(svals, 0.0))
                            u_lr = u * s_sqrt[None, :]
                            v_lr_l = s_sqrt[:, None] * vt
                            d_inv_u_l = d_inv_l[:, None] * u_lr
                            m = np.eye(k_use, dtype=np.float64) + v_lr_l @ d_inv_u_l
                            try:
                                m_inv_l = np.linalg.inv(m)
                            except np.linalg.LinAlgError:
                                m_inv_l = np.linalg.pinv(m, rcond=1e-12)
                            if not np.all(np.isfinite(m_inv_l)):
                                m_inv_l = np.linalg.pinv(m, rcond=1e-12)
                            d_inv_u[l, :, :k_use] = d_inv_u_l
                            v_lr[l, :k_use, :] = v_lr_l
                            m_inv[l, :k_use, :k_use] = m_inv_l

                cached_lr = _LowRankXBlockPrecondCache(
                    d_inv=jnp.asarray(d_inv, dtype=precond_dtype),
                    d_inv_u=jnp.asarray(d_inv_u, dtype=precond_dtype),
                    v=jnp.asarray(v_lr, dtype=precond_dtype),
                    m_inv=jnp.asarray(m_inv, dtype=precond_dtype),
                )
                _RHSMODE1_SXBLOCK_LR_PRECOND_CACHE[cache_key] = cached_lr

            d_inv = cached_lr.d_inv
            d_inv_u = cached_lr.d_inv_u
            v_lr = cached_lr.v
            m_inv = cached_lr.m_inv

            def _apply_full(r_full: jnp.ndarray) -> jnp.ndarray:
                r_full = jnp.asarray(r_full, dtype=precond_dtype)
                f = r_full[: op.f_size].reshape(op.fblock.f_shape)  # (S,X,L,T,Z)
                f_l = jnp.transpose(f, (2, 0, 1, 3, 4))  # (L,S,X,T,Z)
                f_l = f_l.reshape((int(op.n_xi), int(op.n_species) * int(op.n_x), int(op.n_theta), int(op.n_zeta)))
                d_r = d_inv[:, :, None, None] * f_l
                if rank_k > 0:
                    tmp = jnp.einsum("lkn,lntz->lktz", v_lr, d_r)
                    tmp2 = jnp.einsum("lkm,lmtz->lktz", m_inv, tmp)
                    corr = jnp.einsum("lnk,lktz->lntz", d_inv_u, tmp2)
                    z_l = d_r - corr
                else:
                    z_l = d_r
                z_l = z_l.reshape((int(op.n_xi), int(op.n_species), int(op.n_x), int(op.n_theta), int(op.n_zeta)))
                z_f = jnp.transpose(z_l, (1, 2, 0, 3, 4))  # (S,X,L,T,Z)
                tail = r_full[op.f_size :]
                z_full = jnp.concatenate([z_f.reshape((-1,)), tail], axis=0)
                return jnp.asarray(z_full, dtype=jnp.float64)
        else:
            cache_key = _transport_precond_cache_key(op, "rhs1_collision_sxblock")
            cached = _RHSMODE1_SXBLOCK_PRECOND_CACHE.get(cache_key)
            if cached is None:
                f_shape = op.fblock.f_shape
                n_species, n_x, n_l, _, _ = f_shape
                n_block = n_species * n_x
                inv_block = np.zeros((n_l, n_block, n_block), dtype=np.float64)
                mat = np.asarray(op.fblock.fp.mat, dtype=np.float64)  # (S,S,L,X,X)
                reg_env = os.environ.get("SFINCS_JAX_RHSMODE1_BICGSTAB_PRECOND_REG", "").strip()
                try:
                    reg = float(reg_env) if reg_env else 1e-10
                except ValueError:
                    reg = 1e-10
                identity_shift = float(op.fblock.identity_shift)
                pas_diag = None
                if op.fblock.pas is not None:
                    pas = op.fblock.pas
                    l_arr = np.arange(n_l, dtype=np.float64)
                    factor_l = 0.5 * (l_arr * (l_arr + 1.0) + 2.0 * float(pas.krook))
                    pas_diag = float(pas.nu_n) * np.asarray(pas.nu_d_hat, dtype=np.float64)[:, :, None] * factor_l[None, None, :]

                for l in range(n_l):
                    a = np.array(mat[:, :, l, :, :], dtype=np.float64, copy=True)  # (S,S,X,X)
                    a = a.transpose(0, 2, 1, 3).reshape((n_block, n_block))
                    if identity_shift != 0.0:
                        a[np.arange(n_block), np.arange(n_block)] += identity_shift
                    if pas_diag is not None:
                        diag_add = pas_diag[:, :, l].reshape((n_block,))
                        a[np.arange(n_block), np.arange(n_block)] += diag_add
                    if reg != 0.0:
                        a[np.arange(n_block), np.arange(n_block)] += reg
                    try:
                        inv = np.linalg.inv(a)
                    except np.linalg.LinAlgError:
                        inv = np.linalg.pinv(a, rcond=1e-12)
                    if not np.all(np.isfinite(inv)):
                        inv = np.linalg.pinv(a, rcond=1e-12)
                    inv_block[l, :, :] = inv

                cached = _TransportXBlockPrecondCache(inv_xblock=jnp.asarray(inv_block, dtype=precond_dtype))
                _RHSMODE1_SXBLOCK_PRECOND_CACHE[cache_key] = cached

            inv_block = cached.inv_xblock  # (L, S*X, S*X)

            def _apply_full(r_full: jnp.ndarray) -> jnp.ndarray:
                r_full = jnp.asarray(r_full, dtype=precond_dtype)
                f = r_full[: op.f_size].reshape(op.fblock.f_shape)  # (S,X,L,T,Z)
                f_l = jnp.transpose(f, (2, 0, 1, 3, 4))  # (L,S,X,T,Z)
                f_l = f_l.reshape((int(op.n_xi), int(op.n_species) * int(op.n_x), int(op.n_theta), int(op.n_zeta)))
                z_l = jnp.einsum("lmn,lntz->lmtz", inv_block, f_l)
                z_l = z_l.reshape((int(op.n_xi), int(op.n_species), int(op.n_x), int(op.n_theta), int(op.n_zeta)))
                z_f = jnp.transpose(z_l, (1, 2, 0, 3, 4))  # (S,X,L,T,Z)
                tail = r_full[op.f_size :]
                z_full = jnp.concatenate([z_f.reshape((-1,)), tail], axis=0)
                return jnp.asarray(z_full, dtype=jnp.float64)

    elif use_xblock and op.fblock.fp is not None:
        cache_key = _transport_precond_cache_key(op, "rhs1_collision_xblock")
        cached = _RHSMODE1_XBLOCK_PRECOND_CACHE.get(cache_key)
        if cached is None:
            f_shape = op.fblock.f_shape
            n_species, n_x, n_l, _, _ = f_shape
            inv_xblock = np.zeros((n_species, n_l, n_x, n_x), dtype=np.float64)
            mat = np.asarray(op.fblock.fp.mat, dtype=np.float64)  # (S,S,L,X,X)
            reg_env = os.environ.get("SFINCS_JAX_RHSMODE1_BICGSTAB_PRECOND_REG", "").strip()
            try:
                reg = float(reg_env) if reg_env else 1e-10
            except ValueError:
                reg = 1e-10
            identity_shift = float(op.fblock.identity_shift)
            pas_diag = None
            if op.fblock.pas is not None:
                pas = op.fblock.pas
                l_arr = np.arange(n_l, dtype=np.float64)
                factor_l = 0.5 * (l_arr * (l_arr + 1.0) + 2.0 * float(pas.krook))
                pas_diag = float(pas.nu_n) * np.asarray(pas.nu_d_hat, dtype=np.float64)[:, :, None] * factor_l[None, None, :]

            for s in range(n_species):
                for l in range(n_l):
                    a = np.array(mat[s, s, l, :, :], dtype=np.float64, copy=True)
                    if identity_shift != 0.0:
                        a[np.arange(n_x), np.arange(n_x)] += identity_shift
                    if pas_diag is not None:
                        a[np.arange(n_x), np.arange(n_x)] += pas_diag[s, :, l]
                    if reg != 0.0:
                        a[np.arange(n_x), np.arange(n_x)] += reg
                    try:
                        inv = np.linalg.inv(a)
                    except np.linalg.LinAlgError:
                        inv = np.linalg.pinv(a, rcond=1e-12)
                    if not np.all(np.isfinite(inv)):
                        inv = np.linalg.pinv(a, rcond=1e-12)
                    inv_xblock[s, l, :, :] = inv

            cached = _TransportXBlockPrecondCache(inv_xblock=jnp.asarray(inv_xblock, dtype=precond_dtype))
            _RHSMODE1_XBLOCK_PRECOND_CACHE[cache_key] = cached

        inv_xblock = cached.inv_xblock

        def _apply_full(r_full: jnp.ndarray) -> jnp.ndarray:
            r_full = jnp.asarray(r_full, dtype=precond_dtype)
            f = r_full[: op.f_size].reshape(op.fblock.f_shape)  # (S,X,L,T,Z)
            f_sl = jnp.transpose(f, (0, 2, 1, 3, 4))  # (S,L,X,T,Z)
            z_sl = jnp.einsum("slij,sljtz->slitz", inv_xblock, f_sl)
            z_f = jnp.transpose(z_sl, (0, 2, 1, 3, 4))  # (S,X,L,T,Z)
            tail = r_full[op.f_size :]
            z_full = jnp.concatenate([z_f.reshape((-1,)), tail], axis=0)
            return jnp.asarray(z_full, dtype=jnp.float64)
    else:
        cache_key = _transport_precond_cache_key(op, "rhs1_collision_diag")
        cached = _RHSMODE1_DIAG_PRECOND_CACHE.get(cache_key)
        if cached is None:
            f_shape = op.fblock.f_shape
            n_species, n_x, n_l, _, _ = f_shape
            diag = jnp.zeros(f_shape, dtype=jnp.float64)

            if float(op.fblock.identity_shift) != 0.0:
                diag = diag + jnp.asarray(op.fblock.identity_shift, dtype=jnp.float64)

            if op.fblock.pas is not None:
                pas = op.fblock.pas
                l = jnp.arange(n_l, dtype=jnp.float64)
                factor_l = 0.5 * (l * (l + 1.0) + 2.0 * pas.krook)
                pas_diag = pas.nu_n * pas.nu_d_hat[:, :, None] * factor_l[None, None, :]
                diag = diag + pas_diag[:, :, :, None, None]

            if op.fblock.fp is not None:
                mat = op.fblock.fp.mat  # (S,S,L,X,X)
                diag_x = jnp.diagonal(mat, axis1=3, axis2=4)  # (S,S,L,X)
                diag_self = jnp.diagonal(diag_x, axis1=0, axis2=1)  # (L,X,S)
                diag_self = jnp.transpose(diag_self, (2, 1, 0))  # (S,X,L)
                diag = diag + diag_self[:, :, :, None, None]

            nxi_for_x = op.fblock.collisionless.n_xi_for_x.astype(jnp.int32)
            mask = jnp.arange(n_l, dtype=jnp.int32)[None, :] < nxi_for_x[:, None]  # (X,L)
            mask = mask[None, :, :, None, None]
            diag = jnp.where(mask, diag, jnp.asarray(1.0, dtype=jnp.float64))

            reg_env = os.environ.get("SFINCS_JAX_RHSMODE1_BICGSTAB_PRECOND_REG", "").strip()
            try:
                reg = float(reg_env) if reg_env else 1e-10
            except ValueError:
                reg = 1e-10
            reg_l0 = float(reg)
            if op.fblock.pas is not None and op.fblock.fp is None and op.fblock.er_xdot is not None:
                # PAS+Er runs can have an exactly-zero L=0 diagonal (krook=0), so a tiny
                # regularization produces enormous inverse diagonals and can destabilize
                # left-preconditioned Krylov residual norms.
                reg_l0 = max(reg_l0, 1.0)
            reg_by_l = jnp.full((n_l,), jnp.asarray(float(reg), dtype=jnp.float64))
            if n_l > 0:
                reg_by_l = reg_by_l.at[0].set(jnp.asarray(reg_l0, dtype=jnp.float64))
            inv_diag_f = 1.0 / (diag + reg_by_l[None, None, :, None, None])
            cached = _TransportPrecondCache(inv_diag_f=jnp.asarray(inv_diag_f, dtype=precond_dtype))
            _RHSMODE1_DIAG_PRECOND_CACHE[cache_key] = cached

        inv_diag_f = cached.inv_diag_f

        def _apply_full(r_full: jnp.ndarray) -> jnp.ndarray:
            r_full = jnp.asarray(r_full, dtype=precond_dtype)
            f = r_full[: op.f_size].reshape(op.fblock.f_shape)
            z_f = f * inv_diag_f
            tail = r_full[op.f_size :]
            z_full = jnp.concatenate([z_f.reshape((-1,)), tail], axis=0)
            return jnp.asarray(z_full, dtype=jnp.float64)

    if reduce_full is None or expand_reduced is None:
        return _apply_full

    def _apply_reduced(r_reduced: jnp.ndarray) -> jnp.ndarray:
        z_full = _apply_full(expand_reduced(r_reduced))
        return reduce_full(z_full)

    return _apply_reduced


@jtu.register_pytree_node_class
@dataclass(frozen=True)
class V3LinearSolveResult:
    """Result of a single matrix-free GMRES solve for the (currently supported) v3 full-system operator."""

    op: V3FullSystemOperator
    rhs: jnp.ndarray
    gmres: GMRESSolveResult
    metadata: dict[str, object] | None = None

    def tree_flatten(self):
        children = (self.op, self.rhs, self.gmres)
        aux = self.metadata
        return children, aux

    @classmethod
    def tree_unflatten(cls, aux, children):
        op, rhs, gmres_result = children
        return cls(op=op, rhs=rhs, gmres=gmres_result, metadata=aux)

    @property
    def x(self) -> jnp.ndarray:
        return self.gmres.x

    @property
    def residual_norm(self) -> jnp.ndarray:
        return self.gmres.residual_norm


def _gmres_result_is_finite(res: GMRESSolveResult) -> bool:
    """Return True when GMRES returned finite state and residual."""
    return bool(jnp.all(jnp.isfinite(res.x)) and jnp.isfinite(res.residual_norm))


def _block_gmres_result_ready(res: GMRESSolveResult) -> GMRESSolveResult:
    """Synchronize a GMRES result so timing/profiling marks include XLA work."""
    try:
        jax.block_until_ready((res.x, res.residual_norm))
    except Exception:
        pass
    return res


def _diag_only(m: jnp.ndarray) -> jnp.ndarray:
    """Return a diagonal-only copy of a square matrix."""
    return jnp.diag(jnp.diag(m))


def _block_diag_only(m: jnp.ndarray, block: int) -> jnp.ndarray:
    """Return a block-diagonal copy of a square matrix (block size in indices)."""
    if int(block) <= 1:
        return _diag_only(m)
    mat_np = np.asarray(m, dtype=np.float64)
    n = int(mat_np.shape[0])
    mask = np.zeros((n, n), dtype=bool)
    for start in range(0, n, int(block)):
        end = min(n, start + int(block))
        mask[start:end, start:end] = True
    mat_np = np.where(mask, mat_np, 0.0)
    return jnp.asarray(mat_np, dtype=m.dtype)


def _dd_core_patch_ranges(n: int, block: int, overlap: int) -> list[tuple[int, int, int, int]]:
    """Return (core_start, core_end, patch_start, patch_end) ranges for DD/RAS blocks."""
    n = int(n)
    block = max(1, int(block))
    overlap = max(0, int(overlap))
    ranges: list[tuple[int, int, int, int]] = []
    for core_start in range(0, n, block):
        core_end = min(n, core_start + block)
        patch_start = max(0, core_start - overlap)
        patch_end = min(n, core_end + overlap)
        ranges.append((core_start, core_end, patch_start, patch_end))
    return ranges


def _rhs1_dd_auto_block_size(
    *,
    n: int,
    n_dev: int,
    sum_nxi: int,
    dof_target: int,
) -> int:
    """Choose a shard-local Schwarz block that spans more than one local shard.

    A single local shard is often too narrow once theta/zeta sharding is active,
    especially on 4-8 CPU devices. Using ``local_n`` alone over-fragments the
    restricted additive Schwarz patches and increases synchronization overhead.
    The auto rule below keeps the original DOF target, but adds one target-width
    of coupled angular DOFs on top of the local shard width so each patch can
    capture cross-shard angular coupling without becoming nearly global.
    """
    n = max(1, int(n))
    n_dev = max(1, int(n_dev))
    sum_nxi = max(1, int(sum_nxi))
    dof_target = max(128, int(dof_target))
    local_n = max(1, (n + n_dev - 1) // n_dev)
    dof_cap = max(2, int(dof_target) // int(sum_nxi))
    block = max(dof_cap, local_n + dof_cap)
    return max(1, min(n, int(block)))


def _rhs1_dd_coarse_block_size(*, n: int, block: int, overlap: int) -> int:
    """Choose a wider coarse theta/zeta block for two-level Schwarz correction."""
    n = max(1, int(n))
    block = max(1, min(n, int(block)))
    overlap = max(0, int(overlap))
    coarse = block + max(8, block // 2, 2 * overlap)
    return max(1, min(n, int(coarse)))


def _rhs1_dd_coarse_level_count(*, n_dev: int) -> int:
    """Choose how many coarse residual-correction levels to apply."""
    n_dev = max(1, int(n_dev))
    coarse_levels_env = os.environ.get("SFINCS_JAX_RHSMODE1_SCHWARZ_COARSE_LEVELS", "").strip()
    if coarse_levels_env:
        try:
            return max(0, int(coarse_levels_env))
        except ValueError:
            return 1
    if n_dev >= 8:
        return 2
    if n_dev >= 4:
        return 1
    return 0


def _rhs1_dd_coarse_block_sizes(*, n: int, block: int, overlap: int, levels: int) -> tuple[int, ...]:
    """Choose one or more increasingly wider coarse theta/zeta block sizes."""
    n = max(1, int(n))
    current = max(1, min(n, int(block)))
    out: list[int] = []
    for _ in range(max(0, int(levels))):
        next_block = _rhs1_dd_coarse_block_size(n=n, block=current, overlap=overlap)
        if next_block <= current:
            break
        out.append(int(next_block))
        current = int(next_block)
        if current >= n:
            break
    return tuple(out)


def _build_rhsmode1_preconditioner_operator_point(op: V3FullSystemOperator) -> V3FullSystemOperator:
    """Return a simplified RHSMode=1 operator for point-block preconditioning.

    This is the original cheap RHSMode=1 preconditioner: it retains local x/L
    couplings and collisions while dropping theta/zeta derivative couplings
    (streaming, ExB, and magnetic-drift derivatives) by diagonalizing the derivative
    matrices.
    """
    if int(op.rhs_mode) != 1:
        return op

    fblock = op.fblock
    coll = replace(
        fblock.collisionless,
        ddtheta=_diag_only(fblock.collisionless.ddtheta),
        ddzeta=_diag_only(fblock.collisionless.ddzeta),
    )
    exb_theta = None if fblock.exb_theta is None else replace(
        fblock.exb_theta, ddtheta=_diag_only(fblock.exb_theta.ddtheta)
    )
    exb_zeta = None if fblock.exb_zeta is None else replace(
        fblock.exb_zeta, ddzeta=_diag_only(fblock.exb_zeta.ddzeta)
    )
    mag_theta = None
    if fblock.magdrift_theta is not None:
        mag_theta = replace(
            fblock.magdrift_theta,
            ddtheta_plus=_diag_only(fblock.magdrift_theta.ddtheta_plus),
            ddtheta_minus=_diag_only(fblock.magdrift_theta.ddtheta_minus),
        )
    mag_zeta = None
    if fblock.magdrift_zeta is not None:
        mag_zeta = replace(
            fblock.magdrift_zeta,
            ddzeta_plus=_diag_only(fblock.magdrift_zeta.ddzeta_plus),
            ddzeta_minus=_diag_only(fblock.magdrift_zeta.ddzeta_minus),
        )
    fblock_pc = replace(
        fblock,
        collisionless=coll,
        exb_theta=exb_theta,
        exb_zeta=exb_zeta,
        magdrift_theta=mag_theta,
        magdrift_zeta=mag_zeta,
    )
    return replace(op, fblock=fblock_pc)


def _build_transport_preconditioner_operator_point(op: V3FullSystemOperator) -> V3FullSystemOperator:
    """Return a simplified transport operator for point-block preconditioning.

    This mirrors `_build_rhsmode1_preconditioner_operator_point` but does not
    require RHSMode=1, since RHSMode=2/3 transport solves reuse the same operator
    structure with different right-hand sides.
    """
    fblock = op.fblock
    coll = replace(
        fblock.collisionless,
        ddtheta=_diag_only(fblock.collisionless.ddtheta),
        ddzeta=_diag_only(fblock.collisionless.ddzeta),
    )
    exb_theta = None if fblock.exb_theta is None else replace(
        fblock.exb_theta, ddtheta=_diag_only(fblock.exb_theta.ddtheta)
    )
    exb_zeta = None if fblock.exb_zeta is None else replace(
        fblock.exb_zeta, ddzeta=_diag_only(fblock.exb_zeta.ddzeta)
    )
    mag_theta = None
    if fblock.magdrift_theta is not None:
        mag_theta = replace(
            fblock.magdrift_theta,
            ddtheta_plus=_diag_only(fblock.magdrift_theta.ddtheta_plus),
            ddtheta_minus=_diag_only(fblock.magdrift_theta.ddtheta_minus),
        )
    mag_zeta = None
    if fblock.magdrift_zeta is not None:
        mag_zeta = replace(
            fblock.magdrift_zeta,
            ddzeta_plus=_diag_only(fblock.magdrift_zeta.ddzeta_plus),
            ddzeta_minus=_diag_only(fblock.magdrift_zeta.ddzeta_minus),
        )
    fblock_pc = replace(
        fblock,
        collisionless=coll,
        exb_theta=exb_theta,
        exb_zeta=exb_zeta,
        magdrift_theta=mag_theta,
        magdrift_zeta=mag_zeta,
    )
    return replace(op, fblock=fblock_pc)


def _build_rhsmode1_preconditioner_operator_theta_line(op: V3FullSystemOperator) -> V3FullSystemOperator:
    """Return a simplified RHSMode=1 operator for theta-line preconditioning.

    Keep full theta derivative couplings but drop zeta derivative couplings. This enables
    a significantly stronger preconditioner than point-block Jacobi, while remaining
    much cheaper than a full (theta,zeta)-coupled preconditioner.
    """
    if int(op.rhs_mode) != 1:
        return op

    fblock = op.fblock
    coll = replace(
        fblock.collisionless,
        ddzeta=_diag_only(fblock.collisionless.ddzeta),
    )
    exb_theta = fblock.exb_theta
    exb_zeta = None if fblock.exb_zeta is None else replace(
        fblock.exb_zeta, ddzeta=_diag_only(fblock.exb_zeta.ddzeta)
    )
    mag_theta = fblock.magdrift_theta
    mag_zeta = None
    if fblock.magdrift_zeta is not None:
        mag_zeta = replace(
            fblock.magdrift_zeta,
            ddzeta_plus=_diag_only(fblock.magdrift_zeta.ddzeta_plus),
            ddzeta_minus=_diag_only(fblock.magdrift_zeta.ddzeta_minus),
        )
    fblock_pc = replace(
        fblock,
        collisionless=coll,
        exb_theta=exb_theta,
        exb_zeta=exb_zeta,
        magdrift_theta=mag_theta,
        magdrift_zeta=mag_zeta,
    )
    return replace(op, fblock=fblock_pc)


def _build_rhsmode1_preconditioner_operator_theta_dd(
    op: V3FullSystemOperator, *, block: int
) -> V3FullSystemOperator:
    """Return a theta-block domain-decomposition operator for preconditioning.

    This operator shaping is used by RHSMode=1 and RHSMode=2/3 transport solves.
    """

    fblock = op.fblock
    coll = replace(
        fblock.collisionless,
        ddtheta=_block_diag_only(fblock.collisionless.ddtheta, block),
        ddzeta=_diag_only(fblock.collisionless.ddzeta),
    )
    exb_theta = fblock.exb_theta
    exb_zeta = None if fblock.exb_zeta is None else replace(
        fblock.exb_zeta, ddzeta=_diag_only(fblock.exb_zeta.ddzeta)
    )
    mag_theta = fblock.magdrift_theta
    if mag_theta is not None:
        mag_theta = replace(
            mag_theta,
            ddtheta_plus=_block_diag_only(mag_theta.ddtheta_plus, block),
            ddtheta_minus=_block_diag_only(mag_theta.ddtheta_minus, block),
        )
    mag_zeta = None
    if fblock.magdrift_zeta is not None:
        mag_zeta = replace(
            fblock.magdrift_zeta,
            ddzeta_plus=_diag_only(fblock.magdrift_zeta.ddzeta_plus),
            ddzeta_minus=_diag_only(fblock.magdrift_zeta.ddzeta_minus),
        )
    fblock_pc = replace(
        fblock,
        collisionless=coll,
        exb_theta=exb_theta,
        exb_zeta=exb_zeta,
        magdrift_theta=mag_theta,
        magdrift_zeta=mag_zeta,
    )
    return replace(op, fblock=fblock_pc)


def _build_rhsmode1_preconditioner_operator_zeta_line(op: V3FullSystemOperator) -> V3FullSystemOperator:
    """Return a simplified RHSMode=1 operator for zeta-line preconditioning.

    Keep full zeta derivative couplings but drop theta derivative couplings. This is the
    zeta-analog of `_build_rhsmode1_preconditioner_operator_theta_line`.
    """
    if int(op.rhs_mode) != 1:
        return op

    fblock = op.fblock
    coll = replace(
        fblock.collisionless,
        ddtheta=_diag_only(fblock.collisionless.ddtheta),
    )
    exb_theta = None if fblock.exb_theta is None else replace(
        fblock.exb_theta, ddtheta=_diag_only(fblock.exb_theta.ddtheta)
    )
    exb_zeta = fblock.exb_zeta
    mag_theta = None
    if fblock.magdrift_theta is not None:
        mag_theta = replace(
            fblock.magdrift_theta,
            ddtheta_plus=_diag_only(fblock.magdrift_theta.ddtheta_plus),
            ddtheta_minus=_diag_only(fblock.magdrift_theta.ddtheta_minus),
        )
    mag_zeta = fblock.magdrift_zeta
    fblock_pc = replace(
        fblock,
        collisionless=coll,
        exb_theta=exb_theta,
        exb_zeta=exb_zeta,
        magdrift_theta=mag_theta,
        magdrift_zeta=mag_zeta,
    )
    return replace(op, fblock=fblock_pc)


def _build_rhsmode1_preconditioner_operator_zeta_dd(
    op: V3FullSystemOperator, *, block: int
) -> V3FullSystemOperator:
    """Return a zeta-block domain-decomposition operator for preconditioning.

    This operator shaping is used by RHSMode=1 and RHSMode=2/3 transport solves.
    """

    fblock = op.fblock
    coll = replace(
        fblock.collisionless,
        ddtheta=_diag_only(fblock.collisionless.ddtheta),
        ddzeta=_block_diag_only(fblock.collisionless.ddzeta, block),
    )
    exb_theta = None if fblock.exb_theta is None else replace(
        fblock.exb_theta, ddtheta=_diag_only(fblock.exb_theta.ddtheta)
    )
    exb_zeta = fblock.exb_zeta
    mag_theta = None
    if fblock.magdrift_theta is not None:
        mag_theta = replace(
            fblock.magdrift_theta,
            ddtheta_plus=_diag_only(fblock.magdrift_theta.ddtheta_plus),
            ddtheta_minus=_diag_only(fblock.magdrift_theta.ddtheta_minus),
        )
    mag_zeta = fblock.magdrift_zeta
    if mag_zeta is not None:
        mag_zeta = replace(
            mag_zeta,
            ddzeta_plus=_block_diag_only(mag_zeta.ddzeta_plus, block),
            ddzeta_minus=_block_diag_only(mag_zeta.ddzeta_minus, block),
        )
    fblock_pc = replace(
        fblock,
        collisionless=coll,
        exb_theta=exb_theta,
        exb_zeta=exb_zeta,
        magdrift_theta=mag_theta,
        magdrift_zeta=mag_zeta,
    )
    return replace(op, fblock=fblock_pc)


def _build_rhsmode1_block_preconditioner_xdiag(
    *,
    op: V3FullSystemOperator,
    reduce_full: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
    expand_reduced: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
    preconditioner_xi: int = 1,
) -> Callable[[jnp.ndarray], jnp.ndarray]:
    """Block preconditioner with x-diagonal blocks (per species, per x).

    This matches v3's `preconditioner_x=1` behavior by dropping x-couplings while
    retaining the requested xi coupling.
    """
    cache_key = _rhsmode1_precond_cache_key(op, f"point_xdiag_xi{int(preconditioner_xi)}")
    cached = _RHSMODE1_PRECOND_DIAGX_CACHE.get(cache_key)
    if cached is None:
        op_pc = _build_rhsmode1_preconditioner_operator_point(op)
        n_s = int(op.n_species)
        n_x = int(op.n_x)
        n_l = int(op.n_xi)
        n_t = int(op.n_theta)
        n_z = int(op.n_zeta)
        total = int(op.total_size)

        nxi_for_x = np.asarray(op.fblock.collisionless.n_xi_for_x, dtype=np.int32)
        max_l = int(np.max(nxi_for_x)) if nxi_for_x.size else 0
        precond_dtype = _precond_dtype(max_l * max_l)

        reg_env = os.environ.get("SFINCS_JAX_RHSMODE1_PRECOND_REG", "").strip()
        reg_val = float(reg_env) if reg_env else 1e-10
        reg = np.float64(reg_val)

        block_inv_list: list[list[jnp.ndarray]] = []
        idx_map_list: list[list[jnp.ndarray]] = []
        for s in range(n_s):
            inv_row: list[jnp.ndarray] = []
            idx_row: list[jnp.ndarray] = []
            for ix in range(n_x):
                max_lx = int(nxi_for_x[ix])
                if max_lx <= 0:
                    inv_row.append(jnp.zeros((0, 0), dtype=precond_dtype))
                    idx_row.append(jnp.zeros((n_t, n_z, 0), dtype=jnp.int32))
                    continue
                rep_idx = np.zeros((max_lx,), dtype=np.int32)
                for il in range(max_lx):
                    rep_idx[il] = int(((((s * n_x + ix) * n_l + il) * n_t + 0) * n_z + 0))
                chunk_cols = _precond_chunk_cols(total, int(rep_idx.shape[0]))
                y_sub = _matvec_submatrix(
                    op_pc,
                    col_idx=rep_idx,
                    row_idx=rep_idx,
                    total_size=total,
                    chunk_cols=chunk_cols,
                )
                a = np.asarray(y_sub.T, dtype=np.float64)
                if preconditioner_xi != 0:
                    a = np.diag(np.diag(a))
                a = a + reg * np.eye(max_lx, dtype=np.float64)
                try:
                    inv = np.linalg.inv(a)
                except np.linalg.LinAlgError:
                    inv = np.linalg.pinv(a, rcond=1e-12)
                if not np.all(np.isfinite(inv)):
                    inv = np.linalg.pinv(a, rcond=1e-12)
                inv_row.append(jnp.asarray(inv, dtype=precond_dtype))
                idx_map = np.zeros((n_t, n_z, max_lx), dtype=np.int32)
                for it in range(n_t):
                    for iz in range(n_z):
                        for il in range(max_lx):
                            idx_map[it, iz, il] = int(
                                ((((s * n_x + ix) * n_l + il) * n_t + it) * n_z + iz)
                            )
                idx_row.append(jnp.asarray(idx_map, dtype=jnp.int32))
            block_inv_list.append(inv_row)
            idx_map_list.append(idx_row)

        extra_start = int(op.f_size + op.phi1_size)
        extra_size = int(op.extra_size)
        extra_idx_np = np.arange(extra_start, extra_start + extra_size, dtype=np.int32)
        extra_idx_jnp = jnp.asarray(extra_idx_np, dtype=jnp.int32)
        extra_inv_jnp: jnp.ndarray | None = None
        if extra_size > 0:
            chunk_cols = _precond_chunk_cols(total, int(extra_idx_np.shape[0]))
            y_sub = _matvec_submatrix(
                op_pc,
                col_idx=extra_idx_np,
                row_idx=extra_idx_np,
                total_size=total,
                chunk_cols=chunk_cols,
            )
            ee = np.asarray(y_sub.T, dtype=np.float64)
            ee = ee + reg * np.eye(extra_size, dtype=np.float64)
            try:
                ee_inv = np.linalg.inv(ee)
            except np.linalg.LinAlgError:
                ee_inv = np.linalg.pinv(ee, rcond=1e-12)
            if not np.all(np.isfinite(ee_inv)):
                ee_inv = np.linalg.pinv(ee, rcond=1e-12)
            extra_inv_jnp = jnp.asarray(ee_inv, dtype=precond_dtype)

        cached = _RHSMode1PrecondDiagXCache(
            block_inv_list=tuple(tuple(row) for row in block_inv_list),
            idx_map_list=tuple(tuple(row) for row in idx_map_list),
            extra_idx_jnp=extra_idx_jnp,
            extra_inv_jnp=extra_inv_jnp,
        )
        _RHSMODE1_PRECOND_DIAGX_CACHE[cache_key] = cached

    block_inv_list = cached.block_inv_list
    idx_map_list = cached.idx_map_list
    extra_idx_jnp = cached.extra_idx_jnp
    extra_inv_jnp = cached.extra_inv_jnp
    n_s = int(op.n_species)
    n_x = int(op.n_x)

    def _apply_full(r_full: jnp.ndarray) -> jnp.ndarray:
        r_full = jnp.asarray(r_full, dtype=block_inv_list[0][0].dtype if n_s > 0 and n_x > 0 else _precond_dtype())
        z_full = jnp.zeros_like(r_full)
        for s in range(n_s):
            for ix in range(n_x):
                inv = block_inv_list[s][ix]
                idx_map = idx_map_list[s][ix]
                if idx_map.size == 0:
                    continue
                r_loc = r_full[idx_map].reshape((int(op.n_theta), int(op.n_zeta), int(inv.shape[0])))
                z_loc = jnp.einsum("ij,tzj->tzi", inv, r_loc)
                z_full = z_full.at[idx_map].set(z_loc, unique_indices=True)
        if extra_inv_jnp is not None:
            r_extra = r_full[extra_idx_jnp]
            z_extra = extra_inv_jnp @ r_extra
            z_full = z_full.at[extra_idx_jnp].set(z_extra, unique_indices=True)
        return jnp.asarray(z_full, dtype=jnp.float64)

    if reduce_full is None or expand_reduced is None:
        return _apply_full

    def _apply_reduced(r_reduced: jnp.ndarray) -> jnp.ndarray:
        z_full = _apply_full(expand_reduced(r_reduced))
        return reduce_full(z_full)

    return _apply_reduced


def _build_rhsmode1_block_preconditioner(
    *,
    op: V3FullSystemOperator,
    reduce_full: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
    expand_reduced: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
    preconditioner_species: int = 1,
    preconditioner_x: int = 1,
    preconditioner_xi: int = 1,
) -> Callable[[jnp.ndarray], jnp.ndarray]:
    """Build a PETSc-like block preconditioner for RHSMode=1 solves.

    Structure:
    - x/L local block solve per species at each (theta,zeta), using a representative
      per-species block matrix from a simplified operator.
    - explicit extra/source-row solve via a dense small block.
    """
    if int(preconditioner_species) == 0:
        return _build_rhsmode1_species_xblock_preconditioner(op=op, reduce_full=reduce_full, expand_reduced=expand_reduced)
    if int(preconditioner_x) == 1:
        return _build_rhsmode1_block_preconditioner_xdiag(
            op=op, reduce_full=reduce_full, expand_reduced=expand_reduced, preconditioner_xi=preconditioner_xi
        )
    cache_key = _rhsmode1_precond_cache_key(op, "point")
    precond_dtype = _precond_dtype()
    cached = _RHSMODE1_PRECOND_CACHE.get(cache_key)
    if cached is None:
        op_pc = _build_rhsmode1_preconditioner_operator_point(op)
        n_s = int(op.n_species)
        n_x = int(op.n_x)
        n_l = int(op.n_xi)
        n_t = int(op.n_theta)
        n_z = int(op.n_zeta)
        total = int(op.total_size)

        nxi_for_x = np.asarray(op.fblock.collisionless.n_xi_for_x, dtype=np.int32)
        local_per_species = int(np.sum(nxi_for_x))

        # Representative local x/L blocks at (theta,zeta)=(0,0), one per species.
        rep_indices_by_species: list[np.ndarray] = []
        for s in range(n_s):
            idx: list[int] = []
            for ix in range(n_x):
                max_l = int(nxi_for_x[ix])
                for il in range(max_l):
                    f_idx = ((((s * n_x + ix) * n_l + il) * n_t + 0) * n_z + 0)
                    idx.append(int(f_idx))
            rep_indices_by_species.append(np.asarray(idx, dtype=np.int32))

        reg_env = os.environ.get("SFINCS_JAX_RHSMODE1_PRECOND_REG", "").strip()
        reg_val = float(reg_env) if reg_env else 1e-10
        reg = np.float64(reg_val)

        block_inv = np.zeros((n_s, local_per_species, local_per_species), dtype=np.float64)
        for s in range(n_s):
            rep_idx = rep_indices_by_species[s]
            chunk_cols = _precond_chunk_cols(total, int(np.asarray(rep_idx).shape[0]))
            y_sub = _matvec_submatrix(
                op_pc,
                col_idx=rep_idx,
                row_idx=rep_idx,
                total_size=total,
                chunk_cols=chunk_cols,
            )
            a = np.asarray(y_sub.T, dtype=np.float64)
            a = a + reg * np.eye(local_per_species, dtype=np.float64)
            try:
                inv = np.linalg.inv(a)
            except np.linalg.LinAlgError:
                inv = np.linalg.pinv(a, rcond=1e-12)
            if not np.all(np.isfinite(inv)):
                inv = np.linalg.pinv(a, rcond=1e-12)
            block_inv[s, :, :] = inv

        # Build per-(s,theta,zeta) gather map for active x/L rows.
        idx_map = np.zeros((n_s, n_t, n_z, local_per_species), dtype=np.int32)
        for s in range(n_s):
            for it in range(n_t):
                for iz in range(n_z):
                    k = 0
                    for ix in range(n_x):
                        max_l = int(nxi_for_x[ix])
                        for il in range(max_l):
                            idx_map[s, it, iz, k] = int(
                                ((((s * n_x + ix) * n_l + il) * n_t + it) * n_z + iz)
                            )
                            k += 1

        idx_map_jnp = jnp.asarray(idx_map, dtype=jnp.int32)
        flat_idx_jnp = idx_map_jnp.reshape((-1,))
        block_inv_jnp = jnp.asarray(block_inv, dtype=precond_dtype)

        extra_start = int(op.f_size + op.phi1_size)
        extra_size = int(op.extra_size)
        extra_idx_np = np.arange(extra_start, extra_start + extra_size, dtype=np.int32)
        extra_idx_jnp = jnp.asarray(extra_idx_np, dtype=jnp.int32)
        extra_inv_jnp: jnp.ndarray | None = None
        if extra_size > 0:
            chunk_cols = _precond_chunk_cols(total, int(extra_idx_np.shape[0]))
            y_sub = _matvec_submatrix(
                op_pc,
                col_idx=extra_idx_np,
                row_idx=extra_idx_np,
                total_size=total,
                chunk_cols=chunk_cols,
            )
            ee = np.asarray(y_sub.T, dtype=np.float64)
            ee = ee + reg * np.eye(extra_size, dtype=np.float64)
            try:
                ee_inv = np.linalg.inv(ee)
            except np.linalg.LinAlgError:
                ee_inv = np.linalg.pinv(ee, rcond=1e-12)
            if not np.all(np.isfinite(ee_inv)):
                ee_inv = np.linalg.pinv(ee, rcond=1e-12)
            extra_inv_jnp = jnp.asarray(ee_inv, dtype=precond_dtype)

        cached = _RHSMode1PrecondCache(
            idx_map_jnp=idx_map_jnp,
            flat_idx_jnp=flat_idx_jnp,
            block_inv_jnp=block_inv_jnp,
            extra_idx_jnp=extra_idx_jnp,
            extra_inv_jnp=extra_inv_jnp,
        )
        _RHSMODE1_PRECOND_CACHE[cache_key] = cached

    n_s = int(op.n_species)
    n_t = int(op.n_theta)
    n_z = int(op.n_zeta)
    local_per_species = int(cached.block_inv_jnp.shape[-1])
    flat_idx_jnp = cached.flat_idx_jnp
    block_inv_jnp = cached.block_inv_jnp
    extra_idx_jnp = cached.extra_idx_jnp
    extra_inv_jnp = cached.extra_inv_jnp

    def _apply_full(r_full: jnp.ndarray) -> jnp.ndarray:
        r_full = jnp.asarray(r_full, dtype=precond_dtype)
        r_loc = r_full[flat_idx_jnp].reshape((n_s, n_t, n_z, local_per_species))
        z_loc = jnp.einsum("sab,stzb->stza", block_inv_jnp, r_loc)
        z_full = jnp.zeros_like(r_full)
        z_full = z_full.at[flat_idx_jnp].set(z_loc.reshape((-1,)), unique_indices=True)
        if extra_inv_jnp is not None:
            r_extra = r_full[extra_idx_jnp]
            z_extra = extra_inv_jnp @ r_extra
            z_full = z_full.at[extra_idx_jnp].set(z_extra, unique_indices=True)
        return jnp.asarray(z_full, dtype=jnp.float64)

    if reduce_full is None or expand_reduced is None:
        return _apply_full

    def _apply_reduced(r_reduced: jnp.ndarray) -> jnp.ndarray:
        z_full = _apply_full(expand_reduced(r_reduced))
        return reduce_full(z_full)

    return _apply_reduced


def _build_rhsmode23_theta_dd_preconditioner(
    *,
    op: V3FullSystemOperator,
    block: int,
    reduce_full: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
    expand_reduced: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
) -> Callable[[jnp.ndarray], jnp.ndarray]:
    """Domain-decomposition theta-block preconditioner for RHSMode=2/3 transport solves."""
    return _build_rhsmode1_theta_dd_preconditioner(
        op=op,
        block=int(block),
        reduce_full=reduce_full,
        expand_reduced=expand_reduced,
    )


def _build_rhsmode23_zeta_dd_preconditioner(
    *,
    op: V3FullSystemOperator,
    block: int,
    reduce_full: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
    expand_reduced: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
) -> Callable[[jnp.ndarray], jnp.ndarray]:
    """Domain-decomposition zeta-block preconditioner for RHSMode=2/3 transport solves."""
    return _build_rhsmode1_zeta_dd_preconditioner(
        op=op,
        block=int(block),
        reduce_full=reduce_full,
        expand_reduced=expand_reduced,
    )


def _build_rhsmode23_theta_schwarz_preconditioner(
    *,
    op: V3FullSystemOperator,
    block: int,
    overlap: int,
    reduce_full: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
    expand_reduced: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
) -> Callable[[jnp.ndarray], jnp.ndarray]:
    """Restricted additive Schwarz theta-line preconditioner for transport solves."""
    return _build_rhsmode1_theta_schwarz_preconditioner(
        op=op,
        block=int(block),
        overlap=int(overlap),
        reduce_full=reduce_full,
        expand_reduced=expand_reduced,
    )


def _build_rhsmode23_zeta_schwarz_preconditioner(
    *,
    op: V3FullSystemOperator,
    block: int,
    overlap: int,
    reduce_full: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
    expand_reduced: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
) -> Callable[[jnp.ndarray], jnp.ndarray]:
    """Restricted additive Schwarz zeta-line preconditioner for transport solves."""
    return _build_rhsmode1_zeta_schwarz_preconditioner(
        op=op,
        block=int(block),
        overlap=int(overlap),
        reduce_full=reduce_full,
        expand_reduced=expand_reduced,
    )


def _build_rhsmode23_block_preconditioner(
    *,
    op: V3FullSystemOperator,
    reduce_full: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
    expand_reduced: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
) -> Callable[[jnp.ndarray], jnp.ndarray]:
    """Build a block-Jacobi preconditioner for RHSMode=2/3 transport solves.

    Uses the same local x/L block structure as RHSMode=1 preconditioning, but
    applies it to the transport operator (RHSMode=2/3) using a simplified
    operator with diagonalized theta/zeta derivatives.
    """
    cache_key = _transport_precond_cache_key(op, "block")
    precond_dtype = _precond_dtype()
    cached = _RHSMODE23_PRECOND_CACHE.get(cache_key)
    if cached is None:
        op_pc = _build_transport_preconditioner_operator_point(op)
        n_s = int(op.n_species)
        n_x = int(op.n_x)
        n_l = int(op.n_xi)
        n_t = int(op.n_theta)
        n_z = int(op.n_zeta)
        total = int(op.total_size)

        nxi_for_x = np.asarray(op.fblock.collisionless.n_xi_for_x, dtype=np.int32)
        local_per_species = int(np.sum(nxi_for_x))

        rep_indices_by_species: list[np.ndarray] = []
        for s in range(n_s):
            idx: list[int] = []
            for ix in range(n_x):
                max_l = int(nxi_for_x[ix])
                for il in range(max_l):
                    f_idx = ((((s * n_x + ix) * n_l + il) * n_t + 0) * n_z + 0)
                    idx.append(int(f_idx))
            rep_indices_by_species.append(np.asarray(idx, dtype=np.int32))

        reg_env = os.environ.get("SFINCS_JAX_TRANSPORT_PRECOND_BLOCK_REG", "").strip()
        if not reg_env:
            reg_env = os.environ.get("SFINCS_JAX_TRANSPORT_PRECOND_REG", "").strip()
        try:
            reg = float(reg_env) if reg_env else 1e-10
        except ValueError:
            reg = 1e-10

        block_inv = np.zeros((n_s, local_per_species, local_per_species), dtype=np.float64)
        for s in range(n_s):
            rep_idx = rep_indices_by_species[s]
            chunk_cols = _precond_chunk_cols(total, int(np.asarray(rep_idx).shape[0]))
            y_sub = _matvec_submatrix(
                op_pc,
                col_idx=rep_idx,
                row_idx=rep_idx,
                total_size=total,
                chunk_cols=chunk_cols,
            )
            a = np.asarray(y_sub.T, dtype=np.float64)
            a = a + reg * np.eye(local_per_species, dtype=np.float64)
            try:
                inv = np.linalg.inv(a)
            except np.linalg.LinAlgError:
                inv = np.linalg.pinv(a, rcond=1e-12)
            if not np.all(np.isfinite(inv)):
                inv = np.linalg.pinv(a, rcond=1e-12)
            block_inv[s, :, :] = inv

        idx_map = np.zeros((n_s, n_t, n_z, local_per_species), dtype=np.int32)
        for s in range(n_s):
            for it in range(n_t):
                for iz in range(n_z):
                    k = 0
                    for ix in range(n_x):
                        max_l = int(nxi_for_x[ix])
                        for il in range(max_l):
                            idx_map[s, it, iz, k] = int(
                                ((((s * n_x + ix) * n_l + il) * n_t + it) * n_z + iz)
                            )
                            k += 1

        idx_map_jnp = jnp.asarray(idx_map, dtype=jnp.int32)
        flat_idx_jnp = idx_map_jnp.reshape((-1,))
        block_inv_jnp = jnp.asarray(block_inv, dtype=precond_dtype)

        extra_start = int(op.f_size + op.phi1_size)
        extra_size = int(op.extra_size)
        extra_idx_np = np.arange(extra_start, extra_start + extra_size, dtype=np.int32)
        extra_idx_jnp = jnp.asarray(extra_idx_np, dtype=jnp.int32)
        extra_inv_jnp: jnp.ndarray | None = None
        if extra_size > 0:
            chunk_cols = _precond_chunk_cols(total, int(extra_idx_np.shape[0]))
            y_sub = _matvec_submatrix(
                op_pc,
                col_idx=extra_idx_np,
                row_idx=extra_idx_np,
                total_size=total,
                chunk_cols=chunk_cols,
            )
            a = np.asarray(y_sub.T, dtype=np.float64)
            a = a + reg * np.eye(extra_size, dtype=np.float64)
            try:
                extra_inv = np.linalg.inv(a)
            except np.linalg.LinAlgError:
                extra_inv = np.linalg.pinv(a, rcond=1e-12)
            if not np.all(np.isfinite(extra_inv)):
                extra_inv = np.linalg.pinv(a, rcond=1e-12)
            extra_inv_jnp = jnp.asarray(extra_inv, dtype=precond_dtype)

        cached = _RHSMode1PrecondCache(
            idx_map_jnp=idx_map_jnp,
            flat_idx_jnp=flat_idx_jnp,
            block_inv_jnp=block_inv_jnp,
            extra_idx_jnp=extra_idx_jnp,
            extra_inv_jnp=extra_inv_jnp,
        )
        _RHSMODE23_PRECOND_CACHE[cache_key] = cached

    idx_map_jnp = cached.idx_map_jnp
    flat_idx_jnp = cached.flat_idx_jnp
    block_inv_jnp = cached.block_inv_jnp
    extra_idx_jnp = cached.extra_idx_jnp
    extra_inv_jnp = cached.extra_inv_jnp
    n_s = int(op.n_species)
    n_t = int(op.n_theta)
    n_z = int(op.n_zeta)
    local_per_species = int(idx_map_jnp.shape[-1])

    def _apply_full(r_full: jnp.ndarray) -> jnp.ndarray:
        r_full = jnp.asarray(r_full, dtype=precond_dtype)
        r_loc = r_full[flat_idx_jnp].reshape((n_s, n_t, n_z, local_per_species))
        z_loc = jnp.einsum("sab,stzb->stza", block_inv_jnp, r_loc)
        z_full = jnp.zeros_like(r_full)
        z_full = z_full.at[flat_idx_jnp].set(z_loc.reshape((-1,)), unique_indices=True)
        if extra_inv_jnp is not None:
            r_extra = r_full[extra_idx_jnp]
            z_extra = extra_inv_jnp @ r_extra
            z_full = z_full.at[extra_idx_jnp].set(z_extra, unique_indices=True)
        return jnp.asarray(z_full, dtype=jnp.float64)

    if reduce_full is None or expand_reduced is None:
        return _apply_full

    def _apply_reduced(r_reduced: jnp.ndarray) -> jnp.ndarray:
        z_full = _apply_full(expand_reduced(r_reduced))
        return reduce_full(z_full)

    return _apply_reduced


def _build_rhsmode23_fp_tzfft_preconditioner(
    *,
    op: V3FullSystemOperator,
    reduce_full: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
    expand_reduced: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
) -> Callable[[jnp.ndarray], jnp.ndarray]:
    """Fourier-space FP transport preconditioner for high-collisionality 3D runs.

    The W7-X high-``nu'`` FP transport lane is stiff because the Fokker-Planck
    collision block is dense in speed/species while the streaming/mirror terms
    dominate the angular Krylov spectrum. This preconditioner keeps the full FP
    dense block in ``(species, x)`` for each Legendre mode and adds a
    flux-surface-averaged streaming/mirror symbol in Fourier space. Each
    ``(k_theta, k_zeta)`` mode then solves one modest dense block over
    ``L * species * x``.

    It is intentionally opt-in through ``SFINCS_JAX_TRANSPORT_PRECOND=fp_tzfft``
    until full W7-X high-``nu'`` GPU residual benchmarks prove it should become
    a default.
    """
    if op.fblock.fp is None:
        return _build_rhsmode23_tzfft_preconditioner(
            op=op, reduce_full=reduce_full, expand_reduced=expand_reduced
        )

    n_species = int(op.n_species)
    n_x = int(op.n_x)
    n_l = int(op.n_xi)
    n_theta = int(op.n_theta)
    n_zeta = int(op.n_zeta)
    n_block = int(n_species * n_x)
    n_mode = int(n_l * n_block)
    if n_mode <= 0 or n_theta <= 0 or n_zeta <= 0:
        return _build_rhsmode23_sxblock_preconditioner(
            op=op, reduce_full=reduce_full, expand_reduced=expand_reduced
        )

    precond_dtype = _precond_dtype()
    complex_dtype = jnp.complex64 if precond_dtype == jnp.float32 else jnp.complex128
    bytes_per_complex = 8.0 if complex_dtype == jnp.complex64 else 16.0
    est_mb = float(n_theta * n_zeta * n_mode * n_mode) * bytes_per_complex / 1.0e6
    max_env = os.environ.get("SFINCS_JAX_TRANSPORT_FP_TZFFT_MAX_MB", "").strip()
    try:
        max_mb = float(max_env) if max_env else 384.0
    except ValueError:
        max_mb = 384.0
    if max_mb > 0.0 and est_mb > max_mb:
        return _build_rhsmode23_sxblock_preconditioner(
            op=op, reduce_full=reduce_full, expand_reduced=expand_reduced
        )

    reg_env = os.environ.get("SFINCS_JAX_TRANSPORT_FP_TZFFT_REG", "").strip()
    try:
        reg = float(reg_env) if reg_env else 1.0e-10
    except ValueError:
        reg = 1.0e-10
    pinv_env = os.environ.get("SFINCS_JAX_TRANSPORT_FP_TZFFT_PINV_RCOND", "").strip()
    try:
        pinv_rcond = float(pinv_env) if pinv_env else 1.0e-12
    except ValueError:
        pinv_rcond = 1.0e-12

    cache_key = _transport_precond_cache_key(op, f"fp_tzfft_{complex_dtype}_{float(reg):.3e}")
    cached = _TRANSPORT_FP_TZFFT_PRECOND_CACHE.get(cache_key)
    if cached is None:
        cl = op.fblock.collisionless
        fp = op.fblock.fp
        assert cl is not None
        assert fp is not None

        ddtheta0 = np.asarray(cl.ddtheta[:, 0], dtype=np.complex128)
        ddzeta0 = np.asarray(cl.ddzeta[:, 0], dtype=np.complex128)
        eig_theta = np.fft.fft(ddtheta0)  # (T,)
        eig_zeta = np.fft.fft(ddzeta0)  # (Z,)

        factor = np.asarray(_fs_average_factor(op.theta_weights, op.zeta_weights, op.d_hat), dtype=np.float64)
        wsum = float(np.sum(factor))
        if wsum == 0.0:
            wsum = 1.0

        b_hat = np.asarray(op.b_hat, dtype=np.float64)
        b_sup_theta = np.asarray(op.b_hat_sup_theta, dtype=np.float64)
        b_sup_zeta = np.asarray(op.b_hat_sup_zeta, dtype=np.float64)
        db_dtheta = np.asarray(op.db_hat_dtheta, dtype=np.float64)
        db_dzeta = np.asarray(op.db_hat_dzeta, dtype=np.float64)

        v_theta = float(np.sum(factor * (b_sup_theta / b_hat)) / wsum)
        v_zeta = float(np.sum(factor * (b_sup_zeta / b_hat)) / wsum)
        mirror_geom = b_sup_theta * db_dtheta + b_sup_zeta * db_dzeta
        mirror_base = float(np.sum(factor * (mirror_geom / (2.0 * (b_hat**2)))) / wsum)

        sqrt_t_over_m = np.sqrt(np.asarray(op.t_hat, dtype=np.float64) / np.asarray(op.m_hat, dtype=np.float64))
        v_theta_s = sqrt_t_over_m * v_theta
        v_zeta_s = sqrt_t_over_m * v_zeta
        mirror_factor_s = -sqrt_t_over_m * mirror_base
        d_symbol = (
            v_theta_s[:, None, None] * eig_theta[None, :, None]
            + v_zeta_s[:, None, None] * eig_zeta[None, None, :]
        )  # (S,T,Z)

        exb_symbol = np.zeros((n_theta, n_zeta), dtype=np.complex128)
        if op.fblock.exb_theta is not None or op.fblock.exb_zeta is not None:
            if op.fblock.exb_theta is not None:
                exb_theta = op.fblock.exb_theta
                if getattr(exb_theta, "use_dkes_exb_drift", False):
                    denom = float(np.asarray(exb_theta.fsab_hat2, dtype=np.float64).reshape(()))
                    coef = np.asarray(exb_theta.d_hat * exb_theta.b_hat_sub_zeta, dtype=np.float64) / denom
                else:
                    coef = np.asarray(exb_theta.d_hat * exb_theta.b_hat_sub_zeta, dtype=np.float64) / (
                        np.asarray(exb_theta.b_hat, dtype=np.float64) ** 2
                    )
                coef_avg = float(np.sum(factor * coef) / wsum)
                exb_factor = (
                    float(np.asarray(exb_theta.alpha, dtype=np.float64).reshape(()))
                    * float(np.asarray(exb_theta.delta, dtype=np.float64).reshape(()))
                    * 0.5
                    * float(np.asarray(exb_theta.dphi_hat_dpsi_hat, dtype=np.float64).reshape(()))
                )
                exb_symbol += (exb_factor * coef_avg * eig_theta)[:, None]
            if op.fblock.exb_zeta is not None:
                exb_zeta = op.fblock.exb_zeta
                if getattr(exb_zeta, "use_dkes_exb_drift", False):
                    denom = float(np.asarray(exb_zeta.fsab_hat2, dtype=np.float64).reshape(()))
                    coef = np.asarray(exb_zeta.d_hat * exb_zeta.b_hat_sub_theta, dtype=np.float64) / denom
                else:
                    coef = np.asarray(exb_zeta.d_hat * exb_zeta.b_hat_sub_theta, dtype=np.float64) / (
                        np.asarray(exb_zeta.b_hat, dtype=np.float64) ** 2
                    )
                coef_avg = float(np.sum(factor * coef) / wsum)
                exb_factor = (
                    -float(np.asarray(exb_zeta.alpha, dtype=np.float64).reshape(()))
                    * float(np.asarray(exb_zeta.delta, dtype=np.float64).reshape(()))
                    * 0.5
                    * float(np.asarray(exb_zeta.dphi_hat_dpsi_hat, dtype=np.float64).reshape(()))
                )
                exb_symbol += (exb_factor * coef_avg * eig_zeta)[None, :]

        mat_fp = np.asarray(fp.mat, dtype=np.float64)  # (S,S,L,X,X)
        identity_shift = float(op.fblock.identity_shift)
        pas_diag = None
        if op.fblock.pas is not None:
            pas = op.fblock.pas
            l_arr = np.arange(n_l, dtype=np.float64)
            factor_l = 0.5 * (l_arr * (l_arr + 1.0) + 2.0 * float(pas.krook))
            pas_diag = float(pas.nu_n) * np.asarray(pas.nu_d_hat, dtype=np.float64)[:, :, None] * factor_l[None, None, :]

        nxi_for_x = np.asarray(op.fblock.collisionless.n_xi_for_x, dtype=np.int32)
        active = np.arange(n_l, dtype=np.int32)[None, :] < nxi_for_x[:, None]  # (X,L)
        x_arr = np.asarray(cl.x, dtype=np.float64)
        l_arr = np.arange(n_l, dtype=np.float64)
        coef_plus = x_arr[:, None] * (l_arr[None, :] + 1.0) / (2.0 * l_arr[None, :] + 3.0)
        coef_minus = np.where(l_arr[None, :] > 0, x_arr[:, None] * l_arr[None, :] / (2.0 * l_arr[None, :] - 1.0), 0.0)
        coef_mirror_plus = x_arr[:, None] * (l_arr[None, :] + 1.0) * (l_arr[None, :] + 2.0) / (
            2.0 * l_arr[None, :] + 3.0
        )
        coef_mirror_minus = np.where(
            l_arr[None, :] > 1,
            -x_arr[:, None] * l_arr[None, :] * (l_arr[None, :] - 1.0) / (2.0 * l_arr[None, :] - 1.0),
            0.0,
        )

        base_blocks: list[np.ndarray] = []
        for il in range(n_l):
            a_l = np.array(mat_fp[:, :, il, :, :], dtype=np.float64, copy=True)
            a_l = a_l.transpose(0, 2, 1, 3).reshape((n_block, n_block))
            diag_add = np.full((n_block,), identity_shift + float(reg), dtype=np.float64)
            if pas_diag is not None:
                diag_add += pas_diag[:, :, il].reshape((n_block,))
            a_l[np.arange(n_block), np.arange(n_block)] += diag_add
            inactive_x = np.where(~active[:, il])[0]
            for ix in inactive_x:
                for s in range(n_species):
                    p = int(s * n_x + int(ix))
                    a_l[p, :] = 0.0
                    a_l[:, p] = 0.0
                    a_l[p, p] = 1.0
            base_blocks.append(a_l)

        inv_mode = np.zeros((n_theta, n_zeta, n_mode, n_mode), dtype=np.complex128)
        for kt in range(n_theta):
            for kz in range(n_zeta):
                a = np.zeros((n_mode, n_mode), dtype=np.complex128)
                for il, a_l in enumerate(base_blocks):
                    r0 = int(il * n_block)
                    r1 = r0 + n_block
                    a[r0:r1, r0:r1] = a_l.astype(np.complex128)
                    if exb_symbol[kt, kz] != 0.0:
                        for s in range(n_species):
                            for ix in range(n_x):
                                if active[ix, il]:
                                    p = r0 + int(s * n_x + ix)
                                    a[p, p] += exb_symbol[kt, kz]
                for il in range(n_l):
                    for s in range(n_species):
                        symbol = d_symbol[s, kt, kz]
                        mirror_symbol = mirror_factor_s[s]
                        for ix in range(n_x):
                            p = int(il * n_block + s * n_x + ix)
                            if il + 1 < n_l and active[ix, il] and active[ix, il + 1]:
                                q = int((il + 1) * n_block + s * n_x + ix)
                                a[p, q] += coef_plus[ix, il] * symbol + coef_mirror_plus[ix, il] * mirror_symbol
                            if il - 1 >= 0 and active[ix, il] and active[ix, il - 1]:
                                q = int((il - 1) * n_block + s * n_x + ix)
                                a[p, q] += coef_minus[ix, il] * symbol + coef_mirror_minus[ix, il] * mirror_symbol
                try:
                    inv = np.linalg.inv(a)
                except np.linalg.LinAlgError:
                    inv = np.linalg.pinv(a, rcond=pinv_rcond)
                if not np.all(np.isfinite(inv)):
                    inv = np.linalg.pinv(a, rcond=pinv_rcond)
                inv_mode[kt, kz, :, :] = inv

        cached = _TransportFpTzFftPrecondCache(
            inv_mode=jnp.asarray(inv_mode, dtype=complex_dtype),
            n_block=int(n_block),
        )
        _TRANSPORT_FP_TZFFT_PRECOND_CACHE[cache_key] = cached

    inv_mode = cached.inv_mode
    n_block = int(cached.n_block)

    def _apply_full(r_full: jnp.ndarray) -> jnp.ndarray:
        r_full = jnp.asarray(r_full, dtype=jnp.float64)
        f = r_full[: op.f_size].reshape(op.fblock.f_shape)  # (S,X,L,T,Z)
        f_hat = jnp.fft.fftn(f.astype(complex_dtype), axes=(-2, -1))
        rhs_modes = jnp.transpose(f_hat, (3, 4, 2, 0, 1)).reshape((n_theta, n_zeta, n_l * n_block))
        sol_modes = jnp.einsum("tzij,tzj->tzi", inv_mode, rhs_modes)
        sol = sol_modes.reshape((n_theta, n_zeta, n_l, n_species, n_x))
        sol_f = jnp.transpose(sol, (3, 4, 2, 0, 1))  # (S,X,L,T,Z)
        z_f = jnp.fft.ifftn(sol_f, axes=(-2, -1)).real.astype(jnp.float64)
        tail = r_full[op.f_size :]
        z_full = jnp.concatenate([z_f.reshape((-1,)), tail], axis=0)
        return jnp.asarray(z_full, dtype=jnp.float64)

    if reduce_full is None or expand_reduced is None:
        return _apply_full

    def _apply_reduced(r_reduced: jnp.ndarray) -> jnp.ndarray:
        z_full = _apply_full(expand_reduced(r_reduced))
        return reduce_full(z_full)

    return _apply_reduced


def _build_rhsmode1_schur_preconditioner(
    *,
    op: V3FullSystemOperator,
    reduce_full: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
    expand_reduced: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
) -> Callable[[jnp.ndarray], jnp.ndarray]:
    """Approximate Schur-complement preconditioner for constraintScheme=2 RHSMode=1 solves."""
    precond_dtype = _precond_dtype()
    geom_scheme = int(_PRECOND_GEOM_SCHEME_HINT or 0)
    base_xblock_tz_lmax = 0
    base_kind_env = os.environ.get("SFINCS_JAX_RHSMODE1_SCHUR_BASE", "").strip().lower()
    nxi_for_x = np.asarray(op.fblock.collisionless.n_xi_for_x, dtype=np.int32)
    use_dkes_exb = bool(getattr(op.fblock.exb_theta, "use_dkes_exb_drift", False)) or bool(
        getattr(op.fblock.exb_zeta, "use_dkes_exb_drift", False)
    )
    base_kind = resolve_rhs1_schur_base_kind(
        base_kind_env=base_kind_env,
        n_theta=int(op.n_theta),
        n_zeta=int(op.n_zeta),
        n_species=int(op.n_species),
        total_size=int(op.total_size),
        nxi_for_x=nxi_for_x,
        has_pas=op.fblock.pas is not None,
        has_fp=op.fblock.fp is not None,
        has_er_xdot=op.fblock.er_xdot is not None,
        has_er_xidot=op.fblock.er_xidot is not None,
        use_dkes_exb=use_dkes_exb,
        pas_tokamak_theta_applicable=_pas_tokamak_theta_preconditioner_applicable(op),
        pas_tz_applicable=_pas_tz_preconditioner_applicable(op),
        geom_scheme=geom_scheme,
    )

    if base_kind == "theta_line":
        base_precond = _build_rhsmode1_theta_line_preconditioner(op=op)
    elif base_kind == "theta_dd":
        dd_block_env = os.environ.get("SFINCS_JAX_RHSMODE1_DD_BLOCK_T", "").strip()
        try:
            dd_block = int(dd_block_env) if dd_block_env else 8
        except ValueError:
            dd_block = 8
        base_precond = _build_rhsmode1_theta_dd_preconditioner(op=op, block=dd_block)
    elif base_kind == "species_block":
        base_precond = _build_rhsmode1_species_block_preconditioner(op=op)
    elif base_kind == "sxblock_tz":
        base_precond = _build_rhsmode1_sxblock_tz_preconditioner(op=op)
    elif base_kind == "xblock_tz":
        base_precond = _build_rhsmode1_xblock_tz_preconditioner(op=op)
    elif base_kind == "xblock_tz_lmax":
        lmax_env = os.environ.get("SFINCS_JAX_RHSMODE1_SCHUR_XBLOCK_TZ_LMAX", "").strip()
        if not lmax_env:
            lmax_env = os.environ.get("SFINCS_JAX_RHSMODE1_XBLOCK_TZ_LMAX", "").strip()
        try:
            lmax_use = int(lmax_env) if lmax_env else int(base_xblock_tz_lmax)
        except ValueError:
            lmax_use = int(base_xblock_tz_lmax)
        base_precond = _build_rhsmode1_xblock_tz_lmax_preconditioner(op=op, lmax=int(lmax_use))
    elif base_kind == "pas_ilu":
        base_precond = _build_rhsmode1_pas_xblock_ilu_preconditioner(op=op)
    elif base_kind == "xmg":
        base_precond = _build_rhsmode1_xmg_preconditioner(op=op)
    elif base_kind == "pas_lite":
        base_precond = _build_rhsmode1_pas_lite_preconditioner(op=op, safe=False)
    elif base_kind == "pas_hybrid":
        base_precond = _build_rhsmode1_pas_hybrid_preconditioner(op=op, safe=False)
    elif base_kind == "pas_schur":
        base_precond = _build_rhsmode1_pas_schur_preconditioner(op=op, safe=False)
    elif base_kind == "pas_tokamak_theta":
        base_precond = _build_rhsmode1_pas_tokamak_theta_preconditioner(op=op)
    elif base_kind == "pas_tz":
        base_precond = _build_rhsmode1_pas_tz_preconditioner(op=op)
    elif base_kind == "theta_zeta":
        base_precond = _build_rhsmode1_theta_zeta_preconditioner(op=op)
    elif base_kind == "zeta_line":
        base_precond = _build_rhsmode1_zeta_line_preconditioner(op=op)
    elif base_kind == "zeta_dd":
        dd_block_env = os.environ.get("SFINCS_JAX_RHSMODE1_DD_BLOCK_Z", "").strip()
        try:
            dd_block = int(dd_block_env) if dd_block_env else 8
        except ValueError:
            dd_block = 8
        base_precond = _build_rhsmode1_zeta_dd_preconditioner(op=op, block=dd_block)
    elif base_kind == "adi":
        pre_theta = _build_rhsmode1_theta_line_preconditioner(op=op)
        pre_zeta = _build_rhsmode1_zeta_line_preconditioner(op=op)
        sweeps_env = os.environ.get("SFINCS_JAX_RHSMODE1_ADI_SWEEPS", "").strip()
        try:
            sweeps = int(sweeps_env) if sweeps_env else 2
        except ValueError:
            sweeps = 2
        sweeps = max(1, sweeps)

        def base_precond(v: jnp.ndarray) -> jnp.ndarray:
            out = v
            for _ in range(sweeps):
                out = pre_zeta(pre_theta(out))
            return out
    else:
        base_precond = _build_rhsmode1_block_preconditioner(op=op)
    f_size = int(op.f_size)
    extra_size = int(op.extra_size)
    n_species = int(op.n_species)
    n_x = int(op.n_x)
    n_constraints = int(extra_size)
    ix0 = _ix_min(bool(op.point_at_x0))

    theta_w = np.asarray(op.theta_weights, dtype=np.float64)
    zeta_w = np.asarray(op.zeta_weights, dtype=np.float64)
    d_hat = np.asarray(op.d_hat, dtype=np.float64)
    fs_sum = float(np.sum((theta_w[:, None] * zeta_w[None, :]) / d_hat))

    # Large PAS+Er constrained systems are expensive to precondition if we assemble a dense Schur
    # complement via repeated full-size preconditioner applications. For the important PAS branch,
    # the constraint operator only touches the L=0 flux-surface average, so we can approximate
    # S^{-1} using an x-coupled L=0 block (dense in x) built from collisions + averaged Er xDot.
    #
    # This is a "block-Schur with x-coarsening" strategy:
    # - Base preconditioner: x-coarse (xmg) for the kinetic block M^{-1}.
    # - Schur inverse approximation: (1/<1>) * M_L0, where <1>=fs_sum and M_L0 is an x-coupled
    #   approximation to the L=0 rows/cols.
    xschur_min_env = os.environ.get("SFINCS_JAX_RHSMODE1_SCHUR_XMG_MIN", "").strip()
    try:
        xschur_min = int(xschur_min_env) if xschur_min_env else 50000
    except ValueError:
        xschur_min = 50000
    use_xschur = bool(
        base_kind in {"xmg", "pas_lite", "pas_hybrid", "pas_tz", "pas_schur"}
        and op.fblock.pas is not None
        and op.fblock.fp is None
        and op.fblock.er_xdot is not None
        and int(op.total_size) >= xschur_min
        and fs_sum != 0.0
    )
    a0_cached: jnp.ndarray | None = None  # (S,X,X)
    if use_xschur:
        try:
            er = op.fblock.er_xdot
            assert er is not None
            pas = op.fblock.pas
            assert pas is not None

            alpha = float(np.asarray(er.alpha, dtype=np.float64).reshape(()))
            delta = float(np.asarray(er.delta, dtype=np.float64).reshape(()))
            dphi = float(np.asarray(er.dphi_hat_dpsi_hat, dtype=np.float64).reshape(()))
            d_hat_er = np.asarray(er.d_hat, dtype=np.float64)  # (T,Z)
            b_hat = np.asarray(er.b_hat, dtype=np.float64)  # (T,Z)
            b_sub_theta = np.asarray(er.b_hat_sub_theta, dtype=np.float64)  # (T,Z)
            b_sub_zeta = np.asarray(er.b_hat_sub_zeta, dtype=np.float64)  # (T,Z)
            db_dtheta = np.asarray(er.db_hat_dtheta, dtype=np.float64)  # (T,Z)
            db_dzeta = np.asarray(er.db_hat_dzeta, dtype=np.float64)  # (T,Z)

            factor0 = -(alpha * delta * dphi) / 4.0
            xdot_factor = factor0 * d_hat_er / (b_hat**3) * (b_sub_theta * db_dzeta - b_sub_zeta * db_dtheta)  # (T,Z)
            fs_factor = (theta_w[:, None] * zeta_w[None, :]) / d_hat  # (T,Z)
            fs_sum_safe = float(np.sum(fs_factor))
            if fs_sum_safe > 0.0:
                xdot_rms = float(np.sqrt(np.sum(fs_factor * (xdot_factor * xdot_factor)) / fs_sum_safe))
            else:
                xdot_rms = 0.0

            # Diagonal-in-L coefficient for L=0 from `apply_er_xdot_v3`:
            # diag_coef = 2*(3L^2+3L-2) / ((2L+3)(2L-1)) -> 4/3 at L=0.
            diag_coef0 = 4.0 / 3.0
            xdot_coef0 = diag_coef0 * xdot_rms

            x_arr = np.asarray(er.x, dtype=np.float64)
            ddx = np.asarray(er.ddx_plus, dtype=np.float64)
            x_part = x_arr[:, None] * ddx  # (X,X)

            pas_coef = np.asarray(pas.coef, dtype=np.float64)  # (S,X,L)
            identity_shift = float(op.fblock.identity_shift)
            reg_env = os.environ.get("SFINCS_JAX_RHSMODE1_SCHUR_XMG_REG", "").strip()
            try:
                reg = float(reg_env) if reg_env else 1e-12
            except ValueError:
                reg = 1e-12

            nxi_for_x = np.asarray(op.fblock.collisionless.n_xi_for_x, dtype=np.int32)
            inactive_x = np.where(nxi_for_x <= 0)[0]
            a0 = np.zeros((n_species, n_x, n_x), dtype=np.float64)
            for s in range(n_species):
                a = np.array(xdot_coef0 * x_part, dtype=np.float64, copy=True)
                a[np.arange(n_x), np.arange(n_x)] += identity_shift + reg + pas_coef[s, :, 0]
                if inactive_x.size:
                    for ix in inactive_x:
                        a[ix, :] = 0.0
                        a[:, ix] = 0.0
                        a[ix, ix] = 1.0
                a0[s, :, :] = a
            a0_cached = jnp.asarray(a0, dtype=precond_dtype)
        except Exception:  # noqa: BLE001
            use_xschur = False
            a0_cached = None

    def _schur_inv_diag() -> jnp.ndarray:
        cache_key = _rhsmode1_precond_cache_key(op, "schur_diag")
        cached = _RHSMODE1_SCHUR_CACHE.get(cache_key)
        if cached is not None:
            return cached
        # Ensure base block preconditioner cache exists.
        _build_rhsmode1_block_preconditioner(
            op=op,
            preconditioner_species=1,
            preconditioner_x=0,
            preconditioner_xi=1,
        )
        block_key = _rhsmode1_precond_cache_key(op, "point")
        block_cached = _RHSMODE1_PRECOND_CACHE.get(block_key)
        if block_cached is None:
            raise RuntimeError("Schur preconditioner requires block preconditioner cache.")
        block_inv = np.asarray(block_cached.block_inv_jnp, dtype=np.float64)
        nxi_for_x = np.asarray(op.fblock.collisionless.n_xi_for_x, dtype=np.int32)
        offsets = np.concatenate([[0], np.cumsum(nxi_for_x)])
        idx = offsets[:-1]
        diag = np.zeros((n_species, n_x), dtype=np.float64)
        for s in range(n_species):
            diag[s, :] = block_inv[s, idx, idx]
        theta_w = np.asarray(op.theta_weights, dtype=np.float64)
        zeta_w = np.asarray(op.zeta_weights, dtype=np.float64)
        d_hat = np.asarray(op.d_hat, dtype=np.float64)
        fs_sum = float(np.sum((theta_w[:, None] * zeta_w[None, :]) / d_hat))
        diag = diag * fs_sum
        eps_env = os.environ.get("SFINCS_JAX_RHSMODE1_SCHUR_EPS", "").strip()
        try:
            eps = float(eps_env) if eps_env else 1e-14
        except ValueError:
            eps = 1e-14
        inv_diag = np.zeros_like(diag)
        mask = np.abs(diag) > eps
        inv_diag[mask] = 1.0 / diag[mask]
        ix0 = _ix_min(bool(op.point_at_x0))
        if ix0 > 0:
            inv_diag[:, :ix0] = 0.0
        inv_diag_jnp = jnp.asarray(inv_diag, dtype=precond_dtype)
        _RHSMODE1_SCHUR_CACHE[cache_key] = inv_diag_jnp
        return inv_diag_jnp

    def _schur_inv_full() -> jnp.ndarray:
        cache_key = _rhsmode1_precond_cache_key(op, f"schur_full_{n_constraints}")
        cached = _RHSMODE1_SCHUR_CACHE.get(cache_key)
        if cached is not None:
            return cached
        # Build a dense approximate Schur complement: S ~= C M^{-1} B.
        # M^{-1} is the block preconditioner for the f-block.
        if n_constraints <= 0:
            inv = np.zeros((0, 0), dtype=np.float64)
            inv_jnp = jnp.asarray(inv, dtype=jnp.float64)
            _RHSMODE1_SCHUR_CACHE[cache_key] = inv_jnp
            return inv_jnp
        if base_kind == "pas_ilu":
            # For block-Jacobi (species,x) ILU bases, S ~= C M^{-1} B is diagonal in the
            # (species,x) constraint index. Building the full Schur matrix by repeatedly
            # applying M^{-1} is wasteful and can dominate runtime for PAS DKES cases.
            #
            # Instead, compute the diagonal using the ILU factors in NumPy (no JAX calls),
            # then return a diagonal dense inverse for compatibility with the existing
            # preconditioner application.
            factors = getattr(base_precond, "_sfincs_pas_ilu_factors", None)
            block_size_max = getattr(base_precond, "_sfincs_pas_ilu_block_size_max", None)
            if factors is not None and block_size_max is not None and int(n_constraints) == int(n_species) * int(n_x):
                (
                    inv_perm_r_sx_jnp,
                    perm_c_sx_jnp,
                    lower_idx_sx_jnp,
                    lower_val_sx_jnp,
                    upper_idx_sx_jnp,
                    upper_val_sx_jnp,
                    upper_diag_sx_jnp,
                ) = factors
                inv_perm_r_sx_np = np.asarray(inv_perm_r_sx_jnp, dtype=np.int32)
                perm_c_sx_np = np.asarray(perm_c_sx_jnp, dtype=np.int32)
                lower_idx_sx_np = np.asarray(lower_idx_sx_jnp, dtype=np.int32)
                lower_val_sx_np = np.asarray(lower_val_sx_jnp, dtype=np.float64)
                upper_idx_sx_np = np.asarray(upper_idx_sx_jnp, dtype=np.int32)
                upper_val_sx_np = np.asarray(upper_val_sx_jnp, dtype=np.float64)
                upper_diag_sx_np = np.asarray(upper_diag_sx_jnp, dtype=np.float64)

                n_theta = int(op.n_theta)
                n_zeta = int(op.n_zeta)
                n_tz = int(n_theta * n_zeta)
                factor_tz = ((theta_w[:, None] * zeta_w[None, :]) / d_hat).reshape((-1,))  # (TZ,)

                rhs_unit = np.zeros((int(block_size_max),), dtype=np.float64)
                rhs_unit[:n_tz] = 1.0

                def _solve_block_np(
                    rhs: np.ndarray,
                    inv_perm_r: np.ndarray,
                    perm_c: np.ndarray,
                    lower_idx: np.ndarray,
                    lower_val: np.ndarray,
                    upper_idx: np.ndarray,
                    upper_val: np.ndarray,
                    upper_diag: np.ndarray,
                ) -> np.ndarray:
                    rhs_perm = rhs[inv_perm_r]
                    n = int(rhs_perm.shape[0])
                    y = np.zeros((n,), dtype=np.float64)
                    if int(lower_idx.shape[1]) > 0:
                        for i in range(n):
                            cols = lower_idx[i]
                            vals = lower_val[i]
                            mask = cols >= 0
                            if np.any(mask):
                                contrib = float(np.dot(vals[mask], y[cols[mask]]))
                            else:
                                contrib = 0.0
                            y[i] = rhs_perm[i] - contrib
                    else:
                        y = rhs_perm
                    x = np.zeros((n,), dtype=np.float64)
                    if int(upper_idx.shape[1]) > 0:
                        for i in range(n - 1, -1, -1):
                            cols = upper_idx[i]
                            vals = upper_val[i]
                            mask = cols >= 0
                            if np.any(mask):
                                contrib = float(np.dot(vals[mask], x[cols[mask]]))
                            else:
                                contrib = 0.0
                            x[i] = (y[i] - contrib) / float(upper_diag[i])
                    else:
                        x = y / upper_diag
                    return x[perm_c]

                diag = np.zeros((n_constraints,), dtype=np.float64)
                for j in range(int(n_constraints)):
                    s = int(j // int(n_x))
                    ix = int(j - s * int(n_x))
                    if ix0 > 0 and ix < int(ix0):
                        # For pointAtX0, the x=0 constraint rows are enforced directly.
                        diag[j] = 1.0
                        continue
                    sol = _solve_block_np(
                        rhs_unit,
                        inv_perm_r_sx_np[s, ix],
                        perm_c_sx_np[s, ix],
                        lower_idx_sx_np[s, ix],
                        lower_val_sx_np[s, ix],
                        upper_idx_sx_np[s, ix],
                        upper_val_sx_np[s, ix],
                        upper_diag_sx_np[s, ix],
                    )
                    diag[j] = float(np.dot(factor_tz, sol[:n_tz]))

                reg_env = os.environ.get("SFINCS_JAX_RHSMODE1_SCHUR_REG", "").strip()
                try:
                    reg = float(reg_env) if reg_env else 1e-12
                except ValueError:
                    reg = 1e-12
                diag = diag + float(reg)
                eps_env = os.environ.get("SFINCS_JAX_RHSMODE1_SCHUR_EPS", "").strip()
                try:
                    eps = float(eps_env) if eps_env else 1e-14
                except ValueError:
                    eps = 1e-14
                inv_diag = np.zeros_like(diag)
                mask = np.abs(diag) > float(eps)
                inv_diag[mask] = 1.0 / diag[mask]
                s_inv = np.diag(inv_diag)
                s_inv_jnp = jnp.asarray(s_inv, dtype=precond_dtype)
                _RHSMODE1_SCHUR_CACHE[cache_key] = s_inv_jnp
                return s_inv_jnp
        # Fast path: if constraints are per-(species,x) and the base preconditioner is
        # block-diagonal in x (i.e. the operator has no x-coupling), then the approximate
        # Schur complement S ~= C M^{-1} B is diagonal in the (species,x) index.
        #
        # Instead of building S column-by-column via n_constraints preconditioner applications,
        # recover the diagonal with a *single* base-preconditioner apply by injecting all
        # constraint sources simultaneously. This is a large win for tokamak-like PAS runs
        # with many x points.
        base_has_x_coupling = bool(
            op.fblock.fp is not None or op.fblock.er_xdot is not None or op.fblock.er_xidot is not None
        )
        # Some bases (point/species/sxblock) deliberately introduce x-coupling even if the
        # underlying operator is x-block-diagonal. Exclude them from the diagonal-Schur shortcut.
        base_is_x_coupled_kind = base_kind in {
            "xmg",
            "pas_lite",
            "pas_hybrid",
            "pas_tz",
            "point",
            "species_block",
            "sxblock_tz",
        }
        if (
            int(n_constraints) == int(n_species) * int(n_x)
            and (not base_has_x_coupling)
            and (not base_is_x_coupled_kind)
        ):
            zeros_e = jnp.zeros((extra_size,), dtype=jnp.float64)
            src = np.ones((n_species, n_x), dtype=np.float64)
            if ix0 > 0:
                src[:, :ix0] = 0.0
            f_src = np.zeros(op.fblock.f_shape, dtype=np.float64)
            f_src[:, ix0:, 0, :, :] = src[:, ix0:, None, None]
            y_full = base_precond(
                jnp.concatenate([jnp.asarray(f_src.reshape((-1,)), dtype=jnp.float64), zeros_e], axis=0)
            )
            y_f = np.asarray(y_full[:f_size], dtype=np.float64).reshape(op.fblock.f_shape)
            factor = ((theta_w[:, None] * zeta_w[None, :]) / d_hat).astype(np.float64, copy=False)  # (T,Z)
            diag_sx = np.einsum("tz,sxtz->sx", factor, y_f[:, :, 0, :, :])  # (S,X)
            diag = diag_sx.reshape((-1,)).copy()
            if ix0 > 0:
                # For pointAtX0, the x=0 constraint rows are enforced directly.
                for j in range(int(n_constraints)):
                    s = int(j // int(n_x))
                    ix = int(j - s * int(n_x))
                    if ix < int(ix0):
                        diag[j] = 1.0
            reg_env = os.environ.get("SFINCS_JAX_RHSMODE1_SCHUR_REG", "").strip()
            try:
                reg = float(reg_env) if reg_env else 1e-12
            except ValueError:
                reg = 1e-12
            diag = diag + float(reg)
            eps_env = os.environ.get("SFINCS_JAX_RHSMODE1_SCHUR_EPS", "").strip()
            try:
                eps = float(eps_env) if eps_env else 1e-14
            except ValueError:
                eps = 1e-14
            inv_diag = np.zeros_like(diag)
            mask = np.abs(diag) > float(eps)
            inv_diag[mask] = 1.0 / diag[mask]
            s_inv = np.diag(inv_diag)
            s_inv_jnp = jnp.asarray(s_inv, dtype=precond_dtype)
            _RHSMODE1_SCHUR_CACHE[cache_key] = s_inv_jnp
            return s_inv_jnp
        zeros_e = jnp.zeros((extra_size,), dtype=jnp.float64)
        s_mat = np.zeros((n_constraints, n_constraints), dtype=np.float64)
        # Build columns of S by applying M^{-1} to constraint injections.
        for j in range(n_constraints):
            basis = np.zeros((n_species, n_x), dtype=np.float64)
            basis.reshape(-1)[j] = 1.0
            f_src = _constraint_scheme2_inject_source(op, basis).reshape((-1,))
            y_full = base_precond(jnp.concatenate([jnp.asarray(f_src, dtype=jnp.float64), zeros_e], axis=0))
            y_f = np.asarray(y_full[:f_size], dtype=np.float64).reshape(op.fblock.f_shape)
            c_y = np.asarray(_constraint_scheme2_source_from_f(op, y_f), dtype=np.float64).reshape((-1,))
            s_mat[:, j] = c_y
        reg_env = os.environ.get("SFINCS_JAX_RHSMODE1_SCHUR_REG", "").strip()
        try:
            reg = float(reg_env) if reg_env else 1e-12
        except ValueError:
            reg = 1e-12
        s_mat = s_mat + reg * np.eye(n_constraints, dtype=np.float64)
        try:
            s_inv = np.linalg.inv(s_mat)
        except np.linalg.LinAlgError:
            s_inv = np.linalg.pinv(s_mat, rcond=1e-12)
        if not np.all(np.isfinite(s_inv)):
            s_inv = np.linalg.pinv(s_mat, rcond=1e-12)
        s_inv_jnp = jnp.asarray(s_inv, dtype=precond_dtype)
        _RHSMODE1_SCHUR_CACHE[cache_key] = s_inv_jnp
        return s_inv_jnp

    schur_mode_env = os.environ.get("SFINCS_JAX_RHSMODE1_SCHUR_MODE", "").strip().lower()
    if schur_mode_env in {"full", "dense"}:
        schur_mode = "full"
    elif schur_mode_env in {"diag", "diagonal"}:
        schur_mode = "diag"
    elif schur_mode_env in {"auto", ""}:
        schur_mode = "auto"
    else:
        schur_mode = "diag"
    schur_full_max_env = os.environ.get("SFINCS_JAX_RHSMODE1_SCHUR_FULL_MAX", "").strip()
    try:
        schur_full_max = int(schur_full_max_env) if schur_full_max_env else 256
    except ValueError:
        schur_full_max = 256
    use_full_schur = bool(schur_mode == "full" or (schur_mode == "auto" and n_constraints <= schur_full_max))

    # Building the diagonal Schur approximation currently requires constructing the
    # (theta,zeta)-point block preconditioner cache, which can be expensive for large
    # active DOF systems. If we are going to use the dense (small) Schur complement,
    # skip the diagonal approximation entirely.
    if use_xschur:
        inv_diag_cached = None
        inv_schur_cached = None
    else:
        inv_diag_cached = _schur_inv_diag() if (not use_full_schur) else None
        inv_schur_cached = _schur_inv_full() if use_full_schur else None

    def _apply_full(r_full: jnp.ndarray) -> jnp.ndarray:
        r_full = jnp.asarray(r_full, dtype=jnp.float64)
        if int(op.rhs_mode) != 1 or int(op.constraint_scheme) != 2 or int(op.phi1_size) != 0 or extra_size == 0:
            return base_precond(r_full)
        r_f = r_full[:f_size]
        r_e = r_full[f_size:]
        zeros_e = jnp.zeros((extra_size,), dtype=r_full.dtype)
        y_full = base_precond(jnp.concatenate([r_f, zeros_e], axis=0))
        y_f = y_full[:f_size]
        f = y_f.reshape(op.fblock.f_shape)
        c_y = _constraint_scheme2_source_from_f(op, f).reshape((-1,))
        if use_xschur and a0_cached is not None:
            y = (c_y - r_e).reshape((n_species, n_x))
            x_e = jnp.einsum("sij,sj->si", a0_cached, y) / float(fs_sum)
            if ix0 > 0:
                # For pointAtX0, the x=0 constraint row is `y_extra = src`, so treat it as identity.
                r_e_mat = r_e.reshape((n_species, n_x))
                x_e = x_e.at[:, :ix0].set(r_e_mat[:, :ix0])
            x_e = x_e.reshape((-1,))
        elif use_full_schur and inv_schur_cached is not None:
            x_e = inv_schur_cached @ (c_y - r_e)
        else:
            inv_diag = inv_diag_cached.reshape((-1,)) if inv_diag_cached is not None else jnp.zeros_like(r_e)
            x_e = (c_y - r_e) * inv_diag
        f_corr = _constraint_scheme2_inject_source(op, x_e.reshape((n_species, n_x)))
        r_corr = r_f - f_corr
        y_corr = base_precond(jnp.concatenate([r_corr, zeros_e], axis=0))
        x_f = y_corr[:f_size]
        return jnp.concatenate([x_f, x_e], axis=0)

    if reduce_full is None or expand_reduced is None:
        return _apply_full

    def _apply_reduced(r_reduced: jnp.ndarray) -> jnp.ndarray:
        z_full = _apply_full(expand_reduced(r_reduced))
        return reduce_full(z_full)

    return _apply_reduced


def _build_rhsmode1_theta_line_preconditioner(
    *,
    op: V3FullSystemOperator,
    reduce_full: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
    expand_reduced: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
) -> Callable[[jnp.ndarray], jnp.ndarray]:
    """Build a stronger RHSMode=1 preconditioner using theta-line blocks.

    For each species and each zeta plane, solve a representative block that couples
    all theta points for all local (x,L) unknowns at that zeta. This approximates the
    dominant streaming/mirror couplings along theta while ignoring zeta derivatives.
    """
    cache_key = _rhsmode1_precond_cache_key(op, "theta_line")
    precond_dtype = _precond_dtype()
    cached = _RHSMODE1_PRECOND_CACHE.get(cache_key)
    if cached is None:
        op_pc = _build_rhsmode1_preconditioner_operator_theta_line(op)
        n_species = int(op.n_species)
        n_x = int(op.n_x)
        n_l = int(op.n_xi)
        n_theta = int(op.n_theta)
        n_zeta = int(op.n_zeta)
        total_size = int(op.total_size)

        nxi_for_x = np.asarray(op.fblock.collisionless.n_xi_for_x, dtype=np.int32)
        local_per_species = int(np.sum(nxi_for_x))
        line_size = int(n_theta * local_per_species)

        reg_env = os.environ.get("SFINCS_JAX_RHSMODE1_PRECOND_REG", "").strip()
        reg_val = float(reg_env) if reg_env else 1e-10
        reg = np.float64(reg_val)

        # Build per-(species,zeta) gather map for all theta points and local (x,L) indices.
        idx_map = np.zeros((n_species, n_zeta, line_size), dtype=np.int32)
        for s in range(n_species):
            for iz in range(n_zeta):
                k = 0
                for it in range(n_theta):
                    for ix in range(n_x):
                        max_l = int(nxi_for_x[ix])
                        for il in range(max_l):
                            idx_map[s, iz, k] = int(
                                ((((s * n_x + ix) * n_l + il) * n_theta + it) * n_zeta + iz)
                            )
                            k += 1

        idx_map_jnp = jnp.asarray(idx_map, dtype=jnp.int32)
        flat_idx_jnp = idx_map_jnp.reshape((-1,))

        # Invert a theta-line block for each zeta plane.
        block_inv = np.zeros((n_species, n_zeta, line_size, line_size), dtype=np.float64)
        for s in range(n_species):
            for iz in range(n_zeta):
                rep_idx = np.asarray(idx_map[s, iz, :], dtype=np.int32)
                chunk_cols = _precond_chunk_cols(total_size, int(rep_idx.shape[0]))
                y_sub = _matvec_submatrix(
                    op_pc,
                    col_idx=rep_idx,
                    row_idx=rep_idx,
                    total_size=total_size,
                    chunk_cols=chunk_cols,
                )
                a = np.asarray(y_sub.T, dtype=np.float64)  # (line_size, line_size)
                a = a + reg * np.eye(line_size, dtype=np.float64)
                try:
                    inv = np.linalg.inv(a)
                except np.linalg.LinAlgError:
                    inv = np.linalg.pinv(a, rcond=1e-12)
                if not np.all(np.isfinite(inv)):
                    inv = np.linalg.pinv(a, rcond=1e-12)
                block_inv[s, iz, :, :] = inv
        block_inv_jnp = jnp.asarray(block_inv, dtype=precond_dtype)

        extra_start = int(op.f_size + op.phi1_size)
        extra_size = int(op.extra_size)
        extra_idx_np = np.arange(extra_start, extra_start + extra_size, dtype=np.int32)
        extra_idx_jnp = jnp.asarray(extra_idx_np, dtype=jnp.int32)
        extra_inv_jnp: jnp.ndarray | None = None
        if extra_size > 0:
            chunk_cols = _precond_chunk_cols(total_size, int(extra_idx_np.shape[0]))
            y_sub = _matvec_submatrix(
                op_pc,
                col_idx=extra_idx_np,
                row_idx=extra_idx_np,
                total_size=total_size,
                chunk_cols=chunk_cols,
            )
            ee = np.asarray(y_sub.T, dtype=np.float64)
            ee = ee + reg * np.eye(extra_size, dtype=np.float64)
            try:
                ee_inv = np.linalg.inv(ee)
            except np.linalg.LinAlgError:
                ee_inv = np.linalg.pinv(ee, rcond=1e-12)
            if not np.all(np.isfinite(ee_inv)):
                ee_inv = np.linalg.pinv(ee, rcond=1e-12)
            extra_inv_jnp = jnp.asarray(ee_inv, dtype=precond_dtype)

        cached = _RHSMode1PrecondCache(
            idx_map_jnp=idx_map_jnp,
            flat_idx_jnp=flat_idx_jnp,
            block_inv_jnp=block_inv_jnp,
            extra_idx_jnp=extra_idx_jnp,
            extra_inv_jnp=extra_inv_jnp,
        )
        _RHSMODE1_PRECOND_CACHE[cache_key] = cached

    n_species = int(op.n_species)
    n_zeta = int(op.n_zeta)
    line_size = int(cached.block_inv_jnp.shape[-1])
    flat_idx_jnp = cached.flat_idx_jnp
    block_inv_jnp = cached.block_inv_jnp
    extra_idx_jnp = cached.extra_idx_jnp
    extra_inv_jnp = cached.extra_inv_jnp

    def _apply_full(r_full: jnp.ndarray) -> jnp.ndarray:
        r_full = jnp.asarray(r_full, dtype=precond_dtype)
        r_loc = r_full[flat_idx_jnp].reshape((n_species, n_zeta, line_size))
        z_loc = jnp.einsum("szab,szb->sza", block_inv_jnp, r_loc)
        z_full = jnp.zeros_like(r_full)
        z_full = z_full.at[flat_idx_jnp].set(z_loc.reshape((-1,)), unique_indices=True)
        if extra_inv_jnp is not None:
            r_extra = r_full[extra_idx_jnp]
            z_extra = extra_inv_jnp @ r_extra
            z_full = z_full.at[extra_idx_jnp].set(z_extra, unique_indices=True)
        return jnp.asarray(z_full, dtype=jnp.float64)

    if reduce_full is None or expand_reduced is None:
        return _apply_full

    def _apply_reduced(r_reduced: jnp.ndarray) -> jnp.ndarray:
        z_full = _apply_full(expand_reduced(r_reduced))
        return reduce_full(z_full)

    return _apply_reduced


