def _build_rhsmode1_theta_schwarz_preconditioner(
    *,
    op: V3FullSystemOperator,
    block: int,
    overlap: int,
    reduce_full: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
    expand_reduced: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
) -> Callable[[jnp.ndarray], jnp.ndarray]:
    """Restricted additive Schwarz preconditioner on theta lines.

    Uses local theta patches with configurable overlap and writes only each
    patch's non-overlapped core region (RAS), avoiding duplicate writes while
    still capturing nearest-neighbor line coupling across block boundaries.
    """
    block = max(1, min(int(op.n_theta), int(block)))
    overlap = max(0, min(int(op.n_theta) - 1, int(overlap)))
    cache_key = _rhsmode1_precond_cache_key(op, f"theta_schwarz_b{block}_o{overlap}")
    precond_dtype = _precond_dtype()
    cached = _RHSMODE1_SCHWARZ_PRECOND_CACHE.get(cache_key)
    if cached is None:
        block_pc = max(block, block + 2 * overlap)
        op_pc = _build_rhsmode1_preconditioner_operator_theta_dd(op, block=block_pc)
        n_species = int(op.n_species)
        n_x = int(op.n_x)
        n_l = int(op.n_xi)
        n_theta = int(op.n_theta)
        n_zeta = int(op.n_zeta)
        total_size = int(op.total_size)

        nxi_for_x = np.asarray(op.fblock.collisionless.n_xi_for_x, dtype=np.int32)
        reg_env = os.environ.get("SFINCS_JAX_RHSMODE1_PRECOND_REG", "").strip()
        reg_val = float(reg_env) if reg_env else 1e-10
        reg = np.float64(reg_val)

        inv_list: list[np.ndarray] = []
        patch_idx_list: list[np.ndarray] = []
        core_idx_list: list[np.ndarray] = []
        core_local_list: list[np.ndarray] = []

        ranges = _dd_core_patch_ranges(n=n_theta, block=block, overlap=overlap)
        for s in range(n_species):
            for iz in range(n_zeta):
                for core_start, core_end, patch_start, patch_end in ranges:
                    patch_idx: list[int] = []
                    core_idx: list[int] = []
                    core_local: list[int] = []
                    k = 0
                    for it in range(patch_start, patch_end):
                        for ix in range(n_x):
                            max_l = int(nxi_for_x[ix])
                            for il in range(max_l):
                                idx = int(((((s * n_x + ix) * n_l + il) * n_theta + it) * n_zeta + iz))
                                patch_idx.append(idx)
                                if core_start <= it < core_end:
                                    core_idx.append(idx)
                                    core_local.append(k)
                                k += 1
                    if not patch_idx:
                        continue
                    patch_idx_np = np.asarray(patch_idx, dtype=np.int32)
                    core_idx_np = np.asarray(core_idx, dtype=np.int32)
                    core_local_np = np.asarray(core_local, dtype=np.int32)
                    chunk_cols = _precond_chunk_cols(total_size, int(patch_idx_np.shape[0]))
                    y_sub = _matvec_submatrix(
                        op_pc,
                        col_idx=patch_idx_np,
                        row_idx=patch_idx_np,
                        total_size=total_size,
                        chunk_cols=chunk_cols,
                    )
                    a = np.asarray(y_sub.T, dtype=np.float64)
                    a = a + reg * np.eye(int(patch_idx_np.shape[0]), dtype=np.float64)
                    try:
                        inv = np.linalg.inv(a)
                    except np.linalg.LinAlgError:
                        inv = np.linalg.pinv(a, rcond=1e-12)
                    if not np.all(np.isfinite(inv)):
                        inv = np.linalg.pinv(a, rcond=1e-12)
                    inv_list.append(inv)
                    patch_idx_list.append(patch_idx_np)
                    core_idx_list.append(core_idx_np)
                    core_local_list.append(core_local_np)

        if not inv_list:
            return _build_rhsmode1_theta_dd_preconditioner(
                op=op,
                block=block,
                reduce_full=reduce_full,
                expand_reduced=expand_reduced,
            )

        n_patch = len(inv_list)
        max_patch = max(int(v.shape[0]) for v in patch_idx_list)
        max_core = max(int(v.shape[0]) for v in core_idx_list)
        inv_padded = np.zeros((n_patch, max_patch, max_patch), dtype=np.float64)
        patch_idx_padded = np.zeros((n_patch, max_patch), dtype=np.int32)
        core_idx_padded = np.zeros((n_patch, max_core), dtype=np.int32)
        core_local_padded = np.zeros((n_patch, max_core), dtype=np.int32)
        core_mask_padded = np.zeros((n_patch, max_core), dtype=np.float64)
        for i in range(n_patch):
            patch_n = int(patch_idx_list[i].shape[0])
            core_n = int(core_idx_list[i].shape[0])
            inv_padded[i, :patch_n, :patch_n] = inv_list[i]
            patch_idx_padded[i, :patch_n] = patch_idx_list[i]
            core_idx_padded[i, :core_n] = core_idx_list[i]
            core_local_padded[i, :core_n] = core_local_list[i]
            core_mask_padded[i, :core_n] = 1.0

        extra_start = int(op.f_size + op.phi1_size)
        extra_size = int(op.extra_size)
        extra_idx_np = np.arange(extra_start, extra_start + extra_size, dtype=np.int32)
        extra_idx_jnp = jnp.asarray(extra_idx_np, dtype=jnp.int32)
        extra_inv_jnp: jnp.ndarray | None = None
        if extra_size > 0:
            chunk_cols = _precond_chunk_cols(total_size, int(extra_idx_np.shape[0]))
            y_sub = _matvec_submatrix(
                op_pc,
                col_idx=extra_idx_np,
                row_idx=extra_idx_np,
                total_size=total_size,
                chunk_cols=chunk_cols,
            )
            ee = np.asarray(y_sub.T, dtype=np.float64)
            ee = ee + reg * np.eye(extra_size, dtype=np.float64)
            try:
                ee_inv = np.linalg.inv(ee)
            except np.linalg.LinAlgError:
                ee_inv = np.linalg.pinv(ee, rcond=1e-12)
            if not np.all(np.isfinite(ee_inv)):
                ee_inv = np.linalg.pinv(ee, rcond=1e-12)
            extra_inv_jnp = jnp.asarray(ee_inv, dtype=precond_dtype)

        cached = _RHSMode1SchwarzPrecondCache(
            inv_padded_jnp=jnp.asarray(inv_padded, dtype=precond_dtype),
            patch_idx_padded_jnp=jnp.asarray(patch_idx_padded, dtype=jnp.int32),
            core_idx_padded_jnp=jnp.asarray(core_idx_padded, dtype=jnp.int32),
            core_local_padded_jnp=jnp.asarray(core_local_padded, dtype=jnp.int32),
            core_mask_padded_jnp=jnp.asarray(core_mask_padded, dtype=precond_dtype),
            extra_idx_jnp=extra_idx_jnp,
            extra_inv_jnp=extra_inv_jnp,
        )
        _RHSMODE1_SCHWARZ_PRECOND_CACHE[cache_key] = cached

    inv_padded_jnp = cached.inv_padded_jnp
    patch_idx_padded_jnp = cached.patch_idx_padded_jnp
    core_idx_padded_jnp = cached.core_idx_padded_jnp
    core_local_padded_jnp = cached.core_local_padded_jnp
    core_mask_padded_jnp = cached.core_mask_padded_jnp
    extra_idx_jnp = cached.extra_idx_jnp
    extra_inv_jnp = cached.extra_inv_jnp
    n_patch = int(inv_padded_jnp.shape[0])

    def _apply_full(r_full: jnp.ndarray) -> jnp.ndarray:
        r_full = jnp.asarray(r_full, dtype=precond_dtype)
        z_full = jnp.zeros_like(r_full)
        for ip in range(n_patch):
            r_patch = r_full[patch_idx_padded_jnp[ip]]
            z_patch = inv_padded_jnp[ip] @ r_patch
            z_core = z_patch[core_local_padded_jnp[ip]] * core_mask_padded_jnp[ip]
            z_full = z_full.at[core_idx_padded_jnp[ip]].add(z_core)
        if extra_inv_jnp is not None:
            r_extra = r_full[extra_idx_jnp]
            z_extra = extra_inv_jnp @ r_extra
            z_full = z_full.at[extra_idx_jnp].set(z_extra, unique_indices=True)
        return jnp.asarray(z_full, dtype=jnp.float64)

    coarse_env = os.environ.get("SFINCS_JAX_RHSMODE1_SCHWARZ_COARSE", "").strip().lower()
    coarse_auto = coarse_env not in {"0", "false", "no", "off"}
    coarse_steps_env = os.environ.get("SFINCS_JAX_RHSMODE1_SCHWARZ_COARSE_STEPS", "").strip()
    try:
        coarse_steps = int(coarse_steps_env) if coarse_steps_env else 1
    except ValueError:
        coarse_steps = 1
    coarse_damp_env = os.environ.get("SFINCS_JAX_RHSMODE1_SCHWARZ_COARSE_DAMP", "").strip()
    try:
        coarse_damp = float(coarse_damp_env) if coarse_damp_env else 1.0
    except ValueError:
        coarse_damp = 1.0

    apply_full_raw = _apply_full
    n_dev = max(1, int(jax.device_count()))
    if coarse_auto and n_dev >= 4 and _matvec_shard_axis(op) == "theta":
        coarse_blocks = _rhs1_dd_coarse_block_sizes(
            n=int(op.n_theta),
            block=int(block),
            overlap=int(overlap),
            levels=_rhs1_dd_coarse_level_count(n_dev=n_dev),
        )
        if coarse_blocks:
            coarse_levels = tuple(
                _build_rhsmode1_theta_dd_preconditioner(op=op, block=coarse_block)
                for coarse_block in coarse_blocks
            )
            apply_full_raw = _compose_multilevel_residual_correction_preconditioner(
                base=apply_full_raw,
                coarse_levels=coarse_levels,
                matvec=lambda v: apply_v3_full_system_operator_cached(op, v),
                damping=coarse_damp,
                steps=coarse_steps,
            )

    apply_full_safe = _safe_preconditioner(apply_full_raw)
    if reduce_full is None or expand_reduced is None:
        return apply_full_safe

    def _apply_reduced(r_reduced: jnp.ndarray) -> jnp.ndarray:
        z_full = apply_full_safe(expand_reduced(r_reduced))
        return reduce_full(z_full)

    return _apply_reduced


def _build_rhsmode1_zeta_schwarz_preconditioner(
    *,
    op: V3FullSystemOperator,
    block: int,
    overlap: int,
    reduce_full: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
    expand_reduced: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
) -> Callable[[jnp.ndarray], jnp.ndarray]:
    """Restricted additive Schwarz preconditioner on zeta lines."""
    block = max(1, min(int(op.n_zeta), int(block)))
    overlap = max(0, min(int(op.n_zeta) - 1, int(overlap)))
    cache_key = _rhsmode1_precond_cache_key(op, f"zeta_schwarz_b{block}_o{overlap}")
    precond_dtype = _precond_dtype()
    cached = _RHSMODE1_SCHWARZ_PRECOND_CACHE.get(cache_key)
    if cached is None:
        block_pc = max(block, block + 2 * overlap)
        op_pc = _build_rhsmode1_preconditioner_operator_zeta_dd(op, block=block_pc)
        n_species = int(op.n_species)
        n_x = int(op.n_x)
        n_l = int(op.n_xi)
        n_theta = int(op.n_theta)
        n_zeta = int(op.n_zeta)
        total_size = int(op.total_size)

        nxi_for_x = np.asarray(op.fblock.collisionless.n_xi_for_x, dtype=np.int32)
        reg_env = os.environ.get("SFINCS_JAX_RHSMODE1_PRECOND_REG", "").strip()
        reg_val = float(reg_env) if reg_env else 1e-10
        reg = np.float64(reg_val)

        inv_list: list[np.ndarray] = []
        patch_idx_list: list[np.ndarray] = []
        core_idx_list: list[np.ndarray] = []
        core_local_list: list[np.ndarray] = []

        ranges = _dd_core_patch_ranges(n=n_zeta, block=block, overlap=overlap)
        for s in range(n_species):
            for it in range(n_theta):
                for core_start, core_end, patch_start, patch_end in ranges:
                    patch_idx: list[int] = []
                    core_idx: list[int] = []
                    core_local: list[int] = []
                    k = 0
                    for iz in range(patch_start, patch_end):
                        for ix in range(n_x):
                            max_l = int(nxi_for_x[ix])
                            for il in range(max_l):
                                idx = int(((((s * n_x + ix) * n_l + il) * n_theta + it) * n_zeta + iz))
                                patch_idx.append(idx)
                                if core_start <= iz < core_end:
                                    core_idx.append(idx)
                                    core_local.append(k)
                                k += 1
                    if not patch_idx:
                        continue
                    patch_idx_np = np.asarray(patch_idx, dtype=np.int32)
                    core_idx_np = np.asarray(core_idx, dtype=np.int32)
                    core_local_np = np.asarray(core_local, dtype=np.int32)
                    chunk_cols = _precond_chunk_cols(total_size, int(patch_idx_np.shape[0]))
                    y_sub = _matvec_submatrix(
                        op_pc,
                        col_idx=patch_idx_np,
                        row_idx=patch_idx_np,
                        total_size=total_size,
                        chunk_cols=chunk_cols,
                    )
                    a = np.asarray(y_sub.T, dtype=np.float64)
                    a = a + reg * np.eye(int(patch_idx_np.shape[0]), dtype=np.float64)
                    try:
                        inv = np.linalg.inv(a)
                    except np.linalg.LinAlgError:
                        inv = np.linalg.pinv(a, rcond=1e-12)
                    if not np.all(np.isfinite(inv)):
                        inv = np.linalg.pinv(a, rcond=1e-12)
                    inv_list.append(inv)
                    patch_idx_list.append(patch_idx_np)
                    core_idx_list.append(core_idx_np)
                    core_local_list.append(core_local_np)

        if not inv_list:
            return _build_rhsmode1_zeta_dd_preconditioner(
                op=op,
                block=block,
                reduce_full=reduce_full,
                expand_reduced=expand_reduced,
            )

        n_patch = len(inv_list)
        max_patch = max(int(v.shape[0]) for v in patch_idx_list)
        max_core = max(int(v.shape[0]) for v in core_idx_list)
        inv_padded = np.zeros((n_patch, max_patch, max_patch), dtype=np.float64)
        patch_idx_padded = np.zeros((n_patch, max_patch), dtype=np.int32)
        core_idx_padded = np.zeros((n_patch, max_core), dtype=np.int32)
        core_local_padded = np.zeros((n_patch, max_core), dtype=np.int32)
        core_mask_padded = np.zeros((n_patch, max_core), dtype=np.float64)
        for i in range(n_patch):
            patch_n = int(patch_idx_list[i].shape[0])
            core_n = int(core_idx_list[i].shape[0])
            inv_padded[i, :patch_n, :patch_n] = inv_list[i]
            patch_idx_padded[i, :patch_n] = patch_idx_list[i]
            core_idx_padded[i, :core_n] = core_idx_list[i]
            core_local_padded[i, :core_n] = core_local_list[i]
            core_mask_padded[i, :core_n] = 1.0

        extra_start = int(op.f_size + op.phi1_size)
        extra_size = int(op.extra_size)
        extra_idx_np = np.arange(extra_start, extra_start + extra_size, dtype=np.int32)
        extra_idx_jnp = jnp.asarray(extra_idx_np, dtype=jnp.int32)
        extra_inv_jnp: jnp.ndarray | None = None
        if extra_size > 0:
            chunk_cols = _precond_chunk_cols(total_size, int(extra_idx_np.shape[0]))
            y_sub = _matvec_submatrix(
                op_pc,
                col_idx=extra_idx_np,
                row_idx=extra_idx_np,
                total_size=total_size,
                chunk_cols=chunk_cols,
            )
            ee = np.asarray(y_sub.T, dtype=np.float64)
            ee = ee + reg * np.eye(extra_size, dtype=np.float64)
            try:
                ee_inv = np.linalg.inv(ee)
            except np.linalg.LinAlgError:
                ee_inv = np.linalg.pinv(ee, rcond=1e-12)
            if not np.all(np.isfinite(ee_inv)):
                ee_inv = np.linalg.pinv(ee, rcond=1e-12)
            extra_inv_jnp = jnp.asarray(ee_inv, dtype=precond_dtype)

        cached = _RHSMode1SchwarzPrecondCache(
            inv_padded_jnp=jnp.asarray(inv_padded, dtype=precond_dtype),
            patch_idx_padded_jnp=jnp.asarray(patch_idx_padded, dtype=jnp.int32),
            core_idx_padded_jnp=jnp.asarray(core_idx_padded, dtype=jnp.int32),
            core_local_padded_jnp=jnp.asarray(core_local_padded, dtype=jnp.int32),
            core_mask_padded_jnp=jnp.asarray(core_mask_padded, dtype=precond_dtype),
            extra_idx_jnp=extra_idx_jnp,
            extra_inv_jnp=extra_inv_jnp,
        )
        _RHSMODE1_SCHWARZ_PRECOND_CACHE[cache_key] = cached

    inv_padded_jnp = cached.inv_padded_jnp
    patch_idx_padded_jnp = cached.patch_idx_padded_jnp
    core_idx_padded_jnp = cached.core_idx_padded_jnp
    core_local_padded_jnp = cached.core_local_padded_jnp
    core_mask_padded_jnp = cached.core_mask_padded_jnp
    extra_idx_jnp = cached.extra_idx_jnp
    extra_inv_jnp = cached.extra_inv_jnp
    n_patch = int(inv_padded_jnp.shape[0])

    def _apply_full(r_full: jnp.ndarray) -> jnp.ndarray:
        r_full = jnp.asarray(r_full, dtype=precond_dtype)
        z_full = jnp.zeros_like(r_full)
        for ip in range(n_patch):
            r_patch = r_full[patch_idx_padded_jnp[ip]]
            z_patch = inv_padded_jnp[ip] @ r_patch
            z_core = z_patch[core_local_padded_jnp[ip]] * core_mask_padded_jnp[ip]
            z_full = z_full.at[core_idx_padded_jnp[ip]].add(z_core)
        if extra_inv_jnp is not None:
            r_extra = r_full[extra_idx_jnp]
            z_extra = extra_inv_jnp @ r_extra
            z_full = z_full.at[extra_idx_jnp].set(z_extra, unique_indices=True)
        return jnp.asarray(z_full, dtype=jnp.float64)

    coarse_env = os.environ.get("SFINCS_JAX_RHSMODE1_SCHWARZ_COARSE", "").strip().lower()
    coarse_auto = coarse_env not in {"0", "false", "no", "off"}
    coarse_steps_env = os.environ.get("SFINCS_JAX_RHSMODE1_SCHWARZ_COARSE_STEPS", "").strip()
    try:
        coarse_steps = int(coarse_steps_env) if coarse_steps_env else 1
    except ValueError:
        coarse_steps = 1
    coarse_damp_env = os.environ.get("SFINCS_JAX_RHSMODE1_SCHWARZ_COARSE_DAMP", "").strip()
    try:
        coarse_damp = float(coarse_damp_env) if coarse_damp_env else 1.0
    except ValueError:
        coarse_damp = 1.0

    apply_full_raw = _apply_full
    n_dev = max(1, int(jax.device_count()))
    if coarse_auto and n_dev >= 4 and _matvec_shard_axis(op) == "zeta":
        coarse_blocks = _rhs1_dd_coarse_block_sizes(
            n=int(op.n_zeta),
            block=int(block),
            overlap=int(overlap),
            levels=_rhs1_dd_coarse_level_count(n_dev=n_dev),
        )
        if coarse_blocks:
            coarse_levels = tuple(
                _build_rhsmode1_zeta_dd_preconditioner(op=op, block=coarse_block)
                for coarse_block in coarse_blocks
            )
            apply_full_raw = _compose_multilevel_residual_correction_preconditioner(
                base=apply_full_raw,
                coarse_levels=coarse_levels,
                matvec=lambda v: apply_v3_full_system_operator_cached(op, v),
                damping=coarse_damp,
                steps=coarse_steps,
            )

    apply_full_safe = _safe_preconditioner(apply_full_raw)
    if reduce_full is None or expand_reduced is None:
        return apply_full_safe

    def _apply_reduced(r_reduced: jnp.ndarray) -> jnp.ndarray:
        z_full = apply_full_safe(expand_reduced(r_reduced))
        return reduce_full(z_full)

    return _apply_reduced


def _build_rhsmode1_theta_line_xdiag_preconditioner(
    *,
    op: V3FullSystemOperator,
    reduce_full: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
    expand_reduced: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
) -> Callable[[jnp.ndarray], jnp.ndarray]:
    """Cheaper theta-line preconditioner with diagonal x/L blocks.

    Build independent theta-line blocks for each (species, x, L, zeta). This avoids
    the large coupled theta-line system while retaining theta streaming coupling.
    """
    cache_key = _rhsmode1_precond_cache_key(op, "theta_line_xdiag")
    precond_dtype = _precond_dtype()
    cached = _RHSMODE1_THETA_LINE_DIAGX_CACHE.get(cache_key)
    if cached is None:
        op_pc = _build_rhsmode1_preconditioner_operator_theta_line(op)
        n_s = int(op.n_species)
        n_x = int(op.n_x)
        n_l = int(op.n_xi)
        n_t = int(op.n_theta)
        n_z = int(op.n_zeta)
        total = int(op.total_size)

        nxi_for_x = np.asarray(op.fblock.collisionless.n_xi_for_x, dtype=np.int32)

        reg_env = os.environ.get("SFINCS_JAX_RHSMODE1_PRECOND_REG", "").strip()
        reg_val = float(reg_env) if reg_env else 1e-10
        reg = np.float64(reg_val)

        block_inv_list: list[np.ndarray] = []
        block_idx_list: list[np.ndarray] = []
        for s in range(n_s):
            for ix in range(n_x):
                max_lx = int(nxi_for_x[ix])
                for il in range(max_lx):
                    for iz in range(n_z):
                        rep_idx = np.zeros((n_t,), dtype=np.int32)
                        for it in range(n_t):
                            rep_idx[it] = int(((((s * n_x + ix) * n_l + il) * n_t + it) * n_z + iz))
                        chunk_cols = _precond_chunk_cols(total, int(rep_idx.shape[0]))
                        y_sub = _matvec_submatrix(
                            op_pc,
                            col_idx=rep_idx,
                            row_idx=rep_idx,
                            total_size=total,
                            chunk_cols=chunk_cols,
                        )
                        a = np.asarray(y_sub.T, dtype=np.float64)
                        a = a + reg * np.eye(n_t, dtype=np.float64)
                        try:
                            inv = np.linalg.inv(a)
                        except np.linalg.LinAlgError:
                            inv = np.linalg.pinv(a, rcond=1e-12)
                        if not np.all(np.isfinite(inv)):
                            inv = np.linalg.pinv(a, rcond=1e-12)
                        block_inv_list.append(inv)
                        block_idx_list.append(rep_idx)

        if block_inv_list:
            block_inv = jnp.asarray(np.stack(block_inv_list), dtype=precond_dtype)
            block_idx = jnp.asarray(np.stack(block_idx_list), dtype=jnp.int32)
        else:
            block_inv = jnp.zeros((0, n_t, n_t), dtype=precond_dtype)
            block_idx = jnp.zeros((0, n_t), dtype=jnp.int32)

        extra_start = int(op.f_size + op.phi1_size)
        extra_size = int(op.extra_size)
        extra_idx_np = np.arange(extra_start, extra_start + extra_size, dtype=np.int32)
        extra_idx_jnp = jnp.asarray(extra_idx_np, dtype=jnp.int32)
        extra_inv_jnp: jnp.ndarray | None = None
        if extra_size > 0:
            chunk_cols = _precond_chunk_cols(total, int(extra_idx_np.shape[0]))
            y_sub = _matvec_submatrix(
                op_pc,
                col_idx=extra_idx_np,
                row_idx=extra_idx_np,
                total_size=total,
                chunk_cols=chunk_cols,
            )
            ee = np.asarray(y_sub.T, dtype=np.float64)
            ee = ee + reg * np.eye(extra_size, dtype=np.float64)
            try:
                ee_inv = np.linalg.inv(ee)
            except np.linalg.LinAlgError:
                ee_inv = np.linalg.pinv(ee, rcond=1e-12)
            if not np.all(np.isfinite(ee_inv)):
                ee_inv = np.linalg.pinv(ee, rcond=1e-12)
            extra_inv_jnp = jnp.asarray(ee_inv, dtype=precond_dtype)

        cached = _RHSMode1ThetaLineDiagXCache(
            block_inv=block_inv,
            block_idx=block_idx,
            extra_idx_jnp=extra_idx_jnp,
            extra_inv_jnp=extra_inv_jnp,
        )
        _RHSMODE1_THETA_LINE_DIAGX_CACHE[cache_key] = cached

    block_inv = cached.block_inv
    block_idx = cached.block_idx
    extra_idx_jnp = cached.extra_idx_jnp
    extra_inv_jnp = cached.extra_inv_jnp

    def _apply_full(r_full: jnp.ndarray) -> jnp.ndarray:
        r_full = jnp.asarray(r_full, dtype=precond_dtype)
        z_full = jnp.zeros_like(r_full)
        if block_inv.shape[0] > 0:
            r_loc = r_full[block_idx]
            z_loc = jnp.einsum("bij,bj->bi", block_inv, r_loc)
            z_full = z_full.at[block_idx.reshape((-1,))].set(z_loc.reshape((-1,)), unique_indices=True)
        if extra_inv_jnp is not None:
            r_extra = r_full[extra_idx_jnp]
            z_extra = extra_inv_jnp @ r_extra
            z_full = z_full.at[extra_idx_jnp].set(z_extra, unique_indices=True)
        return jnp.asarray(z_full, dtype=jnp.float64)

    if reduce_full is None or expand_reduced is None:
        return _apply_full

    def _apply_reduced(r_reduced: jnp.ndarray) -> jnp.ndarray:
        z_full = _apply_full(expand_reduced(r_reduced))
        return reduce_full(z_full)

    return _apply_reduced


def _build_rhsmode1_theta_zeta_preconditioner(
    *,
    op: V3FullSystemOperator,
    reduce_full: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
    expand_reduced: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
) -> Callable[[jnp.ndarray], jnp.ndarray]:
    """Build a RHSMode=1 preconditioner using full (theta,zeta) blocks.

    For each species and each active (x,L) pair, solve the full angular block over
    all theta/zeta points. This captures 2D angular coupling while treating x/L
    coupling as diagonal, making it stronger than the theta- or zeta-line options.
    """
    cache_key = _rhsmode1_precond_cache_key(op, "theta_zeta")
    precond_dtype = _precond_dtype()
    cached = _RHSMODE1_PRECOND_CACHE.get(cache_key)
    if cached is None:
        op_pc = op
        n_species = int(op.n_species)
        n_x = int(op.n_x)
        n_l = int(op.n_xi)
        n_theta = int(op.n_theta)
        n_zeta = int(op.n_zeta)
        total_size = int(op.total_size)

        nxi_for_x = np.asarray(op.fblock.collisionless.n_xi_for_x, dtype=np.int32)
        local_per_species = int(np.sum(nxi_for_x))
        block_count = int(n_species * local_per_species)
        block_size = int(n_theta * n_zeta)

        reg_env = os.environ.get("SFINCS_JAX_RHSMODE1_PRECOND_REG", "").strip()
        reg_val = float(reg_env) if reg_env else 1e-10
        reg = np.float64(reg_val)

        idx_map = np.zeros((block_count, block_size), dtype=np.int32)
        block_inv = np.zeros((block_count, block_size, block_size), dtype=np.float64)

        block_idx = 0
        for s in range(n_species):
            for ix in range(n_x):
                max_l = int(nxi_for_x[ix])
                for il in range(max_l):
                    k = 0
                    for it in range(n_theta):
                        for iz in range(n_zeta):
                            idx_map[block_idx, k] = int(
                                ((((s * n_x + ix) * n_l + il) * n_theta + it) * n_zeta + iz)
                            )
                            k += 1
                    rep_idx = idx_map[block_idx, :]
                    chunk_cols = _precond_chunk_cols(total_size, int(rep_idx.shape[0]))
                    y_sub = _matvec_submatrix(
                        op_pc,
                        col_idx=rep_idx,
                        row_idx=rep_idx,
                        total_size=total_size,
                        chunk_cols=chunk_cols,
                    )
                    a = np.asarray(y_sub.T, dtype=np.float64)
                    a = a + reg * np.eye(block_size, dtype=np.float64)
                    try:
                        inv = np.linalg.inv(a)
                    except np.linalg.LinAlgError:
                        inv = np.linalg.pinv(a, rcond=1e-12)
                    if not np.all(np.isfinite(inv)):
                        inv = np.linalg.pinv(a, rcond=1e-12)
                    block_inv[block_idx, :, :] = inv
                    block_idx += 1

        idx_map_jnp = jnp.asarray(idx_map, dtype=jnp.int32)
        flat_idx_jnp = idx_map_jnp.reshape((-1,))
        block_inv_jnp = jnp.asarray(block_inv, dtype=precond_dtype)

        extra_start = int(op.f_size + op.phi1_size)
        extra_size = int(op.extra_size)
        extra_idx_np = np.arange(extra_start, extra_start + extra_size, dtype=np.int32)
        extra_idx_jnp = jnp.asarray(extra_idx_np, dtype=jnp.int32)
        extra_inv_jnp: jnp.ndarray | None = None
        if extra_size > 0:
            chunk_cols = _precond_chunk_cols(total_size, int(extra_idx_np.shape[0]))
            y_sub = _matvec_submatrix(
                op_pc,
                col_idx=extra_idx_np,
                row_idx=extra_idx_np,
                total_size=total_size,
                chunk_cols=chunk_cols,
            )
            ee = np.asarray(y_sub.T, dtype=np.float64)
            ee = ee + reg * np.eye(extra_size, dtype=np.float64)
            try:
                ee_inv = np.linalg.inv(ee)
            except np.linalg.LinAlgError:
                ee_inv = np.linalg.pinv(ee, rcond=1e-12)
            if not np.all(np.isfinite(ee_inv)):
                ee_inv = np.linalg.pinv(ee, rcond=1e-12)
            extra_inv_jnp = jnp.asarray(ee_inv, dtype=precond_dtype)

        cached = _RHSMode1PrecondCache(
            idx_map_jnp=idx_map_jnp,
            flat_idx_jnp=flat_idx_jnp,
            block_inv_jnp=block_inv_jnp,
            extra_idx_jnp=extra_idx_jnp,
            extra_inv_jnp=extra_inv_jnp,
        )
        _RHSMODE1_PRECOND_CACHE[cache_key] = cached

    block_inv_jnp = cached.block_inv_jnp
    flat_idx_jnp = cached.flat_idx_jnp
    extra_idx_jnp = cached.extra_idx_jnp
    extra_inv_jnp = cached.extra_inv_jnp
    block_size = int(block_inv_jnp.shape[-1])
    block_count = int(block_inv_jnp.shape[0])

    def _apply_full(r_full: jnp.ndarray) -> jnp.ndarray:
        r_full = jnp.asarray(r_full, dtype=precond_dtype)
        r_loc = r_full[flat_idx_jnp].reshape((block_count, block_size))
        z_loc = jnp.einsum("bij,bj->bi", block_inv_jnp, r_loc)
        z_full = jnp.zeros_like(r_full)
        z_full = z_full.at[flat_idx_jnp].set(z_loc.reshape((-1,)), unique_indices=True)
        if extra_inv_jnp is not None:
            r_extra = r_full[extra_idx_jnp]
            z_extra = extra_inv_jnp @ r_extra
            z_full = z_full.at[extra_idx_jnp].set(z_extra, unique_indices=True)
        return jnp.asarray(z_full, dtype=jnp.float64)

    if reduce_full is None or expand_reduced is None:
        return _apply_full

    def _apply_reduced(r_reduced: jnp.ndarray) -> jnp.ndarray:
        z_full = _apply_full(expand_reduced(r_reduced))
        return reduce_full(z_full)

    return _apply_reduced


def _compose_preconditioners(
    first: Callable[[jnp.ndarray], jnp.ndarray],
    second: Callable[[jnp.ndarray], jnp.ndarray],
) -> Callable[[jnp.ndarray], jnp.ndarray]:
    def _apply(v: jnp.ndarray) -> jnp.ndarray:
        return second(first(v))

    return _apply


def _compose_residual_correction_preconditioner(
    *,
    base: Callable[[jnp.ndarray], jnp.ndarray],
    coarse: Callable[[jnp.ndarray], jnp.ndarray],
    matvec: Callable[[jnp.ndarray], jnp.ndarray],
    damping: float = 1.0,
    steps: int = 1,
) -> Callable[[jnp.ndarray], jnp.ndarray]:
    """Apply a small multiplicative coarse correction after a base preconditioner."""
    return _compose_multilevel_residual_correction_preconditioner(
        base=base,
        coarse_levels=(coarse,),
        matvec=matvec,
        damping=damping,
        steps=steps,
    )


def _compose_multilevel_residual_correction_preconditioner(
    *,
    base: Callable[[jnp.ndarray], jnp.ndarray],
    coarse_levels: Sequence[Callable[[jnp.ndarray], jnp.ndarray]],
    matvec: Callable[[jnp.ndarray], jnp.ndarray],
    damping: float = 1.0,
    steps: int = 1,
) -> Callable[[jnp.ndarray], jnp.ndarray]:
    """Apply one or more bounded residual-correction levels after a base preconditioner."""
    steps = max(0, int(steps))
    damping = float(damping)
    coarse_levels = tuple(coarse_levels)
    if steps <= 0 or not coarse_levels:
        return base

    def _apply(v: jnp.ndarray) -> jnp.ndarray:
        z = base(v)
        for _ in range(steps):
            for coarse in coarse_levels:
                r = v - matvec(z)
                z = z + damping * coarse(r)
        return z

    return _apply


def _compose_multilevel_minres_correction_preconditioner(
    *,
    base: Callable[[jnp.ndarray], jnp.ndarray],
    coarse_levels: Sequence[Callable[[jnp.ndarray], jnp.ndarray]],
    matvec: Callable[[jnp.ndarray], jnp.ndarray],
    alpha_clip: float = 1.0,
    min_improvement: float = 0.0,
    steps: int = 1,
) -> Callable[[jnp.ndarray], jnp.ndarray]:
    """Apply accepted coarse corrections with a local minimum-residual step."""
    steps = max(0, int(steps))
    coarse_levels = tuple(coarse_levels)
    if steps <= 0 or not coarse_levels:
        return base
    alpha_clip = float(alpha_clip)
    min_improvement = max(0.0, float(min_improvement))
    improvement_factor = max(0.0, 1.0 - min_improvement) ** 2

    def _apply(v: jnp.ndarray) -> jnp.ndarray:
        z = base(v)
        residual = v - matvec(z)
        residual_norm_sq = jnp.real(jnp.vdot(residual, residual))
        for _ in range(steps):
            for coarse in coarse_levels:
                direction = coarse(residual)
                a_direction = matvec(direction)
                denom = jnp.real(jnp.vdot(a_direction, a_direction))
                numer = jnp.real(jnp.vdot(residual, a_direction))
                alpha = jnp.where(denom > 0.0, numer / denom, 0.0)
                alpha = jnp.nan_to_num(alpha, nan=0.0, posinf=0.0, neginf=0.0)
                if alpha_clip > 0.0:
                    alpha = jnp.clip(alpha, -alpha_clip, alpha_clip)
                trial_residual = residual - alpha * a_direction
                trial_norm_sq = jnp.real(jnp.vdot(trial_residual, trial_residual))
                accept = jnp.logical_and(
                    jnp.isfinite(trial_norm_sq),
                    trial_norm_sq < residual_norm_sq * improvement_factor,
                )
                z = jnp.where(accept, z + alpha * direction, z)
                residual = jnp.where(accept, trial_residual, residual)
                residual_norm_sq = jnp.where(accept, trial_norm_sq, residual_norm_sq)
        return z

    return _apply


def _rhs1_pas_tz_guarded_structured_levels(raw: str) -> tuple[str, ...]:
    """Parse opt-in low-memory coarse levels for guarded PAS-TZ fallback trials."""
    normalized = str(raw or "").strip().lower().replace("-", "_")
    if normalized in {"", "0", "false", "no", "off", "none"}:
        return ()
    for sep in ("+", ";", ":", "|"):
        normalized = normalized.replace(sep, ",")
    aliases = {
        "x": "xmg",
        "x_grid": "xmg",
        "xmultigrid": "xmg",
        "x_mg": "xmg",
        "coll": "collision",
        "collisions": "collision",
        "collision_diag": "collision",
        "collision_diagonal": "collision",
        "diag": "collision",
        "xmg_collision": "xmg,collision",
        "collision_xmg": "collision,xmg",
        "structured": "xmg,collision",
        "default": "xmg,collision",
    }
    expanded_tokens: list[str] = []
    for token in normalized.replace(" ", ",").split(","):
        token = token.strip("_ ")
        if not token:
            continue
        expanded = aliases.get(token, token)
        expanded_tokens.extend(part.strip("_ ") for part in expanded.split(",") if part.strip("_ "))

    levels: list[str] = []
    for token in expanded_tokens:
        if token not in {"xmg", "collision"}:
            continue
        if token not in levels:
            levels.append(token)
    return tuple(levels)


def _safe_preconditioner(
    precond: Callable[[jnp.ndarray], jnp.ndarray],
    *,
    clip: float = 1.0e100,
) -> Callable[[jnp.ndarray], jnp.ndarray]:
    clip_val = float(clip)

    def _apply(v: jnp.ndarray) -> jnp.ndarray:
        out = precond(v)
        out = jnp.nan_to_num(out, nan=0.0, posinf=0.0, neginf=0.0)
        if clip_val > 0:
            out = jnp.clip(out, -clip_val, clip_val)
        return out

    return _apply


def _apply_preconditioned_minres_correction(
    *,
    matvec: Callable[[jnp.ndarray], jnp.ndarray],
    rhs: jnp.ndarray,
    x0: jnp.ndarray,
    preconditioner: Callable[[jnp.ndarray], jnp.ndarray],
    steps: int,
    alpha_clip: float = 10.0,
    min_improvement: float = 0.0,
) -> tuple[jnp.ndarray, jnp.ndarray, tuple[float, ...], tuple[float, ...]]:
    """Apply accepted matrix-free minimal-residual corrections.

    Each step computes ``d = M^{-1} r`` and chooses the scalar ``alpha`` that
    minimizes ``||r - alpha A d||_2``. The correction is accepted only when the
    measured residual decreases, so this is safe as a bounded post-Krylov rescue
    for weak preconditioners and does not require storing dense operator blocks.
    """
    x = jnp.asarray(x0, dtype=jnp.float64)
    rhs = jnp.asarray(rhs, dtype=jnp.float64)
    residual = rhs - jnp.asarray(matvec(x), dtype=jnp.float64)
    residual_norm = float(jnp.linalg.norm(residual))
    history: list[float] = [residual_norm]
    alphas: list[float] = []
    steps_use = max(0, int(steps))
    alpha_clip_use = max(0.0, float(alpha_clip))
    min_improvement_use = max(0.0, float(min_improvement))

    for _ in range(steps_use):
        direction = jnp.asarray(preconditioner(residual), dtype=jnp.float64)
        if not bool(jnp.all(jnp.isfinite(direction))):
            break
        a_direction = jnp.asarray(matvec(direction), dtype=jnp.float64)
        if not bool(jnp.all(jnp.isfinite(a_direction))):
            break
        denom = float(jnp.real(jnp.vdot(a_direction, a_direction)))
        if (not np.isfinite(denom)) or denom <= 1.0e-300:
            break
        numer = float(jnp.real(jnp.vdot(a_direction, residual)))
        alpha = numer / denom
        if alpha_clip_use > 0.0:
            alpha = max(-alpha_clip_use, min(alpha_clip_use, float(alpha)))
        if not np.isfinite(alpha) or alpha == 0.0:
            break
        trial_residual = residual - float(alpha) * a_direction
        trial_norm = float(jnp.linalg.norm(trial_residual))
        if (not np.isfinite(trial_norm)) or trial_norm >= residual_norm * (1.0 - min_improvement_use):
            break
        x = x + float(alpha) * direction
        residual = trial_residual
        residual_norm = trial_norm
        history.append(residual_norm)
        alphas.append(float(alpha))

    return x, residual, tuple(history), tuple(alphas)


def _rhs1_bool_env(name: str, *, default: bool = False) -> bool:
    """Parse a boolean environment variable used by RHSMode=1 diagnostic hooks."""
    raw = os.environ.get(name, "").strip().lower()
    if not raw:
        return bool(default)
    if raw in {"1", "true", "t", "yes", "on", ".true.", ".t."}:
        return True
    if raw in {"0", "false", "f", "no", "off", ".false.", ".f."}:
        return False
    return bool(default)


def _rhs1_int_env(name: str, *, default: int, minimum: int = 0) -> int:
    """Parse an integer environment variable with a lower bound."""
    raw = os.environ.get(name, "").strip()
    try:
        value = int(raw) if raw else int(default)
    except ValueError:
        value = int(default)
    return max(int(minimum), int(value))


def _rhs1_float_env(name: str, *, default: float, minimum: float = 0.0) -> float:
    """Parse a float environment variable with a lower bound."""
    raw = os.environ.get(name, "").strip()
    try:
        value = float(raw) if raw else float(default)
    except ValueError:
        value = float(default)
    return max(float(minimum), float(value))


def _rhs1_xblock_fallback_initial_guess(
    *,
    candidate: np.ndarray,
    original_x0: jnp.ndarray | None,
    rhs_shape: tuple[int, ...],
    candidate_residual_norm: float,
    rhs_norm: float,
    precondition_side: str,
) -> tuple[jnp.ndarray | None, bool, bool]:
    """Return the safe GMRES fallback initial guess for x-block Krylov rescues.

    Non-GMRES host Krylov methods may produce a useful physical-space state
    before failing the strict true-residual gate. Reusing that state is safe for
    left/no preconditioning when it improves over the zero-state RHS norm. It is
    deliberately disabled for right preconditioning because SciPy's right-PC
    iteration state lives in preconditioned coordinates.
    """
    candidate_improved_rhs = bool(
        np.isfinite(float(candidate_residual_norm))
        and np.isfinite(float(rhs_norm))
        and float(candidate_residual_norm) < float(rhs_norm)
    )
    if (not candidate_improved_rhs) or str(precondition_side).strip().lower() == "right":
        return original_x0, False, candidate_improved_rhs
    try:
        candidate_x0 = jnp.asarray(candidate, dtype=jnp.float64)
        if candidate_x0.shape == tuple(rhs_shape) and bool(jnp.all(jnp.isfinite(candidate_x0))):
            return candidate_x0, True, candidate_improved_rhs
    except Exception:
        pass
    return original_x0, False, candidate_improved_rhs


def _rhs1_xblock_post_coarse_directions(
    *,
    op: V3FullSystemOperator,
    residual: jnp.ndarray,
    preconditioner: Callable[[jnp.ndarray], jnp.ndarray],
    direction_projector: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
    expected_size: int | None = None,
    include_raw: bool,
    fsavg_lmax: int,
    max_extra_units: int,
    max_directions: int,
) -> tuple[tuple[str, jnp.ndarray], ...]:
    """Build a small physics-aware correction basis for stalled RHSMode=1 solves.

    The basis is intentionally low-dimensional and matrix-free: residual-like
    directions handle generic error, flux-surface-averaged low-L modes target
    moment/nullspace drift, and source/constraint directions target the
    constraint rows that are not visible to a pure x-block preconditioner.
    """
    residual = jnp.asarray(residual, dtype=jnp.float64)
    total = int(op.total_size)
    expected_size_use = total if expected_size is None else int(expected_size)
    directions: list[tuple[str, jnp.ndarray]] = []

    def _add(name: str, direction: jnp.ndarray) -> None:
        if len(directions) >= int(max_directions):
            return
        vec = jnp.asarray(direction, dtype=jnp.float64).reshape((-1,))
        if vec.shape != (total,):
            return
        if direction_projector is not None:
            vec = jnp.asarray(direction_projector(vec), dtype=jnp.float64).reshape((-1,))
        if vec.shape != (expected_size_use,):
            return
        try:
            norm = float(jnp.linalg.norm(vec))
        except Exception:
            return
        if np.isfinite(norm) and norm > 0.0:
            directions.append((str(name), vec))

    try:
        _add("preconditioned_residual", preconditioner(residual))
    except Exception:
        pass
    if include_raw:
        _add("raw_residual", residual)

    f_res = residual[: op.f_size].reshape(op.fblock.f_shape)
    factor = _fs_average_factor(op.theta_weights, op.zeta_weights, op.d_hat)
    lmax_use = min(max(0, int(fsavg_lmax)), max(0, int(op.n_xi) - 1))
    for il in range(lmax_use + 1):
        if len(directions) >= int(max_directions):
            break
        avg = jnp.einsum("tz,sxtz->sx", factor, f_res[:, :, il, :, :])
        f_dir = jnp.zeros(op.fblock.f_shape, dtype=jnp.float64)
        f_dir = f_dir.at[:, :, il, :, :].set(avg[:, :, None, None])
        tail = jnp.zeros((total - op.f_size,), dtype=jnp.float64)
        _add(f"fsavg_l{il}", jnp.concatenate([f_dir.reshape((-1,)), tail]))

    extra_start = int(op.f_size + op.phi1_size)
    extra_size = int(op.extra_size)
    if extra_size > 0 and len(directions) < int(max_directions):
        extra_res = residual[extra_start : extra_start + extra_size]
        extra_dir = jnp.zeros((total,), dtype=jnp.float64).at[extra_start : extra_start + extra_size].set(extra_res)
        _add("extra_residual", extra_dir)
        if extra_size <= int(max_extra_units):
            for ie in range(extra_size):
                if len(directions) >= int(max_directions):
                    break
                unit = jnp.zeros((total,), dtype=jnp.float64).at[extra_start + ie].set(1.0)
                _add(f"extra_unit_{ie}", unit)

    if int(op.constraint_scheme) == 1 and len(directions) < int(max_directions):
        ix0 = _ix_min(bool(op.point_at_x0))
        source_basis = _source_basis_constraint_scheme_1(op.x)
        for s in range(int(op.n_species)):
            for ibasis, basis in enumerate(source_basis):
                if len(directions) >= int(max_directions):
                    break
                f_dir = jnp.zeros(op.fblock.f_shape, dtype=jnp.float64)
                f_dir = f_dir.at[s, ix0:, 0, :, :].set(basis[ix0:, None, None])
                tail = jnp.zeros((total - op.f_size,), dtype=jnp.float64)
                full = jnp.concatenate([f_dir.reshape((-1,)), tail])
                _add(f"constraint1_source_s{s}_{ibasis}", full)

    return tuple(directions)


def _rhs1_xblock_global_coarse_basis(
    *,
    op: V3FullSystemOperator,
    rhs: jnp.ndarray,
    preconditioner: Callable[[jnp.ndarray], jnp.ndarray],
    include_rhs: bool,
    fsavg_lmax: int,
    max_extra_units: int,
    max_directions: int,
) -> tuple[tuple[str, jnp.ndarray], ...]:
    """Build a fixed low-dimensional RHSMode=1 coarse basis.

    Unlike the post-Krylov residual basis above, this basis is fixed for the
    solve, so it can be used inside a linear two-level preconditioner. The
    directions target the global pieces an x-block preconditioner cannot remove:
    RHS-like components, flux-surface-averaged low-L moments across x, and
    constraint/source rows.
    """
    rhs = jnp.asarray(rhs, dtype=jnp.float64).reshape((-1,))
    total = int(op.total_size)
    directions: list[tuple[str, jnp.ndarray]] = []

    def _add(name: str, direction: jnp.ndarray) -> None:
        if len(directions) >= int(max_directions):
            return
        vec = jnp.asarray(direction, dtype=jnp.float64).reshape((-1,))
        if vec.shape != (total,):
            return
        try:
            norm = float(jnp.linalg.norm(vec))
        except Exception:
            return
        if np.isfinite(norm) and norm > 0.0:
            directions.append((str(name), vec))

    if include_rhs:
        try:
            _add("preconditioned_rhs", preconditioner(rhs))
        except Exception:
            pass
        _add("raw_rhs", rhs)

    extra_start = int(op.f_size + op.phi1_size)
    extra_size = int(op.extra_size)
    if extra_size > 0:
        rhs_extra = rhs[extra_start : extra_start + extra_size]
        extra_dir = jnp.zeros((total,), dtype=jnp.float64).at[extra_start : extra_start + extra_size].set(rhs_extra)
        _add("extra_rhs", extra_dir)
        if extra_size <= int(max_extra_units):
            for ie in range(extra_size):
                if len(directions) >= int(max_directions):
                    break
                unit = jnp.zeros((total,), dtype=jnp.float64).at[extra_start + ie].set(1.0)
                _add(f"extra_unit_{ie}", unit)

    if int(op.constraint_scheme) == 1:
        ix0 = _ix_min(bool(op.point_at_x0))
        source_basis = _source_basis_constraint_scheme_1(op.x)
        for s in range(int(op.n_species)):
            for ibasis, basis in enumerate(source_basis):
                if len(directions) >= int(max_directions):
                    break
                f_dir = jnp.zeros(op.fblock.f_shape, dtype=jnp.float64)
                f_dir = f_dir.at[s, ix0:, 0, :, :].set(basis[ix0:, None, None])
                tail = jnp.zeros((total - op.f_size,), dtype=jnp.float64)
                _add(f"constraint1_source_s{s}_{ibasis}", jnp.concatenate([f_dir.reshape((-1,)), tail]))

    lmax_use = min(max(0, int(fsavg_lmax)), max(0, int(op.n_xi) - 1))
    angular_norm = float(max(1, int(op.n_theta) * int(op.n_zeta))) ** -0.5
    for il in range(lmax_use + 1):
        for s in range(int(op.n_species)):
            for ix in range(int(op.n_x)):
                if len(directions) >= int(max_directions):
                    return tuple(directions)
                f_dir = jnp.zeros(op.fblock.f_shape, dtype=jnp.float64)
                f_dir = f_dir.at[s, ix, il, :, :].set(angular_norm)
                tail = jnp.zeros((total - op.f_size,), dtype=jnp.float64)
                _add(f"fsavg_s{s}_x{ix}_l{il}", jnp.concatenate([f_dir.reshape((-1,)), tail]))

    return tuple(directions)


def _rhs1_xblock_global_coupling_load_basis(
    *,
    op: V3FullSystemOperator,
    rhs: jnp.ndarray,
    include_rhs: bool,
    fsavg_lmax: int,
    angular_lmax: int,
    max_extra_units: int,
    max_directions: int,
) -> tuple[tuple[str, jnp.ndarray], ...]:
    """Build load vectors for a smoothed global-coupling x-block correction.

    The vectors represent the low-dimensional error channels that a per-x block
    inverse cannot see: conserved-source rows, low-L flux-surface averages, and
    the lowest theta/zeta Fourier components. The actual correction subspace is
    obtained by applying the base x-block preconditioner to these loads.
    """
    rhs = jnp.asarray(rhs, dtype=jnp.float64).reshape((-1,))
    total = int(op.total_size)
    directions: list[tuple[str, jnp.ndarray]] = []

    def _add(name: str, direction: jnp.ndarray) -> None:
        if len(directions) >= int(max_directions):
            return
        vec = jnp.asarray(direction, dtype=jnp.float64).reshape((-1,))
        if vec.shape != (total,):
            return
        try:
            norm = float(jnp.linalg.norm(vec))
        except Exception:
            return
        if np.isfinite(norm) and norm > 0.0:
            directions.append((str(name), vec))

    if include_rhs:
        _add("raw_rhs", rhs)

    extra_start = int(op.f_size + op.phi1_size)
    extra_size = int(op.extra_size)
    if extra_size > 0:
        rhs_extra = rhs[extra_start : extra_start + extra_size]
        extra_dir = jnp.zeros((total,), dtype=jnp.float64).at[extra_start : extra_start + extra_size].set(rhs_extra)
        _add("extra_rhs", extra_dir)
        if extra_size <= int(max_extra_units):
            for ie in range(extra_size):
                if len(directions) >= int(max_directions):
                    break
                unit = jnp.zeros((total,), dtype=jnp.float64).at[extra_start + ie].set(1.0)
                _add(f"extra_unit_{ie}", unit)

    if int(op.constraint_scheme) == 1:
        ix0 = _ix_min(bool(op.point_at_x0))
        source_basis = _source_basis_constraint_scheme_1(op.x)
        for s in range(int(op.n_species)):
            for ibasis, basis in enumerate(source_basis):
                if len(directions) >= int(max_directions):
                    break
                f_dir = jnp.zeros(op.fblock.f_shape, dtype=jnp.float64)
                f_dir = f_dir.at[s, ix0:, 0, :, :].set(basis[ix0:, None, None])
                tail = jnp.zeros((total - op.f_size,), dtype=jnp.float64)
                _add(f"constraint1_source_s{s}_{ibasis}", jnp.concatenate([f_dir.reshape((-1,)), tail]))

    lmax_use = min(max(0, int(fsavg_lmax)), max(0, int(op.n_xi) - 1))
    angular_norm = float(max(1, int(op.n_theta) * int(op.n_zeta))) ** -0.5
    for il in range(lmax_use + 1):
        for s in range(int(op.n_species)):
            for ix in range(int(op.n_x)):
                if len(directions) >= int(max_directions):
                    return tuple(directions)
                f_dir = jnp.zeros(op.fblock.f_shape, dtype=jnp.float64)
                f_dir = f_dir.at[s, ix, il, :, :].set(angular_norm)
                tail = jnp.zeros((total - op.f_size,), dtype=jnp.float64)
                _add(f"fsavg_s{s}_x{ix}_l{il}", jnp.concatenate([f_dir.reshape((-1,)), tail]))

    angular_l_use = min(max(0, int(angular_lmax)), max(0, int(op.n_xi) - 1))
    if angular_l_use >= 0 and int(op.n_theta) > 1 and int(op.n_zeta) > 1:
        theta = jnp.arange(int(op.n_theta), dtype=jnp.float64)
        zeta = jnp.arange(int(op.n_zeta), dtype=jnp.float64)
        two_pi = float(2.0 * np.pi)
        mode_pairs = ((1, 0), (0, 1), (1, 1), (1, -1), (2, 0), (0, 2), (2, 1), (1, 2))
        for il in range(angular_l_use + 1):
            for m_mode, n_mode in mode_pairs:
                phase = two_pi * (
                    float(m_mode) * theta[:, None] / float(max(1, int(op.n_theta)))
                    + float(n_mode) * zeta[None, :] / float(max(1, int(op.n_zeta)))
                )
                for parity, pattern in (("cos", jnp.cos(phase)), ("sin", jnp.sin(phase))):
                    pattern_norm = float(jnp.linalg.norm(pattern))
                    if (not np.isfinite(pattern_norm)) or pattern_norm <= 0.0:
                        continue
                    pattern = pattern / pattern_norm
                    for s in range(int(op.n_species)):
                        if len(directions) >= int(max_directions):
                            return tuple(directions)
                        f_dir = jnp.zeros(op.fblock.f_shape, dtype=jnp.float64)
                        f_dir = f_dir.at[s, :, il, :, :].set(pattern[None, :, :])
                        tail = jnp.zeros((total - op.f_size,), dtype=jnp.float64)
                        _add(
                            f"angular_s{s}_allx_l{il}_m{m_mode}_n{n_mode}_{parity}",
                            jnp.concatenate([f_dir.reshape((-1,)), tail]),
                        )

    return tuple(directions)


def _build_rhs1_xblock_two_level_preconditioner(
    *,
    op: V3FullSystemOperator,
    rhs: jnp.ndarray,
    matvec: Callable[[jnp.ndarray], jnp.ndarray],
    base_preconditioner: Callable[[jnp.ndarray], jnp.ndarray],
    direction_projector: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
    expected_size: int | None = None,
    mode: str,
    fsavg_lmax: int,
    max_extra_units: int,
    max_directions: int,
    rcond: float,
    include_rhs: bool,
    emit: Callable[[int, str], None] | None = None,
) -> tuple[Callable[[jnp.ndarray], jnp.ndarray], dict[str, object], dict[str, int]]:
    """Wrap the x-block preconditioner with a fixed two-level coarse inverse."""
    from scipy.linalg import qr, solve_triangular  # noqa: PLC0415

    mode_use = str(mode).strip().lower().replace("-", "_")
    if mode_use not in {"additive", "multiplicative"}:
        mode_use = "additive"
    max_dirs_use = max(1, int(max_directions))
    expected_size_use = int(op.total_size) if expected_size is None else int(expected_size)
    raw_directions = _rhs1_xblock_global_coarse_basis(
        op=op,
        rhs=rhs,
        preconditioner=base_preconditioner,
        include_rhs=bool(include_rhs),
        fsavg_lmax=int(fsavg_lmax),
        max_extra_units=int(max_extra_units),
        max_directions=max_dirs_use,
    )
    basis_cols: list[np.ndarray] = []
    abasis_cols: list[np.ndarray] = []
    names: list[str] = []
    for name, direction in raw_directions[:max_dirs_use]:
        if direction_projector is not None:
            direction = direction_projector(direction)
        direction_np = np.asarray(jax.device_get(direction), dtype=np.float64).reshape((-1,))
        if direction_np.shape != (expected_size_use,) or not np.all(np.isfinite(direction_np)):
            continue
        norm = float(np.linalg.norm(direction_np))
        if (not np.isfinite(norm)) or norm <= 0.0:
            continue
        direction_np = direction_np / norm
        a_direction = np.asarray(
            jax.device_get(matvec(jnp.asarray(direction_np, dtype=jnp.float64))),
            dtype=np.float64,
        ).reshape((-1,))
        if a_direction.shape != direction_np.shape or not np.all(np.isfinite(a_direction)):
            continue
        a_norm = float(np.linalg.norm(a_direction))
        if (not np.isfinite(a_norm)) or a_norm <= 0.0:
            continue
        names.append(str(name))
        basis_cols.append(direction_np)
        abasis_cols.append(a_direction)

    if not basis_cols:
        raise RuntimeError("two-level x-block preconditioner found no valid coarse directions")

    basis = np.column_stack(basis_cols)
    abasis = np.column_stack(abasis_cols)
    q, r, piv = qr(abasis, mode="economic", pivoting=True)
    diag = np.abs(np.diag(r))
    if diag.size == 0:
        raise RuntimeError("two-level x-block preconditioner coarse QR is empty")
    threshold = max(float(rcond), 0.0) * max(float(diag[0]), 1.0)
    rank = int(np.count_nonzero(diag > threshold))
    if rank <= 0:
        raise RuntimeError("two-level x-block preconditioner coarse QR is rank deficient")
    piv_use = np.asarray(piv[:rank], dtype=np.int32)
    q_use = np.asarray(q[:, :rank], dtype=np.float64)
    r_use = np.asarray(r[:rank, :rank], dtype=np.float64)
    basis_use = np.asarray(basis[:, piv_use], dtype=np.float64)
    names_use = tuple(names[int(i)] for i in piv_use)
    stats = {"applies": 0, "coarse_applies": 0}

    def _coarse_correction(vec_np: np.ndarray) -> np.ndarray:
        rhs_small = q_use.T @ np.asarray(vec_np, dtype=np.float64).reshape((-1,))
        coeff = solve_triangular(r_use, rhs_small, lower=False, check_finite=False)
        return basis_use @ np.asarray(coeff, dtype=np.float64).reshape((-1,))

    def _apply(v: jnp.ndarray) -> jnp.ndarray:
        stats["applies"] += 1
        v_np = np.asarray(jax.device_get(v), dtype=np.float64).reshape((-1,))
        base = np.asarray(
            jax.device_get(base_preconditioner(jnp.asarray(v_np, dtype=jnp.float64))),
            dtype=np.float64,
        ).reshape((-1,))
        if mode_use == "multiplicative":
            abase = np.asarray(
                jax.device_get(matvec(jnp.asarray(base, dtype=jnp.float64))),
                dtype=np.float64,
            ).reshape((-1,))
            coarse_input = v_np - abase
        else:
            coarse_input = v_np
        correction = _coarse_correction(coarse_input)
        stats["coarse_applies"] += 1
        return jnp.asarray(base + correction, dtype=jnp.float64)

    metadata: dict[str, object] = {
        "mode": mode_use,
        "basis_size": int(len(basis_cols)),
        "rank": int(rank),
        "requested_max_directions": int(max_dirs_use),
        "fsavg_lmax": int(fsavg_lmax),
        "include_rhs": bool(include_rhs),
        "rcond": float(rcond),
        "basis_names": names_use,
        "active_projected": bool(direction_projector is not None),
        "expected_size": int(expected_size_use),
    }
    if emit is not None:
        emit(
            0,
            "solve_v3_full_system_linear_gmres: xblock_sparse_pc_gmres two-level coarse "
            f"built mode={mode_use} basis={len(basis_cols)} rank={rank}",
        )
    return _apply, metadata, stats


def _build_rhs1_xblock_smoothed_global_coupling_preconditioner(
    *,
    op: V3FullSystemOperator,
    rhs: jnp.ndarray,
    matvec: Callable[[jnp.ndarray], jnp.ndarray],
    base_preconditioner: Callable[[jnp.ndarray], jnp.ndarray],
    direction_projector: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
    expected_size: int | None = None,
    mode: str,
    fsavg_lmax: int,
    angular_lmax: int,
    max_extra_units: int,
    max_directions: int,
    rcond: float,
    include_rhs: bool,
    emit: Callable[[int, str], None] | None = None,
) -> tuple[Callable[[jnp.ndarray], jnp.ndarray], dict[str, object], dict[str, int]]:
    """Wrap x-block LU with a smoothed low-rank global-coupling correction.

    This is a constrained two-level method. The load basis ``P`` is deliberately
    low rank and physics-aware, the correction basis is ``Z = B^{-1} P`` using
    the already-built per-x preconditioner, and the coarse solve minimizes
    ``||r - A Z c||``. It keeps setup bounded while giving GMRES a fixed global
    subspace for flux-surface, source, and low Fourier coupling modes.
    """
    from scipy.linalg import qr, solve_triangular  # noqa: PLC0415

    mode_use = str(mode).strip().lower().replace("-", "_")
    if mode_use not in {"additive", "multiplicative"}:
        mode_use = "additive"
    max_dirs_use = max(1, int(max_directions))
    expected_size_use = int(op.total_size) if expected_size is None else int(expected_size)
    raw_loads = _rhs1_xblock_global_coupling_load_basis(
        op=op,
        rhs=rhs,
        include_rhs=bool(include_rhs),
        fsavg_lmax=int(fsavg_lmax),
        angular_lmax=int(angular_lmax),
        max_extra_units=int(max_extra_units),
        max_directions=max_dirs_use,
    )
    z_cols: list[np.ndarray] = []
    az_cols: list[np.ndarray] = []
    names: list[str] = []
    for name, load in raw_loads[:max_dirs_use]:
        if direction_projector is not None:
            load = direction_projector(load)
        load_np = np.asarray(jax.device_get(load), dtype=np.float64).reshape((-1,))
        if load_np.shape != (expected_size_use,) or not np.all(np.isfinite(load_np)):
            continue
        load_norm = float(np.linalg.norm(load_np))
        if (not np.isfinite(load_norm)) or load_norm <= 0.0:
            continue
        smoothed = np.asarray(
            jax.device_get(base_preconditioner(jnp.asarray(load_np / load_norm, dtype=jnp.float64))),
            dtype=np.float64,
        ).reshape((-1,))
        if smoothed.shape != load_np.shape or not np.all(np.isfinite(smoothed)):
            continue
        z_norm = float(np.linalg.norm(smoothed))
        if (not np.isfinite(z_norm)) or z_norm <= 0.0:
            continue
        smoothed = smoothed / z_norm
        a_smoothed = np.asarray(
            jax.device_get(matvec(jnp.asarray(smoothed, dtype=jnp.float64))),
            dtype=np.float64,
        ).reshape((-1,))
        if a_smoothed.shape != smoothed.shape or not np.all(np.isfinite(a_smoothed)):
            continue
        a_norm = float(np.linalg.norm(a_smoothed))
        if (not np.isfinite(a_norm)) or a_norm <= 0.0:
            continue
        names.append(str(name))
        z_cols.append(smoothed)
        az_cols.append(a_smoothed)

    if not z_cols:
        raise RuntimeError("global-coupling x-block preconditioner found no valid smoothed directions")

    z_basis = np.column_stack(z_cols)
    az_basis = np.column_stack(az_cols)
    q, r, piv = qr(az_basis, mode="economic", pivoting=True)
    diag = np.abs(np.diag(r))
    if diag.size == 0:
        raise RuntimeError("global-coupling x-block preconditioner coarse QR is empty")
    threshold = max(float(rcond), 0.0) * max(float(diag[0]), 1.0)
    rank = int(np.count_nonzero(diag > threshold))
    if rank <= 0:
        raise RuntimeError("global-coupling x-block preconditioner coarse QR is rank deficient")
    piv_use = np.asarray(piv[:rank], dtype=np.int32)
    q_use = np.asarray(q[:, :rank], dtype=np.float64)
    r_use = np.asarray(r[:rank, :rank], dtype=np.float64)
    z_use = np.asarray(z_basis[:, piv_use], dtype=np.float64)
    names_use = tuple(names[int(i)] for i in piv_use)
    stats = {"applies": 0, "coarse_applies": 0}

    def _coarse_correction(vec_np: np.ndarray) -> np.ndarray:
        rhs_small = q_use.T @ np.asarray(vec_np, dtype=np.float64).reshape((-1,))
        coeff = solve_triangular(r_use, rhs_small, lower=False, check_finite=False)
        return z_use @ np.asarray(coeff, dtype=np.float64).reshape((-1,))

    def _apply(v: jnp.ndarray) -> jnp.ndarray:
        stats["applies"] += 1
        v_np = np.asarray(jax.device_get(v), dtype=np.float64).reshape((-1,))
        base = np.asarray(
            jax.device_get(base_preconditioner(jnp.asarray(v_np, dtype=jnp.float64))),
            dtype=np.float64,
        ).reshape((-1,))
        if mode_use == "multiplicative":
            abase = np.asarray(
                jax.device_get(matvec(jnp.asarray(base, dtype=jnp.float64))),
                dtype=np.float64,
            ).reshape((-1,))
            coarse_input = v_np - abase
        else:
            coarse_input = v_np
        correction = _coarse_correction(coarse_input)
        stats["coarse_applies"] += 1
        return jnp.asarray(base + correction, dtype=jnp.float64)

    metadata: dict[str, object] = {
        "mode": mode_use,
        "load_basis_size": int(len(raw_loads)),
        "basis_size": int(len(z_cols)),
        "rank": int(rank),
        "requested_max_directions": int(max_dirs_use),
        "fsavg_lmax": int(fsavg_lmax),
        "angular_lmax": int(angular_lmax),
        "include_rhs": bool(include_rhs),
        "rcond": float(rcond),
        "basis_names": names_use,
    }
    if emit is not None:
        emit(
            0,
            "solve_v3_full_system_linear_gmres: xblock_sparse_pc_gmres global-coupling "
            f"built mode={mode_use} loads={len(raw_loads)} basis={len(z_cols)} rank={rank}",
        )
    return _apply, metadata, stats


def _build_rhs1_xblock_device_global_coupling_preconditioner(
    *,
    op: V3FullSystemOperator,
    rhs: jnp.ndarray,
    matvec: Callable[[jnp.ndarray], jnp.ndarray],
    base_preconditioner: Callable[[jnp.ndarray], jnp.ndarray],
    direction_projector: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
    expected_size: int | None = None,
    mode: str,
    fsavg_lmax: int,
    angular_lmax: int,
    max_extra_units: int,
    max_directions: int,
    rcond: float,
    include_rhs: bool,
    emit: Callable[[int, str], None] | None = None,
) -> tuple[Callable[[jnp.ndarray], jnp.ndarray], dict[str, object], dict[str, int]]:
    """Build a JAX-array global-coupling correction for device Krylov paths.

    The host global-coupling helper above is useful for SciPy Krylov probes but
    applies a coarse correction through host QR factors on every Krylov step.
    This variant performs the same physics-aware load smoothing, then stores
    ``Z`` and ``A Z`` as JAX arrays and applies a small ridge-regularized normal
    equation entirely with ``jnp`` operations.
    """

    mode_use = str(mode).strip().lower().replace("-", "_")
    if mode_use not in {"additive", "multiplicative"}:
        mode_use = "additive"
    expected_size_use = int(op.total_size) if expected_size is None else int(expected_size)
    max_dirs_use = max(1, int(max_directions))
    raw_loads = _rhs1_xblock_global_coupling_load_basis(
        op=op,
        rhs=rhs,
        include_rhs=bool(include_rhs),
        fsavg_lmax=int(fsavg_lmax),
        angular_lmax=int(angular_lmax),
        max_extra_units=int(max_extra_units),
        max_directions=max_dirs_use,
    )
    z_cols: list[jnp.ndarray] = []
    az_cols: list[jnp.ndarray] = []
    names: list[str] = []
    for name, load in raw_loads[:max_dirs_use]:
        if direction_projector is not None:
            load = direction_projector(load)
        load_j = jnp.asarray(load, dtype=jnp.float64).reshape((-1,))
        if load_j.shape != (expected_size_use,):
            continue
        load_np = np.asarray(jax.device_get(load_j), dtype=np.float64)
        if not np.all(np.isfinite(load_np)):
            continue
        load_norm = float(np.linalg.norm(load_np))
        if (not np.isfinite(load_norm)) or load_norm <= 0.0:
            continue
        load_unit = jnp.asarray(load_np / load_norm, dtype=jnp.float64)
        z = jnp.asarray(base_preconditioner(load_unit), dtype=jnp.float64).reshape((-1,))
        z_np = np.asarray(jax.device_get(z), dtype=np.float64)
        if z_np.shape != load_np.shape or not np.all(np.isfinite(z_np)):
            continue
        z_norm = float(np.linalg.norm(z_np))
        if (not np.isfinite(z_norm)) or z_norm <= 0.0:
            continue
        z = jnp.asarray(z_np / z_norm, dtype=jnp.float64)
        az = jnp.asarray(matvec(z), dtype=jnp.float64).reshape((-1,))
        az_np = np.asarray(jax.device_get(az), dtype=np.float64)
        if az_np.shape != z_np.shape or not np.all(np.isfinite(az_np)):
            continue
        az_norm = float(np.linalg.norm(az_np))
        if (not np.isfinite(az_norm)) or az_norm <= 0.0:
            continue
        names.append(str(name))
        z_cols.append(z)
        az_cols.append(az)

    if not z_cols:
        raise RuntimeError("device global-coupling x-block preconditioner found no valid smoothed directions")

    z_basis = jnp.stack(z_cols, axis=1)
    az_basis = jnp.stack(az_cols, axis=1)
    gram = az_basis.T @ az_basis
    diag_scale = jnp.maximum(jnp.max(jnp.abs(jnp.diag(gram))), jnp.asarray(1.0, dtype=jnp.float64))
    ridge = jnp.asarray(max(float(rcond), 1.0e-14), dtype=jnp.float64) * diag_scale
    coarse_inv = jnp.linalg.inv(gram + ridge * jnp.eye(int(gram.shape[0]), dtype=jnp.float64))
    gram_eigs = jnp.maximum(jnp.linalg.eigvalsh(gram), jnp.asarray(0.0, dtype=jnp.float64))
    singular_values = np.asarray(jax.device_get(jnp.sqrt(gram_eigs[::-1])), dtype=np.float64)
    if singular_values.size == 0 or not np.all(np.isfinite(singular_values)):
        raise RuntimeError("device global-coupling x-block preconditioner coarse spectrum is invalid")
    rank_threshold = max(float(rcond), 0.0) * max(float(np.max(singular_values, initial=0.0)), 1.0)
    rank = int(np.count_nonzero(singular_values > rank_threshold))
    if rank <= 0:
        raise RuntimeError("device global-coupling x-block preconditioner coarse system is rank deficient")
    stats = {"applies": 0, "coarse_applies": 0}

    def _apply(v: jnp.ndarray) -> jnp.ndarray:
        stats["applies"] += 1
        v_j = jnp.asarray(v, dtype=jnp.float64)
        base = jnp.asarray(base_preconditioner(v_j), dtype=jnp.float64)
        if mode_use == "multiplicative":
            coarse_input = v_j - jnp.asarray(matvec(base), dtype=jnp.float64)
        else:
            coarse_input = v_j
        coeff = coarse_inv @ (az_basis.T @ coarse_input)
        stats["coarse_applies"] += 1
        return base + z_basis @ coeff

    metadata: dict[str, object] = {
        "mode": mode_use,
        "load_basis_size": int(len(raw_loads)),
        "basis_size": int(z_basis.shape[1]),
        "rank": int(rank),
        "requested_max_directions": int(max_dirs_use),
        "fsavg_lmax": int(fsavg_lmax),
        "angular_lmax": int(angular_lmax),
        "include_rhs": bool(include_rhs),
        "rcond": float(rcond),
        "ridge": float(jax.device_get(ridge)),
        "basis_names": tuple(names),
        "device_resident": True,
        "singular_values": tuple(float(v) for v in singular_values[: min(int(singular_values.size), 16)]),
    }
    if emit is not None:
        emit(
            0,
            "solve_v3_full_system_linear_gmres: xblock_sparse_pc_gmres device global-coupling "
            f"built mode={mode_use} loads={len(raw_loads)} basis={int(z_basis.shape[1])} rank={rank}",
        )
    return _apply, metadata, stats


def _apply_subspace_minres_correction(
    *,
    matvec: Callable[[jnp.ndarray], jnp.ndarray],
    rhs: jnp.ndarray,
    x0: jnp.ndarray,
    direction_builder: Callable[[jnp.ndarray], Sequence[tuple[str, jnp.ndarray]]],
    steps: int,
    max_directions: int,
    alpha_clip: float = 0.0,
    rcond: float = 1.0e-12,
    min_improvement: float = 0.0,
) -> tuple[jnp.ndarray, jnp.ndarray, tuple[float, ...], tuple[int, ...], tuple[str, ...]]:
    """Apply accepted least-squares residual corrections over a small basis.

    This is a matrix-free coarse solve: it forms only ``A d_i`` for a bounded
    number of candidate directions, solves ``min_alpha ||r - A D alpha||_2``,
    and accepts the update only when the true residual decreases.
    """
    rhs = jnp.asarray(rhs, dtype=jnp.float64)
    x = jnp.asarray(x0, dtype=jnp.float64)
    residual = rhs - jnp.asarray(matvec(x), dtype=jnp.float64)
    residual_norm = float(jnp.linalg.norm(residual))
    history: list[float] = [residual_norm]
    accepted_counts: list[int] = []
    accepted_names: list[str] = []
    steps_use = max(0, int(steps))
    max_dirs_use = max(1, int(max_directions))
    alpha_clip_use = max(0.0, float(alpha_clip))
    rcond_use = max(0.0, float(rcond))
    min_improvement_use = max(0.0, float(min_improvement))

    for _ in range(steps_use):
        raw_directions = tuple(direction_builder(residual))[:max_dirs_use]
        names: list[str] = []
        basis_cols: list[np.ndarray] = []
        abasis_cols: list[np.ndarray] = []
        for name, direction in raw_directions:
            direction_np = np.asarray(jax.device_get(direction), dtype=np.float64).reshape((-1,))
            if direction_np.shape != (int(x.size),) or not np.all(np.isfinite(direction_np)):
                continue
            norm = float(np.linalg.norm(direction_np))
            if (not np.isfinite(norm)) or norm <= 0.0:
                continue
            direction_np = direction_np / norm
            a_direction = np.asarray(
                jax.device_get(matvec(jnp.asarray(direction_np, dtype=jnp.float64))),
                dtype=np.float64,
            ).reshape((-1,))
            if a_direction.shape != direction_np.shape or not np.all(np.isfinite(a_direction)):
                continue
            a_norm = float(np.linalg.norm(a_direction))
            if (not np.isfinite(a_norm)) or a_norm <= 0.0:
                continue
            names.append(str(name))
            basis_cols.append(direction_np)
            abasis_cols.append(a_direction)
        if not basis_cols:
            break

        residual_np = np.asarray(jax.device_get(residual), dtype=np.float64).reshape((-1,))
        basis = np.column_stack(basis_cols)
        abasis = np.column_stack(abasis_cols)
        try:
            coeff, *_ = np.linalg.lstsq(abasis, residual_np, rcond=rcond_use if rcond_use > 0.0 else None)
        except np.linalg.LinAlgError:
            coeff = np.linalg.pinv(abasis, rcond=max(rcond_use, 1.0e-12)) @ residual_np
        coeff = np.asarray(coeff, dtype=np.float64).reshape((-1,))
        if alpha_clip_use > 0.0:
            coeff = np.clip(coeff, -alpha_clip_use, alpha_clip_use)
        if not np.all(np.isfinite(coeff)):
            break
        trial_residual_np = residual_np - abasis @ coeff
        trial_norm = float(np.linalg.norm(trial_residual_np))
        if (not np.isfinite(trial_norm)) or trial_norm >= residual_norm * (1.0 - min_improvement_use):
            break
        x_np = np.asarray(jax.device_get(x), dtype=np.float64).reshape((-1,)) + basis @ coeff
        x = jnp.asarray(x_np, dtype=jnp.float64)
        residual = jnp.asarray(trial_residual_np, dtype=jnp.float64)
        residual_norm = trial_norm
        history.append(residual_norm)
        accepted_counts.append(int(len(basis_cols)))
        accepted_names.extend(names)

    return x, residual, tuple(history), tuple(accepted_counts), tuple(accepted_names)


def _build_rhsmode1_pas_lite_preconditioner(
    *,
    op: V3FullSystemOperator,
    reduce_full: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
    expand_reduced: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
    safe: bool = True,
) -> Callable[[jnp.ndarray], jnp.ndarray]:
    """Lightweight PAS preconditioner: angular PAS block (if cheap) + x-coarse + collision diag.

    This preconditioner is intended for large PAS DKES/full-trajectory cases where the
    full PAS hybrid (line/xblock) preconditioner is expensive to build. We optionally
    apply a PAS-specific angular preconditioner (tokamak theta or 3D tz) only when the
    angular block size is modest, then follow with x-coarsening and a collision-diagonal
    smoothing pass.
    """
    angular_precond: Callable[[jnp.ndarray], jnp.ndarray] | None = None
    if _pas_tokamak_theta_preconditioner_applicable(op):
        angular_precond = _build_rhsmode1_pas_tokamak_theta_preconditioner(
            op=op, reduce_full=reduce_full, expand_reduced=expand_reduced
        )
    elif _pas_tz_preconditioner_applicable(op):
        tz_max_env = os.environ.get("SFINCS_JAX_PAS_LITE_TZ_MAX", "").strip()
        try:
            tz_max = int(tz_max_env) if tz_max_env else 256
        except ValueError:
            tz_max = 256
        tz_size = int(op.n_theta) * int(op.n_zeta)
        if tz_max > 0 and tz_size <= tz_max:
            angular_precond = _build_rhsmode1_pas_tz_preconditioner(
                op=op, reduce_full=reduce_full, expand_reduced=expand_reduced
            )

    x_precond = _build_rhsmode1_xmg_preconditioner(
        op=op, reduce_full=reduce_full, expand_reduced=expand_reduced
    )
    collision_precond = _build_rhsmode1_collision_preconditioner(
        op=op, reduce_full=reduce_full, expand_reduced=expand_reduced
    )
    precond = x_precond
    if angular_precond is not None:
        precond = _compose_preconditioners(angular_precond, precond)
    precond = _compose_preconditioners(precond, collision_precond)
    return _safe_preconditioner(precond) if bool(safe) else precond


def _build_rhsmode1_pas_hybrid_preconditioner(
    *,
    op: V3FullSystemOperator,
    reduce_full: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
    expand_reduced: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
    safe: bool = True,
) -> Callable[[jnp.ndarray], jnp.ndarray]:
    """Hybrid PAS preconditioner: line solve + coarse-x correction + collision diagonal.

    This targets PAS DKES/full-trajectory cases where pure line or x-coarse preconditioners
    can stagnate. We apply a line preconditioner (theta or zeta), then a coarse-x additive
    correction (xmg), and finally the collision diagonal as a cheap smoothing pass.
    """
    line_precond: Callable[[jnp.ndarray], jnp.ndarray] | None = None
    nxi_for_x = np.asarray(op.fblock.collisionless.n_xi_for_x, dtype=np.int32)
    local_per_species = int(np.sum(nxi_for_x))
    line_size = int(local_per_species * int(op.n_theta))
    line_max_env = os.environ.get("SFINCS_JAX_PAS_HYBRID_LINE_MAX", "").strip()
    try:
        line_max = int(line_max_env) if line_max_env else 512
    except ValueError:
        line_max = 512
    if not line_max_env:
        # For small-Nzeta tokamak-like grids, allow line preconditioning by default.
        if int(op.n_zeta) <= 5 and int(op.n_theta) >= 8:
            line_max = max(int(line_max), 4096)
    if line_size <= line_max:
        if int(op.n_theta) >= int(op.n_zeta):
            line_precond = _build_rhsmode1_theta_line_preconditioner(
                op=op, reduce_full=reduce_full, expand_reduced=expand_reduced
            )
        else:
            line_precond = _build_rhsmode1_zeta_line_preconditioner(
                op=op, reduce_full=reduce_full, expand_reduced=expand_reduced
            )
    else:
        # Try a truncated-L (theta,zeta) block per x as a cheaper angular preconditioner.
        lmax_env = os.environ.get("SFINCS_JAX_PAS_HYBRID_LMAX", "").strip()
        has_er = op.fblock.er_xdot is not None or op.fblock.er_xidot is not None
        use_dkes_exb = bool(getattr(op.fblock.exb_theta, "use_dkes_exb_drift", False)) or bool(
            getattr(op.fblock.exb_zeta, "use_dkes_exb_drift", False)
        )
        needs_stronger_l = bool(has_er or use_dkes_exb)
        nz = int(op.n_theta) * int(op.n_zeta)
        try:
            if lmax_env:
                lmax = int(lmax_env)
            else:
                # The v3 Er xDot / xiDot terms couple ΔL=±2, so a truncated angular block that
                # only retains L=0 is often too weak. Default to keeping L=0..2 when these
                # terms are present (bounded by xblock_max below). For small angular grids
                # (tokamak-like cases), keep a few more L modes even without Er to improve robustness.
                lmax = 8 if (needs_stronger_l or nz <= 256) else 2
        except ValueError:
            lmax = 8 if (needs_stronger_l or nz <= 256) else 2
        xblock_max_env = os.environ.get("SFINCS_JAX_PAS_HYBRID_XBLOCK_MAX", "").strip()
        try:
            # PAS+Er runs need larger angular blocks to be effective; allow a larger default.
            # For small angular grids, allow a larger default so truncated-L blocks remain useful.
            xblock_max_default = 2048 if (needs_stronger_l or nz <= 256) else 256
            xblock_max = int(xblock_max_env) if xblock_max_env else xblock_max_default
        except ValueError:
            xblock_max = 2048 if (needs_stronger_l or nz <= 256) else 256
        if nz > 0:
            max_allowed = int(xblock_max // nz)
            if max_allowed > 0:
                lmax = min(int(lmax), max_allowed)
        block_size = int(max(0, lmax) * int(op.n_theta) * int(op.n_zeta))
        if lmax > 0 and block_size > 0 and block_size <= xblock_max:
            line_precond = _build_rhsmode1_xblock_tz_lmax_preconditioner(
                op=op,
                lmax=lmax,
                reduce_full=reduce_full,
                expand_reduced=expand_reduced,
            )
    x_precond: Callable[[jnp.ndarray], jnp.ndarray]
    if op.fblock.pas is not None and op.fblock.fp is None and op.fblock.er_xdot is not None:
        # The dense ddx matrices in the v3 Er xDot operator can be extremely ill-conditioned.
        # Prefer a stable x-upwind solve over explicit dense x-block inversions.
        x_precond = _build_rhsmode1_xupwind_preconditioner(
            op=op, reduce_full=reduce_full, expand_reduced=expand_reduced
        )
    else:
        x_precond = _build_rhsmode1_xmg_preconditioner(op=op, reduce_full=reduce_full, expand_reduced=expand_reduced)
    collision_precond = _build_rhsmode1_collision_preconditioner(
        op=op, reduce_full=reduce_full, expand_reduced=expand_reduced
    )
    # Apply angular/line preconditioner (if enabled), then x-coarse correction, then collision smoothing.
    precond = x_precond
    if line_precond is not None:
        precond = _compose_preconditioners(line_precond, precond)
    precond = _compose_preconditioners(precond, collision_precond)
    # Guard against non-finite preconditioned vectors causing GMRES breakdown.
    #
    # Note: this wrapper is *nonlinear* (nan_to_num/clip). Avoid it when the preconditioner is
    # used as a building block inside other Krylov preconditioners (e.g. Schur), where linearity
    # matters for stability.
    return _safe_preconditioner(precond) if bool(safe) else precond


def _build_rhsmode1_pas_schur_preconditioner(
    *,
    op: V3FullSystemOperator,
    reduce_full: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
    expand_reduced: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
    safe: bool = True,
) -> Callable[[jnp.ndarray], jnp.ndarray]:
    """PAS block-Schur preconditioner: (L,theta/zeta) coupling + x-coarsening + collisions.

    This targets tokamak/near-tokamak PAS RHSMode=1 systems where line/x-coarse
    preconditioners stagnate. We apply a stronger angular/L block preconditioner
    (pas_tokamak_theta or pas_tz), then an x-coarse correction (xmg or x-upwind),
    followed by the collision diagonal as a smoothing pass.
    """
    if _pas_tokamak_theta_preconditioner_applicable(op):
        angular_precond = _build_rhsmode1_pas_tokamak_theta_preconditioner(
            op=op, reduce_full=reduce_full, expand_reduced=expand_reduced
        )
    elif _pas_tz_preconditioner_applicable(op):
        angular_precond = _build_rhsmode1_pas_tz_preconditioner(
            op=op, reduce_full=reduce_full, expand_reduced=expand_reduced
        )
    else:
        angular_precond = _build_rhsmode1_pas_hybrid_preconditioner(
            op=op, reduce_full=reduce_full, expand_reduced=expand_reduced, safe=False
        )

    if op.fblock.pas is not None and op.fblock.fp is None and op.fblock.er_xdot is not None:
        x_precond = _build_rhsmode1_xupwind_preconditioner(
            op=op, reduce_full=reduce_full, expand_reduced=expand_reduced
        )
    else:
        x_precond = _build_rhsmode1_xmg_preconditioner(op=op, reduce_full=reduce_full, expand_reduced=expand_reduced)

    collision_precond = _build_rhsmode1_collision_preconditioner(
        op=op, reduce_full=reduce_full, expand_reduced=expand_reduced
    )
    precond = _compose_preconditioners(angular_precond, x_precond)
    precond = _compose_preconditioners(precond, collision_precond)
    return _safe_preconditioner(precond) if bool(safe) else precond


def _build_rhsmode1_species_block_preconditioner(
    *,
    op: V3FullSystemOperator,
    reduce_full: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
    expand_reduced: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
) -> Callable[[jnp.ndarray], jnp.ndarray]:
    """Build a RHSMode=1 preconditioner using full species blocks.

    For each species, solve a block over all (x,L,theta,zeta) points. This captures
    both angular and x/L coupling within each species while ignoring inter-species
    coupling, providing a much stronger preconditioner for PAS systems.
    """
    cache_key = _rhsmode1_precond_cache_key(op, "species_block")
    # Use block-size hint for mixed-precision selection on large species blocks.
    nxi_for_x = np.asarray(op.fblock.collisionless.n_xi_for_x, dtype=np.int32)
    local_per_species = int(np.sum(nxi_for_x))
    block_size_hint = int(local_per_species * int(op.n_theta) * int(op.n_zeta))
    precond_dtype = _precond_dtype(block_size_hint * block_size_hint)
    cached = _RHSMODE1_PRECOND_CACHE.get(cache_key)
    if cached is None:
        op_pc = op
        n_species = int(op.n_species)
        n_x = int(op.n_x)
        n_l = int(op.n_xi)
        n_theta = int(op.n_theta)
        n_zeta = int(op.n_zeta)
        total_size = int(op.total_size)

        nxi_for_x = np.asarray(op.fblock.collisionless.n_xi_for_x, dtype=np.int32)
        local_per_species = int(np.sum(nxi_for_x))
        block_size = int(local_per_species * n_theta * n_zeta)

        reg_env = os.environ.get("SFINCS_JAX_RHSMODE1_PRECOND_REG", "").strip()
        reg_val = float(reg_env) if reg_env else 1e-10
        reg = np.float64(reg_val)

        idx_map = np.zeros((n_species, block_size), dtype=np.int32)
        block_inv = np.zeros((n_species, block_size, block_size), dtype=np.float64)

        for s in range(n_species):
            k = 0
            for ix in range(n_x):
                max_l = int(nxi_for_x[ix])
                for il in range(max_l):
                    for it in range(n_theta):
                        for iz in range(n_zeta):
                            idx_map[s, k] = int(
                                ((((s * n_x + ix) * n_l + il) * n_theta + it) * n_zeta + iz)
                            )
                            k += 1
            rep_idx = idx_map[s, :]
            chunk_cols = _precond_chunk_cols(total_size, int(rep_idx.shape[0]))
            y_sub = _matvec_submatrix(
                op_pc,
                col_idx=rep_idx,
                row_idx=rep_idx,
                total_size=total_size,
                chunk_cols=chunk_cols,
            )
            a = np.asarray(y_sub.T, dtype=np.float64)
            a = a + reg * np.eye(block_size, dtype=np.float64)
            try:
                inv = np.linalg.inv(a)
            except np.linalg.LinAlgError:
                inv = np.linalg.pinv(a, rcond=1e-12)
            if not np.all(np.isfinite(inv)):
                inv = np.linalg.pinv(a, rcond=1e-12)
            block_inv[s, :, :] = inv

        idx_map_jnp = jnp.asarray(idx_map, dtype=jnp.int32)
        flat_idx_jnp = idx_map_jnp.reshape((-1,))
        block_inv_jnp = jnp.asarray(block_inv, dtype=precond_dtype)

        extra_start = int(op.f_size + op.phi1_size)
        extra_size = int(op.extra_size)
        extra_idx_np = np.arange(extra_start, extra_start + extra_size, dtype=np.int32)
        extra_idx_jnp = jnp.asarray(extra_idx_np, dtype=jnp.int32)
        extra_inv_jnp: jnp.ndarray | None = None
        if extra_size > 0:
            chunk_cols = _precond_chunk_cols(total_size, int(extra_idx_np.shape[0]))
            y_sub = _matvec_submatrix(
                op_pc,
                col_idx=extra_idx_np,
                row_idx=extra_idx_np,
                total_size=total_size,
                chunk_cols=chunk_cols,
            )
            ee = np.asarray(y_sub.T, dtype=np.float64)
            ee = ee + reg * np.eye(extra_size, dtype=np.float64)
            try:
                ee_inv = np.linalg.inv(ee)
            except np.linalg.LinAlgError:
                ee_inv = np.linalg.pinv(ee, rcond=1e-12)
            if not np.all(np.isfinite(ee_inv)):
                ee_inv = np.linalg.pinv(ee, rcond=1e-12)
            extra_inv_jnp = jnp.asarray(ee_inv, dtype=precond_dtype)

        cached = _RHSMode1PrecondCache(
            idx_map_jnp=idx_map_jnp,
            flat_idx_jnp=flat_idx_jnp,
            block_inv_jnp=block_inv_jnp,
            extra_idx_jnp=extra_idx_jnp,
            extra_inv_jnp=extra_inv_jnp,
        )
        _RHSMODE1_PRECOND_CACHE[cache_key] = cached

    block_inv_jnp = cached.block_inv_jnp
    flat_idx_jnp = cached.flat_idx_jnp
    extra_idx_jnp = cached.extra_idx_jnp
    extra_inv_jnp = cached.extra_inv_jnp
    n_species = int(block_inv_jnp.shape[0])
    block_size = int(block_inv_jnp.shape[-1])

    def _apply_full(r_full: jnp.ndarray) -> jnp.ndarray:
        r_full = jnp.asarray(r_full, dtype=precond_dtype)
        r_loc = r_full[flat_idx_jnp].reshape((n_species, block_size))
        z_loc = jnp.einsum("sij,sj->si", block_inv_jnp, r_loc)
        z_full = jnp.zeros_like(r_full)
        z_full = z_full.at[flat_idx_jnp].set(z_loc.reshape((-1,)), unique_indices=True)
        if extra_inv_jnp is not None:
            r_extra = r_full[extra_idx_jnp]
            z_extra = extra_inv_jnp @ r_extra
            z_full = z_full.at[extra_idx_jnp].set(z_extra, unique_indices=True)
        return jnp.asarray(z_full, dtype=jnp.float64)

    if reduce_full is None or expand_reduced is None:
        return _apply_full

    def _apply_reduced(r_reduced: jnp.ndarray) -> jnp.ndarray:
        z_full = _apply_full(expand_reduced(r_reduced))
        return reduce_full(z_full)

    return _apply_reduced


def _build_rhsmode1_species_xblock_preconditioner(
    *,
    op: V3FullSystemOperator,
    reduce_full: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
    expand_reduced: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
) -> Callable[[jnp.ndarray], jnp.ndarray]:
    """Build a RHSMode=1 preconditioner with a single species×x/L block per (theta,zeta).

    This includes inter-species coupling in the local (x,L) block, which is useful for
    FP collision cases where the field-particle terms couple species.
    """
    cache_key = _rhsmode1_precond_cache_key(op, "sxblock")
    nxi_for_x = np.asarray(op.fblock.collisionless.n_xi_for_x, dtype=np.int32)
    local_per_species = int(np.sum(nxi_for_x))
    block_size = int(int(op.n_species) * local_per_species)
    precond_dtype = _precond_dtype(block_size * block_size)
    cached = _RHSMODE1_PRECOND_GLOBAL_CACHE.get(cache_key)
    if cached is None:
        op_pc = op
        n_species = int(op.n_species)
        n_x = int(op.n_x)
        n_l = int(op.n_xi)
        n_theta = int(op.n_theta)
        n_zeta = int(op.n_zeta)
        total_size = int(op.total_size)

        reg_env = os.environ.get("SFINCS_JAX_RHSMODE1_PRECOND_REG", "").strip()
        reg_val = float(reg_env) if reg_env else 1e-10
        reg = np.float64(reg_val)

        rep_idx: list[int] = []
        for s in range(n_species):
            for ix in range(n_x):
                max_l = int(nxi_for_x[ix])
                for il in range(max_l):
                    f_idx = ((((s * n_x + ix) * n_l + il) * n_theta + 0) * n_zeta + 0)
                    rep_idx.append(int(f_idx))
        rep_idx_np = np.asarray(rep_idx, dtype=np.int32)
        chunk_cols = _precond_chunk_cols(total_size, int(rep_idx_np.shape[0]))
        y_sub = _matvec_submatrix(
            op_pc,
            col_idx=rep_idx_np,
            row_idx=rep_idx_np,
            total_size=total_size,
            chunk_cols=chunk_cols,
        )
        a = np.asarray(y_sub.T, dtype=np.float64)
        a = a + reg * np.eye(block_size, dtype=np.float64)
        try:
            inv = np.linalg.inv(a)
        except np.linalg.LinAlgError:
            inv = np.linalg.pinv(a, rcond=1e-12)
        if not np.all(np.isfinite(inv)):
            inv = np.linalg.pinv(a, rcond=1e-12)

        idx_map = np.zeros((n_theta, n_zeta, block_size), dtype=np.int32)
        for it in range(n_theta):
            for iz in range(n_zeta):
                k = 0
                for s in range(n_species):
                    for ix in range(n_x):
                        max_l = int(nxi_for_x[ix])
                        for il in range(max_l):
                            idx_map[it, iz, k] = int(
                                ((((s * n_x + ix) * n_l + il) * n_theta + it) * n_zeta + iz)
                            )
                            k += 1

        idx_map_jnp = jnp.asarray(idx_map, dtype=jnp.int32)
        flat_idx_jnp = idx_map_jnp.reshape((-1,))
        block_inv_jnp = jnp.asarray(inv, dtype=precond_dtype)

        extra_start = int(op.f_size + op.phi1_size)
        extra_size = int(op.extra_size)
        extra_idx_np = np.arange(extra_start, extra_start + extra_size, dtype=np.int32)
        extra_idx_jnp = jnp.asarray(extra_idx_np, dtype=jnp.int32)
        extra_inv_jnp: jnp.ndarray | None = None
        if extra_size > 0:
            chunk_cols = _precond_chunk_cols(total_size, int(extra_idx_np.shape[0]))
            y_sub = _matvec_submatrix(
                op_pc,
                col_idx=extra_idx_np,
                row_idx=extra_idx_np,
                total_size=total_size,
                chunk_cols=chunk_cols,
            )
            ee = np.asarray(y_sub.T, dtype=np.float64)
            ee = ee + reg * np.eye(extra_size, dtype=np.float64)
            try:
                ee_inv = np.linalg.inv(ee)
            except np.linalg.LinAlgError:
                ee_inv = np.linalg.pinv(ee, rcond=1e-12)
            if not np.all(np.isfinite(ee_inv)):
                ee_inv = np.linalg.pinv(ee, rcond=1e-12)
            extra_inv_jnp = jnp.asarray(ee_inv, dtype=precond_dtype)

        cached = _RHSMode1PrecondGlobalCache(
            idx_map_jnp=idx_map_jnp,
            flat_idx_jnp=flat_idx_jnp,
            block_inv_jnp=block_inv_jnp,
            extra_idx_jnp=extra_idx_jnp,
            extra_inv_jnp=extra_inv_jnp,
        )
        _RHSMODE1_PRECOND_GLOBAL_CACHE[cache_key] = cached

    block_inv_jnp = cached.block_inv_jnp
    flat_idx_jnp = cached.flat_idx_jnp
    extra_idx_jnp = cached.extra_idx_jnp
    extra_inv_jnp = cached.extra_inv_jnp

    def _apply_full(r_full: jnp.ndarray) -> jnp.ndarray:
        r_full = jnp.asarray(r_full, dtype=precond_dtype)
        r_loc = r_full[flat_idx_jnp].reshape((int(op.n_theta), int(op.n_zeta), block_size))
        z_loc = jnp.einsum("ij,tzj->tzi", block_inv_jnp, r_loc)
        z_full = jnp.zeros_like(r_full)
        z_full = z_full.at[flat_idx_jnp].set(z_loc.reshape((-1,)), unique_indices=True)
        if extra_inv_jnp is not None:
            r_extra = r_full[extra_idx_jnp]
            z_extra = extra_inv_jnp @ r_extra
            z_full = z_full.at[extra_idx_jnp].set(z_extra, unique_indices=True)
        return jnp.asarray(z_full, dtype=jnp.float64)

    if reduce_full is None or expand_reduced is None:
        return _apply_full

    def _apply_reduced(r_reduced: jnp.ndarray) -> jnp.ndarray:
        z_full = _apply_full(expand_reduced(r_reduced))
        return reduce_full(z_full)

    return _apply_reduced


def _build_rhsmode1_xblock_tz_preconditioner(
    *,
    op: V3FullSystemOperator,
    reduce_full: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
    expand_reduced: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
) -> Callable[[jnp.ndarray], jnp.ndarray]:
    """Build a RHSMode=1 preconditioner using full (theta,zeta) blocks per x.

    For each species and each x, solve the block over all (L,theta,zeta) points.
    This captures angular coupling while retaining x/L coupling without assembling
    full species blocks.
    """
    cache_key = _rhsmode1_precond_cache_key(op, "xblock_tz")
    cached = _RHSMODE1_PRECOND_LIST_CACHE.get(cache_key)
    if cached is None:
        op_pc = op
        n_species = int(op.n_species)
        n_x = int(op.n_x)
        n_l = int(op.n_xi)
        n_theta = int(op.n_theta)
        n_zeta = int(op.n_zeta)
        total_size = int(op.total_size)

        nxi_for_x = np.asarray(op.fblock.collisionless.n_xi_for_x, dtype=np.int32)
        max_l = int(np.max(nxi_for_x)) if nxi_for_x.size else 0
        max_block_size = int(max_l * n_theta * n_zeta)
        precond_dtype = _precond_dtype(max_block_size * max_block_size)

        reg_env = os.environ.get("SFINCS_JAX_RHSMODE1_PRECOND_REG", "").strip()
        reg_val = float(reg_env) if reg_env else 1e-10
        reg = np.float64(reg_val)
        pas_max_cols = None
        if op.fblock.pas is not None:
            pas_cols_env = os.environ.get("SFINCS_JAX_PRECOND_PAS_MAX_COLS", "").strip()
            try:
                if pas_cols_env:
                    pas_max_cols = int(pas_cols_env)
                else:
                    tz_size = int(n_theta) * int(n_zeta)
                    pas_max_cols = 256 if tz_size <= 256 else 64
            except ValueError:
                tz_size = int(n_theta) * int(n_zeta)
                pas_max_cols = 256 if tz_size <= 256 else 64

        block_inv_list: list[jnp.ndarray] = []
        block_slices: list[tuple[int, int]] = []

        for s in range(n_species):
            for ix in range(n_x):
                max_l = int(nxi_for_x[ix])
                block_size = int(max_l * n_theta * n_zeta)
                start = int((((s * n_x + ix) * n_l) * n_theta) * n_zeta)
                if block_size <= 0:
                    continue
                rep_idx = np.arange(start, start + block_size, dtype=np.int32)
                chunk_cols = _precond_chunk_cols(total_size, int(rep_idx.shape[0]))
                if pas_max_cols is not None and block_size >= 256:
                    chunk_cols = min(chunk_cols, pas_max_cols)
                y_sub = _matvec_submatrix(
                    op_pc,
                    col_idx=rep_idx,
                    row_idx=rep_idx,
                    total_size=total_size,
                    chunk_cols=chunk_cols,
                )
                a = np.asarray(y_sub.T, dtype=np.float64)
                a = a + reg * np.eye(block_size, dtype=np.float64)
                try:
                    inv = np.linalg.inv(a)
                except np.linalg.LinAlgError:
                    inv = np.linalg.pinv(a, rcond=1e-12)
                if not np.all(np.isfinite(inv)):
                    inv = np.linalg.pinv(a, rcond=1e-12)
                block_inv_list.append(jnp.asarray(inv, dtype=precond_dtype))
                block_slices.append((start, block_size))

        extra_start = int(op.f_size + op.phi1_size)
        extra_size = int(op.extra_size)
        extra_idx_np = np.arange(extra_start, extra_start + extra_size, dtype=np.int32)
        extra_idx_jnp = jnp.asarray(extra_idx_np, dtype=jnp.int32)
        extra_inv_jnp: jnp.ndarray | None = None
        if extra_size > 0:
            chunk_cols = _precond_chunk_cols(total_size, int(extra_idx_np.shape[0]))
            y_sub = _matvec_submatrix(
                op_pc,
                col_idx=extra_idx_np,
                row_idx=extra_idx_np,
                total_size=total_size,
                chunk_cols=chunk_cols,
            )
            ee = np.asarray(y_sub.T, dtype=np.float64)
            ee = ee + reg * np.eye(extra_size, dtype=np.float64)
            try:
                ee_inv = np.linalg.inv(ee)
            except np.linalg.LinAlgError:
                ee_inv = np.linalg.pinv(ee, rcond=1e-12)
            if not np.all(np.isfinite(ee_inv)):
                ee_inv = np.linalg.pinv(ee, rcond=1e-12)
            extra_inv_jnp = jnp.asarray(ee_inv, dtype=precond_dtype)

        cached = _RHSMode1PrecondListCache(
            block_inv_list=tuple(block_inv_list),
            block_slices=tuple(block_slices),
            extra_idx_jnp=extra_idx_jnp,
            extra_inv_jnp=extra_inv_jnp,
        )
        _RHSMODE1_PRECOND_LIST_CACHE[cache_key] = cached

    block_inv_list = cached.block_inv_list
    block_slices = cached.block_slices
    extra_idx_jnp = cached.extra_idx_jnp
    extra_inv_jnp = cached.extra_inv_jnp
    precond_dtype = block_inv_list[0].dtype if block_inv_list else _precond_dtype()

    def _apply_full(r_full: jnp.ndarray) -> jnp.ndarray:
        r_full = jnp.asarray(r_full, dtype=precond_dtype)
        z_full = jnp.zeros_like(r_full)
        for inv, (start, block_size) in zip(block_inv_list, block_slices, strict=True):
            r_loc = r_full[start : start + block_size]
            z_loc = inv @ r_loc
            z_full = z_full.at[start : start + block_size].set(z_loc, unique_indices=True)
        if extra_inv_jnp is not None:
            r_extra = r_full[extra_idx_jnp]
            z_extra = extra_inv_jnp @ r_extra
            z_full = z_full.at[extra_idx_jnp].set(z_extra, unique_indices=True)
        return jnp.asarray(z_full, dtype=jnp.float64)

    apply_full_safe = _safe_preconditioner(_apply_full)

    if reduce_full is None or expand_reduced is None:
        return apply_full_safe

    def _apply_reduced(r_reduced: jnp.ndarray) -> jnp.ndarray:
        z_full = apply_full_safe(expand_reduced(r_reduced))
        return reduce_full(z_full)

    return _apply_reduced


def _build_rhsmode1_xblock_tz_lmax_preconditioner(
    *,
    op: V3FullSystemOperator,
    lmax: int,
    reduce_full: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
    expand_reduced: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
) -> Callable[[jnp.ndarray], jnp.ndarray]:
    """Build a RHSMode=1 preconditioner using truncated-L (theta,zeta) blocks per x.

    Uses only the lowest L<=lmax modes per x to reduce block size while retaining
    angular coupling. Higher-L rows are left unpreconditioned (identity).
    """
    lmax = int(lmax)
    if lmax <= 0:
        return _build_rhsmode1_xblock_tz_preconditioner(op=op, reduce_full=reduce_full, expand_reduced=expand_reduced)
    cache_key = _rhsmode1_precond_cache_key(op, f"xblock_tz_lmax_{lmax}")
    cached = _RHSMODE1_PRECOND_LIST_CACHE.get(cache_key)
    if cached is None:
        op_pc = op
        n_species = int(op.n_species)
        n_x = int(op.n_x)
        n_l = int(op.n_xi)
        n_theta = int(op.n_theta)
        n_zeta = int(op.n_zeta)
        total_size = int(op.total_size)

        nxi_for_x = np.asarray(op.fblock.collisionless.n_xi_for_x, dtype=np.int32)
        max_l = int(np.max(nxi_for_x)) if nxi_for_x.size else 0
        max_l = min(max_l, lmax)
        max_block_size = int(max_l * n_theta * n_zeta)
        precond_dtype = _precond_dtype(max_block_size * max_block_size)

        reg_env = os.environ.get("SFINCS_JAX_RHSMODE1_PRECOND_REG", "").strip()
        reg_val = float(reg_env) if reg_env else 1e-10
        reg = np.float64(reg_val)
        pas_max_cols = None
        if op.fblock.pas is not None:
            pas_cols_env = os.environ.get("SFINCS_JAX_PRECOND_PAS_MAX_COLS", "").strip()
            try:
                pas_max_cols = int(pas_cols_env) if pas_cols_env else 64
            except ValueError:
                pas_max_cols = 64

        block_inv_list: list[jnp.ndarray] = []
        block_slices: list[tuple[int, int]] = []

        for s in range(n_species):
            for ix in range(n_x):
                max_lx = min(int(nxi_for_x[ix]), lmax)
                block_size = int(max_lx * n_theta * n_zeta)
                start = int((((s * n_x + ix) * n_l) * n_theta) * n_zeta)
                if block_size <= 0:
                    continue
                rep_idx = np.arange(start, start + block_size, dtype=np.int32)
                chunk_cols = _precond_chunk_cols(total_size, int(rep_idx.shape[0]))
                if pas_max_cols is not None and block_size >= 256:
                    chunk_cols = min(chunk_cols, pas_max_cols)
                y_sub = _matvec_submatrix(
                    op_pc,
                    col_idx=rep_idx,
                    row_idx=rep_idx,
                    total_size=total_size,
                    chunk_cols=chunk_cols,
                )
                a = np.asarray(y_sub.T, dtype=np.float64)
                a = a + reg * np.eye(block_size, dtype=np.float64)
                try:
                    inv = np.linalg.inv(a)
                except np.linalg.LinAlgError:
                    inv = np.linalg.pinv(a, rcond=1e-12)
                if not np.all(np.isfinite(inv)):
                    inv = np.linalg.pinv(a, rcond=1e-12)
                block_inv_list.append(jnp.asarray(inv, dtype=precond_dtype))
                block_slices.append((start, block_size))

        extra_start = int(op.f_size + op.phi1_size)
        extra_size = int(op.extra_size)
        extra_idx_np = np.arange(extra_start, extra_start + extra_size, dtype=np.int32)
        extra_idx_jnp = jnp.asarray(extra_idx_np, dtype=jnp.int32)
        extra_inv_jnp: jnp.ndarray | None = None
        if extra_size > 0:
            chunk_cols = _precond_chunk_cols(total_size, int(extra_idx_np.shape[0]))
            y_sub = _matvec_submatrix(
                op_pc,
                col_idx=extra_idx_np,
                row_idx=extra_idx_np,
                total_size=total_size,
                chunk_cols=chunk_cols,
            )
            ee = np.asarray(y_sub.T, dtype=np.float64)
            ee = ee + reg * np.eye(extra_size, dtype=np.float64)
            try:
                ee_inv = np.linalg.inv(ee)
            except np.linalg.LinAlgError:
                ee_inv = np.linalg.pinv(ee, rcond=1e-12)
            if not np.all(np.isfinite(ee_inv)):
                ee_inv = np.linalg.pinv(ee, rcond=1e-12)
            extra_inv_jnp = jnp.asarray(ee_inv, dtype=precond_dtype)

        cached = _RHSMode1PrecondListCache(
            block_inv_list=tuple(block_inv_list),
            block_slices=tuple(block_slices),
            extra_idx_jnp=extra_idx_jnp,
            extra_inv_jnp=extra_inv_jnp,
        )
        _RHSMODE1_PRECOND_LIST_CACHE[cache_key] = cached

    block_inv_list = cached.block_inv_list
    block_slices = cached.block_slices
    extra_idx_jnp = cached.extra_idx_jnp
    extra_inv_jnp = cached.extra_inv_jnp
    precond_dtype = block_inv_list[0].dtype if block_inv_list else _precond_dtype()

    def _apply_full(r_full: jnp.ndarray) -> jnp.ndarray:
        r_full = jnp.asarray(r_full, dtype=precond_dtype)
        z_full = jnp.asarray(r_full, dtype=precond_dtype)
        for inv, (start, block_size) in zip(block_inv_list, block_slices, strict=True):
            r_loc = r_full[start : start + block_size]
            z_loc = inv @ r_loc
            z_full = z_full.at[start : start + block_size].set(z_loc, unique_indices=True)
        if extra_inv_jnp is not None:
            r_extra = r_full[extra_idx_jnp]
            z_extra = extra_inv_jnp @ r_extra
            z_full = z_full.at[extra_idx_jnp].set(z_extra, unique_indices=True)
        return jnp.asarray(z_full, dtype=jnp.float64)

    apply_full_safe = _safe_preconditioner(_apply_full)

    if reduce_full is None or expand_reduced is None:
        return apply_full_safe

    def _apply_reduced(r_reduced: jnp.ndarray) -> jnp.ndarray:
        z_full = apply_full_safe(expand_reduced(r_reduced))
        return reduce_full(z_full)

    return _apply_reduced


def _rhsmode1_xblock_sparse_lu_default_max(op: object, *, build_jax_factors: bool) -> int:
    """Default exact-LU cap for RHSMode=1 x-block sparse preconditioners."""
    fblock = getattr(op, "fblock", None)
    return _rhs1_xblock_sparse_host_policy.rhs1_xblock_sparse_lu_default_max(
        has_fp=getattr(fblock, "fp", None) is not None,
        has_pas=getattr(fblock, "pas", None) is not None,
        build_jax_factors=bool(build_jax_factors),
    )


def _build_rhsmode1_xblock_tz_sparse_preconditioner(
    *,
    op: V3FullSystemOperator,
    reduce_full: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
    expand_reduced: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
    build_jax_factors: bool,
    preconditioner_species: int,
    preconditioner_xi: int,
    drop_tol: float,
    drop_rel: float,
    ilu_drop_tol: float,
    fill_factor: float,
    force_assembled_host_fp: bool = False,
    emit: Callable[[int, str], None] | None = None,
) -> Callable[[jnp.ndarray], jnp.ndarray]:
    """Sparse per-x preconditioner for large FP RHSMode=1 systems.

    This is a closer analogue to v3's default matrix preconditioner when
    ``preconditioner_x > 0``: retain the full local (theta,zeta,L) coupling
    inside each x-block, but drop inter-x coupling by factorizing each
    per-(species,x) block independently with sparse ILU/LU.
    """
    row_cap_env = os.environ.get("SFINCS_JAX_RHSMODE1_XBLOCK_SPARSE_ROW_NNZ_MAX", "").strip()
    try:
        row_cap = int(row_cap_env) if row_cap_env else 64
    except ValueError:
        row_cap = 64
    row_cap = max(0, int(row_cap))
    n_species = int(op.n_species)
    n_x = int(op.n_x)
    n_l = int(op.n_xi)
    n_theta = int(op.n_theta)
    n_zeta = int(op.n_zeta)
    total_size = int(op.total_size)
    nxi_for_x = np.asarray(op.fblock.collisionless.n_xi_for_x, dtype=np.int32)
    block_size_max = int(n_l * n_theta * n_zeta)
    default_lu_max = _rhsmode1_xblock_sparse_lu_default_max(op, build_jax_factors=build_jax_factors)
    lu_max_env = os.environ.get("SFINCS_JAX_RHSMODE1_XBLOCK_SPARSE_LU_MAX", "").strip()
    try:
        lu_max = int(lu_max_env) if lu_max_env else default_lu_max
    except ValueError:
        lu_max = default_lu_max
    lu_max = max(0, int(lu_max))
    cache_key = (
        *_rhsmode1_precond_cache_key(op, "xblock_tz_sparse"),
        bool(build_jax_factors),
        float(drop_tol),
        float(drop_rel),
        float(ilu_drop_tol),
        float(fill_factor),
        int(row_cap),
        int(lu_max),
        bool(force_assembled_host_fp),
    )

    if build_jax_factors:
        cached = _RHSMODE1_SPARSE_XBLOCK_PRECOND_CACHE.get(cache_key)
    else:
        cached = _RHSMODE1_SPARSE_XBLOCK_HOST_PRECOND_CACHE.get(cache_key)

    if cached is None:
        extra_start = int(op.f_size + op.phi1_size)
        extra_size = int(op.extra_size)
        extra_idx_np = np.arange(extra_start, extra_start + extra_size, dtype=np.int32)
        reg_env = os.environ.get("SFINCS_JAX_RHSMODE1_PRECOND_REG", "").strip()
        reg_val = float(reg_env) if reg_env else 1e-10
        assembled_host_fp = bool(
            (
                bool(force_assembled_host_fp)
                and (not bool(build_jax_factors))
                and int(op.rhs_mode) == 1
                and (not bool(op.include_phi1))
                and op.fblock.fp is not None
                and op.fblock.pas is None
                and _rhsmode1_fp_xblock_species_decoupled_for_host_assembly(
                    op=op,
                    preconditioner_species=preconditioner_species,
                )
                and int(preconditioner_xi) == 1
                and (not bool(op.point_at_x0))
            )
            or _rhsmode1_fp_xblock_assembled_host_allowed(
                op=op,
                preconditioner_species=preconditioner_species,
                preconditioner_xi=preconditioner_xi,
                use_implicit=build_jax_factors,
            )
        )
        assembled_host_cache = _get_rhsmode1_fp_xblock_assembled_host_cache(op=op) if assembled_host_fp else None

        if build_jax_factors:
            perm_r_blocks: list[np.ndarray] = []
            inv_perm_c_blocks: list[np.ndarray] = []
            lower_idx_blocks: list[np.ndarray] = []
            lower_val_blocks: list[np.ndarray] = []
            upper_idx_blocks: list[np.ndarray] = []
            upper_val_blocks: list[np.ndarray] = []
            upper_diag_blocks: list[np.ndarray] = []
            max_lower_global = 0
            max_upper_global = 0

            for s in range(n_species):
                for ix in range(n_x):
                    n_lx = int(nxi_for_x[ix])
                    block_size = int(n_lx * n_theta * n_zeta)
                    start = int((((s * n_x + ix) * n_l) * n_theta) * n_zeta)

                    perm_r_full = np.arange(block_size_max, dtype=np.int32)
                    inv_perm_c_full = np.arange(block_size_max, dtype=np.int32)
                    lower_idx_full = np.zeros((block_size_max, 0), dtype=np.int32)
                    lower_val_full = np.zeros((block_size_max, 0), dtype=np.float64)
                    upper_idx_full = np.zeros((block_size_max, 0), dtype=np.int32)
                    upper_val_full = np.zeros((block_size_max, 0), dtype=np.float64)
                    upper_diag_full = np.ones((block_size_max,), dtype=np.float64)

                    if block_size > 0:
                        block_slice = slice(start, start + block_size)

                        def _mv_block(v_block: jnp.ndarray, *, _block_slice=block_slice) -> jnp.ndarray:
                            x_full = jnp.zeros((total_size,), dtype=v_block.dtype)
                            x_full = x_full.at[_block_slice].set(v_block)
                            y_full = apply_v3_full_system_operator_cached(op, x_full)
                            return y_full[_block_slice]

                        block_cache_key = (cache_key, int(s), int(ix), int(block_size))
                        exact_lu = block_size <= int(lu_max)
                        try:
                            _build_sparse_ilu_from_matvec(
                                matvec=_mv_block,
                                n=int(block_size),
                                dtype=jnp.float64,
                                cache_key=block_cache_key,
                                drop_tol=drop_tol,
                                drop_rel=drop_rel,
                                ilu_drop_tol=ilu_drop_tol,
                                fill_factor=fill_factor,
                                build_dense_factors=False,
                                build_jax_factors=True,
                                build_ilu=True,
                                store_dense=False,
                                factorization="lu" if exact_lu else "ilu",
                                row_nnz_cap=int(row_cap),
                                emit=emit,
                            )
                            fac_cache = _RHSMODE1_SPARSE_ILU_CACHE.get(block_cache_key)
                        except Exception as exc:  # noqa: BLE001
                            fac_cache = None
                            if emit is not None:
                                emit(
                                    1,
                                    "xblock_sparse: factorization failed for block "
                                    f"(species={int(s)} x={int(ix)} size={int(block_size)}) "
                                    f"({type(exc).__name__}: {exc})",
                                )
                        if fac_cache is not None:
                            perm_r = fac_cache.perm_r
                            inv_perm_c = fac_cache.inv_perm_c
                            lower_idx = fac_cache.lower_idx
                            lower_val = fac_cache.lower_val
                            upper_idx = fac_cache.upper_idx
                            upper_val = fac_cache.upper_val
                            upper_diag = fac_cache.upper_diag
                            if (
                                perm_r is not None
                                and inv_perm_c is not None
                                and lower_idx is not None
                                and lower_val is not None
                                and upper_idx is not None
                                and upper_val is not None
                                and upper_diag is not None
                            ):
                                perm_r_np = np.asarray(perm_r, dtype=np.int32)
                                inv_perm_c_np = np.asarray(inv_perm_c, dtype=np.int32)
                                lower_idx_np = np.asarray(lower_idx, dtype=np.int32)
                                lower_val_np = np.asarray(lower_val, dtype=np.float64)
                                upper_idx_np = np.asarray(upper_idx, dtype=np.int32)
                                upper_val_np = np.asarray(upper_val, dtype=np.float64)
                                upper_diag_np = np.asarray(upper_diag, dtype=np.float64)
                                max_lower = int(lower_idx_np.shape[1])
                                max_upper = int(upper_idx_np.shape[1])
                                perm_r_full[:block_size] = perm_r_np
                                inv_perm_c_full[:block_size] = inv_perm_c_np
                                lower_idx_full = -np.ones((block_size_max, max_lower), dtype=np.int32)
                                lower_val_full = np.zeros((block_size_max, max_lower), dtype=np.float64)
                                lower_idx_full[:block_size, :] = lower_idx_np
                                lower_val_full[:block_size, :] = lower_val_np
                                upper_idx_full = -np.ones((block_size_max, max_upper), dtype=np.int32)
                                upper_val_full = np.zeros((block_size_max, max_upper), dtype=np.float64)
                                upper_idx_full[:block_size, :] = upper_idx_np
                                upper_val_full[:block_size, :] = upper_val_np
                                upper_diag_full[:block_size] = upper_diag_np
                            elif emit is not None:
                                emit(
                                    1,
                                    "xblock_sparse: missing JAX factors for block "
                                    f"(species={int(s)} x={int(ix)} size={int(block_size)}); using identity",
                                )

                    perm_r_blocks.append(perm_r_full)
                    inv_perm_c_blocks.append(inv_perm_c_full)
                    lower_idx_blocks.append(lower_idx_full)
                    lower_val_blocks.append(lower_val_full)
                    upper_idx_blocks.append(upper_idx_full)
                    upper_val_blocks.append(upper_val_full)
                    upper_diag_blocks.append(upper_diag_full)
                    max_lower_global = max(max_lower_global, int(lower_idx_full.shape[1]))
                    max_upper_global = max(max_upper_global, int(upper_idx_full.shape[1]))

            for i in range(len(lower_idx_blocks)):
                lower_idx_block = lower_idx_blocks[i]
                lower_val_block = lower_val_blocks[i]
                upper_idx_block = upper_idx_blocks[i]
                upper_val_block = upper_val_blocks[i]
                if int(lower_idx_block.shape[1]) < max_lower_global:
                    pad = int(max_lower_global - int(lower_idx_block.shape[1]))
                    lower_idx_block = np.pad(lower_idx_block, ((0, 0), (0, pad)), constant_values=-1)
                    lower_val_block = np.pad(lower_val_block, ((0, 0), (0, pad)), constant_values=0.0)
                if int(upper_idx_block.shape[1]) < max_upper_global:
                    pad = int(max_upper_global - int(upper_idx_block.shape[1]))
                    upper_idx_block = np.pad(upper_idx_block, ((0, 0), (0, pad)), constant_values=-1)
                    upper_val_block = np.pad(upper_val_block, ((0, 0), (0, pad)), constant_values=0.0)
                lower_idx_blocks[i] = lower_idx_block
                lower_val_blocks[i] = lower_val_block
                upper_idx_blocks[i] = upper_idx_block
                upper_val_blocks[i] = upper_val_block

            perm_r_np = np.stack(perm_r_blocks, axis=0).reshape((n_species, n_x, block_size_max))
            inv_perm_c_np = np.stack(inv_perm_c_blocks, axis=0).reshape((n_species, n_x, block_size_max))
            lower_idx_np = np.stack(lower_idx_blocks, axis=0).reshape(
                (n_species, n_x, block_size_max, max_lower_global)
            )
            lower_val_np = np.stack(lower_val_blocks, axis=0).reshape(
                (n_species, n_x, block_size_max, max_lower_global)
            )
            upper_idx_np = np.stack(upper_idx_blocks, axis=0).reshape(
                (n_species, n_x, block_size_max, max_upper_global)
            )
            upper_val_np = np.stack(upper_val_blocks, axis=0).reshape(
                (n_species, n_x, block_size_max, max_upper_global)
            )
            upper_diag_np = np.stack(upper_diag_blocks, axis=0).reshape((n_species, n_x, block_size_max))

            extra_idx_jnp = jnp.asarray(extra_idx_np, dtype=jnp.int32)
            extra_inv_jnp: jnp.ndarray | None = None
            if extra_size > 0:
                chunk_cols = _precond_chunk_cols(total_size, int(extra_idx_np.shape[0]))
                y_sub = _matvec_submatrix(
                    op,
                    col_idx=extra_idx_np,
                    row_idx=extra_idx_np,
                    total_size=total_size,
                    chunk_cols=chunk_cols,
                )
                ee = np.asarray(y_sub.T, dtype=np.float64)
                ee = ee + np.float64(reg_val) * np.eye(extra_size, dtype=np.float64)
                try:
                    ee_inv = np.linalg.inv(ee)
                except np.linalg.LinAlgError:
                    ee_inv = np.linalg.pinv(ee, rcond=1e-12)
                if not np.all(np.isfinite(ee_inv)):
                    ee_inv = np.linalg.pinv(ee, rcond=1e-12)
                extra_inv_jnp = jnp.asarray(ee_inv, dtype=jnp.float64)

            cached = _RHSMode1SparseXBlockPrecondCache(
                perm_r_sx=jnp.asarray(perm_r_np, dtype=jnp.int32),
                inv_perm_c_sx=jnp.asarray(inv_perm_c_np, dtype=jnp.int32),
                lower_idx_sx=jnp.asarray(lower_idx_np, dtype=jnp.int32),
                lower_val_sx=jnp.asarray(lower_val_np, dtype=jnp.float64),
                upper_idx_sx=jnp.asarray(upper_idx_np, dtype=jnp.int32),
                upper_val_sx=jnp.asarray(upper_val_np, dtype=jnp.float64),
                upper_diag_sx=jnp.asarray(upper_diag_np, dtype=jnp.float64),
                extra_idx_jnp=extra_idx_jnp,
                extra_inv_jnp=extra_inv_jnp,
            )
            _RHSMODE1_SPARSE_XBLOCK_PRECOND_CACHE[cache_key] = cached
        else:
            block_slices: list[tuple[int, int]] = []
            block_factors: list[object | None] = []
            for s in range(n_species):
                for ix in range(n_x):
                    n_lx = int(nxi_for_x[ix])
                    block_size = int(n_lx * n_theta * n_zeta)
                    start = int((((s * n_x + ix) * n_l) * n_theta) * n_zeta)
                    if block_size <= 0:
                        continue
                    block_slice = slice(start, start + block_size)

                    def _mv_block(v_block: jnp.ndarray, *, _block_slice=block_slice) -> jnp.ndarray:
                        x_full = jnp.zeros((total_size,), dtype=v_block.dtype)
                        x_full = x_full.at[_block_slice].set(v_block)
                        y_full = apply_v3_full_system_operator_cached(op, x_full)
                        return y_full[_block_slice]

                    block_cache_key = (cache_key, int(s), int(ix), int(block_size))
                    exact_lu = block_size <= int(lu_max)
                    try:
                        fac_cache = _RHSMODE1_SPARSE_ILU_CACHE.get(block_cache_key)
                        if fac_cache is None or fac_cache.ilu is None:
                            if assembled_host_fp:
                                if emit is not None:
                                    emit(
                                        1,
                                        "xblock_sparse_host: assembling explicit FP x-block "
                                        f"(species={int(s)} x={int(ix)} size={int(block_size)})",
                                    )
                                a_block = _assemble_rhsmode1_fp_xblock_tz_sparse_matrix(
                                    op=op,
                                    species=int(s),
                                    ix=int(ix),
                                    preconditioner_xi=preconditioner_xi,
                                    host_cache=assembled_host_cache,
                                )
                                _factorize_sparse_matrix_csr_host(
                                    a_csr_full=a_block.tocsr(),
                                    cache_key=block_cache_key,
                                    drop_tol=drop_tol,
                                    drop_rel=drop_rel,
                                    ilu_drop_tol=ilu_drop_tol,
                                    fill_factor=fill_factor,
                                    factorization="lu" if exact_lu else "ilu",
                                    emit=emit,
                                )
                            else:
                                _build_sparse_ilu_from_matvec(
                                    matvec=_mv_block,
                                    n=int(block_size),
                                    dtype=jnp.float64,
                                    cache_key=block_cache_key,
                                    drop_tol=drop_tol,
                                    drop_rel=drop_rel,
                                    ilu_drop_tol=ilu_drop_tol,
                                    fill_factor=fill_factor,
                                    build_dense_factors=False,
                                    build_jax_factors=False,
                                    build_ilu=True,
                                    store_dense=False,
                                    factorization="lu" if exact_lu else "ilu",
                                    row_nnz_cap=int(row_cap),
                                    emit=emit,
                                )
                            fac_cache = _RHSMODE1_SPARSE_ILU_CACHE.get(block_cache_key)
                    except Exception as exc:  # noqa: BLE001
                        fac_cache = None
                        if emit is not None:
                            emit(
                                1,
                                "xblock_sparse_host: factorization failed for block "
                                f"(species={int(s)} x={int(ix)} size={int(block_size)}) "
                                f"({type(exc).__name__}: {exc})",
                            )
                    host_factor = None if fac_cache is None else fac_cache.ilu
                    if assembled_host_fp and host_factor is not None:
                        if not _rhsmode1_host_factor_probe_ok(factor=host_factor, block_size=int(block_size)):
                            if emit is not None:
                                emit(
                                    1,
                                    "xblock_sparse_host: rejecting unstable block factor "
                                    f"(species={int(s)} x={int(ix)} size={int(block_size)})",
                                )
                            host_factor = None
                    block_slices.append((start, block_size))
                    block_factors.append(host_factor)

            extra_inv_np: np.ndarray | None = None
            if extra_size > 0:
                chunk_cols = _precond_chunk_cols(total_size, int(extra_idx_np.shape[0]))
                y_sub = _matvec_submatrix(
                    op,
                    col_idx=extra_idx_np,
                    row_idx=extra_idx_np,
                    total_size=total_size,
                    chunk_cols=chunk_cols,
                )
                ee = np.asarray(y_sub.T, dtype=np.float64)
                ee = ee + np.float64(reg_val) * np.eye(extra_size, dtype=np.float64)
                try:
                    extra_inv_np = np.linalg.inv(ee)
                except np.linalg.LinAlgError:
                    extra_inv_np = np.linalg.pinv(ee, rcond=1e-12)
                if not np.all(np.isfinite(extra_inv_np)):
                    extra_inv_np = np.linalg.pinv(ee, rcond=1e-12)

            cached = _RHSMode1SparseXBlockHostPrecondCache(
                block_slices=tuple(block_slices),
                block_factors=tuple(block_factors),
                extra_idx_np=extra_idx_np,
                extra_inv_np=extra_inv_np,
            )
            _RHSMODE1_SPARSE_XBLOCK_HOST_PRECOND_CACHE[cache_key] = cached

    if build_jax_factors:
        perm_r_sx = cached.perm_r_sx
        inv_perm_c_sx = cached.inv_perm_c_sx
        lower_idx_sx = cached.lower_idx_sx
        lower_val_sx = cached.lower_val_sx
        upper_idx_sx = cached.upper_idx_sx
        upper_val_sx = cached.upper_val_sx
        upper_diag_sx = cached.upper_diag_sx
        extra_idx_jnp = cached.extra_idx_jnp
        extra_inv_jnp = cached.extra_inv_jnp

        f_size = int(op.f_size)

        def _solve_block(
            r: jnp.ndarray,
            perm_r: jnp.ndarray,
            inv_perm_c: jnp.ndarray,
            lower_idx: jnp.ndarray,
            lower_val: jnp.ndarray,
            upper_idx: jnp.ndarray,
            upper_val: jnp.ndarray,
            upper_diag: jnp.ndarray,
        ) -> jnp.ndarray:
            r_perm = r[perm_r]
            y = _triangular_solve_lower_padded(lower_idx=lower_idx, lower_val=lower_val, b=r_perm)
            z = _triangular_solve_upper_padded(
                upper_idx=upper_idx,
                upper_val=upper_val,
                upper_diag=upper_diag,
                b=y,
            )
            return z[inv_perm_c]

        _solve_over_x = jax.vmap(
            _solve_block,
            in_axes=(0, 0, 0, 0, 0, 0, 0, 0),
            out_axes=0,
        )
        _solve_over_sx = jax.vmap(
            _solve_over_x,
            in_axes=(0, 0, 0, 0, 0, 0, 0, 0),
            out_axes=0,
        )

        def _apply_full(r_full: jnp.ndarray) -> jnp.ndarray:
            r_full = jnp.asarray(r_full, dtype=jnp.float64)
            r_f = r_full[:f_size].reshape((n_species, n_x, block_size_max))
            z_f = _solve_over_sx(
                r_f,
                perm_r_sx,
                inv_perm_c_sx,
                lower_idx_sx,
                lower_val_sx,
                upper_idx_sx,
                upper_val_sx,
                upper_diag_sx,
            )
            z_full = jnp.concatenate([z_f.reshape((-1,)), r_full[f_size:]], axis=0)
            if extra_inv_jnp is not None:
                r_extra = r_full[extra_idx_jnp]
                z_extra = extra_inv_jnp @ r_extra
                z_full = z_full.at[extra_idx_jnp].set(z_extra, unique_indices=True)
            return jnp.asarray(z_full, dtype=jnp.float64)
    else:
        def _apply_full(r_full: jnp.ndarray) -> jnp.ndarray:
            r_np = np.asarray(r_full, dtype=np.float64).reshape((-1,))
            z_np = np.array(r_np, copy=True)
            for (start, block_size), fac in zip(cached.block_slices, cached.block_factors, strict=True):
                if fac is None or block_size <= 0:
                    continue
                sl = slice(int(start), int(start + block_size))
                z_np[sl] = np.asarray(fac.solve(r_np[sl]), dtype=np.float64)
            if cached.extra_inv_np is not None and cached.extra_idx_np.size:
                z_np[cached.extra_idx_np] = cached.extra_inv_np @ r_np[cached.extra_idx_np]
            return jnp.asarray(z_np, dtype=jnp.float64)

    apply_full_safe = _safe_preconditioner(_apply_full)

    if reduce_full is None or expand_reduced is None:
        return apply_full_safe

    def _apply_reduced(r_reduced: jnp.ndarray) -> jnp.ndarray:
        z_full = apply_full_safe(expand_reduced(r_reduced))
        return reduce_full(z_full)

    return _apply_reduced


def _build_rhsmode1_sxblock_tz_sparse_host_preconditioner(
    *,
    op: V3FullSystemOperator,
    reduce_full: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
    expand_reduced: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
    drop_tol: float,
    drop_rel: float,
    ilu_drop_tol: float,
    fill_factor: float,
    emit: Callable[[int, str], None] | None = None,
) -> Callable[[jnp.ndarray], jnp.ndarray]:
    """Explicit-only sparse per-L species/x rescue preconditioner for large FP systems."""
    cache_key = (
        *_rhsmode1_precond_cache_key(op, "sxblock_tz_sparse_host"),
        float(drop_tol),
        float(drop_rel),
        float(ilu_drop_tol),
        float(fill_factor),
    )
    cached = _RHSMODE1_SPARSE_SXBLOCK_HOST_PRECOND_CACHE.get(cache_key)
    n_species = int(op.n_species)
    n_x = int(op.n_x)
    n_l = int(op.n_xi)
    n_theta = int(op.n_theta)
    n_zeta = int(op.n_zeta)
    total_size = int(op.total_size)
    nxi_for_x = np.asarray(op.fblock.collisionless.n_xi_for_x, dtype=np.int32)
    lu_max_env = os.environ.get("SFINCS_JAX_RHSMODE1_SXBLOCK_SPARSE_LU_MAX", "").strip()
    try:
        lu_max = int(lu_max_env) if lu_max_env else 4000
    except ValueError:
        lu_max = 4000
    lu_max = max(0, int(lu_max))

    if cached is None:
        import scipy.sparse as sp  # noqa: PLC0415

        extra_start = int(op.f_size + op.phi1_size)
        extra_size = int(op.extra_size)
        extra_idx_np = np.arange(extra_start, extra_start + extra_size, dtype=np.int32)
        reg_env = os.environ.get("SFINCS_JAX_RHSMODE1_PRECOND_REG", "").strip()
        reg_val = float(reg_env) if reg_env else 1e-10
        struct_tol = _sparse_structural_tol()
        block_indices: list[np.ndarray] = []
        block_factors: list[object | None] = []
        for il in range(n_l):
            active_x = np.where(nxi_for_x > il)[0]
            if active_x.size == 0:
                continue
            idx: list[int] = []
            for s in range(n_species):
                for ix in active_x:
                    base = int((((s * n_x + int(ix)) * n_l + il) * n_theta) * n_zeta)
                    for it in range(n_theta):
                        for iz in range(n_zeta):
                            idx.append(base + it * n_zeta + iz)
            rep_idx_np = np.asarray(idx, dtype=np.int32)
            block_cache_key = (cache_key, int(il), int(rep_idx_np.size))
            exact_lu = int(rep_idx_np.size) <= int(lu_max)
            try:
                if emit is not None:
                    emit(
                        1,
                        "sxblock_sparse_host: assembling per-L species/x block "
                        f"(L={int(il)} size={int(rep_idx_np.size)})",
                    )
                chunk_cols = _precond_chunk_cols(total_size, int(rep_idx_np.shape[0]))
                y_sub = _matvec_submatrix(
                    op,
                    col_idx=rep_idx_np,
                    row_idx=rep_idx_np,
                    total_size=total_size,
                    chunk_cols=chunk_cols,
                )
                a_block = np.asarray(y_sub.T, dtype=np.float64)
                if struct_tol > 0.0 and a_block.size:
                    a_block[np.abs(a_block) <= struct_tol] = 0.0
                a_csr = sp.csr_matrix(a_block)
                a_csr.eliminate_zeros()
                _factorize_sparse_matrix_csr_host(
                    a_csr_full=a_csr,
                    cache_key=block_cache_key,
                    drop_tol=drop_tol,
                    drop_rel=drop_rel,
                    ilu_drop_tol=ilu_drop_tol,
                    fill_factor=fill_factor,
                    factorization="lu" if exact_lu else "ilu",
                    emit=emit,
                )
                fac_cache = _RHSMODE1_SPARSE_ILU_CACHE.get(block_cache_key)
            except Exception as exc:  # noqa: BLE001
                fac_cache = None
                if emit is not None:
                    emit(
                        1,
                        "sxblock_sparse_host: factorization failed for block "
                        f"(L={int(il)} size={int(rep_idx_np.size)}) "
                        f"({type(exc).__name__}: {exc})",
                    )
            host_factor = None if fac_cache is None else fac_cache.ilu
            if host_factor is not None and (
                not _rhsmode1_host_factor_probe_ok(factor=host_factor, block_size=int(rep_idx_np.size))
            ):
                if emit is not None:
                    emit(
                        1,
                        "sxblock_sparse_host: rejecting unstable block factor "
                        f"(L={int(il)} size={int(rep_idx_np.size)})",
                    )
                host_factor = None
            block_indices.append(rep_idx_np)
            block_factors.append(host_factor)

        extra_inv_np: np.ndarray | None = None
        if extra_size > 0:
            chunk_cols = _precond_chunk_cols(total_size, int(extra_idx_np.shape[0]))
            y_sub = _matvec_submatrix(
                op,
                col_idx=extra_idx_np,
                row_idx=extra_idx_np,
                total_size=total_size,
                chunk_cols=chunk_cols,
            )
            ee = np.asarray(y_sub.T, dtype=np.float64)
            ee = ee + np.float64(reg_val) * np.eye(extra_size, dtype=np.float64)
            try:
                extra_inv_np = np.linalg.inv(ee)
            except np.linalg.LinAlgError:
                extra_inv_np = np.linalg.pinv(ee, rcond=1e-12)
            if not np.all(np.isfinite(extra_inv_np)):
                extra_inv_np = np.linalg.pinv(ee, rcond=1e-12)

        cached = _RHSMode1SparseSXBlockHostPrecondCache(
            block_indices=tuple(block_indices),
            block_factors=tuple(block_factors),
            extra_idx_np=extra_idx_np,
            extra_inv_np=extra_inv_np,
        )
        _RHSMODE1_SPARSE_SXBLOCK_HOST_PRECOND_CACHE[cache_key] = cached

    def _apply_full(r_full: jnp.ndarray) -> jnp.ndarray:
        r_np = np.asarray(r_full, dtype=np.float64).reshape((-1,))
        z_np = np.array(r_np, copy=True)
        for idx_np, fac in zip(cached.block_indices, cached.block_factors, strict=True):
            if fac is None or idx_np.size == 0:
                continue
            z_np[idx_np] = np.asarray(fac.solve(r_np[idx_np]), dtype=np.float64)
        if cached.extra_inv_np is not None and cached.extra_idx_np.size:
            z_np[cached.extra_idx_np] = cached.extra_inv_np @ r_np[cached.extra_idx_np]
        return jnp.asarray(z_np, dtype=jnp.float64)

    apply_full_safe = _safe_preconditioner(_apply_full)

    if reduce_full is None or expand_reduced is None:
        return apply_full_safe

    def _apply_reduced(r_reduced: jnp.ndarray) -> jnp.ndarray:
        z_full = apply_full_safe(expand_reduced(r_reduced))
        return reduce_full(z_full)

    return _apply_reduced


def _compute_rhsmode1_sxblock_tz_sparse_host_seed(
    *,
    op: V3FullSystemOperator,
    rhs_reduced: jnp.ndarray,
    reduce_full: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
    expand_reduced: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
    drop_tol: float,
    drop_rel: float,
    ilu_drop_tol: float,
    fill_factor: float,
    emit: Callable[[int, str], None] | None = None,
) -> jnp.ndarray:
    """Build an explicit sxblock_tz seed without retaining all per-L factors."""
    import scipy.sparse as sp  # noqa: PLC0415

    rhs_full = expand_reduced(rhs_reduced) if expand_reduced is not None else rhs_reduced
    rhs_full_np = np.asarray(rhs_full, dtype=np.float64).reshape((-1,))
    seed_full_np = np.array(rhs_full_np, copy=True)

    n_species = int(op.n_species)
    n_x = int(op.n_x)
    n_l = int(op.n_xi)
    n_theta = int(op.n_theta)
    n_zeta = int(op.n_zeta)
    total_size = int(op.total_size)
    nxi_for_x = np.asarray(op.fblock.collisionless.n_xi_for_x, dtype=np.int32)
    lu_max_env = os.environ.get("SFINCS_JAX_RHSMODE1_SXBLOCK_SPARSE_LU_MAX", "").strip()
    chunk_cols_env = os.environ.get("SFINCS_JAX_RHSMODE1_SXBLOCK_CHUNK_COLS", "").strip()
    try:
        lu_max = int(lu_max_env) if lu_max_env else 4000
    except ValueError:
        lu_max = 4000
    lu_max = max(0, int(lu_max))
    try:
        chunk_cols_cap = int(chunk_cols_env) if chunk_cols_env else 32
    except ValueError:
        chunk_cols_cap = 32
    chunk_cols_cap = max(1, int(chunk_cols_cap))
    struct_tol = _sparse_structural_tol()

    for il in range(n_l):
        active_x = np.where(nxi_for_x > il)[0]
        if active_x.size == 0:
            continue
        idx: list[int] = []
        for s in range(n_species):
            for ix in active_x:
                base = int((((s * n_x + int(ix)) * n_l + il) * n_theta) * n_zeta)
                for it in range(n_theta):
                    for iz in range(n_zeta):
                        idx.append(base + it * n_zeta + iz)
        rep_idx_np = np.asarray(idx, dtype=np.int32)
        exact_lu = int(rep_idx_np.size) <= int(lu_max)
        block_cache_key = (
            *_rhsmode1_precond_cache_key(op, "sxblock_tz_sparse_seed"),
            int(il),
            int(rep_idx_np.size),
            float(drop_tol),
            float(drop_rel),
            float(ilu_drop_tol),
            float(fill_factor),
            int(exact_lu),
        )
        try:
            if emit is not None:
                emit(
                    1,
                    "sxblock_sparse_seed: assembling per-L species/x block "
                    f"(L={int(il)} size={int(rep_idx_np.size)})",
                )
            chunk_cols = min(_precond_chunk_cols(total_size, int(rep_idx_np.shape[0])), int(chunk_cols_cap))
            y_sub = _matvec_submatrix(
                op,
                col_idx=rep_idx_np,
                row_idx=rep_idx_np,
                total_size=total_size,
                chunk_cols=chunk_cols,
            )
            a_block = np.asarray(y_sub.T, dtype=np.float64)
            if struct_tol > 0.0 and a_block.size:
                a_block[np.abs(a_block) <= struct_tol] = 0.0
            a_csr = sp.csr_matrix(a_block)
            a_csr.eliminate_zeros()
            _factorize_sparse_matrix_csr_host(
                a_csr_full=a_csr,
                cache_key=block_cache_key,
                drop_tol=drop_tol,
                drop_rel=drop_rel,
                ilu_drop_tol=ilu_drop_tol,
                fill_factor=fill_factor,
                factorization="lu" if exact_lu else "ilu",
                emit=emit,
            )
            fac_cache = _RHSMODE1_SPARSE_ILU_CACHE.pop(block_cache_key, None)
            fac = None if fac_cache is None else fac_cache.ilu
            if fac is None:
                continue
            sol = np.asarray(fac.solve(rhs_full_np[rep_idx_np]), dtype=np.float64)
            if np.all(np.isfinite(sol)):
                seed_full_np[rep_idx_np] = sol
        except Exception as exc:  # noqa: BLE001
            if emit is not None:
                emit(
                    1,
                    "sxblock_sparse_seed: block solve failed "
                    f"(L={int(il)} size={int(rep_idx_np.size)}) "
                    f"({type(exc).__name__}: {exc})",
                )

    extra_start = int(op.f_size + op.phi1_size)
    extra_size = int(op.extra_size)
    if extra_size > 0:
        extra_idx_np = np.arange(extra_start, extra_start + extra_size, dtype=np.int32)
        reg_env = os.environ.get("SFINCS_JAX_RHSMODE1_PRECOND_REG", "").strip()
        reg_val = float(reg_env) if reg_env else 1e-10
        chunk_cols = _precond_chunk_cols(total_size, int(extra_idx_np.shape[0]))
        y_sub = _matvec_submatrix(
            op,
            col_idx=extra_idx_np,
            row_idx=extra_idx_np,
            total_size=total_size,
            chunk_cols=chunk_cols,
        )
        ee = np.asarray(y_sub.T, dtype=np.float64)
        ee = ee + np.float64(reg_val) * np.eye(extra_size, dtype=np.float64)
        try:
            extra_inv_np = np.linalg.inv(ee)
        except np.linalg.LinAlgError:
            extra_inv_np = np.linalg.pinv(ee, rcond=1e-12)
        if not np.all(np.isfinite(extra_inv_np)):
            extra_inv_np = np.linalg.pinv(ee, rcond=1e-12)
        seed_full_np[extra_idx_np] = extra_inv_np @ rhs_full_np[extra_idx_np]

    seed_full = jnp.asarray(seed_full_np, dtype=jnp.float64)
    return reduce_full(seed_full) if reduce_full is not None else seed_full


def _build_rhsmode1_sxblock_tz_preconditioner(
    *,
    op: V3FullSystemOperator,
    reduce_full: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
    expand_reduced: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
) -> Callable[[jnp.ndarray], jnp.ndarray]:
    """Build a RHSMode=1 preconditioner with species/x blocks over (theta,zeta) per L."""
    cache_key = _rhsmode1_precond_cache_key(op, "sxblock_tz")
    cached = _RHSMODE1_PRECOND_IDX_CACHE.get(cache_key)
    if cached is None:
        n_s = int(op.n_species)
        n_x = int(op.n_x)
        n_l = int(op.n_xi)
        n_t = int(op.n_theta)
        n_z = int(op.n_zeta)
        total = int(op.total_size)

        nxi_for_x = np.asarray(op.fblock.collisionless.n_xi_for_x, dtype=np.int32)
        max_block_size = 0
        for l in range(n_l):
            active_x = np.where(nxi_for_x > l)[0]
            if active_x.size:
                max_block_size = max(max_block_size, int(active_x.size) * n_s * n_t * n_z)
        precond_dtype = _precond_dtype(max_block_size * max_block_size)

        reg_env = os.environ.get("SFINCS_JAX_RHSMODE1_PRECOND_REG", "").strip()
        reg_val = float(reg_env) if reg_env else 1e-10
        reg = np.float64(reg_val)

        block_inv_list: list[jnp.ndarray] = []
        block_idx_list: list[jnp.ndarray] = []
        for l in range(n_l):
            active_x = np.where(nxi_for_x > l)[0]
            if active_x.size == 0:
                continue
            idx: list[int] = []
            for s in range(n_s):
                for ix in active_x:
                    base = int((((s * n_x + int(ix)) * n_l + l) * n_t) * n_z)
                    for it in range(n_t):
                        for iz in range(n_z):
                            idx.append(base + it * n_z + iz)
            rep_idx = np.asarray(idx, dtype=np.int32)
            chunk_cols = _precond_chunk_cols(total, int(rep_idx.shape[0]))
            y_sub = _matvec_submatrix(
                op,
                col_idx=rep_idx,
                row_idx=rep_idx,
                total_size=total,
                chunk_cols=chunk_cols,
            )
            a = np.asarray(y_sub.T, dtype=np.float64)
            a = a + reg * np.eye(int(rep_idx.shape[0]), dtype=np.float64)
            try:
                inv = np.linalg.inv(a)
            except np.linalg.LinAlgError:
                inv = np.linalg.pinv(a, rcond=1e-12)
            if not np.all(np.isfinite(inv)):
                inv = np.linalg.pinv(a, rcond=1e-12)
            block_inv_list.append(jnp.asarray(inv, dtype=precond_dtype))
            block_idx_list.append(jnp.asarray(rep_idx, dtype=jnp.int32))

        extra_start = int(op.f_size + op.phi1_size)
        extra_size = int(op.extra_size)
        extra_idx_np = np.arange(extra_start, extra_start + extra_size, dtype=np.int32)
        extra_idx_jnp = jnp.asarray(extra_idx_np, dtype=jnp.int32)
        extra_inv_jnp: jnp.ndarray | None = None
        if extra_size > 0:
            chunk_cols = _precond_chunk_cols(total, int(extra_idx_np.shape[0]))
            y_sub = _matvec_submatrix(
                op,
                col_idx=extra_idx_np,
                row_idx=extra_idx_np,
                total_size=total,
                chunk_cols=chunk_cols,
            )
            ee = np.asarray(y_sub.T, dtype=np.float64)
            ee = ee + reg * np.eye(extra_size, dtype=np.float64)
            try:
                ee_inv = np.linalg.inv(ee)
            except np.linalg.LinAlgError:
                ee_inv = np.linalg.pinv(ee, rcond=1e-12)
            if not np.all(np.isfinite(ee_inv)):
                ee_inv = np.linalg.pinv(ee, rcond=1e-12)
            extra_inv_jnp = jnp.asarray(ee_inv, dtype=precond_dtype)

        cached = _RHSMode1PrecondIdxCache(
            block_inv_list=tuple(block_inv_list),
            block_idx_list=tuple(block_idx_list),
            extra_idx_jnp=extra_idx_jnp,
            extra_inv_jnp=extra_inv_jnp,
        )
        _RHSMODE1_PRECOND_IDX_CACHE[cache_key] = cached

    block_inv_list = cached.block_inv_list
    block_idx_list = cached.block_idx_list
    extra_idx_jnp = cached.extra_idx_jnp
    extra_inv_jnp = cached.extra_inv_jnp
    precond_dtype = block_inv_list[0].dtype if block_inv_list else _precond_dtype()

    def _apply_full(r_full: jnp.ndarray) -> jnp.ndarray:
        r_full = jnp.asarray(r_full, dtype=precond_dtype)
        z_full = jnp.zeros_like(r_full)
        for inv, idx in zip(block_inv_list, block_idx_list, strict=True):
            r_loc = r_full[idx]
            z_loc = inv @ r_loc
            z_full = z_full.at[idx].set(z_loc, unique_indices=True)
        if extra_inv_jnp is not None:
            r_extra = r_full[extra_idx_jnp]
            z_extra = extra_inv_jnp @ r_extra
            z_full = z_full.at[extra_idx_jnp].set(z_extra, unique_indices=True)
        return jnp.asarray(z_full, dtype=jnp.float64)

    if reduce_full is None or expand_reduced is None:
        return _apply_full

    def _apply_reduced(r_reduced: jnp.ndarray) -> jnp.ndarray:
        z_full = _apply_full(expand_reduced(r_reduced))
        return reduce_full(z_full)

    return _apply_reduced


def _build_rhsmode1_pas_xblock_ilu_preconditioner(
    *,
    op: V3FullSystemOperator,
    reduce_full: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
    expand_reduced: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
) -> Callable[[jnp.ndarray], jnp.ndarray]:
    """Sparse block-Jacobi ILU preconditioner for PAS-like RHSMode=1 operators.

    This preconditioner targets PAS DKES / PAS collisionless runs that are *dense* in the
    existing (theta,zeta,L) block inverses, making preconditioner build/application very
    expensive.

    We assemble a sparse approximation to the per-(species,x) (L,theta,zeta) block matrix
    using the same stencil-like operator structure used in the matrix-free apply:
    - collisionless streaming+mirror (ΔL=±1, spatial derivatives)
    - ExB drifts (spatial derivatives, diagonal in L)
    - pitch-angle scattering collisions (diagonal in L and in theta/zeta)

    Then we compute an ILU factorization with SciPy (`spilu`), and convert the L/U factors
    to a padded row format so the apply path is pure JAX (triangular solves) and can run
    inside JITted GMRES iterations.

    Notes
    -----
    - The ILU factorization is *not* differentiated through; gradients for solves come from
      the implicit-diff VJP of the linear solve, not backpropagating through GMRES.
    - This is intended for PAS-only (no FP) operators. For FP, the x-coupling makes a
      per-x block ILU far less effective.
    """
    if op.fblock.pas is None or op.fblock.fp is not None:
        # Not applicable: fall back to existing defaults.
        return _build_rhsmode1_pas_hybrid_preconditioner(
            op=op, reduce_full=reduce_full, expand_reduced=expand_reduced
        )

    try:
        import scipy.sparse as sp  # noqa: PLC0415
        from scipy.sparse.linalg import spilu, splu  # noqa: PLC0415
    except Exception:
        # SciPy missing: fall back to existing defaults.
        return _build_rhsmode1_pas_hybrid_preconditioner(
            op=op, reduce_full=reduce_full, expand_reduced=expand_reduced
        )

    # Detect the DKES-trajectory branch (strong ExB drift). These PAS systems are often
    # much stiffer / less diagonally-dominant than tokamak-like cases, and the default
    # ILU drop settings can be too aggressive, leading to slow or stalled Krylov solves.
    exb_theta = op.fblock.exb_theta
    exb_zeta = op.fblock.exb_zeta
    use_dkes_exb = bool(getattr(exb_theta, "use_dkes_exb_drift", False)) or bool(
        getattr(exb_zeta, "use_dkes_exb_drift", False)
    )

    # ILU parameters (PETSc-like PCILU defaults). Keep these conservative to
    # avoid unstable factors on ill-conditioned blocks. In particular, we cap
    # the stored nnz-per-row for L/U factors so the JAX-side padded-row format
    # does not explode memory usage on hard PAS blocks.
    ilu_drop_tol_env = os.environ.get("SFINCS_JAX_RHSMODE1_PAS_ILU_DROP_TOL", "").strip()
    ilu_fill_env = os.environ.get("SFINCS_JAX_RHSMODE1_PAS_ILU_FILL_FACTOR", "").strip()
    row_nnz_env = os.environ.get("SFINCS_JAX_RHSMODE1_PAS_ILU_ROW_NNZ_MAX", "").strip()
    reg_env = os.environ.get("SFINCS_JAX_RHSMODE1_PAS_ILU_REG", "").strip()
    try:
        # For DKES-like PAS cases, default to a stronger (less dropping) ILU since the
        # operator can be poorly conditioned.
        default_drop = 1e-4 if use_dkes_exb else 1e-3
        ilu_drop_tol = float(ilu_drop_tol_env) if ilu_drop_tol_env else default_drop
    except ValueError:
        ilu_drop_tol = 1e-4 if use_dkes_exb else 1e-3
    try:
        default_fill = 10.0 if use_dkes_exb else 5.0
        ilu_fill_factor = float(ilu_fill_env) if ilu_fill_env else default_fill
    except ValueError:
        ilu_fill_factor = 10.0 if use_dkes_exb else 5.0
    try:
        row_nnz_max = int(row_nnz_env) if row_nnz_env else 64
    except ValueError:
        row_nnz_max = 64
    row_nnz_max = max(0, int(row_nnz_max))
    try:
        reg = float(reg_env) if reg_env else 1e-12
    except ValueError:
        reg = 1e-12
    reg = float(max(reg, 0.0))

    # Cache key: include the physics pieces that affect the assembled sparse block.
    # For small per-x blocks, an exact sparse LU can be both robust and faster overall
    # than a weak ILU (fewer Krylov iterations). We only enable this for small blocks
    # to avoid dense factors in the padded-row JAX format.
    lu_max_env = os.environ.get("SFINCS_JAX_RHSMODE1_PAS_LU_MAX", "").strip()
    try:
        # For DKES-like PAS systems, the sparse blocks can be much less diagonally-dominant.
        # Default to a larger LU cutoff there for robustness. For non-DKES PAS systems,
        # prefer ILU for medium-sized blocks to reduce factorization time and memory.
        default_lu_max = 5000 if use_dkes_exb else 1000
        lu_max = int(lu_max_env) if lu_max_env else default_lu_max
    except ValueError:
        lu_max = 5000 if use_dkes_exb else 1000
    lu_max = max(0, int(lu_max))
    # Row cap for *exact LU* factors. Exact sparse LU can have substantially more fill than
    # ILU; we allow a higher cap for LU factors (to keep the preconditioner strong) but
    # still cap aggressively to avoid allocating dense padded-row arrays.
    lu_full_env = os.environ.get("SFINCS_JAX_RHSMODE1_PAS_LU_ROW_NNZ_MAX", "").strip()
    try:
        # Default to a lower LU row cap than earlier revisions to reduce peak RSS.
        # If LU is needed for robustness in a particularly stiff DKES case, this can
        # be increased via env var without touching code.
        lu_full_row_nnz_max = int(lu_full_env) if lu_full_env else 256
    except ValueError:
        lu_full_row_nnz_max = 256
    lu_full_row_nnz_max = max(0, int(lu_full_row_nnz_max))

    colless = op.fblock.collisionless
    pas = op.fblock.pas

    cache_key = (
        *_rhsmode1_precond_cache_key(op, "pas_xblock_ilu"),
        float(op.fblock.identity_shift),
        float(pas.nu_n),
        float(pas.krook),
        _hash_array(pas.nu_d_hat),
        _hash_array(colless.ddtheta),
        _hash_array(colless.ddzeta),
        _hash_array(colless.b_hat_sup_theta),
        _hash_array(colless.b_hat_sup_zeta),
        _hash_array(colless.db_hat_dtheta),
        _hash_array(colless.db_hat_dzeta),
        float(ilu_drop_tol),
        float(ilu_fill_factor),
        int(row_nnz_max),
        float(reg),
        int(lu_max),
        int(lu_full_row_nnz_max),
        bool(exb_theta is not None),
        bool(exb_zeta is not None),
        bool(getattr(exb_theta, "use_dkes_exb_drift", False)) if exb_theta is not None else False,
        bool(getattr(exb_zeta, "use_dkes_exb_drift", False)) if exb_zeta is not None else False,
    )
    cached = _RHSMODE1_PRECOND_ILU_CACHE.get(cache_key)
    if cached is None:
        n_species = int(op.n_species)
        n_x = int(op.n_x)
        n_l = int(op.n_xi)
        n_theta = int(op.n_theta)
        n_zeta = int(op.n_zeta)
        total_size = int(op.total_size)
        nxi_for_x = np.asarray(colless.n_xi_for_x, dtype=np.int32)

        # Build sparse derivative matrices on the (theta,zeta) grid. (zeta is fastest.)
        ddtheta = np.asarray(colless.ddtheta, dtype=np.float64)
        ddzeta = np.asarray(colless.ddzeta, dtype=np.float64)
        ddtheta_sp = sp.csr_matrix(ddtheta)
        ddzeta_sp = sp.csr_matrix(ddzeta)
        i_theta = sp.eye(n_theta, format="csr", dtype=np.float64)
        i_zeta = sp.eye(n_zeta, format="csr", dtype=np.float64)
        dtheta_tz = sp.kron(ddtheta_sp, i_zeta, format="csr")
        dzeta_tz = sp.kron(i_theta, ddzeta_sp, format="csr")
        n_tz = int(n_theta * n_zeta)
        i_tz = sp.eye(n_tz, format="csr", dtype=np.float64)

        # Precompute ExB drift diagonal-in-L spatial operator (shared across species/x).
        exb_op_tz: sp.csr_matrix | None = None
        if exb_theta is not None:
            exb_theta_np = exb_theta
            alpha = float(np.asarray(exb_theta_np.alpha, dtype=np.float64).reshape(()))
            delta = float(np.asarray(exb_theta_np.delta, dtype=np.float64).reshape(()))
            dphi = float(np.asarray(exb_theta_np.dphi_hat_dpsi_hat, dtype=np.float64).reshape(()))
            if getattr(exb_theta_np, "use_dkes_exb_drift", False):
                denom = float(np.asarray(exb_theta_np.fsab_hat2, dtype=np.float64).reshape(()))
                coef = np.asarray(exb_theta_np.d_hat * exb_theta_np.b_hat_sub_zeta, dtype=np.float64) / denom
            else:
                b2 = np.asarray(exb_theta_np.b_hat, dtype=np.float64) ** 2
                coef = np.asarray(exb_theta_np.d_hat * exb_theta_np.b_hat_sub_zeta, dtype=np.float64) / b2
            factor = alpha * delta * 0.5 * dphi
            coef_flat = (factor * coef).reshape((-1,))
            exb_op_tz = sp.diags(coef_flat, 0, format="csr") @ dtheta_tz
        if exb_zeta is not None:
            exb_zeta_np = exb_zeta
            alpha = float(np.asarray(exb_zeta_np.alpha, dtype=np.float64).reshape(()))
            delta = float(np.asarray(exb_zeta_np.delta, dtype=np.float64).reshape(()))
            dphi = float(np.asarray(exb_zeta_np.dphi_hat_dpsi_hat, dtype=np.float64).reshape(()))
            if getattr(exb_zeta_np, "use_dkes_exb_drift", False):
                denom = float(np.asarray(exb_zeta_np.fsab_hat2, dtype=np.float64).reshape(()))
                coef = np.asarray(exb_zeta_np.d_hat * exb_zeta_np.b_hat_sub_theta, dtype=np.float64) / denom
            else:
                b2 = np.asarray(exb_zeta_np.b_hat, dtype=np.float64) ** 2
                coef = np.asarray(exb_zeta_np.d_hat * exb_zeta_np.b_hat_sub_theta, dtype=np.float64) / b2
            factor = -alpha * delta * 0.5 * dphi
            coef_flat = (factor * coef).reshape((-1,))
            term = sp.diags(coef_flat, 0, format="csr") @ dzeta_tz
            exb_op_tz = term if exb_op_tz is None else (exb_op_tz + term)

        # Geometry pieces for collisionless streaming/mirror.
        b_hat = np.asarray(colless.b_hat, dtype=np.float64)
        v_theta = np.asarray(colless.b_hat_sup_theta, dtype=np.float64) / b_hat
        v_zeta = np.asarray(colless.b_hat_sup_zeta, dtype=np.float64) / b_hat
        mirror_geom = (
            np.asarray(colless.b_hat_sup_theta, dtype=np.float64) * np.asarray(colless.db_hat_dtheta, dtype=np.float64)
            + np.asarray(colless.b_hat_sup_zeta, dtype=np.float64) * np.asarray(colless.db_hat_dzeta, dtype=np.float64)
        )
        mirror_geom = np.asarray(mirror_geom, dtype=np.float64)

        t_hat = np.asarray(op.t_hat, dtype=np.float64).reshape((n_species,))
        m_hat = np.asarray(op.m_hat, dtype=np.float64).reshape((n_species,))
        x_arr = np.asarray(colless.x, dtype=np.float64).reshape((n_x,))
        pas_coef = np.asarray(pas.coef, dtype=np.float64)  # (S,X,Lmax)
        identity_shift = float(np.asarray(op.fblock.identity_shift, dtype=np.float64).reshape(()))

        # Precompute per-species spatial operators.
        stream_op_by_s: list[sp.csr_matrix] = []
        mirror_diag_by_s: list[sp.csr_matrix] = []
        sqrt_t_over_m = np.sqrt(t_hat / m_hat)  # (S,)
        for s in range(n_species):
            v_theta_s_flat = (sqrt_t_over_m[s] * v_theta).reshape((-1,))
            v_zeta_s_flat = (sqrt_t_over_m[s] * v_zeta).reshape((-1,))
            stream = sp.diags(v_theta_s_flat, 0, format="csr") @ dtheta_tz
            stream = stream + (sp.diags(v_zeta_s_flat, 0, format="csr") @ dzeta_tz)
            stream_op_by_s.append(stream)

            mirror_factor_flat = (-sqrt_t_over_m[s] * mirror_geom / (2.0 * (b_hat**2))).reshape((-1,))
            mirror_diag_by_s.append(sp.diags(mirror_factor_flat, 0, format="csr"))

        block_size_max = int(n_l * n_tz)
        # Store one block per (species,x), matching F-block layout.
        n_blocks = int(n_species) * int(n_x)
        inv_perm_r_blocks: list[np.ndarray | None] = [None] * n_blocks
        perm_c_blocks: list[np.ndarray | None] = [None] * n_blocks
        lower_idx_blocks: list[np.ndarray | None] = [None] * n_blocks
        lower_val_blocks: list[np.ndarray | None] = [None] * n_blocks
        upper_idx_blocks: list[np.ndarray | None] = [None] * n_blocks
        upper_val_blocks: list[np.ndarray | None] = [None] * n_blocks
        upper_diag_blocks: list[np.ndarray | None] = [None] * n_blocks
        max_lower_global = 0
        max_upper_global = 0

        def _factor_one(args: tuple[int, int]) -> tuple[int, np.ndarray, np.ndarray, np.ndarray, np.ndarray, np.ndarray, np.ndarray, np.ndarray]:
            s, ix = args
            stream_tz = stream_op_by_s[s]
            mirror_diag = mirror_diag_by_s[s]

            n_lx = int(nxi_for_x[ix])
            active_n = int(n_lx * n_tz)

            # Default: identity for the whole block (used when active_n==0 or ILU fails).
            perm_r_full = np.arange(block_size_max, dtype=np.int32)
            perm_c_full = np.arange(block_size_max, dtype=np.int32)
            inv_perm_r_full = perm_r_full.copy()
            lower_idx_full = np.zeros((block_size_max, 0), dtype=np.int32)
            lower_val_full = np.zeros((block_size_max, 0), dtype=np.float64)
            upper_idx_full = np.zeros((block_size_max, 0), dtype=np.int32)
            upper_val_full = np.zeros((block_size_max, 0), dtype=np.float64)
            upper_diag_full = np.ones((block_size_max,), dtype=np.float64)

            if active_n > 0:
                # L-coupling coefficients for this x.
                l = np.arange(n_lx, dtype=np.float64)
                coef_plus = (l + 1.0) / (2.0 * l + 3.0)
                coef_minus = np.where(l > 0, l / (2.0 * l - 1.0), 0.0)
                coef_m_plus = (l + 1.0) * (l + 2.0) / (2.0 * l + 3.0)
                coef_m_minus = np.where(l > 1, -l * (l - 1.0) / (2.0 * l - 1.0), 0.0)
                coef_plus *= x_arr[ix]
                coef_minus *= x_arr[ix]
                coef_m_plus *= x_arr[ix]
                coef_m_minus *= x_arr[ix]

                # Assemble sparse block matrix for the active L-modes.
                #
                # Previous implementations used a Python nested list + `sp.bmat`, which
                # can be surprisingly expensive. The structure here is block-tridiagonal
                # in L, so build it with Kronecker products.
                diag_vals = identity_shift + np.asarray(pas_coef[s, ix, :n_lx], dtype=np.float64) + float(reg)
                a = sp.kron(sp.diags(diag_vals, 0, format="csr"), i_tz, format="csc")
                if exb_op_tz is not None:
                    a = a + sp.kron(sp.eye(n_lx, format="csr", dtype=np.float64), exb_op_tz, format="csc")
                if n_lx > 1:
                    c_stream = sp.diags(
                        [coef_minus[1:], coef_plus[:-1]],
                        offsets=[-1, 1],
                        shape=(n_lx, n_lx),
                        format="csr",
                        dtype=np.float64,
                    )
                    c_mirror = sp.diags(
                        [coef_m_minus[1:], coef_m_plus[:-1]],
                        offsets=[-1, 1],
                        shape=(n_lx, n_lx),
                        format="csr",
                        dtype=np.float64,
                    )
                    a = a + sp.kron(c_stream, stream_tz, format="csc") + sp.kron(c_mirror, mirror_diag, format="csc")
                a = a.tocsc()

                # Prefer ILU for most PAS blocks to avoid SuperLU exact-LU peak allocations
                # and the resulting resident-set spikes. Fall back to exact LU only if ILU
                # fails to factor (e.g. due to numerical issues) and the block is small enough.
                fac = None
                used_lu = False
                try:
                    # ILU (PETSc PCILU analogue).
                    fac = spilu(
                        a,
                        drop_tol=ilu_drop_tol,
                        fill_factor=ilu_fill_factor,
                        permc_spec="COLAMD",
                    )
                except Exception:  # noqa: BLE001
                    fac = None
                if fac is None and lu_max > 0 and int(active_n) <= int(lu_max):
                    # Exact sparse LU (PETSc PCLU analogue) fallback for robustness.
                    try:
                        fac = splu(a, permc_spec="COLAMD")
                        used_lu = True
                    except Exception:  # noqa: BLE001
                        fac = None

                if fac is not None:
                    perm_r = np.asarray(fac.perm_r, dtype=np.int32)
                    perm_c = np.asarray(fac.perm_c, dtype=np.int32)

                    l_csr = fac.L.tocsr()
                    u_csr = fac.U.tocsr()
                    n = int(active_n)
                    # Truncating exact LU factors can severely degrade preconditioner quality.
                    # For LU factors, allow more fill than the ILU cap, but still cap to
                    # avoid dense padded-row allocations.
                    row_nnz_eff = int(row_nnz_max)
                    if used_lu and lu_full_row_nnz_max > 0:
                        row_nnz_eff = max(int(row_nnz_eff), min(int(n), int(lu_full_row_nnz_max)))

                    # Strict lower-triangular part (unit diagonal assumed).
                    lower_cols: list[np.ndarray] = []
                    lower_vals: list[np.ndarray] = []
                    max_lower = 0
                    for i in range(n):
                        rs = int(l_csr.indptr[i])
                        re = int(l_csr.indptr[i + 1])
                        cols = l_csr.indices[rs:re]
                        vals = l_csr.data[rs:re]
                        mask = cols < i
                        cols = cols[mask].astype(np.int32, copy=False)
                        vals = vals[mask].astype(np.float64, copy=False)
                        if row_nnz_eff > 0 and int(cols.size) > row_nnz_eff:
                            sel = np.argpartition(np.abs(vals), -row_nnz_eff)[-row_nnz_eff:]
                            cols = cols[sel]
                            vals = vals[sel]
                        if cols.size:
                            order = np.argsort(cols)
                            cols = cols[order]
                            vals = vals[order]
                        lower_cols.append(cols)
                        lower_vals.append(vals)
                        max_lower = max(max_lower, int(cols.size))
                    lower_idx = -np.ones((n, max_lower), dtype=np.int32)
                    lower_val = np.zeros((n, max_lower), dtype=np.float64)
                    for i in range(n):
                        k = int(lower_cols[i].size)
                        if k:
                            lower_idx[i, :k] = lower_cols[i]
                            lower_val[i, :k] = lower_vals[i]

                    # Strict upper + diagonal.
                    upper_cols: list[np.ndarray] = []
                    upper_vals: list[np.ndarray] = []
                    upper_diag = np.ones((n,), dtype=np.float64)
                    max_upper = 0
                    for i in range(n):
                        rs = int(u_csr.indptr[i])
                        re = int(u_csr.indptr[i + 1])
                        cols = u_csr.indices[rs:re]
                        vals = u_csr.data[rs:re]
                        diag_mask = cols == i
                        if np.any(diag_mask):
                            upper_diag[i] = float(vals[diag_mask][0])
                        mask = cols > i
                        cols_u = cols[mask].astype(np.int32, copy=False)
                        vals_u = vals[mask].astype(np.float64, copy=False)
                        if row_nnz_eff > 0 and int(cols_u.size) > row_nnz_eff:
                            sel = np.argpartition(np.abs(vals_u), -row_nnz_eff)[-row_nnz_eff:]
                            cols_u = cols_u[sel]
                            vals_u = vals_u[sel]
                        if cols_u.size:
                            order = np.argsort(cols_u)
                            cols_u = cols_u[order]
                            vals_u = vals_u[order]
                        upper_cols.append(cols_u)
                        upper_vals.append(vals_u)
                        max_upper = max(max_upper, int(cols_u.size))
                    upper_idx = -np.ones((n, max_upper), dtype=np.int32)
                    upper_val = np.zeros((n, max_upper), dtype=np.float64)
                    for i in range(n):
                        k = int(upper_cols[i].size)
                        if k:
                            upper_idx[i, :k] = upper_cols[i]
                            upper_val[i, :k] = upper_vals[i]

                    bad = ~np.isfinite(upper_diag) | (upper_diag == 0.0)
                    if np.any(bad):
                        upper_diag[bad] = 1.0

                    # Pad to the full x-block size by appending identity rows/cols.
                    perm_r_full[:n] = perm_r
                    perm_c_full[:n] = perm_c
                    inv_perm_r_full = _inverse_permutation(perm_r_full)

                    lower_idx_full = -np.ones((block_size_max, max_lower), dtype=np.int32)
                    lower_val_full = np.zeros((block_size_max, max_lower), dtype=np.float64)
                    lower_idx_full[:n, :] = lower_idx
                    lower_val_full[:n, :] = lower_val

                    upper_idx_full = -np.ones((block_size_max, max_upper), dtype=np.int32)
                    upper_val_full = np.zeros((block_size_max, max_upper), dtype=np.float64)
                    upper_idx_full[:n, :] = upper_idx
                    upper_val_full[:n, :] = upper_val

                    upper_diag_full = np.ones((block_size_max,), dtype=np.float64)
                    upper_diag_full[:n] = upper_diag

            block_idx = int(s) * int(n_x) + int(ix)
            return (
                block_idx,
                inv_perm_r_full,
                perm_c_full,
                lower_idx_full,
                lower_val_full,
                upper_idx_full,
                upper_val_full,
                upper_diag_full,
            )

        args_list = [(s, ix) for s in range(n_species) for ix in range(n_x)]
        threads_env = os.environ.get("SFINCS_JAX_RHSMODE1_PAS_ILU_THREADS", "").strip()
        try:
            threads_req = int(threads_env) if threads_env else 0
        except ValueError:
            threads_req = 0
        if threads_req > 0:
            n_workers = min(int(threads_req), int(n_blocks))
        else:
            # Auto: ILU build is often the dominant cost in PAS DKES cases. Parallelize across
            # independent (species,x) blocks, but cap workers to avoid oversubscribing CPU.
            n_cpu = os.cpu_count() or 1
            n_workers = min(int(n_blocks), max(1, int(n_cpu)), 8)

        if n_workers > 1 and n_blocks > 1:
            from concurrent.futures import ThreadPoolExecutor  # noqa: PLC0415

            with ThreadPoolExecutor(max_workers=int(n_workers)) as ex:
                for (
                    block_idx,
                    inv_perm_r_full,
                    perm_c_full,
                    lower_idx_full,
                    lower_val_full,
                    upper_idx_full,
                    upper_val_full,
                    upper_diag_full,
                ) in ex.map(_factor_one, args_list):
                    inv_perm_r_blocks[block_idx] = inv_perm_r_full
                    perm_c_blocks[block_idx] = perm_c_full
                    lower_idx_blocks[block_idx] = lower_idx_full
                    lower_val_blocks[block_idx] = lower_val_full
                    upper_idx_blocks[block_idx] = upper_idx_full
                    upper_val_blocks[block_idx] = upper_val_full
                    upper_diag_blocks[block_idx] = upper_diag_full
                    max_lower_global = max(max_lower_global, int(lower_idx_full.shape[1]))
                    max_upper_global = max(max_upper_global, int(upper_idx_full.shape[1]))
        else:
            for out in map(_factor_one, args_list):
                (
                    block_idx,
                    inv_perm_r_full,
                    perm_c_full,
                    lower_idx_full,
                    lower_val_full,
                    upper_idx_full,
                    upper_val_full,
                    upper_diag_full,
                ) = out
                inv_perm_r_blocks[block_idx] = inv_perm_r_full
                perm_c_blocks[block_idx] = perm_c_full
                lower_idx_blocks[block_idx] = lower_idx_full
                lower_val_blocks[block_idx] = lower_val_full
                upper_idx_blocks[block_idx] = upper_idx_full
                upper_val_blocks[block_idx] = upper_val_full
                upper_diag_blocks[block_idx] = upper_diag_full
                max_lower_global = max(max_lower_global, int(lower_idx_full.shape[1]))
                max_upper_global = max(max_upper_global, int(upper_idx_full.shape[1]))

        assert all(v is not None for v in inv_perm_r_blocks)
        assert all(v is not None for v in perm_c_blocks)
        assert all(v is not None for v in lower_idx_blocks)
        assert all(v is not None for v in lower_val_blocks)
        assert all(v is not None for v in upper_idx_blocks)
        assert all(v is not None for v in upper_val_blocks)
        assert all(v is not None for v in upper_diag_blocks)

        # Finalize uniform (Klower,Kupper) padding.
        for i in range(len(lower_idx_blocks)):
            lower_idx_block = lower_idx_blocks[i]
            lower_val_block = lower_val_blocks[i]
            upper_idx_block = upper_idx_blocks[i]
            upper_val_block = upper_val_blocks[i]
            assert lower_idx_block is not None
            assert lower_val_block is not None
            assert upper_idx_block is not None
            assert upper_val_block is not None

            if int(lower_idx_block.shape[1]) < max_lower_global:
                pad = int(max_lower_global - int(lower_idx_block.shape[1]))
                lower_idx_block = np.pad(lower_idx_block, ((0, 0), (0, pad)), constant_values=-1)
                lower_val_block = np.pad(lower_val_block, ((0, 0), (0, pad)), constant_values=0.0)
            if int(upper_idx_block.shape[1]) < max_upper_global:
                pad = int(max_upper_global - int(upper_idx_block.shape[1]))
                upper_idx_block = np.pad(upper_idx_block, ((0, 0), (0, pad)), constant_values=-1)
                upper_val_block = np.pad(upper_val_block, ((0, 0), (0, pad)), constant_values=0.0)

            lower_idx_blocks[i] = lower_idx_block
            lower_val_blocks[i] = lower_val_block
            upper_idx_blocks[i] = upper_idx_block
            upper_val_blocks[i] = upper_val_block

        inv_perm_r_np = np.stack(inv_perm_r_blocks, axis=0).reshape((n_species, n_x, block_size_max))  # type: ignore[arg-type]
        perm_c_np = np.stack(perm_c_blocks, axis=0).reshape((n_species, n_x, block_size_max))  # type: ignore[arg-type]
        lower_idx_np = np.stack(lower_idx_blocks, axis=0).reshape(  # type: ignore[arg-type]
            (n_species, n_x, block_size_max, max_lower_global)
        )
        lower_val_np = np.stack(lower_val_blocks, axis=0).reshape(  # type: ignore[arg-type]
            (n_species, n_x, block_size_max, max_lower_global)
        )
        upper_idx_np = np.stack(upper_idx_blocks, axis=0).reshape(  # type: ignore[arg-type]
            (n_species, n_x, block_size_max, max_upper_global)
        )
        upper_val_np = np.stack(upper_val_blocks, axis=0).reshape(  # type: ignore[arg-type]
            (n_species, n_x, block_size_max, max_upper_global)
        )
        upper_diag_np = np.stack(upper_diag_blocks, axis=0).reshape((n_species, n_x, block_size_max))  # type: ignore[arg-type]

        # Extra (constraint) block: keep the existing dense inverse on the small extra subsystem.
        extra_start = int(op.f_size + op.phi1_size)
        extra_size = int(op.extra_size)
        extra_idx_np = np.arange(extra_start, extra_start + extra_size, dtype=np.int32)
        extra_idx_jnp = jnp.asarray(extra_idx_np, dtype=jnp.int32)
        extra_inv_jnp: jnp.ndarray | None = None
        if extra_size > 0:
            chunk_cols = _precond_chunk_cols(total_size, int(extra_idx_np.shape[0]))
            y_sub = _matvec_submatrix(
                op,
                col_idx=extra_idx_np,
                row_idx=extra_idx_np,
                total_size=total_size,
                chunk_cols=chunk_cols,
            )
            ee = np.asarray(y_sub.T, dtype=np.float64)
            ee = ee + float(reg) * np.eye(extra_size, dtype=np.float64)
            try:
                ee_inv = np.linalg.inv(ee)
            except np.linalg.LinAlgError:
                ee_inv = np.linalg.pinv(ee, rcond=1e-12)
            if not np.all(np.isfinite(ee_inv)):
                ee_inv = np.linalg.pinv(ee, rcond=1e-12)
            extra_inv_jnp = jnp.asarray(ee_inv, dtype=jnp.float64)

        cached = _RHSMode1ILUBlockPrecondCache(
            inv_perm_r_sx=jnp.asarray(inv_perm_r_np, dtype=jnp.int32),
            perm_c_sx=jnp.asarray(perm_c_np, dtype=jnp.int32),
            lower_idx_sx=jnp.asarray(lower_idx_np, dtype=jnp.int32),
            lower_val_sx=jnp.asarray(lower_val_np, dtype=jnp.float64),
            upper_idx_sx=jnp.asarray(upper_idx_np, dtype=jnp.int32),
            upper_val_sx=jnp.asarray(upper_val_np, dtype=jnp.float64),
            upper_diag_sx=jnp.asarray(upper_diag_np, dtype=jnp.float64),
            extra_idx_jnp=extra_idx_jnp,
            extra_inv_jnp=extra_inv_jnp,
        )
        _RHSMODE1_PRECOND_ILU_CACHE[cache_key] = cached

    inv_perm_r_sx = cached.inv_perm_r_sx
    perm_c_sx = cached.perm_c_sx
    lower_idx_sx = cached.lower_idx_sx
    lower_val_sx = cached.lower_val_sx
    upper_idx_sx = cached.upper_idx_sx
    upper_val_sx = cached.upper_val_sx
    upper_diag_sx = cached.upper_diag_sx
    extra_idx_jnp = cached.extra_idx_jnp
    extra_inv_jnp = cached.extra_inv_jnp

    f_size = int(op.f_size)
    n_species = int(op.n_species)
    n_x = int(op.n_x)
    block_size_max = int(inv_perm_r_sx.shape[-1])

    def _solve_block(
        r: jnp.ndarray,
        inv_perm_r: jnp.ndarray,
        perm_c: jnp.ndarray,
        lower_idx: jnp.ndarray,
        lower_val: jnp.ndarray,
        upper_idx: jnp.ndarray,
        upper_val: jnp.ndarray,
        upper_diag: jnp.ndarray,
    ) -> jnp.ndarray:
        r_perm = r[inv_perm_r]
        y = _triangular_solve_lower_padded(lower_idx=lower_idx, lower_val=lower_val, b=r_perm)
        z = _triangular_solve_upper_padded(
            upper_idx=upper_idx, upper_val=upper_val, upper_diag=upper_diag, b=y
        )
        return z[perm_c]

    _solve_over_x = jax.vmap(
        _solve_block,
        in_axes=(0, 0, 0, 0, 0, 0, 0, 0),
        out_axes=0,
    )
    _solve_over_sx = jax.vmap(
        _solve_over_x,
        in_axes=(0, 0, 0, 0, 0, 0, 0, 0),
        out_axes=0,
    )

    def _apply_full(r_full: jnp.ndarray) -> jnp.ndarray:
        r_full = jnp.asarray(r_full, dtype=jnp.float64)
        r_f = r_full[:f_size].reshape((n_species, n_x, block_size_max))
        z_f = _solve_over_sx(
            r_f,
            inv_perm_r_sx,
            perm_c_sx,
            lower_idx_sx,
            lower_val_sx,
            upper_idx_sx,
            upper_val_sx,
            upper_diag_sx,
        )
        z_full = jnp.concatenate([z_f.reshape((-1,)), r_full[f_size:]], axis=0)
        if extra_inv_jnp is not None:
            r_extra = r_full[extra_idx_jnp]
            z_extra = extra_inv_jnp @ r_extra
            z_full = z_full.at[extra_idx_jnp].set(z_extra, unique_indices=True)
        return jnp.asarray(z_full, dtype=jnp.float64)

    apply_full_safe = _safe_preconditioner(_apply_full)
    # Expose ILU factor data for higher-level preconditioners (e.g. Schur) that can
    # exploit the per-(species,x) block structure without repeatedly applying the
    # full block-Jacobi operator during preconditioner setup.
    try:  # pragma: no cover - best-effort metadata for performance
        setattr(
            apply_full_safe,
            "_sfincs_pas_ilu_factors",
            (
                inv_perm_r_sx,
                perm_c_sx,
                lower_idx_sx,
                lower_val_sx,
                upper_idx_sx,
                upper_val_sx,
                upper_diag_sx,
            ),
        )
        setattr(apply_full_safe, "_sfincs_pas_ilu_block_size_max", int(block_size_max))
    except Exception:
        pass

    if reduce_full is None or expand_reduced is None:
        return apply_full_safe

    def _apply_reduced(r_reduced: jnp.ndarray) -> jnp.ndarray:
        z_full = apply_full_safe(expand_reduced(r_reduced))
        return reduce_full(z_full)

    return _apply_reduced


def _build_rhsmode1_zeta_line_preconditioner(
    *,
    op: V3FullSystemOperator,
    reduce_full: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
    expand_reduced: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
) -> Callable[[jnp.ndarray], jnp.ndarray]:
    """Build a stronger RHSMode=1 preconditioner using zeta-line blocks.

    For each species and each theta plane, solve a representative block that couples
    all zeta points for all local (x,L) unknowns at that theta. This approximates the
    dominant derivative couplings along zeta while ignoring theta derivatives.
    """
    cache_key = _rhsmode1_precond_cache_key(op, "zeta_line")
    precond_dtype = _precond_dtype()
    cached = _RHSMODE1_PRECOND_CACHE.get(cache_key)
    if cached is None:
        op_pc = _build_rhsmode1_preconditioner_operator_zeta_line(op)
        n_species = int(op.n_species)
        n_x = int(op.n_x)
        n_l = int(op.n_xi)
        n_theta = int(op.n_theta)
        n_zeta = int(op.n_zeta)
        total_size = int(op.total_size)

        nxi_for_x = np.asarray(op.fblock.collisionless.n_xi_for_x, dtype=np.int32)
        local_per_species = int(np.sum(nxi_for_x))
        line_size = int(n_zeta * local_per_species)

        reg_env = os.environ.get("SFINCS_JAX_RHSMODE1_PRECOND_REG", "").strip()
        reg_val = float(reg_env) if reg_env else 1e-10
        reg = np.float64(reg_val)

        # Build per-(species,theta) gather map for all zeta points and local (x,L) indices.
        idx_map = np.zeros((n_species, n_theta, line_size), dtype=np.int32)
        for s in range(n_species):
            for it in range(n_theta):
                k = 0
                for iz in range(n_zeta):
                    for ix in range(n_x):
                        max_l = int(nxi_for_x[ix])
                        for il in range(max_l):
                            idx_map[s, it, k] = int(
                                ((((s * n_x + ix) * n_l + il) * n_theta + it) * n_zeta + iz)
                            )
                            k += 1

        idx_map_jnp = jnp.asarray(idx_map, dtype=jnp.int32)
        flat_idx_jnp = idx_map_jnp.reshape((-1,))

        # Invert a zeta-line block for each theta plane.
        block_inv = np.zeros((n_species, n_theta, line_size, line_size), dtype=np.float64)
        for s in range(n_species):
            for it in range(n_theta):
                rep_idx = np.asarray(idx_map[s, it, :], dtype=np.int32)
                chunk_cols = _precond_chunk_cols(total_size, int(rep_idx.shape[0]))
                y_sub = _matvec_submatrix(
                    op_pc,
                    col_idx=rep_idx,
                    row_idx=rep_idx,
                    total_size=total_size,
                    chunk_cols=chunk_cols,
                )
                a = np.asarray(y_sub.T, dtype=np.float64)  # (line_size, line_size)
                a = a + reg * np.eye(line_size, dtype=np.float64)
                try:
                    inv = np.linalg.inv(a)
                except np.linalg.LinAlgError:
                    inv = np.linalg.pinv(a, rcond=1e-12)
                if not np.all(np.isfinite(inv)):
                    inv = np.linalg.pinv(a, rcond=1e-12)
                block_inv[s, it, :, :] = inv
        block_inv_jnp = jnp.asarray(block_inv, dtype=precond_dtype)

        extra_start = int(op.f_size + op.phi1_size)
        extra_size = int(op.extra_size)
        extra_idx_np = np.arange(extra_start, extra_start + extra_size, dtype=np.int32)
        extra_idx_jnp = jnp.asarray(extra_idx_np, dtype=jnp.int32)
        extra_inv_jnp: jnp.ndarray | None = None
        if extra_size > 0:
            chunk_cols = _precond_chunk_cols(total_size, int(extra_idx_np.shape[0]))
            y_sub = _matvec_submatrix(
                op_pc,
                col_idx=extra_idx_np,
                row_idx=extra_idx_np,
                total_size=total_size,
                chunk_cols=chunk_cols,
            )
            ee = np.asarray(y_sub.T, dtype=np.float64)
            ee = ee + reg * np.eye(extra_size, dtype=np.float64)
            try:
                ee_inv = np.linalg.inv(ee)
            except np.linalg.LinAlgError:
                ee_inv = np.linalg.pinv(ee, rcond=1e-12)
            if not np.all(np.isfinite(ee_inv)):
                ee_inv = np.linalg.pinv(ee, rcond=1e-12)
            extra_inv_jnp = jnp.asarray(ee_inv, dtype=precond_dtype)

        cached = _RHSMode1PrecondCache(
            idx_map_jnp=idx_map_jnp,
            flat_idx_jnp=flat_idx_jnp,
            block_inv_jnp=block_inv_jnp,
            extra_idx_jnp=extra_idx_jnp,
            extra_inv_jnp=extra_inv_jnp,
        )
        _RHSMODE1_PRECOND_CACHE[cache_key] = cached

    n_species = int(op.n_species)
    n_theta = int(op.n_theta)
    line_size = int(cached.block_inv_jnp.shape[-1])
    flat_idx_jnp = cached.flat_idx_jnp
    block_inv_jnp = cached.block_inv_jnp
    extra_idx_jnp = cached.extra_idx_jnp
    extra_inv_jnp = cached.extra_inv_jnp

    def _apply_full(r_full: jnp.ndarray) -> jnp.ndarray:
        r_full = jnp.asarray(r_full, dtype=precond_dtype)
        r_loc = r_full[flat_idx_jnp].reshape((n_species, n_theta, line_size))
        z_loc = jnp.einsum("stab,stb->sta", block_inv_jnp, r_loc)
        z_full = jnp.zeros_like(r_full)
        z_full = z_full.at[flat_idx_jnp].set(z_loc.reshape((-1,)), unique_indices=True)
        if extra_inv_jnp is not None:
            r_extra = r_full[extra_idx_jnp]
            z_extra = extra_inv_jnp @ r_extra
            z_full = z_full.at[extra_idx_jnp].set(z_extra, unique_indices=True)
        return jnp.asarray(z_full, dtype=jnp.float64)

    if reduce_full is None or expand_reduced is None:
        return _apply_full

    def _apply_reduced(r_reduced: jnp.ndarray) -> jnp.ndarray:
        z_full = _apply_full(expand_reduced(r_reduced))
        return reduce_full(z_full)

    return _apply_reduced


def _build_rhs1_preconditioner_from_kind(
    *,
    op: V3FullSystemOperator,
    rhs1_precond_kind: str | None,
    reduce_full: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
    expand_reduced: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
    preconditioner_species: int = 1,
    preconditioner_x: int = 1,
    preconditioner_xi: int = 1,
    rhs1_xblock_tz_lmax: int | None = None,
    dd_block_theta: int = 8,
    dd_overlap_theta: int = 1,
    dd_block_zeta: int = 8,
    dd_overlap_zeta: int = 1,
    adi_sweeps: int = 2,
    emit: Callable[[int, str], None] | None = None,
) -> Callable[[jnp.ndarray], jnp.ndarray]:
    """Resolve the RHSMode=1 preconditioner builder from the selected kind.

    The actual dispatch ladder lives in ``rhs1_preconditioner_dispatch.py``.
    This wrapper binds the current builder functions at call time so existing
    monkeypatch-based tests and local debug workflows continue to operate on
    ``sfincs_jax.v3_driver`` without behavioral changes.
    """
    return _dispatch_rhs1_preconditioner_from_kind(
        op=op,
        rhs1_precond_kind=rhs1_precond_kind,
        builders=RHS1PreconditionerDispatchBuilders(
            theta_line_builder=_build_rhsmode1_theta_line_preconditioner,
            theta_dd_builder=_build_rhsmode1_theta_dd_preconditioner,
            theta_schwarz_builder=_build_rhsmode1_theta_schwarz_preconditioner,
            theta_line_xdiag_builder=_build_rhsmode1_theta_line_xdiag_preconditioner,
            block_xdiag_builder=_build_rhsmode1_block_preconditioner_xdiag,
            species_block_builder=_build_rhsmode1_species_block_preconditioner,
            sxblock_builder=_build_rhsmode1_species_xblock_preconditioner,
            sxblock_tz_builder=_build_rhsmode1_sxblock_tz_preconditioner,
            xblock_tz_builder=_build_rhsmode1_xblock_tz_preconditioner,
            xblock_tz_lmax_builder=_build_rhsmode1_xblock_tz_lmax_preconditioner,
            theta_zeta_builder=_build_rhsmode1_theta_zeta_preconditioner,
            xmg_builder=_build_rhsmode1_xmg_preconditioner,
            pas_lite_builder=_build_rhsmode1_pas_lite_preconditioner,
            pas_hybrid_builder=_build_rhsmode1_pas_hybrid_preconditioner,
            pas_schur_builder=_build_rhsmode1_pas_schur_preconditioner,
            pas_tz_builder=_build_rhsmode1_pas_tz_preconditioner,
            pas_tzfft_builder=_build_rhsmode23_tzfft_preconditioner,
            pas_tokamak_theta_builder=_build_rhsmode1_pas_tokamak_theta_preconditioner,
            pas_ilu_builder=_build_rhsmode1_pas_xblock_ilu_preconditioner,
            zeta_line_builder=_build_rhsmode1_zeta_line_preconditioner,
            zeta_dd_builder=_build_rhsmode1_zeta_dd_preconditioner,
            zeta_schwarz_builder=_build_rhsmode1_zeta_schwarz_preconditioner,
            schur_builder=_build_rhsmode1_schur_preconditioner,
            collision_builder=_build_rhsmode1_collision_preconditioner,
            block_builder=_build_rhsmode1_block_preconditioner,
            compose_preconditioners=_compose_preconditioners,
        ),
        reduce_full=reduce_full,
        expand_reduced=expand_reduced,
        preconditioner_species=preconditioner_species,
        preconditioner_x=preconditioner_x,
        preconditioner_xi=preconditioner_xi,
        rhs1_xblock_tz_lmax=rhs1_xblock_tz_lmax,
        dd_block_theta=dd_block_theta,
        dd_overlap_theta=dd_overlap_theta,
        dd_block_zeta=dd_block_zeta,
        dd_overlap_zeta=dd_overlap_zeta,
        adi_sweeps=adi_sweeps,
        emit=emit,
    )


def _build_rhs1_strong_preconditioner_full_from_kind(
    *,
    op: V3FullSystemOperator,
    strong_precond_kind: str | None,
    rhs1_precond_kind: str | None,
    residual_norm: float,
    rhs1_xblock_tz_lmax: int | None = None,
    dd_block_theta: int = 8,
    dd_overlap_theta: int = 1,
    dd_block_zeta: int = 8,
    dd_overlap_zeta: int = 1,
    adi_sweeps: int = 2,
) -> tuple[str | None, Callable[[jnp.ndarray], jnp.ndarray] | None]:
    """Build the full-system strong fallback preconditioner via shared dispatch."""
    return build_rhs1_strong_preconditioner_full_from_kind(
        op=op,
        strong_precond_kind=strong_precond_kind,
        base_preconditioner_kind=rhs1_precond_kind,
        residual_norm=float(residual_norm),
        rhs1_xblock_tz_lmax=rhs1_xblock_tz_lmax,
        dd_block_theta=dd_block_theta,
        dd_overlap_theta=dd_overlap_theta,
        dd_block_zeta=dd_block_zeta,
        dd_overlap_zeta=dd_overlap_zeta,
        adi_sweeps=adi_sweeps,
        dispatch_builder=_build_rhs1_preconditioner_from_kind,
    )


def solve_v3_full_system_linear_gmres(
    *,
    nml: Namelist,
    which_rhs: int | None = None,
    op: V3FullSystemOperator | None = None,
    x0: jnp.ndarray | None = None,
    tol: float = 1e-10,
    atol: float = 0.0,
    restart: int = 80,
    maxiter: int | None = 400,
    solve_method: str = "auto",
    identity_shift: float = 0.0,
    phi1_hat_base: jnp.ndarray | None = None,
    differentiable: bool | None = None,
    emit: Callable[[int, str], None] | None = None,
    recycle_basis: Sequence[jnp.ndarray] | None = None,
) -> V3LinearSolveResult:
    """Solve the current v3 full-system linear problem `A x = rhs` matrix-free using GMRES.

    Notes
    -----
    This helper currently targets the linear runs exercised in the parity fixtures
    (e.g. includePhi1InKineticEquation=false). For nonlinear runs, use `residual_v3_full_system`
    and an outer Newton-Krylov iteration (not yet shipped as a stable API).
    """
    t = Timer()
    profiler = maybe_profiler(emit=emit)

    def _mark(label: str) -> None:
        if profiler is not None:
            profiler.mark(label)

    def _rhs1_solver_candidate_metrics(
        *,
        name: str,
        result: GMRESSolveResult,
        target_value: float,
        solve_s: float | None = None,
        setup_s: float | None = None,
    ) -> SolverCandidateMetrics:
        """Build measured solver-policy metrics from a real RHSMode=1 retry."""
        try:
            residual_norm = float(result.residual_norm)
        except Exception:
            residual_norm = None
        finite = residual_norm is not None and bool(np.isfinite(residual_norm))
        return SolverCandidateMetrics(
            name=str(name),
            residual_norm=residual_norm,
            target=float(target_value),
            setup_s=setup_s,
            solve_s=solve_s,
            peak_rss_mb=_rss_mb(),
            finite=finite,
        )
    restart_env = os.environ.get("SFINCS_JAX_GMRES_RESTART", "").strip()
    restart_env_forced = False
    if restart_env:
        try:
            restart = int(restart_env)
            restart_env_forced = True
        except ValueError:
            pass
    maxiter_env = os.environ.get("SFINCS_JAX_GMRES_MAXITER", "").strip()
    maxiter_env_forced = False
    if maxiter_env:
        try:
            maxiter = int(maxiter_env)
            maxiter_env_forced = True
        except ValueError:
            pass
    geom_params_hint = nml.group("geometryParameters")
    geom_scheme_hint = int(
        geom_params_hint.get(
            "GEOMETRYSCHEME",
            geom_params_hint.get("geometryScheme", geom_params_hint.get("geometryscheme", 0)),
        )
        or 0
    )
    vmec_operator_timer: Timer | None = None
    if emit is not None:
        emit(1, "solve_v3_full_system_linear_gmres: building operator")
        if geom_scheme_hint == 5:
            eq_hint = geom_params_hint.get(
                "EQUILIBRIUMFILE",
                geom_params_hint.get("equilibriumFile", geom_params_hint.get("equilibriumfile", "")),
            )
            eq_name = Path(str(eq_hint)).name if eq_hint else "VMEC equilibrium"
            emit(1, f"solve_v3_full_system_linear_gmres: VMEC operator build start ({eq_name})")
            vmec_operator_timer = Timer()
    op = (
        full_system_operator_from_namelist(
            nml=nml,
            identity_shift=identity_shift,
            phi1_hat_base=phi1_hat_base,
        )
        if op is None
        else op
    )
    if emit is not None and vmec_operator_timer is not None:
        emit(1, f"solve_v3_full_system_linear_gmres: VMEC operator build done elapsed_s={vmec_operator_timer.elapsed_s():.3f}")
    _mark("operator_built")
    _set_precond_size_hint(int(op.total_size))
    _set_precond_policy_hints(
        geom_scheme=geom_scheme_hint,
        has_pas=getattr(op.fblock, "pas", None) is not None,
        has_fp=getattr(op.fblock, "fp", None) is not None,
        include_phi1=bool(op.include_phi1),
        rhs_mode=int(op.rhs_mode),
    )
    # FP-only large systems: tighten tolerance automatically to recover flow/Mach parity.
    # This avoids relying on dense fallbacks while keeping the default solverTolerance
    # unchanged for smaller cases.
    fp_tol_env = os.environ.get("SFINCS_JAX_RHSMODE1_FP_TOL", "").strip()
    fp_tol_min_env = os.environ.get("SFINCS_JAX_RHSMODE1_FP_TOL_MIN_SIZE", "").strip()
    try:
        fp_tol = float(fp_tol_env) if fp_tol_env else 1.0e-8
    except ValueError:
        fp_tol = 1.0e-8
    try:
        fp_tol_min = int(fp_tol_min_env) if fp_tol_min_env else 80000
    except ValueError:
        fp_tol_min = 80000
    if (
        int(op.rhs_mode) == 1
        and (not bool(op.include_phi1))
        and op.fblock.fp is not None
        and op.fblock.pas is None
        and int(op.total_size) >= max(1, int(fp_tol_min))
        and fp_tol > 0.0
    ):
        tol_old = float(tol)
        tol = min(float(tol), float(fp_tol))
        if emit is not None and float(tol) < tol_old:
            emit(1, f"solve_v3_full_system_linear_gmres: FP tol tightened {tol_old:.1e} -> {float(tol):.1e}")
    pas_tol_env = os.environ.get("SFINCS_JAX_RHSMODE1_PAS_TOL", "").strip()
    if pas_tol_env:
        try:
            pas_tol = float(pas_tol_env)
        except ValueError:
            pas_tol = None
    else:
        pas_tol = None
    if (
        int(op.rhs_mode) == 1
        and (not bool(op.include_phi1))
        and op.fblock.pas is not None
        and int(op.constraint_scheme) == 2
        and pas_tol is not None
        and pas_tol > 0.0
    ):
        tol_old = float(tol)
        tol = min(float(tol), float(pas_tol))
        if emit is not None and float(tol) < tol_old:
            emit(1, f"solve_v3_full_system_linear_gmres: PAS tol tightened {tol_old:.1e} -> {float(tol):.1e}")
    if int(op.rhs_mode) in {2, 3}:
        # v3 sets (dnHatdpsiHats, dTHatdpsiHats, EParallelHat) internally based on whichRHS.
        # If the input file omits gradients (common for monoenergetic runs), callers must select whichRHS.
        if which_rhs is None:
            which_rhs = 1
        op = with_transport_rhs_settings(op, which_rhs=int(which_rhs))
        if emit is not None:
            emit(1, f"solve_v3_full_system_linear_gmres: applied transport RHS settings whichRHS={int(which_rhs)}")
    if emit is not None:
        emit(1, f"solve_v3_full_system_linear_gmres: total_size={int(op.total_size)}")
        emit(1, "solve_v3_full_system_linear_gmres: assembling RHS")
    rhs = rhs_v3_full_system(op)
    _mark("rhs_assembled")
    rhs_norm = jnp.linalg.norm(rhs)
    if emit is not None:
        emit(2, f"solve_v3_full_system_linear_gmres: rhs_norm={float(rhs_norm):.6e}")
    rhs1_progress_notes = RHS1ProgressNotes(
        emit=emit,
        enabled=rhs1_large_progress_enabled(rhs_mode=int(op.rhs_mode), total_size=int(op.total_size)),
    )
    solve_method_kind_requested = str(solve_method).strip().lower().replace("-", "_")
    sparse_host_requested = solve_method_kind_requested in _SPARSE_HOST_DIRECT_SOLVE_METHODS
    sparse_host_safe_requested = solve_method_kind_requested in _SPARSE_HOST_SAFE_SOLVE_METHODS
    sparse_pc_gmres_requested = (
        solve_method_kind_requested in _SPARSE_HOST_PC_GMRES_SOLVE_METHODS
        or solve_method_kind_requested in _SPARSE_HOST_XBLOCK_PC_GMRES_SOLVE_METHODS
    )
    sparse_minimum_norm_requested = solve_method_kind_requested in _SPARSE_HOST_MINIMUM_NORM_SOLVE_METHODS
    sparse_host_like_requested = (
        sparse_host_requested
        or sparse_host_safe_requested
        or sparse_pc_gmres_requested
        or sparse_minimum_norm_requested
    )
    xblock_active_dof_requested = (
        solve_method_kind_requested in _SPARSE_HOST_XBLOCK_PC_GMRES_SOLVE_METHODS
        and _rhs1_bool_env("SFINCS_JAX_RHSMODE1_XBLOCK_ACTIVE_DOF", default=False)
    )

    recycle_k_env = os.environ.get("SFINCS_JAX_RHSMODE1_RECYCLE_K", "").strip()
    try:
        recycle_k = int(recycle_k_env) if recycle_k_env else 4
    except ValueError:
        recycle_k = 4
    recycle_k = max(0, recycle_k)
    recycle_basis_use: list[jnp.ndarray] = []
    if recycle_k > 0 and recycle_basis:
        for vec in recycle_basis:
            v = jnp.asarray(vec)
            if v.shape == (op.total_size,):
                recycle_basis_use.append(v)
        if len(recycle_basis_use) > recycle_k:
            recycle_basis_use = recycle_basis_use[-recycle_k:]

    def _recycled_initial_guess(
        rhs_vec: jnp.ndarray,
        basis: list[jnp.ndarray],
        basis_au: list[jnp.ndarray],
    ) -> jnp.ndarray | None:
        if not basis or not basis_au:
            return None
        u = jnp.stack(basis, axis=1)  # (N, k)
        au = jnp.stack(basis_au, axis=1)  # (N, k)
        coeff = _small_regularized_lstsq(au, rhs_vec)
        x0_guess = u @ coeff
        if not jnp.all(jnp.isfinite(x0_guess)):
            return None
        return x0_guess

    active_env = os.environ.get("SFINCS_JAX_ACTIVE_DOF", "").strip().lower()
    nxi_for_x = np.asarray(op.fblock.collisionless.n_xi_for_x, dtype=np.int32)
    max_l = int(np.max(nxi_for_x)) if nxi_for_x.size else 0
    has_reduced_modes = bool(np.any(nxi_for_x < int(op.n_xi)))
    phys_params = nml.group("physicsParameters")
    def _nml_get(group: dict, key: str, default=None):
        if key in group:
            return group[key]
        key_upper = key.upper()
        if key_upper in group:
            return group[key_upper]
        key_lower = key.lower()
        if key_lower in group:
            return group[key_lower]
        return default

    def _nml_bool(val: object | None) -> bool:
        if val is None:
            return False
        if isinstance(val, bool):
            return bool(val)
        if isinstance(val, (int, np.integer)):
            return bool(int(val))
        if isinstance(val, (float, np.floating)):
            return bool(float(val))
        if isinstance(val, str):
            return val.strip().lower() in {"t", "true", "1", "yes", ".true.", ".t."}
        return False
    use_dkes = _nml_bool(
        _nml_get(
            phys_params,
            "useDKESExBDrift",
            _nml_get(phys_params, "useDKESExBdrift", _nml_get(phys_params, "use_dkes_exb_drift", None)),
        )
    )
    include_xdot_sparse_pc = _nml_bool(_nml_get(phys_params, "includeXDotTerm", None))
    include_electric_field_xi_sparse_pc = _nml_bool(_nml_get(phys_params, "includeElectricFieldTermInXiDot", None))

    def _nml_abs_float(key: str) -> float:
        value = _nml_get(phys_params, key, None)
        try:
            return abs(float(value)) if value is not None else 0.0
        except (TypeError, ValueError):
            return 0.0

    er_abs_sparse_pc = max(
        _nml_abs_float("Er"),
        _nml_abs_float("dPhiHatdpsiHat"),
        _nml_abs_float("dPhiHatdpsiN"),
        _nml_abs_float("dPhiHatdrHat"),
        _nml_abs_float("dPhiHatdrN"),
    )
    if (
        int(op.rhs_mode) == 1
        and (not bool(op.include_phi1))
        and op.fblock.fp is not None
        and op.fblock.pas is None
        and use_dkes
        and fp_tol > 0.0
    ):
        tol_old = float(tol)
        tol = min(float(tol), float(fp_tol))
        if emit is not None and float(tol) < tol_old:
            emit(1, f"solve_v3_full_system_linear_gmres: FP DKES tol tightened {tol_old:.1e} -> {float(tol):.1e}")
    if op.fblock.pas is not None and use_dkes:
        # DKES trajectory runs can be stiff, but very large GMRES restart/maxiter
        # values are expensive in JAX (memory + orthogonalization cost). Prefer
        # moderate defaults and let stage2/strong-preconditioner fallbacks handle the
        # truly difficult cases. Explicit GMRES env/CLI budgets are respected so
        # profiling and bounded production probes cannot be silently escalated.
        restart, maxiter, restart_defaulted, maxiter_defaulted = _rhs1_dkes_gmres_budget(
            restart=int(restart),
            maxiter=maxiter,
            restart_forced=bool(restart_env_forced),
            maxiter_forced=bool(maxiter_env_forced),
            restart_cap_env=os.environ.get("SFINCS_JAX_RHSMODE1_DKES_RESTART_CAP", "").strip(),
        )
        if emit is not None and (restart_env_forced or maxiter_env_forced):
            emit(
                1,
                "solve_v3_full_system_linear_gmres: PAS DKES respecting explicit GMRES budget "
                f"restart={int(restart)} maxiter={maxiter}",
            )
        elif emit is not None and (restart_defaulted or maxiter_defaulted):
            emit(
                1,
                "solve_v3_full_system_linear_gmres: PAS DKES default GMRES budget "
                f"restart={int(restart)} maxiter={maxiter}",
            )
    use_active_dof_mode = False
    if active_env in {"1", "true", "yes", "on"}:
        use_active_dof_mode = True
    elif active_env in {"0", "false", "no", "off"}:
        use_active_dof_mode = False
    else:
        # Auto mode:
        # - Always use active-DOF reduction for RHSMode=2/3 with truncated pitch grid.
        # - Also use it for RHSMode=1 when includePhi1 is off and pitch truncation is
        #   present. This reduces solve size and JIT cost in upstream-like reduced runs.
        # - Keep includePhi1 RHSMode=1 on the full system to preserve sensitive parity
        #   branches in tiny includePhi1 fixtures.
        use_active_dof_mode = has_reduced_modes and (
            int(op.rhs_mode) in {2, 3} or (int(op.rhs_mode) == 1 and (not bool(op.include_phi1)))
        )
        if sparse_host_like_requested and not xblock_active_dof_requested:
            use_active_dof_mode = False
        # Upstream v3 always drops inactive (x,L) modes when `Nxi_for_x` truncation is
        # active. Keep this reduction on for DKES trajectories as well to match v3's
        # linear-system size/conditioning and avoid singular inactive rows.
        dkes_active_env = os.environ.get("SFINCS_JAX_ACTIVE_DOF_DKES", "").strip().lower()
        if dkes_active_env in {"0", "false", "no", "off"} and use_active_dof_mode and int(op.rhs_mode) == 1 and op.fblock.pas is not None and use_dkes:
            use_active_dof_mode = False

    precond_opts = nml.group("preconditionerOptions")
    pas_project_env = os.environ.get("SFINCS_JAX_PAS_PROJECT_CONSTRAINTS", "").strip().lower()
    if pas_project_env in {"1", "true", "yes", "on"}:
        pas_project_mode = "on"
    elif pas_project_env in {"0", "false", "no", "off"}:
        pas_project_mode = "off"
    elif pas_project_env in {"", "auto"}:
        pas_project_mode = "auto"
    else:
        pas_project_mode = "off"
    def _precond_opt_int(key: str, default: int) -> int:
        val = precond_opts.get(key, None)
        if val is None:
            return default
        try:
            return int(val)
        except (TypeError, ValueError):
            return default

    preconditioner_species = _precond_opt_int("PRECONDITIONER_SPECIES", 1)
    preconditioner_x = _precond_opt_int("PRECONDITIONER_X", 1)
    preconditioner_xi = _precond_opt_int("PRECONDITIONER_XI", 1)
    full_precond_requested = (
        preconditioner_species == 0 and preconditioner_x == 0 and preconditioner_xi == 0
    )
    geom_params = nml.group("geometryParameters")
    geom_scheme = int(_nml_get(geom_params, "geometryScheme", -1) or -1)
    pas_project_enabled = bool(
        pas_project_mode == "on"
        or (
            pas_project_mode == "auto"
            and not full_precond_requested
            and geom_scheme != 1
        )
    )
    use_pas_projection = bool(
        (not sparse_host_like_requested)
        and pas_project_enabled
        and int(op.rhs_mode) == 1
        and (not bool(op.include_phi1))
        and int(op.constraint_scheme) == 2
        and op.fblock.pas is not None
        and int(op.phi1_size) == 0
    )
    if use_pas_projection:
        pas_project_min_env = os.environ.get("SFINCS_JAX_PAS_PROJECT_MIN", "").strip()
        try:
            pas_project_min = int(pas_project_min_env) if pas_project_min_env else 2000
        except ValueError:
            pas_project_min = 2000
        if int(op.total_size) < max(0, int(pas_project_min)):
            use_pas_projection = False
    if use_pas_projection:
        # Force a reduced system when projecting out constraintScheme=2 sources.
        use_active_dof_mode = True

    active_idx_jnp: jnp.ndarray | None = None
    full_to_active_jnp: jnp.ndarray | None = None
    active_size = int(op.total_size)
    if use_active_dof_mode:
        if use_pas_projection:
            active_idx_np = _transport_active_dof_indices(op)
            active_idx_np = active_idx_np[active_idx_np < int(op.f_size)]
            active_idx_jnp = jnp.asarray(active_idx_np, dtype=jnp.int32)
            full_to_active_np = np.zeros((int(op.f_size),), dtype=np.int32)
            full_to_active_np[np.asarray(active_idx_np, dtype=np.int32)] = np.arange(
                1, int(active_idx_np.shape[0]) + 1, dtype=np.int32
            )
            full_to_active_jnp = jnp.asarray(full_to_active_np, dtype=jnp.int32)
            active_size = int(active_idx_np.shape[0])
            if emit is not None:
                emit(
                    1,
                    "solve_v3_full_system_linear_gmres: PAS constraint projection enabled "
                    f"(size={active_size}/{int(op.total_size)})",
                )
        else:
            active_idx_np = _transport_active_dof_indices(op)
            active_idx_jnp = jnp.asarray(active_idx_np, dtype=jnp.int32)
            full_to_active_np = np.zeros((int(op.total_size),), dtype=np.int32)
            full_to_active_np[np.asarray(active_idx_np, dtype=np.int32)] = np.arange(
                1, int(active_idx_np.shape[0]) + 1, dtype=np.int32
            )
            full_to_active_jnp = jnp.asarray(full_to_active_np, dtype=jnp.int32)
            active_size = int(active_idx_np.shape[0])
            if emit is not None:
                emit(1, f"solve_v3_full_system_linear_gmres: active-DOF mode enabled (size={active_size}/{int(op.total_size)})")

    # Tiny PAS systems can be ill-conditioned; allow full-restart GMRES to reach
    # the tight PETSc-style tolerances used in parity fixtures.
    pas_full_gmres_env = os.environ.get("SFINCS_JAX_PAS_FULL_GMRES_MAX", "").strip()
    try:
        pas_full_gmres_max = int(pas_full_gmres_env) if pas_full_gmres_env else 1200
    except ValueError:
        pas_full_gmres_max = 1200
    if op.fblock.pas is not None and int(active_size) <= max(0, int(pas_full_gmres_max)):
        restart = max(int(restart), int(active_size))
        if maxiter is None or int(maxiter) < int(active_size):
            maxiter = int(active_size)

    full_precond_env = os.environ.get("SFINCS_JAX_RHSMODE1_FULL_PRECOND", "").strip().lower()
    if full_precond_env in {"0", "false", "no", "off"}:
        full_precond_mode = "off"
    elif full_precond_env in {"dense", "dense_ksp"}:
        full_precond_mode = full_precond_env
    else:
        full_precond_mode = "auto"

    full_precond_max_env = os.environ.get("SFINCS_JAX_RHSMODE1_FULL_PRECOND_DENSE_MAX", "").strip()
    try:
        full_precond_dense_max = int(full_precond_max_env) if full_precond_max_env else 2500
    except ValueError:
        full_precond_dense_max = 2500

    full_precond_size = active_size if use_active_dof_mode else int(op.total_size)
    auto_dense_full_precond = bool(
        full_precond_mode == "auto"
        and full_precond_requested
        and int(op.rhs_mode) == 1
        and (not bool(op.include_phi1))
        and int(op.constraint_scheme) != 0
        and full_precond_dense_max > 0
        and int(full_precond_size) <= int(full_precond_dense_max)
        and _rhsmode1_dense_backend_allowed()
        and str(solve_method).strip().lower() in {"auto", "default"}
    )
    if (
        full_precond_requested
        and (full_precond_mode in {"dense", "dense_ksp"} or auto_dense_full_precond)
        and int(op.rhs_mode) == 1
        and (not bool(op.include_phi1))
        and full_precond_dense_max > 0
        and int(full_precond_size) <= int(full_precond_dense_max)
        and str(solve_method).strip().lower() in {"auto", "default"}
    ):
        solve_method = "dense" if (full_precond_mode != "dense_ksp" or use_active_dof_mode) else "dense_ksp"
        if emit is not None:
            emit(
                0,
                "solve_v3_full_system_linear_gmres: full preconditioner requested; "
                f"using solve_method={solve_method} (size={int(full_precond_size)})",
            )
    elif (
        full_precond_requested
        and full_precond_mode == "auto"
        and int(op.rhs_mode) == 1
        and (not bool(op.include_phi1))
        and int(op.constraint_scheme) != 0
        and full_precond_dense_max > 0
        and int(full_precond_size) <= int(full_precond_dense_max)
        and (not _rhsmode1_dense_backend_allowed())
        and str(solve_method).strip().lower() in {"auto", "default"}
    ):
        if emit is not None:
            emit(
                0,
                "solve_v3_full_system_linear_gmres: full preconditioner requested; "
                f"skipping dense auto mode on backend={jax.default_backend()}",
            )

    tokamak_pas = bool(
        op.fblock.pas is not None
        and int(op.rhs_mode) == 1
        and (not bool(op.include_phi1))
        and (geom_scheme == 1 or int(op.n_zeta) <= 5)
    )
    pas_large_fastpath_env = os.environ.get("SFINCS_JAX_PAS_LARGE_BICGSTAB_FASTPATH", "").strip().lower()
    try:
        pas_large_fastpath_min = int(
            os.environ.get("SFINCS_JAX_PAS_LARGE_BICGSTAB_FASTPATH_MIN", "").strip() or 80000
        )
    except ValueError:
        pas_large_fastpath_min = 80000
    pas_large_fastpath_auto = pas_large_fastpath_env in {"", "auto"}
    pas_large_fastpath_on = pas_large_fastpath_env in {"1", "true", "yes", "on"}
    pas_large_fastpath_off = pas_large_fastpath_env in {"0", "false", "no", "off"}
    pas_large_bicgstab_fastpath = bool(
        (pas_large_fastpath_on or pas_large_fastpath_auto)
        and (not pas_large_fastpath_off)
        and tokamak_pas
        and geom_scheme == 1
        and int(op.n_species) == 1
        and int(op.n_zeta) == 1
        and int(active_size) >= max(1, int(pas_large_fastpath_min))
    )

    if int(op.rhs_mode) == 1 and str(solve_method).strip().lower() in {"auto", "default"}:
        # Keep `auto` intact on explicit multi-device sharded runs so the later
        # distributed solver dispatch can choose a short-recurrence Krylov method.
        sharded_axis_hint = _matvec_shard_axis(op)
        sharded_multidevice_hint = sharded_axis_hint in {"theta", "zeta"} and jax.device_count() > 1
        if pas_large_bicgstab_fastpath:
            solve_method = "bicgstab"
            if emit is not None:
                emit(
                    1,
                    "solve_v3_full_system_linear_gmres: enabling PAS-large BiCGStab fastpath "
                    f"(active_size={int(active_size)} >= {int(pas_large_fastpath_min)})",
                )
        elif sharded_multidevice_hint:
            solve_method = "auto"
            if emit is not None:
                emit(
                    1,
                    "solve_v3_full_system_linear_gmres: preserving auto solver selection for "
                    f"multi-device sharded axis={sharded_axis_hint}",
                )
        else:
            # Default RHSMode=1 to parity-robust GMRES on non-sharded paths.
            solve_method = "incremental"
    if emit is not None:
        emit(1, f"solve_v3_full_system_linear_gmres: GMRES tol={tol} atol={atol} restart={restart} maxiter={maxiter} solve_method={solve_method}")
        emit(1, "solve_v3_full_system_linear_gmres: evaluateJacobian called (matrix-free)")
    solve_method_kind_explicit = str(solve_method).strip().lower().replace("-", "_")
    if solve_method_kind_explicit in _SPARSE_HOST_SAFE_SOLVE_METHODS:
        try:
            direct_result = solve_v3_full_system_linear_gmres(
                nml=nml,
                which_rhs=which_rhs,
                op=op,
                x0=x0,
                tol=tol,
                atol=atol,
                restart=restart,
                maxiter=maxiter,
                solve_method="sparse_host",
                identity_shift=identity_shift,
                phi1_hat_base=phi1_hat_base,
                differentiable=differentiable,
                emit=emit,
                recycle_basis=recycle_basis,
            )
            metadata = dict(getattr(direct_result, "metadata", None) or {})
            metadata.update(
                {
                    "requested_solve_method": solve_method_kind_explicit,
                    "safe_sparse_host_fallback_used": False,
                    "accepted_converged": bool(metadata.get("accepted_converged", True)),
                    "acceptance_criterion": metadata.get("acceptance_criterion", "true_residual"),
                }
            )
            return replace(direct_result, metadata=metadata)
        except RuntimeError as exc:
            if "Host sparse factorization failed" not in str(exc):
                raise
            if not (
                int(op.rhs_mode) == 1
                and int(op.constraint_scheme) == 2
                and (not bool(op.include_phi1))
                and op.fblock.pas is not None
            ):
                raise
            if emit is not None:
                emit(
                    0,
                    "solve_v3_full_system_linear_gmres: sparse_host_safe falling back to "
                    "PETSc-compatible minimum-norm constrained-PAS branch after sparse LU failure",
                )
            compat_result = solve_v3_full_system_linear_gmres(
                nml=nml,
                which_rhs=which_rhs,
                op=op,
                x0=x0,
                tol=tol,
                atol=atol,
                restart=restart,
                maxiter=maxiter,
                solve_method="petsc_compat",
                identity_shift=identity_shift,
                phi1_hat_base=phi1_hat_base,
                differentiable=differentiable,
                emit=emit,
                recycle_basis=recycle_basis,
            )
            metadata = dict(getattr(compat_result, "metadata", None) or {})
            metadata.update(
                {
                    "requested_solve_method": solve_method_kind_explicit,
                    "safe_sparse_host_fallback_used": True,
                    "sparse_host_failure": str(exc),
                }
            )
            return replace(compat_result, metadata=metadata)
    if (
        solve_method_kind_explicit in _SPARSE_HOST_PC_GMRES_SOLVE_METHODS
        or solve_method_kind_explicit in _SPARSE_HOST_XBLOCK_PC_GMRES_SOLVE_METHODS
    ):
        if differentiable is True:
            raise ValueError(
                "solve_method='sparse_pc_gmres'/'xblock_sparse_pc_gmres' is a non-differentiable host sparse-PC GMRES path."
            )
        if int(op.rhs_mode) != 1:
            raise NotImplementedError(
                "solve_method='sparse_pc_gmres'/'xblock_sparse_pc_gmres' is currently implemented for RHSMode=1 only."
            )
        constrained_pas_pc = bool(
            int(op.rhs_mode) == 1
            and int(op.constraint_scheme) == 2
            and (not bool(op.include_phi1))
            and op.fblock.pas is not None
            and op.fblock.fp is None
        )
        tokamak_pas_noer_pc = bool(
            constrained_pas_pc
            and int(getattr(op, "n_zeta", 1)) == 1
            and float(er_abs_sparse_pc) == 0.0
        )
        tokamak_pas_er_pc = bool(
            constrained_pas_pc
            and int(getattr(op, "n_zeta", 1)) == 1
            and float(er_abs_sparse_pc) > 0.0
            and (
                bool(use_dkes)
                or bool(include_xdot_sparse_pc)
                or bool(include_electric_field_xi_sparse_pc)
            )
        )
        tokamak_fp_er_pc = bool(
            int(op.rhs_mode) == 1
            and int(op.constraint_scheme) == 1
            and (not bool(op.include_phi1))
            and op.fblock.fp is not None
            and op.fblock.pas is None
            and int(getattr(op, "n_zeta", 1)) == 1
            and float(er_abs_sparse_pc) > 0.0
            and (
                bool(use_dkes)
                or bool(include_xdot_sparse_pc)
                or bool(include_electric_field_xi_sparse_pc)
            )
        )
        tokamak_fp_noer_pc = bool(
            int(op.rhs_mode) == 1
            and int(op.constraint_scheme) == 0
            and (not bool(op.include_phi1))
            and op.fblock.fp is not None
            and op.fblock.pas is None
            and int(getattr(op, "n_zeta", 1)) == 1
            and float(er_abs_sparse_pc) == 0.0
        )
        tokamak_fp_pc = bool(tokamak_fp_er_pc or tokamak_fp_noer_pc)
        xblock_sparse_pc = solve_method_kind_explicit in _SPARSE_HOST_XBLOCK_PC_GMRES_SOLVE_METHODS
        sparse_pc_active_env = os.environ.get("SFINCS_JAX_RHSMODE1_SPARSE_PC_ACTIVE_DOF", "").strip().lower()
        sparse_pc_active_forced_on = sparse_pc_active_env in {"1", "true", "t", "yes", "on", ".true.", ".t."}
        sparse_pc_active_forced_off = sparse_pc_active_env in {"0", "false", "f", "no", "off", ".false.", ".f."}
        sparse_pc_active_auto = sparse_pc_active_env in {"", "auto"}
        sparse_pc_use_active_dof = bool(
            (not xblock_sparse_pc)
            and has_reduced_modes
            and int(op.rhs_mode) == 1
            and (not bool(op.include_phi1))
            and (
                sparse_pc_active_forced_on
                or (
                    sparse_pc_active_auto
                    and (tokamak_pas_er_pc or tokamak_pas_noer_pc)
                )
            )
            and (not sparse_pc_active_forced_off)
        )
        xblock_use_active_dof = bool(
            xblock_sparse_pc
            and use_active_dof_mode
            and bool(xblock_active_dof_requested)
            and active_idx_jnp is not None
            and full_to_active_jnp is not None
        )
        if use_active_dof_mode and not (sparse_pc_use_active_dof or xblock_use_active_dof):
            raise NotImplementedError(
                "solve_method='sparse_pc_gmres'/'xblock_sparse_pc_gmres' active-DOF mode is only implemented "
                "for the generic sparse_pc_gmres branch or opt-in x-block branch. Set "
                "SFINCS_JAX_RHSMODE1_SPARSE_PC_ACTIVE_DOF=1, "
                "SFINCS_JAX_RHSMODE1_XBLOCK_ACTIVE_DOF=1, or SFINCS_JAX_ACTIVE_DOF=0."
            )
        fp_dense_velocity_env = os.environ.get(
            "SFINCS_JAX_RHSMODE1_SPARSE_PC_FP_DENSE_VELOCITY_BLOCK",
            "",
        ).strip().lower()
        if fp_dense_velocity_env in {"0", "false", "f", "no", "off", ".false.", ".f."}:
            sparse_pc_fp_dense_velocity_block: bool | None = False
        elif fp_dense_velocity_env in {"1", "true", "t", "yes", "on", ".true.", ".t."}:
            sparse_pc_fp_dense_velocity_block = True
        else:
            sparse_pc_fp_dense_velocity_block = None

        sparse_timer = Timer()
        pc_restart_env = os.environ.get("SFINCS_JAX_RHSMODE1_SPARSE_PC_GMRES_RESTART", "").strip()
        pc_restart, pc_maxiter = rhs1_parse_polish_gmres_config(
            restart_env_name="SFINCS_JAX_RHSMODE1_SPARSE_PC_GMRES_RESTART",
            maxiter_env_name="SFINCS_JAX_RHSMODE1_SPARSE_PC_GMRES_MAXITER",
            default_restart=max(20, int(restart)),
            default_maxiter=max(100, int(maxiter) if maxiter is not None else 400),
            min_restart=2,
            min_maxiter=1,
        )
        pc_restart = _rhsmode1_sparse_pc_default_restart(
            requested_restart=int(pc_restart),
            restart_env_value=pc_restart_env,
            tokamak_pas_er_pc=bool(tokamak_pas_er_pc),
            n_species=int(op.n_species),
        )

        if xblock_sparse_pc:
            if op.fblock.fp is None or op.fblock.pas is not None:
                raise NotImplementedError("solve_method='xblock_sparse_pc_gmres' currently targets full-FP RHSMode=1 systems.")

            def _env_float(name: str, default: float) -> float:
                raw = os.environ.get(name, "").strip()
                try:
                    return float(raw) if raw else float(default)
                except ValueError:
                    return float(default)

            xblock_drop_tol = _env_float("SFINCS_JAX_RHSMODE1_XBLOCK_PC_DROP_TOL", 0.0)
            xblock_drop_rel = _env_float("SFINCS_JAX_RHSMODE1_XBLOCK_PC_DROP_REL", 1.0e-8)
            xblock_ilu_drop_tol = _env_float("SFINCS_JAX_RHSMODE1_XBLOCK_PC_ILU_DROP_TOL", 1.0e-4)
            xblock_fill_factor = _env_float("SFINCS_JAX_RHSMODE1_XBLOCK_PC_FILL_FACTOR", 10.0)
            xblock_preconditioner_xi = int(preconditioner_xi)
            if xblock_preconditioner_xi == 0:
                xblock_preconditioner_xi = 1
            force_assembled_env = os.environ.get(
                "SFINCS_JAX_RHSMODE1_XBLOCK_PC_ASSEMBLED_HOST",
                "",
            ).strip().lower()
            force_assembled_host_fp = force_assembled_env not in {"0", "false", "f", "no", "off", ".false.", ".f."}
            xblock_assembled_host_fp = bool(
                (
                    bool(force_assembled_host_fp)
                    and int(op.rhs_mode) == 1
                    and (not bool(op.include_phi1))
                    and op.fblock.fp is not None
                    and op.fblock.pas is None
                    and _rhsmode1_fp_xblock_species_decoupled_for_host_assembly(
                        op=op,
                        preconditioner_species=preconditioner_species,
                    )
                    and int(xblock_preconditioner_xi) == 1
                    and (not bool(op.point_at_x0))
                )
                or _rhsmode1_fp_xblock_assembled_host_allowed(
                    op=op,
                    preconditioner_species=preconditioner_species,
                    preconditioner_xi=xblock_preconditioner_xi,
                    use_implicit=False,
                )
            )
            xblock_krylov_env = os.environ.get("SFINCS_JAX_RHSMODE1_XBLOCK_PC_KRYLOV", "").strip().lower()
            xblock_krylov_requested, _xblock_krylov_unknown_early = _rhs1_xblock_policy.rhs1_xblock_krylov_method(
                xblock_krylov_env
            )
            xblock_device_fgmres_requested = str(xblock_krylov_requested) == "fgmres_jax"
            xblock_device_gmres_requested = str(xblock_krylov_requested) == "gmres_jax"
            xblock_device_krylov_requested = bool(xblock_device_fgmres_requested or xblock_device_gmres_requested)
            xblock_jax_factors_env = os.environ.get("SFINCS_JAX_RHSMODE1_XBLOCK_PC_JAX_FACTORS", "").strip().lower()
            xblock_jax_factors = _rhs1_bool_env(
                "SFINCS_JAX_RHSMODE1_XBLOCK_PC_JAX_FACTORS",
                default=False,
            ) or bool(xblock_device_krylov_requested)
            xblock_device_krylov_forced_jax_factors = bool(
                xblock_device_krylov_requested
                and xblock_jax_factors_env not in {"1", "true", "t", "yes", "on", ".true.", ".t."}
            )
            if emit is not None:
                factor_backend = "jax" if bool(xblock_jax_factors) else "host"
                factor_reason = " device-krylov" if bool(xblock_device_krylov_forced_jax_factors) else ""
                emit(
                    1,
                    "solve_v3_full_system_linear_gmres: xblock_sparse_pc_gmres building "
                    f"{factor_backend} x-block preconditioner preconditioner_xi={int(xblock_preconditioner_xi)}"
                    f"{factor_reason}",
                )
            factor_start_s = sparse_timer.elapsed_s()
            precond_xblock = _build_rhsmode1_xblock_tz_sparse_preconditioner(
                op=op,
                build_jax_factors=bool(xblock_jax_factors),
                preconditioner_species=preconditioner_species,
                preconditioner_xi=xblock_preconditioner_xi,
                drop_tol=xblock_drop_tol,
                drop_rel=xblock_drop_rel,
                ilu_drop_tol=xblock_ilu_drop_tol,
                fill_factor=xblock_fill_factor,
                force_assembled_host_fp=bool(force_assembled_host_fp),
                emit=emit,
            )
            pc_factor_s = sparse_timer.elapsed_s() - factor_start_s
            setup_s = sparse_timer.elapsed_s()

            side_env = os.environ.get("SFINCS_JAX_GMRES_PRECONDITION_SIDE", "").strip().lower()
            full_fp_3d_right_pc_max_env = os.environ.get(
                "SFINCS_JAX_RHSMODE1_XBLOCK_RIGHT_PC_MAX", ""
            ).strip()
            full_fp_3d_pc = bool(
                op.fblock.fp is not None
                and op.fblock.pas is None
                and int(getattr(op, "n_zeta", 1)) > 1
            )
            xblock_policy = resolve_rhs1_xblock_sparse_pc_policy(
                precondition_side_env_value=side_env,
                krylov_env_value=xblock_krylov_env,
                requested_restart=int(pc_restart),
                restart_env_value=pc_restart_env,
                tokamak_fp_er_pc=bool(tokamak_fp_er_pc),
                full_fp_3d_pc=bool(full_fp_3d_pc),
                active_size=int(active_size),
                full_fp_3d_right_pc_max_env_value=full_fp_3d_right_pc_max_env,
                use_dkes=bool(use_dkes),
                include_xdot=bool(include_xdot_sparse_pc),
                include_electric_field_xi=bool(include_electric_field_xi_sparse_pc),
            )
            precondition_side = xblock_policy.precondition_side
            xblock_default_right_pc = xblock_policy.default_right_preconditioned
            xblock_krylov_method = xblock_policy.krylov_method
            xblock_device_fgmres_forced_right_pc = False
            if str(xblock_krylov_method) == "fgmres_jax" and str(precondition_side) == "left":
                precondition_side = "right"
                xblock_device_fgmres_forced_right_pc = True
            pc_restart = xblock_policy.gmres_restart
            xblock_default_restart_capped = xblock_policy.restart_capped
            if xblock_policy.ignored_krylov_env:
                if emit is not None:
                    emit(
                        1,
                        "solve_v3_full_system_linear_gmres: xblock_sparse_pc_gmres "
                        f"ignoring unknown SFINCS_JAX_RHSMODE1_XBLOCK_PC_KRYLOV={xblock_krylov_env!r}",
                )
            progress_every_env = os.environ.get("SFINCS_JAX_SPARSE_PC_PROGRESS_EVERY", "").strip()
            try:
                progress_every = int(progress_every_env) if progress_every_env else 25
            except ValueError:
                progress_every = 25
            progress_every = max(0, int(progress_every))
            mv_count = 0

            xblock_linear_size = int(op.total_size)
            xblock_active_idx_np: np.ndarray | None = None
            xblock_rhs = rhs
            if xblock_use_active_dof:
                assert active_idx_jnp is not None
                assert full_to_active_jnp is not None
                xblock_active_idx_np = np.asarray(jax.device_get(active_idx_jnp), dtype=np.int32)
                xblock_linear_size = int(xblock_active_idx_np.shape[0])
                xblock_rhs = rhs[active_idx_jnp]
                if emit is not None:
                    emit(
                        1,
                        "solve_v3_full_system_linear_gmres: xblock_sparse_pc_gmres active-DOF reduction "
                        f"enabled (size={int(xblock_linear_size)}/{int(op.total_size)})",
                    )

            def _xblock_reduce_full(v_full: jnp.ndarray) -> jnp.ndarray:
                if not xblock_use_active_dof:
                    return v_full
                assert active_idx_jnp is not None
                return v_full[active_idx_jnp]

            def _xblock_expand_reduced(v_vec: jnp.ndarray) -> jnp.ndarray:
                if not xblock_use_active_dof:
                    return v_vec
                assert full_to_active_jnp is not None
                z0 = jnp.zeros((1,), dtype=v_vec.dtype)
                padded = jnp.concatenate([z0, v_vec], axis=0)
                return padded[full_to_active_jnp]

            def _mv_true_no_count(v: jnp.ndarray) -> jnp.ndarray:
                x_full = _xblock_expand_reduced(jnp.asarray(v, dtype=rhs.dtype))
                y_full = apply_v3_full_system_operator_cached(op, x_full)
                return _xblock_reduce_full(y_full)

            def _mv_true(v: jnp.ndarray) -> jnp.ndarray:
                nonlocal mv_count
                mv_count += 1
                if emit is not None and progress_every > 0 and mv_count % progress_every == 0:
                    emit(
                        1,
                        "solve_v3_full_system_linear_gmres: xblock_sparse_pc_gmres "
                        f"matvecs={int(mv_count)} elapsed_s={sparse_timer.elapsed_s():.3f}",
                    )
                return _mv_true_no_count(v)

            _mv_xblock_krylov = _mv_true

            def _precond_xblock_krylov_base(v: jnp.ndarray) -> jnp.ndarray:
                if not xblock_use_active_dof:
                    return precond_xblock(v)
                z_full = precond_xblock(_xblock_expand_reduced(jnp.asarray(v, dtype=rhs.dtype)))
                return _xblock_reduce_full(z_full)

            assembled_operator_enabled = _rhs1_bool_env(
                "SFINCS_JAX_RHSMODE1_XBLOCK_ASSEMBLED_OPERATOR",
                default=False,
            )
            assembled_operator_built = False
            assembled_operator_metadata: dict[str, object] = {}
            if assembled_operator_enabled:
                assembled_operator_start_s = sparse_timer.elapsed_s()
                try:
                    if emit is not None:
                        emit(
                            1,
                            "solve_v3_full_system_linear_gmres: xblock_sparse_pc_gmres "
                            "building assembled operator for Krylov matvec reuse",
                        )
                    assembled_csr_max_mb = _rhs1_float_env(
                        "SFINCS_JAX_RHSMODE1_XBLOCK_ASSEMBLED_OPERATOR_CSR_MAX_MB",
                        default=2048.0,
                        minimum=0.0,
                    )
                    assembled_drop_tol = _rhs1_float_env(
                        "SFINCS_JAX_RHSMODE1_XBLOCK_ASSEMBLED_OPERATOR_DROP_TOL",
                        default=0.0,
                        minimum=0.0,
                    )
                    assembled_max_colors = _rhs1_int_env(
                        "SFINCS_JAX_RHSMODE1_XBLOCK_ASSEMBLED_OPERATOR_MAX_COLORS",
                        default=512,
                        minimum=1,
                    )
                    def _csr_storage_nbytes(*, nnz: int, n_rows: int) -> int:
                        return int(
                            int(nnz) * (np.dtype(np.float64).itemsize + np.dtype(np.int32).itemsize)
                            + (int(n_rows) + 1) * np.dtype(np.int32).itemsize
                        )

                    assembled_preflight = estimate_v3_full_system_conservative_sparsity_summary(
                        op,
                        fp_dense_velocity_block=sparse_pc_fp_dense_velocity_block,
                    )
                    assembled_preflight_csr_nbytes = _csr_storage_nbytes(
                        nnz=int(assembled_preflight.nnz),
                        n_rows=int(assembled_preflight.shape[0]),
                    )
                    assembled_preflight_peak_nbytes = int(3 * assembled_preflight_csr_nbytes)
                    assembled_csr_cap_nbytes = int(max(0.0, float(assembled_csr_max_mb)) * 1.0e6)
                    assembled_pattern = None
                    assembled_preflight_scope = "full"
                    assembled_operator_metadata.update(
                        {
                            "active_dof": bool(xblock_active_idx_np is not None),
                            "preflight_scope": assembled_preflight_scope,
                            "preflight_pattern_nnz_estimate": int(assembled_preflight.nnz),
                            "preflight_pattern_max_row_nnz_estimate": int(assembled_preflight.max_row_nnz),
                            "preflight_csr_nbytes_estimate": int(assembled_preflight_csr_nbytes),
                            "preflight_peak_nbytes_estimate": int(assembled_preflight_peak_nbytes),
                            "preflight_full_pattern_nnz_estimate": int(assembled_preflight.nnz),
                            "preflight_full_csr_nbytes_estimate": int(assembled_preflight_csr_nbytes),
                            "preflight_csr_max_mb": float(assembled_csr_max_mb),
                            "preflight_rejected": False,
                        }
                    )
                    if assembled_csr_cap_nbytes <= 0:
                        assembled_operator_metadata["preflight_rejected"] = True
                        raise MemoryError(
                            "assembled x-block operator preflight rejected non-positive CSR memory budget "
                            f"{float(assembled_csr_max_mb):.3g} MB"
                        )
                    if xblock_active_idx_np is not None:
                        # The full-system conservative estimate can be several times
                        # larger than the actual active-DOF Krylov operator when
                        # ``Nxi_for_x`` truncation is enabled. Build the reduced
                        # structural pattern directly and apply the memory gate to
                        # the matrix that will actually be probed.
                        assembled_pattern = v3_full_system_conservative_sparsity_pattern_for_indices(
                            op,
                            xblock_active_idx_np,
                            fp_dense_velocity_block=sparse_pc_fp_dense_velocity_block,
                        )
                        active_preflight = summarize_v3_sparse_pattern(op, assembled_pattern)
                        assembled_preflight_scope = "active_dof"
                        assembled_preflight_csr_nbytes = _csr_storage_nbytes(
                            nnz=int(active_preflight.nnz),
                            n_rows=int(active_preflight.shape[0]),
                        )
                        assembled_preflight_peak_nbytes = int(3 * assembled_preflight_csr_nbytes)
                        assembled_operator_metadata.update(
                            {
                                "preflight_scope": assembled_preflight_scope,
                                "preflight_pattern_nnz_estimate": int(active_preflight.nnz),
                                "preflight_pattern_max_row_nnz_estimate": int(active_preflight.max_row_nnz),
                                "preflight_csr_nbytes_estimate": int(assembled_preflight_csr_nbytes),
                                "preflight_peak_nbytes_estimate": int(assembled_preflight_peak_nbytes),
                                "preflight_active_pattern_nnz_estimate": int(active_preflight.nnz),
                                "preflight_active_csr_nbytes_estimate": int(assembled_preflight_csr_nbytes),
                            }
                        )
                    if assembled_preflight_csr_nbytes > assembled_csr_cap_nbytes:
                        assembled_operator_metadata["preflight_rejected"] = True
                        raise MemoryError(
                            "assembled x-block operator preflight rejected "
                            f"{assembled_preflight_scope} CSR estimate "
                            f"{assembled_preflight_csr_nbytes / 1.0e6:.3g} MB > "
                            f"{float(assembled_csr_max_mb):.3g} MB"
                        )
                    if assembled_pattern is None:
                        assembled_pattern = v3_full_system_conservative_sparsity_pattern(
                            op,
                            fp_dense_velocity_block=sparse_pc_fp_dense_velocity_block,
                        )
                    assembled_summary = summarize_v3_sparse_pattern(op, assembled_pattern)

                    def _matvec_np_no_count(x_np: np.ndarray) -> np.ndarray:
                        return np.asarray(
                            jax.device_get(
                                _mv_true_no_count(jnp.asarray(np.asarray(x_np, dtype=np.float64), dtype=rhs.dtype))
                            ),
                            dtype=np.float64,
                        ).reshape((-1,))

                    assembled_bundle = build_operator_from_pattern(
                        _matvec_np_no_count,
                        pattern=assembled_pattern,
                        dtype=np.float64,
                        backend=jax.default_backend(),
                        csr_max_mb=float(assembled_csr_max_mb),
                        drop_tol=float(assembled_drop_tol),
                        allow_operator_only=False,
                        max_colors=int(assembled_max_colors),
                    )
                    assembled_matrix = assembled_bundle.matrix
                    if assembled_matrix is None:
                        raise RuntimeError("assembled x-block operator materialization returned no matrix")
                    validation_samples = _rhs1_int_env(
                        "SFINCS_JAX_RHSMODE1_XBLOCK_ASSEMBLED_OPERATOR_VALIDATE",
                        default=1,
                        minimum=0,
                    )
                    validation_tol = _rhs1_float_env(
                        "SFINCS_JAX_RHSMODE1_XBLOCK_ASSEMBLED_OPERATOR_VALIDATE_RTOL",
                        default=1.0e-8,
                        minimum=0.0,
                    )
                    validation_errors: list[float] = []
                    rng = np.random.default_rng(1729)
                    for _ in range(int(validation_samples)):
                        probe = rng.standard_normal(int(xblock_linear_size)).astype(np.float64)
                        probe_norm = float(np.linalg.norm(probe))
                        if np.isfinite(probe_norm) and probe_norm > 0.0:
                            probe /= probe_norm
                        ref = _matvec_np_no_count(probe)
                        got = np.asarray(assembled_bundle.matvec(probe), dtype=np.float64).reshape((-1,))
                        denom = max(float(np.linalg.norm(ref)), 1.0e-300)
                        rel = float(np.linalg.norm(got - ref) / denom)
                        validation_errors.append(rel)
                    max_validation_error = max(validation_errors, default=0.0)
                    if max_validation_error > float(validation_tol):
                        raise RuntimeError(
                            "assembled x-block operator validation failed "
                            f"max_rel_error={max_validation_error:.3e} > {float(validation_tol):.3e}"
                        )

                    def _mv_assembled(v: jnp.ndarray) -> jnp.ndarray:
                        nonlocal mv_count
                        mv_count += 1
                        if emit is not None and progress_every > 0 and mv_count % progress_every == 0:
                            emit(
                                1,
                                "solve_v3_full_system_linear_gmres: xblock_sparse_pc_gmres "
                                f"assembled_matvecs={int(mv_count)} elapsed_s={sparse_timer.elapsed_s():.3f}",
                            )
                        v_np = np.asarray(jax.device_get(v), dtype=np.float64).reshape((-1,))
                        return jnp.asarray(assembled_bundle.matvec(v_np), dtype=jnp.float64)

                    _mv_xblock_krylov = _mv_assembled
                    assembled_operator_built = True
                    if hasattr(assembled_matrix, "nnz"):
                        assembled_matrix_nnz = int(assembled_matrix.nnz)
                    else:
                        assembled_matrix_nnz = int(np.count_nonzero(np.asarray(assembled_matrix)))
                    assembled_operator_metadata = {
                        **assembled_operator_metadata,
                        "setup_s": float(sparse_timer.elapsed_s() - assembled_operator_start_s),
                        "pattern_nnz": int(assembled_summary.nnz),
                        "pattern_avg_row_nnz": float(assembled_summary.avg_row_nnz),
                        "pattern_max_row_nnz": int(assembled_summary.max_row_nnz),
                        "storage_kind": assembled_bundle.metadata.storage_kind,
                        "reason": assembled_bundle.metadata.reason,
                        "matrix_nnz": int(assembled_matrix_nnz),
                        "csr_nbytes_estimate": int(assembled_bundle.metadata.csr_nbytes_estimate),
                        "max_colors": int(assembled_max_colors),
                        "validation_rel_errors": tuple(float(v) for v in validation_errors),
                    }
                    pc_factor_s += float(assembled_operator_metadata["setup_s"])
                    if emit is not None:
                        emit(
                            0,
                            "solve_v3_full_system_linear_gmres: xblock_sparse_pc_gmres assembled operator "
                            f"built nnz={assembled_operator_metadata['matrix_nnz']} "
                            f"setup_s={assembled_operator_metadata['setup_s']:.3f}",
                        )
                except Exception as exc:  # noqa: BLE001
                    assembled_operator_metadata = {
                        **assembled_operator_metadata,
                        "error": f"{type(exc).__name__}: {exc}",
                        "setup_s": float(sparse_timer.elapsed_s() - assembled_operator_start_s),
                    }
                    if emit is not None:
                        emit(
                            1,
                            "solve_v3_full_system_linear_gmres: xblock_sparse_pc_gmres "
                            f"assembled operator disabled after build failure ({type(exc).__name__}: {exc})",
                        )

            precond_xblock_krylov = _precond_xblock_krylov_base
            two_level_enabled = _rhs1_bool_env("SFINCS_JAX_RHSMODE1_XBLOCK_PC_TWO_LEVEL", default=False)
            two_level_built = False
            two_level_metadata: dict[str, object] = {}
            two_level_stats = {"applies": 0, "coarse_applies": 0}
            if two_level_enabled and precondition_side != "none":
                two_level_start_s = sparse_timer.elapsed_s()
                two_level_mode = os.environ.get(
                    "SFINCS_JAX_RHSMODE1_XBLOCK_PC_TWO_LEVEL_MODE",
                    "additive",
                ).strip()
                two_level_max_directions = _rhs1_int_env(
                    "SFINCS_JAX_RHSMODE1_XBLOCK_PC_TWO_LEVEL_MAX_DIRECTIONS",
                    default=48,
                    minimum=1,
                )
                two_level_fsavg_lmax = _rhs1_int_env(
                    "SFINCS_JAX_RHSMODE1_XBLOCK_PC_TWO_LEVEL_FSAVG_LMAX",
                    default=8,
                    minimum=0,
                )
                two_level_max_extra_units = _rhs1_int_env(
                    "SFINCS_JAX_RHSMODE1_XBLOCK_PC_TWO_LEVEL_MAX_EXTRA_UNITS",
                    default=8,
                    minimum=0,
                )
                two_level_rcond = _rhs1_float_env(
                    "SFINCS_JAX_RHSMODE1_XBLOCK_PC_TWO_LEVEL_RCOND",
                    default=1.0e-11,
                    minimum=0.0,
                )
                two_level_include_rhs = _rhs1_bool_env(
                    "SFINCS_JAX_RHSMODE1_XBLOCK_PC_TWO_LEVEL_INCLUDE_RHS",
                    default=True,
                )
                try:
                    precond_xblock_krylov, two_level_metadata, two_level_stats = (
                        _build_rhs1_xblock_two_level_preconditioner(
                            op=op,
                            rhs=rhs,
                            matvec=_mv_xblock_krylov,
                            base_preconditioner=precond_xblock_krylov,
                            direction_projector=_xblock_reduce_full if xblock_use_active_dof else None,
                            expected_size=int(xblock_linear_size),
                            mode=two_level_mode,
                            fsavg_lmax=two_level_fsavg_lmax,
                            max_extra_units=two_level_max_extra_units,
                            max_directions=two_level_max_directions,
                            rcond=two_level_rcond,
                            include_rhs=two_level_include_rhs,
                            emit=emit,
                        )
                    )
                    two_level_built = True
                    two_level_metadata["setup_s"] = float(sparse_timer.elapsed_s() - two_level_start_s)
                    pc_factor_s += float(two_level_metadata["setup_s"])
                except Exception as exc:  # noqa: BLE001
                    two_level_metadata = {
                        "error": f"{type(exc).__name__}: {exc}",
                        "setup_s": float(sparse_timer.elapsed_s() - two_level_start_s),
                    }
                    if emit is not None:
                        emit(
                            1,
                            "solve_v3_full_system_linear_gmres: xblock_sparse_pc_gmres "
                            f"two-level coarse disabled after build failure ({type(exc).__name__}: {exc})",
                        )

            global_coupling_enabled = _rhs1_bool_env(
                "SFINCS_JAX_RHSMODE1_XBLOCK_PC_GLOBAL_COUPLING",
                default=False,
            )
            global_coupling_built = False
            global_coupling_metadata: dict[str, object] = {}
            global_coupling_stats = {"applies": 0, "coarse_applies": 0}
            if global_coupling_enabled and precondition_side != "none":
                global_coupling_start_s = sparse_timer.elapsed_s()
                global_coupling_mode = os.environ.get(
                    "SFINCS_JAX_RHSMODE1_XBLOCK_PC_GLOBAL_COUPLING_MODE",
                    "additive",
                ).strip()
                global_coupling_max_directions = _rhs1_int_env(
                    "SFINCS_JAX_RHSMODE1_XBLOCK_PC_GLOBAL_COUPLING_MAX_DIRECTIONS",
                    default=96,
                    minimum=1,
                )
                global_coupling_fsavg_lmax = _rhs1_int_env(
                    "SFINCS_JAX_RHSMODE1_XBLOCK_PC_GLOBAL_COUPLING_FSAVG_LMAX",
                    default=12,
                    minimum=0,
                )
                global_coupling_angular_lmax = _rhs1_int_env(
                    "SFINCS_JAX_RHSMODE1_XBLOCK_PC_GLOBAL_COUPLING_ANGULAR_LMAX",
                    default=2,
                    minimum=0,
                )
                global_coupling_max_extra_units = _rhs1_int_env(
                    "SFINCS_JAX_RHSMODE1_XBLOCK_PC_GLOBAL_COUPLING_MAX_EXTRA_UNITS",
                    default=8,
                    minimum=0,
                )
                global_coupling_rcond = _rhs1_float_env(
                    "SFINCS_JAX_RHSMODE1_XBLOCK_PC_GLOBAL_COUPLING_RCOND",
                    default=1.0e-11,
                    minimum=0.0,
                )
                global_coupling_include_rhs = _rhs1_bool_env(
                    "SFINCS_JAX_RHSMODE1_XBLOCK_PC_GLOBAL_COUPLING_INCLUDE_RHS",
                    default=True,
                )
                try:
                    global_builder = (
                        _build_rhs1_xblock_device_global_coupling_preconditioner
                        if str(xblock_krylov_method) in {"fgmres_jax", "gmres_jax"}
                        else _build_rhs1_xblock_smoothed_global_coupling_preconditioner
                    )
                    precond_xblock_krylov, global_coupling_metadata, global_coupling_stats = (
                        global_builder(
                            op=op,
                            rhs=rhs,
                            matvec=_mv_xblock_krylov,
                            base_preconditioner=precond_xblock_krylov,
                            direction_projector=_xblock_reduce_full if xblock_use_active_dof else None,
                            expected_size=int(xblock_linear_size),
                            mode=global_coupling_mode,
                            fsavg_lmax=global_coupling_fsavg_lmax,
                            angular_lmax=global_coupling_angular_lmax,
                            max_extra_units=global_coupling_max_extra_units,
                            max_directions=global_coupling_max_directions,
                            rcond=global_coupling_rcond,
                            include_rhs=global_coupling_include_rhs,
                            emit=emit,
                        )
                    )
                    global_coupling_built = True
                    global_coupling_metadata["setup_s"] = float(sparse_timer.elapsed_s() - global_coupling_start_s)
                    pc_factor_s += float(global_coupling_metadata["setup_s"])
                except Exception as exc:  # noqa: BLE001
                    global_coupling_metadata = {
                        "error": f"{type(exc).__name__}: {exc}",
                        "setup_s": float(sparse_timer.elapsed_s() - global_coupling_start_s),
                    }
                    if emit is not None:
                        emit(
                            1,
                            "solve_v3_full_system_linear_gmres: xblock_sparse_pc_gmres "
                            f"global-coupling disabled after build failure ({type(exc).__name__}: {exc})",
                        )

            setup_s = sparse_timer.elapsed_s()
            x0_full = None
            if x0 is not None:
                x0_arr = jnp.asarray(x0, dtype=jnp.float64)
                if x0_arr.shape == xblock_rhs.shape:
                    x0_full = x0_arr
                elif xblock_use_active_dof and x0_arr.shape == rhs.shape:
                    x0_full = _xblock_reduce_full(x0_arr)
                elif emit is not None:
                    emit(
                        1,
                        "solve_v3_full_system_linear_gmres: xblock_sparse_pc_gmres ignoring incompatible x0 "
                        f"shape={tuple(x0_arr.shape)} expected={tuple(xblock_rhs.shape)}"
                        + (f" or {tuple(rhs.shape)}" if xblock_use_active_dof else ""),
                    )
            xblock_initial_seed_used = False
            xblock_initial_seed_residual_norm: float | None = None
            xblock_initial_seed_residual_ratio: float | None = None
            seed_env = os.environ.get("SFINCS_JAX_RHSMODE1_XBLOCK_PC_INITIAL_SEED", "").strip().lower()
            seed_enabled = seed_env in {"1", "true", "t", "yes", "on", ".true.", ".t."}
            if x0_full is None and seed_enabled:
                try:
                    seed_vec = jnp.asarray(precond_xblock_krylov(xblock_rhs), dtype=jnp.float64)
                    if seed_vec.shape == xblock_rhs.shape and bool(jnp.all(jnp.isfinite(seed_vec))):
                        seed_residual = xblock_rhs - _mv_true(seed_vec)
                        seed_residual_norm = float(jnp.linalg.norm(seed_residual))
                        rhs_norm_float = float(jnp.linalg.norm(xblock_rhs))
                        xblock_initial_seed_residual_norm = float(seed_residual_norm)
                        xblock_initial_seed_residual_ratio = (
                            float(seed_residual_norm) / rhs_norm_float if rhs_norm_float > 0.0 else None
                        )
                        if np.isfinite(seed_residual_norm) and seed_residual_norm < rhs_norm_float:
                            x0_full = seed_vec
                            xblock_initial_seed_used = True
                            if emit is not None:
                                emit(
                                    0,
                                    "solve_v3_full_system_linear_gmres: xblock_sparse_pc_gmres "
                                    f"initial x-block seed residual={seed_residual_norm:.6e} "
                                    f"rhs_norm={rhs_norm_float:.6e}",
                                )
                        elif emit is not None:
                            emit(
                                1,
                                "solve_v3_full_system_linear_gmres: xblock_sparse_pc_gmres "
                                f"initial x-block seed rejected residual={seed_residual_norm:.6e} "
                                f"rhs_norm={rhs_norm_float:.6e}",
                            )
                except Exception as exc:  # noqa: BLE001
                    if emit is not None:
                        emit(
                            1,
                            "solve_v3_full_system_linear_gmres: xblock_sparse_pc_gmres "
                            f"initial x-block seed failed ({type(exc).__name__}: {exc})",
                        )

            xblock_rhs_norm = float(jnp.linalg.norm(xblock_rhs))
            target_xblock = max(float(atol), float(tol) * float(xblock_rhs_norm))
            xblock_side_probe_enabled = _rhs1_xblock_policy.rhs1_xblock_side_probe_enabled(
                env_value=os.environ.get("SFINCS_JAX_RHSMODE1_XBLOCK_PC_SIDE_PROBE", ""),
                explicit_side_env_value=side_env,
                full_fp_3d_pc=bool(full_fp_3d_pc),
                active_size=int(active_size),
                min_active_size_env_value=os.environ.get(
                    "SFINCS_JAX_RHSMODE1_XBLOCK_PC_SIDE_PROBE_MIN_ACTIVE",
                    "",
                ),
                krylov_method=str(xblock_krylov_method),
                precondition_side=str(precondition_side),
            )
            xblock_side_probe_used = False
            xblock_side_probe_switched = False
            xblock_side_probe_initial_side: str | None = None
            xblock_side_probe_selected_side: str | None = None
            xblock_side_probe_initial_method: str | None = None
            xblock_side_probe_selected_method: str | None = None
            xblock_side_probe_lgmres_rescue = False
            xblock_lgmres_rescue_maxiter_capped = False
            xblock_lgmres_rescue_outer_k: int | None = None
            xblock_side_probe_residual_norm: float | None = None
            xblock_side_probe_residual_ratio: float | None = None
            xblock_side_probe_iterations = 0
            xblock_side_probe_matvecs = 0
            xblock_side_probe_s = 0.0
            xblock_side_probe_switch_suppressed_by_global_coupling = False
            xblock_side_probe_physical_seed_preserved_after_switch = False
            if xblock_side_probe_enabled:
                xblock_side_probe_used = True
                xblock_side_probe_initial_side = str(precondition_side)
                xblock_side_probe_initial_method = str(xblock_krylov_method)
                probe_restart = _rhs1_int_env(
                    "SFINCS_JAX_RHSMODE1_XBLOCK_PC_SIDE_PROBE_RESTART",
                    default=int(pc_restart),
                    minimum=2,
                )
                probe_maxiter = _rhs1_int_env(
                    "SFINCS_JAX_RHSMODE1_XBLOCK_PC_SIDE_PROBE_MAXITER",
                    default=1,
                    minimum=1,
                )
                if emit is not None:
                    emit(
                        0,
                        "solve_v3_full_system_linear_gmres: xblock_sparse_pc_gmres side probe start "
                        f"side={precondition_side} restart={int(probe_restart)} maxiter={int(probe_maxiter)}",
                    )
                probe_start_s = sparse_timer.elapsed_s()
                probe_start_mv = int(mv_count)
                try:
                    x_probe, residual_probe, history_probe = gmres_solve_with_history_scipy(
                        matvec=_mv_xblock_krylov,
                        b=xblock_rhs,
                        preconditioner=precond_xblock_krylov if precondition_side != "none" else None,
                        x0=x0_full,
                        tol=tol,
                        atol=atol,
                        restart=probe_restart,
                        maxiter=probe_maxiter,
                        precondition_side=precondition_side,
                    )
                    xblock_side_probe_s = float(sparse_timer.elapsed_s() - probe_start_s)
                    xblock_side_probe_matvecs = int(mv_count) - int(probe_start_mv)
                    xblock_side_probe_iterations = int(len(history_probe or []))
                    xblock_side_probe_residual_norm = float(residual_probe)
                    xblock_side_probe_residual_ratio = (
                        float(residual_probe) / float(target_xblock) if float(target_xblock) > 0.0 else None
                    )
                    if str(precondition_side) == "left":
                        x0_full = jnp.asarray(x_probe, dtype=jnp.float64)
                    should_switch_side = _rhs1_xblock_policy.rhs1_xblock_side_probe_should_switch(
                        residual_ratio=xblock_side_probe_residual_ratio,
                        switch_ratio_env_value=os.environ.get(
                            "SFINCS_JAX_RHSMODE1_XBLOCK_PC_SIDE_PROBE_SWITCH_RATIO",
                            "",
                        ),
                    )
                    lgmres_rescue_env = os.environ.get("SFINCS_JAX_RHSMODE1_XBLOCK_PC_LGMRES_RESCUE", "")
                    lgmres_rescue_forced = lgmres_rescue_env.strip().lower() in {
                        "1",
                        "true",
                        "t",
                        "yes",
                        "on",
                        ".true.",
                        ".t.",
                    }
                    lgmres_rescue_backend_allowed = str(jax.default_backend()).strip().lower() == "cpu"
                    lgmres_rescue_enabled = _rhs1_xblock_policy.rhs1_xblock_lgmres_rescue_enabled(
                        env_value=os.environ.get("SFINCS_JAX_RHSMODE1_XBLOCK_PC_LGMRES_RESCUE", ""),
                        krylov_env_value=xblock_krylov_env,
                    ) and (bool(lgmres_rescue_backend_allowed) or bool(lgmres_rescue_forced))
                    if (
                        should_switch_side
                        and bool(global_coupling_built)
                        and (not bool(lgmres_rescue_enabled))
                        and str(precondition_side) == "left"
                    ):
                        keep_left_ratio = _rhs1_float_env(
                            "SFINCS_JAX_RHSMODE1_XBLOCK_PC_GLOBAL_COUPLING_KEEP_LEFT_RATIO",
                            default=1.0e6,
                            minimum=1.0,
                        )
                        if (
                            xblock_side_probe_residual_ratio is not None
                            and np.isfinite(float(xblock_side_probe_residual_ratio))
                            and float(xblock_side_probe_residual_ratio) <= float(keep_left_ratio)
                        ):
                            should_switch_side = False
                            xblock_side_probe_switch_suppressed_by_global_coupling = True
                    if should_switch_side and lgmres_rescue_enabled and str(precondition_side) == "left":
                        # Reuse the physical-space left-probe state: for these
                        # large 3D full-FP systems the measured slow mode is
                        # GMRES restart sensitivity, not the x-block factors.
                        xblock_krylov_method = "lgmres"
                        xblock_side_probe_lgmres_rescue = True
                        pc_maxiter, xblock_lgmres_rescue_maxiter_capped = (
                            _rhs1_xblock_policy.rhs1_xblock_lgmres_rescue_maxiter(
                                os.environ.get("SFINCS_JAX_RHSMODE1_XBLOCK_PC_LGMRES_RESCUE_MAXITER", ""),
                                int(pc_maxiter),
                            )
                        )
                        xblock_lgmres_rescue_outer_k = _rhs1_xblock_policy.rhs1_xblock_lgmres_rescue_outer_k(
                            os.environ.get("SFINCS_JAX_RHSMODE1_XBLOCK_PC_LGMRES_RESCUE_OUTER_K", "")
                        )
                    elif should_switch_side:
                        precondition_side = "right" if str(precondition_side) == "left" else "left"
                        xblock_side_probe_switched = True
                        if str(precondition_side) == "right" and x0_full is not None:
                            xblock_side_probe_physical_seed_preserved_after_switch = True
                    xblock_side_probe_selected_side = str(precondition_side)
                    xblock_side_probe_selected_method = str(xblock_krylov_method)
                    if emit is not None:
                        if xblock_side_probe_lgmres_rescue:
                            action = "method_rescue"
                        elif xblock_side_probe_switch_suppressed_by_global_coupling:
                            action = "keep_global_coupling"
                        else:
                            action = "switch" if xblock_side_probe_switched else "keep"
                        emit(
                            0,
                            "solve_v3_full_system_linear_gmres: xblock_sparse_pc_gmres side probe "
                            f"{action} side={xblock_side_probe_initial_side}->{xblock_side_probe_selected_side} "
                            f"method={xblock_side_probe_initial_method}->{xblock_side_probe_selected_method} "
                            f"iters={xblock_side_probe_iterations} matvecs={xblock_side_probe_matvecs} "
                            f"residual={float(xblock_side_probe_residual_norm):.6e} "
                            f"ratio={float(xblock_side_probe_residual_ratio):.6e}"
                            + (
                                " preserved_physical_seed=1"
                                if xblock_side_probe_physical_seed_preserved_after_switch
                                else ""
                            ),
                        )
                except Exception as exc:  # noqa: BLE001
                    xblock_side_probe_s = float(sparse_timer.elapsed_s() - probe_start_s)
                    xblock_side_probe_selected_side = str(precondition_side)
                    xblock_side_probe_selected_method = str(xblock_krylov_method)
                    if emit is not None:
                        emit(
                            1,
                            "solve_v3_full_system_linear_gmres: xblock_sparse_pc_gmres "
                            f"side probe failed ({type(exc).__name__}: {exc}); keeping side={precondition_side}",
                        )

            if precondition_side != "none":
                if xblock_use_active_dof:

                    def _coarse_preconditioner_for_basis(v_full: jnp.ndarray) -> jnp.ndarray:
                        reduced = _xblock_reduce_full(jnp.asarray(v_full, dtype=jnp.float64))
                        return _xblock_expand_reduced(precond_xblock_krylov(reduced))

                else:
                    _coarse_preconditioner_for_basis = precond_xblock_krylov
            else:

                def _coarse_preconditioner_for_basis(v_full: jnp.ndarray) -> jnp.ndarray:
                    return jnp.asarray(v_full, dtype=jnp.float64)

            def _xblock_coarse_direction_builder(
                residual_vec: jnp.ndarray,
                *,
                include_raw: bool,
                fsavg_lmax: int,
                max_extra_units: int,
                max_directions: int,
            ) -> tuple[tuple[str, jnp.ndarray], ...]:
                residual_for_basis = (
                    _xblock_expand_reduced(jnp.asarray(residual_vec, dtype=jnp.float64))
                    if xblock_use_active_dof
                    else jnp.asarray(residual_vec, dtype=jnp.float64)
                )
                return _rhs1_xblock_post_coarse_directions(
                    op=op,
                    residual=residual_for_basis,
                    preconditioner=_coarse_preconditioner_for_basis,
                    direction_projector=_xblock_reduce_full if xblock_use_active_dof else None,
                    expected_size=int(xblock_linear_size),
                    include_raw=bool(include_raw),
                    fsavg_lmax=int(fsavg_lmax),
                    max_extra_units=int(max_extra_units),
                    max_directions=int(max_directions),
                )

            probe_coarse_enabled = _rhs1_bool_env(
                "SFINCS_JAX_RHSMODE1_XBLOCK_PC_PROBE_COARSE",
                default=False,
            )
            probe_coarse_steps_requested = (
                _rhs1_int_env("SFINCS_JAX_RHSMODE1_XBLOCK_PC_PROBE_COARSE_STEPS", default=1, minimum=1)
                if probe_coarse_enabled
                else 0
            )
            probe_coarse_max_directions = _rhs1_int_env(
                "SFINCS_JAX_RHSMODE1_XBLOCK_PC_PROBE_COARSE_MAX_DIRECTIONS",
                default=16,
                minimum=1,
            )
            probe_coarse_max_extra_units = _rhs1_int_env(
                "SFINCS_JAX_RHSMODE1_XBLOCK_PC_PROBE_COARSE_MAX_EXTRA_UNITS",
                default=8,
                minimum=0,
            )
            probe_coarse_fsavg_lmax = _rhs1_int_env(
                "SFINCS_JAX_RHSMODE1_XBLOCK_PC_PROBE_COARSE_FSAVG_LMAX",
                default=2,
                minimum=0,
            )
            probe_coarse_include_raw = _rhs1_bool_env(
                "SFINCS_JAX_RHSMODE1_XBLOCK_PC_PROBE_COARSE_INCLUDE_RAW",
                default=True,
            )
            probe_coarse_alpha_clip = _rhs1_float_env(
                "SFINCS_JAX_RHSMODE1_XBLOCK_PC_PROBE_COARSE_ALPHA_CLIP",
                default=0.0,
                minimum=0.0,
            )
            probe_coarse_rcond = _rhs1_float_env(
                "SFINCS_JAX_RHSMODE1_XBLOCK_PC_PROBE_COARSE_RCOND",
                default=1.0e-12,
                minimum=0.0,
            )
            probe_coarse_min_improvement = _rhs1_float_env(
                "SFINCS_JAX_RHSMODE1_XBLOCK_PC_PROBE_COARSE_MIN_IMPROVEMENT",
                default=0.0,
                minimum=0.0,
            )
            probe_coarse_s = 0.0
            probe_coarse_history: tuple[float, ...] = ()
            probe_coarse_direction_counts: tuple[int, ...] = ()
            probe_coarse_direction_names: tuple[str, ...] = ()
            probe_coarse_residual_before: float | None = None
            probe_coarse_residual_after: float | None = None
            if probe_coarse_steps_requested > 0 and x0_full is not None:
                probe_coarse_start_s = sparse_timer.elapsed_s()

                def _probe_coarse_direction_builder(
                    residual_vec: jnp.ndarray,
                ) -> tuple[tuple[str, jnp.ndarray], ...]:
                    return _xblock_coarse_direction_builder(
                        residual_vec,
                        include_raw=bool(probe_coarse_include_raw),
                        fsavg_lmax=int(probe_coarse_fsavg_lmax),
                        max_extra_units=int(probe_coarse_max_extra_units),
                        max_directions=int(probe_coarse_max_directions),
                    )

                try:
                    seed_residual = xblock_rhs - jnp.asarray(_mv_true(jnp.asarray(x0_full, dtype=jnp.float64)))
                    probe_coarse_residual_before = float(jnp.linalg.norm(seed_residual))
                    if (
                        np.isfinite(float(probe_coarse_residual_before))
                        and float(probe_coarse_residual_before) > float(target_xblock)
                    ):
                        (
                            x_probe_coarse,
                            residual_probe_coarse,
                            probe_coarse_history,
                            probe_coarse_direction_counts,
                            probe_coarse_direction_names,
                        ) = _apply_subspace_minres_correction(
                            matvec=_mv_true,
                            rhs=xblock_rhs,
                            x0=jnp.asarray(x0_full, dtype=jnp.float64),
                            direction_builder=_probe_coarse_direction_builder,
                            steps=probe_coarse_steps_requested,
                            max_directions=probe_coarse_max_directions,
                            alpha_clip=probe_coarse_alpha_clip,
                            rcond=probe_coarse_rcond,
                            min_improvement=probe_coarse_min_improvement,
                        )
                        probe_coarse_residual_after = float(jnp.linalg.norm(residual_probe_coarse))
                        if (
                            np.isfinite(float(probe_coarse_residual_after))
                            and float(probe_coarse_residual_after) < float(probe_coarse_residual_before)
                        ):
                            x0_full = jnp.asarray(x_probe_coarse, dtype=jnp.float64)
                            if emit is not None:
                                emit(
                                    0,
                                    "solve_v3_full_system_linear_gmres: xblock_sparse_pc_gmres "
                                    f"probe-coarse improved seed residual {probe_coarse_residual_before:.6e} "
                                    f"-> {probe_coarse_residual_after:.6e} "
                                    f"(steps={len(probe_coarse_direction_counts)} "
                                    f"directions={sum(probe_coarse_direction_counts)})",
                                )
                        elif emit is not None:
                            after = (
                                float(probe_coarse_residual_after)
                                if probe_coarse_residual_after is not None
                                else float("nan")
                            )
                            emit(
                                1,
                                "solve_v3_full_system_linear_gmres: xblock_sparse_pc_gmres "
                                f"probe-coarse rejected seed residual {probe_coarse_residual_before:.6e} "
                                f"-> {after:.6e}",
                            )
                except Exception as exc:  # noqa: BLE001
                    if emit is not None:
                        emit(
                            1,
                            "solve_v3_full_system_linear_gmres: xblock_sparse_pc_gmres "
                            f"probe-coarse failed ({type(exc).__name__}: {exc})",
                        )
                probe_coarse_s = float(sparse_timer.elapsed_s() - probe_coarse_start_s)

            if emit is not None:
                emit(
                    0,
                    "solve_v3_full_system_linear_gmres: xblock_sparse_pc_gmres solve start "
                    f"method={xblock_krylov_method} restart={int(pc_restart)} maxiter={int(pc_maxiter)} "
                    f"precondition_side={precondition_side}",
                )
            solve_start_s = sparse_timer.elapsed_s()
            if xblock_krylov_method == "lgmres":
                x_np, residual_norm_xblock_pc, history = lgmres_solve_with_history_scipy(
                    matvec=_mv_xblock_krylov,
                    b=xblock_rhs,
                    preconditioner=precond_xblock_krylov if precondition_side != "none" else None,
                    x0=x0_full,
                    tol=tol,
                    atol=atol,
                    restart=pc_restart,
                    maxiter=pc_maxiter,
                    outer_k=xblock_lgmres_rescue_outer_k,
                    precondition_side=precondition_side,
                )
            elif xblock_krylov_method == "gmres_jax":
                gmres_jax_result, _gmres_jax_residual = fgmres_solve_with_residual(
                    matvec=_mv_xblock_krylov,
                    b=xblock_rhs,
                    preconditioner=precond_xblock_krylov if precondition_side != "none" else None,
                    x0=x0_full,
                    tol=tol,
                    atol=atol,
                    restart=pc_restart,
                    maxiter=pc_maxiter,
                    precondition_side=precondition_side,
                    skip_inactive_work=not bool(two_level_built),
                )
                x_np = np.asarray(jax.device_get(gmres_jax_result.x), dtype=np.float64)
                residual_norm_xblock_pc = float(jax.device_get(gmres_jax_result.residual_norm))
                history_arr = np.asarray(jax.device_get(gmres_jax_result.residual_history), dtype=np.float64)
                n_iterations = int(jax.device_get(gmres_jax_result.n_iterations))
                history = [float(v) for v in history_arr[: n_iterations + 1] if np.isfinite(float(v))]
            elif xblock_krylov_method == "fgmres_jax":
                fgmres_result, _fgmres_residual = fgmres_solve_with_residual(
                    matvec=_mv_xblock_krylov,
                    b=xblock_rhs,
                    preconditioner=precond_xblock_krylov if precondition_side != "none" else None,
                    x0=x0_full,
                    tol=tol,
                    atol=atol,
                    restart=pc_restart,
                    maxiter=pc_maxiter,
                    precondition_side=precondition_side,
                    skip_inactive_work=not bool(two_level_built),
                )
                x_np = np.asarray(jax.device_get(fgmres_result.x), dtype=np.float64)
                residual_norm_xblock_pc = float(jax.device_get(fgmres_result.residual_norm))
                history_arr = np.asarray(jax.device_get(fgmres_result.residual_history), dtype=np.float64)
                n_iterations = int(jax.device_get(fgmres_result.n_iterations))
                history = [float(v) for v in history_arr[: n_iterations + 1] if np.isfinite(float(v))]
            elif xblock_krylov_method == "gcrotmk":
                x_np, residual_norm_xblock_pc, history = gcrotmk_solve_with_history_scipy(
                    matvec=_mv_xblock_krylov,
                    b=xblock_rhs,
                    preconditioner=precond_xblock_krylov if precondition_side != "none" else None,
                    x0=x0_full,
                    tol=tol,
                    atol=atol,
                    restart=pc_restart,
                    maxiter=pc_maxiter,
                    precondition_side=precondition_side,
                )
            elif xblock_krylov_method == "bicgstab":
                x_np, residual_norm_xblock_pc, history = bicgstab_solve_with_history_scipy(
                    matvec=_mv_xblock_krylov,
                    b=xblock_rhs,
                    preconditioner=precond_xblock_krylov if precondition_side != "none" else None,
                    x0=x0_full,
                    tol=tol,
                    atol=atol,
                    maxiter=pc_maxiter,
                    precondition_side=precondition_side,
                )
            else:
                x_np, residual_norm_xblock_pc, history = gmres_solve_with_history_scipy(
                    matvec=_mv_xblock_krylov,
                    b=xblock_rhs,
                    preconditioner=precond_xblock_krylov if precondition_side != "none" else None,
                    x0=x0_full,
                    tol=tol,
                    atol=atol,
                    restart=pc_restart,
                    maxiter=pc_maxiter,
                    precondition_side=precondition_side,
                )
            solve_s = (sparse_timer.elapsed_s() - solve_start_s) + float(xblock_side_probe_s) + float(probe_coarse_s)
            try:
                residual_true = np.asarray(xblock_rhs, dtype=np.float64) - np.asarray(
                    jax.device_get(_mv_true(jnp.asarray(x_np, dtype=jnp.float64))),
                    dtype=np.float64,
                )
                residual_norm_xblock_pc = float(np.linalg.norm(residual_true))
            except Exception:
                residual_norm_xblock_pc = float(residual_norm_xblock_pc)
            candidate_krylov_method = str(xblock_krylov_method)
            candidate_residual_norm = float(residual_norm_xblock_pc)
            candidate_iterations = int(len(history or []))
            candidate_matvecs = int(mv_count)
            fallback_started_from_candidate = False
            fallback_candidate_improved_rhs = False
            fallback_env = os.environ.get("SFINCS_JAX_RHSMODE1_XBLOCK_PC_FALLBACK_GMRES", "").strip().lower()
            fallback_to_gmres = fallback_env not in {"0", "false", "f", "no", "off", ".false.", ".f."}
            if xblock_side_probe_lgmres_rescue and not fallback_env:
                fallback_to_gmres = False
            if xblock_krylov_method in {"fgmres_jax", "gmres_jax"} and not fallback_env:
                fallback_to_gmres = False
            if (
                xblock_krylov_method != "gmres"
                and fallback_to_gmres
                and (
                    (not np.isfinite(float(residual_norm_xblock_pc)))
                    or float(residual_norm_xblock_pc) > float(target_xblock)
                )
            ):
                if emit is not None:
                    emit(
                        0,
                        "solve_v3_full_system_linear_gmres: xblock_sparse_pc_gmres "
                        f"{xblock_krylov_method} residual={float(residual_norm_xblock_pc):.6e} "
                        f"> target={float(target_xblock):.6e}; falling back to gmres",
                    )
                (
                    fallback_x0,
                    fallback_started_from_candidate,
                    fallback_candidate_improved_rhs,
                ) = _rhs1_xblock_fallback_initial_guess(
                    candidate=np.asarray(x_np, dtype=np.float64),
                    original_x0=x0_full,
                    rhs_shape=tuple(rhs.shape),
                    candidate_residual_norm=float(candidate_residual_norm),
                    rhs_norm=float(xblock_rhs_norm),
                    precondition_side=str(precondition_side),
                )
                fallback_start_s = sparse_timer.elapsed_s()
                x_np, residual_norm_xblock_pc, history = gmres_solve_with_history_scipy(
                    matvec=_mv_xblock_krylov,
                    b=xblock_rhs,
                    preconditioner=precond_xblock_krylov if precondition_side != "none" else None,
                    x0=fallback_x0,
                    tol=tol,
                    atol=atol,
                    restart=pc_restart,
                    maxiter=pc_maxiter,
                    precondition_side=precondition_side,
                )
                solve_s += sparse_timer.elapsed_s() - fallback_start_s
                xblock_krylov_method = "gmres"
                try:
                    residual_true = np.asarray(xblock_rhs, dtype=np.float64) - np.asarray(
                        jax.device_get(_mv_true(jnp.asarray(x_np, dtype=jnp.float64))),
                        dtype=np.float64,
                    )
                    residual_norm_xblock_pc = float(np.linalg.norm(residual_true))
                except Exception:
                    residual_norm_xblock_pc = float(residual_norm_xblock_pc)
            post_minres_env = os.environ.get(
                "SFINCS_JAX_RHSMODE1_XBLOCK_PC_POST_MINRES_STEPS",
                "",
            ).strip()
            try:
                post_minres_steps_requested = int(post_minres_env) if post_minres_env else 0
            except ValueError:
                post_minres_steps_requested = 0
            post_minres_steps_requested = max(0, int(post_minres_steps_requested))
            post_minres_alpha_env = os.environ.get(
                "SFINCS_JAX_RHSMODE1_XBLOCK_PC_POST_MINRES_ALPHA_CLIP",
                "",
            ).strip()
            try:
                post_minres_alpha_clip = float(post_minres_alpha_env) if post_minres_alpha_env else 10.0
            except ValueError:
                post_minres_alpha_clip = 10.0
            post_minres_improve_env = os.environ.get(
                "SFINCS_JAX_RHSMODE1_XBLOCK_PC_POST_MINRES_MIN_IMPROVEMENT",
                "",
            ).strip()
            try:
                post_minres_min_improvement = float(post_minres_improve_env) if post_minres_improve_env else 0.0
            except ValueError:
                post_minres_min_improvement = 0.0
            post_minres_history: tuple[float, ...] = ()
            post_minres_alphas: tuple[float, ...] = ()
            post_minres_residual_before: float | None = None
            post_minres_residual_after: float | None = None
            post_coarse_enabled = _rhs1_bool_env("SFINCS_JAX_RHSMODE1_XBLOCK_PC_POST_COARSE", default=False)
            post_coarse_steps_requested = (
                _rhs1_int_env("SFINCS_JAX_RHSMODE1_XBLOCK_PC_POST_COARSE_STEPS", default=1, minimum=1)
                if post_coarse_enabled
                else 0
            )
            post_coarse_max_directions = _rhs1_int_env(
                "SFINCS_JAX_RHSMODE1_XBLOCK_PC_POST_COARSE_MAX_DIRECTIONS",
                default=16,
                minimum=1,
            )
            post_coarse_max_extra_units = _rhs1_int_env(
                "SFINCS_JAX_RHSMODE1_XBLOCK_PC_POST_COARSE_MAX_EXTRA_UNITS",
                default=8,
                minimum=0,
            )
            post_coarse_fsavg_lmax = _rhs1_int_env(
                "SFINCS_JAX_RHSMODE1_XBLOCK_PC_POST_COARSE_FSAVG_LMAX",
                default=2,
                minimum=0,
            )
            post_coarse_include_raw = _rhs1_bool_env(
                "SFINCS_JAX_RHSMODE1_XBLOCK_PC_POST_COARSE_INCLUDE_RAW",
                default=True,
            )
            post_coarse_alpha_clip = _rhs1_float_env(
                "SFINCS_JAX_RHSMODE1_XBLOCK_PC_POST_COARSE_ALPHA_CLIP",
                default=0.0,
                minimum=0.0,
            )
            post_coarse_rcond = _rhs1_float_env(
                "SFINCS_JAX_RHSMODE1_XBLOCK_PC_POST_COARSE_RCOND",
                default=1.0e-12,
                minimum=0.0,
            )
            post_coarse_min_improvement = _rhs1_float_env(
                "SFINCS_JAX_RHSMODE1_XBLOCK_PC_POST_COARSE_MIN_IMPROVEMENT",
                default=0.0,
                minimum=0.0,
            )
            post_coarse_history: tuple[float, ...] = ()
            post_coarse_direction_counts: tuple[int, ...] = ()
            post_coarse_direction_names: tuple[str, ...] = ()
            post_coarse_residual_before: float | None = None
            post_coarse_residual_after: float | None = None
            if (
                post_minres_steps_requested > 0
                and np.isfinite(float(residual_norm_xblock_pc))
                and float(residual_norm_xblock_pc) > float(target_xblock)
            ):
                post_minres_residual_before = float(residual_norm_xblock_pc)
                post_minres_start_s = sparse_timer.elapsed_s()
                try:
                    x_corr, residual_corr, post_history, post_alphas = _apply_preconditioned_minres_correction(
                        matvec=_mv_true,
                        rhs=xblock_rhs,
                        x0=jnp.asarray(x_np, dtype=jnp.float64),
                        preconditioner=precond_xblock_krylov if precondition_side != "none" else (lambda v: v),
                        steps=post_minres_steps_requested,
                        alpha_clip=post_minres_alpha_clip,
                        min_improvement=post_minres_min_improvement,
                    )
                    post_minres_history = tuple(float(v) for v in post_history)
                    post_minres_alphas = tuple(float(v) for v in post_alphas)
                    post_minres_residual_after = float(jnp.linalg.norm(residual_corr))
                    if (
                        np.isfinite(float(post_minres_residual_after))
                        and float(post_minres_residual_after) < float(residual_norm_xblock_pc)
                    ):
                        x_np = np.asarray(x_corr, dtype=np.float64)
                        residual_norm_xblock_pc = float(post_minres_residual_after)
                        if emit is not None:
                            emit(
                                0,
                                "solve_v3_full_system_linear_gmres: xblock_sparse_pc_gmres "
                                f"post-minres improved residual {post_minres_residual_before:.6e} "
                                f"-> {post_minres_residual_after:.6e} "
                                f"(accepted_steps={len(post_minres_alphas)})",
                            )
                    elif emit is not None:
                        after = (
                            float(post_minres_residual_after)
                            if post_minres_residual_after is not None
                            else float("nan")
                        )
                        emit(
                            1,
                            "solve_v3_full_system_linear_gmres: xblock_sparse_pc_gmres "
                            f"post-minres rejected residual {post_minres_residual_before:.6e} -> {after:.6e}",
                        )
                except Exception as exc:  # noqa: BLE001
                    if emit is not None:
                        emit(
                            1,
                            "solve_v3_full_system_linear_gmres: xblock_sparse_pc_gmres "
                            f"post-minres failed ({type(exc).__name__}: {exc})",
                        )
                solve_s += sparse_timer.elapsed_s() - post_minres_start_s
            if (
                post_coarse_steps_requested > 0
                and np.isfinite(float(residual_norm_xblock_pc))
                and float(residual_norm_xblock_pc) > float(target_xblock)
            ):
                post_coarse_residual_before = float(residual_norm_xblock_pc)
                post_coarse_start_s = sparse_timer.elapsed_s()

                def _post_coarse_direction_builder(residual_vec: jnp.ndarray) -> tuple[tuple[str, jnp.ndarray], ...]:
                    return _xblock_coarse_direction_builder(
                        residual_vec,
                        include_raw=bool(post_coarse_include_raw),
                        fsavg_lmax=int(post_coarse_fsavg_lmax),
                        max_extra_units=int(post_coarse_max_extra_units),
                        max_directions=int(post_coarse_max_directions),
                    )

                try:
                    (
                        x_coarse,
                        residual_coarse,
                        post_coarse_history,
                        post_coarse_direction_counts,
                        post_coarse_direction_names,
                    ) = _apply_subspace_minres_correction(
                        matvec=_mv_true,
                        rhs=xblock_rhs,
                        x0=jnp.asarray(x_np, dtype=jnp.float64),
                        direction_builder=_post_coarse_direction_builder,
                        steps=post_coarse_steps_requested,
                        max_directions=post_coarse_max_directions,
                        alpha_clip=post_coarse_alpha_clip,
                        rcond=post_coarse_rcond,
                        min_improvement=post_coarse_min_improvement,
                    )
                    post_coarse_residual_after = float(jnp.linalg.norm(residual_coarse))
                    if (
                        np.isfinite(float(post_coarse_residual_after))
                        and float(post_coarse_residual_after) < float(residual_norm_xblock_pc)
                    ):
                        x_np = np.asarray(x_coarse, dtype=np.float64)
                        residual_norm_xblock_pc = float(post_coarse_residual_after)
                        if emit is not None:
                            emit(
                                0,
                                "solve_v3_full_system_linear_gmres: xblock_sparse_pc_gmres "
                                f"post-coarse improved residual {post_coarse_residual_before:.6e} "
                                f"-> {post_coarse_residual_after:.6e} "
                                f"(steps={len(post_coarse_direction_counts)} "
                                f"directions={sum(post_coarse_direction_counts)})",
                            )
                    elif emit is not None:
                        after = (
                            float(post_coarse_residual_after)
                            if post_coarse_residual_after is not None
                            else float("nan")
                        )
                        emit(
                            1,
                            "solve_v3_full_system_linear_gmres: xblock_sparse_pc_gmres "
                            f"post-coarse rejected residual {post_coarse_residual_before:.6e} -> {after:.6e}",
                        )
                except Exception as exc:  # noqa: BLE001
                    if emit is not None:
                        emit(
                            1,
                            "solve_v3_full_system_linear_gmres: xblock_sparse_pc_gmres "
                            f"post-coarse failed ({type(exc).__name__}: {exc})",
                        )
                solve_s += sparse_timer.elapsed_s() - post_coarse_start_s
            if emit is not None:
                ksp_suffix = f" ksp_residual={float(history[-1]):.6e}" if history else ""
                emit(
                    0,
                    "solve_v3_full_system_linear_gmres: xblock_sparse_pc_gmres complete "
                    f"method={xblock_krylov_method} elapsed_s={sparse_timer.elapsed_s():.3f} "
                    f"iters={len(history or [])} "
                    f"matvecs={int(mv_count)} residual={float(residual_norm_xblock_pc):.6e} "
                    f"target={float(target_xblock):.6e}{ksp_suffix}",
                )
            xblock_solver_kind = (
                "xblock_sparse_pc_gmres"
                if xblock_krylov_method == "gmres"
                else f"xblock_sparse_pc_{xblock_krylov_method}"
            )
            return V3LinearSolveResult(
                op=op,
                rhs=rhs,
                gmres=GMRESSolveResult(
                    x=_xblock_expand_reduced(jnp.asarray(x_np, dtype=jnp.float64)),
                    residual_norm=jnp.asarray(residual_norm_xblock_pc, dtype=jnp.float64),
                ),
                metadata={
                    "solver_kind": xblock_solver_kind,
                    "residual_kind": "true_residual",
                    "accepted_converged": bool(
                        float(residual_norm_xblock_pc) <= float(target_xblock)
                    ),
                    "acceptance_criterion": "true_residual",
                    "iterations": int(len(history or [])),
                    "matvecs": int(mv_count),
                    "krylov_method": str(xblock_krylov_method),
                    "candidate_krylov_method": str(candidate_krylov_method),
                    "candidate_iterations": int(candidate_iterations),
                    "candidate_matvecs": int(candidate_matvecs),
                    "candidate_residual_norm": float(candidate_residual_norm),
                    "fallback_from_krylov_method": (
                        str(candidate_krylov_method) if candidate_krylov_method != str(xblock_krylov_method) else None
                    ),
                    "fallback_started_from_candidate": bool(fallback_started_from_candidate),
                    "fallback_candidate_improved_rhs": bool(fallback_candidate_improved_rhs),
                    "precondition_side": str(precondition_side),
                    "default_right_preconditioned": bool(xblock_default_right_pc),
                    "default_short_restart_capped": bool(xblock_default_restart_capped),
                    "gmres_restart": int(pc_restart),
                    "gmres_maxiter": int(pc_maxiter),
                    "setup_s": float(setup_s),
                    "solve_s": float(solve_s),
                    "elapsed_s": float(sparse_timer.elapsed_s()),
                    "sparse_pc_factor_s": float(pc_factor_s),
                    "sparse_pc_xblock_preconditioner_xi": int(xblock_preconditioner_xi),
                    "sparse_pc_xblock_assembled_host": bool(xblock_assembled_host_fp),
                    "sparse_pc_xblock_jax_factors": bool(xblock_jax_factors),
                    "xblock_device_krylov_method": (
                        str(xblock_krylov_method)
                        if str(xblock_krylov_method) in {"fgmres_jax", "gmres_jax"}
                        else None
                    ),
                    "xblock_device_gmres_enabled": bool(str(xblock_krylov_method) == "gmres_jax"),
                    "xblock_device_fgmres_enabled": bool(str(xblock_krylov_method) == "fgmres_jax"),
                    "xblock_device_krylov_forced_jax_factors": bool(xblock_device_krylov_forced_jax_factors),
                    "xblock_device_fgmres_forced_jax_factors": bool(xblock_device_krylov_forced_jax_factors),
                    "xblock_device_fgmres_forced_right_pc": bool(xblock_device_fgmres_forced_right_pc),
                    "xblock_device_krylov_host_transfer_free": bool(
                        str(xblock_krylov_method) in {"fgmres_jax", "gmres_jax"}
                        and bool(xblock_jax_factors)
                        and not bool(assembled_operator_built)
                        and not bool(two_level_built)
                        and (
                            not bool(global_coupling_built)
                            or bool(global_coupling_metadata.get("device_resident", False))
                        )
                    ),
                    "xblock_device_fgmres_host_transfer_free": bool(
                        str(xblock_krylov_method) in {"fgmres_jax", "gmres_jax"}
                        and bool(xblock_jax_factors)
                        and not bool(assembled_operator_built)
                        and not bool(two_level_built)
                        and (
                            not bool(global_coupling_built)
                            or bool(global_coupling_metadata.get("device_resident", False))
                        )
                    ),
                    "xblock_active_dof": bool(xblock_use_active_dof),
                    "xblock_linear_size": int(xblock_linear_size),
                    "xblock_full_size": int(op.total_size),
                    "xblock_assembled_operator_enabled": bool(assembled_operator_enabled),
                    "xblock_assembled_operator_built": bool(assembled_operator_built),
                    "xblock_assembled_operator_active_dof": assembled_operator_metadata.get("active_dof", False),
                    "xblock_assembled_operator_preflight_scope": assembled_operator_metadata.get("preflight_scope"),
                    "xblock_assembled_operator_setup_s": assembled_operator_metadata.get("setup_s"),
                    "xblock_assembled_operator_preflight_rejected": assembled_operator_metadata.get(
                        "preflight_rejected", False
                    ),
                    "xblock_assembled_operator_preflight_pattern_nnz_estimate": assembled_operator_metadata.get(
                        "preflight_pattern_nnz_estimate"
                    ),
                    "xblock_assembled_operator_preflight_peak_nbytes_estimate": assembled_operator_metadata.get(
                        "preflight_peak_nbytes_estimate"
                    ),
                    "xblock_assembled_operator_preflight_full_csr_nbytes_estimate": assembled_operator_metadata.get(
                        "preflight_full_csr_nbytes_estimate"
                    ),
                    "xblock_assembled_operator_preflight_active_csr_nbytes_estimate": assembled_operator_metadata.get(
                        "preflight_active_csr_nbytes_estimate"
                    ),
                    "xblock_assembled_operator_pattern_nnz": assembled_operator_metadata.get("pattern_nnz"),
                    "xblock_assembled_operator_matrix_nnz": assembled_operator_metadata.get("matrix_nnz"),
                    "xblock_assembled_operator_csr_nbytes_estimate": assembled_operator_metadata.get(
                        "csr_nbytes_estimate"
                    ),
                    "xblock_assembled_operator_max_colors": assembled_operator_metadata.get("max_colors"),
                    "xblock_assembled_operator_validation_rel_errors": assembled_operator_metadata.get(
                        "validation_rel_errors",
                        (),
                    ),
                    "xblock_assembled_operator_error": assembled_operator_metadata.get("error"),
                    "xblock_two_level_enabled": bool(two_level_enabled),
                    "xblock_two_level_built": bool(two_level_built),
                    "xblock_two_level_mode": two_level_metadata.get("mode"),
                    "xblock_two_level_basis_size": two_level_metadata.get("basis_size"),
                    "xblock_two_level_rank": two_level_metadata.get("rank"),
                    "xblock_two_level_setup_s": two_level_metadata.get("setup_s"),
                    "xblock_two_level_rcond": two_level_metadata.get("rcond"),
                    "xblock_two_level_basis_names": two_level_metadata.get("basis_names", ()),
                    "xblock_two_level_active_projected": bool(two_level_metadata.get("active_projected", False)),
                    "xblock_two_level_expected_size": two_level_metadata.get("expected_size"),
                    "xblock_two_level_error": two_level_metadata.get("error"),
                    "xblock_two_level_applies": int(two_level_stats.get("applies", 0)),
                    "xblock_two_level_coarse_applies": int(two_level_stats.get("coarse_applies", 0)),
                    "xblock_global_coupling_enabled": bool(global_coupling_enabled),
                    "xblock_global_coupling_built": bool(global_coupling_built),
                    "xblock_global_coupling_mode": global_coupling_metadata.get("mode"),
                    "xblock_global_coupling_load_basis_size": global_coupling_metadata.get("load_basis_size"),
                    "xblock_global_coupling_basis_size": global_coupling_metadata.get("basis_size"),
                    "xblock_global_coupling_rank": global_coupling_metadata.get("rank"),
                    "xblock_global_coupling_setup_s": global_coupling_metadata.get("setup_s"),
                    "xblock_global_coupling_rcond": global_coupling_metadata.get("rcond"),
                    "xblock_global_coupling_device_resident": bool(
                        global_coupling_metadata.get("device_resident", False)
                    ),
                    "xblock_global_coupling_fsavg_lmax": global_coupling_metadata.get("fsavg_lmax"),
                    "xblock_global_coupling_angular_lmax": global_coupling_metadata.get("angular_lmax"),
                    "xblock_global_coupling_basis_names": global_coupling_metadata.get("basis_names", ()),
                    "xblock_global_coupling_error": global_coupling_metadata.get("error"),
                    "xblock_global_coupling_applies": int(global_coupling_stats.get("applies", 0)),
                    "xblock_global_coupling_coarse_applies": int(global_coupling_stats.get("coarse_applies", 0)),
                    "xblock_initial_seed_used": bool(xblock_initial_seed_used),
                    "xblock_initial_seed_residual_norm": xblock_initial_seed_residual_norm,
                    "xblock_initial_seed_residual_ratio": xblock_initial_seed_residual_ratio,
                    "xblock_side_probe_enabled": bool(xblock_side_probe_enabled),
                    "xblock_side_probe_used": bool(xblock_side_probe_used),
                    "xblock_side_probe_switched": bool(xblock_side_probe_switched),
                    "xblock_side_probe_switch_suppressed_by_global_coupling": bool(
                        xblock_side_probe_switch_suppressed_by_global_coupling
                    ),
                    "xblock_side_probe_physical_seed_preserved_after_switch": bool(
                        xblock_side_probe_physical_seed_preserved_after_switch
                    ),
                    "xblock_side_probe_initial_side": xblock_side_probe_initial_side,
                    "xblock_side_probe_selected_side": xblock_side_probe_selected_side,
                    "xblock_side_probe_initial_method": xblock_side_probe_initial_method,
                    "xblock_side_probe_selected_method": xblock_side_probe_selected_method,
                    "xblock_side_probe_lgmres_rescue": bool(xblock_side_probe_lgmres_rescue),
                    "xblock_lgmres_rescue_maxiter_capped": bool(xblock_lgmres_rescue_maxiter_capped),
                    "xblock_lgmres_rescue_outer_k": xblock_lgmres_rescue_outer_k,
                    "xblock_side_probe_residual_norm": xblock_side_probe_residual_norm,
                    "xblock_side_probe_residual_ratio": xblock_side_probe_residual_ratio,
                    "xblock_side_probe_iterations": int(xblock_side_probe_iterations),
                    "xblock_side_probe_matvecs": int(xblock_side_probe_matvecs),
                    "xblock_side_probe_s": float(xblock_side_probe_s),
                    "xblock_probe_coarse_steps_requested": int(probe_coarse_steps_requested),
                    "xblock_probe_coarse_steps_accepted": int(len(probe_coarse_direction_counts)),
                    "xblock_probe_coarse_direction_count": int(sum(probe_coarse_direction_counts)),
                    "xblock_probe_coarse_residual_before": probe_coarse_residual_before,
                    "xblock_probe_coarse_residual_after": probe_coarse_residual_after,
                    "xblock_probe_coarse_s": float(probe_coarse_s),
                    "xblock_probe_coarse_history": probe_coarse_history,
                    "xblock_probe_coarse_direction_counts": probe_coarse_direction_counts,
                    "xblock_probe_coarse_direction_names": probe_coarse_direction_names,
                    "xblock_post_minres_steps_requested": int(post_minres_steps_requested),
                    "xblock_post_minres_steps_accepted": int(len(post_minres_alphas)),
                    "xblock_post_minres_residual_before": post_minres_residual_before,
                    "xblock_post_minres_residual_after": post_minres_residual_after,
                    "xblock_post_minres_alphas": post_minres_alphas,
                    "xblock_post_minres_history": post_minres_history,
                    "xblock_post_coarse_steps_requested": int(post_coarse_steps_requested),
                    "xblock_post_coarse_steps_accepted": int(len(post_coarse_direction_counts)),
                    "xblock_post_coarse_direction_count": int(sum(post_coarse_direction_counts)),
                    "xblock_post_coarse_residual_before": post_coarse_residual_before,
                    "xblock_post_coarse_residual_after": post_coarse_residual_after,
                    "xblock_post_coarse_history": post_coarse_history,
                    "xblock_post_coarse_direction_counts": post_coarse_direction_counts,
                    "xblock_post_coarse_direction_names": post_coarse_direction_names,
                },
            )

        sparse_pc_active_idx_np: np.ndarray | None = None
        sparse_pc_active_idx_jnp: jnp.ndarray | None = None
        sparse_pc_full_to_active_jnp: jnp.ndarray | None = None
        sparse_pc_rhs = rhs
        sparse_pc_linear_size = int(op.total_size)
        if sparse_pc_use_active_dof:
            sparse_pc_active_idx_np = _transport_active_dof_indices(op)
            sparse_pc_active_idx_jnp = jnp.asarray(sparse_pc_active_idx_np, dtype=jnp.int32)
            sparse_pc_full_to_active_np = np.zeros((int(op.total_size),), dtype=np.int32)
            sparse_pc_full_to_active_np[np.asarray(sparse_pc_active_idx_np, dtype=np.int32)] = np.arange(
                1, int(sparse_pc_active_idx_np.shape[0]) + 1, dtype=np.int32
            )
            sparse_pc_full_to_active_jnp = jnp.asarray(sparse_pc_full_to_active_np, dtype=jnp.int32)
            sparse_pc_rhs = rhs[sparse_pc_active_idx_jnp]
            sparse_pc_linear_size = int(sparse_pc_active_idx_np.shape[0])
            if emit is not None:
                emit(
                    1,
                    "solve_v3_full_system_linear_gmres: sparse_pc_gmres active-DOF reduction "
                    f"enabled (size={int(sparse_pc_linear_size)}/{int(op.total_size)})",
                )

        def _sparse_pc_reduce_full(v_full: jnp.ndarray) -> jnp.ndarray:
            if not sparse_pc_use_active_dof:
                return v_full
            assert sparse_pc_active_idx_jnp is not None
            return v_full[sparse_pc_active_idx_jnp]

        def _sparse_pc_expand_reduced(v_vec: jnp.ndarray) -> jnp.ndarray:
            if not sparse_pc_use_active_dof:
                return v_vec
            assert sparse_pc_full_to_active_jnp is not None
            z0 = jnp.zeros((1,), dtype=v_vec.dtype)
            padded = jnp.concatenate([z0, v_vec], axis=0)
            return padded[sparse_pc_full_to_active_jnp]

        pattern_start_s = sparse_timer.elapsed_s()
        if emit is not None:
            emit(1, "solve_v3_full_system_linear_gmres: sparse_pc_gmres building conservative pattern")
        pattern_full = v3_full_system_conservative_sparsity_pattern(
            op,
            fp_dense_velocity_block=sparse_pc_fp_dense_velocity_block,
        )
        if sparse_pc_use_active_dof:
            assert sparse_pc_active_idx_np is not None
            pattern = pattern_full[np.asarray(sparse_pc_active_idx_np), :][:, np.asarray(sparse_pc_active_idx_np)].tocsr()
        else:
            pattern = pattern_full
        pattern_build_s = sparse_timer.elapsed_s() - pattern_start_s
        summary = summarize_v3_sparse_pattern(op, pattern)
        if emit is not None:
            emit(
                1,
                "solve_v3_full_system_linear_gmres: sparse_pc_gmres pattern "
                f"nnz={summary.nnz} avg_row_nnz={summary.avg_row_nnz:.3g} max_row_nnz={summary.max_row_nnz}",
            )
        op_pc = _build_rhsmode1_preconditioner_operator_point(op)
        pc_shift_env = os.environ.get("SFINCS_JAX_RHSMODE1_SPARSE_PC_SHIFT", "").strip()
        try:
            pc_shift = float(pc_shift_env) if pc_shift_env else (1.0e-8 if (constrained_pas_pc or tokamak_fp_pc) else 0.0)
        except ValueError:
            pc_shift = 1.0e-8 if (constrained_pas_pc or tokamak_fp_pc) else 0.0
        factor_kind_env = os.environ.get("SFINCS_JAX_EXPLICIT_SPARSE_FACTOR_KIND", "").strip().lower()
        sparse_pc_factorization = "ilu" if factor_kind_env in {"ilu", "spilu"} else "lu"
        sparse_pc_dtype_env = os.environ.get("SFINCS_JAX_RHSMODE1_SPARSE_PC_FACTOR_DTYPE", "").strip().lower()
        if sparse_pc_dtype_env in {"float32", "fp32", "32"}:
            sparse_pc_factor_dtype_initial = np.dtype(np.float32)
        elif sparse_pc_dtype_env in {"float64", "fp64", "64"}:
            sparse_pc_factor_dtype_initial = np.dtype(np.float64)
        elif os.environ.get("SFINCS_JAX_HOST_SPARSE_FACTOR_DTYPE", "").strip():
            sparse_pc_factor_dtype_initial = _host_sparse_factor_dtype(
                size=int(sparse_pc_linear_size),
                factorization=sparse_pc_factorization,
                use_implicit=False,
            )
        else:
            # Unlike direct-solve fallbacks, sparse-PC GMRES is very sensitive to
            # preconditioner quality. Single-precision SuperLU can reduce factor
            # storage but has caused thousands of extra Krylov matvecs on
            # production PAS+Er systems, so keep this path FP64 unless explicitly
            # requested for a memory experiment.
            sparse_pc_factor_dtype_initial = np.dtype(np.float64)
        sparse_pc_factor_dtype_used = sparse_pc_factor_dtype_initial
        sparse_pc_factor_dtype_retry: str | None = None
        sparse_pc_default_permc_spec = _rhsmode1_sparse_pc_default_permc_spec(
            constrained_pas_pc=bool(constrained_pas_pc),
            tokamak_pas_er_pc=bool(tokamak_pas_er_pc),
            n_species=int(op.n_species),
        )
        sparse_pc_permc_env = os.environ.get("SFINCS_JAX_EXPLICIT_SPARSE_PERMC_SPEC", "").strip().upper()
        sparse_pc_permc_spec = (
            sparse_pc_permc_env
            if sparse_pc_permc_env in {"NATURAL", "MMD_ATA", "MMD_AT_PLUS_A", "COLAMD"}
            else sparse_pc_default_permc_spec
        )
        fp32_probe_maxiter_env = os.environ.get("SFINCS_JAX_RHSMODE1_SPARSE_PC_FP32_PROBE_MAXITER", "").strip()
        try:
            fp32_probe_maxiter = int(fp32_probe_maxiter_env) if fp32_probe_maxiter_env else 2
        except ValueError:
            fp32_probe_maxiter = 2
        fp32_probe_maxiter = max(1, int(fp32_probe_maxiter))
        sparse_pc_first_attempt_maxiter = (
            min(int(pc_maxiter), int(fp32_probe_maxiter))
            if sparse_pc_factor_dtype_initial == np.dtype(np.float32)
            else int(pc_maxiter)
        )
        budget_env = os.environ.get("SFINCS_JAX_RHSMODE1_SPARSE_PC_MAX_ESTIMATED_MB", "").strip()
        if budget_env:
            try:
                budget_mb = float(budget_env)
            except ValueError:
                budget_mb = 0.0
            if budget_mb > 0.0:
                fill_env = os.environ.get("SFINCS_JAX_RHSMODE1_SPARSE_PC_FACTOR_FILL_ESTIMATE", "").strip()
                try:
                    fill_estimate = float(fill_env) if fill_env else 8.0
                except ValueError:
                    fill_estimate = 8.0
                memory_estimate = estimate_sparse_pc_memory(
                    unknowns=int(sparse_pc_linear_size),
                    gmres_restart=int(pc_restart),
                    csr_nnz=int(summary.nnz),
                    dtype=sparse_pc_factor_dtype_initial,
                    factor_fill_estimate=float(fill_estimate),
                    device_count=max(1, int(jax.device_count())),
                )
                estimated_mb = (
                    float(memory_estimate.csr_total_nbytes or memory_estimate.dense_total_nbytes)
                    / 1.0e6
                )
                if estimated_mb > float(budget_mb):
                    raise MemoryError(
                        "sparse_pc_gmres memory preflight exceeds "
                        "SFINCS_JAX_RHSMODE1_SPARSE_PC_MAX_ESTIMATED_MB: "
                        f"estimated={estimated_mb:.3f} MB budget={float(budget_mb):.3f} MB "
                        f"unknowns={int(sparse_pc_linear_size)} csr_nnz={int(summary.nnz)} "
                        f"restart={int(pc_restart)} factor_fill_estimate={float(fill_estimate):.3g}. "
                        "Raise the budget, lower the resolution, or use a lower-memory matrix-free route."
                    )

        def _sparse_pc_factor_mv(x_np: np.ndarray) -> jnp.ndarray:
            x_jnp = _sparse_pc_expand_reduced(jnp.asarray(x_np, dtype=rhs.dtype))
            y_jnp = apply_v3_full_system_operator_cached(op_pc, x_jnp)
            if pc_shift != 0.0:
                y_jnp = y_jnp + jnp.asarray(pc_shift, dtype=rhs.dtype) * x_jnp
            return _sparse_pc_reduce_full(y_jnp)

        if emit is not None:
            shift_note = f" shift={pc_shift:.1e}" if pc_shift != 0.0 else ""
            emit(
                1,
                "solve_v3_full_system_linear_gmres: sparse_pc_gmres factoring RHSMode=1 preconditioner"
                f"{shift_note} factor_dtype={sparse_pc_factor_dtype_initial.name} "
                f"permc={sparse_pc_permc_spec}",
            )
        factor_start_s = sparse_timer.elapsed_s()
        _operator_bundle_pc, factor_bundle_pc = _build_host_sparse_direct_factor_from_matvec(
            matvec=_sparse_pc_factor_mv,
            n=int(sparse_pc_linear_size),
            dtype=rhs.dtype,
            factor_dtype=sparse_pc_factor_dtype_initial,
            pattern=pattern,
            emit=emit,
            default_diag_pivot_thresh=0.0 if (constrained_pas_pc or tokamak_fp_pc) else 1.0,
            default_permc_spec=sparse_pc_default_permc_spec,
        )
        pc_factor_s = sparse_timer.elapsed_s() - factor_start_s
        setup_s = sparse_timer.elapsed_s()

        side_env = os.environ.get("SFINCS_JAX_GMRES_PRECONDITION_SIDE", "").strip().lower()
        precondition_side = side_env if side_env in {"left", "right", "none"} else "left"
        pc_form = os.environ.get("SFINCS_JAX_RHSMODE1_SPARSE_PC_FORM", "").strip().lower()
        if pc_form not in {"", "scipy_left", "scipy", "explicit_left", "petsc_left"}:
            pc_form = ""
        pc_form = pc_form or "scipy_left"
        progress_every_env = os.environ.get("SFINCS_JAX_SPARSE_PC_PROGRESS_EVERY", "").strip()
        try:
            progress_every = int(progress_every_env) if progress_every_env else 25
        except ValueError:
            progress_every = 25
        progress_every = max(0, int(progress_every))
        mv_count = 0

        def _mv_true(v: jnp.ndarray) -> jnp.ndarray:
            nonlocal mv_count
            mv_count += 1
            if emit is not None and progress_every > 0 and mv_count % progress_every == 0:
                emit(
                    1,
                    "solve_v3_full_system_linear_gmres: sparse_pc_gmres "
                    f"matvecs={int(mv_count)} elapsed_s={sparse_timer.elapsed_s():.3f}",
                )
            x_full = _sparse_pc_expand_reduced(jnp.asarray(v, dtype=rhs.dtype))
            y_full = apply_v3_full_system_operator_cached(op, x_full)
            return _sparse_pc_reduce_full(y_full)

        def _precond_sparse(v: jnp.ndarray) -> jnp.ndarray:
            v_np = np.asarray(v, dtype=np.float64).reshape((-1,))
            y_np = factor_bundle_pc.solve(v_np)
            return jnp.asarray(y_np, dtype=jnp.float64)

        x0_sparse = None
        if x0 is not None:
            x0_arr = jnp.asarray(x0, dtype=jnp.float64)
            if x0_arr.shape == sparse_pc_rhs.shape:
                x0_sparse = x0_arr
            elif x0_arr.shape == rhs.shape:
                x0_sparse = _sparse_pc_reduce_full(x0_arr)
            elif emit is not None:
                emit(
                    1,
                    "solve_v3_full_system_linear_gmres: sparse_pc_gmres ignoring incompatible x0 "
                    f"shape={tuple(x0_arr.shape)} expected={tuple(sparse_pc_rhs.shape)} or {tuple(rhs.shape)}",
                )

        sparse_pc_rhs_norm = jnp.linalg.norm(sparse_pc_rhs)
        target = max(float(atol), float(tol) * float(sparse_pc_rhs_norm))

        def _run_sparse_pc_gmres_once(x0_arg, *, maxiter_arg: int):
            if emit is not None:
                emit(
                    0,
                    "solve_v3_full_system_linear_gmres: sparse_pc_gmres solve start "
                    f"form={pc_form} restart={int(pc_restart)} maxiter={int(maxiter_arg)} "
                    f"precondition_side={precondition_side} "
                    f"factor_dtype={np.dtype(sparse_pc_factor_dtype_used).name}",
                )
            rn_pc_local = float("nan")
            solve_start_s_local = sparse_timer.elapsed_s()
            if pc_form in {"explicit_left", "petsc_left"}:
                x_np_local, residual_norm_local, rn_pc_local, history_local = explicit_left_preconditioned_gmres_scipy(
                    matvec=_mv_true,
                    b=sparse_pc_rhs,
                    preconditioner=_precond_sparse,
                    x0=x0_arg,
                    tol=tol,
                    atol=atol,
                    restart=pc_restart,
                    maxiter=maxiter_arg,
                )
            else:
                x_np_local, residual_norm_local, history_local = gmres_solve_with_history_scipy(
                    matvec=_mv_true,
                    b=sparse_pc_rhs,
                    preconditioner=_precond_sparse if precondition_side != "none" else None,
                    x0=x0_arg,
                    tol=tol,
                    atol=atol,
                    restart=pc_restart,
                    maxiter=maxiter_arg,
                    precondition_side=precondition_side,
                )
            solve_s_local = sparse_timer.elapsed_s() - solve_start_s_local
            try:
                residual_true = np.asarray(sparse_pc_rhs, dtype=np.float64) - np.asarray(
                    jax.device_get(_mv_true(jnp.asarray(x_np_local, dtype=jnp.float64))),
                    dtype=np.float64,
                )
                residual_norm_local = float(np.linalg.norm(residual_true))
            except Exception:
                residual_norm_local = float(residual_norm_local)
            return x_np_local, float(residual_norm_local), rn_pc_local, history_local, float(solve_s_local)

        x_np, residual_norm_sparse_pc, rn_pc, history, solve_s = _run_sparse_pc_gmres_once(
            x0_sparse,
            maxiter_arg=sparse_pc_first_attempt_maxiter,
        )
        if (
            sparse_pc_factor_dtype_used == np.dtype(np.float32)
            and (not np.isfinite(residual_norm_sparse_pc) or float(residual_norm_sparse_pc) > float(target))
        ):
            sparse_pc_factor_dtype_retry = "float64"
            sparse_pc_factor_dtype_used = np.dtype(np.float64)
            if emit is not None:
                emit(
                    0,
                    "solve_v3_full_system_linear_gmres: sparse_pc_gmres retrying preconditioner "
                    f"with factor_dtype={sparse_pc_factor_dtype_used.name} "
                    f"after residual={float(residual_norm_sparse_pc):.6e} target={float(target):.6e}",
                )
            retry_factor_start_s = sparse_timer.elapsed_s()
            _operator_bundle_pc, factor_bundle_pc = _build_host_sparse_direct_factor_from_matvec(
                matvec=_sparse_pc_factor_mv,
                n=int(sparse_pc_linear_size),
                dtype=rhs.dtype,
                factor_dtype=sparse_pc_factor_dtype_used,
                pattern=pattern,
                emit=emit,
                default_diag_pivot_thresh=0.0 if (constrained_pas_pc or tokamak_fp_pc) else 1.0,
                default_permc_spec=sparse_pc_default_permc_spec,
            )
            pc_factor_s += sparse_timer.elapsed_s() - retry_factor_start_s
            setup_s = sparse_timer.elapsed_s()
            x0_retry = jnp.asarray(x_np, dtype=jnp.float64) if np.all(np.isfinite(x_np)) else x0_sparse
            x_np, residual_norm_sparse_pc, rn_pc, history, solve_s_retry = _run_sparse_pc_gmres_once(
                x0_retry,
                maxiter_arg=int(pc_maxiter),
            )
            solve_s += solve_s_retry
        if emit is not None:
            pc_suffix = f" preconditioned_residual={float(rn_pc):.6e}" if np.isfinite(rn_pc) else ""
            if history:
                pc_suffix = f"{pc_suffix} ksp_residual={float(history[-1]):.6e}"
            emit(
                0,
                "solve_v3_full_system_linear_gmres: sparse_pc_gmres complete "
                f"elapsed_s={sparse_timer.elapsed_s():.3f} iters={len(history or [])} "
                f"matvecs={int(mv_count)} residual={float(residual_norm_sparse_pc):.6e} "
                f"target={float(target):.6e}{pc_suffix}",
            )
        return V3LinearSolveResult(
            op=op,
            rhs=rhs,
            gmres=GMRESSolveResult(
                x=_sparse_pc_expand_reduced(jnp.asarray(x_np, dtype=jnp.float64)),
                residual_norm=jnp.asarray(residual_norm_sparse_pc, dtype=jnp.float64),
            ),
            metadata={
                "solver_kind": "sparse_pc_gmres",
                "residual_kind": "true_residual",
                "accepted_converged": bool(float(residual_norm_sparse_pc) <= max(float(atol), float(tol) * float(rhs_norm))),
                "acceptance_criterion": "true_residual",
                "iterations": int(len(history or [])),
                "matvecs": int(mv_count),
                "gmres_restart": int(pc_restart),
                "gmres_maxiter": int(pc_maxiter),
                "sparse_pc_first_attempt_maxiter": int(sparse_pc_first_attempt_maxiter),
                "sparse_pc_shift": float(pc_shift),
                "sparse_pc_factor_dtype": np.dtype(sparse_pc_factor_dtype_used).name,
                "sparse_pc_initial_factor_dtype": np.dtype(sparse_pc_factor_dtype_initial).name,
                "sparse_pc_factor_dtype_retry": sparse_pc_factor_dtype_retry,
                "sparse_pc_permc_spec": sparse_pc_permc_spec,
                "sparse_pc_default_permc_spec": sparse_pc_default_permc_spec,
                "sparse_pc_active_dof": bool(sparse_pc_use_active_dof),
                "sparse_pc_linear_size": int(sparse_pc_linear_size),
                "sparse_pc_full_size": int(op.total_size),
                "sparse_pc_fp_dense_velocity_block": (
                    None
                    if sparse_pc_fp_dense_velocity_block is None
                    else bool(sparse_pc_fp_dense_velocity_block)
                ),
                "setup_s": float(setup_s),
                "solve_s": float(solve_s),
                "elapsed_s": float(sparse_timer.elapsed_s()),
                "sparse_pattern_nnz": int(summary.nnz),
                "sparse_pattern_avg_row_nnz": float(summary.avg_row_nnz),
                "sparse_pattern_max_row_nnz": int(summary.max_row_nnz),
                "sparse_pattern_build_s": float(pattern_build_s),
                "sparse_pc_factor_s": float(pc_factor_s),
                "sparse_pc_factor_nbytes_estimate": (
                    None
                    if getattr(factor_bundle_pc, "factor_nbytes_estimate", None) is None
                    else int(getattr(factor_bundle_pc, "factor_nbytes_estimate"))
                ),
                "sparse_pc_factor_nnz_estimate": (
                    None
                    if getattr(factor_bundle_pc, "factor_nnz_estimate", None) is None
                    else int(getattr(factor_bundle_pc, "factor_nnz_estimate"))
                ),
            },
        )
    if solve_method_kind_explicit in _SPARSE_HOST_MINIMUM_NORM_SOLVE_METHODS:
        if differentiable is True:
            raise ValueError("solve_method='sparse_lsmr' is a non-differentiable host sparse minimum-norm path.")
        if int(op.rhs_mode) != 1:
            raise NotImplementedError("solve_method='sparse_lsmr' is currently implemented for RHSMode=1 only.")
        if use_active_dof_mode:
            raise NotImplementedError(
                "solve_method='sparse_lsmr' currently targets the full system; set SFINCS_JAX_ACTIVE_DOF=0 "
                "or use the default matrix-free solver for active-DOF runs."
            )
        sparse_timer = Timer()
        if emit is not None:
            emit(1, "solve_v3_full_system_linear_gmres: sparse_lsmr building conservative pattern")
        pattern = v3_full_system_conservative_sparsity_pattern(op)
        if emit is not None:
            summary = summarize_v3_sparse_pattern(op, pattern)
            emit(
                1,
                "solve_v3_full_system_linear_gmres: sparse_lsmr pattern "
                f"nnz={summary.nnz} avg_row_nnz={summary.avg_row_nnz:.3g} max_row_nnz={summary.max_row_nnz}",
            )

        def _sparse_min_norm_mv(x_np: np.ndarray) -> jnp.ndarray:
            return apply_v3_full_system_operator_cached(op, jnp.asarray(x_np, dtype=rhs.dtype))

        csr_max_env = os.environ.get("SFINCS_JAX_EXPLICIT_SPARSE_CSR_MAX_MB", "").strip()
        drop_tol_env = os.environ.get("SFINCS_JAX_EXPLICIT_SPARSE_DROP_TOL", "").strip()
        try:
            csr_max_mb = float(csr_max_env) if csr_max_env else 512.0
        except ValueError:
            csr_max_mb = 512.0
        try:
            drop_tol = float(drop_tol_env) if drop_tol_env else 0.0
        except ValueError:
            drop_tol = 0.0

        def _matvec_np(x_np: np.ndarray) -> np.ndarray:
            return np.asarray(_sparse_min_norm_mv(np.asarray(x_np, dtype=np.float64)), dtype=np.float64)

        operator_bundle = build_operator_from_pattern(
            _matvec_np,
            pattern=pattern,
            dtype=np.float64,
            backend=jax.default_backend(),
            csr_max_mb=float(csr_max_mb),
            drop_tol=float(drop_tol),
            allow_operator_only=False,
        )
        if emit is not None:
            emit(
                1,
                "explicit_sparse: "
                f"storage={operator_bundle.metadata.storage_kind} "
                f"reason={operator_bundle.metadata.reason}",
            )
        matrix = operator_bundle.matrix
        if matrix is None:
            raise RuntimeError("sparse_lsmr requires a materialized sparse matrix.")

        import scipy.sparse.linalg as _spla  # noqa: PLC0415

        lsmr_atol_env = os.environ.get("SFINCS_JAX_SPARSE_LSMR_ATOL", "").strip()
        lsmr_btol_env = os.environ.get("SFINCS_JAX_SPARSE_LSMR_BTOL", "").strip()
        lsmr_conlim_env = os.environ.get("SFINCS_JAX_SPARSE_LSMR_CONLIM", "").strip()
        lsmr_damp_env = os.environ.get("SFINCS_JAX_SPARSE_LSMR_DAMP", "").strip()
        lsmr_maxiter_env = os.environ.get("SFINCS_JAX_SPARSE_LSMR_MAXITER", "").strip()
        try:
            lsmr_atol = float(lsmr_atol_env) if lsmr_atol_env else float(tol)
        except ValueError:
            lsmr_atol = float(tol)
        try:
            lsmr_btol = float(lsmr_btol_env) if lsmr_btol_env else float(tol)
        except ValueError:
            lsmr_btol = float(tol)
        try:
            lsmr_conlim = float(lsmr_conlim_env) if lsmr_conlim_env else 1.0e8
        except ValueError:
            lsmr_conlim = 1.0e8
        try:
            lsmr_damp = float(lsmr_damp_env) if lsmr_damp_env else 0.0
        except ValueError:
            lsmr_damp = 0.0
        try:
            lsmr_maxiter = int(lsmr_maxiter_env) if lsmr_maxiter_env else max(1000, int(maxiter or 400))
        except ValueError:
            lsmr_maxiter = max(1000, int(maxiter or 400))
        lsmr_maxiter = max(1, int(lsmr_maxiter))
        rhs_np = np.asarray(rhs, dtype=np.float64).reshape((-1,))
        use_lsqr = solve_method_kind_explicit in {"sparse_lsqr", "sparse_host_lsqr"}
        if emit is not None:
            solver_name = "lsqr" if use_lsqr else "lsmr"
            emit(
                0,
                "solve_v3_full_system_linear_gmres: sparse_lsmr solve start "
                f"solver={solver_name} atol={lsmr_atol:.1e} btol={lsmr_btol:.1e} "
                f"damp={lsmr_damp:.1e} conlim={lsmr_conlim:.1e} maxiter={int(lsmr_maxiter)}",
            )
        if use_lsqr:
            ls_result = _spla.lsqr(
                matrix,
                rhs_np,
                damp=float(lsmr_damp),
                atol=float(lsmr_atol),
                btol=float(lsmr_btol),
                conlim=float(lsmr_conlim),
                iter_lim=int(lsmr_maxiter),
                show=bool(emit is not None and os.environ.get("SFINCS_JAX_SPARSE_LSMR_SHOW", "").strip().lower() in {"1", "true", "yes", "on"}),
            )
            x_np = np.asarray(ls_result[0], dtype=np.float64)
            istop = int(ls_result[1])
            iters = int(ls_result[2])
            solver_reported_residual = float(ls_result[3])
        else:
            ls_result = _spla.lsmr(
                matrix,
                rhs_np,
                damp=float(lsmr_damp),
                atol=float(lsmr_atol),
                btol=float(lsmr_btol),
                conlim=float(lsmr_conlim),
                maxiter=int(lsmr_maxiter),
                show=bool(emit is not None and os.environ.get("SFINCS_JAX_SPARSE_LSMR_SHOW", "").strip().lower() in {"1", "true", "yes", "on"}),
            )
            x_np = np.asarray(ls_result[0], dtype=np.float64)
            istop = int(ls_result[1])
            iters = int(ls_result[2])
            solver_reported_residual = float(ls_result[3])
        residual_true = rhs_np - np.asarray(matrix @ x_np, dtype=np.float64)
        residual_norm_sparse_lsmr = float(np.linalg.norm(residual_true))
        target = max(float(atol), float(tol) * float(rhs_norm))
        true_residual_converged = bool(float(residual_norm_sparse_lsmr) <= float(target))
        compatibility_converged = bool(int(istop) in {1, 2})
        petsc_compat_requested = solve_method_kind_explicit in _SPARSE_HOST_PETSC_COMPAT_SOLVE_METHODS
        accepted_converged = bool(true_residual_converged or (petsc_compat_requested and compatibility_converged))
        acceptance_criterion = (
            "true_residual"
            if true_residual_converged
            else "petsc_compatible_minimum_norm"
            if petsc_compat_requested and compatibility_converged
            else "not_converged"
        )
        if emit is not None:
            emit(
                0,
                "solve_v3_full_system_linear_gmres: sparse_lsmr complete "
                f"elapsed_s={sparse_timer.elapsed_s():.3f} iters={iters} istop={istop} "
                f"reported_residual={solver_reported_residual:.6e} "
                f"residual={residual_norm_sparse_lsmr:.6e} target={float(target):.6e} "
                f"accepted={accepted_converged} criterion={acceptance_criterion}",
            )
        return V3LinearSolveResult(
            op=op,
            rhs=rhs,
            gmres=GMRESSolveResult(
                x=jnp.asarray(x_np, dtype=jnp.float64),
                residual_norm=jnp.asarray(residual_norm_sparse_lsmr, dtype=jnp.float64),
            ),
            metadata={
                "solver_kind": "sparse_lsmr",
                "residual_kind": "least_squares_true_residual",
                "reported_residual_norm": float(solver_reported_residual),
                "iterations": int(iters),
                "info_code": int(istop),
                "least_squares_converged": bool(compatibility_converged),
                "true_residual_converged": bool(true_residual_converged),
                "accepted_converged": bool(accepted_converged),
                "acceptance_criterion": str(acceptance_criterion),
                "petsc_compat_requested": bool(petsc_compat_requested),
            },
        )
    if solve_method_kind_explicit in _SPARSE_HOST_DIRECT_SOLVE_METHODS:
        if differentiable is True:
            raise ValueError("solve_method='sparse_host' is a non-differentiable host sparse LU path.")
        if int(op.rhs_mode) != 1:
            raise NotImplementedError("solve_method='sparse_host' is currently implemented for RHSMode=1 only.")
        if use_active_dof_mode:
            raise NotImplementedError(
                "solve_method='sparse_host' currently targets the full system; set SFINCS_JAX_ACTIVE_DOF=0 "
                "or use the default matrix-free solver for active-DOF runs."
            )
        sparse_timer = Timer()
        if emit is not None:
            emit(1, "solve_v3_full_system_linear_gmres: sparse_host building conservative pattern")
        pattern = v3_full_system_conservative_sparsity_pattern(op)
        if emit is not None:
            summary = summarize_v3_sparse_pattern(op, pattern)
            emit(
                1,
                "solve_v3_full_system_linear_gmres: sparse_host pattern "
                f"nnz={summary.nnz} avg_row_nnz={summary.avg_row_nnz:.3g} max_row_nnz={summary.max_row_nnz}",
            )

        def _sparse_host_mv(x_np: np.ndarray) -> jnp.ndarray:
            return apply_v3_full_system_operator(op, jnp.asarray(x_np, dtype=rhs.dtype))

        operator_bundle, factor_bundle = _build_host_sparse_direct_factor_from_matvec(
            matvec=_sparse_host_mv,
            n=int(op.total_size),
            dtype=rhs.dtype,
            factor_dtype=np.dtype(np.float64),
            pattern=pattern,
            emit=emit,
        )
        x_np, residual_norm_sparse = _host_direct_solve_with_refinement(
            factor_solve=factor_bundle.solve,
            operator_matrix=operator_bundle.matrix,
            rhs_vec=rhs,
            factor_dtype=np.dtype(np.float64),
            refine_steps=_host_sparse_direct_refine_steps(
                "SFINCS_JAX_RHSMODE1_SPARSE_DIRECT_REFINE",
                default=2,
            ),
        )
        try:
            residual_true = np.asarray(rhs, dtype=np.float64) - np.asarray(
                jax.device_get(_sparse_host_mv(x_np)),
                dtype=np.float64,
            )
            residual_norm_sparse = float(np.linalg.norm(residual_true))
        except Exception:
            residual_norm_sparse = float(residual_norm_sparse)
        if emit is not None:
            emit(
                0,
                "solve_v3_full_system_linear_gmres: sparse_host complete "
                f"elapsed_s={sparse_timer.elapsed_s():.3f} residual={float(residual_norm_sparse):.6e}",
            )
        return V3LinearSolveResult(
            op=op,
            rhs=rhs,
            gmres=GMRESSolveResult(
                x=jnp.asarray(x_np, dtype=jnp.float64),
                residual_norm=jnp.asarray(residual_norm_sparse, dtype=jnp.float64),
            ),
            metadata={
                "solver_kind": "sparse_host",
                "residual_kind": "true_residual",
                "accepted_converged": bool(float(residual_norm_sparse) <= max(float(atol), float(tol) * float(rhs_norm))),
                "acceptance_criterion": "true_residual",
            },
        )
    rhs1_precond_env = os.environ.get("SFINCS_JAX_RHSMODE1_PRECONDITIONER", "").strip().lower()
    rhs1_precond_env_user = rhs1_precond_env
    rhs1_bicgstab_env = os.environ.get("SFINCS_JAX_RHSMODE1_BICGSTAB_PRECOND", "").strip().lower()
    rhs1_bicgstab_env_user = rhs1_bicgstab_env
    rhs1_precond_env = _rhs1_fp_dkes_env_preconditioner_kind(
        rhs1_precond_env=rhs1_precond_env,
        rhs_mode=int(op.rhs_mode),
        include_phi1=bool(op.include_phi1),
        has_fp=op.fblock.fp is not None,
        use_dkes=bool(use_dkes),
        total_size=int(op.total_size),
        n_theta=int(op.n_theta),
        n_zeta=int(op.n_zeta),
        max_l=int(np.max(nxi_for_x)) if nxi_for_x.size else 0,
    )
    try:
        pre_theta = int(precond_opts.get("PRECONDITIONER_THETA", 0) or 0)
    except (TypeError, ValueError):
        pre_theta = 0
    try:
        pre_zeta = int(precond_opts.get("PRECONDITIONER_ZETA", 0) or 0)
    except (TypeError, ValueError):
        pre_zeta = 0
    rhs1_precond_kind: str | None
    rhs1_xblock_tz_lmax: int | None = None
    rhs1_gpu_tokamak_pas_tight_gmres = False
    def _rhs1_dd_sharded_axis() -> str | None:
        gmres_dist_env = os.environ.get("SFINCS_JAX_GMRES_DISTRIBUTED", "").strip().lower()
        if gmres_dist_env in {"0", "false", "no", "off"}:
            return None
        if jax.device_count() <= 1:
            return None
        if gmres_dist_env in {"theta", "zeta"}:
            return gmres_dist_env
        axis_auto = _matvec_shard_axis(op)
        return axis_auto if axis_auto in {"theta", "zeta"} else None

    def _rhs1_dd_patch_dof_target() -> int:
        target_env = os.environ.get("SFINCS_JAX_RHSMODE1_SCHWARZ_PATCH_DOF_TARGET", "").strip()
        try:
            target = int(target_env) if target_env else 1200
        except ValueError:
            target = 1200
        return max(128, int(target))

    def _rhs1_dd_sum_nxi() -> int:
        nxi_for_x = np.asarray(op.fblock.collisionless.n_xi_for_x, dtype=np.int32)
        return max(1, int(np.sum(nxi_for_x)))

    def _parse_rhs1_dd_block(axis: str) -> int:
        if axis == "theta":
            env_key = "SFINCS_JAX_RHSMODE1_DD_BLOCK_T"
            n = int(op.n_theta)
        else:
            env_key = "SFINCS_JAX_RHSMODE1_DD_BLOCK_Z"
            n = int(op.n_zeta)
        env = os.environ.get(env_key, "").strip()
        try:
            block = int(env) if env else 0
        except ValueError:
            block = 0
        if block <= 0 and _rhs1_dd_sharded_axis() == axis:
            n_dev = max(1, int(jax.device_count()))
            sum_nxi = _rhs1_dd_sum_nxi()
            block = _rhs1_dd_auto_block_size(
                n=int(n),
                n_dev=n_dev,
                sum_nxi=sum_nxi,
                dof_target=_rhs1_dd_patch_dof_target(),
            )
        if block <= 0:
            block = 8
        return max(1, min(max(1, n), int(block)))

    def _parse_rhs1_dd_overlap(axis: str, *, default: int) -> int:
        if axis == "theta":
            axis_key = "SFINCS_JAX_RHSMODE1_DD_OVERLAP_T"
            n = int(op.n_theta)
        else:
            axis_key = "SFINCS_JAX_RHSMODE1_DD_OVERLAP_Z"
            n = int(op.n_zeta)
        env_axis = os.environ.get(axis_key, "").strip()
        env_generic = os.environ.get("SFINCS_JAX_RHSMODE1_DD_OVERLAP", "").strip()
        raw = env_axis if env_axis else env_generic
        try:
            overlap = int(raw) if raw else -1
        except ValueError:
            overlap = -1
        if overlap < 0 and _rhs1_dd_sharded_axis() == axis:
            block_auto = _parse_rhs1_dd_block(axis)
            sum_nxi = _rhs1_dd_sum_nxi()
            target = _rhs1_dd_patch_dof_target()
            overlap = 2 if int(block_auto) >= 4 else 1
            while overlap > 1 and int(block_auto + 2 * overlap) * int(sum_nxi) > int(target):
                overlap -= 1
            overlap = max(1, int(overlap))
        if overlap < 0:
            overlap = int(default)
        return max(0, min(max(0, n - 1), int(overlap)))

    pas_auto_strong_ratio_env = os.environ.get("SFINCS_JAX_PAS_AUTO_STRONG_RATIO", "").strip()
    try:
        pas_auto_strong_ratio = float(pas_auto_strong_ratio_env) if pas_auto_strong_ratio_env else 10.0
    except ValueError:
        pas_auto_strong_ratio = 10.0
    er_abs = 0.0
    schur_er_min = 1.0e-12

    if rhs1_precond_env:
        rhs1_precond_kind = _canonical_rhs1_preconditioner_kind(rhs1_precond_env)
    else:
        # Default to v3-like preconditioner options: when preconditioner_theta/zeta are 0,
        # use point-block Jacobi. Enable line preconditioning only when explicitly requested.
        if int(op.rhs_mode) == 1 and (not bool(op.include_phi1)):
            if pre_theta == 0 and pre_zeta == 0:
                tz_max_env = os.environ.get("SFINCS_JAX_RHSMODE1_TZ_PRECOND_MAX", "").strip()
                try:
                    tz_max = int(tz_max_env) if tz_max_env else 128
                except ValueError:
                    tz_max = 128
                xblock_tz_max_env = os.environ.get("SFINCS_JAX_RHSMODE1_XBLOCK_TZ_MAX", "").strip()
                default_xblock_tz_max = 1200
                if op.fblock.pas is not None and geom_scheme == 1:
                    default_xblock_tz_max = 6000
                elif op.fblock.pas is not None:
                    default_xblock_tz_max = 2000
                try:
                    xblock_tz_max = int(xblock_tz_max_env) if xblock_tz_max_env else default_xblock_tz_max
                except ValueError:
                    xblock_tz_max = default_xblock_tz_max
                xblock_tz_lmax_env = os.environ.get("SFINCS_JAX_RHSMODE1_XBLOCK_TZ_LMAX", "").strip()
                try:
                    xblock_tz_lmax_override = int(xblock_tz_lmax_env) if xblock_tz_lmax_env else 0
                except ValueError:
                    xblock_tz_lmax_override = 0
                species_block_max_env = os.environ.get("SFINCS_JAX_RHSMODE1_SPECIES_BLOCK_MAX", "").strip()
                try:
                    species_block_max = int(species_block_max_env) if species_block_max_env else 1600
                except ValueError:
                    species_block_max = 1600
                nxi_for_x = np.asarray(op.fblock.collisionless.n_xi_for_x, dtype=np.int32)
                max_l = int(np.max(nxi_for_x)) if nxi_for_x.size else 0
                lmax_auto = 0
                if int(op.n_theta) > 0 and int(op.n_zeta) > 0:
                    lmax_auto = int(xblock_tz_max // (int(op.n_theta) * int(op.n_zeta)))
                lmax_auto = max(0, min(max_l, lmax_auto))
                local_per_species = int(np.sum(nxi_for_x))
                dke_size = int(local_per_species * int(op.n_theta) * int(op.n_zeta))
                line_size = int(local_per_species * int(op.n_theta))
                sxblock_max_env = os.environ.get("SFINCS_JAX_RHSMODE1_SXBLOCK_MAX", "").strip()
                try:
                    sxblock_max = int(sxblock_max_env) if sxblock_max_env else 64
                except ValueError:
                    sxblock_max = 64
                sxblock_tz_max_env = os.environ.get("SFINCS_JAX_RHSMODE1_SXBLOCK_TZ_MAX", "").strip()
                try:
                    sxblock_tz_max = int(sxblock_tz_max_env) if sxblock_tz_max_env else 0
                except ValueError:
                    sxblock_tz_max = 0
                sxblock_tz_active_max_env = os.environ.get("SFINCS_JAX_RHSMODE1_SXBLOCK_TZ_ACTIVE_MAX", "").strip()
                try:
                    sxblock_tz_active_max = int(sxblock_tz_active_max_env) if sxblock_tz_active_max_env else 20000
                except ValueError:
                    sxblock_tz_active_max = 20000
                if sxblock_tz_max == 0 and op.fblock.fp is not None and (
                    int(op.n_theta) > 1 or int(op.n_zeta) > 1
                ):
                    # Allow a modest FP sxblock_tz preconditioner in multi-angle FP cases
                    # to avoid RHSMode=1 stagnation without large dense fallbacks.
                    sxblock_tz_max = 2000
                sxblock_size = int(int(op.n_species) * local_per_species)
                sxblock_tz_size = int(int(op.n_species) * int(op.n_x) * int(op.n_theta) * int(op.n_zeta))
                schur_auto = False
                if (
                    int(op.constraint_scheme) == 2
                    and int(op.extra_size) > 0
                    and op.fblock.pas is not None
                    and (int(op.n_theta) > 1 or int(op.n_zeta) > 1)
                ):
                    schur_auto_min_env = os.environ.get("SFINCS_JAX_RHSMODE1_SCHUR_AUTO_MIN", "").strip()
                    try:
                        schur_auto_min = int(schur_auto_min_env) if schur_auto_min_env else 2500
                    except ValueError:
                        schur_auto_min = 2500
                    schur_auto = int(op.total_size) >= schur_auto_min
                phys_params = nml.group("physicsParameters")
                er_val = phys_params.get("ER", phys_params.get("Er", phys_params.get("er", None)))
                er_abs = 0.0
                if er_val is not None:
                    try:
                        er_abs = float(er_val)
                    except (TypeError, ValueError):
                        er_abs = 0.0
                er_abs = abs(er_abs)
                epar_val = phys_params.get("EPARALLELHAT", phys_params.get("EParallelHat", None))
                try:
                    epar_abs = abs(float(epar_val)) if epar_val is not None else 0.0
                except (TypeError, ValueError):
                    epar_abs = 0.0
                if epar_abs > 0.0 and sxblock_tz_max == 0:
                    sxblock_tz_max = 2000
                schur_er_env = os.environ.get("SFINCS_JAX_RHSMODE1_SCHUR_ER_ABS_MIN", "").strip()
                try:
                    schur_er_min = float(schur_er_env) if schur_er_env else 1.0e-12
                except ValueError:
                    schur_er_min = 1.0e-12
                pas_dkes_gpu_xblock_env = os.environ.get("SFINCS_JAX_RHSMODE1_PAS_DKES_GPU_XBLOCK_TZ_MAX", "").strip()
                try:
                    pas_dkes_gpu_xblock_max = int(pas_dkes_gpu_xblock_env) if pas_dkes_gpu_xblock_env else 2500
                except ValueError:
                    pas_dkes_gpu_xblock_max = 2500
                pas_xdiag_env = os.environ.get("SFINCS_JAX_RHSMODE1_PAS_XDIAG_MIN", "").strip()
                try:
                    pas_xdiag_min = int(pas_xdiag_env) if pas_xdiag_env else 1000000000
                except ValueError:
                    pas_xdiag_min = 1000000000
                pas_xmg_env = os.environ.get("SFINCS_JAX_RHSMODE1_PAS_XMG_MIN", "").strip()
                try:
                    pas_xmg_min = int(pas_xmg_env) if pas_xmg_env else 80000
                except ValueError:
                    pas_xmg_min = 80000
                fp_xmg_env = os.environ.get("SFINCS_JAX_RHSMODE1_FP_XMG_MAX", "").strip()
                try:
                    # Keep xmg as the default for larger FP systems as long as we are still
                    # in the matrix-free Krylov regime; this avoids expensive Schwarz builds
                    # that can dominate runtime in high-resolution single-RHS runs.
                    fp_xmg_max = int(fp_xmg_env) if fp_xmg_env else 200000
                except ValueError:
                    fp_xmg_max = 200000
                schur_tokamak_env = os.environ.get("SFINCS_JAX_RHSMODE1_SCHUR_TOKAMAK", "").strip().lower()
                schur_tokamak = schur_tokamak_env in {"1", "true", "yes", "on"}
                tokamak_like = int(op.n_zeta) == 1 or geom_scheme == 1
                if full_precond_requested and int(op.constraint_scheme) == 2 and int(op.extra_size) > 0:
                    if tokamak_like and schur_tokamak and er_abs <= schur_er_min:
                        rhs1_precond_kind = "schur"
                    elif tokamak_like and (not schur_tokamak) and er_abs <= schur_er_min:
                        if op.fblock.pas is not None:
                            # For tiny tokamak PAS systems, prefer the xblock_tz preconditioner
                            # (matches legacy fixtures). For larger systems, keep the lighter
                            # PAS hybrid to avoid expensive dense angular blocks.
                            xblock_small_env = os.environ.get("SFINCS_JAX_RHSMODE1_XBLOCK_TZ_SMALL_MAX", "").strip()
                            try:
                                xblock_small_max = int(xblock_small_env) if xblock_small_env else 4000
                            except ValueError:
                                xblock_small_max = 4000
                            if (
                                int(op.total_size) <= max(1, int(xblock_small_max))
                                and int(max_l) * int(op.n_theta) * int(op.n_zeta) <= max(1, int(xblock_tz_max))
                            ):
                                rhs1_precond_kind = "xblock_tz"
                            else:
                                # Tokamak-like PAS systems benefit from the PAS hybrid (line + x-coarse)
                                # preconditioner; avoid the expensive global Schur/xblock path here.
                                rhs1_precond_kind = "pas_hybrid"
                        else:
                            pas_schur_small_env = os.environ.get("SFINCS_JAX_RHSMODE1_PAS_SCHUR_SMALL_MAX", "").strip()
                            try:
                                pas_schur_small_max = int(pas_schur_small_env) if pas_schur_small_env else 20000
                            except ValueError:
                                pas_schur_small_max = 20000
                            if int(op.total_size) <= max(1, int(pas_schur_small_max)):
                                rhs1_precond_kind = "schur"
                            elif (
                                int(op.n_theta) > 1
                                and xblock_tz_max > 0
                                and int(max_l) * int(op.n_theta) * int(op.n_zeta) <= xblock_tz_max
                            ):
                                rhs1_precond_kind = "xblock_tz"
                            else:
                                rhs1_precond_kind = "theta_line" if int(op.n_theta) >= int(op.n_zeta) else "zeta_line"
                    else:
                        if (
                            op.fblock.pas is not None
                            and er_abs <= schur_er_min
                            and (not schur_tokamak)
                            and int(op.total_size) < pas_xmg_min
                        ):
                            # For constrained PAS near-zero-Er systems below the Schur regime,
                            # prefer a lightweight PAS preconditioner when angular blocks are
                            # modest; otherwise fall back to x-coarsening to avoid expensive
                            # global Schur setup while retaining good Krylov convergence.
                            tz_size = int(op.n_theta) * int(op.n_zeta)
                            pas_lite_tz_env = os.environ.get("SFINCS_JAX_PAS_LITE_TZ_MAX", "").strip()
                            try:
                                pas_lite_tz_max = int(pas_lite_tz_env) if pas_lite_tz_env else 256
                            except ValueError:
                                pas_lite_tz_max = 256
                            if _pas_tz_preconditioner_applicable(op) and pas_lite_tz_max > 0 and tz_size <= pas_lite_tz_max:
                                pas_lite_min_env = os.environ.get("SFINCS_JAX_PAS_LITE_MIN", "").strip()
                                try:
                                    pas_lite_min = int(pas_lite_min_env) if pas_lite_min_env else 20000
                                except ValueError:
                                    pas_lite_min = 20000
                                if int(active_size) >= max(1, int(pas_lite_min)):
                                    rhs1_precond_kind = "pas_lite"
                                else:
                                    rhs1_precond_kind = "pas_hybrid"
                            else:
                                rhs1_precond_kind = "xmg"
                        elif (
                            op.fblock.fp is not None
                            and er_abs <= schur_er_min
                            and int(op.total_size) < fp_xmg_max
                        ):
                            rhs1_precond_kind = "xmg"
                        elif _rhs1_pas_tokamak_gpu_xblock_preferred(
                            has_pas=op.fblock.pas is not None,
                            has_fp=op.fblock.fp is not None,
                            backend=jax.default_backend(),
                            tokamak_like=tokamak_like,
                            active_size=int(active_size),
                            er_abs=float(er_abs),
                            schur_er_min=float(schur_er_min),
                            has_magdrift=(
                                op.fblock.magdrift_theta is not None
                                or op.fblock.magdrift_zeta is not None
                                or op.fblock.magdrift_xidot is not None
                            ),
                            has_collisionless=op.fblock.collisionless is not None,
                            n_theta=int(op.n_theta),
                            n_zeta=int(op.n_zeta),
                            max_l=int(max_l),
                            xblock_tz_limit=max(int(xblock_tz_max), int(pas_dkes_gpu_xblock_max)),
                        ):
                            rhs1_precond_kind = "xblock_tz"
                            if emit is not None:
                                emit(
                                    1,
                                    "solve_v3_full_system_linear_gmres: GPU PAS tokamak "
                                    "auto -> xblock_tz preconditioner",
                                )
                        elif _rhs1_pas_tokamak_gpu_theta_allowed(
                            has_pas=op.fblock.pas is not None,
                            has_fp=op.fblock.fp is not None,
                            backend=jax.default_backend(),
                            tokamak_like=tokamak_like,
                            active_size=int(active_size),
                            er_abs=float(er_abs),
                            schur_er_min=float(schur_er_min),
                            has_magdrift=(
                                op.fblock.magdrift_theta is not None
                                or op.fblock.magdrift_zeta is not None
                                or op.fblock.magdrift_xidot is not None
                            ),
                            has_collisionless=op.fblock.collisionless is not None,
                        ):
                            rhs1_precond_kind = None
                            rhs1_gpu_tokamak_pas_tight_gmres = True
                            if emit is not None:
                                emit(
                                    1,
                                    "solve_v3_full_system_linear_gmres: GPU PAS tokamak "
                                    "auto -> tight unpreconditioned GMRES",
                                )
                        elif op.fblock.pas is not None and int(op.total_size) >= pas_xmg_min:
                            # Large constrained PAS+Er systems need stronger x/L coupling than
                            # collision/point/xmg alone, but a global Schur setup can dominate
                            # wall time. Keep the auto path in the PAS-native family here so
                            # the later tokamak/3D refinements can promote to pas_tz/pas_ilu.
                            rhs1_precond_kind = _rhs1_pas_auto_large_base_kind(active_size=int(active_size))
                        elif op.fblock.pas is not None and int(op.total_size) >= pas_xdiag_min:
                            lmax_use = xblock_tz_lmax_override if xblock_tz_lmax_override > 0 else lmax_auto
                            if lmax_use >= 1:
                                rhs1_precond_kind = "xblock_tz_lmax"
                                rhs1_xblock_tz_lmax = int(lmax_use)
                            else:
                                rhs1_precond_kind = "point_xdiag"
                        else:
                            if op.fblock.pas is not None:
                                rhs1_precond_kind = _rhs1_pas_auto_large_base_kind(active_size=int(active_size))
                            else:
                                rhs1_precond_kind = "schur"
                elif full_precond_requested and (int(op.n_theta) > 1 or int(op.n_zeta) > 1):
                    if (
                        op.fblock.pas is not None
                        and er_abs <= schur_er_min
                        and (not schur_tokamak)
                        and int(op.total_size) < pas_xmg_min
                    ):
                        tz_size = int(op.n_theta) * int(op.n_zeta)
                        pas_lite_tz_env = os.environ.get("SFINCS_JAX_PAS_LITE_TZ_MAX", "").strip()
                        try:
                            pas_lite_tz_max = int(pas_lite_tz_env) if pas_lite_tz_env else 256
                        except ValueError:
                            pas_lite_tz_max = 256
                        if _pas_tz_preconditioner_applicable(op) and pas_lite_tz_max > 0 and tz_size <= pas_lite_tz_max:
                            pas_lite_min_env = os.environ.get("SFINCS_JAX_PAS_LITE_MIN", "").strip()
                            try:
                                pas_lite_min = int(pas_lite_min_env) if pas_lite_min_env else 20000
                            except ValueError:
                                pas_lite_min = 20000
                            if int(active_size) >= max(1, int(pas_lite_min)):
                                rhs1_precond_kind = "pas_lite"
                            else:
                                rhs1_precond_kind = "pas_hybrid"
                        else:
                            rhs1_precond_kind = "xmg"
                    elif (
                        op.fblock.fp is not None
                        and er_abs <= schur_er_min
                        and int(op.total_size) < fp_xmg_max
                    ):
                        rhs1_precond_kind = "xmg"
                    else:
                        rhs1_precond_kind = "theta_line" if int(op.n_theta) >= int(op.n_zeta) else "zeta_line"
                elif schur_auto:
                    # For sharded multi-device PAS near-zero-Er runs, Schur can become
                    # communication-dominated as device count increases. Prefer x-coarsening
                    # here to keep Krylov/preconditioner cost closer to shard-local.
                    shard_axis_auto = _matvec_shard_axis(op)
                    if (
                        op.fblock.pas is not None
                        and (not bool(op.include_phi1))
                        and float(er_abs) <= float(schur_er_min)
                        and shard_axis_auto in {"theta", "zeta"}
                        and jax.device_count() > 1
                        and int(op.total_size) <= max(1, int(pas_xmg_min))
                    ):
                        rhs1_precond_kind = "xmg"
                        if emit is not None:
                            emit(
                                1,
                                "solve_v3_full_system_linear_gmres: sharded PAS near-zero-Er "
                                "schur_auto -> xmg preconditioner",
                            )
                    elif _rhs1_pas_dkes_pas_tz_preferred(
                        has_pas=op.fblock.pas is not None,
                        use_dkes=bool(use_dkes),
                        backend=jax.default_backend(),
                        n_theta=int(op.n_theta),
                        n_zeta=int(op.n_zeta),
                        max_l=int(max_l),
                        active_size=int(active_size),
                    ):
                        rhs1_precond_kind = "pas_tz"
                        if emit is not None:
                            emit(
                                1,
                                "solve_v3_full_system_linear_gmres: PAS DKES "
                                "schur_auto -> pas_tz preconditioner",
                            )
                    elif _rhs1_pas_dkes_xblock_allowed(
                        has_pas=op.fblock.pas is not None,
                        use_dkes=bool(use_dkes),
                        backend=jax.default_backend(),
                        n_theta=int(op.n_theta),
                        n_zeta=int(op.n_zeta),
                        max_l=int(max_l),
                        xblock_tz_limit=max(int(xblock_tz_max), int(pas_dkes_gpu_xblock_max)),
                    ):
                        rhs1_precond_kind = "xblock_tz"
                        if emit is not None:
                            emit(
                                1,
                                "solve_v3_full_system_linear_gmres: GPU PAS DKES "
                                "schur_auto -> xblock_tz preconditioner",
                            )
                    else:
                        rhs1_precond_kind = "schur"
                elif op.fblock.fp is not None and use_dkes:
                    # DKES-trajectory FP cases can stagnate with collision-only
                    # preconditioners. Prefer a lightweight xmg/sxblock_tz path for
                    # small/medium systems, and fall back to collision for larger sizes
                    # to avoid expensive block builds.
                    max_l = int(np.max(nxi_for_x)) if nxi_for_x.size else 0
                    rhs1_precond_kind = _rhs1_fp_dkes_default_kind(
                        active_size=int(active_size),
                        n_theta=int(op.n_theta),
                        n_zeta=int(op.n_zeta),
                        max_l=int(max_l),
                        xblock_tz_limit=int(xblock_tz_max),
                    )
                    if rhs1_precond_kind == "xblock_tz" and not rhs1_precond_env:
                        rhs1_precond_env = "xblock_tz"
                elif (
                    op.fblock.fp is not None
                    and er_abs <= schur_er_min
                    and int(active_size) < fp_xmg_max
                ):
                    # For moderate-size FP systems at near-zero Er, x-coarsened preconditioning
                    # is typically much cheaper than global (S,X,theta,zeta) blocks and
                    # preserves parity for RHSMode=1.
                    rhs1_precond_kind = "xmg"
                elif (
                    op.fblock.fp is not None
                    and (int(op.n_theta) > 1 or int(op.n_zeta) > 1)
                    and sxblock_tz_max > 0
                    and int(op.total_size) <= max(1, int(sxblock_tz_active_max))
                    and sxblock_tz_size <= sxblock_tz_max
                ):
                    rhs1_precond_kind = "sxblock_tz"
                elif (
                    op.fblock.fp is not None
                    and (int(op.n_theta) > 1 or int(op.n_zeta) > 1)
                    and int(op.n_theta) * int(op.n_zeta) <= tz_max
                ):
                    rhs1_precond_kind = "theta_zeta"
                elif op.fblock.fp is not None and sxblock_max > 0 and sxblock_size <= sxblock_max:
                    rhs1_precond_kind = "sxblock"
                elif (
                    op.fblock.pas is not None
                    and int(op.n_theta) > 1
                    and int(op.n_zeta) > 1
                    and species_block_max > 0
                    and dke_size <= species_block_max
                ):
                    rhs1_precond_kind = "species_block"
                elif _rhs1_pas_dkes_pas_tz_preferred(
                    has_pas=op.fblock.pas is not None,
                    use_dkes=bool(use_dkes),
                    backend=jax.default_backend(),
                    n_theta=int(op.n_theta),
                    n_zeta=int(op.n_zeta),
                    max_l=int(max_l),
                    active_size=int(active_size),
                ):
                    rhs1_precond_kind = "pas_tz"
                    if emit is not None:
                        emit(
                            1,
                            "solve_v3_full_system_linear_gmres: PAS DKES "
                            "auto -> pas_tz preconditioner",
                        )
                elif (
                    op.fblock.pas is not None
                    and int(op.n_theta) > 1
                    and xblock_tz_max > 0
                    and int(max_l) * int(op.n_theta) * int(op.n_zeta) <= xblock_tz_max
                ):
                    rhs1_precond_kind = "xblock_tz"
                elif (
                    op.fblock.pas is not None
                    and int(op.n_theta) > 1
                    and int(op.n_zeta) > 1
                    and int(op.n_theta) * int(op.n_zeta) <= tz_max
                ):
                    rhs1_precond_kind = "theta_zeta"
                elif (
                    op.fblock.pas is not None
                    and int(active_size) >= pas_xmg_min
                ):
                    # Large PAS systems tend to be x/L-coupling dominated. Prefer the
                    # x-coarsened PAS preconditioner over weak collision/point
                    # preconditioners that often trigger expensive fallback branches.
                    rhs1_precond_kind = "xmg"
                else:
                    if (
                        op.fblock.pas is not None
                        and er_abs <= schur_er_min
                        and int(active_size) < pas_xmg_min
                    ):
                        tz_size = int(op.n_theta) * int(op.n_zeta)
                        pas_lite_tz_env = os.environ.get("SFINCS_JAX_PAS_LITE_TZ_MAX", "").strip()
                        try:
                            pas_lite_tz_max = int(pas_lite_tz_env) if pas_lite_tz_env else 256
                        except ValueError:
                            pas_lite_tz_max = 256
                        if _pas_tz_preconditioner_applicable(op) and pas_lite_tz_max > 0 and tz_size <= pas_lite_tz_max:
                            pas_lite_min_env = os.environ.get("SFINCS_JAX_PAS_LITE_MIN", "").strip()
                            try:
                                pas_lite_min = int(pas_lite_min_env) if pas_lite_min_env else 20000
                            except ValueError:
                                pas_lite_min = 20000
                            if int(active_size) >= max(1, int(pas_lite_min)):
                                rhs1_precond_kind = "pas_lite"
                            else:
                                rhs1_precond_kind = "pas_hybrid"
                        else:
                            rhs1_precond_kind = "xmg"
                    else:
                        collision_precond_min_env = os.environ.get("SFINCS_JAX_RHSMODE1_COLLISION_PRECOND_MIN", "").strip()
                        try:
                            collision_precond_min = int(collision_precond_min_env) if collision_precond_min_env else 600
                        except ValueError:
                            collision_precond_min = 600
                        use_collision_precond = (
                            (op.fblock.fp is not None or op.fblock.pas is not None)
                            and int(op.total_size) >= collision_precond_min
                        )
                        if (
                            use_collision_precond
                            and full_precond_requested
                            and op.fblock.pas is not None
                            and int(op.total_size) >= pas_xdiag_min
                        ):
                            rhs1_precond_kind = "point_xdiag"
                        else:
                            # Last-resort auto mode: collision-only preconditioning is cheap but
                            # can be too weak/unstable for FP systems at nonzero Er. Prefer xmg
                            # when the (x,theta,zeta) grid is still moderate to improve robustness.
                            if (
                                op.fblock.fp is not None
                                and op.fblock.pas is None
                                and int(active_size) < fp_xmg_max
                            ):
                                rhs1_precond_kind = "xmg"
                            else:
                                rhs1_precond_kind = "collision" if use_collision_precond else "point"
                theta_line_max_env = os.environ.get("SFINCS_JAX_RHSMODE1_THETA_LINE_MAX", "").strip()
                try:
                    theta_line_max = int(theta_line_max_env) if theta_line_max_env else 0
                except ValueError:
                    theta_line_max = 0
                if rhs1_precond_kind == "theta_line" and theta_line_max > 0 and line_size > theta_line_max:
                    rhs1_precond_kind = "theta_line_xdiag"
            elif pre_theta > 0 and pre_zeta > 0:
                rhs1_precond_kind = "adi"
            elif pre_theta > 0:
                rhs1_precond_kind = "theta_line"
            elif pre_zeta > 0:
                rhs1_precond_kind = "zeta_line"
            else:
                rhs1_precond_kind = "point"
        else:
            rhs1_precond_kind = None
    if (
        (not rhs1_precond_env)
        and int(op.rhs_mode) == 1
        and (not bool(op.include_phi1))
        and op.fblock.pas is not None
        and rhs1_precond_kind
        in {
            None,
            "collision",
            "point",
            "xmg",
            "theta_line",
            "zeta_line",
            "theta_zeta",
            "xblock_tz",
            "xblock_tz_lmax",
            "theta_line_xdiag",
        }
        and not rhs1_gpu_tokamak_pas_tight_gmres
    ):
        # PAS runs can stagnate with weak preconditioners; use the
        # PAS hybrid (line + x-coarse) preconditioner by default. For large systems,
        # prefer a lighter PAS preconditioner to keep setup cost down. The PAS probe
        # can still downgrade to a collision preconditioner if it suffices.
        max_l_local = int(np.max(nxi_for_x)) if nxi_for_x.size else 0
        rhs1_precond_kind = _rhs1_pas_weak_auto_override_kind(
            rhs1_precond_env=rhs1_precond_env,
            rhs_mode=int(op.rhs_mode),
            include_phi1=bool(op.include_phi1),
            has_pas=op.fblock.pas is not None,
            current_kind=rhs1_precond_kind,
            active_size=int(active_size),
            n_theta=int(op.n_theta),
            n_zeta=int(op.n_zeta),
            max_l=int(max_l_local),
        )
        if (
            rhs1_precond_kind == "xblock_tz"
            and _rhs1_pas_dkes_pas_tz_preferred(
                has_pas=op.fblock.pas is not None,
                use_dkes=bool(use_dkes),
                backend=jax.default_backend(),
                n_theta=int(op.n_theta),
                n_zeta=int(op.n_zeta),
                max_l=int(max_l_local),
                active_size=int(active_size),
            )
        ):
            rhs1_precond_kind = "pas_tz"
            if emit is not None:
                emit(
                    1,
                    "solve_v3_full_system_linear_gmres: PAS DKES "
                    "weak-auto override -> pas_tz preconditioner",
                )
    tokamak_like = bool(geom_scheme == 1 or int(op.n_zeta) <= 5)
    rhs1_precond_kind = _rhs1_pas_family_refinement_kind(
        rhs1_precond_env=rhs1_precond_env,
        has_pas=op.fblock.pas is not None,
        has_fp=op.fblock.fp is not None,
        current_kind=rhs1_precond_kind,
        active_size=int(active_size),
        n_zeta=int(op.n_zeta),
        geom_scheme=int(geom_scheme),
        pas_tz_applicable=_pas_tz_preconditioner_applicable(op),
        pas_tokamak_theta_applicable=_pas_tokamak_theta_preconditioner_applicable(op),
    )
    if (
        rhs1_precond_env in {"", "auto", "default"}
        and rhs1_precond_kind == "schur"
        and _rhs1_pas_full_pas_tz_preferred(
            has_pas=op.fblock.pas is not None,
            has_fp=op.fblock.fp is not None,
            use_dkes=bool(use_dkes),
            backend=jax.default_backend(),
            geom_scheme=int(geom_scheme),
            n_theta=int(op.n_theta),
            n_zeta=int(op.n_zeta),
            max_l=int(max_l),
            active_size=int(active_size),
            pas_tz_applicable=_pas_tz_preconditioner_applicable(op),
        )
    ):
        rhs1_precond_kind = "pas_tz"
        if emit is not None:
            emit(
                1,
                "solve_v3_full_system_linear_gmres: full-trajectory PAS "
                "auto -> pas_tz preconditioner",
            )
    if _rhs1_geometry4_pas_memory_pas_tz_preferred(
        rhs1_precond_env=rhs1_precond_env,
        current_kind=rhs1_precond_kind,
        has_pas=op.fblock.pas is not None,
        has_fp=op.fblock.fp is not None,
        use_dkes=bool(use_dkes),
        geom_scheme=int(geom_scheme),
        n_theta=int(op.n_theta),
        n_zeta=int(op.n_zeta),
        max_l=int(max_l),
        active_size=int(active_size),
        er_abs=float(er_abs),
        schur_er_min=float(schur_er_min),
        pas_tz_applicable=_pas_tz_preconditioner_applicable(op),
    ):
        rhs1_precond_kind = "pas_tz"
        if emit is not None:
            emit(
                1,
                "solve_v3_full_system_linear_gmres: geometry4 PAS memory "
                "auto -> pas_tz preconditioner",
            )
    if (
        tokamak_like
        and rhs1_precond_env in {"", "auto", "default"}
        and rhs1_precond_kind in {"pas_lite", "pas_hybrid", "pas_tokamak_theta", "pas_tz", "xmg", "collision", "point"}
        and op.fblock.pas is not None
        and op.fblock.fp is None
        and (not _pas_tz_preconditioner_applicable(op))
        and (not _pas_tokamak_theta_preconditioner_applicable(op))
        and (not _rhs1_pas_tokamak_gpu_theta_allowed(
            has_pas=op.fblock.pas is not None,
            has_fp=op.fblock.fp is not None,
            backend=jax.default_backend(),
            tokamak_like=tokamak_like,
            active_size=int(active_size),
            er_abs=float(er_abs),
            schur_er_min=float(schur_er_min),
            has_magdrift=(
                op.fblock.magdrift_theta is not None
                or op.fblock.magdrift_zeta is not None
                or op.fblock.magdrift_xidot is not None
            ),
            has_collisionless=op.fblock.collisionless is not None,
        ))
    ):
        if _rhs1_pas_tokamak_cpu_xblock_preferred(
            has_pas=op.fblock.pas is not None,
            has_fp=op.fblock.fp is not None,
            backend=jax.default_backend(),
            tokamak_like=tokamak_like,
            active_size=int(active_size),
            er_abs=float(er_abs),
            schur_er_min=float(schur_er_min),
            has_magdrift=(
                op.fblock.magdrift_theta is not None
                or op.fblock.magdrift_zeta is not None
                or op.fblock.magdrift_xidot is not None
            ),
            has_collisionless=op.fblock.collisionless is not None,
            n_theta=int(op.n_theta),
            n_zeta=int(op.n_zeta),
            max_l=int(max_l),
            xblock_tz_limit=max(1, int(xblock_tz_max)),
        ):
            rhs1_precond_kind = "xblock_tz"
            if emit is not None:
                emit(
                    1,
                    "solve_v3_full_system_linear_gmres: CPU PAS tokamak "
                    "auto -> xblock_tz preconditioner",
                )
        else:
            rhs1_precond_kind = "pas_schur"
    if (
        rhs1_precond_env == ""
        and int(op.rhs_mode) == 1
        and (not bool(op.include_phi1))
        and op.fblock.fp is not None
        and op.fblock.pas is None
        and float(er_abs) <= float(schur_er_min)
    ):
        rhs1_precond_kind_override = _rhs1_large_fp_near_zero_er_override_kind(
            rhs1_precond_env=rhs1_precond_env,
            rhs_mode=int(op.rhs_mode),
            include_phi1=bool(op.include_phi1),
            has_fp=op.fblock.fp is not None,
            has_pas=op.fblock.pas is not None,
            current_kind=rhs1_precond_kind,
            total_size=int(op.total_size),
            er_abs=float(er_abs),
            schur_er_min=float(schur_er_min),
        )
        if rhs1_precond_kind_override != rhs1_precond_kind:
            rhs1_precond_kind = rhs1_precond_kind_override
            if emit is not None:
                emit(
                    1,
                    "solve_v3_full_system_linear_gmres: large FP near-zero-Er "
                    "auto override -> xmg preconditioner",
                )
    if (
        rhs1_precond_env == ""
        and int(op.rhs_mode) == 1
        and op.fblock.pas is not None
        and rhs1_precond_kind in {None, "collision", "point"}
        and not rhs1_gpu_tokamak_pas_tight_gmres
    ):
        pas_strong_max_env = os.environ.get("SFINCS_JAX_PAS_STRONG_MAX", "").strip()
        try:
            pas_strong_max = int(pas_strong_max_env) if pas_strong_max_env else 25000
        except ValueError:
            pas_strong_max = 25000
        if int(active_size) <= max(1, int(pas_strong_max)):
            rhs1_precond_kind = "pas_hybrid"
    if (
        rhs1_precond_env == ""
        and int(op.rhs_mode) == 1
        and (not bool(op.include_phi1))
        and op.fblock.pas is not None
        and int(op.n_species) >= 2
        and (geom_scheme == 1 or int(op.n_zeta) <= 9)
        and rhs1_precond_kind in {"theta_line", "zeta_line", "theta_zeta"}
    ):
        # Multi-species PAS tokamak-like runs are prone to stagnation with pure line
        # preconditioners; prefer Schur by default for robustness/parity.
        rhs1_precond_kind = "schur"
    rhs1_precond_kind_requested = rhs1_precond_kind
    if rhs1_precond_env == "" and rhs1_precond_kind == "point" and use_pas_projection:
        # PAS tokamak-like cases benefit from a stronger line preconditioner by default.
        rhs1_precond_kind = "theta_line" if int(op.n_theta) >= int(op.n_zeta) else "zeta_line"
    if rhs1_precond_env == "":
        shard_axis = _matvec_shard_axis(op)
        if shard_axis in {"theta", "zeta"} and jax.device_count() > 1:
            pas_tz_estimate = _estimate_rhs1_pas_tz_build_bytes(op)
            pas_tz_max_bytes = _rhs1_pas_tz_max_bytes()
            pas_shard_xmg_min_env = os.environ.get("SFINCS_JAX_RHSMODE1_PAS_SHARD_XMG_MIN", "").strip()
            try:
                pas_shard_xmg_min = int(pas_shard_xmg_min_env) if pas_shard_xmg_min_env else 80000
            except ValueError:
                pas_shard_xmg_min = 80000
            fp_shard_xmg_min_env = os.environ.get("SFINCS_JAX_RHSMODE1_FP_SHARD_XMG_MIN", "").strip()
            try:
                fp_shard_xmg_min = int(fp_shard_xmg_min_env) if fp_shard_xmg_min_env else 120000
            except ValueError:
                fp_shard_xmg_min = 120000
            keep_xmg_for_large_pas_er = bool(
                rhs1_precond_kind == "xmg"
                and op.fblock.pas is not None
                and int(op.total_size) >= max(1, int(pas_shard_xmg_min))
            )
            keep_xmg_for_large_fp = bool(
                rhs1_precond_kind == "xmg"
                and op.fblock.fp is not None
                and int(op.total_size) >= max(1, int(fp_shard_xmg_min))
            )
            schwarz_auto_min_env = os.environ.get("SFINCS_JAX_RHSMODE1_SCHWARZ_AUTO_MIN", "").strip()
            try:
                schwarz_auto_min = int(schwarz_auto_min_env) if schwarz_auto_min_env else 120000
            except ValueError:
                schwarz_auto_min = 120000
            force_schwarz = bool(schwarz_auto_min_env) and int(schwarz_auto_min) <= 0
            if force_schwarz:
                rhs1_precond_kind = "theta_schwarz" if shard_axis == "theta" else "zeta_schwarz"
            elif _rhs1_sharded_line_override_allowed(rhs1_precond_kind):
                # Preserve dedicated PAS preconditioners on sharded runs. Demoting
                # pas_tz/pas_tokamak_theta/pas_ilu to pure line blocks can turn a
                # parity-clean moderate PAS solve into a long line-preconditioned
                # Krylov run with no robustness benefit.
                if rhs1_precond_kind in {"theta_line", "zeta_line"} and rhs1_precond_kind != f"{shard_axis}_line":
                    pass
                elif keep_xmg_for_large_pas_er or keep_xmg_for_large_fp:
                    pass
                elif (
                    op.fblock.pas is not None
                    and pas_tz_estimate > max(0, int(pas_tz_max_bytes))
                ):
                    rhs1_precond_kind = "theta_schwarz" if shard_axis == "theta" else "zeta_schwarz"
                    if emit is not None:
                        emit(
                            1,
                            "solve_v3_full_system_linear_gmres: sharded PAS large pas_tz "
                            f"(est={pas_tz_estimate / 2**30:.2f} GiB > cap={pas_tz_max_bytes / 2**30:.2f} GiB) -> "
                            f"{rhs1_precond_kind}",
                        )
                elif int(op.total_size) >= max(1, int(schwarz_auto_min)):
                    rhs1_precond_kind = "theta_schwarz" if shard_axis == "theta" else "zeta_schwarz"
                else:
                    rhs1_precond_kind = "theta_line" if shard_axis == "theta" else "zeta_line"
    if (
        rhs1_precond_env == ""
        and rhs1_precond_kind == "schur"
        and op.fblock.pas is not None
        and (not bool(op.include_phi1))
    ):
        # In sharded multi-device PAS runs, the global Schur preconditioner can dominate
        # wall time for moderate-size systems. Prefer shard-local Schwarz blocks when
        # Er is near zero, where this branch is typically more than sufficient.
        shard_axis = _matvec_shard_axis(op)
        if shard_axis in {"theta", "zeta"} and jax.device_count() > 1:
            schur_shard_max_env = os.environ.get("SFINCS_JAX_RHSMODE1_SCHUR_SHARD_MAX", "").strip()
            try:
                schur_shard_max = int(schur_shard_max_env) if schur_shard_max_env else 30000
            except ValueError:
                schur_shard_max = 30000
            schur_shard_er_env = os.environ.get("SFINCS_JAX_RHSMODE1_SCHUR_SHARD_ER_MAX", "").strip()
            try:
                schur_shard_er_max = float(schur_shard_er_env) if schur_shard_er_env else 1.0e-8
            except ValueError:
                schur_shard_er_max = 1.0e-8
            if int(op.total_size) <= max(1, int(schur_shard_max)) and float(er_abs) <= max(
                0.0, float(schur_shard_er_max)
            ):
                rhs1_precond_kind = "theta_schwarz" if shard_axis == "theta" else "zeta_schwarz"
                if emit is not None:
                    emit(
                        1,
                        "solve_v3_full_system_linear_gmres: sharded PAS near-zero-Er -> "
                        f"{rhs1_precond_kind} preconditioner",
                    )
    if str(solve_method).strip().lower() in {"dense", "dense_ksp", "dense_row_scaled"}:
        rhs1_precond_kind = None
    pas_tokamak_gpu_tol = _rhs1_pas_tokamak_gpu_tight_tol(
        enabled=rhs1_gpu_tokamak_pas_tight_gmres or rhs1_precond_kind == "pas_tokamak_theta",
        has_pas=op.fblock.pas is not None,
        has_fp=op.fblock.fp is not None,
        backend=jax.default_backend(),
        tokamak_like=tokamak_like,
        active_size=int(active_size),
        er_abs=float(er_abs),
        schur_er_min=float(schur_er_min),
        has_magdrift=(
            op.fblock.magdrift_theta is not None
            or op.fblock.magdrift_zeta is not None
            or op.fblock.magdrift_xidot is not None
        ),
        has_collisionless=op.fblock.collisionless is not None,
    )
    if pas_tokamak_gpu_tol is not None:
        tol_old = float(tol)
        tol = min(float(tol), float(pas_tokamak_gpu_tol))
        if emit is not None and float(tol) < tol_old:
            emit(
                1,
                "solve_v3_full_system_linear_gmres: GPU PAS tokamak "
                f"tol tightened {tol_old:.1e} -> {float(tol):.1e}",
            )
    if (
        (not rhs1_precond_env)
        and maxiter_env == ""
        and int(op.rhs_mode) == 1
        and (not bool(op.include_phi1))
        and op.fblock.fp is not None
        and op.fblock.pas is None
        and rhs1_precond_kind == "xmg"
        and int(op.total_size) >= 120000
    ):
        # Keep large full-trajectory FP cases inside the regression budget by
        # capping default Krylov work when xmg is selected automatically.
        #
        # Use the same cap on single- and multi-device runs. The tighter multi-device
        # cap can under-converge large FP systems.
        fp_auto_maxiter = 800
        maxiter = min(int(maxiter if maxiter is not None else 400), int(fp_auto_maxiter))
        fp_auto_restart_max = 160
        restart = max(80, min(int(restart), int(fp_auto_restart_max)))
        if emit is not None:
            emit(
                1,
                "solve_v3_full_system_linear_gmres: large FP auto-tune "
                f"(precond=xmg restart={int(restart)} maxiter={int(maxiter)})",
            )
    rhs1_precond_enabled = (
        rhs1_precond_kind is not None
        and int(op.rhs_mode) == 1
        and (not bool(op.include_phi1))
    )
    _set_precond_policy_hints(
        geom_scheme=geom_scheme,
        use_dkes=bool(use_dkes),
        rhs1_precond_kind=rhs1_precond_kind,
        has_pas=getattr(op.fblock, "pas", None) is not None,
        has_fp=getattr(op.fblock, "fp", None) is not None,
        include_phi1=bool(op.include_phi1),
        rhs_mode=int(op.rhs_mode),
        er_abs=float(er_abs),
    )
    if rhs1_bicgstab_env in {"0", "false", "no", "off"}:
        rhs1_bicgstab_kind = None
    elif rhs1_bicgstab_env in {"rhs1", "same", "preconditioner"}:
        rhs1_bicgstab_kind = "rhs1"
    elif rhs1_bicgstab_env in {"", "1", "true", "yes", "on", "collision", "diag"}:
        rhs1_bicgstab_kind = "collision"
    else:
        rhs1_bicgstab_kind = None
    if tokamak_pas and rhs1_bicgstab_env in {"", "auto"}:
        # Tokamak PAS systems converge more reliably with GMRES-only.
        rhs1_bicgstab_kind = None
    if (
        rhs1_bicgstab_kind == "collision"
        and op.fblock.fp is not None
        and rhs1_precond_kind not in {None, "collision"}
    ):
        rhs1_bicgstab_kind = "rhs1"
    if (
        rhs1_bicgstab_kind == "collision"
        and op.fblock.pas is not None
        and use_dkes
        and rhs1_precond_kind not in {None, "collision"}
    ):
        # For PAS+DKES, BiCGStab only pays off if it uses the same strong RHS1
        # preconditioner as GMRES (typically Schur + sparse PAS blocks). A cheap
        # collision-only preconditioner often stagnates and just triggers a GMRES
        # fallback (wasting compile/runtime).
        rhs1_bicgstab_kind = "rhs1"
    solve_method_kind = str(solve_method).strip().lower()
    use_implicit = _resolve_use_implicit(differentiable=differentiable)
    if (
        solve_method_kind in {"auto", "default", "incremental"}
        and (not use_implicit)
        and op.fblock.fp is not None
        and op.fblock.pas is None
        and (not bool(op.include_phi1))
        and int(op.rhs_mode) == 1
    ):
        dense_auto_cutoff = _rhs1_dense_auto_fp_cutoff_impl(
            dense_active_cutoff=_rhsmode1_dense_fallback_max(op),
        )
        if _rhs1_dense_auto_fp_allowed_impl(
            backend=jax.default_backend(),
            active_size=int(active_size),
            dense_active_cutoff=_rhsmode1_dense_fallback_max(op),
        ):
            solve_method = "dense"
            solve_method_kind = "dense"
            if emit is not None:
                emit(
                    1,
                    "solve_v3_full_system_linear_gmres: auto-selected dense "
                    f"full-FP solve (size={int(active_size)} <= cutoff={int(dense_auto_cutoff)})",
                )
    if solve_method_kind == "dense_ksp":
        # `dense_ksp` uses its own PETSc-like block preconditioner on the assembled dense system.
        rhs1_precond_enabled = False
    gmres_precond_side_env = os.environ.get("SFINCS_JAX_GMRES_PRECONDITION_SIDE", "").strip().lower()
    if gmres_precond_side_env not in {"", "left", "right", "none"}:
        gmres_precond_side_env = ""
    # Upstream SFINCS v3 reports KSP residual norms for the *preconditioned* residual, matching
    # a left-preconditioned solve. Default to left to align solver-branch parity and to avoid
    # JAX transpose-rule limitations in the right-preconditioned path.
    gmres_precond_side = gmres_precond_side_env or "left"

    bicgstab_fallback_env = os.environ.get("SFINCS_JAX_BICGSTAB_FALLBACK", "").strip().lower()
    if bicgstab_fallback_env in {"0", "false", "no", "off"}:
        bicgstab_fallback_strict = False
    elif bicgstab_fallback_env in {"1", "true", "yes", "on", "strict"}:
        bicgstab_fallback_strict = True
    else:
        # Default to strict fallback to preserve parity when BiCGStab stagnates.
        bicgstab_fallback_strict = True
    if pas_large_bicgstab_fastpath and bicgstab_fallback_env == "":
        # PAS-large fastpath intentionally accepts the short-recurrence solution
        # when it is already parity-accurate at our regression tolerances.
        bicgstab_fallback_strict = False
    distributed_axis = _resolve_distributed_gmres_axis(op=op, emit=emit)
    use_sharded_matvec = distributed_axis in {"theta", "zeta"} and (not use_implicit)
    distributed_auto_solver_env = os.environ.get("SFINCS_JAX_DISTRIBUTED_KRYLOV", "").strip().lower()
    if distributed_auto_solver_env in {"", "auto", "comm_reduced", "short_recurrence", "bicgstab", "bicgstab_jax"}:
        distributed_auto_solver = "bicgstab"
    elif distributed_auto_solver_env in {"gmres", "incremental", "batched"}:
        distributed_auto_solver = "gmres"
    else:
        distributed_auto_solver = "bicgstab"
    if use_sharded_matvec:
        def mv(x):
            return apply_v3_full_system_operator(op, x, allow_sharding=True)
    else:
        def mv(x):
            # Use the JIT-compiled operator application to reduce Python overhead in repeated matvecs
            # (e.g. during GMRES iterations and Er scans).
            return apply_v3_full_system_operator_cached(op, x)

    sparse_precond_env = os.environ.get("SFINCS_JAX_RHSMODE1_SPARSE_PRECOND", "").strip().lower()
    if sparse_precond_env in {"jax", "jax_native", "native"}:
        sparse_precond_mode = "on"
        sparse_precond_kind = "jax"
    elif sparse_precond_env in {"scipy", "ilu", "spilu"}:
        sparse_precond_mode = "on"
        sparse_precond_kind = "scipy"
    elif sparse_precond_env in {"1", "true", "yes", "on"}:
        sparse_precond_mode = "on"
        sparse_precond_kind = "auto"
    elif sparse_precond_env in {"0", "false", "no", "off"}:
        sparse_precond_mode = "off"
        sparse_precond_kind = "auto"
    else:
        sparse_precond_mode = "auto"
        sparse_precond_kind = "auto"
    sparse_allow_nondiff_env = os.environ.get("SFINCS_JAX_RHSMODE1_SPARSE_ALLOW_NONDIFF", "").strip().lower()
    sparse_allow_nondiff = sparse_allow_nondiff_env in {"1", "true", "yes", "on"}
    sparse_matvec_env = os.environ.get("SFINCS_JAX_RHSMODE1_SPARSE_MATVEC", "").strip().lower()
    if sparse_matvec_env in {"1", "true", "yes", "on"}:
        sparse_use_matvec = True
    elif sparse_matvec_env in {"0", "false", "no", "off"}:
        sparse_use_matvec = False
    else:
        sparse_use_matvec = False
    sparse_operator_env = os.environ.get("SFINCS_JAX_RHSMODE1_SPARSE_OPERATOR", "").strip().lower()
    if sparse_operator_env in {"1", "true", "yes", "on"}:
        sparse_operator_mode = "on"
    elif sparse_operator_env in {"0", "false", "no", "off"}:
        sparse_operator_mode = "off"
    else:
        sparse_operator_mode = "auto"
    sparse_max_env = os.environ.get("SFINCS_JAX_RHSMODE1_SPARSE_MAX", "").strip()
    # Assembling a sparse ILU preconditioner currently uses a dense (n^2) operator
    # assembly, so keep the default max modest. This cap is still large enough to
    # cover the reduced-suite FP DKES cases that otherwise trigger dense fallback.
    default_sparse_max = 6000
    if op.fblock.pas is not None and use_dkes:
        default_sparse_max = 60000
    try:
        sparse_max_size = int(sparse_max_env) if sparse_max_env else default_sparse_max
    except ValueError:
        sparse_max_size = default_sparse_max
    pas_sparse_min_env = os.environ.get("SFINCS_JAX_RHSMODE1_PAS_SPARSE_ILU_MIN", "").strip()
    try:
        pas_sparse_min = int(pas_sparse_min_env) if pas_sparse_min_env else 2000
    except ValueError:
        pas_sparse_min = 2000
    if op.fblock.pas is not None and int(active_size) < max(0, int(pas_sparse_min)):
        sparse_precond_mode = "off"
    sparse_drop_tol_env = os.environ.get("SFINCS_JAX_RHSMODE1_SPARSE_DROP_TOL", "").strip()
    sparse_drop_rel_env = os.environ.get("SFINCS_JAX_RHSMODE1_SPARSE_DROP_REL", "").strip()
    sparse_ilu_drop_env = os.environ.get("SFINCS_JAX_RHSMODE1_SPARSE_ILU_DROP_TOL", "").strip()
    sparse_ilu_fill_env = os.environ.get("SFINCS_JAX_RHSMODE1_SPARSE_ILU_FILL_FACTOR", "").strip()
    sparse_ilu_dense_env = os.environ.get("SFINCS_JAX_RHSMODE1_SPARSE_ILU_DENSE_MAX", "").strip()
    sparse_dense_cache_env = os.environ.get("SFINCS_JAX_RHSMODE1_SPARSE_DENSE_CACHE_MAX", "").strip()
    try:
        sparse_drop_tol = float(sparse_drop_tol_env) if sparse_drop_tol_env else 0.0
    except ValueError:
        sparse_drop_tol = 0.0
    try:
        sparse_drop_rel = float(sparse_drop_rel_env) if sparse_drop_rel_env else 1.0e-8
    except ValueError:
        sparse_drop_rel = 1.0e-8
    try:
        sparse_ilu_drop_tol = float(sparse_ilu_drop_env) if sparse_ilu_drop_env else 1.0e-4
    except ValueError:
        sparse_ilu_drop_tol = 1.0e-4
    try:
        sparse_ilu_fill = float(sparse_ilu_fill_env) if sparse_ilu_fill_env else 10.0
    except ValueError:
        sparse_ilu_fill = 10.0
    default_sparse_ilu_dense_max = 3000 if jax.default_backend() != "cpu" else 2500
    try:
        sparse_ilu_dense_max = int(sparse_ilu_dense_env) if sparse_ilu_dense_env else default_sparse_ilu_dense_max
    except ValueError:
        sparse_ilu_dense_max = default_sparse_ilu_dense_max
    try:
        sparse_dense_cache_max = int(sparse_dense_cache_env) if sparse_dense_cache_env else 3000
    except ValueError:
        sparse_dense_cache_max = 3000
    sparse_jax_max_env = os.environ.get("SFINCS_JAX_RHSMODE1_SPARSE_JAX_MAX_MB", "").strip()
    try:
        sparse_jax_max_mb = float(sparse_jax_max_env) if sparse_jax_max_env else 128.0
    except ValueError:
        sparse_jax_max_mb = 128.0
    sparse_jax_sweeps_env = os.environ.get("SFINCS_JAX_RHSMODE1_SPARSE_JAX_SWEEPS", "").strip()
    try:
        sparse_jax_sweeps = int(sparse_jax_sweeps_env) if sparse_jax_sweeps_env else 2
    except ValueError:
        sparse_jax_sweeps = 2
    sparse_jax_sweeps = max(1, sparse_jax_sweeps)
    sparse_jax_omega_env = os.environ.get("SFINCS_JAX_RHSMODE1_SPARSE_JAX_OMEGA", "").strip()
    try:
        sparse_jax_omega = float(sparse_jax_omega_env) if sparse_jax_omega_env else 0.8
    except ValueError:
        sparse_jax_omega = 0.8
    sparse_jax_reg_env = os.environ.get("SFINCS_JAX_RHSMODE1_SPARSE_JAX_REG", "").strip()
    try:
        sparse_jax_reg = float(sparse_jax_reg_env) if sparse_jax_reg_env else 1e-10
    except ValueError:
        sparse_jax_reg = 1e-10
    sparse_exact_lu = _rhsmode1_sparse_exact_lu_requested(
        op=op,
        solve_method_kind=solve_method_kind,
        active_size=int(active_size),
        sparse_max_size=int(sparse_max_size),
        full_precond_requested=bool(full_precond_requested),
        preconditioner_x=int(preconditioner_x),
        use_dkes=bool(use_dkes),
    )
    sparse_exact_direct = _rhsmode1_host_sparse_direct_allowed(
        sparse_exact_lu=sparse_exact_lu,
        use_implicit=bool(use_implicit),
    )
    sparse_prefer_over_dense_shortcut = _rhsmode1_prefer_sparse_over_dense_shortcut(
        op=op,
        active_size=int(active_size),
        sparse_max_size=int(sparse_max_size),
        use_implicit=bool(use_implicit),
    )
    sparse_prefer_skips_stage2 = _rhsmode1_sparse_prefer_skips_stage2(
        sparse_prefer_over_dense_shortcut=bool(sparse_prefer_over_dense_shortcut),
        sparse_precond_mode=sparse_precond_mode,
    )
    gpu_dkes_sparse_shortcut = bool(
        rhs1_precond_env_user in {"", "auto"}
        and rhs1_bicgstab_env_user in {"", "auto"}
        and solve_method_kind not in {"dense", "dense_ksp"}
        and jax.default_backend() != "cpu"
        and int(op.rhs_mode) == 1
        and (not bool(op.include_phi1))
        and op.fblock.fp is not None
        and op.fblock.pas is None
        and use_dkes
        and sparse_precond_mode != "off"
        and int(active_size) <= int(sparse_max_size)
    )
    cs0_sparse_first = _rhsmode1_constraint0_sparse_first(
        op=op,
        solve_method_kind=solve_method_kind,
        sparse_precond_mode=sparse_precond_mode,
        active_size=int(active_size),
        sparse_max_size=int(sparse_max_size),
    )
    cs0_petsc_compat = _rhsmode1_constraint0_petsc_compat(
        op=op,
        solve_method_kind=solve_method_kind,
        sparse_precond_mode=sparse_precond_mode,
        active_size=int(active_size),
        sparse_max_size=int(sparse_max_size),
    )
    cs0_dense_fallback_allowed = _rhsmode1_constraint0_dense_fallback_allowed(op)
    if cs0_petsc_compat:
        rhs1_precond_kind = None
        rhs1_precond_enabled = False
        rhs1_bicgstab_kind = None
        if emit is not None:
            emit(
                1,
                "solve_v3_full_system_linear_gmres: constraintScheme=0 PETSc-compat auto mode "
                "-> dedicated sparse ILU path",
            )
    if gpu_dkes_sparse_shortcut:
        rhs1_precond_kind = None
        rhs1_precond_enabled = False
        rhs1_bicgstab_kind = None
        if emit is not None:
            emit(
                1,
                "solve_v3_full_system_linear_gmres: GPU DKES auto mode -> sparse ILU shortcut "
                f"(size={int(active_size)})",
            )

    def _solver_kind(method: str) -> tuple[str, str]:
        method_l = str(method).strip().lower()
        if method_l in {"auto", "default"}:
            # On distributed/sharded single-RHS solves, prefer short-recurrence
            # Krylov by default to reduce synchronization pressure.
            if distributed_axis is not None and int(op.rhs_mode) == 1 and distributed_auto_solver == "bicgstab":
                return "bicgstab", "batched"
            # Transport matrices involve constrained/near-singular systems; GMRES is
            # generally more reliable for parity, while BiCGStab remains available.
            if int(op.rhs_mode) in {2, 3}:
                return "gmres", "incremental"
            small_gmres_env = os.environ.get("SFINCS_JAX_RHSMODE1_GMRES_SMALL_MAX", "").strip()
            try:
                small_gmres_max = int(small_gmres_env) if small_gmres_env else 600
            except ValueError:
                small_gmres_max = 600
            if small_gmres_max > 0 and int(op.total_size) <= small_gmres_max:
                return "gmres", "incremental"
            # Default RHSMode=1 to GMRES to match PETSc/KSP parity.
            return "gmres", "incremental"
        if method_l in {"bicgstab", "bicgstab_jax"}:
            return "bicgstab", "batched"
        return "gmres", method_l

    stage2_env = os.environ.get("SFINCS_JAX_LINEAR_STAGE2", "").strip().lower()
    if stage2_env in {"0", "false", "no", "off"}:
        stage2_enabled = False
    elif stage2_env in {"1", "true", "yes", "on"}:
        stage2_enabled = True
    else:
        solver_kind_default = _solver_kind(solve_method)[0]
        stage2_enabled = (
            int(op.rhs_mode) == 1
            and (not bool(op.include_phi1))
            and solver_kind_default in {"gmres", "bicgstab"}
        )
    if pas_large_bicgstab_fastpath and stage2_env == "":
        stage2_enabled = False
    # Stage-2 is a "stronger" fallback solve for difficult cases. The default time cap
    # must be large enough to still trigger after any one-time preconditioner setup,
    # while remaining bounded for interactive use and CI.
    stage2_time_cap_s = float(os.environ.get("SFINCS_JAX_LINEAR_STAGE2_MAX_ELAPSED_S", "30.0"))
    if tokamak_pas and stage2_time_cap_s < 120.0:
        stage2_time_cap_s = 120.0
    if op.fblock.fp is not None and use_dkes and stage2_time_cap_s < 120.0:
        stage2_time_cap_s = 120.0
    if op.fblock.fp is not None and int(op.total_size) >= 300000 and stage2_time_cap_s < 1200.0:
        # Large FP systems can spend most of this budget in preconditioner setup;
        # keep stage2 available by default so validation does not depend on external
        # reference files and so difficult high-resolution cases can still polish.
        stage2_time_cap_s = 1200.0
    if op.fblock.fp is not None and int(op.total_size) >= 600000 and stage2_time_cap_s < 2400.0:
        stage2_time_cap_s = 2400.0

    def _solve_linear(
        *,
        matvec_fn,
        b_vec: jnp.ndarray,
        precond_fn,
        x0_vec: jnp.ndarray | None,
        tol_val: float,
        atol_val: float,
        restart_val: int,
        maxiter_val: int | None,
        solve_method_val: str,
        precond_side: str,
    ):
        if use_implicit:
            solver_kind, gmres_method = _solver_kind(solve_method_val)
            return linear_custom_solve(
                matvec=matvec_fn,
                b=b_vec,
                preconditioner=precond_fn,
                x0=x0_vec,
                tol=tol_val,
                atol=atol_val,
                restart=restart_val,
                maxiter=maxiter_val,
                solve_method=gmres_method,
                solver=solver_kind,
                precondition_side=precond_side,
                # Use the *actual* system size (active/reduced sizing) for solver-JIT heuristics.
                size_hint=int(b_vec.shape[0]),
            )
        solver_kind, gmres_method = _solver_kind(solve_method_val)
        solver_jit_active = _use_solver_jit()
        solve_method_dispatch = "bicgstab" if solver_kind == "bicgstab" else _rhs_krylov_method_for_context(
            gmres_method=gmres_method,
            use_implicit=use_implicit,
            distributed_axis=distributed_axis,
            solver_jit=solver_jit_active,
        )
        return _gmres_solve_dispatch(
            matvec=matvec_fn,
            b=b_vec,
            preconditioner=precond_fn,
            x0=x0_vec,
            tol=tol_val,
            atol=atol_val,
            restart=restart_val,
            maxiter=maxiter_val,
            solve_method=solve_method_dispatch,
            distributed_axis=distributed_axis,
            precondition_side=precond_side,
        )

    def _solve_linear_with_residual(
        *,
        matvec_fn,
        b_vec: jnp.ndarray,
        precond_fn,
        x0_vec: jnp.ndarray | None,
        tol_val: float,
        atol_val: float,
        restart_val: int,
        maxiter_val: int | None,
        solve_method_val: str,
        precond_side: str,
    ) -> tuple[GMRESSolveResult, jnp.ndarray]:
        solver_kind, gmres_method = _solver_kind(solve_method_val)
        if use_implicit:
            return linear_custom_solve_with_residual(
                matvec=matvec_fn,
                b=b_vec,
                preconditioner=precond_fn,
                x0=x0_vec,
                tol=tol_val,
                atol=atol_val,
                restart=restart_val,
                maxiter=maxiter_val,
                solve_method=gmres_method,
                solver=solver_kind,
                precondition_side=precond_side,
                size_hint=int(b_vec.shape[0]),
            )
        if solver_kind == "bicgstab":
            if distributed_axis is not None:
                with sharding_constraints(True):
                    return gmres_solve_with_residual_distributed(
                        matvec=matvec_fn,
                        b=b_vec,
                        preconditioner=precond_fn,
                        x0=x0_vec,
                        tol=tol_val,
                        atol=atol_val,
                        restart=restart_val,
                        maxiter=maxiter_val,
                        solve_method="bicgstab",
                        precondition_side=precond_side,
                        axis_name=distributed_axis,
                    )
            solver_fn = bicgstab_solve_with_residual_jit if _use_solver_jit() else bicgstab_solve_with_residual
            return solver_fn(
                matvec=matvec_fn,
                b=b_vec,
                preconditioner=precond_fn,
                x0=x0_vec,
                tol=tol_val,
                atol=atol_val,
                maxiter=maxiter_val,
                precondition_side=precond_side,
            )
        solver_jit_active = _use_solver_jit()
        gmres_method_dispatch = _rhs_krylov_method_for_context(
            gmres_method=gmres_method,
            use_implicit=use_implicit,
            distributed_axis=distributed_axis,
            solver_jit=solver_jit_active,
        )
        if distributed_axis is not None:
            with sharding_constraints(True):
                return gmres_solve_with_residual_distributed(
                    matvec=matvec_fn,
                    b=b_vec,
                    preconditioner=precond_fn,
                    x0=x0_vec,
                    tol=tol_val,
                    atol=atol_val,
                    restart=restart_val,
                    maxiter=maxiter_val,
                    solve_method=gmres_method_dispatch,
                    precondition_side=precond_side,
                    axis_name=distributed_axis,
                )
        solver_fn = gmres_solve_with_residual_jit if solver_jit_active else gmres_solve_with_residual
        return solver_fn(
            matvec=matvec_fn,
            b=b_vec,
            preconditioner=precond_fn,
            x0=x0_vec,
            tol=tol_val,
            atol=atol_val,
            restart=restart_val,
            maxiter=maxiter_val,
            solve_method=gmres_method_dispatch,
            precondition_side=precond_side,
        )

    fortran_stdout_env = os.environ.get("SFINCS_JAX_FORTRAN_STDOUT", "").strip().lower()
    if fortran_stdout_env in {"0", "false", "no", "off"}:
        fortran_stdout = False
    elif fortran_stdout_env in {"1", "true", "yes", "on"}:
        fortran_stdout = True
    else:
        fortran_stdout = emit is not None
    ksp_history_max_env = os.environ.get("SFINCS_JAX_KSP_HISTORY_MAX_SIZE", "").strip().lower()
    if ksp_history_max_env in {"none", "inf", "infinite", "unlimited"}:
        ksp_history_max_size = None
    else:
        try:
            ksp_history_max_size = int(ksp_history_max_env) if ksp_history_max_env else 800
        except ValueError:
            ksp_history_max_size = 800
    ksp_history_max_iter_env = os.environ.get("SFINCS_JAX_KSP_HISTORY_MAX_ITER", "").strip()
    try:
        ksp_history_max_iter = int(ksp_history_max_iter_env) if ksp_history_max_iter_env else 2000
    except ValueError:
        ksp_history_max_iter = 2000
    iter_stats_env = os.environ.get("SFINCS_JAX_SOLVER_ITER_STATS", "").strip().lower()
    iter_stats_enabled = iter_stats_env in {"1", "true", "yes", "on"}
    iter_stats_max_env = os.environ.get("SFINCS_JAX_SOLVER_ITER_STATS_MAX_SIZE", "").strip()
    try:
        iter_stats_max_size = int(iter_stats_max_env) if iter_stats_max_env else None
    except ValueError:
        iter_stats_max_size = None

    ksp_matvec = None
    ksp_b = None
    ksp_precond = None
    ksp_x0 = None
    ksp_restart = restart
    ksp_maxiter = maxiter
    ksp_precond_side = gmres_precond_side
    ksp_solver_kind = "gmres"
    residual_vec: jnp.ndarray | None = None

    def _apply_rhs1_handoff(state) -> None:
        nonlocal ksp_matvec, ksp_b, ksp_precond, ksp_x0, ksp_restart, ksp_maxiter, ksp_precond_side, ksp_solver_kind
        if state is None:
            return
        ksp_matvec = state.matvec_fn
        ksp_b = state.b_vec
        ksp_precond = state.precond_fn
        ksp_x0 = state.x0_vec
        ksp_restart = state.restart
        ksp_maxiter = state.maxiter
        ksp_precond_side = state.precond_side
        ksp_solver_kind = state.solver_kind

    def _emit_ksp_history(
        *,
        matvec_fn,
        b_vec: jnp.ndarray,
        precond_fn,
        x0_vec: jnp.ndarray | None,
        tol_val: float,
        atol_val: float,
        restart_val: int,
        maxiter_val: int | None,
        precond_side: str,
        solver_kind: str,
        solve_method_val: str,
    ) -> list[float] | None:
        if emit is None or not fortran_stdout:
            return None
        solver_label = _ksp_iteration_solver_label(solver_kind=solver_kind, solve_method=solve_method_val)
        if solver_label not in {"gmres", "lgmres"}:
            return None
        size = int(b_vec.size)
        if ksp_history_max_size is not None and size > int(ksp_history_max_size):
            emit(1, f"fortran-stdout: KSP history skipped (size={size} > max={int(ksp_history_max_size)})")
            return None
        if maxiter_val is not None and ksp_history_max_iter is not None:
            est_iters = int(maxiter_val)
            if solver_label == "gmres":
                est_iters *= max(1, int(restart_val))
            if est_iters > int(ksp_history_max_iter):
                emit(
                    1,
                    "fortran-stdout: KSP history skipped "
                    f"(estimated_iters={est_iters} > max={int(ksp_history_max_iter)})",
                )
                return None
        try:
            if solver_label == "lgmres":
                _x_hist, _rn, history = lgmres_solve_with_history_scipy(
                    matvec=matvec_fn,
                    b=b_vec,
                    preconditioner=precond_fn,
                    x0=x0_vec,
                    tol=tol_val,
                    atol=atol_val,
                    restart=restart_val,
                    maxiter=maxiter_val,
                    precondition_side=precond_side,
                )
            else:
                _x_hist, _rn, history = gmres_solve_with_history_scipy(
                    matvec=matvec_fn,
                    b=b_vec,
                    preconditioner=precond_fn,
                    x0=x0_vec,
                    tol=tol_val,
                    atol=atol_val,
                    restart=restart_val,
                    maxiter=maxiter_val,
                    precondition_side=precond_side,
                )
        except Exception as exc:  # noqa: BLE001
            emit(1, f"fortran-stdout: KSP history unavailable ({type(exc).__name__}: {exc})")
            return None
        for k, rn in enumerate(history):
            emit(0, f"{k:4d} KSP Residual norm {rn: .12e} ")
        if history:
            emit(0, " Linear iteration (KSP) converged.  KSPConvergedReason =            2")
            emit(0, "   KSP_CONVERGED_RTOL: Norm decreased by rtol.")
        return history

    def _emit_ksp_iter_stats(
        *,
        matvec_fn,
        b_vec: jnp.ndarray,
        precond_fn,
        x0_vec: jnp.ndarray | None,
        tol_val: float,
        atol_val: float,
        restart_val: int,
        maxiter_val: int | None,
        precond_side: str,
        solver_kind: str,
        history: list[float] | None,
        solve_method_val: str,
    ) -> None:
        if emit is None or not iter_stats_enabled:
            return
        size = int(b_vec.size)
        if iter_stats_max_size is not None and size > int(iter_stats_max_size):
            emit(1, f"ksp_iterations skipped (size={size} > max={int(iter_stats_max_size)})")
            return
        solver_kind_l = str(solver_kind).strip().lower()
        solver_label = _ksp_iteration_solver_label(solver_kind=solver_kind_l, solve_method=solve_method_val)
        iter_stats_max_iter_env = os.environ.get("SFINCS_JAX_SOLVER_ITER_STATS_MAX_ITER", "").strip()
        try:
            iter_stats_max_iter = int(iter_stats_max_iter_env) if iter_stats_max_iter_env else 2000
        except ValueError:
            iter_stats_max_iter = 2000
        if maxiter_val is not None and iter_stats_max_iter is not None:
            est_iters = int(maxiter_val)
            if solver_label == "gmres":
                est_iters *= max(1, int(restart_val))
            if est_iters > int(iter_stats_max_iter):
                emit(
                    1,
                    "ksp_iterations skipped "
                    f"(estimated_iters={est_iters} > max={int(iter_stats_max_iter)})",
                )
                return
        try:
            if solver_label == "gmres":
                if history is None:
                    _x_hist, _rn, history = gmres_solve_with_history_scipy(
                        matvec=matvec_fn,
                        b=b_vec,
                        preconditioner=precond_fn,
                        x0=x0_vec,
                        tol=tol_val,
                        atol=atol_val,
                        restart=restart_val,
                        maxiter=maxiter_val,
                        precondition_side=precond_side,
                    )
                iters = len(history or [])
            elif solver_label == "lgmres":
                if history is None:
                    _x_hist, _rn, history = lgmres_solve_with_history_scipy(
                        matvec=matvec_fn,
                        b=b_vec,
                        preconditioner=precond_fn,
                        x0=x0_vec,
                        tol=tol_val,
                        atol=atol_val,
                        restart=restart_val,
                        maxiter=maxiter_val,
                        precondition_side=precond_side,
                    )
                iters = len(history or [])
            elif solver_kind_l == "bicgstab":
                _x_hist, _rn, history = bicgstab_solve_with_history_scipy(
                    matvec=matvec_fn,
                    b=b_vec,
                    preconditioner=precond_fn,
                    x0=x0_vec,
                    tol=tol_val,
                    atol=atol_val,
                    maxiter=maxiter_val,
                    precondition_side=precond_side,
                )
                iters = len(history or [])
            else:
                return
        except Exception as exc:  # noqa: BLE001
            emit(1, f"ksp_iterations unavailable ({type(exc).__name__}: {exc})")
            return
        emit(0, f"ksp_iterations={iters} solver={solver_label}")
    if use_active_dof_mode:
        assert active_idx_jnp is not None
        assert full_to_active_jnp is not None

        def reduce_full(v_full: jnp.ndarray) -> jnp.ndarray:
            return v_full[active_idx_jnp]

        if use_pas_projection:
            fs_factor = _fs_average_factor(op.theta_weights, op.zeta_weights, op.d_hat)
            fs_sum = jnp.sum(fs_factor)
            fs_sum_safe = jnp.where(fs_sum != 0, fs_sum, jnp.asarray(1.0, dtype=jnp.float64))
            ix0 = _ix_min(bool(op.point_at_x0))
            mask_x = (jnp.arange(int(op.n_x)) >= ix0).astype(jnp.float64)

            def _project_pas_f(f_flat: jnp.ndarray) -> jnp.ndarray:
                f = f_flat.reshape(op.fblock.f_shape)
                avg = jnp.einsum("tz,sxtz->sx", fs_factor, f[:, :, 0, :, :])
                avg = avg * mask_x[None, :]
                avg = avg / fs_sum_safe
                f = f.at[:, :, 0, :, :].add(-avg[:, :, None, None])
                return f.reshape((-1,))

            def _expand_active_f(v_reduced: jnp.ndarray) -> jnp.ndarray:
                z0 = jnp.zeros((1,), dtype=v_reduced.dtype)
                padded = jnp.concatenate([z0, v_reduced], axis=0)
                return padded[full_to_active_jnp]

            def _project_reduced(v_reduced: jnp.ndarray) -> jnp.ndarray:
                f_full = _expand_active_f(v_reduced)
                f_proj = _project_pas_f(f_full)
                return reduce_full(f_proj)

            def _wrap_pas_precond(precond_fn: Callable[[jnp.ndarray], jnp.ndarray]) -> Callable[[jnp.ndarray], jnp.ndarray]:
                def _apply(v_reduced: jnp.ndarray) -> jnp.ndarray:
                    z_reduced = precond_fn(v_reduced)
                    return _project_reduced(z_reduced)
                return _apply

            def expand_reduced(v_reduced: jnp.ndarray) -> jnp.ndarray:
                f_full = _expand_active_f(v_reduced)
                if int(op.extra_size) > 0:
                    zeros_e = jnp.zeros((int(op.extra_size),), dtype=v_reduced.dtype)
                    return jnp.concatenate([f_full, zeros_e], axis=0)
                return f_full

            zeros_extra = jnp.zeros((int(op.extra_size),), dtype=jnp.float64)

            def mv_reduced(x_reduced: jnp.ndarray) -> jnp.ndarray:
                f_full = _expand_active_f(x_reduced)
                f_proj = _project_pas_f(f_full)
                x_full = jnp.concatenate([f_proj, zeros_extra], axis=0) if int(op.extra_size) > 0 else f_proj
                y_full = mv(x_full)
                y_f = y_full[: op.f_size]
                y_proj = _project_pas_f(y_f)
                return reduce_full(y_proj)

            rhs_f = rhs[: op.f_size]
            rhs_proj = _project_pas_f(rhs_f)
            rhs_reduced = reduce_full(rhs_proj)
            x0_reduced = None
            if x0 is not None:
                x0_arr = jnp.asarray(x0)
                if x0_arr.shape == (active_size,):
                    x0_reduced = _project_reduced(x0_arr)
                elif x0_arr.shape == (op.total_size,):
                    f0_proj = _project_pas_f(x0_arr[: op.f_size])
                    x0_reduced = reduce_full(f0_proj)
                elif x0_arr.shape == (op.f_size,):
                    f0_proj = _project_pas_f(x0_arr)
                    x0_reduced = reduce_full(f0_proj)
            if recycle_basis_use:
                basis_reduced: list[jnp.ndarray] = []
                for vec in recycle_basis_use:
                    if vec.shape != (op.total_size,):
                        continue
                    f_proj = _project_pas_f(vec[: op.f_size])
                    basis_reduced.append(reduce_full(f_proj))
                if basis_reduced:
                    basis_au = [mv_reduced(b) for b in basis_reduced]
                    x0_recycled = _recycled_initial_guess(rhs_reduced, basis_reduced, basis_au)
                    if x0_recycled is not None:
                        if x0_reduced is None:
                            x0_reduced = x0_recycled
                        else:
                            r0 = jnp.linalg.norm(mv_reduced(x0_reduced) - rhs_reduced)
                            r1 = jnp.linalg.norm(mv_reduced(x0_recycled) - rhs_reduced)
                            if jnp.isfinite(r1) and (not jnp.isfinite(r0) or float(r1) < float(r0)):
                                x0_reduced = x0_recycled
        else:
            def expand_reduced(v_reduced: jnp.ndarray) -> jnp.ndarray:
                z0 = jnp.zeros((1,), dtype=v_reduced.dtype)
                padded = jnp.concatenate([z0, v_reduced], axis=0)
                return padded[full_to_active_jnp]

            def mv_reduced(x_reduced: jnp.ndarray) -> jnp.ndarray:
                return reduce_full(mv(expand_reduced(x_reduced)))

            rhs_reduced = reduce_full(rhs)
            x0_reduced = None
            if x0 is not None:
                x0_arr = jnp.asarray(x0)
                if x0_arr.shape == (active_size,):
                    x0_reduced = x0_arr
                elif x0_arr.shape == (op.total_size,):
                    x0_reduced = reduce_full(x0_arr)
                elif use_pas_projection and x0_arr.shape == (op.f_size,):
                    x0_reduced = x0_arr[active_idx_jnp]
            if recycle_basis_use:
                basis_reduced = []
                for vec in recycle_basis_use:
                    if vec.shape != (op.total_size,):
                        continue
                    basis_reduced.append(reduce_full(vec))
                if basis_reduced:
                    basis_au = [mv_reduced(b) for b in basis_reduced]
                    x0_recycled = _recycled_initial_guess(rhs_reduced, basis_reduced, basis_au)
                    if x0_recycled is not None:
                        if x0_reduced is None:
                            x0_reduced = x0_recycled
                        else:
                            r0 = jnp.linalg.norm(mv_reduced(x0_reduced) - rhs_reduced)
                            r1 = jnp.linalg.norm(mv_reduced(x0_recycled) - rhs_reduced)
                            if jnp.isfinite(r1) and (not jnp.isfinite(r0) or float(r1) < float(r0)):
                                x0_reduced = x0_recycled
        target_reduced = max(float(atol), float(tol) * float(jnp.linalg.norm(rhs_reduced)))
        target_stage2 = float(target_reduced)
        if op.fblock.fp is not None and op.fblock.pas is None and (not bool(op.include_phi1)):
            # FP RHS can have large norms; enforce a stricter absolute target for
            # stage2/strong-preconditioner decisions to avoid premature convergence
            # with loose relative norms.
            target_stage2 = min(float(target_stage2), max(float(atol), float(tol)))
        dense_shortcut_ratio_env = os.environ.get("SFINCS_JAX_RHSMODE1_DENSE_SHORTCUT_RATIO", "").strip()
        try:
            dense_shortcut_ratio = float(dense_shortcut_ratio_env) if dense_shortcut_ratio_env else 1.0e6
        except ValueError:
            dense_shortcut_ratio = 1.0e6
        disable_dense_pas = (
            op.fblock.pas is not None
            and (not bool(op.include_phi1))
            and int(op.constraint_scheme) != 0
        )
        pas_dense_allow_env = os.environ.get("SFINCS_JAX_RHSMODE1_PAS_DENSE_ALLOW_MAX", "").strip()
        try:
            pas_dense_allow_max = int(pas_dense_allow_env) if pas_dense_allow_env else 4000
        except ValueError:
            pas_dense_allow_max = 4000
        if disable_dense_pas and int(active_size) <= max(0, int(pas_dense_allow_max)):
            disable_dense_pas = False
        if disable_dense_pas or op.fblock.pas is not None:
            dense_shortcut_ratio = 0.0
        dense_fallback_max = _rhsmode1_dense_fallback_max(op)
        if disable_dense_pas:
            dense_fallback_max = 0
        dense_backend_allowed = _rhsmode1_dense_backend_allowed()
        host_dense_fallback_allowed = _rhsmode1_host_dense_fallback_allowed()
        dense_krylov_allowed = _rhsmode1_dense_krylov_allowed()
        if not dense_backend_allowed:
            dense_shortcut_ratio = 0.0
            if not host_dense_fallback_allowed and not dense_krylov_allowed:
                dense_fallback_max = 0
            if emit is not None:
                dense_note = "dense shortcut/fallback"
                if host_dense_fallback_allowed:
                    dense_note = "dense shortcut (host dense fallback kept)"
                elif dense_krylov_allowed:
                    dense_note = "dense shortcut disabled (dense Krylov fallback kept)"
                emit(
                    1,
                    f"solve_v3_full_system_linear_gmres: disabling RHSMode=1 {dense_note} "
                    f"on backend={jax.default_backend()}",
                )
        # FP dense-fallback probe shortcut: for medium FP systems where the probe is
        # likely to trigger a direct solve, avoid building heavy block preconditioners
        # that can allocate O(GB) of scratch. Use the cheap collision preconditioner
        # for the probe instead.
        fp_probe_env = os.environ.get("SFINCS_JAX_RHSMODE1_FP_PRECOND_PROBE", "").strip().lower()
        fp_probe_enabled = fp_probe_env not in {"0", "false", "no", "off"}
        if op.fblock.fp is not None and (not use_dkes):
            fp_probe_enabled = False
        fp_probe_min_env = os.environ.get("SFINCS_JAX_RHSMODE1_FP_PRECOND_PROBE_MIN", "").strip()
        try:
            fp_probe_min = int(fp_probe_min_env) if fp_probe_min_env else 2500
        except ValueError:
            fp_probe_min = 2500
        heavy_precond_kinds_fp = {
            "point",
            "theta_line",
            "theta_schwarz",
            "zeta_line",
            "zeta_schwarz",
            "theta_zeta",
            "adi",
            "xblock_tz",
            "sxblock_tz",
            "species_block",
            "schur",
            "pas_hybrid",
        }
        if (
            fp_probe_enabled
            and (not rhs1_precond_env)
            and op.fblock.fp is not None
            and (not bool(op.include_phi1))
            and dense_fallback_max > 0
            and int(active_size) >= int(fp_probe_min)
            and int(active_size) <= int(dense_fallback_max)
            and rhs1_precond_enabled
            and solve_method_kind not in {"dense", "dense_ksp"}
            and rhs1_precond_kind in heavy_precond_kinds_fp
        ):
            rhs1_precond_kind = "collision"
        early_dense_shortcut = False
        probe_shortcut = False
        probe_x0: jnp.ndarray | None = None
        preconditioner_reduced = None
        strong_preconditioner_reduced = None
        bicgstab_preconditioner_reduced = None
        pas_precond_force_collision = False
        rhs1_pas_tz_guarded_fallback = False
        rhs1_pas_tz_guarded_axis: str | None = None
        dense_matrix_cache: np.ndarray | None = None
        host_dense_shortcut = _rhsmode1_host_dense_shortcut_allowed(
            op=op,
            active_size=int(active_size),
            use_implicit=bool(use_implicit),
            solve_method_kind=str(solve_method_kind),
        )

        def _solve_host_dense_reduced(*, x0_dense: jnp.ndarray | None = None) -> GMRESSolveResult:
            use_row_scaled = bool(
                int(op.constraint_scheme) == 0
                or (int(op.constraint_scheme) == 1 and op.fblock.fp is not None)
            )
            import scipy.linalg as sla  # noqa: PLC0415

            if dense_matrix_cache is not None:
                a_np = np.asarray(dense_matrix_cache, dtype=np.float64)
            else:
                a_dense_jnp = assemble_dense_matrix_from_matvec(
                    matvec=mv_reduced, n=int(active_size), dtype=rhs_reduced.dtype
                )
                a_np = np.asarray(a_dense_jnp, dtype=np.float64)
            a_np = np.array(a_np, dtype=np.float64, copy=True)
            if a_np.ndim != 2:
                a_np = np.squeeze(a_np)

            mv_dense = mv_reduced
            b_dense = jnp.asarray(rhs_reduced, dtype=jnp.float64)
            if use_row_scaled:
                diag_floor = 1e-12
                diag = np.diag(a_np).astype(np.float64, copy=False)
                diag_abs = np.abs(diag)
                diag_safe = np.where(diag_abs > diag_floor, diag, np.sign(diag) * diag_floor)
                diag_safe = np.where(diag_safe != 0.0, diag_safe, diag_floor)
                scale = (1.0 / diag_safe).astype(np.float64, copy=False)
                a_np = a_np * scale[:, None]
                scale_jnp = jnp.asarray(scale, dtype=jnp.float64)
                b_dense = b_dense * scale_jnp

                def mv_dense(x: jnp.ndarray) -> jnp.ndarray:
                    return scale_jnp * mv_reduced(x)

            if a_np.ndim != 2 or a_np.shape[0] != a_np.shape[1]:
                x_np = np.asarray(
                    np.linalg.lstsq(a_np, np.asarray(b_dense, dtype=np.float64), rcond=None)[0],
                    dtype=np.float64,
                )
                x_dense = jnp.asarray(x_np, dtype=jnp.float64)
            else:
                lu, piv = sla.lu_factor(a_np)
                x_np = np.asarray(sla.lu_solve((lu, piv), np.asarray(b_dense, dtype=np.float64)), dtype=np.float64)
                if x0_dense is not None and x0_dense.shape == rhs_reduced.shape:
                    x_np = x_np + 0.0 * np.asarray(x0_dense, dtype=np.float64)
                x_dense = jnp.asarray(x_np, dtype=jnp.float64)

            r_dense = rhs_reduced - mv_reduced(x_dense)
            return GMRESSolveResult(x=x_dense, residual_norm=jnp.linalg.norm(r_dense))
        if rhs1_bicgstab_kind is not None:
            if emit is not None:
                emit(1, f"solve_v3_full_system_linear_gmres: RHSMode=1 BiCGStab preconditioner={rhs1_bicgstab_kind}")
            if rhs1_bicgstab_kind == "collision":
                bicgstab_preconditioner_reduced = _build_rhsmode1_collision_preconditioner(
                    op=op, reduce_full=reduce_full, expand_reduced=expand_reduced
                )
            if use_pas_projection:
                bicgstab_preconditioner_reduced = _wrap_pas_precond(bicgstab_preconditioner_reduced)

        # PAS probe shortcut: avoid expensive block/line preconditioner builds when a
        # cheap collision-based preconditioner already provides a strong residual drop.
        pas_probe_env = os.environ.get("SFINCS_JAX_PAS_PRECOND_PROBE", "").strip().lower()
        pas_probe_enabled = pas_probe_env not in {"0", "false", "no", "off"}
        pas_probe_rel_env = os.environ.get("SFINCS_JAX_PAS_PRECOND_PROBE_REL_MAX", "").strip()
        try:
            pas_probe_rel_max = float(pas_probe_rel_env) if pas_probe_rel_env else 0.9
        except ValueError:
            pas_probe_rel_max = 0.9
        pas_build_max_env = os.environ.get("SFINCS_JAX_PAS_PRECOND_BUILD_MAX", "").strip()
        try:
            pas_build_max = int(pas_build_max_env) if pas_build_max_env else 20000
        except ValueError:
            pas_build_max = 20000
        heavy_precond_kinds = {
            "point",
            "theta_line",
            "zeta_line",
            "theta_zeta",
            "adi",
            "xblock_tz",
            "sxblock_tz",
            "species_block",
            "schur",
            "pas_hybrid",
        }
        if (
            rhs1_precond_env in {"", "auto", "default"}
            and int(op.rhs_mode) == 1
            and (not bool(op.include_phi1))
            and op.fblock.pas is not None
            and int(op.n_species) >= 2
            and (geom_scheme == 1 or int(op.n_zeta) <= 9)
        ):
            # Robust default for multi-species tokamak-like PAS runs:
            # prefer Schur over pure theta/zeta line preconditioners.
            rhs1_precond_kind = "schur"
        if (
            pas_probe_enabled
            and rhs1_precond_kind in heavy_precond_kinds
            and rhs1_precond_enabled
            and solve_method_kind not in {"dense", "dense_ksp"}
            and op.fblock.pas is not None
            and (not use_dkes)
        ):
            probe_key = _rhsmode1_precond_cache_key(op, "pas_probe_decision")
            use_collision_precond = _RHSMODE1_PAS_PRECOND_PROBE_CACHE.get(probe_key)
            if (
                use_collision_precond is None
                and int(op.total_size) >= int(pas_build_max)
                and not (int(op.constraint_scheme) == 2 and int(op.extra_size) > 0)
            ):
                use_collision_precond = True
                _RHSMODE1_PAS_PRECOND_PROBE_CACHE[probe_key] = True
                if emit is not None:
                    emit(
                        1,
                        "solve_v3_full_system_linear_gmres: PAS precond skip "
                        f"(size={int(op.total_size)} >= {int(pas_build_max)}) -> collision",
                    )
            if use_collision_precond is None:
                try:
                    probe_precond = _build_rhsmode1_collision_preconditioner(
                        op=op, reduce_full=reduce_full, expand_reduced=expand_reduced
                    )
                    if use_pas_projection:
                        probe_precond = _wrap_pas_precond(probe_precond)
                    probe_x = probe_precond(rhs_reduced)
                    probe_r = rhs_reduced - mv_reduced(probe_x)
                    rhs_norm = float(jnp.linalg.norm(rhs_reduced))
                    probe_rel = float(jnp.linalg.norm(probe_r)) / rhs_norm if rhs_norm > 0 else 0.0
                    use_collision_precond = probe_rel <= pas_probe_rel_max
                    _RHSMODE1_PAS_PRECOND_PROBE_CACHE[probe_key] = bool(use_collision_precond)
                    if emit is not None:
                        emit(
                            1,
                            "solve_v3_full_system_linear_gmres: PAS precond probe "
                            f"(rel={probe_rel:.3e}, max={pas_probe_rel_max:.3e}) -> "
                            f"{'collision' if use_collision_precond else 'full'}",
                        )
                except Exception as exc:  # noqa: BLE001
                    use_collision_precond = None
                    if emit is not None:
                        emit(1, f"solve_v3_full_system_linear_gmres: PAS precond probe failed ({type(exc).__name__}: {exc})")
            if use_collision_precond:
                preconditioner_reduced = _build_rhsmode1_collision_preconditioner(
                    op=op, reduce_full=reduce_full, expand_reduced=expand_reduced
                )
                if use_pas_projection:
                    preconditioner_reduced = _wrap_pas_precond(preconditioner_reduced)
                rhs1_precond_kind = "collision"
                pas_precond_force_collision = True
                if rhs1_bicgstab_kind == "rhs1":
                    bicgstab_preconditioner_reduced = preconditioner_reduced

        def _build_rhs1_preconditioner_reduced():
            nonlocal rhs1_pas_tz_guarded_axis, rhs1_pas_tz_guarded_fallback
            _mark("rhs1_precond_build_start")
            if emit is not None:
                emit(
                    1,
                    "solve_v3_full_system_linear_gmres: building RHSMode=1 preconditioner="
                    f"{rhs1_precond_kind} (active-DOF)",
                )
                rhs1_progress_notes.preconditioner_build(rhs1_precond_kind)
            sweeps_env = os.environ.get("SFINCS_JAX_RHSMODE1_ADI_SWEEPS", "").strip()
            try:
                sweeps = int(sweeps_env) if sweeps_env else 2
            except ValueError:
                sweeps = 2
            lmax_use = rhs1_xblock_tz_lmax or 0
            if rhs1_precond_kind == "xblock_tz_lmax" and lmax_use <= 0:
                lmax_env = os.environ.get("SFINCS_JAX_RHSMODE1_XBLOCK_TZ_LMAX", "").strip()
                try:
                    lmax_use = int(lmax_env) if lmax_env else 0
                except ValueError:
                    lmax_use = 0
            precond = _build_rhs1_preconditioner_from_kind(
                op=op,
                rhs1_precond_kind=rhs1_precond_kind,
                reduce_full=reduce_full,
                expand_reduced=expand_reduced,
                preconditioner_species=preconditioner_species,
                preconditioner_x=preconditioner_x,
                preconditioner_xi=preconditioner_xi,
                rhs1_xblock_tz_lmax=lmax_use,
                dd_block_theta=_parse_rhs1_dd_block("theta"),
                dd_overlap_theta=_parse_rhs1_dd_overlap("theta", default=1 if rhs1_precond_kind == "theta_schwarz" else 0),
                dd_block_zeta=_parse_rhs1_dd_block("zeta"),
                dd_overlap_zeta=_parse_rhs1_dd_overlap("zeta", default=1 if rhs1_precond_kind == "zeta_schwarz" else 0),
                adi_sweeps=max(1, sweeps),
                emit=emit,
            )
            rhs1_pas_tz_guarded_fallback = bool(getattr(precond, "_sfincs_jax_pas_tz_guarded_fallback", False))
            if rhs1_pas_tz_guarded_fallback:
                rhs1_pas_tz_guarded_axis = str(getattr(precond, "_sfincs_jax_pas_tz_guarded_axis", "unknown"))
            if rhs1_pas_tz_guarded_fallback and emit is not None:
                emit(
                    1,
                    "solve_v3_full_system_linear_gmres: PAS-TZ structured fallback "
                    f"guarded out (axis={rhs1_pas_tz_guarded_axis}); using cheap fallback",
                )
            precond = _wrap_pas_precond(precond) if use_pas_projection else precond
            if rhs1_pas_tz_guarded_fallback:
                poly_steps_env = os.environ.get("SFINCS_JAX_RHSMODE1_PAS_TZ_GUARDED_POLY_STEPS", "").strip()
                poly_damping_env = os.environ.get("SFINCS_JAX_RHSMODE1_PAS_TZ_GUARDED_POLY_DAMPING", "").strip()
                try:
                    poly_steps = int(poly_steps_env) if poly_steps_env else 0
                except ValueError:
                    poly_steps = 0
                try:
                    poly_damping = float(poly_damping_env) if poly_damping_env else 0.5
                except ValueError:
                    poly_damping = 0.5
                if poly_steps > 0:
                    precond = _compose_residual_correction_preconditioner(
                        base=precond,
                        coarse=precond,
                        matvec=mv_reduced,
                        damping=float(poly_damping),
                        steps=int(poly_steps),
                    )
                    if emit is not None:
                        emit(
                            1,
                            "solve_v3_full_system_linear_gmres: PAS-TZ guarded matrix-free "
                            f"polynomial correction steps={int(poly_steps)} damping={float(poly_damping):.3g}",
                        )
                structured_levels = _rhs1_pas_tz_guarded_structured_levels(
                    os.environ.get("SFINCS_JAX_RHSMODE1_PAS_TZ_GUARDED_STRUCTURED_LEVELS", "")
                )
                if structured_levels:
                    coarse_preconditioners: list[Callable[[jnp.ndarray], jnp.ndarray]] = []
                    for level in structured_levels:
                        if level == "xmg":
                            coarse = _build_rhsmode1_xmg_preconditioner(
                                op=op, reduce_full=reduce_full, expand_reduced=expand_reduced
                            )
                        elif level == "collision":
                            coarse = _build_rhsmode1_collision_preconditioner(
                                op=op, reduce_full=reduce_full, expand_reduced=expand_reduced
                            )
                        else:
                            continue
                        coarse_preconditioners.append(_wrap_pas_precond(coarse) if use_pas_projection else coarse)
                    structured_steps_env = os.environ.get(
                        "SFINCS_JAX_RHSMODE1_PAS_TZ_GUARDED_STRUCTURED_STEPS", ""
                    ).strip()
                    structured_damping_env = os.environ.get(
                        "SFINCS_JAX_RHSMODE1_PAS_TZ_GUARDED_STRUCTURED_DAMPING", ""
                    ).strip()
                    structured_mode = (
                        os.environ.get("SFINCS_JAX_RHSMODE1_PAS_TZ_GUARDED_STRUCTURED_MODE", "")
                        .strip()
                        .lower()
                        .replace("-", "_")
                    )
                    try:
                        structured_steps = int(structured_steps_env) if structured_steps_env else 1
                    except ValueError:
                        structured_steps = 1
                    try:
                        structured_damping = float(structured_damping_env) if structured_damping_env else 0.7
                    except ValueError:
                        structured_damping = 0.7
                    if coarse_preconditioners and structured_steps > 0:
                        if structured_mode in {"fixed", "damped", "residual"}:
                            precond = _compose_multilevel_residual_correction_preconditioner(
                                base=precond,
                                coarse_levels=tuple(coarse_preconditioners),
                                matvec=mv_reduced,
                                damping=float(structured_damping),
                                steps=int(structured_steps),
                            )
                            structured_mode_label = f"fixed damping={float(structured_damping):.3g}"
                        else:
                            alpha_clip_env = os.environ.get(
                                "SFINCS_JAX_RHSMODE1_PAS_TZ_GUARDED_STRUCTURED_ALPHA_CLIP", ""
                            ).strip()
                            min_improve_env = os.environ.get(
                                "SFINCS_JAX_RHSMODE1_PAS_TZ_GUARDED_STRUCTURED_MIN_IMPROVEMENT", ""
                            ).strip()
                            try:
                                alpha_clip = float(alpha_clip_env) if alpha_clip_env else 1.0
                            except ValueError:
                                alpha_clip = 1.0
                            try:
                                min_improve = float(min_improve_env) if min_improve_env else 0.0
                            except ValueError:
                                min_improve = 0.0
                            precond = _compose_multilevel_minres_correction_preconditioner(
                                base=precond,
                                coarse_levels=tuple(coarse_preconditioners),
                                matvec=mv_reduced,
                                alpha_clip=float(alpha_clip),
                                min_improvement=float(min_improve),
                                steps=int(structured_steps),
                            )
                            structured_mode_label = (
                                f"minres alpha_clip={float(alpha_clip):.3g} "
                                f"min_improvement={float(min_improve):.3g}"
                            )
                        if emit is not None:
                            emit(
                                1,
                                "solve_v3_full_system_linear_gmres: PAS-TZ guarded structured "
                                "residual correction levels="
                                f"{','.join(structured_levels)} steps={int(structured_steps)} "
                                f"mode={structured_mode_label}",
                            )
            _mark("rhs1_precond_build_done")
            return precond

        def _build_rhs1_preconditioner_reduced_with_fallback():
            nonlocal rhs1_precond_kind, pas_precond_force_collision, bicgstab_preconditioner_reduced
            try:
                return _build_rhs1_preconditioner_reduced()
            except Exception as exc:  # noqa: BLE001
                if (
                    jax.default_backend() != "cpu"
                    and op.fblock.pas is not None
                    and rhs1_precond_kind not in {"collision", "point"}
                    and _is_resource_exhausted_error(exc)
                ):
                    if emit is not None:
                        emit(
                            0,
                            "solve_v3_full_system_linear_gmres: accelerator PAS preconditioner "
                            f"OOM for kind={rhs1_precond_kind}; falling back to collision preconditioner",
                        )
                    rhs1_precond_kind = "collision"
                    pas_precond_force_collision = True
                    precond = _build_rhsmode1_collision_preconditioner(
                        op=op, reduce_full=reduce_full, expand_reduced=expand_reduced
                    )
                    if use_pas_projection:
                        precond = _wrap_pas_precond(precond)
                    if rhs1_bicgstab_kind == "rhs1":
                        bicgstab_preconditioner_reduced = precond
                    return precond
                raise

        if rhs1_precond_enabled and (not host_dense_shortcut):
            solver_kind = _solver_kind(solve_method)[0]
            build_rhs1 = (
                (solver_kind != "bicgstab" and solve_method_kind != "dense")
                or (rhs1_bicgstab_kind == "rhs1" and solve_method_kind != "dense")
            )
            if build_rhs1 and preconditioner_reduced is None:
                preconditioner_reduced = _build_rhs1_preconditioner_reduced_with_fallback()
                if rhs1_bicgstab_kind == "rhs1":
                    bicgstab_preconditioner_reduced = preconditioner_reduced
        if (not host_dense_shortcut) and preconditioner_reduced is None and bicgstab_preconditioner_reduced is not None:
            preconditioner_reduced = bicgstab_preconditioner_reduced
        if (not host_dense_shortcut) and preconditioner_reduced is not None and rhs1_precond_kind in {
            "pas_hybrid",
            "pas_lite",
            "pas_tz",
            "pas_schur",
            "pas_tokamak_theta",
            "pas_ilu",
        }:
            try:
                probe = preconditioner_reduced(rhs_reduced)
                probe_ok = bool(jnp.all(jnp.isfinite(probe)))
            except Exception as exc:  # noqa: BLE001
                probe_ok = False
                if emit is not None:
                    emit(
                        1,
                        "solve_v3_full_system_linear_gmres: PAS precond probe failed "
                        f"({type(exc).__name__}: {exc}), using collision preconditioner",
                    )
            if not probe_ok:
                preconditioner_reduced = _build_rhsmode1_collision_preconditioner(
                    op=op, reduce_full=reduce_full, expand_reduced=expand_reduced
                )
                if use_pas_projection:
                    preconditioner_reduced = _wrap_pas_precond(preconditioner_reduced)
                if rhs1_bicgstab_kind == "rhs1":
                    bicgstab_preconditioner_reduced = preconditioner_reduced
                if emit is not None:
                    emit(
                        1,
                        "solve_v3_full_system_linear_gmres: PAS precond non-finite -> collision",
                    )
        # FP-only large systems: optionally augment the base preconditioner with a
        # low-L block correction to improve flow/Mach convergence without dense fallback.
        if (
            not host_dense_shortcut
            and
            preconditioner_reduced is not None
            and int(op.rhs_mode) == 1
            and (not bool(op.include_phi1))
            and op.fblock.fp is not None
            and op.fblock.pas is None
        ):
            fp_l1_env = os.environ.get("SFINCS_JAX_RHSMODE1_FP_L1_HYBRID", "").strip().lower()
            fp_l1_enabled = fp_l1_env in {"1", "true", "yes", "on"}
            fp_l1_min_env = os.environ.get("SFINCS_JAX_RHSMODE1_FP_L1_HYBRID_MIN", "").strip()
            fp_l1_lmax_env = os.environ.get("SFINCS_JAX_RHSMODE1_FP_L1_HYBRID_LMAX", "").strip()
            fp_l1_block_env = os.environ.get("SFINCS_JAX_RHSMODE1_FP_L1_HYBRID_BLOCK_MAX", "").strip()
            try:
                fp_l1_min = int(fp_l1_min_env) if fp_l1_min_env else 80000
            except ValueError:
                fp_l1_min = 80000
            try:
                fp_l1_lmax = int(fp_l1_lmax_env) if fp_l1_lmax_env else 1
            except ValueError:
                fp_l1_lmax = 1
            try:
                fp_l1_block_max = int(fp_l1_block_env) if fp_l1_block_env else 1500
            except ValueError:
                fp_l1_block_max = 1500
            fp_l1_lmax = max(1, min(int(fp_l1_lmax), int(op.n_xi)))
            if fp_l1_enabled and int(active_size) >= max(1, int(fp_l1_min)):
                n_theta = int(op.n_theta)
                n_zeta = int(op.n_zeta)
                block_size = int(fp_l1_lmax * n_theta * n_zeta)
                if block_size > 0 and block_size <= int(fp_l1_block_max):
                    if emit is not None:
                        emit(
                            1,
                            "solve_v3_full_system_linear_gmres: FP L1 hybrid preconditioner "
                            f"(lmax={fp_l1_lmax} block={block_size})",
                        )
                    try:
                        l1_precond = _build_rhsmode1_xblock_tz_lmax_preconditioner(
                            op=op,
                            lmax=int(fp_l1_lmax),
                            reduce_full=reduce_full,
                            expand_reduced=expand_reduced,
                        )
                        base_precond = preconditioner_reduced

                        def _fp_l1_hybrid(v: jnp.ndarray) -> jnp.ndarray:
                            z0 = base_precond(v)
                            r1 = v - mv_reduced(z0)
                            z1 = l1_precond(r1)
                            return z0 + z1

                        preconditioner_reduced = _fp_l1_hybrid
                        if rhs1_bicgstab_kind == "rhs1":
                            bicgstab_preconditioner_reduced = preconditioner_reduced
                    except Exception as exc:  # noqa: BLE001
                        if emit is not None:
                            emit(
                                1,
                                "solve_v3_full_system_linear_gmres: FP L1 hybrid precond failed "
                                f"({type(exc).__name__}: {exc})",
                            )
        if host_dense_shortcut:
            _mark("rhs1_host_dense_shortcut_start")
            if emit is not None:
                emit(
                    0,
                    "solve_v3_full_system_linear_gmres: accelerator FP small system -> "
                    f"using host dense shortcut (size={int(active_size)})",
                )
            res_reduced = _solve_host_dense_reduced(x0_dense=x0_reduced)
            _mark("rhs1_host_dense_shortcut_done")
            early_dense_shortcut = True
            probe_shortcut = True
            ksp_matvec = mv_reduced
            ksp_b = rhs_reduced
            ksp_precond = None
            ksp_x0 = x0_reduced
            ksp_precond_side = "none"
            ksp_solver_kind = _solver_kind("incremental")[0]
        sparse_operator_use = False
        if sparse_operator_mode == "on":
            sparse_operator_use = True
        elif sparse_operator_mode == "auto":
            sparse_operator_use = sparse_use_matvec and (op.fblock.fp is not None)
        if sparse_operator_use:
            sparse_operator_use = int(op.rhs_mode) == 1 and (not bool(op.include_phi1))
        if sparse_operator_use:
            if use_implicit and not sparse_allow_nondiff:
                sparse_operator_use = False
                if emit is not None:
                    emit(1, "sparse_operator: disabled for implicit solves (set SFINCS_JAX_RHSMODE1_SPARSE_ALLOW_NONDIFF=1 to override)")
            elif int(active_size) > sparse_max_size:
                sparse_operator_use = False
                if emit is not None:
                    emit(1, f"sparse_operator: disabled (size={int(active_size)} > max={int(sparse_max_size)})")
        if sparse_operator_use:
            try:
                cache_key = _rhsmode1_sparse_cache_key(
                    op,
                    kind="sparse_operator",
                    active_size=int(active_size),
                    use_active_dof_mode=True,
                    use_pas_projection=use_pas_projection,
                    drop_tol=sparse_drop_tol,
                    drop_rel=sparse_drop_rel,
                    ilu_drop_tol=sparse_ilu_drop_tol,
                    fill_factor=sparse_ilu_fill,
                )
                a_csr_full, _a_csr_drop, _ilu, _a_dense, _l_dense, _u_dense, _l_unit = _build_sparse_ilu_from_matvec(
                    matvec=mv_reduced,
                    n=int(active_size),
                    dtype=rhs_reduced.dtype,
                    cache_key=cache_key,
                    drop_tol=sparse_drop_tol,
                    drop_rel=sparse_drop_rel,
                    ilu_drop_tol=sparse_ilu_drop_tol,
                    fill_factor=sparse_ilu_fill,
                    build_dense_factors=False,
                    build_jax_factors=False,
                    build_ilu=False,
                    store_dense=False,
                    emit=emit,
                )

                def _mv_sparse(v: jnp.ndarray) -> jnp.ndarray:
                    x_np = np.asarray(v, dtype=np.float64).reshape((-1,))
                    y_np = a_csr_full @ x_np
                    return jnp.asarray(y_np, dtype=jnp.float64)

                mv_reduced = _mv_sparse
                if emit is not None:
                    emit(0, "solve_v3_full_system_linear_gmres: using sparse operator matvec")
            except Exception as exc:  # noqa: BLE001
                if emit is not None:
                    emit(1, f"sparse_operator: failed ({type(exc).__name__}: {exc})")
        if cs0_petsc_compat and solve_method_kind not in {"dense", "dense_ksp"}:
            try:
                import scipy.sparse as sp  # noqa: PLC0415
                from scipy.sparse.csgraph import reverse_cuthill_mckee  # noqa: PLC0415
                from scipy.sparse.linalg import spilu  # noqa: PLC0415

                compat_drop_env = os.environ.get("SFINCS_JAX_RHSMODE1_CS0_PETSC_COMPAT_DROP_TOL", "").strip()
                compat_fill_env = os.environ.get("SFINCS_JAX_RHSMODE1_CS0_PETSC_COMPAT_FILL", "").strip()
                compat_pivot_env = os.environ.get("SFINCS_JAX_RHSMODE1_CS0_PETSC_COMPAT_DIAG_PIVOT", "").strip()
                compat_restart_env = os.environ.get("SFINCS_JAX_RHSMODE1_CS0_PETSC_COMPAT_RESTART", "").strip()
                compat_maxiter_env = os.environ.get("SFINCS_JAX_RHSMODE1_CS0_PETSC_COMPAT_MAXITER", "").strip()
                try:
                    compat_drop_tol = float(compat_drop_env) if compat_drop_env else 1.0e-4
                except ValueError:
                    compat_drop_tol = 1.0e-4
                try:
                    compat_fill = float(compat_fill_env) if compat_fill_env else 10.0
                except ValueError:
                    compat_fill = 10.0
                try:
                    compat_diag_pivot = float(compat_pivot_env) if compat_pivot_env else 0.0
                except ValueError:
                    compat_diag_pivot = 0.0
                try:
                    compat_restart = int(compat_restart_env) if compat_restart_env else max(int(restart), 2000)
                except ValueError:
                    compat_restart = max(int(restart), 2000)
                try:
                    compat_maxiter = int(compat_maxiter_env) if compat_maxiter_env else max(int(maxiter or 1), 1)
                except ValueError:
                    compat_maxiter = max(int(maxiter or 1), 1)

                if emit is not None:
                    emit(
                        0,
                        "solve_v3_full_system_linear_gmres: constraintScheme=0 PETSc-compat sparse ILU solve "
                        f"(size={int(active_size)} drop_tol={compat_drop_tol:.1e} fill={compat_fill:.1f})",
                    )

                a_dense_cs0 = assemble_dense_matrix_from_matvec(
                    matvec=mv_reduced,
                    n=int(active_size),
                    dtype=rhs_reduced.dtype,
                )
                a_np_cs0 = np.asarray(a_dense_cs0, dtype=np.float64)
                max_abs_cs0 = float(np.max(np.abs(a_np_cs0))) if a_np_cs0.size else 0.0
                compat_drop_thresh = max(float(sparse_drop_tol), float(sparse_drop_rel) * max_abs_cs0)
                if compat_drop_thresh > 0.0:
                    a_np_cs0 = a_np_cs0.copy()
                    a_np_cs0[np.abs(a_np_cs0) < compat_drop_thresh] = 0.0
                a_csr_cs0 = sp.csr_matrix(a_np_cs0)
                a_csr_cs0.eliminate_zeros()
                compat_reg_env = os.environ.get("SFINCS_JAX_RHSMODE1_CS0_PETSC_COMPAT_REG", "").strip()
                max_abs_cs0 = float(np.max(np.abs(a_csr_cs0.data))) if int(a_csr_cs0.nnz) > 0 else 0.0
                try:
                    compat_reg = float(compat_reg_env) if compat_reg_env else (1.0e-12 * max_abs_cs0)
                except ValueError:
                    compat_reg = 1.0e-12 * max_abs_cs0
                compat_reg = max(0.0, float(compat_reg))
                perm = np.asarray(
                    reverse_cuthill_mckee(a_csr_cs0, symmetric_mode=False),
                    dtype=np.int32,
                )
                inv_perm = np.argsort(perm).astype(np.int32, copy=False)
                a_perm = a_csr_cs0[perm][:, perm].tocsc()
                if compat_reg != 0.0:
                    diag_idx = np.arange(int(active_size), dtype=np.int32)
                    a_perm = a_perm.copy()
                    a_perm[diag_idx, diag_idx] = a_perm[diag_idx, diag_idx] + compat_reg
                ilu_cs0 = spilu(
                    a_perm,
                    drop_tol=float(compat_drop_tol),
                    fill_factor=float(compat_fill),
                    permc_spec="NATURAL",
                    diag_pivot_thresh=float(compat_diag_pivot),
                )
                rhs_perm = jnp.asarray(np.asarray(rhs_reduced, dtype=np.float64)[perm], dtype=jnp.float64)
                x0_perm = None

                def _mv_perm(v: jnp.ndarray) -> jnp.ndarray:
                    x_np = np.asarray(v, dtype=np.float64).reshape((-1,))
                    return jnp.asarray(a_perm @ x_np, dtype=jnp.float64)

                def _precond_perm(v: jnp.ndarray) -> jnp.ndarray:
                    x_np = np.asarray(v, dtype=np.float64).reshape((-1,))
                    return jnp.asarray(ilu_cs0.solve(x_np), dtype=jnp.float64)

                rhs_pc_perm_np = np.asarray(_precond_perm(rhs_perm), dtype=np.float64)
                rhs_pc_norm = float(np.linalg.norm(rhs_pc_perm_np))
                if emit is not None:
                    emit(
                        1,
                        "solve_v3_full_system_linear_gmres: constraintScheme=0 PETSc-compat rhs_pc "
                        f"norm={rhs_pc_norm:.3e} finite={bool(np.all(np.isfinite(rhs_pc_perm_np)))} "
                        f"drop={compat_drop_thresh:.3e} reg={compat_reg:.3e} nnz={int(a_csr_cs0.nnz)}",
                    )
                rhs_perm_norm = float(np.linalg.norm(np.asarray(rhs_perm, dtype=np.float64)))
                rhs_pc_zero_tol = max(float(atol), max(1.0, rhs_perm_norm) * float(tol))
                if np.isfinite(rhs_pc_norm) and rhs_pc_norm <= rhs_pc_zero_tol:
                    x_perm_np = np.zeros((int(active_size),), dtype=np.float64)
                    rn_true_cs0 = rhs_perm_norm
                    rn_pc_cs0 = rhs_pc_norm
                else:
                    x_perm_np, rn_true_cs0, rn_pc_cs0, _history = explicit_left_preconditioned_gmres_scipy(
                        matvec=_mv_perm,
                        b=rhs_perm,
                        preconditioner=_precond_perm,
                        x0=x0_perm,
                        tol=tol,
                        atol=atol,
                        restart=min(int(active_size), max(1, int(compat_restart))),
                        maxiter=max(1, int(compat_maxiter)),
                    )
                x_cs0_np = np.asarray(x_perm_np, dtype=np.float64)[inv_perm]
                rhs_pc_np = rhs_pc_perm_np[inv_perm]

                def _mv_cs0_pc_full(v: jnp.ndarray) -> jnp.ndarray:
                    x_np = np.asarray(v, dtype=np.float64).reshape((-1,))
                    y_perm = np.asarray(a_perm @ x_np[perm], dtype=np.float64)
                    z_perm = ilu_cs0.solve(y_perm)
                    return jnp.asarray(z_perm[inv_perm], dtype=jnp.float64)

                res_reduced = GMRESSolveResult(
                    x=jnp.asarray(x_cs0_np, dtype=jnp.float64),
                    residual_norm=jnp.asarray(rn_pc_cs0, dtype=jnp.float64),
                )
                ksp_matvec = _mv_cs0_pc_full
                ksp_b = jnp.asarray(rhs_pc_np, dtype=jnp.float64)
                ksp_precond = None
                ksp_x0 = None if x0_reduced is None else jnp.asarray(x0_reduced, dtype=jnp.float64)
                ksp_precond_side = "none"
                ksp_solver_kind = _solver_kind("incremental")[0]
                if emit is not None:
                    emit(
                        1,
                        "solve_v3_full_system_linear_gmres: constraintScheme=0 PETSc-compat residuals "
                        f"preconditioned={rn_pc_cs0:.3e} true={rn_true_cs0:.3e}",
                    )
            except Exception as exc:  # noqa: BLE001
                cs0_petsc_compat = False
                if emit is not None:
                    emit(
                        1,
                        "solve_v3_full_system_linear_gmres: constraintScheme=0 PETSc-compat solve failed "
                        f"({type(exc).__name__}: {exc})",
                    )
        probe_env = os.environ.get("SFINCS_JAX_RHSMODE1_DENSE_PROBE", "").strip().lower()
        probe_enabled = probe_env not in {"0", "false", "no", "off"}
        if (
            probe_enabled
            and (not probe_shortcut)
            and (not cs0_petsc_compat)
            and (not cs0_sparse_first)
            and (cs0_dense_fallback_allowed or int(op.constraint_scheme) != 0)
            and preconditioner_reduced is not None
            and solve_method_kind not in {"dense", "dense_ksp"}
        ):
            try:
                probe_x0 = preconditioner_reduced(rhs_reduced)
                probe_r = rhs_reduced - mv_reduced(probe_x0)
                probe_norm = float(jnp.linalg.norm(probe_r))
                probe_ratio = probe_norm / max(float(target_reduced), 1e-300)
                if dense_shortcut_ratio > 0 and probe_ratio >= dense_shortcut_ratio:
                    allow_probe_shortcut = dense_fallback_max > 0 and int(active_size) <= dense_fallback_max
                    if allow_probe_shortcut and (not sparse_prefer_over_dense_shortcut):
                        early_dense_shortcut = True
                        probe_shortcut = True
                        res_reduced = GMRESSolveResult(x=probe_x0, residual_norm=jnp.asarray(probe_norm))
                        ksp_matvec = mv_reduced
                        ksp_b = rhs_reduced
                        ksp_precond = preconditioner_reduced
                        ksp_x0 = probe_x0
                        ksp_precond_side = gmres_precond_side
                        ksp_solver_kind = _solver_kind(solve_method)[0]
                        if emit is not None:
                            emit(
                                0,
                                "solve_v3_full_system_linear_gmres: dense fallback shortcut (probe) "
                                f"(ratio={probe_ratio:.3e} >= {dense_shortcut_ratio:.1e})",
                            )
                    else:
                        if emit is not None:
                            if sparse_prefer_over_dense_shortcut and allow_probe_shortcut:
                                emit(
                                    1,
                                    "solve_v3_full_system_linear_gmres: probe shortcut skipped "
                                    "(preferring sparse rescue over dense shortcut)",
                                )
                            else:
                                emit(
                                    1,
                                    "solve_v3_full_system_linear_gmres: probe shortcut skipped "
                                    f"(size={int(active_size)} > dense_max={dense_fallback_max})",
                                )
                        if x0_reduced is None:
                            x0_reduced = probe_x0
                elif x0_reduced is None:
                    x0_reduced = probe_x0
            except Exception as exc:  # noqa: BLE001
                if emit is not None:
                    emit(1, f"solve_v3_full_system_linear_gmres: probe failed ({type(exc).__name__}: {exc})")
        cpu_large_xblock_shortcut = False
        if cs0_petsc_compat:
            pass
        elif probe_shortcut:
            pass
        elif solve_method_kind == "dense_ksp":
            if int(op.phi1_size) != 0:
                raise NotImplementedError("dense_ksp is only supported for includePhi1=false RHSMode=1 solves.")
            if emit is not None:
                emit(1, "solve_v3_full_system_linear_gmres: assembling dense reduced matrix for dense_ksp")
            a_dense = assemble_dense_matrix_from_matvec(matvec=mv_reduced, n=active_size, dtype=rhs_reduced.dtype)

            if emit is not None:
                emit(1, "solve_v3_full_system_linear_gmres: building PETSc-like species-block preconditioner (dense_ksp)")

            import jax.scipy.linalg as jla  # noqa: PLC0415

            n_species = int(op.n_species)
            n_theta = int(op.n_theta)
            n_zeta = int(op.n_zeta)
            local_per_species = int(np.sum(nxi_for_x))
            dke_size = int(local_per_species * n_theta * n_zeta)
            extra_size = int(op.extra_size)
            extra_per_species = int(extra_size // max(1, n_species)) if extra_size else 0
            if extra_size and (extra_per_species * n_species != extra_size):
                extra_per_species = 0

            f_size = int(n_species * dke_size)
            expected_active = int(f_size + int(op.phi1_size) + extra_size)
            if int(active_size) != expected_active:
                raise RuntimeError(f"dense_ksp expects active_size={expected_active}, got {active_size}")

            lu_factors: list[tuple[jnp.ndarray, jnp.ndarray]] = []
            idx_blocks: list[jnp.ndarray] = []
            for s in range(n_species):
                f_idx = np.arange(s * dke_size, (s + 1) * dke_size, dtype=np.int32)
                extra_idx = np.arange(f_size + s * extra_per_species, f_size + (s + 1) * extra_per_species, dtype=np.int32)
                block_idx_np = np.concatenate([f_idx, extra_idx], axis=0) if extra_per_species else f_idx
                block_idx = jnp.asarray(block_idx_np, dtype=jnp.int32)
                a_block = a_dense[jnp.ix_(block_idx, block_idx)]
                lu, piv = jla.lu_factor(a_block)
                lu_factors.append((lu, piv))
                idx_blocks.append(block_idx)

            def preconditioner_dense(v: jnp.ndarray) -> jnp.ndarray:
                out = jnp.zeros_like(v)
                for block_idx, (lu, piv) in zip(idx_blocks, lu_factors, strict=True):
                    rhs_block = v[block_idx]
                    sol_block = jla.lu_solve((lu, piv), rhs_block)
                    out = out.at[block_idx].set(sol_block, unique_indices=True)
                return out

            def mv_dense(x: jnp.ndarray) -> jnp.ndarray:
                return a_dense @ x

            # PETSc v3 uses *left* preconditioning and checks convergence in the
            # preconditioned residual norm ||M^{-1} r||. To match this behavior with
            # JAX's GMRES (which uses a SciPy-style convergence check), solve the
            # explicitly left-preconditioned system:
            #   (M^{-1} A) x = (M^{-1} b).
            rhs_pc = preconditioner_dense(rhs_reduced)

            def mv_pc(x: jnp.ndarray) -> jnp.ndarray:
                return preconditioner_dense(mv_dense(x))

            rhs1_progress_notes.krylov_start()
            _mark("rhs1_krylov_solve_start")
            res_reduced = _solve_linear(
                matvec_fn=mv_pc,
                b_vec=rhs_pc,
                precond_fn=None,
                x0_vec=x0_reduced,
                tol_val=tol,
                atol_val=atol,
                restart_val=restart,
                maxiter_val=maxiter,
                solve_method_val="incremental",
                precond_side="none",
            )
            res_reduced = _block_gmres_result_ready(res_reduced)
            _mark("rhs1_krylov_solve_done")
            ksp_matvec = mv_pc
            ksp_b = rhs_pc
            ksp_precond = None
            ksp_x0 = x0_reduced
            ksp_precond_side = "none"
            ksp_solver_kind = _solver_kind("incremental")[0]
        else:
            # If the probe indicates the system is far from converged but the dense
            # fallback is not allowed (e.g. medium FP DKES systems), avoid spending
            # many matvecs on a weak/expensive preconditioner. Instead, jump directly
            # to the sparse ILU branch.
            cpu_large_xblock_shortcut = _rhsmode1_large_cpu_xblock_skip_primary_allowed(
                op=op,
                solve_method_kind=solve_method_kind,
                active_size=int(active_size),
                sparse_max_size=int(sparse_max_size),
                preconditioner_species=preconditioner_species,
                preconditioner_x=preconditioner_x,
                preconditioner_xi=preconditioner_xi,
                pre_theta=pre_theta,
                pre_zeta=pre_zeta,
                use_implicit=bool(use_implicit),
                rhs1_precond_env=str(rhs1_precond_env),
            )
            skip_primary_krylov = (
                (
                    (op.fblock.fp is not None)
                    and bool(early_dense_shortcut)
                    and (not bool(probe_shortcut))
                    and sparse_precond_mode != "off"
                    and int(active_size) <= int(sparse_max_size)
                    and solve_method_kind not in {"dense", "dense_ksp"}
                )
                or gpu_dkes_sparse_shortcut
                or cpu_large_xblock_shortcut
            )
            if skip_primary_krylov:
                if emit is not None:
                    reason = "probe ratio huge, dense disabled"
                    if gpu_dkes_sparse_shortcut:
                        reason = "GPU DKES auto sparse shortcut"
                    elif cpu_large_xblock_shortcut:
                        backend_name = str(jax.default_backend()).strip().lower()
                        reason = (
                            "CPU large FP x-block shortcut"
                            if backend_name == "cpu"
                            else f"{backend_name} host-sparse FP x-block shortcut"
                        )
                    emit(
                        0,
                        "solve_v3_full_system_linear_gmres: skipping initial Krylov "
                        f"({reason}) -> sparse ILU",
                    )
                if x0_reduced is None:
                    x0_reduced = jnp.zeros_like(rhs_reduced)
                try:
                    r0 = rhs_reduced - mv_reduced(x0_reduced)
                    rn0 = jnp.linalg.norm(r0)
                except Exception:
                    rn0 = jnp.asarray(np.inf, dtype=jnp.float64)
                res_reduced = GMRESSolveResult(x=x0_reduced, residual_norm=jnp.asarray(rn0, dtype=jnp.float64))
                ksp_matvec = mv_reduced
                ksp_b = rhs_reduced
                ksp_precond = preconditioner_reduced
                ksp_x0 = x0_reduced
                ksp_precond_side = gmres_precond_side
                ksp_solver_kind = _solver_kind(solve_method)[0]
            else:
                rhs1_progress_notes.krylov_start()
                _mark("rhs1_krylov_solve_start")
                res_reduced = _solve_linear(
                    matvec_fn=mv_reduced,
                    b_vec=rhs_reduced,
                    precond_fn=preconditioner_reduced,
                    x0_vec=x0_reduced,
                    tol_val=tol,
                    atol_val=atol,
                    restart_val=restart,
                    maxiter_val=maxiter,
                    solve_method_val=solve_method,
                    precond_side=gmres_precond_side,
                )
                res_reduced = _block_gmres_result_ready(res_reduced)
                _mark("rhs1_krylov_solve_done")
                ksp_matvec = mv_reduced
                ksp_b = rhs_reduced
                ksp_precond = preconditioner_reduced
                ksp_x0 = x0_reduced
                ksp_precond_side = gmres_precond_side
                ksp_solver_kind = _solver_kind(solve_method)[0]
        if (not probe_shortcut) and preconditioner_reduced is not None and (not _gmres_result_is_finite(res_reduced)):
            if emit is not None:
                emit(0, "solve_v3_full_system_linear_gmres: preconditioned reduced GMRES returned non-finite result; retrying without preconditioner")
            res_reduced = _solve_linear(
                matvec_fn=mv_reduced,
                b_vec=rhs_reduced,
                precond_fn=None,
                x0_vec=x0_reduced,
                tol_val=tol,
                atol_val=atol,
                restart_val=restart,
                maxiter_val=maxiter,
                solve_method_val=solve_method,
                precond_side=gmres_precond_side,
            )
            res_reduced = _block_gmres_result_ready(res_reduced)
            ksp_matvec = mv_reduced
            ksp_b = rhs_reduced
            ksp_precond = None
            ksp_x0 = x0_reduced
            ksp_precond_side = gmres_precond_side
            ksp_solver_kind = _solver_kind(solve_method)[0]
        if (
            pas_precond_force_collision
            and op.fblock.pas is not None
            and float(res_reduced.residual_norm) > target_reduced
        ):
            force_full_ratio_env = os.environ.get("SFINCS_JAX_PAS_FORCE_FULL_RATIO", "").strip()
            try:
                force_full_ratio = float(force_full_ratio_env) if force_full_ratio_env else 50.0
            except ValueError:
                force_full_ratio = 50.0
            res_ratio_full = float(res_reduced.residual_norm) / max(float(target_reduced), 1e-300)
            if res_ratio_full > force_full_ratio:
                forced_kind = rhs1_precond_kind_requested or "xmg"
                if op.fblock.pas is not None:
                    pas_lite_min_env = os.environ.get("SFINCS_JAX_PAS_LITE_MIN", "").strip()
                    try:
                        pas_lite_min = int(pas_lite_min_env) if pas_lite_min_env else 20000
                    except ValueError:
                        pas_lite_min = 20000
                    if int(active_size) >= max(1, int(pas_lite_min)):
                        forced_kind = "pas_lite"
                    else:
                        forced_kind = "pas_hybrid"
                elif forced_kind in {"collision", "schur", "point"}:
                    forced_kind = "xmg"
                if emit is not None:
                    emit(
                        0,
                        "solve_v3_full_system_linear_gmres: PAS forcing full preconditioner "
                        f"(kind={forced_kind}, residual={float(res_reduced.residual_norm):.3e} > "
                        f"{force_full_ratio:.1f}x target)",
                    )
                rhs1_precond_kind = forced_kind
                preconditioner_reduced = _build_rhs1_preconditioner_reduced_with_fallback()
                if use_pas_projection:
                    preconditioner_reduced = _wrap_pas_precond(preconditioner_reduced)
                res_full = _solve_linear(
                    matvec_fn=mv_reduced,
                    b_vec=rhs_reduced,
                    precond_fn=preconditioner_reduced,
                    x0_vec=res_reduced.x,
                    tol_val=tol,
                    atol_val=atol,
                    restart_val=restart,
                    maxiter_val=maxiter,
                    solve_method_val="incremental",
                    precond_side=gmres_precond_side,
                )
                res_reduced, residual_vec, handoff_state, _accepted = rhs1_accept_candidate(
                    current_result=res_reduced,
                    candidate_result=res_full,
                    current_residual_vec=residual_vec,
                    candidate_residual_vec=residual_vec,
                    matvec_fn=mv_reduced,
                    b_vec=rhs_reduced,
                    precond_fn=preconditioner_reduced,
                    x0_vec=res_full.x,
                    restart=restart,
                    maxiter=maxiter,
                    precond_side=gmres_precond_side,
                    solver_kind=_solver_kind("incremental")[0],
                )
                _apply_rhs1_handoff(handoff_state)
        residual_norm_check = float(res_reduced.residual_norm)
        residual_norm_true = residual_norm_check
        try:
            r_vec = rhs_reduced - mv_reduced(res_reduced.x)
            residual_norm_true = float(jnp.linalg.norm(r_vec))
            if not np.isfinite(residual_norm_true):
                residual_norm_true = residual_norm_check
        except Exception:
            residual_norm_true = residual_norm_check
        if np.isfinite(residual_norm_true):
            res_reduced = GMRESSolveResult(
                x=res_reduced.x, residual_norm=jnp.asarray(residual_norm_true, dtype=jnp.float64)
            )
        if (
            rhs1_pas_tz_guarded_fallback
            and preconditioner_reduced is not None
            and float(res_reduced.residual_norm) > float(target_reduced)
        ):
            correction_preconditioner = preconditioner_reduced
            correction_kind = resolve_pas_tz_guarded_correction_kind(
                requested=os.environ.get("SFINCS_JAX_RHSMODE1_PAS_TZ_GUARDED_CORRECTION", "")
            )
            if correction_kind == "tzfft" and rhs1_pas_tz_guarded_axis != "tzfft":
                try:
                    correction_preconditioner = _build_rhsmode23_tzfft_preconditioner(
                        op=op, reduce_full=reduce_full, expand_reduced=expand_reduced
                    )
                    if use_pas_projection:
                        correction_preconditioner = _wrap_pas_precond(correction_preconditioner)
                    if emit is not None:
                        emit(
                            1,
                            "solve_v3_full_system_linear_gmres: PAS-TZ guarded "
                            "matrix-free correction=tzfft",
                        )
                except Exception as exc:  # noqa: BLE001
                    correction_preconditioner = preconditioner_reduced
                    if emit is not None:
                        emit(
                            1,
                            "solve_v3_full_system_linear_gmres: PAS-TZ guarded "
                            f"matrix-free correction=tzfft unavailable ({type(exc).__name__}); "
                            "using base fallback",
                        )
            minres_steps_env = os.environ.get("SFINCS_JAX_RHSMODE1_PAS_TZ_GUARDED_MINRES_STEPS", "").strip()
            minres_clip_env = os.environ.get("SFINCS_JAX_RHSMODE1_PAS_TZ_GUARDED_MINRES_ALPHA_CLIP", "").strip()
            minres_improve_env = os.environ.get("SFINCS_JAX_RHSMODE1_PAS_TZ_GUARDED_MINRES_MIN_IMPROVEMENT", "").strip()
            try:
                minres_steps = int(minres_steps_env) if minres_steps_env else 2
            except ValueError:
                minres_steps = 2
            try:
                minres_clip = float(minres_clip_env) if minres_clip_env else 10.0
            except ValueError:
                minres_clip = 10.0
            try:
                minres_improve = float(minres_improve_env) if minres_improve_env else 0.0
            except ValueError:
                minres_improve = 0.0
            if minres_steps > 0:
                x_minres, residual_minres, minres_history, minres_alphas = _apply_preconditioned_minres_correction(
                    matvec=mv_reduced,
                    rhs=rhs_reduced,
                    x0=res_reduced.x,
                    preconditioner=correction_preconditioner,
                    steps=int(minres_steps),
                    alpha_clip=float(minres_clip),
                    min_improvement=float(minres_improve),
                )
                if minres_history and float(minres_history[-1]) < float(res_reduced.residual_norm):
                    old_residual = float(res_reduced.residual_norm)
                    residual_norm_true = float(minres_history[-1])
                    residual_vec = residual_minres
                    res_reduced = GMRESSolveResult(
                        x=jnp.asarray(x_minres, dtype=jnp.float64),
                        residual_norm=jnp.asarray(residual_norm_true, dtype=jnp.float64),
                    )
                    if emit is not None:
                        emit(
                            1,
                            "solve_v3_full_system_linear_gmres: PAS-TZ guarded minres correction "
                            f"accepted {len(minres_alphas)} step(s), residual="
                            f"{old_residual:.3e}->{residual_norm_true:.3e}",
                        )
        weak_minres_ratio = float(residual_norm_true) / max(float(target_reduced), 1e-300)
        weak_minres_steps = rhs1_pas_weak_minres_steps(
            has_pas=op.fblock.pas is not None,
            rhs1_precond_kind=rhs1_precond_kind,
            res_ratio=float(weak_minres_ratio),
        )
        if (
            (not rhs1_pas_tz_guarded_fallback)
            and preconditioner_reduced is not None
            and weak_minres_steps > 0
            and float(res_reduced.residual_norm) > float(target_reduced)
        ):
            weak_clip_env = os.environ.get("SFINCS_JAX_PAS_WEAK_MINRES_ALPHA_CLIP", "").strip()
            weak_improve_env = os.environ.get("SFINCS_JAX_PAS_WEAK_MINRES_MIN_IMPROVEMENT", "").strip()
            try:
                weak_clip = float(weak_clip_env) if weak_clip_env else 10.0
            except ValueError:
                weak_clip = 10.0
            try:
                weak_improve = float(weak_improve_env) if weak_improve_env else 0.0
            except ValueError:
                weak_improve = 0.0
            x_minres, residual_minres, minres_history, minres_alphas = _apply_preconditioned_minres_correction(
                matvec=mv_reduced,
                rhs=rhs_reduced,
                x0=res_reduced.x,
                preconditioner=preconditioner_reduced,
                steps=int(weak_minres_steps),
                alpha_clip=float(weak_clip),
                min_improvement=float(weak_improve),
            )
            if minres_history and float(minres_history[-1]) < float(res_reduced.residual_norm):
                old_residual = float(res_reduced.residual_norm)
                residual_norm_true = float(minres_history[-1])
                residual_vec = residual_minres
                res_reduced = GMRESSolveResult(
                    x=jnp.asarray(x_minres, dtype=jnp.float64),
                    residual_norm=jnp.asarray(residual_norm_true, dtype=jnp.float64),
                )
                if emit is not None:
                    emit(
                        1,
                        "solve_v3_full_system_linear_gmres: weak PAS minres correction "
                        f"accepted {len(minres_alphas)} step(s), residual="
                        f"{old_residual:.3e}->{residual_norm_true:.3e}",
                    )
        res_ratio = float(residual_norm_true) / max(float(target_reduced), 1e-300)
        stage2_trigger = rhs1_stage2_trigger(res_ratio=res_ratio, use_dkes=bool(use_dkes))
        fp_force_stage2 = rhs1_fp_force_stage2(
            has_fp=op.fblock.fp is not None,
            include_phi1=bool(op.include_phi1),
            residual_norm=float(res_reduced.residual_norm),
        )
        if fp_force_stage2:
            stage2_trigger = True
        if cpu_large_xblock_shortcut:
            stage2_trigger = False
            if emit is not None:
                emit(
                    1,
                    "solve_v3_full_system_linear_gmres: CPU large FP x-block shortcut "
                    "skipping stage2 GMRES and proceeding directly to x-block rescue",
                )
        if rhs1_pas_stage2_skip(
            has_pas=op.fblock.pas is not None,
            rhs1_precond_kind=rhs1_precond_kind,
            res_ratio=float(res_ratio),
        ):
            stage2_trigger = False
            if emit is not None:
                emit(
                    1,
                    "solve_v3_full_system_linear_gmres: PAS stage2 skipped "
                    f"(residual ratio={res_ratio:.3e}; set the relevant PAS stage2 skip ratio to 0 to retry)",
                )
        if rhs1_pas_tz_guarded_fallback and stage2_trigger and not rhs1_pas_tz_guarded_stage2_retry():
            stage2_trigger = False
            if emit is not None:
                emit(
                    1,
                    "solve_v3_full_system_linear_gmres: stage2 reduced GMRES skipped "
                    "after guarded PAS-TZ fallback; set "
                    "SFINCS_JAX_RHSMODE1_PAS_TZ_GUARDED_STAGE2_RETRY=1 to retry",
                )
        if (
            (not early_dense_shortcut)
            and (not cs0_sparse_first)
            and (cs0_dense_fallback_allowed or int(op.constraint_scheme) != 0)
            and dense_shortcut_ratio > 0
            and res_ratio >= dense_shortcut_ratio
            and (not sparse_prefer_over_dense_shortcut)
        ):
            dense_fallback_max_huge_env = os.environ.get("SFINCS_JAX_RHSMODE1_DENSE_FALLBACK_MAX_HUGE", "").strip()
            dense_fallback_ratio_env = os.environ.get("SFINCS_JAX_RHSMODE1_DENSE_FALLBACK_RATIO", "").strip()
            try:
                dense_fallback_max_huge = int(dense_fallback_max_huge_env) if dense_fallback_max_huge_env else dense_fallback_max
            except ValueError:
                dense_fallback_max_huge = dense_fallback_max
            try:
                dense_fallback_ratio = float(dense_fallback_ratio_env) if dense_fallback_ratio_env else 1.0e2
            except ValueError:
                dense_fallback_ratio = 1.0e2
            dense_fallback_limit = dense_fallback_max_huge if res_ratio > dense_fallback_ratio else dense_fallback_max
            if dense_fallback_limit > 0 and int(active_size) <= int(dense_fallback_limit):
                early_dense_shortcut = True
                if emit is not None:
                    emit(
                        0,
                        "solve_v3_full_system_linear_gmres: dense fallback shortcut (early) "
                        f"(ratio={res_ratio:.3e} >= {dense_shortcut_ratio:.1e})",
                    )
            elif emit is not None:
                emit(
                    1,
                    "solve_v3_full_system_linear_gmres: dense fallback shortcut skipped "
                    f"(size={int(active_size)} > dense_max={int(dense_fallback_limit)})",
                )
        solver_kind = _solver_kind(solve_method)[0]
        bicgstab_fallback_target = float(target_reduced)
        if bicgstab_fallback_strict:
            fallback_floor_env = os.environ.get("SFINCS_JAX_BICGSTAB_FALLBACK_ABS_FLOOR", "").strip()
            default_floor = 0.0
            if distributed_axis is not None and op.fblock.pas is not None and (not bool(op.include_phi1)):
                # In distributed PAS runs, BiCGStab often reaches solutions that are
                # already parity-accurate, but the strict relative target is tiny due to
                # small RHS norms. Avoid an expensive GMRES polish when residual is tiny.
                default_floor = 1.0e-7
            try:
                fallback_floor = float(fallback_floor_env) if fallback_floor_env else default_floor
            except ValueError:
                fallback_floor = default_floor
            bicgstab_fallback_target = max(float(target_reduced), max(0.0, float(fallback_floor)))
        if solver_kind == "bicgstab" and (
            (not _gmres_result_is_finite(res_reduced))
            or (bicgstab_fallback_strict and float(res_reduced.residual_norm) > bicgstab_fallback_target)
        ):
            if emit is not None:
                emit(
                    0,
                    "solve_v3_full_system_linear_gmres: BiCGStab fallback to GMRES "
                    f"(residual={float(res_reduced.residual_norm):.3e} > target={bicgstab_fallback_target:.3e})",
                )
            if preconditioner_reduced is None and rhs1_precond_enabled:
                preconditioner_reduced = _build_rhs1_preconditioner_reduced_with_fallback()
            res_reduced = _solve_linear(
                matvec_fn=mv_reduced,
                b_vec=rhs_reduced,
                precond_fn=preconditioner_reduced,
                x0_vec=x0_reduced,
                tol_val=tol,
                atol_val=atol,
                restart_val=restart,
                maxiter_val=maxiter,
                solve_method_val="incremental",
                precond_side=gmres_precond_side,
            )
            res_reduced = _block_gmres_result_ready(res_reduced)
            ksp_matvec = mv_reduced
            ksp_b = rhs_reduced
            ksp_precond = preconditioner_reduced
            ksp_x0 = x0_reduced
            ksp_precond_side = gmres_precond_side
            ksp_solver_kind = "gmres"
        if (
            sparse_prefer_skips_stage2
            and float(res_reduced.residual_norm) > target_reduced
            and stage2_enabled
            and stage2_trigger
            and not early_dense_shortcut
            and not gpu_dkes_sparse_shortcut
            and emit is not None
        ):
            emit(
                1,
                "solve_v3_full_system_linear_gmres: stage2 reduced GMRES skipped "
                "(preferring sparse rescue first)",
            )
        if (
            (float(res_reduced.residual_norm) > target_reduced or fp_force_stage2)
            and stage2_enabled
            and stage2_trigger
            and not early_dense_shortcut
            and not gpu_dkes_sparse_shortcut
            and not sparse_prefer_skips_stage2
            and t.elapsed_s() < stage2_time_cap_s
        ):
            if preconditioner_reduced is None and rhs1_precond_enabled:
                preconditioner_reduced = _build_rhs1_preconditioner_reduced_with_fallback()
            stage2_maxiter_env = os.environ.get("SFINCS_JAX_LINEAR_STAGE2_MAXITER", "")
            stage2_restart_env = os.environ.get("SFINCS_JAX_LINEAR_STAGE2_RESTART", "")
            stage2_maxiter = int(stage2_maxiter_env or str(max(600, int(maxiter or 400) * 2)))
            stage2_restart = int(stage2_restart_env or str(max(120, int(restart))))
            if tokamak_pas and (not stage2_maxiter_env):
                stage2_maxiter = max(int(stage2_maxiter), 2000)
            if tokamak_pas and (not stage2_restart_env):
                stage2_restart = max(int(stage2_restart), 160)
            if (
                op.fblock.fp is not None
                and op.fblock.pas is None
                and int(active_size) >= 300000
                and (not stage2_maxiter_env)
            ):
                # Large FP systems often need stage2 to close diagnostics, but
                # maxiter=800 is unnecessarily expensive in practice.
                stage2_maxiter = min(int(stage2_maxiter), 600)
            if (
                op.fblock.fp is not None
                and op.fblock.pas is None
                and int(active_size) >= 300000
                and (not stage2_restart_env)
            ):
                stage2_restart = min(max(80, int(stage2_restart)), 100)
            stage2_method = os.environ.get("SFINCS_JAX_LINEAR_STAGE2_METHOD", "incremental").strip().lower()
            if stage2_method not in {"batched", "incremental", "dense"}:
                stage2_method = "incremental"
            if emit is not None:
                emit(
                    0,
                    "solve_v3_full_system_linear_gmres: stage2 reduced GMRES "
                    f"(residual={float(res_reduced.residual_norm):.3e} > target={target_reduced:.3e}) "
                    f"restart={stage2_restart} maxiter={stage2_maxiter} method={stage2_method}",
                )
            stage2_timer = Timer()
            res2 = _solve_linear(
                matvec_fn=mv_reduced,
                b_vec=rhs_reduced,
                precond_fn=preconditioner_reduced,
                x0_vec=res_reduced.x,
                tol_val=tol,
                atol_val=atol,
                restart_val=stage2_restart,
                maxiter_val=stage2_maxiter,
                solve_method_val=stage2_method,
                precond_side=gmres_precond_side,
            )
            res2 = _block_gmres_result_ready(res2)
            stage2_elapsed_s = stage2_timer.elapsed_s()
            res_reduced, residual_vec, handoff_state, _accepted = rhs1_accept_candidate(
                current_result=res_reduced,
                candidate_result=res2,
                current_residual_vec=residual_vec,
                candidate_residual_vec=residual_vec,
                matvec_fn=mv_reduced,
                b_vec=rhs_reduced,
                precond_fn=preconditioner_reduced,
                x0_vec=res2.x,
                restart=stage2_restart,
                maxiter=stage2_maxiter,
                precond_side=gmres_precond_side,
                solver_kind=_solver_kind(stage2_method)[0],
                candidate_metrics=_rhs1_solver_candidate_metrics(
                    name=f"stage2_reduced:{stage2_method}",
                    result=res2,
                    target_value=target_reduced,
                    solve_s=stage2_elapsed_s,
                ),
                baseline_metrics=_rhs1_solver_candidate_metrics(
                    name="current_reduced",
                    result=res_reduced,
                    target_value=target_reduced,
                ),
            )
            _apply_rhs1_handoff(handoff_state)
        pas_fast_accept = _rhsmode1_pas_fast_accept(
            op=op,
            active_size=int(active_size),
            residual_norm=float(res_reduced.residual_norm),
            target=float(target_reduced),
            use_implicit=bool(use_implicit),
        )
        res_ratio = float(res_reduced.residual_norm) / max(float(target_reduced), 1e-300)
        strong_ratio_env = os.environ.get("SFINCS_JAX_RHSMODE1_STRONG_PRECOND_RATIO", "").strip()
        try:
            strong_ratio = float(strong_ratio_env) if strong_ratio_env else 1.0
        except ValueError:
            strong_ratio = 1.0
        if (
            not strong_ratio_env
            and op.fblock.pas is not None
            and rhs1_precond_kind
            in {
                "theta_line",
                "theta_line_xdiag",
                "theta_dd",
                "theta_schwarz",
                "xblock_tz",
                "xblock_tz_lmax",
                "pas_hybrid",
                "pas_lite",
                "pas_tz",
                "pas_schur",
                "pas_tokamak_theta",
            }
        ):
            strong_ratio = max(float(strong_ratio), 1.0e2)
            if rhs1_precond_kind == "pas_tokamak_theta":
                # Avoid expensive strong-preconditioner fallbacks for large tokamak PAS
                # runs; the tokamak theta preconditioner typically converges without
                # needing xblock_tz_lmax, and the fallback cost dominates runtime.
                strong_ratio = max(float(strong_ratio), 1.0e4)
        strong_precond_trigger = bool(res_ratio > strong_ratio) if strong_ratio > 0 else True
        fp_strong_abs_env = os.environ.get("SFINCS_JAX_FP_STRONG_ABS", "").strip()
        try:
            fp_strong_abs = float(fp_strong_abs_env) if fp_strong_abs_env else 1.0e-6
        except ValueError:
            fp_strong_abs = 1.0e-6
        fp_force_strong = bool(
            op.fblock.fp is not None
            and (not bool(op.include_phi1))
            and float(res_reduced.residual_norm) > float(fp_strong_abs)
        )
        if (
            rhs1_precond_kind in {"pas_lite", "pas_hybrid", "pas_tz", "pas_schur", "pas_tokamak_theta"}
            and preconditioner_reduced is not None
            and _rhsmode1_pas_adaptive_smoother_allowed(
                op=op,
                active_size=int(active_size),
                residual_norm=float(res_reduced.residual_norm),
                target=float(target_reduced),
                use_implicit=bool(use_implicit),
            )
        ):
            smoother_max_env = os.environ.get("SFINCS_JAX_PAS_ADAPTIVE_SMOOTHER_SWEEPS", "").strip()
            smoother_omega_env = os.environ.get("SFINCS_JAX_PAS_ADAPTIVE_SMOOTHER_OMEGA", "").strip()
            try:
                smoother_max = int(smoother_max_env) if smoother_max_env else 3
            except ValueError:
                smoother_max = 3
            try:
                smoother_omega = float(smoother_omega_env) if smoother_omega_env else 1.0
            except ValueError:
                smoother_omega = 1.0
            smoother = adaptive_pas_smoother(
                matvec=mv_reduced,
                rhs=rhs_reduced,
                preconditioner=preconditioner_reduced,
                x0=res_reduced.x,
                target=float(target_reduced),
                omega=float(smoother_omega),
                max_sweeps=int(smoother_max),
            )
            if float(smoother.residual_norm) < float(res_reduced.residual_norm):
                if emit is not None:
                    emit(
                        1,
                        "solve_v3_full_system_linear_gmres: PAS adaptive smoother "
                        f"accepted {int(smoother.accepted_sweeps)} sweep(s), "
                        f"reason={smoother.stop_reason}, "
                        f"residual={float(res_reduced.residual_norm):.3e}->{float(smoother.residual_norm):.3e}",
                    )
                smoother_result = GMRESSolveResult(
                    x=smoother.x,
                    residual_norm=jnp.asarray(smoother.residual_norm, dtype=jnp.float64),
                )
                res_reduced, residual_vec, handoff_state, _accepted = rhs1_accept_candidate(
                    current_result=res_reduced,
                    candidate_result=smoother_result,
                    current_residual_vec=residual_vec,
                    candidate_residual_vec=residual_vec,
                    matvec_fn=mv_reduced,
                    b_vec=rhs_reduced,
                    precond_fn=preconditioner_reduced,
                    x0_vec=smoother_result.x,
                    restart=restart,
                    maxiter=maxiter,
                    precond_side=gmres_precond_side,
                    solver_kind=_solver_kind("incremental")[0],
                )
                _apply_rhs1_handoff(handoff_state)
        if fp_force_strong:
            strong_precond_trigger = True
        if (
            float(res_reduced.residual_norm) > target_reduced
            and int(op.rhs_mode) == 1
            and (not bool(op.include_phi1))
            and rhs1_precond_kind == "point"
            and (op.fblock.fp is not None or op.fblock.pas is not None)
            and strong_precond_trigger
        ):
            if bicgstab_preconditioner_reduced is None:
                bicgstab_preconditioner_reduced = _build_rhsmode1_collision_preconditioner(
                    op=op, reduce_full=reduce_full, expand_reduced=expand_reduced
                )
            if bicgstab_preconditioner_reduced is not None:
                if emit is not None:
                    emit(
                        0,
                        "solve_v3_full_system_linear_gmres: retry with collision preconditioner "
                        f"(residual={float(res_reduced.residual_norm):.3e} > target={target_reduced:.3e})",
                    )
                res_collision = _solve_linear(
                    matvec_fn=mv_reduced,
                    b_vec=rhs_reduced,
                    precond_fn=bicgstab_preconditioner_reduced,
                    x0_vec=res_reduced.x,
                    tol_val=tol,
                    atol_val=atol,
                    restart_val=restart,
                    maxiter_val=maxiter,
                    solve_method_val="incremental",
                    precond_side=gmres_precond_side,
                )
                res_reduced, residual_vec, handoff_state, _accepted = rhs1_accept_candidate(
                    current_result=res_reduced,
                    candidate_result=res_collision,
                    current_residual_vec=residual_vec,
                    candidate_residual_vec=residual_vec,
                    matvec_fn=mv_reduced,
                    b_vec=rhs_reduced,
                    precond_fn=bicgstab_preconditioner_reduced,
                    x0_vec=res_collision.x,
                    restart=restart,
                    maxiter=maxiter,
                    precond_side=gmres_precond_side,
                    solver_kind=_solver_kind("incremental")[0],
                )
                _apply_rhs1_handoff(handoff_state)
        large_cpu_sparse_rescue_active = _rhsmode1_large_cpu_sparse_rescue_allowed(
            op=op,
            solve_method_kind=solve_method_kind,
            active_size=int(active_size),
            sparse_max_size=int(sparse_max_size),
            preconditioner_x=int(preconditioner_x),
            residual_norm=float(res_reduced.residual_norm),
            target=float(target_reduced),
        )
        sparse_xblock_rescue_active = _rhsmode1_sparse_xblock_rescue_allowed(
            op=op,
            solve_method_kind=solve_method_kind,
            active_size=int(active_size),
            sparse_max_size=int(sparse_max_size),
            preconditioner_x=int(preconditioner_x),
            pre_theta=int(pre_theta),
            pre_zeta=int(pre_zeta),
            residual_norm=float(res_reduced.residual_norm),
            target=float(target_reduced),
        )
        sparse_sxblock_rescue_active = _rhsmode1_sparse_sxblock_rescue_allowed(
            op=op,
            solve_method_kind=solve_method_kind,
            active_size=int(active_size),
            sparse_max_size=int(sparse_max_size),
            preconditioner_x=int(preconditioner_x),
            pre_theta=int(pre_theta),
            pre_zeta=int(pre_zeta),
            use_implicit=bool(use_implicit),
        )
        strong_precond_env = os.environ.get("SFINCS_JAX_RHSMODE1_STRONG_PRECOND", "").strip().lower()
        large_cpu_sparse_rescue_first = _rhsmode1_large_cpu_sparse_rescue_first(
            large_cpu_sparse_rescue=large_cpu_sparse_rescue_active,
            strong_precond_env=strong_precond_env,
        )
        pas_auto_skip = _pas_auto_skip_strong_retry(
            has_pas=op.fblock.pas is not None,
            strong_precond_env=strong_precond_env,
            rhs1_precond_kind=rhs1_precond_kind,
            residual_norm=float(res_reduced.residual_norm),
            target=float(target_reduced),
            ratio=float(pas_auto_strong_ratio),
        )
        strong_control = rhs1_resolved_strong_preconditioner_control(
            strong_precond_env=strong_precond_env,
            has_extra_constraint_block=int(op.constraint_scheme) == 2 and int(op.extra_size) > 0 and (not use_pas_projection),
            has_fp=op.fblock.fp is not None,
            has_pas=op.fblock.pas is not None,
            size=int(active_size),
            n_theta=int(op.n_theta),
            n_zeta=int(op.n_zeta),
            pas_large_bicgstab_fastpath=bool(pas_large_bicgstab_fastpath),
            cs0_sparse_first=bool(cs0_sparse_first),
            large_cpu_sparse_rescue_first=bool(large_cpu_sparse_rescue_first),
            pas_auto_skip=bool(pas_auto_skip),
            pas_fast_accept=bool(pas_fast_accept),
            pas_precond_force_collision=bool(pas_precond_force_collision),
            residual_norm=float(res_reduced.residual_norm),
            target=float(target_reduced),
        )
        strong_precond_min = int(strong_control.min_size)
        strong_precond_disabled = bool(strong_control.disabled)
        strong_precond_auto = bool(strong_control.auto)
        if strong_control.reason_cs0_sparse_first and emit is not None:
            emit(
                1,
                "solve_v3_full_system_linear_gmres: constraintScheme=0 sparse-first "
                "auto mode -> defer strong preconditioner until after sparse ILU",
            )
        if strong_control.reason_large_cpu_sparse_first and emit is not None:
            if emit is not None:
                backend_name = str(jax.default_backend()).strip().lower()
                sparse_label = "large CPU" if backend_name == "cpu" else f"{backend_name} host-sparse"
                emit(
                    1,
                    f"solve_v3_full_system_linear_gmres: {sparse_label} rescue-first "
                    "auto mode -> defer strong preconditioner until after sparse LU",
                )
        if strong_control.reason_pas_auto_skip and emit is not None:
            if emit is not None:
                emit(
                    1,
                    "solve_v3_full_system_linear_gmres: PAS auto strong preconditioner skipped "
                    f"after base={rhs1_precond_kind} "
                    f"(residual={float(res_reduced.residual_norm):.3e} <= {float(pas_auto_strong_ratio):.1f}x target)",
                )
        if strong_control.reason_pas_fast_accept and emit is not None:
            if emit is not None:
                emit(
                    1,
                    "solve_v3_full_system_linear_gmres: PAS fast-accept "
                    f"(residual={float(res_reduced.residual_norm):.3e}) -> skip strong preconditioner tail",
                )
        if strong_control.reason_collision_probe_skip and emit is not None:
            emit(1, "solve_v3_full_system_linear_gmres: PAS collision probe disabled strong preconditioner auto")
        elif pas_precond_force_collision and strong_precond_env in {"", "auto"} and emit is not None:
            pas_force_strong_ratio_env = os.environ.get("SFINCS_JAX_PAS_FORCE_STRONG_RATIO", "").strip()
            try:
                pas_force_strong_ratio = float(pas_force_strong_ratio_env) if pas_force_strong_ratio_env else 50.0
            except ValueError:
                pas_force_strong_ratio = 50.0
            if float(res_reduced.residual_norm) > target_reduced * pas_force_strong_ratio:
                emit(
                    1,
                    "solve_v3_full_system_linear_gmres: PAS collision probe allows strong preconditioner "
                    f"(residual={float(res_reduced.residual_norm):.3e} > {pas_force_strong_ratio:.1f}x target)",
                )
        strong_precond_kind: str | None = None
        strong_xblock_tz_lmax: int | None = None
        if strong_precond_disabled:
            strong_precond_kind = None
        else:
            strong_precond_kind = requested_rhs1_strong_preconditioner_kind(
                strong_precond_env,
                mode="reduced",
            )

        if strong_precond_kind is None and (not strong_precond_disabled) and strong_precond_auto:
            if int(op.constraint_scheme) == 2 and int(op.extra_size) > 0:
                if op.fblock.pas is not None:
                    auto_sel = auto_rhs1_reduced_strong_kind(
                        has_pas=True,
                        has_fp=False,
                        geom_scheme=int(geom_scheme),
                        use_dkes=bool(use_dkes),
                        active_size=int(active_size),
                        strong_precond_min=int(strong_precond_min),
                        n_theta=int(op.n_theta),
                        n_zeta=int(op.n_zeta),
                        max_l=int(np.max(nxi_for_x)) if nxi_for_x.size else 0,
                        shard_axis=_matvec_shard_axis(op),
                        device_count=int(jax.device_count()),
                    )
                    strong_precond_kind = auto_sel.kind
                else:
                    strong_precond_kind = "schur"
            else:
                auto_sel = auto_rhs1_reduced_strong_kind(
                    has_pas=op.fblock.pas is not None,
                    has_fp=op.fblock.fp is not None,
                    geom_scheme=int(geom_scheme),
                    use_dkes=bool(use_dkes),
                    active_size=int(active_size),
                    strong_precond_min=int(strong_precond_min),
                    n_theta=int(op.n_theta),
                    n_zeta=int(op.n_zeta),
                    max_l=int(np.max(nxi_for_x)) if nxi_for_x.size else 0,
                    shard_axis=_matvec_shard_axis(op),
                    device_count=int(jax.device_count()),
                )
                strong_precond_kind = auto_sel.kind
                strong_xblock_tz_lmax = auto_sel.xblock_tz_lmax

        auto_sel = adjust_rhs1_reduced_auto_kind(
            kind=strong_precond_kind,
            has_pas=op.fblock.pas is not None,
            geom_scheme=int(geom_scheme),
            n_zeta=int(op.n_zeta),
            strong_precond_trigger=bool(strong_precond_trigger),
            max_l=int(np.max(nxi_for_x)) if nxi_for_x.size else 0,
            n_theta=int(op.n_theta),
        )
        strong_precond_kind = auto_sel.kind
        if auto_sel.xblock_tz_lmax is not None:
            strong_xblock_tz_lmax = auto_sel.xblock_tz_lmax

        auto_sel = adjust_rhs1_theta_line_auto_kind(
            kind=strong_precond_kind,
            n_theta=int(op.n_theta),
            nxi_for_x_sum=int(np.sum(nxi_for_x)) if nxi_for_x.size else 0,
        )
        strong_precond_kind = auto_sel.kind

        if rhs1_pas_weak_strong_retry_skip(
            has_pas=op.fblock.pas is not None,
            rhs1_precond_kind=rhs1_precond_kind,
            res_ratio=float(res_ratio),
        ):
            if emit is not None and strong_precond_kind is not None:
                emit(
                    1,
                    "solve_v3_full_system_linear_gmres: skipping strong preconditioner "
                    "after weak PAS base residual exceeded skip threshold; set "
                    "SFINCS_JAX_PAS_STRONG_WEAK_SKIP_RATIO=0 to retry",
                )
            strong_precond_kind = None
            strong_precond_trigger = False

        if rhs1_pas_tz_guarded_fallback:
            guarded_retry_env = os.environ.get("SFINCS_JAX_RHSMODE1_PAS_TZ_GUARDED_STRONG_RETRY", "").strip().lower()
            guarded_retry = guarded_retry_env in {"1", "true", "yes", "on"}
            if not guarded_retry:
                if emit is not None and strong_precond_kind is not None:
                    emit(
                        1,
                        "solve_v3_full_system_linear_gmres: skipping strong preconditioner "
                        "after guarded PAS-TZ fallback; set "
                        "SFINCS_JAX_RHSMODE1_PAS_TZ_GUARDED_STRONG_RETRY=1 to retry",
                    )
                strong_precond_kind = None
                strong_precond_trigger = False

        if (
            strong_precond_kind is not None
            and _rhs1_residual_needs_rescue(
                float(res_reduced.residual_norm),
                float(target_reduced),
                force=bool(fp_force_strong),
            )
            and strong_precond_trigger
            and not early_dense_shortcut
        ):
            if op.fblock.fp is not None and op.fblock.pas is None:
                fp_strong_max_env = os.environ.get("SFINCS_JAX_RHSMODE1_FP_STRONG_PRECOND_MAX", "").strip()
                try:
                    fp_strong_max = int(fp_strong_max_env) if fp_strong_max_env else 120000
                except ValueError:
                    fp_strong_max = 120000
                fp_heavy_kinds = {
                    "theta_line",
                    "theta_line_xdiag",
                    "zeta_line",
                    "theta_zeta",
                    "xblock_tz",
                    "xblock_tz_lmax",
                    "species_block",
                    "sxblock",
                    "sxblock_tz",
                }
                if int(active_size) > max(0, int(fp_strong_max)) and strong_precond_kind in fp_heavy_kinds:
                    if emit is not None:
                        emit(
                            1,
                            "solve_v3_full_system_linear_gmres: skipping strong preconditioner "
                            f"(kind={strong_precond_kind}, size={int(active_size)} > fp_max={int(fp_strong_max)})",
                        )
                    strong_precond_kind = None
        if (
            strong_precond_kind is not None
            and _rhs1_residual_needs_rescue(
                float(res_reduced.residual_norm),
                float(target_reduced),
                force=bool(fp_force_strong),
            )
            and strong_precond_trigger
            and not early_dense_shortcut
        ):
            if (
                strong_precond_kind == "schur"
                and op.fblock.pas is not None
                and rhs1_precond_kind in {"pas_lite", "pas_hybrid", "pas_tz"}
                and np.isfinite(float(res_reduced.residual_norm))
            ):
                pas_schur_small_env = os.environ.get("SFINCS_JAX_PAS_SCHUR_SMALL_MAX", "").strip()
                try:
                    pas_schur_small_max = int(pas_schur_small_env) if pas_schur_small_env else 2000
                except ValueError:
                    pas_schur_small_max = 2000
                if int(active_size) > max(0, int(pas_schur_small_max)):
                    # Avoid expensive Schur builds when PAS-lite/hybrid is already active
                    # and the residual is finite; keep PAS-specific strong preconditioner instead.
                    strong_precond_kind = "pas_hybrid"
            _mark("rhs1_strong_precond_build_start")
            if emit is not None:
                emit(
                    0,
                    "solve_v3_full_system_linear_gmres: strong preconditioner fallback "
                    f"kind={strong_precond_kind} (residual={float(res_reduced.residual_norm):.3e} > target={target_reduced:.3e})",
                )

            if strong_precond_kind == "theta_line":
                strong_preconditioner_reduced = _build_rhsmode1_theta_line_preconditioner(
                    op=op, reduce_full=reduce_full, expand_reduced=expand_reduced
                )
            elif strong_precond_kind == "theta_schwarz":
                dd_block = _parse_rhs1_dd_block("theta")
                dd_overlap = _parse_rhs1_dd_overlap("theta", default=1)
                strong_preconditioner_reduced = _build_rhsmode1_theta_schwarz_preconditioner(
                    op=op,
                    block=dd_block,
                    overlap=dd_overlap,
                    reduce_full=reduce_full,
                    expand_reduced=expand_reduced,
                )
            elif strong_precond_kind == "theta_line_xdiag":
                strong_preconditioner_reduced = _build_rhsmode1_theta_line_xdiag_preconditioner(
                    op=op, reduce_full=reduce_full, expand_reduced=expand_reduced
                )
                if op.fblock.fp is not None or op.fblock.pas is not None:
                    collision_precond = _build_rhsmode1_collision_preconditioner(
                        op=op, reduce_full=reduce_full, expand_reduced=expand_reduced
                    )
                    strong_preconditioner_reduced = _compose_preconditioners(
                        collision_precond, strong_preconditioner_reduced
                    )
            elif strong_precond_kind == "species_block":
                strong_preconditioner_reduced = _build_rhsmode1_species_block_preconditioner(
                    op=op, reduce_full=reduce_full, expand_reduced=expand_reduced
                )
            elif strong_precond_kind == "sxblock":
                strong_preconditioner_reduced = _build_rhsmode1_species_xblock_preconditioner(
                    op=op, reduce_full=reduce_full, expand_reduced=expand_reduced
                )
            elif strong_precond_kind == "sxblock_tz":
                strong_preconditioner_reduced = _build_rhsmode1_sxblock_tz_preconditioner(
                    op=op, reduce_full=reduce_full, expand_reduced=expand_reduced
                )
            elif strong_precond_kind == "theta_zeta":
                strong_preconditioner_reduced = _build_rhsmode1_theta_zeta_preconditioner(
                    op=op, reduce_full=reduce_full, expand_reduced=expand_reduced
                )
            elif strong_precond_kind == "xmg":
                strong_preconditioner_reduced = _build_rhsmode1_xmg_preconditioner(
                    op=op, reduce_full=reduce_full, expand_reduced=expand_reduced
                )
            elif strong_precond_kind == "pas_lite":
                strong_preconditioner_reduced = _build_rhsmode1_pas_lite_preconditioner(
                    op=op, reduce_full=reduce_full, expand_reduced=expand_reduced
                )
            elif strong_precond_kind == "pas_hybrid":
                strong_preconditioner_reduced = _build_rhsmode1_pas_hybrid_preconditioner(
                    op=op, reduce_full=reduce_full, expand_reduced=expand_reduced
                )
            elif strong_precond_kind == "xblock_tz":
                strong_preconditioner_reduced = _build_rhsmode1_xblock_tz_preconditioner(
                    op=op, reduce_full=reduce_full, expand_reduced=expand_reduced
                )
            elif strong_precond_kind == "xblock_tz_lmax":
                lmax_use = strong_xblock_tz_lmax or 0
                if lmax_use <= 0:
                    lmax_env = os.environ.get("SFINCS_JAX_RHSMODE1_XBLOCK_TZ_LMAX", "").strip()
                    try:
                        lmax_use = int(lmax_env) if lmax_env else 0
                    except ValueError:
                        lmax_use = 0
                strong_preconditioner_reduced = _build_rhsmode1_xblock_tz_lmax_preconditioner(
                    op=op,
                    lmax=int(lmax_use),
                    reduce_full=reduce_full,
                    expand_reduced=expand_reduced,
                )
            elif strong_precond_kind == "zeta_line":
                strong_preconditioner_reduced = _build_rhsmode1_zeta_line_preconditioner(
                    op=op, reduce_full=reduce_full, expand_reduced=expand_reduced
                )
            elif strong_precond_kind == "zeta_schwarz":
                dd_block = _parse_rhs1_dd_block("zeta")
                dd_overlap = _parse_rhs1_dd_overlap("zeta", default=1)
                strong_preconditioner_reduced = _build_rhsmode1_zeta_schwarz_preconditioner(
                    op=op,
                    block=dd_block,
                    overlap=dd_overlap,
                    reduce_full=reduce_full,
                    expand_reduced=expand_reduced,
                )
            elif strong_precond_kind == "schur":
                strong_preconditioner_reduced = _build_rhsmode1_schur_preconditioner(
                    op=op, reduce_full=reduce_full, expand_reduced=expand_reduced
                )
            else:
                pre_theta = _build_rhsmode1_theta_line_preconditioner(
                    op=op, reduce_full=reduce_full, expand_reduced=expand_reduced
                )
                pre_zeta = _build_rhsmode1_zeta_line_preconditioner(
                    op=op, reduce_full=reduce_full, expand_reduced=expand_reduced
                )
                sweeps_env = os.environ.get("SFINCS_JAX_RHSMODE1_ADI_SWEEPS", "").strip()
                try:
                    sweeps = int(sweeps_env) if sweeps_env else 2
                except ValueError:
                    sweeps = 2
                sweeps = max(1, sweeps)

                def strong_preconditioner_reduced(v: jnp.ndarray) -> jnp.ndarray:
                    out = v
                    for _ in range(sweeps):
                        out = pre_zeta(pre_theta(out))
                    return out
            _mark("rhs1_strong_precond_build_done")
            if use_pas_projection:
                strong_preconditioner_reduced = _wrap_pas_precond(strong_preconditioner_reduced)

            strong_restart_env = os.environ.get("SFINCS_JAX_RHSMODE1_STRONG_PRECOND_RESTART", "").strip()
            strong_maxiter_env = os.environ.get("SFINCS_JAX_RHSMODE1_STRONG_PRECOND_MAXITER", "").strip()
            try:
                strong_restart = int(strong_restart_env) if strong_restart_env else max(120, int(restart))
            except ValueError:
                strong_restart = max(120, int(restart))
            try:
                strong_maxiter = int(strong_maxiter_env) if strong_maxiter_env else max(800, int(maxiter or 400) * 2)
            except ValueError:
                strong_maxiter = max(800, int(maxiter or 400) * 2)
            strong_timer = Timer()
            res_strong = _solve_linear(
                matvec_fn=mv_reduced,
                b_vec=rhs_reduced,
                precond_fn=strong_preconditioner_reduced,
                x0_vec=res_reduced.x,
                tol_val=tol,
                atol_val=atol,
                restart_val=strong_restart,
                maxiter_val=strong_maxiter,
                solve_method_val="incremental",
                precond_side=gmres_precond_side,
            )
            res_strong = _block_gmres_result_ready(res_strong)
            strong_elapsed_s = strong_timer.elapsed_s()
            res_reduced, residual_vec, handoff_state, _accepted = rhs1_accept_candidate(
                current_result=res_reduced,
                candidate_result=res_strong,
                current_residual_vec=residual_vec,
                candidate_residual_vec=residual_vec,
                matvec_fn=mv_reduced,
                b_vec=rhs_reduced,
                precond_fn=strong_preconditioner_reduced,
                x0_vec=res_strong.x,
                restart=strong_restart,
                maxiter=strong_maxiter,
                precond_side=gmres_precond_side,
                solver_kind=_solver_kind("incremental")[0],
                candidate_metrics=_rhs1_solver_candidate_metrics(
                    name="strong_reduced",
                    result=res_strong,
                    target_value=target_reduced,
                    solve_s=strong_elapsed_s,
                ),
                baseline_metrics=_rhs1_solver_candidate_metrics(
                    name="current_reduced",
                    result=res_reduced,
                    target_value=target_reduced,
                ),
            )
            _apply_rhs1_handoff(handoff_state)

        # Only treat the probe as a "dense shortcut" when the dense branch is
        # actually allowed (probe_shortcut). Otherwise we still want to try
        # stronger preconditioners (e.g. sparse ILU) before giving up.
        dense_shortcut = probe_shortcut
        if not dense_shortcut and dense_shortcut_ratio > 0:
            quick_ratio = float(res_reduced.residual_norm) / max(float(target_reduced), 1e-300)
            if quick_ratio >= dense_shortcut_ratio:
                dense_fallback_max = _rhsmode1_dense_fallback_max(op)
                dense_fallback_max_huge = 0
                dense_fallback_ratio = 1.0e2
                if dense_fallback_max > 0:
                    dense_fallback_max_huge_env = os.environ.get("SFINCS_JAX_RHSMODE1_DENSE_FALLBACK_MAX_HUGE", "").strip()
                    try:
                        dense_fallback_max_huge = int(dense_fallback_max_huge_env) if dense_fallback_max_huge_env else dense_fallback_max
                    except ValueError:
                        dense_fallback_max_huge = dense_fallback_max
                    dense_fallback_ratio_env = os.environ.get("SFINCS_JAX_RHSMODE1_DENSE_FALLBACK_RATIO", "").strip()
                    try:
                        dense_fallback_ratio = float(dense_fallback_ratio_env) if dense_fallback_ratio_env else 1.0e2
                    except ValueError:
                        dense_fallback_ratio = 1.0e2
                r_vec = rhs_reduced - mv_reduced(res_reduced.x)
                residual_norm_true = float(jnp.linalg.norm(r_vec))
                if not np.isfinite(residual_norm_true):
                    residual_norm_true = float("inf")
                res_ratio = float(residual_norm_true) / max(float(target_reduced), 1e-300)
                dense_fallback_limit = dense_fallback_max_huge if res_ratio > dense_fallback_ratio else dense_fallback_max
                force_dense_cs0 = bool(int(op.constraint_scheme) == 0 and (not cs0_sparse_first))
                if force_dense_cs0:
                    dense_fallback_limit = max(dense_fallback_limit, dense_fallback_max)
                dense_fallback_trigger = bool(res_ratio > dense_fallback_ratio) if dense_fallback_ratio > 0 else True
                if (
                    dense_fallback_limit > 0
                    and int(active_size) <= dense_fallback_limit
                    and dense_fallback_trigger
                    and (float(residual_norm_true) > target_reduced or force_dense_cs0)
                    and res_ratio >= dense_shortcut_ratio
                ):
                    if sparse_prefer_over_dense_shortcut and (not sparse_exact_direct):
                        if emit is not None:
                            emit(
                                1,
                                "solve_v3_full_system_linear_gmres: dense shortcut skipped "
                                "(preferring sparse rescue over dense shortcut)",
                            )
                    else:
                        dense_shortcut = True
                        if emit is not None:
                            emit(
                                0,
                                "solve_v3_full_system_linear_gmres: dense fallback shortcut "
                                f"(ratio={res_ratio:.3e} >= {dense_shortcut_ratio:.1e})",
                            )

        sparse_enabled = rhs1_sparse_enabled_initial(
            sparse_precond_mode=sparse_precond_mode,
            has_fp=op.fblock.fp is not None,
            has_pas=op.fblock.pas is not None,
            residual_norm=float(res_reduced.residual_norm),
            target=float(target_reduced),
            rhs_mode=int(op.rhs_mode),
            include_phi1=bool(op.include_phi1),
        )
        sparse_kind_use = rhs1_sparse_kind_use(sparse_precond_kind=sparse_precond_kind)
        sparse_jax_est_mb: float | None = None
        if sparse_enabled and sparse_kind_use == "jax" and int(active_size) <= int(sparse_max_size):
            precond_dtype = _precond_dtype(int(active_size))
            bytes_per = 4.0 if precond_dtype == jnp.float32 else 8.0
            sparse_jax_est_mb = (int(active_size) ** 2) * bytes_per / 1.0e6
        sparse_order = rhs1_resolved_sparse_rescue_ordering(
            sparse_enabled=bool(sparse_enabled),
            sparse_kind_use=sparse_kind_use,
            dense_shortcut=bool(dense_shortcut),
            sparse_exact_direct=bool(sparse_exact_direct),
            size=int(active_size),
            sparse_max_size=int(sparse_max_size),
            large_cpu_sparse_rescue=bool(large_cpu_sparse_rescue_active),
            sparse_xblock_rescue_active=bool(sparse_xblock_rescue_active),
            sparse_sxblock_rescue_active=bool(sparse_sxblock_rescue_active),
            sparse_jax_est_mb=sparse_jax_est_mb,
            sparse_jax_max_mb=float(sparse_jax_max_mb),
            pas_fast_accept=bool(pas_fast_accept),
            gpu_sparse_skip=bool(
                _rhs1_gpu_sparse_fallback_skip_allowed(
                    op=op,
                    rhs1_precond_kind=rhs1_precond_kind,
                    use_active_dof_mode=True,
                    residual_norm=float(res_reduced.residual_norm),
                    target=float(target_reduced),
                )
            ),
        )
        sparse_enabled = bool(sparse_order.enabled)
        sparse_kind_use = str(sparse_order.kind_use)
        sparse_xblock_rescue_active = bool(sparse_order.xblock_rescue_active)
        sparse_sxblock_rescue_active = bool(sparse_order.sxblock_rescue_active)
        if sparse_order.prefer_sparse_exact_over_dense_shortcut and emit is not None:
            emit(
                0,
                "solve_v3_full_system_linear_gmres: preferring sparse exact rescue over dense shortcut",
            )
        if sparse_order.reason_size_large_cpu:
            sparse_exact_lu = _rhsmode1_large_cpu_sparse_exact_lu_allowed(active_size=int(active_size))
            if emit is not None:
                backend_name = str(jax.default_backend()).strip().lower()
                sparse_label = "large CPU sparse" if backend_name == "cpu" else f"{backend_name} host-sparse"
                emit(
                    0,
                    f"solve_v3_full_system_linear_gmres: {sparse_label} {'LU' if sparse_exact_lu else 'ILU'} rescue "
                    f"(size={int(active_size)} > max={int(sparse_max_size)})",
                )
        elif sparse_order.reason_size_exact_direct and emit is not None:
            emit(
                0,
                "solve_v3_full_system_linear_gmres: exact sparse LU rescue "
                f"(size={int(active_size)} > max={int(sparse_max_size)})",
            )
        elif sparse_order.reason_size_targeted and emit is not None:
            rescue_kind = "xblock" if sparse_xblock_rescue_active else "sxblock"
            emit(
                0,
                "solve_v3_full_system_linear_gmres: targeted sparse "
                f"{rescue_kind} rescue (size={int(active_size)} > max={int(sparse_max_size)})",
            )
        elif sparse_order.reason_size_disabled and emit is not None:
            emit(1, f"sparse_ilu: disabled (size={int(active_size)} > max={int(sparse_max_size)})")
        if sparse_order.reason_sparse_jax_mem_disabled and sparse_jax_est_mb is not None and emit is not None:
            emit(
                1,
                "sparse_jax: disabled "
                f"(est_mem={sparse_jax_est_mb:.1f} MB > max_mb={sparse_jax_max_mb:.1f})",
            )

        host_sparse_direct_used = False
        precond_sparse_xblock_current = None
        explicit_fp_xblock_seed_used = False
        explicit_fp_xblock_seed_residual = float("inf")
        explicit_fp_xblock_seed_improvement_ratio = 1.0
        if sparse_order.reason_large_cpu_exact_skips_targeted:
            if emit is not None:
                emit(
                    1,
                    "solve_v3_full_system_linear_gmres: exact large-CPU sparse LU selected "
                    "-> skipping targeted sparse xblock/sxblock rescue",
                )
        if sparse_order.reason_pas_fast_accept and emit is not None:
            emit(
                1,
                "solve_v3_full_system_linear_gmres: PAS fast-accept "
                f"(residual={float(res_reduced.residual_norm):.3e}) -> skip sparse rescue tail",
            )
        if sparse_order.reason_gpu_sparse_skip and emit is not None:
            emit(
                1,
                "solve_v3_full_system_linear_gmres: GPU sparse fallback skipped after "
                f"{rhs1_precond_kind} accept (residual={float(res_reduced.residual_norm):.3e})",
            )
        if sparse_enabled and float(res_reduced.residual_norm) > target_reduced:
            if sparse_xblock_rescue_active:
                try:
                    if emit is not None:
                        emit(
                            0,
                            "solve_v3_full_system_linear_gmres: v3-like sparse x-block rescue "
                            f"(size={int(active_size)} preconditioner_x={int(preconditioner_x)})",
                        )
                    sparse_xblock_preconditioner_xi = int(preconditioner_xi)
                    if (
                        sparse_xblock_preconditioner_xi == 0
                        and (not bool(use_implicit))
                        and op.fblock.fp is not None
                        and op.fblock.pas is None
                    ):
                        sparse_xblock_preconditioner_xi = 1
                        if emit is not None:
                            emit(
                                1,
                                "solve_v3_full_system_linear_gmres: promoting sparse x-block rescue "
                                "preconditioner_xi 0 -> 1 for stronger host FP factorization",
                            )
                    assembled_host_fp = _rhsmode1_fp_xblock_assembled_host_allowed(
                        op=op,
                        preconditioner_species=preconditioner_species,
                        preconditioner_xi=sparse_xblock_preconditioner_xi,
                        use_implicit=bool(use_implicit),
                        active_size=int(active_size),
                    )
                    _mark("rhs1_sparse_precond_build_start")
                    precond_sparse_xblock = _build_rhsmode1_xblock_tz_sparse_preconditioner(
                        op=op,
                        reduce_full=reduce_full,
                        expand_reduced=expand_reduced,
                        build_jax_factors=bool(use_implicit),
                        preconditioner_species=preconditioner_species,
                        preconditioner_xi=sparse_xblock_preconditioner_xi,
                        drop_tol=sparse_drop_tol,
                        drop_rel=sparse_drop_rel,
                        ilu_drop_tol=sparse_ilu_drop_tol,
                        fill_factor=sparse_ilu_fill,
                        force_assembled_host_fp=bool(assembled_host_fp),
                        emit=emit,
                    )
                    precond_sparse_xblock_current = precond_sparse_xblock
                    _mark("rhs1_sparse_precond_build_done")
                    _mark("rhs1_sparse_precond_solve_start")
                    if use_implicit:
                        res_sparse_xblock = _solve_linear(
                            matvec_fn=mv_reduced,
                            b_vec=rhs_reduced,
                            precond_fn=precond_sparse_xblock,
                            x0_vec=res_reduced.x,
                            tol_val=tol,
                            atol_val=atol,
                            restart_val=restart,
                            maxiter_val=maxiter,
                            solve_method_val="incremental",
                            precond_side=gmres_precond_side,
                        )
                    else:
                        res_sparse_xblock = None
                        if assembled_host_fp:
                            refine_env = os.environ.get("SFINCS_JAX_RHSMODE1_FP_XBLOCK_REFINES", "").strip()
                            try:
                                refine_steps = int(refine_env) if refine_env else 2
                            except ValueError:
                                refine_steps = 2
                            refine_steps = max(0, int(refine_steps))
                            accept_ratio = rhs1_parse_accept_ratio(
                                env_name="SFINCS_JAX_RHSMODE1_FP_XBLOCK_ACCEPT_RATIO",
                                default=10.0,
                            )
                            polish_enabled = rhs1_polish_enabled(
                                env_name="SFINCS_JAX_RHSMODE1_FP_XBLOCK_POLISH",
                            )
                            polish_restart, polish_maxiter = rhs1_parse_polish_gmres_config(
                                restart_env_name="SFINCS_JAX_RHSMODE1_FP_XBLOCK_POLISH_RESTART",
                                maxiter_env_name="SFINCS_JAX_RHSMODE1_FP_XBLOCK_POLISH_MAXITER",
                                default_restart=min(int(restart), 40),
                                default_maxiter=min(int(maxiter or 80), 80),
                            )
                            base_residual_norm = float(res_reduced.residual_norm)
                            x_trial = jnp.asarray(precond_sparse_xblock(rhs_reduced), dtype=jnp.float64)
                            residual_vec_sparse_xblock = rhs_reduced - mv_reduced(x_trial)
                            residual_norm_sparse_xblock = float(jnp.linalg.norm(residual_vec_sparse_xblock))
                            explicit_fp_xblock_seed_residual = float(residual_norm_sparse_xblock)
                            if np.isfinite(residual_norm_sparse_xblock) and residual_norm_sparse_xblock > 0.0:
                                explicit_fp_xblock_seed_improvement_ratio = float(base_residual_norm) / float(
                                    residual_norm_sparse_xblock
                                )
                            elif np.isfinite(residual_norm_sparse_xblock):
                                explicit_fp_xblock_seed_improvement_ratio = float("inf")
                            if emit is not None:
                                emit(
                                    0,
                                    "solve_v3_full_system_linear_gmres: explicit FP x-block seed "
                                    f"(residual={residual_norm_sparse_xblock:.6e} current={base_residual_norm:.6e})",
                                )
                            for _ in range(refine_steps):
                                if not np.isfinite(residual_norm_sparse_xblock) or residual_norm_sparse_xblock == 0.0:
                                    break
                                dx_trial = jnp.asarray(precond_sparse_xblock(residual_vec_sparse_xblock), dtype=jnp.float64)
                                x_next = x_trial + dx_trial
                                residual_vec_next = rhs_reduced - mv_reduced(x_next)
                                residual_norm_next = float(jnp.linalg.norm(residual_vec_next))
                                if not np.isfinite(residual_norm_next) or residual_norm_next >= residual_norm_sparse_xblock:
                                    break
                                x_trial = x_next
                                residual_vec_sparse_xblock = residual_vec_next
                                residual_norm_sparse_xblock = residual_norm_next
                            if (
                                np.isfinite(residual_norm_sparse_xblock)
                                and residual_norm_sparse_xblock <= max(float(target_reduced), base_residual_norm * accept_ratio)
                            ):
                                if polish_enabled and residual_norm_sparse_xblock > float(target_reduced):
                                    polish_precond = precond_sparse_xblock if precond_sparse_xblock is not None else ksp_precond
                                    x_np, _rn_sparse_xblock, _history = gmres_solve_with_history_scipy(
                                        matvec=mv_reduced,
                                        b=rhs_reduced,
                                        preconditioner=polish_precond,
                                        x0=x_trial,
                                        tol=tol,
                                        atol=atol,
                                        restart=polish_restart,
                                        maxiter=polish_maxiter,
                                        precondition_side=gmres_precond_side,
                                    )
                                    x_polish = jnp.asarray(x_np, dtype=jnp.float64)
                                    residual_vec_polish = rhs_reduced - mv_reduced(x_polish)
                                    residual_norm_polish = float(jnp.linalg.norm(residual_vec_polish))
                                    if np.isfinite(residual_norm_polish) and residual_norm_polish < residual_norm_sparse_xblock:
                                        x_trial = x_polish
                                        residual_norm_sparse_xblock = residual_norm_polish
                                res_sparse_xblock = GMRESSolveResult(
                                    x=x_trial,
                                    residual_norm=jnp.asarray(residual_norm_sparse_xblock, dtype=jnp.float64),
                                )
                            elif emit is not None:
                                emit(
                                    0,
                                    "solve_v3_full_system_linear_gmres: explicit FP x-block seed rejected "
                                    f"(residual={residual_norm_sparse_xblock:.6e}, base={base_residual_norm:.6e}, "
                                    f"accept_ratio={accept_ratio:.1e})",
                                )
                        else:
                            x_np, _rn_sparse_xblock, _history = gmres_solve_with_history_scipy(
                                matvec=mv_reduced,
                                b=rhs_reduced,
                                preconditioner=precond_sparse_xblock,
                                x0=res_reduced.x,
                                tol=tol,
                                atol=atol,
                                restart=restart,
                                maxiter=maxiter,
                                precondition_side=gmres_precond_side,
                            )
                            x_sparse_xblock = jnp.asarray(x_np, dtype=jnp.float64)
                            residual_vec_sparse_xblock = rhs_reduced - mv_reduced(x_sparse_xblock)
                            res_sparse_xblock = GMRESSolveResult(
                                x=x_sparse_xblock,
                                residual_norm=jnp.asarray(jnp.linalg.norm(residual_vec_sparse_xblock), dtype=jnp.float64),
                            )
                    _mark("rhs1_sparse_precond_solve_done")
                    if res_sparse_xblock is not None and float(res_sparse_xblock.residual_norm) < float(res_reduced.residual_norm):
                        res_reduced = res_sparse_xblock
                        explicit_fp_xblock_seed_used = bool(assembled_host_fp and (not bool(use_implicit)))
                        if assembled_host_fp:
                            ksp_x0 = res_reduced.x
                        else:
                            ksp_matvec = mv_reduced
                            ksp_b = rhs_reduced
                            ksp_precond = precond_sparse_xblock
                            ksp_x0 = res_reduced.x
                            ksp_restart = restart
                            ksp_maxiter = maxiter
                            ksp_precond_side = gmres_precond_side
                            ksp_solver_kind = _solver_kind("incremental")[0]
                except Exception as exc:  # noqa: BLE001
                    if emit is not None:
                        emit(1, f"xblock_sparse: failed ({type(exc).__name__}: {exc})")
            skip_global_sparse_after_xblock = _rhsmode1_skip_global_sparse_after_xblock_allowed(
                op=op,
                active_size=int(active_size),
                residual_norm=float(res_reduced.residual_norm),
                target=float(target_reduced),
                used_large_cpu_xblock_shortcut=bool(cpu_large_xblock_shortcut),
                used_explicit_fp_xblock_seed=bool(explicit_fp_xblock_seed_used),
                use_implicit=bool(use_implicit),
                )
            if (
                large_cpu_sparse_rescue_active
                and (not sparse_exact_lu)
                and _rhsmode1_large_cpu_sparse_exact_lu_xblock_allowed(
                    op=op,
                    active_size=int(active_size),
                    preconditioner_x=int(preconditioner_x),
                    used_large_cpu_xblock_shortcut=bool(cpu_large_xblock_shortcut),
                    used_explicit_fp_xblock_seed=bool(explicit_fp_xblock_seed_used),
                    xblock_seed_residual=float(explicit_fp_xblock_seed_residual),
                    xblock_seed_improvement_ratio=float(explicit_fp_xblock_seed_improvement_ratio),
                    use_implicit=bool(use_implicit),
                )
            ):
                sparse_exact_lu = True
                if emit is not None:
                    emit(
                        1,
                        "solve_v3_full_system_linear_gmres: promoting large CPU sparse rescue to exact LU "
                        f"after x-block seed (residual={float(explicit_fp_xblock_seed_residual):.3e} "
                        f"improvement={float(explicit_fp_xblock_seed_improvement_ratio):.1f}x)",
                    )
            if skip_global_sparse_after_xblock and emit is not None:
                emit(
                    1,
                    "solve_v3_full_system_linear_gmres: skipping global sparse rescue after x-block seed "
                    f"(residual={float(res_reduced.residual_norm):.3e})",
                )
            if (
                float(res_reduced.residual_norm) > target_reduced
                and sparse_sxblock_rescue_active
                and (not skip_global_sparse_after_xblock)
            ):
                try:
                    if emit is not None:
                        emit(
                            0,
                            "solve_v3_full_system_linear_gmres: sparse sxblock_tz rescue "
                            f"(size={int(active_size)} n_species={int(op.n_species)})",
                        )
                    _mark("rhs1_sparse_precond_build_start")
                    x_sparse_sxblock = _compute_rhsmode1_sxblock_tz_sparse_host_seed(
                        op=op,
                        rhs_reduced=rhs_reduced,
                        reduce_full=reduce_full,
                        expand_reduced=expand_reduced,
                        drop_tol=sparse_drop_tol,
                        drop_rel=sparse_drop_rel,
                        ilu_drop_tol=sparse_ilu_drop_tol,
                        fill_factor=sparse_ilu_fill,
                        emit=emit,
                    )
                    _mark("rhs1_sparse_precond_build_done")
                    _mark("rhs1_sparse_precond_solve_start")
                    residual_vec_sparse_sxblock = rhs_reduced - mv_reduced(x_sparse_sxblock)
                    res_sparse_sxblock = GMRESSolveResult(
                        x=x_sparse_sxblock,
                        residual_norm=jnp.asarray(jnp.linalg.norm(residual_vec_sparse_sxblock), dtype=jnp.float64),
                    )
                    if emit is not None:
                        emit(
                            0,
                            "solve_v3_full_system_linear_gmres: explicit sxblock seed "
                            f"(residual={float(res_sparse_sxblock.residual_norm):.6e})",
                        )
                    _mark("rhs1_sparse_precond_solve_done")
                    if float(res_sparse_sxblock.residual_norm) < float(res_reduced.residual_norm):
                        res_reduced = res_sparse_sxblock
                        ksp_x0 = res_reduced.x
                        if float(res_reduced.residual_norm) > target_reduced:
                            polish_precond = precond_sparse_xblock_current or preconditioner_reduced
                            if polish_precond is not None:
                                sxblock_polish_restart, sxblock_polish_maxiter = rhs1_parse_polish_gmres_config(
                                    restart_env_name="SFINCS_JAX_RHSMODE1_SXBLOCK_POLISH_RESTART",
                                    maxiter_env_name="SFINCS_JAX_RHSMODE1_SXBLOCK_POLISH_MAXITER",
                                    default_restart=min(int(restart), 40),
                                    default_maxiter=min(max(40, int(maxiter or 120)), 120),
                                )
                                if emit is not None:
                                    emit(
                                        0,
                                        "solve_v3_full_system_linear_gmres: sxblock seed polish "
                                        f"restart={sxblock_polish_restart} maxiter={sxblock_polish_maxiter}",
                                    )
                                x_np, _rn_sxpolish, _history = gmres_solve_with_history_scipy(
                                    matvec=mv_reduced,
                                    b=rhs_reduced,
                                    preconditioner=polish_precond,
                                    x0=res_reduced.x,
                                    tol=tol,
                                    atol=atol,
                                    restart=sxblock_polish_restart,
                                    maxiter=sxblock_polish_maxiter,
                                    precondition_side=gmres_precond_side,
                                )
                                x_sxpolish = jnp.asarray(x_np, dtype=jnp.float64)
                                residual_vec_sxpolish = rhs_reduced - mv_reduced(x_sxpolish)
                                res_sxpolish = GMRESSolveResult(
                                    x=x_sxpolish,
                                    residual_norm=jnp.asarray(jnp.linalg.norm(residual_vec_sxpolish), dtype=jnp.float64),
                                )
                                if float(res_sxpolish.residual_norm) < float(res_reduced.residual_norm):
                                    res_reduced = res_sxpolish
                                    ksp_matvec = mv_reduced
                                    ksp_b = rhs_reduced
                                    ksp_precond = polish_precond
                                    ksp_x0 = res_reduced.x
                                    ksp_restart = sxblock_polish_restart
                                    ksp_maxiter = sxblock_polish_maxiter
                                    ksp_precond_side = gmres_precond_side
                                    ksp_solver_kind = _solver_kind("incremental")[0]
                except Exception as exc:  # noqa: BLE001
                    if emit is not None:
                        emit(1, f"sxblock_sparse: failed ({type(exc).__name__}: {exc})")
            if (
                float(res_reduced.residual_norm) > target_reduced
                and sparse_kind_use == "jax"
                and (not skip_global_sparse_after_xblock)
            ):
                try:
                    _mark("rhs1_sparse_precond_build_start")
                    cache_key = _rhsmode1_sparse_cache_key(
                        op,
                        kind="sparse_jax",
                        active_size=int(active_size),
                        use_active_dof_mode=True,
                        use_pas_projection=use_pas_projection,
                        drop_tol=sparse_drop_tol,
                        drop_rel=sparse_drop_rel,
                        ilu_drop_tol=sparse_ilu_drop_tol,
                        fill_factor=sparse_ilu_fill,
                    )
                    precond_dtype = _precond_dtype(int(active_size))
                    precond_sparse = _build_sparse_jax_preconditioner_from_matvec(
                        matvec=mv_reduced,
                        n=int(active_size),
                        dtype=precond_dtype,
                        cache_key=cache_key,
                        drop_tol=sparse_drop_tol,
                        drop_rel=sparse_drop_rel,
                        reg=sparse_jax_reg,
                        omega=sparse_jax_omega,
                        sweeps=sparse_jax_sweeps,
                        emit=emit,
                    )
                    _mark("rhs1_sparse_precond_build_done")
                    if emit is not None:
                        emit(
                            0,
                            "solve_v3_full_system_linear_gmres: sparse JAX Jacobi fallback "
                            f"(sweeps={int(sparse_jax_sweeps)} omega={float(sparse_jax_omega):.2f})",
                        )
                    sparse_retry_timer = Timer()
                    res_sparse = _solve_linear(
                        matvec_fn=mv_reduced,
                        b_vec=rhs_reduced,
                        precond_fn=precond_sparse,
                        x0_vec=res_reduced.x,
                        tol_val=tol,
                        atol_val=atol,
                        restart_val=restart,
                        maxiter_val=maxiter,
                        solve_method_val="incremental",
                        precond_side=gmres_precond_side,
                    )
                    sparse_retry_elapsed_s = sparse_retry_timer.elapsed_s()
                    if res_sparse is not None:
                        res_reduced, residual_vec, handoff_state, _accepted = rhs1_accept_candidate(
                            current_result=res_reduced,
                            candidate_result=res_sparse,
                            current_residual_vec=residual_vec,
                            candidate_residual_vec=None,
                            matvec_fn=mv_reduced,
                            b_vec=rhs_reduced,
                            precond_fn=precond_sparse,
                            x0_vec=res_sparse.x,
                            restart=restart,
                            maxiter=maxiter,
                            precond_side=gmres_precond_side,
                            solver_kind=_solver_kind("incremental")[0],
                            candidate_metrics=_rhs1_solver_candidate_metrics(
                                name="sparse_jax_reduced",
                                result=res_sparse,
                                target_value=target_reduced,
                                solve_s=sparse_retry_elapsed_s,
                            ),
                            baseline_metrics=_rhs1_solver_candidate_metrics(
                                name="current_reduced",
                                result=res_reduced,
                                target_value=target_reduced,
                            ),
                        )
                        _apply_rhs1_handoff(handoff_state)
                except Exception as exc:  # noqa: BLE001
                    if emit is not None:
                        emit(1, f"sparse_jax: failed ({type(exc).__name__}: {exc})")
            elif float(res_reduced.residual_norm) > target_reduced and (not skip_global_sparse_after_xblock):
                try:
                    _mark("rhs1_sparse_precond_build_start")
                    cache_key = _rhsmode1_sparse_cache_key(
                        op,
                        kind="sparse_lu" if sparse_exact_lu else "sparse_ilu",
                        active_size=int(active_size),
                        use_active_dof_mode=True,
                        use_pas_projection=use_pas_projection,
                        drop_tol=sparse_drop_tol,
                        drop_rel=sparse_drop_rel,
                        ilu_drop_tol=sparse_ilu_drop_tol,
                        fill_factor=sparse_ilu_fill,
                    )
                    host_sparse_direct_wanted = _rhsmode1_host_sparse_direct_allowed(
                        sparse_exact_lu=sparse_exact_lu,
                        use_implicit=bool(use_implicit),
                    )
                    if large_cpu_sparse_rescue_active and sparse_exact_lu:
                        host_sparse_direct_wanted = True
                    factor_dtype = _host_sparse_factor_dtype(
                        size=int(active_size),
                        factorization="lu" if sparse_exact_lu else "ilu",
                        use_implicit=bool(use_implicit),
                    ) if host_sparse_direct_wanted else np.dtype(np.float64)
                    cache_key_use = (
                        _sparse_factor_cache_key(cache_key, factor_dtype)
                        if host_sparse_direct_wanted
                        else cache_key
                    )
                    build_dense_factors = (
                        bool(use_implicit)
                        and (not host_sparse_direct_wanted)
                        and int(active_size) <= int(sparse_ilu_dense_max)
                    )
                    store_dense = int(active_size) <= int(sparse_dense_cache_max)
                    explicit_sparse_operator = None
                    explicit_sparse_factor = None
                    if host_sparse_direct_wanted and _rhsmode1_explicit_sparse_host_direct_allowed(
                        sparse_exact_lu=sparse_exact_lu,
                        use_implicit=bool(use_implicit),
                        active_size=int(active_size),
                    ):
                        explicit_sparse_operator, explicit_sparse_factor = _build_host_sparse_direct_factor_from_matvec(
                            matvec=mv_reduced,
                            n=int(active_size),
                            dtype=rhs_reduced.dtype,
                            factor_dtype=factor_dtype,
                            emit=emit,
                        )
                        a_csr_full = explicit_sparse_operator.matrix
                        _a_csr_drop = a_csr_full
                        ilu = explicit_sparse_factor.factor
                        a_dense_cache = None
                        l_dense = None
                        u_dense = None
                        l_unit_diag = False
                    else:
                        a_csr_full, _a_csr_drop, ilu, a_dense_cache, l_dense, u_dense, l_unit_diag = _build_sparse_ilu_from_matvec(
                            matvec=mv_reduced,
                            n=int(active_size),
                            dtype=rhs_reduced.dtype,
                            cache_key=cache_key_use,
                            factor_dtype=factor_dtype,
                            drop_tol=sparse_drop_tol,
                            drop_rel=sparse_drop_rel,
                            ilu_drop_tol=sparse_ilu_drop_tol,
                            fill_factor=sparse_ilu_fill,
                            build_dense_factors=build_dense_factors,
                            build_jax_factors=bool(use_implicit) and (not host_sparse_direct_wanted),
                            build_ilu=True,
                            store_dense=store_dense,
                            factorization="lu" if sparse_exact_lu else "ilu",
                            emit=emit,
                        )
                    dense_matrix_cache = a_dense_cache
                    _mark("rhs1_sparse_precond_build_done")
                    host_sparse_direct = host_sparse_direct_wanted
                    sparse_retry_timer = Timer()

                    if host_sparse_direct and ilu is not None:
                        host_sparse_direct_used = True
                        if emit is not None:
                            emit(
                                0,
                                "solve_v3_full_system_linear_gmres: host sparse LU direct fallback "
                                f"on backend={jax.default_backend()}",
                            )
                        if explicit_sparse_factor is not None and explicit_sparse_operator is not None:
                            x_np, residual_norm_sparse = _host_direct_solve_with_refinement(
                                factor_solve=explicit_sparse_factor.solve,
                                operator_matrix=explicit_sparse_operator.matrix,
                                rhs_vec=rhs_reduced,
                                factor_dtype=factor_dtype,
                                refine_steps=_host_sparse_direct_refine_steps(
                                    "SFINCS_JAX_RHSMODE1_SPARSE_DIRECT_REFINE",
                                    default=2,
                                ),
                            )
                        else:
                            x_np, residual_norm_sparse = _host_sparse_direct_solve_with_refinement(
                                ilu=ilu,
                                a_csr_full=a_csr_full,
                                rhs_vec=rhs_reduced,
                                factor_dtype=factor_dtype,
                                refine_steps=_host_sparse_direct_refine_steps(
                                    "SFINCS_JAX_RHSMODE1_SPARSE_DIRECT_REFINE",
                                    default=2,
                                ),
                            )
                        res_sparse = GMRESSolveResult(
                            x=jnp.asarray(x_np, dtype=jnp.float64),
                            residual_norm=jnp.asarray(residual_norm_sparse, dtype=jnp.float64),
                        )
                        if factor_dtype == np.dtype(np.float32) and float(res_sparse.residual_norm) > float(target_reduced):
                            if rhs1_polish_enabled(env_name="SFINCS_JAX_RHSMODE1_SPARSE_DIRECT_POLISH"):
                                polish_restart, polish_maxiter = rhs1_parse_polish_gmres_config(
                                    restart_env_name="SFINCS_JAX_RHSMODE1_SPARSE_DIRECT_POLISH_RESTART",
                                    maxiter_env_name="SFINCS_JAX_RHSMODE1_SPARSE_DIRECT_POLISH_MAXITER",
                                    default_restart=min(int(restart), 40),
                                    default_maxiter=min(max(40, int(maxiter or 120)), 120),
                                )
                                if emit is not None:
                                    emit(
                                        0,
                                        "solve_v3_full_system_linear_gmres: host sparse direct polish "
                                        f"restart={polish_restart} maxiter={polish_maxiter}",
                                    )
                                x_polish, residual_norm_polish = _host_sparse_direct_polish(
                                    matvec_fn=mv_reduced,
                                    rhs_vec=rhs_reduced,
                                    x0_np=x_np,
                                    ilu=ilu,
                                    factor_dtype=factor_dtype,
                                    tol=tol,
                                    atol=atol,
                                    restart=polish_restart,
                                    maxiter=polish_maxiter,
                                    precondition_side=gmres_precond_side,
                                )
                                if np.isfinite(residual_norm_polish) and residual_norm_polish < float(res_sparse.residual_norm):
                                    res_sparse = GMRESSolveResult(
                                        x=jnp.asarray(x_polish, dtype=jnp.float64),
                                        residual_norm=jnp.asarray(residual_norm_polish, dtype=jnp.float64),
                                    )
                        residual_vec_sparse = rhs_reduced - mv_reduced(res_sparse.x)
                        _mv_sparse = mv_reduced
                        _precond_sparse = None
                    elif use_implicit:
                        ilu_cache = _RHSMODE1_SPARSE_ILU_CACHE.get(cache_key)
                        perm_r = None if ilu_cache is None else ilu_cache.perm_r
                        inv_perm_c = None if ilu_cache is None else ilu_cache.inv_perm_c
                        lower_idx = None if ilu_cache is None else ilu_cache.lower_idx
                        lower_val = None if ilu_cache is None else ilu_cache.lower_val
                        lower_diag = None if ilu_cache is None else ilu_cache.lower_diag
                        upper_idx = None if ilu_cache is None else ilu_cache.upper_idx
                        upper_val = None if ilu_cache is None else ilu_cache.upper_val
                        upper_diag = None if ilu_cache is None else ilu_cache.upper_diag

                        precond_sparse = None
                        # Prefer dense triangular solves for small systems if available.
                        if (
                            l_dense is not None
                            and u_dense is not None
                            and perm_r is not None
                            and inv_perm_c is not None
                        ):
                            import jax.scipy.linalg as jla  # noqa: PLC0415

                            l_jnp = jnp.asarray(l_dense, dtype=jnp.float64)
                            u_jnp = jnp.asarray(u_dense, dtype=jnp.float64)

                            def _precond_sparse(v: jnp.ndarray) -> jnp.ndarray:
                                v = jnp.asarray(v, dtype=jnp.float64)
                                v_perm = v[perm_r]
                                y = jla.solve_triangular(l_jnp, v_perm, lower=True, unit_diagonal=l_unit_diag)
                                z = jla.solve_triangular(u_jnp, y, lower=False)
                                return z[inv_perm_c]

                            precond_sparse = _precond_sparse
                        elif (
                            perm_r is not None
                            and inv_perm_c is not None
                            and lower_idx is not None
                            and lower_val is not None
                            and upper_idx is not None
                            and upper_val is not None
                            and upper_diag is not None
                        ):
                            def _precond_sparse(v: jnp.ndarray) -> jnp.ndarray:
                                v = jnp.asarray(v, dtype=jnp.float64)
                                v_perm = v[perm_r]
                                y = _triangular_solve_lower_padded(
                                    lower_idx=lower_idx,
                                    lower_val=lower_val,
                                    b=v_perm,
                                )
                                z = _triangular_solve_upper_padded(
                                    upper_idx=upper_idx,
                                    upper_val=upper_val,
                                    upper_diag=upper_diag,
                                    b=y,
                                )
                                return z[inv_perm_c]

                            precond_sparse = _precond_sparse

                        if precond_sparse is None:
                            if emit is not None:
                                emit(
                                    1,
                                    f"{'sparse_lu' if sparse_exact_lu else 'sparse_ilu'}: "
                                    "implicit preconditioner factors unavailable; skipping",
                                )
                            res_sparse = None
                        else:
                            if emit is not None:
                                emit(
                                    0,
                                    "solve_v3_full_system_linear_gmres: "
                                    f"{'sparse LU' if sparse_exact_lu else 'sparse ILU'} (implicit) fallback",
                                )
                            res_sparse = _solve_linear(
                                matvec_fn=mv_reduced,
                                b_vec=rhs_reduced,
                                precond_fn=precond_sparse,
                                x0_vec=res_reduced.x,
                                tol_val=tol,
                                atol_val=atol,
                                restart_val=restart,
                                maxiter_val=maxiter,
                                solve_method_val="incremental",
                                precond_side=gmres_precond_side,
                            )
                    else:
                        if ilu is None:
                            raise RuntimeError("sparse_ilu: ILU factors unavailable")

                        def _precond_sparse(v: jnp.ndarray) -> jnp.ndarray:
                            x_np = np.asarray(v, dtype=np.float64).reshape((-1,))
                            y_np = ilu.solve(x_np)
                            return jnp.asarray(y_np, dtype=jnp.float64)

                        if sparse_use_matvec:
                            def _mv_sparse(v: jnp.ndarray) -> jnp.ndarray:
                                x_np = np.asarray(v, dtype=np.float64).reshape((-1,))
                                y_np = a_csr_full @ x_np
                                return jnp.asarray(y_np, dtype=jnp.float64)
                        else:
                            _mv_sparse = mv_reduced

                        if emit is not None:
                            emit(
                                0,
                                "solve_v3_full_system_linear_gmres: "
                                f"{'sparse LU' if sparse_exact_lu else 'sparse ILU'} GMRES fallback",
                            )
                        x_np, rn_sparse, _history = gmres_solve_with_history_scipy(
                            matvec=_mv_sparse,
                            b=rhs_reduced,
                            preconditioner=_precond_sparse,
                            x0=res_reduced.x,
                            tol=tol,
                            atol=atol,
                            restart=restart,
                            maxiter=maxiter,
                            precondition_side=gmres_precond_side,
                        )
                        res_sparse = GMRESSolveResult(
                            x=jnp.asarray(x_np, dtype=jnp.float64),
                            residual_norm=jnp.asarray(rn_sparse, dtype=jnp.float64),
                        )
                    if res_sparse is not None:
                        sparse_retry_elapsed_s = sparse_retry_timer.elapsed_s()
                        res_reduced, residual_vec, handoff_state, _accepted = rhs1_accept_candidate(
                            current_result=res_reduced,
                            candidate_result=res_sparse,
                            current_residual_vec=residual_vec,
                            candidate_residual_vec=None,
                            matvec_fn=mv_reduced if use_implicit else _mv_sparse,
                            b_vec=rhs_reduced,
                            precond_fn=_precond_sparse,
                            x0_vec=res_sparse.x,
                            restart=restart,
                            maxiter=maxiter,
                            precond_side=gmres_precond_side,
                            solver_kind=_solver_kind("incremental")[0],
                            candidate_metrics=_rhs1_solver_candidate_metrics(
                                name="sparse_reduced",
                                result=res_sparse,
                                target_value=target_reduced,
                                solve_s=sparse_retry_elapsed_s,
                            ),
                            baseline_metrics=_rhs1_solver_candidate_metrics(
                                name="current_reduced",
                                result=res_reduced,
                                target_value=target_reduced,
                            ),
                        )
                        _apply_rhs1_handoff(handoff_state)
                except Exception as exc:  # noqa: BLE001
                    if emit is not None:
                        emit(
                            1,
                            f"{'sparse_lu' if sparse_exact_lu else 'sparse_ilu'}: "
                            f"failed ({type(exc).__name__}: {exc})",
                        )
        residual_norm_check = float(res_reduced.residual_norm)
        residual_norm_true = residual_norm_check
        if ksp_precond is not None and ksp_precond_side == "left":
            try:
                r_vec = ksp_b - ksp_matvec(res_reduced.x)
                residual_norm_true = float(jnp.linalg.norm(r_vec))
                if not np.isfinite(residual_norm_true):
                    residual_norm_true = float("inf")
                r_pc = ksp_precond(r_vec)
                r_pc_norm = float(jnp.linalg.norm(r_pc))
                if np.isfinite(r_pc_norm):
                    residual_norm_check = r_pc_norm
            except Exception:
                pass
        dense_fallback_max = _rhsmode1_dense_fallback_max(op)
        if not dense_backend_allowed and not host_dense_fallback_allowed and not dense_krylov_allowed:
            dense_fallback_max = 0
        dense_fallback_max_huge = 0
        dense_fallback_ratio = 1.0e2
        if dense_fallback_max > 0:
            dense_fallback_max_huge_env = os.environ.get("SFINCS_JAX_RHSMODE1_DENSE_FALLBACK_MAX_HUGE", "").strip()
            try:
                dense_fallback_max_huge = int(dense_fallback_max_huge_env) if dense_fallback_max_huge_env else dense_fallback_max
            except ValueError:
                dense_fallback_max_huge = dense_fallback_max
            dense_fallback_ratio_env = os.environ.get("SFINCS_JAX_RHSMODE1_DENSE_FALLBACK_RATIO", "").strip()
            try:
                dense_fallback_ratio = float(dense_fallback_ratio_env) if dense_fallback_ratio_env else 1.0e2
            except ValueError:
                dense_fallback_ratio = 1.0e2
        res_ratio = float(residual_norm_true) / max(float(target_reduced), 1e-300)
        dense_fallback_limit = dense_fallback_max_huge if res_ratio > dense_fallback_ratio else dense_fallback_max
        dense_fallback_trigger = bool(res_ratio > dense_fallback_ratio) if dense_fallback_ratio > 0 else True
        if host_sparse_direct_used and jax.default_backend() != "cpu":
            host_sparse_skip_ratio = _rhsmode1_host_sparse_skip_dense_ratio()
            if host_sparse_skip_ratio > 0.0 and res_ratio <= float(host_sparse_skip_ratio):
                dense_fallback_trigger = False
                dense_fallback_max = 0
                dense_fallback_limit = 0
                if emit is not None:
                    emit(
                        0,
                        "solve_v3_full_system_linear_gmres: skipping dense fallback after host sparse LU "
                        f"(ratio={res_ratio:.3e} <= {float(host_sparse_skip_ratio):.1e})",
                    )
        pas_force_dense = (
            (not disable_dense_pas)
            and op.fblock.fp is None
            and int(op.constraint_scheme) == 2
            and dense_fallback_limit > 0
            and int(active_size) <= dense_fallback_limit
            and float(res_reduced.residual_norm) > target_reduced
        )
        if pas_force_dense:
            dense_fallback_trigger = True
        fp_force_dense = (
            op.fblock.fp is not None
            and dense_fallback_max > 0
            and int(active_size) <= dense_fallback_max
            and float(residual_norm_true) > target_reduced
        )
        if fp_force_dense:
            dense_fallback_trigger = True
            dense_fallback_limit = max(dense_fallback_limit, dense_fallback_max)
        force_dense_cs0 = bool(
            int(op.constraint_scheme) == 0
            and cs0_dense_fallback_allowed
            and (not cs0_sparse_first)
            and (not cs0_petsc_compat)
        )
        if force_dense_cs0:
            # constraintScheme=0 systems are singular; keep the dense fallback
            # available even when the residual ratio is huge.
            dense_fallback_limit = max(dense_fallback_limit, dense_fallback_max)
            dense_fallback_trigger = True
        if int(op.constraint_scheme) == 0 and not cs0_dense_fallback_allowed:
            dense_fallback_limit = 0
            dense_fallback_trigger = False
        if (
            dense_fallback_limit > 0
            and int(op.rhs_mode) == 1
            and (not bool(op.include_phi1))
            and int(active_size) <= dense_fallback_limit
            and dense_fallback_trigger
            and (float(residual_norm_true) > target_reduced or force_dense_cs0)
        ):
            _mark("rhs1_dense_fallback_start")
            use_row_scaled = bool(
                int(op.constraint_scheme) == 0
                or (int(op.constraint_scheme) == 1 and op.fblock.fp is not None)
            )
            if emit is not None:
                emit(
                    0,
                    "solve_v3_full_system_linear_gmres: dense fallback "
                    f"(size={active_size} residual={float(res_reduced.residual_norm):.3e} > target={target_reduced:.3e})",
                )
            try:
                dense_retry_timer = Timer()
                host_dense_env = os.environ.get("SFINCS_JAX_RHSMODE1_DENSE_HOST_LU", "").strip().lower()
                backend = jax.default_backend()
                if host_dense_env in {"0", "false", "no", "off"}:
                    use_host_dense = False
                elif host_dense_env in {"1", "true", "yes", "on"}:
                    use_host_dense = True
                else:
                    # Default: avoid backend LAPACK/SVD paths on accelerators, and avoid
                    # XLA dense-solve scratch allocations for medium/large CPU systems.
                    use_host_dense = backend != "cpu" or (bool(use_implicit) and int(active_size) >= 2000)
                if op.fblock.pas is not None and int(active_size) <= 2000:
                    use_host_dense = True

                if use_host_dense:
                    import scipy.linalg as sla  # noqa: PLC0415
                    if emit is not None and backend != "cpu" and host_dense_env in {"", "auto"}:
                        emit(
                            0,
                            "solve_v3_full_system_linear_gmres: dense fallback using host LU "
                            f"on backend={backend}",
                        )

                    if dense_matrix_cache is not None:
                        a_np = np.asarray(dense_matrix_cache, dtype=np.float64)
                    else:
                        a_dense_jnp = assemble_dense_matrix_from_matvec(
                            matvec=mv_reduced, n=int(active_size), dtype=rhs_reduced.dtype
                        )
                        a_np = np.asarray(a_dense_jnp, dtype=np.float64)
                    # Make a contiguous copy for LAPACK.
                    a_np = np.array(a_np, dtype=np.float64, copy=True)
                    if a_np.ndim != 2:
                        a_np = np.squeeze(a_np)

                    mv_dense = mv_reduced
                    b_dense = jnp.asarray(rhs_reduced, dtype=jnp.float64)
                    if use_row_scaled:
                        diag_floor = 1e-12
                        diag = np.diag(a_np).astype(np.float64, copy=False)
                        diag_abs = np.abs(diag)
                        diag_safe = np.where(diag_abs > diag_floor, diag, np.sign(diag) * diag_floor)
                        diag_safe = np.where(diag_safe != 0.0, diag_safe, diag_floor)
                        scale = (1.0 / diag_safe).astype(np.float64, copy=False)
                        a_np = a_np * scale[:, None]
                        scale_jnp = jnp.asarray(scale, dtype=jnp.float64)
                        b_dense = b_dense * scale_jnp

                        def mv_dense(x: jnp.ndarray) -> jnp.ndarray:
                            return scale_jnp * mv_reduced(x)

                    if a_np.ndim != 2 or a_np.shape[0] != a_np.shape[1]:
                        if emit is not None:
                            emit(
                                1,
                                "solve_v3_full_system_linear_gmres: dense fallback "
                                f"non-square matrix shape={a_np.shape}; using least-squares host solve",
                            )
                        if not use_implicit:
                            x_np = np.asarray(np.linalg.lstsq(a_np, np.asarray(b_dense, dtype=np.float64), rcond=None)[0], dtype=np.float64)
                            x_dense = jnp.asarray(x_np, dtype=jnp.float64)
                            r_dense = rhs_reduced - mv_reduced(x_dense)
                            res_dense = GMRESSolveResult(x=x_dense, residual_norm=jnp.linalg.norm(r_dense))
                        else:
                            def _solve_cb(rhs_np: np.ndarray) -> np.ndarray:
                                rhs_np = np.asarray(rhs_np, dtype=np.float64)
                                return np.asarray(np.linalg.lstsq(a_np, rhs_np, rcond=None)[0], dtype=np.float64)

                            out_spec = jax.ShapeDtypeStruct(b_dense.shape, jnp.float64)
                            x_dense = jax.pure_callback(_solve_cb, out_spec, b_dense)
                            r_dense = rhs_reduced - mv_reduced(x_dense)
                            res_dense = GMRESSolveResult(x=x_dense, residual_norm=jnp.linalg.norm(r_dense))
                        lu = None
                        piv = None
                    else:
                        lu, piv = sla.lu_factor(a_np)

                    if lu is not None and piv is not None:
                        refine_steps = 0
                        if op.fblock.pas is not None and int(active_size) <= 2000:
                            refine_steps = 2
                        if not use_implicit:
                            rhs_np = np.asarray(b_dense, dtype=np.float64)
                            x_np = np.asarray(sla.lu_solve((lu, piv), rhs_np), dtype=np.float64)
                            for _ in range(int(refine_steps)):
                                r_np = rhs_np - a_np @ x_np
                                dx_np = np.asarray(sla.lu_solve((lu, piv), r_np), dtype=np.float64)
                                x_np = x_np + dx_np
                            x_dense = jnp.asarray(x_np, dtype=jnp.float64)
                        else:
                            out_spec = jax.ShapeDtypeStruct(b_dense.shape, jnp.float64)

                            def _solve_cb(rhs_np: np.ndarray) -> np.ndarray:
                                rhs_np = np.asarray(rhs_np, dtype=np.float64)
                                x_np = np.asarray(sla.lu_solve((lu, piv), rhs_np), dtype=np.float64)
                                for _ in range(int(refine_steps)):
                                    r_np = rhs_np - a_np @ x_np
                                    dx_np = np.asarray(sla.lu_solve((lu, piv), r_np), dtype=np.float64)
                                    x_np = x_np + dx_np
                                return x_np

                            def _solveT_cb(rhs_np: np.ndarray) -> np.ndarray:
                                rhs_np = np.asarray(rhs_np, dtype=np.float64)
                                x_np = np.asarray(sla.lu_solve((lu, piv), rhs_np, trans=1), dtype=np.float64)
                                for _ in range(int(refine_steps)):
                                    r_np = rhs_np - a_np.T @ x_np
                                    dx_np = np.asarray(sla.lu_solve((lu, piv), r_np, trans=1), dtype=np.float64)
                                    x_np = x_np + dx_np
                                return x_np

                            def _solve_host(_mv, rhs: jnp.ndarray) -> jnp.ndarray:
                                return jax.pure_callback(_solve_cb, out_spec, rhs)

                            def _transpose_solve_host(_mv_t, rhs: jnp.ndarray) -> jnp.ndarray:
                                return jax.pure_callback(_solveT_cb, out_spec, rhs)

                            x_dense = jax.lax.custom_linear_solve(
                                mv_dense,
                                b_dense,
                                solve=_solve_host,
                                transpose_solve=_transpose_solve_host,
                                symmetric=False,
                            )
                        r_dense = rhs_reduced - mv_reduced(x_dense)
                        res_dense = GMRESSolveResult(x=x_dense, residual_norm=jnp.linalg.norm(r_dense))
                elif dense_backend_allowed and dense_matrix_cache is not None:
                    a_dense_jnp = jnp.asarray(dense_matrix_cache, dtype=rhs_reduced.dtype)
                    if use_row_scaled:
                        x_dense, _rn = dense_solve_from_matrix_row_scaled(a=a_dense_jnp, b=rhs_reduced)
                    else:
                        x_dense, _rn = dense_solve_from_matrix(a=a_dense_jnp, b=rhs_reduced)
                    r_dense = rhs_reduced - mv_reduced(x_dense)
                    res_dense = GMRESSolveResult(x=x_dense, residual_norm=jnp.linalg.norm(r_dense))
                else:
                    if dense_matrix_cache is not None:
                        a_dense_jnp = jnp.asarray(dense_matrix_cache, dtype=rhs_reduced.dtype)
                    else:
                        a_dense_jnp = assemble_dense_matrix_from_matvec(
                            matvec=mv_reduced, n=int(active_size), dtype=rhs_reduced.dtype
                        )
                    if emit is not None and jax.default_backend() != "cpu":
                        emit(
                            0,
                            "solve_v3_full_system_linear_gmres: dense fallback using explicit dense Krylov "
                            f"on backend={jax.default_backend()}",
                        )
                    res_dense, _residual_dense = dense_krylov_solve_from_matrix_with_residual(
                        a=a_dense_jnp,
                        b=rhs_reduced,
                        x0=res_reduced.x,
                        preconditioner=None,
                        tol=tol,
                        atol=atol,
                        restart=restart,
                        maxiter=maxiter,
                        solve_method="incremental",
                        precondition_side="none" if use_row_scaled else gmres_precond_side,
                        row_scaled=use_row_scaled,
                    )
                dense_retry_elapsed_s = dense_retry_timer.elapsed_s()
                res_reduced, residual_vec, handoff_state, _accepted = rhs1_accept_candidate(
                    current_result=res_reduced,
                    candidate_result=res_dense,
                    current_residual_vec=residual_vec,
                    candidate_residual_vec=None,
                    matvec_fn=mv_reduced,
                    b_vec=rhs_reduced,
                    precond_fn=None,
                    x0_vec=res_dense.x,
                    restart=restart,
                    maxiter=maxiter,
                    precond_side="none",
                    solver_kind="dense",
                    candidate_metrics=_rhs1_solver_candidate_metrics(
                        name="dense_reduced",
                        result=res_dense,
                        target_value=target_reduced,
                        solve_s=dense_retry_elapsed_s,
                    ),
                    baseline_metrics=_rhs1_solver_candidate_metrics(
                        name="current_reduced",
                        result=res_reduced,
                        target_value=target_reduced,
                    ),
                )
                _apply_rhs1_handoff(handoff_state)
            except Exception as exc:  # noqa: BLE001
                if emit is not None:
                    emit(1, f"solve_v3_full_system_linear_gmres: dense fallback failed ({type(exc).__name__}: {exc})")
            _mark("rhs1_dense_fallback_done")
        if (
            _rhsmode1_fast_post_xblock_polish_allowed(
                op=op,
                active_size=int(active_size),
                residual_norm=float(res_reduced.residual_norm),
                target=float(target_reduced),
                used_large_cpu_xblock_shortcut=bool(cpu_large_xblock_shortcut),
                use_implicit=bool(use_implicit),
            )
            and preconditioner_reduced is not None
        ):
            polish_restart_env = os.environ.get("SFINCS_JAX_RHSMODE1_FAST_POST_XBLOCK_POLISH_RESTART", "").strip()
            polish_maxiter_env = os.environ.get("SFINCS_JAX_RHSMODE1_FAST_POST_XBLOCK_POLISH_MAXITER", "").strip()
            polish_tol_env = os.environ.get("SFINCS_JAX_RHSMODE1_FAST_POST_XBLOCK_POLISH_TOL", "").strip()
            try:
                polish_restart = int(polish_restart_env) if polish_restart_env else min(int(restart), 40)
            except ValueError:
                polish_restart = min(int(restart), 40)
            try:
                polish_maxiter = int(polish_maxiter_env) if polish_maxiter_env else min(max(40, int(maxiter or 80)), 80)
            except ValueError:
                polish_maxiter = min(max(40, int(maxiter or 80)), 80)
            try:
                polish_tol = float(polish_tol_env) if polish_tol_env else min(float(tol), 1.0e-10)
            except ValueError:
                polish_tol = min(float(tol), 1.0e-10)
            polish_restart = max(5, int(polish_restart))
            polish_maxiter = max(5, int(polish_maxiter))
            if emit is not None:
                emit(
                    1,
                    "solve_v3_full_system_linear_gmres: fast post-xblock polish "
                    f"(restart={polish_restart} maxiter={polish_maxiter} "
                    f"residual={float(res_reduced.residual_norm):.3e})",
                )
            res_polish = _solve_linear(
                matvec_fn=mv_reduced,
                b_vec=rhs_reduced,
                precond_fn=preconditioner_reduced,
                x0_vec=res_reduced.x,
                tol_val=polish_tol,
                atol_val=atol,
                restart_val=polish_restart,
                maxiter_val=polish_maxiter,
                solve_method_val="incremental",
                precond_side=gmres_precond_side,
            )
            if float(res_polish.residual_norm) < float(res_reduced.residual_norm):
                if emit is not None:
                    emit(
                        1,
                        "solve_v3_full_system_linear_gmres: fast post-xblock polish improved residual "
                        f"{float(res_reduced.residual_norm):.3e} -> {float(res_polish.residual_norm):.3e}",
                    )
                res_reduced = res_polish
        # Cheap post-solve polish for large FP systems:
        # Apply a few damped preconditioned-residual correction steps to improve
        # low-order moments (flow/Mach/jHat) without paying for a full second GMRES pass.
        if (
            int(op.rhs_mode) == 1
            and (not bool(op.include_phi1))
            and op.fblock.fp is not None
            and op.fblock.pas is None
            and rhs1_precond_kind == "xmg"
            and preconditioner_reduced is not None
        ):
            polish_min_env = os.environ.get("SFINCS_JAX_RHSMODE1_FP_POLISH_MIN", "").strip()
            try:
                polish_min = int(polish_min_env) if polish_min_env else 80000
            except ValueError:
                polish_min = 80000
            polish_steps_env = os.environ.get("SFINCS_JAX_RHSMODE1_FP_POLISH_STEPS", "").strip()
            try:
                polish_steps = int(polish_steps_env) if polish_steps_env else 2
            except ValueError:
                polish_steps = 2
            polish_steps = max(0, min(int(polish_steps), 6))
            fp_targeted_polish = _rhsmode1_fp_targeted_polish_allowed(
                op=op,
                active_size=int(active_size),
                residual_norm=float(res_reduced.residual_norm),
                target=float(target_reduced),
                rhs1_precond_kind=rhs1_precond_kind,
                use_implicit=bool(use_implicit),
            )
            polish_hybrid_env = os.environ.get("SFINCS_JAX_RHSMODE1_FP_POLISH_HYBRID", "").strip().lower()
            polish_hybrid = polish_hybrid_env not in {"0", "false", "no", "off"}
            polish_precond = preconditioner_reduced
            lmax_precond_for_l1: Callable[[jnp.ndarray], jnp.ndarray] | None = None
            need_hybrid_fp_precond = fp_targeted_polish or (
                polish_steps > 0 and int(active_size) >= max(1, int(polish_min))
            )
            if polish_hybrid and need_hybrid_fp_precond:
                precond_collision = _build_rhsmode1_collision_preconditioner(
                    op=op,
                    reduce_full=reduce_full,
                    expand_reduced=expand_reduced,
                )

                def _hybrid_precond(v: jnp.ndarray) -> jnp.ndarray:
                    z0 = preconditioner_reduced(v)
                    r1 = v - mv_reduced(z0)
                    z1 = precond_collision(r1)
                    return z0 + z1

                polish_precond = _hybrid_precond

            if polish_steps > 0 and int(active_size) >= max(1, int(polish_min)):
                polish_omega_env = os.environ.get("SFINCS_JAX_RHSMODE1_FP_POLISH_OMEGA", "").strip()
                try:
                    polish_omega = float(polish_omega_env) if polish_omega_env else 1.0
                except ValueError:
                    polish_omega = 1.0
                polish_omega = max(1.0e-3, min(float(polish_omega), 1.5))
                polish_backtrack_env = os.environ.get("SFINCS_JAX_RHSMODE1_FP_POLISH_BACKTRACK", "").strip()
                try:
                    polish_backtrack = int(polish_backtrack_env) if polish_backtrack_env else 3
                except ValueError:
                    polish_backtrack = 3
                polish_backtrack = max(0, min(int(polish_backtrack), 6))
                x_polish = jnp.asarray(res_reduced.x, dtype=jnp.float64)
                rn_best = float(res_reduced.residual_norm)
                improved_any = False
                for _ in range(polish_steps):
                    r_polish = rhs_reduced - mv_reduced(x_polish)
                    rn_r = float(jnp.linalg.norm(r_polish))
                    if (not np.isfinite(rn_r)) or rn_r <= target_reduced:
                        break
                    delta = polish_precond(r_polish)
                    omega_try = float(polish_omega)
                    step_accepted = False
                    for _bt in range(polish_backtrack + 1):
                        x_try = x_polish + omega_try * delta
                        r_try = rhs_reduced - mv_reduced(x_try)
                        rn_try = float(jnp.linalg.norm(r_try))
                        if np.isfinite(rn_try) and rn_try < rn_best:
                            x_polish = x_try
                            rn_best = rn_try
                            step_accepted = True
                            improved_any = True
                            break
                        omega_try *= 0.5
                    if not step_accepted:
                        break
                if improved_any and rn_best < float(res_reduced.residual_norm):
                    if emit is not None:
                        emit(
                            1,
                            "solve_v3_full_system_linear_gmres: FP polish improved residual "
                            f"{float(res_reduced.residual_norm):.3e} -> {rn_best:.3e}",
                        )
                    res_reduced = GMRESSolveResult(
                        x=jnp.asarray(x_polish, dtype=jnp.float64),
                        residual_norm=jnp.asarray(rn_best, dtype=jnp.float64),
                    )
            # Optional FP-specific angular/x preconditioner polish (low-L blocks).
            fp_lmax_polish_env = os.environ.get("SFINCS_JAX_RHSMODE1_FP_POLISH_LMAX", "").strip()
            fp_lmax_max_env = os.environ.get("SFINCS_JAX_RHSMODE1_FP_POLISH_LMAX_BLOCK_MAX", "").strip()
            fp_lmax_restart_env = os.environ.get("SFINCS_JAX_RHSMODE1_FP_POLISH_LMAX_RESTART", "").strip()
            fp_lmax_maxiter_env = os.environ.get("SFINCS_JAX_RHSMODE1_FP_POLISH_LMAX_MAXITER", "").strip()
            try:
                fp_lmax_default = int(fp_lmax_polish_env) if fp_lmax_polish_env else 2
            except ValueError:
                fp_lmax_default = 2
            if (
                (not fp_lmax_polish_env)
                and op.fblock.fp is not None
                and op.fblock.pas is None
                and int(op.n_theta) * int(op.n_zeta) <= 256
            ):
                # When the angular grid is small enough that the low-L blocks are still
                # modest, pushing lmax a bit higher can substantially improve convergence
                # of FP moments (flow/current) without needing an expensive global sparse
                # rescue.
                fp_lmax_default = max(int(fp_lmax_default), 6)
            try:
                fp_lmax_block_max = int(fp_lmax_max_env) if fp_lmax_max_env else 1500
            except ValueError:
                fp_lmax_block_max = 1500
            try:
                fp_lmax_restart = int(fp_lmax_restart_env) if fp_lmax_restart_env else 80
            except ValueError:
                fp_lmax_restart = 80
            try:
                fp_lmax_maxiter = int(fp_lmax_maxiter_env) if fp_lmax_maxiter_env else 120
            except ValueError:
                fp_lmax_maxiter = 120
            if fp_targeted_polish and float(res_reduced.residual_norm) > target_reduced:
                nxi_for_x_np = np.asarray(op.fblock.collisionless.n_xi_for_x, dtype=np.int32)
                max_l = int(np.max(nxi_for_x_np)) if nxi_for_x_np.size else 0
                lmax_use = max(0, min(int(max_l), int(fp_lmax_default)))
                block_size = int(lmax_use) * int(op.n_theta) * int(op.n_zeta)
                if lmax_use > 0 and block_size > 0 and block_size <= int(fp_lmax_block_max):
                    if emit is not None:
                        emit(
                            1,
                            "solve_v3_full_system_linear_gmres: FP low-L polish "
                            f"(lmax={int(lmax_use)} block={block_size} restart={int(fp_lmax_restart)} "
                            f"maxiter={int(fp_lmax_maxiter)})",
                        )
                    try:
                        lmax_precond = _build_rhsmode1_xblock_tz_lmax_preconditioner(
                            op=op,
                            lmax=int(lmax_use),
                            reduce_full=reduce_full,
                            expand_reduced=expand_reduced,
                        )
                        lmax_precond_for_l1 = lmax_precond
                        res_lmax = _solve_linear(
                            matvec_fn=mv_reduced,
                            b_vec=rhs_reduced,
                            precond_fn=lmax_precond,
                            x0_vec=res_reduced.x,
                            tol_val=tol,
                            atol_val=atol,
                            restart_val=int(fp_lmax_restart),
                            maxiter_val=int(fp_lmax_maxiter),
                            solve_method_val="incremental",
                            precond_side=gmres_precond_side,
                        )
                        if float(res_lmax.residual_norm) < float(res_reduced.residual_norm):
                            if emit is not None:
                                emit(
                                    1,
                                    "solve_v3_full_system_linear_gmres: FP low-L polish improved residual "
                                    f"{float(res_reduced.residual_norm):.3e} -> {float(res_lmax.residual_norm):.3e}",
                                )
                            res_reduced = res_lmax
                    except Exception as exc:  # noqa: BLE001
                        if emit is not None:
                            emit(1, f"solve_v3_full_system_linear_gmres: FP low-L polish failed ({type(exc).__name__}: {exc})")
            # L=1 targeted polish (flow channel): solve a small projected system
            # on the L=1 active modes only. This is a cheap way to improve flow/Mach
            # parity when the full-system solve stalls above the strict target.
            l1_polish_env = os.environ.get("SFINCS_JAX_RHSMODE1_FP_L1_POLISH", "").strip().lower()
            l1_polish_enabled = l1_polish_env not in {"0", "false", "no", "off"}
            if fp_targeted_polish and l1_polish_enabled:
                n_s = int(op.n_species)
                n_x = int(op.n_x)
                n_l = int(op.n_xi)
                n_t = int(op.n_theta)
                n_z = int(op.n_zeta)
                nxi_for_x_np = np.asarray(op.fblock.collisionless.n_xi_for_x, dtype=np.int32)
                l1_full_idx: list[int] = []
                if use_active_dof_mode and full_to_active_jnp is not None:
                    full_to_active_np = np.asarray(full_to_active_jnp, dtype=np.int32)
                    for s_idx in range(n_s):
                        for ix in range(n_x):
                            if int(nxi_for_x_np[ix]) <= 1:
                                continue
                            il = 1
                            for it in range(n_t):
                                for iz in range(n_z):
                                    f_idx = int(((((s_idx * n_x + ix) * n_l + il) * n_t + it) * n_z + iz))
                                    l1_full_idx.append(f_idx)
                    if l1_full_idx:
                        l1_full_idx_np = np.asarray(l1_full_idx, dtype=np.int32)
                        l1_active_idx_np = full_to_active_np[l1_full_idx_np] - 1
                        l1_active_idx_np = l1_active_idx_np[l1_active_idx_np >= 0]
                    else:
                        l1_active_idx_np = np.asarray([], dtype=np.int32)
                else:
                    for s_idx in range(n_s):
                        for ix in range(n_x):
                            if int(nxi_for_x_np[ix]) <= 1:
                                continue
                            il = 1
                            for it in range(n_t):
                                for iz in range(n_z):
                                    f_idx = int(((((s_idx * n_x + ix) * n_l + il) * n_t + it) * n_z + iz))
                                    l1_full_idx.append(f_idx)
                    l1_active_idx_np = np.asarray(l1_full_idx, dtype=np.int32)

                if int(l1_active_idx_np.size) > 0:
                    l1_idx_jnp = jnp.asarray(np.unique(l1_active_idx_np), dtype=jnp.int32)
                    l1_n = int(l1_idx_jnp.shape[0])
                    l1_maxiter_env = os.environ.get("SFINCS_JAX_RHSMODE1_FP_L1_POLISH_MAXITER", "").strip()
                    l1_restart_env = os.environ.get("SFINCS_JAX_RHSMODE1_FP_L1_POLISH_RESTART", "").strip()
                    try:
                        l1_maxiter = int(l1_maxiter_env) if l1_maxiter_env else 120
                    except ValueError:
                        l1_maxiter = 120
                    try:
                        l1_restart = int(l1_restart_env) if l1_restart_env else 80
                    except ValueError:
                        l1_restart = 80
                    l1_maxiter = max(5, min(int(l1_maxiter), 200))
                    l1_restart = max(5, min(int(l1_restart), max(5, l1_maxiter)))

                    def _l1_reduce(v: jnp.ndarray) -> jnp.ndarray:
                        return v[l1_idx_jnp]

                    def _l1_expand(v: jnp.ndarray) -> jnp.ndarray:
                        out = jnp.zeros((int(active_size),), dtype=jnp.float64)
                        return out.at[l1_idx_jnp].set(v, unique_indices=True)

                    x_l1_base = jnp.asarray(res_reduced.x, dtype=jnp.float64)
                    r_l1_full = rhs_reduced - mv_reduced(x_l1_base)
                    b_l1 = _l1_reduce(r_l1_full)
                    rn_full_base = float(jnp.linalg.norm(r_l1_full))
                    b_l1_norm = float(jnp.linalg.norm(b_l1))
                    l1_ratio_env = os.environ.get("SFINCS_JAX_RHSMODE1_FP_L1_POLISH_RATIO", "").strip()
                    l1_abs_env = os.environ.get("SFINCS_JAX_RHSMODE1_FP_L1_POLISH_ABS", "").strip()
                    try:
                        l1_ratio = float(l1_ratio_env) if l1_ratio_env else 2.0
                    except ValueError:
                        l1_ratio = 2.0
                    try:
                        l1_abs = float(l1_abs_env) if l1_abs_env else 1.0e-8
                    except ValueError:
                        l1_abs = 1.0e-8
                    l1_thresh = max(float(target_reduced) * max(1.0, float(l1_ratio)), float(l1_abs))
                    if np.isfinite(b_l1_norm) and b_l1_norm > l1_thresh:
                        if emit is not None:
                            emit(
                                1,
                                "solve_v3_full_system_linear_gmres: FP L1 polish "
                                f"(size={l1_n} restart={l1_restart} maxiter={l1_maxiter} b_norm={b_l1_norm:.3e})",
                            )

                        def _mv_l1(v: jnp.ndarray) -> jnp.ndarray:
                            return _l1_reduce(mv_reduced(_l1_expand(v)))

                        def _pre_l1(v: jnp.ndarray) -> jnp.ndarray:
                            if lmax_precond_for_l1 is not None:
                                return _l1_reduce(lmax_precond_for_l1(_l1_expand(v)))
                            return _l1_reduce(polish_precond(_l1_expand(v)))

                        tol_l1_env = os.environ.get("SFINCS_JAX_RHSMODE1_FP_L1_POLISH_TOL", "").strip()
                        try:
                            tol_l1 = float(tol_l1_env) if tol_l1_env else 1.0e-10
                        except ValueError:
                            tol_l1 = 1.0e-10
                        tol_l1 = max(1.0e-14, float(tol_l1))
                        try:
                            l1_corr = _solve_linear(
                                matvec_fn=_mv_l1,
                                b_vec=b_l1,
                                precond_fn=_pre_l1,
                                x0_vec=None,
                                tol_val=tol_l1,
                                atol_val=0.0,
                                restart_val=l1_restart,
                                maxiter_val=l1_maxiter,
                                solve_method_val="incremental",
                                precond_side=gmres_precond_side,
                            )
                            x_l1_try = x_l1_base + _l1_expand(l1_corr.x)
                            r_try = rhs_reduced - mv_reduced(x_l1_try)
                            rn_try = float(jnp.linalg.norm(r_try))
                            b_l1_try = _l1_reduce(r_try)
                            rn_l1_try = float(jnp.linalg.norm(b_l1_try))
                            l1_full_ratio_env = os.environ.get("SFINCS_JAX_RHSMODE1_FP_L1_POLISH_FULL_RATIO", "").strip()
                            try:
                                l1_full_ratio = float(l1_full_ratio_env) if l1_full_ratio_env else 1.2
                            except ValueError:
                                l1_full_ratio = 1.2
                            l1_full_ratio = max(1.0, float(l1_full_ratio))
                            accept_l1 = (
                                np.isfinite(rn_l1_try)
                                and rn_l1_try < b_l1_norm
                                and np.isfinite(rn_try)
                                and rn_try <= max(float(rn_full_base) * l1_full_ratio, float(rn_full_base) + 1.0e-10)
                            )
                            if accept_l1:
                                if emit is not None:
                                    emit(
                                        1,
                                        "solve_v3_full_system_linear_gmres: FP L1 polish improved residual "
                                        f"full {float(rn_full_base):.3e} -> {rn_try:.3e}; "
                                        f"L1 {b_l1_norm:.3e} -> {rn_l1_try:.3e}",
                                    )
                                res_reduced = GMRESSolveResult(
                                    x=jnp.asarray(x_l1_try, dtype=jnp.float64),
                                    residual_norm=jnp.asarray(rn_try, dtype=jnp.float64),
                                )
                        except Exception as exc:  # noqa: BLE001
                            if emit is not None:
                                emit(1, f"solve_v3_full_system_linear_gmres: FP L1 polish failed ({type(exc).__name__}: {exc})")
            # Low-L global polish: solve a projected system on the lowest L modes across all
            # species/x/(theta,zeta). This is more expensive than the L1 polish but can be
            # significantly more effective at improving flow/current parity when the full
            # solve stalls above the strict target (especially for FP+Er).
            global_low_l_env = os.environ.get("SFINCS_JAX_RHSMODE1_FP_GLOBAL_LOW_L_POLISH", "").strip().lower()
            global_low_l_enabled = global_low_l_env in {"1", "true", "yes", "on"}
            if fp_targeted_polish and global_low_l_enabled and float(res_reduced.residual_norm) > target_reduced:
                lmax_env = os.environ.get("SFINCS_JAX_RHSMODE1_FP_GLOBAL_LOW_LMAX", "").strip()
                max_size_env = os.environ.get("SFINCS_JAX_RHSMODE1_FP_GLOBAL_LOW_MAX_SIZE", "").strip()
                ratio_env = os.environ.get("SFINCS_JAX_RHSMODE1_FP_GLOBAL_LOW_RATIO", "").strip()
                try:
                    low_lmax = int(lmax_env) if lmax_env else 6
                except ValueError:
                    low_lmax = 6
                try:
                    low_max_size = int(max_size_env) if max_size_env else 8000
                except ValueError:
                    low_max_size = 8000
                try:
                    low_ratio = float(ratio_env) if ratio_env else 1.0e4
                except ValueError:
                    low_ratio = 1.0e4
                low_lmax = max(0, min(int(low_lmax), int(op.n_xi) - 1))
                low_max_size = max(0, int(low_max_size))
                low_ratio = max(1.0, float(low_ratio))
                if float(res_reduced.residual_norm) > float(target_reduced) * float(low_ratio) and low_lmax > 0:
                    n_s = int(op.n_species)
                    n_x = int(op.n_x)
                    n_l = int(op.n_xi)
                    n_t = int(op.n_theta)
                    n_z = int(op.n_zeta)
                    nxi_for_x_np = np.asarray(op.fblock.collisionless.n_xi_for_x, dtype=np.int32)
                    low_full_idx: list[int] = []
                    if use_active_dof_mode and full_to_active_jnp is not None:
                        full_to_active_np = np.asarray(full_to_active_jnp, dtype=np.int32)
                        for s_idx in range(n_s):
                            for ix in range(n_x):
                                lmax_x = min(int(nxi_for_x_np[ix]) - 1, int(low_lmax))
                                if lmax_x < 0:
                                    continue
                                for il in range(lmax_x + 1):
                                    for it in range(n_t):
                                        for iz in range(n_z):
                                            f_idx = int(((((s_idx * n_x + ix) * n_l + il) * n_t + it) * n_z + iz))
                                            low_full_idx.append(f_idx)
                        if low_full_idx:
                            low_full_idx_np = np.asarray(low_full_idx, dtype=np.int32)
                            low_active_idx_np = full_to_active_np[low_full_idx_np] - 1
                            low_active_idx_np = low_active_idx_np[low_active_idx_np >= 0]
                        else:
                            low_active_idx_np = np.asarray([], dtype=np.int32)
                    else:
                        for s_idx in range(n_s):
                            for ix in range(n_x):
                                lmax_x = min(int(nxi_for_x_np[ix]) - 1, int(low_lmax))
                                if lmax_x < 0:
                                    continue
                                for il in range(lmax_x + 1):
                                    for it in range(n_t):
                                        for iz in range(n_z):
                                            f_idx = int(((((s_idx * n_x + ix) * n_l + il) * n_t + it) * n_z + iz))
                                            low_full_idx.append(f_idx)
                        low_active_idx_np = np.asarray(low_full_idx, dtype=np.int32)

                    if int(low_active_idx_np.size) > 0:
                        low_idx_jnp = jnp.asarray(np.unique(low_active_idx_np), dtype=jnp.int32)
                        low_n = int(low_idx_jnp.shape[0])
                    else:
                        low_n = 0
                        low_idx_jnp = None

                    if low_n > 0 and (low_max_size <= 0 or low_n <= low_max_size):
                        low_maxiter_env = os.environ.get("SFINCS_JAX_RHSMODE1_FP_GLOBAL_LOW_MAXITER", "").strip()
                        low_restart_env = os.environ.get("SFINCS_JAX_RHSMODE1_FP_GLOBAL_LOW_RESTART", "").strip()
                        try:
                            low_maxiter = int(low_maxiter_env) if low_maxiter_env else 120
                        except ValueError:
                            low_maxiter = 120
                        try:
                            low_restart = int(low_restart_env) if low_restart_env else 80
                        except ValueError:
                            low_restart = 80
                        low_maxiter = max(5, min(int(low_maxiter), 250))
                        low_restart = max(5, min(int(low_restart), max(5, low_maxiter)))

                        assert low_idx_jnp is not None

                        def _low_reduce(v: jnp.ndarray) -> jnp.ndarray:
                            return v[low_idx_jnp]

                        def _low_expand(v: jnp.ndarray) -> jnp.ndarray:
                            out = jnp.zeros((int(active_size),), dtype=jnp.float64)
                            return out.at[low_idx_jnp].set(v, unique_indices=True)

                        x_low_base = jnp.asarray(res_reduced.x, dtype=jnp.float64)
                        r_low_full = rhs_reduced - mv_reduced(x_low_base)
                        b_low = _low_reduce(r_low_full)
                        rn_full_base = float(jnp.linalg.norm(r_low_full))
                        b_low_norm = float(jnp.linalg.norm(b_low))
                        low_abs_env = os.environ.get("SFINCS_JAX_RHSMODE1_FP_GLOBAL_LOW_ABS", "").strip()
                        try:
                            low_abs = float(low_abs_env) if low_abs_env else 1.0e-8
                        except ValueError:
                            low_abs = 1.0e-8
                        low_thresh = max(float(target_reduced) * 2.0, float(low_abs))
                        if np.isfinite(b_low_norm) and b_low_norm > low_thresh:
                            if emit is not None:
                                emit(
                                    1,
                                    "solve_v3_full_system_linear_gmres: FP global low-L polish "
                                    f"(lmax={int(low_lmax)} size={int(low_n)} restart={int(low_restart)} "
                                    f"maxiter={int(low_maxiter)} b_norm={b_low_norm:.3e})",
                                )

                            def _mv_low(v: jnp.ndarray) -> jnp.ndarray:
                                return _low_reduce(mv_reduced(_low_expand(v)))

                            def _pre_low(v: jnp.ndarray) -> jnp.ndarray:
                                if lmax_precond_for_l1 is not None:
                                    return _low_reduce(lmax_precond_for_l1(_low_expand(v)))
                                return _low_reduce(polish_precond(_low_expand(v)))

                            try:
                                corr = _solve_linear(
                                    matvec_fn=_mv_low,
                                    b_vec=b_low,
                                    precond_fn=_pre_low,
                                    x0_vec=None,
                                    tol_val=1.0e-10,
                                    atol_val=0.0,
                                    restart_val=low_restart,
                                    maxiter_val=low_maxiter,
                                    solve_method_val="incremental",
                                    precond_side=gmres_precond_side,
                                )
                                x_try = x_low_base + _low_expand(corr.x)
                                r_try = rhs_reduced - mv_reduced(x_try)
                                rn_try = float(jnp.linalg.norm(r_try))
                                b_low_try = _low_reduce(r_try)
                                rn_low_try = float(jnp.linalg.norm(b_low_try))
                                full_ratio_env = os.environ.get("SFINCS_JAX_RHSMODE1_FP_GLOBAL_LOW_FULL_RATIO", "").strip()
                                try:
                                    full_ratio = float(full_ratio_env) if full_ratio_env else 1.2
                                except ValueError:
                                    full_ratio = 1.2
                                full_ratio = max(1.0, float(full_ratio))
                                if (
                                    np.isfinite(rn_try)
                                    and rn_try < float(res_reduced.residual_norm)
                                    and rn_try <= max(float(rn_full_base) * full_ratio, float(rn_full_base) + 1.0e-10)
                                ):
                                    if emit is not None:
                                        emit(
                                            1,
                                            "solve_v3_full_system_linear_gmres: FP global low-L polish improved residual "
                                            f"full {float(rn_full_base):.3e} -> {rn_try:.3e}; "
                                            f"low-L {b_low_norm:.3e} -> {rn_low_try:.3e}",
                                        )
                                    res_reduced = GMRESSolveResult(
                                        x=jnp.asarray(x_try, dtype=jnp.float64),
                                        residual_norm=jnp.asarray(rn_try, dtype=jnp.float64),
                                    )
                            except Exception as exc:  # noqa: BLE001
                                if emit is not None:
                                    emit(
                                        1,
                                        "solve_v3_full_system_linear_gmres: FP global low-L polish failed "
                                        f"({type(exc).__name__}: {exc})",
                                    )
                # Optional BiCGStab polish for large FP systems: short-recurrence Krylov
                # can reduce residuals further when restarted GMRES stagnates.
                fp_bi_env = os.environ.get("SFINCS_JAX_RHSMODE1_FP_BICGSTAB_POLISH", "").strip().lower()
                fp_bi_enabled = fp_bi_env in {"1", "true", "yes", "on"}
                fp_bi_min_env = os.environ.get("SFINCS_JAX_RHSMODE1_FP_BICGSTAB_MIN", "").strip()
                try:
                    fp_bi_min = int(fp_bi_min_env) if fp_bi_min_env else 80000
                except ValueError:
                    fp_bi_min = 80000
                if fp_bi_enabled and int(active_size) >= max(1, int(fp_bi_min)) and float(res_reduced.residual_norm) > target_reduced:
                    fp_bi_maxiter_env = os.environ.get("SFINCS_JAX_RHSMODE1_FP_BICGSTAB_MAXITER", "").strip()
                    fp_bi_tol_env = os.environ.get("SFINCS_JAX_RHSMODE1_FP_BICGSTAB_TOL", "").strip()
                    fp_bi_atol_env = os.environ.get("SFINCS_JAX_RHSMODE1_FP_BICGSTAB_ATOL", "").strip()
                    try:
                        fp_bi_maxiter = int(fp_bi_maxiter_env) if fp_bi_maxiter_env else 120
                    except ValueError:
                        fp_bi_maxiter = 120
                    try:
                        fp_bi_tol = float(fp_bi_tol_env) if fp_bi_tol_env else min(float(tol), 1.0e-10)
                    except ValueError:
                        fp_bi_tol = min(float(tol), 1.0e-10)
                    try:
                        fp_bi_atol = float(fp_bi_atol_env) if fp_bi_atol_env else float(atol)
                    except ValueError:
                        fp_bi_atol = float(atol)
                    fp_bi_maxiter = max(5, min(int(fp_bi_maxiter), 400))
                    if emit is not None:
                        emit(
                            1,
                            "solve_v3_full_system_linear_gmres: FP BiCGStab polish "
                            f"(maxiter={fp_bi_maxiter} tol={fp_bi_tol:.1e})",
                        )
                    precond_bi = preconditioner_reduced
                    if precond_bi is None and polish_hybrid:
                        precond_bi = polish_precond
                    res_bi = _solve_linear(
                        matvec_fn=mv_reduced,
                        b_vec=rhs_reduced,
                        precond_fn=precond_bi,
                        x0_vec=res_reduced.x,
                        tol_val=fp_bi_tol,
                        atol_val=fp_bi_atol,
                        restart_val=restart,
                        maxiter_val=fp_bi_maxiter,
                        solve_method_val="bicgstab",
                        precond_side=gmres_precond_side,
                    )
                    if float(res_bi.residual_norm) < float(res_reduced.residual_norm):
                        if emit is not None:
                            emit(
                                1,
                                "solve_v3_full_system_linear_gmres: FP BiCGStab polish improved residual "
                                f"{float(res_reduced.residual_norm):.3e} -> {float(res_bi.residual_norm):.3e}",
                            )
                        res_reduced = res_bi
        # As a last resort on CPU, retry the reduced solve using SciPy GMRES.
        #
        # JAX's gmres can stagnate or return a poor solution for some FP operators on CPU,
        # even after our strong-preconditioner fallbacks, while SciPy GMRES is often more
        # robust for the same matvec/preconditioner pair. This path is explicitly
        # non-differentiable and intended for CLI robustness.
        if (
            (not bool(use_implicit))
            and jax.default_backend() == "cpu"
            and int(op.rhs_mode) == 1
            and (not bool(op.include_phi1))
            and float(res_reduced.residual_norm) > float(target_reduced)
        ):
            scipy_rescue_env = os.environ.get("SFINCS_JAX_RHSMODE1_SCIPY_GMRES_RESCUE", "").strip().lower()
            if scipy_rescue_env not in {"0", "false", "no", "off"}:
                ratio_env = os.environ.get("SFINCS_JAX_RHSMODE1_SCIPY_GMRES_RESCUE_RATIO", "").strip()
                try:
                    rescue_ratio = float(ratio_env) if ratio_env else 1.0e3
                except ValueError:
                    rescue_ratio = 1.0e3
                rescue_ratio = max(1.0, float(rescue_ratio))
                if float(res_reduced.residual_norm) > float(target_reduced) * float(rescue_ratio):
                    scipy_restart_env = os.environ.get("SFINCS_JAX_RHSMODE1_SCIPY_GMRES_RESCUE_RESTART", "").strip()
                    scipy_maxiter_env = os.environ.get("SFINCS_JAX_RHSMODE1_SCIPY_GMRES_RESCUE_MAXITER", "").strip()
                    scipy_strong_env = os.environ.get("SFINCS_JAX_RHSMODE1_SCIPY_GMRES_RESCUE_USE_STRONG", "").strip().lower()
                    scipy_method_env = os.environ.get("SFINCS_JAX_RHSMODE1_SCIPY_RESCUE_METHOD", "").strip().lower()
                    try:
                        scipy_restart = int(scipy_restart_env) if scipy_restart_env else max(int(restart), 120)
                    except ValueError:
                        scipy_restart = max(int(restart), 120)
                    try:
                        scipy_maxiter = int(scipy_maxiter_env) if scipy_maxiter_env else max(int(maxiter or 400), 600)
                    except ValueError:
                        scipy_maxiter = max(int(maxiter or 400), 600)
                    scipy_restart = max(5, int(scipy_restart))
                    scipy_maxiter = max(5, int(scipy_maxiter))
                    rescue_preconditioner = preconditioner_reduced
                    rescue_precond_name = rhs1_precond_kind or "none"
                    use_strong_rescue = scipy_strong_env not in {"0", "false", "no", "off"}
                    if use_strong_rescue and strong_preconditioner_reduced is not None:
                        rescue_preconditioner = strong_preconditioner_reduced
                        rescue_precond_name = strong_precond_kind or "strong"
                    rescue_method = scipy_method_env
                    if rescue_method not in {"gmres", "bicgstab"}:
                        rescue_method = "bicgstab" if rescue_preconditioner is strong_preconditioner_reduced else "gmres"
                    try:
                        if emit is not None:
                            emit(
                                1,
                                "solve_v3_full_system_linear_gmres: SciPy rescue "
                                f"(residual={float(res_reduced.residual_norm):.3e} > "
                                f"{float(rescue_ratio):.1e}x target={float(target_reduced):.3e} "
                                f"method={rescue_method} restart={int(scipy_restart)} maxiter={int(scipy_maxiter)} "
                                f"preconditioner={rescue_precond_name})",
                            )
                        side = str(gmres_precond_side).strip().lower()
                        if rescue_method == "bicgstab":
                            x_np, rn_scipy, _history = bicgstab_solve_with_history_scipy(
                                matvec=mv_reduced,
                                b=rhs_reduced,
                                preconditioner=rescue_preconditioner,
                                x0=res_reduced.x,
                                tol=float(tol),
                                atol=float(atol),
                                maxiter=int(scipy_maxiter),
                                precondition_side=gmres_precond_side,
                            )
                        elif rescue_preconditioner is not None and side == "left":
                            x_np, rn_scipy, rn_pc_scipy, _history = explicit_left_preconditioned_gmres_scipy(
                                matvec=mv_reduced,
                                b=rhs_reduced,
                                preconditioner=rescue_preconditioner,
                                x0=res_reduced.x,
                                tol=float(tol),
                                atol=float(atol),
                                restart=int(scipy_restart),
                                maxiter=int(scipy_maxiter),
                            )
                            if emit is not None:
                                emit(
                                    1,
                                    "solve_v3_full_system_linear_gmres: SciPy rescue residuals "
                                    f"true={float(rn_scipy):.3e} preconditioned={float(rn_pc_scipy):.3e}",
                                )
                        else:
                            x_np, rn_scipy, _history = gmres_solve_with_history_scipy(
                                matvec=mv_reduced,
                                b=rhs_reduced,
                                preconditioner=rescue_preconditioner,
                                x0=res_reduced.x,
                                tol=float(tol),
                                atol=float(atol),
                                restart=int(scipy_restart),
                                maxiter=int(scipy_maxiter),
                                precondition_side=gmres_precond_side,
                            )
                        x_scipy = jnp.asarray(x_np, dtype=jnp.float64)
                        r_scipy = rhs_reduced - mv_reduced(x_scipy)
                        res_scipy = GMRESSolveResult(x=x_scipy, residual_norm=jnp.linalg.norm(r_scipy))
                        if float(res_scipy.residual_norm) < float(res_reduced.residual_norm):
                            if emit is not None:
                                emit(
                                    1,
                                    "solve_v3_full_system_linear_gmres: SciPy rescue improved residual "
                                    f"{float(res_reduced.residual_norm):.3e} -> {float(res_scipy.residual_norm):.3e}",
                                )
                            res_reduced = res_scipy
                    except Exception as exc:  # noqa: BLE001
                        if emit is not None:
                            emit(1, f"solve_v3_full_system_linear_gmres: SciPy rescue failed ({type(exc).__name__}: {exc})")
        if use_pas_projection:
            f_full = _expand_active_f(res_reduced.x)
            f_full = _project_pas_f(f_full)
            if int(op.extra_size) > 0:
                zeros_extra = jnp.zeros((int(op.extra_size),), dtype=jnp.float64)
                y_full = mv(jnp.concatenate([f_full, zeros_extra], axis=0))
                r_f = rhs[: op.f_size] - y_full[: op.f_size]
                extra = _constraint_scheme2_source_from_f(op, r_f.reshape(op.fblock.f_shape)) / fs_sum_safe
                if ix0 > 0:
                    extra = extra.at[:, :ix0].set(0.0)
                zero_env = os.environ.get("SFINCS_JAX_PAS_SOURCE_ZERO_TOL", "").strip()
                try:
                    zero_tol = float(zero_env) if zero_env else 2e-9
                except ValueError:
                    zero_tol = 2e-9
                if zero_tol > 0.0:
                    max_abs = jnp.max(jnp.abs(extra))
                    extra = jnp.where(max_abs <= zero_tol, jnp.zeros_like(extra), extra)
                x_full = jnp.concatenate([f_full, extra.reshape((-1,))], axis=0)
            else:
                x_full = f_full
        else:
            x_full = expand_reduced(res_reduced.x)
        # Residuals in active-DOF mode are computed on the reduced system to avoid an
        # extra full matvec; this matches the reduced KSP system used upstream.
        residual_norm_full = res_reduced.residual_norm
        result = GMRESSolveResult(x=x_full, residual_norm=residual_norm_full)
    else:
        if solve_method_kind == "dense_ksp":
            if int(op.phi1_size) != 0:
                raise NotImplementedError("dense_ksp is only supported for includePhi1=false RHSMode=1 solves.")
            if emit is not None:
                emit(1, "solve_v3_full_system_linear_gmres: assembling dense full matrix for dense_ksp")
            a_dense = assemble_dense_matrix_from_matvec(matvec=mv, n=int(op.total_size), dtype=rhs.dtype)

            if emit is not None:
                emit(1, "solve_v3_full_system_linear_gmres: building PETSc-like species-block preconditioner (dense_ksp)")

            import jax.scipy.linalg as jla  # noqa: PLC0415

            n_species = int(op.n_species)
            n_theta = int(op.n_theta)
            n_zeta = int(op.n_zeta)
            local_per_species = int(np.sum(nxi_for_x))
            dke_size = int(local_per_species * n_theta * n_zeta)
            extra_size = int(op.extra_size)
            extra_per_species = int(extra_size // max(1, n_species)) if extra_size else 0
            if extra_size and (extra_per_species * n_species != extra_size):
                extra_per_species = 0

            f_size = int(n_species * dke_size)
            expected_size = int(f_size + int(op.phi1_size) + extra_size)
            if int(op.total_size) != expected_size:
                raise RuntimeError(f"dense_ksp expects total_size={expected_size}, got {int(op.total_size)}")

            lu_factors: list[tuple[jnp.ndarray, jnp.ndarray]] = []
            idx_blocks: list[jnp.ndarray] = []
            for s in range(n_species):
                f_idx = np.arange(s * dke_size, (s + 1) * dke_size, dtype=np.int32)
                extra_idx = np.arange(
                    f_size + s * extra_per_species,
                    f_size + (s + 1) * extra_per_species,
                    dtype=np.int32,
                )
                block_idx_np = np.concatenate([f_idx, extra_idx], axis=0) if extra_per_species else f_idx
                block_idx = jnp.asarray(block_idx_np, dtype=jnp.int32)
                a_block = a_dense[jnp.ix_(block_idx, block_idx)]
                lu, piv = jla.lu_factor(a_block)
                lu_factors.append((lu, piv))
                idx_blocks.append(block_idx)

            def preconditioner_dense(v: jnp.ndarray) -> jnp.ndarray:
                out = jnp.zeros_like(v)
                for block_idx, (lu, piv) in zip(idx_blocks, lu_factors, strict=True):
                    rhs_block = v[block_idx]
                    sol_block = jla.lu_solve((lu, piv), rhs_block)
                    out = out.at[block_idx].set(sol_block, unique_indices=True)
                return out

            def mv_dense(x: jnp.ndarray) -> jnp.ndarray:
                return a_dense @ x

            rhs_pc = preconditioner_dense(rhs)

            def mv_pc(x: jnp.ndarray) -> jnp.ndarray:
                return preconditioner_dense(mv_dense(x))

            res_pc = _solve_linear(
                matvec_fn=mv_pc,
                b_vec=rhs_pc,
                precond_fn=None,
                x0_vec=x0,
                tol_val=tol,
                atol_val=atol,
                restart_val=restart,
                maxiter_val=maxiter,
                solve_method_val="incremental",
                precond_side="none",
            )
            ksp_matvec = mv_pc
            ksp_b = rhs_pc
            ksp_precond = None
            ksp_x0 = x0
            ksp_precond_side = "none"
            ksp_solver_kind = _solver_kind("incremental")[0]
            residual_norm_full = jnp.linalg.norm(mv(res_pc.x) - rhs)
            result = GMRESSolveResult(x=res_pc.x, residual_norm=residual_norm_full)
        else:
            preconditioner_full = None
            bicgstab_preconditioner_full = None
            host_dense_shortcut_full = _rhsmode1_host_dense_shortcut_allowed(
                op=op,
                active_size=int(op.total_size),
                use_implicit=bool(use_implicit),
                solve_method_kind=str(solve_method_kind),
            )

            def _solve_host_dense_full(*, x0_dense: jnp.ndarray | None = None) -> tuple[GMRESSolveResult, jnp.ndarray]:
                import scipy.linalg as sla  # noqa: PLC0415

                a_dense_jnp = assemble_dense_matrix_from_matvec(matvec=mv, n=int(op.total_size), dtype=rhs.dtype)
                a_np = np.asarray(a_dense_jnp, dtype=np.float64)
                a_np = np.array(a_np, dtype=np.float64, copy=True)
                if a_np.ndim != 2:
                    a_np = np.squeeze(a_np)
                if a_np.ndim != 2 or a_np.shape[0] != a_np.shape[1]:
                    x_np = np.asarray(
                        np.linalg.lstsq(a_np, np.asarray(rhs, dtype=np.float64), rcond=None)[0],
                        dtype=np.float64,
                    )
                else:
                    lu, piv = sla.lu_factor(a_np)
                    x_np = np.asarray(sla.lu_solve((lu, piv), np.asarray(rhs, dtype=np.float64)), dtype=np.float64)
                if x0_dense is not None and x0_dense.shape == rhs.shape:
                    x_np = x_np + 0.0 * np.asarray(x0_dense, dtype=np.float64)
                x_dense = jnp.asarray(x_np, dtype=jnp.float64)
                residual_vec_dense = rhs - mv(x_dense)
                return (
                    GMRESSolveResult(x=x_dense, residual_norm=jnp.linalg.norm(residual_vec_dense)),
                    residual_vec_dense,
                )

            if rhs1_bicgstab_kind is not None:
                if emit is not None:
                    emit(1, f"solve_v3_full_system_linear_gmres: RHSMode=1 BiCGStab preconditioner={rhs1_bicgstab_kind}")
                if rhs1_bicgstab_kind == "collision":
                    bicgstab_preconditioner_full = _build_rhsmode1_collision_preconditioner(op=op)

            def _build_rhs1_preconditioner_full():
                _mark("rhs1_precond_build_start")
                if emit is not None:
                    emit(1, f"solve_v3_full_system_linear_gmres: building RHSMode=1 preconditioner={rhs1_precond_kind}")
                    rhs1_progress_notes.preconditioner_build(rhs1_precond_kind)
                sweeps_env = os.environ.get("SFINCS_JAX_RHSMODE1_ADI_SWEEPS", "").strip()
                try:
                    sweeps = int(sweeps_env) if sweeps_env else 2
                except ValueError:
                    sweeps = 2
                lmax_use = rhs1_xblock_tz_lmax or 0
                if rhs1_precond_kind == "xblock_tz_lmax" and lmax_use <= 0:
                    lmax_env = os.environ.get("SFINCS_JAX_RHSMODE1_XBLOCK_TZ_LMAX", "").strip()
                    try:
                        lmax_use = int(lmax_env) if lmax_env else 0
                    except ValueError:
                        lmax_use = 0
                precond = _build_rhs1_preconditioner_from_kind(
                    op=op,
                    rhs1_precond_kind=rhs1_precond_kind,
                    preconditioner_species=preconditioner_species,
                    preconditioner_x=preconditioner_x,
                    preconditioner_xi=preconditioner_xi,
                    rhs1_xblock_tz_lmax=lmax_use,
                    dd_block_theta=_parse_rhs1_dd_block("theta"),
                    dd_overlap_theta=_parse_rhs1_dd_overlap("theta", default=1 if rhs1_precond_kind == "theta_schwarz" else 0),
                    dd_block_zeta=_parse_rhs1_dd_block("zeta"),
                    dd_overlap_zeta=_parse_rhs1_dd_overlap("zeta", default=1 if rhs1_precond_kind == "zeta_schwarz" else 0),
                    adi_sweeps=max(1, sweeps),
                    emit=emit,
                )
                _mark("rhs1_precond_build_done")
                return precond

            if rhs1_precond_enabled and (not host_dense_shortcut_full):
                solver_kind = _solver_kind(solve_method)[0]
                build_rhs1 = (
                    (solver_kind != "bicgstab" and solve_method_kind != "dense")
                    or (rhs1_bicgstab_kind == "rhs1" and solve_method_kind != "dense")
                )
                if build_rhs1:
                    preconditioner_full = _build_rhs1_preconditioner_full()
                    if rhs1_bicgstab_kind == "rhs1":
                        bicgstab_preconditioner_full = preconditioner_full
            if (not host_dense_shortcut_full) and preconditioner_full is None and bicgstab_preconditioner_full is not None:
                preconditioner_full = bicgstab_preconditioner_full
            if (not host_dense_shortcut_full) and preconditioner_full is not None and rhs1_precond_kind in {
                "pas_hybrid",
                "pas_lite",
                "pas_tz",
                "pas_schur",
                "pas_tokamak_theta",
                "pas_ilu",
            }:
                try:
                    probe = preconditioner_full(rhs)
                    probe_ok = bool(jnp.all(jnp.isfinite(probe)))
                except Exception as exc:  # noqa: BLE001
                    probe_ok = False
                    if emit is not None:
                        emit(
                            1,
                            "solve_v3_full_system_linear_gmres: PAS precond probe failed "
                            f"({type(exc).__name__}: {exc}), using collision preconditioner",
                        )
                if not probe_ok:
                    preconditioner_full = _build_rhsmode1_collision_preconditioner(op=op)
                    if rhs1_bicgstab_kind == "rhs1":
                        bicgstab_preconditioner_full = preconditioner_full
                    if emit is not None:
                        emit(
                            1,
                            "solve_v3_full_system_linear_gmres: PAS precond non-finite -> collision",
                        )
            if host_dense_shortcut_full:
                _mark("rhs1_host_dense_shortcut_start")
                if emit is not None:
                    emit(
                        0,
                        "solve_v3_full_system_linear_gmres: accelerator FP small system -> "
                        f"using host dense shortcut (size={int(op.total_size)})",
                    )
                result, residual_vec = _solve_host_dense_full(x0_dense=x0)
                _mark("rhs1_host_dense_shortcut_done")
                ksp_matvec = mv
                ksp_b = rhs
                ksp_precond = None
                ksp_x0 = x0
                ksp_precond_side = "none"
                ksp_solver_kind = _solver_kind("incremental")[0]
            if recycle_basis_use and (not host_dense_shortcut_full):
                basis_full: list[jnp.ndarray] = []
                for vec in recycle_basis_use:
                    if vec.shape == (op.total_size,):
                        basis_full.append(vec)
                if basis_full:
                    basis_au = [mv(v) for v in basis_full]
                    x0_recycled = _recycled_initial_guess(rhs, basis_full, basis_au)
                    if x0_recycled is not None:
                        if x0 is None:
                            x0 = x0_recycled
                        else:
                            r0 = jnp.linalg.norm(mv(jnp.asarray(x0)) - rhs)
                            r1 = jnp.linalg.norm(mv(x0_recycled) - rhs)
                            if jnp.isfinite(r1) and (not jnp.isfinite(r0) or float(r1) < float(r0)):
                                x0 = x0_recycled
            if not host_dense_shortcut_full:
                rhs1_progress_notes.krylov_start()
                _mark("rhs1_krylov_solve_start")
                result, residual_vec = _solve_linear_with_residual(
                    matvec_fn=mv,
                    b_vec=rhs,
                    precond_fn=preconditioner_full,
                    x0_vec=x0,
                    tol_val=tol,
                    atol_val=atol,
                    restart_val=restart,
                    maxiter_val=maxiter,
                    solve_method_val=solve_method,
                    precond_side=gmres_precond_side,
                )
                result = _block_gmres_result_ready(result)
                try:
                    jax.block_until_ready(residual_vec)
                except Exception:
                    pass
                _mark("rhs1_krylov_solve_done")
                ksp_matvec = mv
                ksp_b = rhs
                ksp_precond = preconditioner_full
                ksp_x0 = x0
                ksp_precond_side = gmres_precond_side
                ksp_solver_kind = _solver_kind(solve_method)[0]
            if (not host_dense_shortcut_full) and preconditioner_full is not None and (not _gmres_result_is_finite(result)):
                if emit is not None:
                    emit(0, "solve_v3_full_system_linear_gmres: preconditioned GMRES returned non-finite result; retrying without preconditioner")
                _mark("rhs1_krylov_solve_retry_start")
                result, residual_vec = _solve_linear_with_residual(
                    matvec_fn=mv,
                    b_vec=rhs,
                    precond_fn=None,
                    x0_vec=x0,
                    tol_val=tol,
                    atol_val=atol,
                    restart_val=restart,
                    maxiter_val=maxiter,
                    solve_method_val=solve_method,
                    precond_side=gmres_precond_side,
                )
                result = _block_gmres_result_ready(result)
                try:
                    jax.block_until_ready(residual_vec)
                except Exception:
                    pass
                _mark("rhs1_krylov_solve_retry_done")
                ksp_matvec = mv
                ksp_b = rhs
                ksp_precond = None
                ksp_x0 = x0
                ksp_precond_side = gmres_precond_side
                ksp_solver_kind = _solver_kind(solve_method)[0]
            # If GMRES does not reach the requested tolerance (common without preconditioning),
            # retry with a larger iteration budget and the more robust incremental mode.
            target = max(float(atol), float(tol) * float(rhs_norm))
            res_ratio = float(result.residual_norm) / max(float(target), 1e-300)
            stage2_trigger = rhs1_stage2_trigger(
                res_ratio=res_ratio,
                use_dkes=bool(op.fblock.pas is not None and use_dkes),
            )
            solver_kind = _solver_kind(solve_method)[0]
            bicgstab_fallback_target = float(target)
            if bicgstab_fallback_strict:
                fallback_floor_env = os.environ.get("SFINCS_JAX_BICGSTAB_FALLBACK_ABS_FLOOR", "").strip()
                default_floor = 0.0
                if distributed_axis is not None and op.fblock.pas is not None and (not bool(op.include_phi1)):
                    default_floor = 1.0e-7
                try:
                    fallback_floor = float(fallback_floor_env) if fallback_floor_env else default_floor
                except ValueError:
                    fallback_floor = default_floor
                bicgstab_fallback_target = max(float(target), max(0.0, float(fallback_floor)))
            if solver_kind == "bicgstab" and (
                (not _gmres_result_is_finite(result))
                or (bicgstab_fallback_strict and float(result.residual_norm) > bicgstab_fallback_target)
            ):
                if emit is not None:
                    emit(
                        0,
                        "solve_v3_full_system_linear_gmres: BiCGStab fallback to GMRES "
                        f"(residual={float(result.residual_norm):.3e} > target={bicgstab_fallback_target:.3e})",
                    )
                if preconditioner_full is None and rhs1_precond_enabled:
                    preconditioner_full = _build_rhs1_preconditioner_full()
                result, residual_vec = _solve_linear_with_residual(
                    matvec_fn=mv,
                    b_vec=rhs,
                    precond_fn=preconditioner_full,
                    x0_vec=x0,
                    tol_val=tol,
                    atol_val=atol,
                    restart_val=restart,
                    maxiter_val=maxiter,
                    solve_method_val="incremental",
                    precond_side=gmres_precond_side,
                )
                ksp_matvec = mv
                ksp_b = rhs
                ksp_precond = preconditioner_full
                ksp_x0 = x0
                ksp_precond_side = gmres_precond_side
                ksp_solver_kind = "gmres"
        # The full-size RHSMode=1 branch does not have the later active-DOF sparse
        # ILU rescue. On accelerators, skipping stage2 GMRES here can therefore
        # return a high-residual solution with no real recovery path.
        prefer_sparse_accel = False
        if prefer_sparse_accel and float(result.residual_norm) > target and stage2_trigger and emit is not None:
            emit(
                0,
                "solve_v3_full_system_linear_gmres: skipping stage2 GMRES on accelerator "
                "backend; prefer sparse fallback",
            )
        if (
            float(result.residual_norm) > target
            and stage2_enabled
            and stage2_trigger
            and (not prefer_sparse_accel)
            and t.elapsed_s() < stage2_time_cap_s
        ):
            if preconditioner_full is None and rhs1_precond_enabled:
                preconditioner_full = _build_rhs1_preconditioner_full()
            stage2_maxiter_env = os.environ.get("SFINCS_JAX_LINEAR_STAGE2_MAXITER", "").strip()
            stage2_restart_env = os.environ.get("SFINCS_JAX_LINEAR_STAGE2_RESTART", "").strip()
            stage2_maxiter = int(stage2_maxiter_env or str(max(600, int(maxiter or 400) * 2)))
            stage2_restart = int(stage2_restart_env or str(max(120, int(restart))))
            if (
                op.fblock.fp is not None
                and op.fblock.pas is None
                and int(op.total_size) >= 300000
                and (not stage2_maxiter_env)
            ):
                stage2_maxiter = min(int(stage2_maxiter), 600)
            if (
                op.fblock.fp is not None
                and op.fblock.pas is None
                and int(op.total_size) >= 300000
                and (not stage2_restart_env)
            ):
                stage2_restart = min(max(80, int(stage2_restart)), 100)
            stage2_method = os.environ.get("SFINCS_JAX_LINEAR_STAGE2_METHOD", "incremental").strip().lower()
            if stage2_method not in {"batched", "incremental", "dense"}:
                stage2_method = "incremental"
            if emit is not None:
                emit(
                    0,
                    "solve_v3_full_system_linear_gmres: stage2 GMRES "
                    f"(residual={float(result.residual_norm):.3e} > target={target:.3e}) "
                    f"restart={stage2_restart} maxiter={stage2_maxiter} method={stage2_method}",
                )
            stage2_timer = Timer()
            res2, residual_vec2 = _solve_linear_with_residual(
                matvec_fn=mv,
                b_vec=rhs,
                precond_fn=preconditioner_full,
                x0_vec=result.x,
                tol_val=tol,
                atol_val=atol,
                restart_val=stage2_restart,
                maxiter_val=stage2_maxiter,
                solve_method_val=stage2_method,
                precond_side=gmres_precond_side,
            )
            stage2_elapsed_s = stage2_timer.elapsed_s()
            result, residual_vec, handoff_state, _accepted = rhs1_accept_candidate(
                current_result=result,
                candidate_result=res2,
                current_residual_vec=residual_vec,
                candidate_residual_vec=residual_vec2,
                matvec_fn=mv,
                b_vec=rhs,
                precond_fn=preconditioner_full,
                x0_vec=res2.x,
                restart=stage2_restart,
                maxiter=stage2_maxiter,
                precond_side=gmres_precond_side,
                solver_kind=_solver_kind(stage2_method)[0],
                candidate_metrics=_rhs1_solver_candidate_metrics(
                    name=f"stage2_full:{stage2_method}",
                    result=res2,
                    target_value=target,
                    solve_s=stage2_elapsed_s,
                ),
                baseline_metrics=_rhs1_solver_candidate_metrics(
                    name="current_full",
                    result=result,
                    target_value=target,
                ),
            )
            _apply_rhs1_handoff(handoff_state)
        # Krylov solvers with left preconditioning report the preconditioned residual
        # norm. Recompute the true residual before deciding whether to escalate to a
        # stronger preconditioner or dense fallback so those decisions track the
        # printed residual and H5 parity behavior.
        try:
            residual_vec_true = residual_vec if residual_vec is not None else rhs - mv(result.x)
            residual_norm_true = float(jnp.linalg.norm(residual_vec_true))
            if np.isfinite(residual_norm_true):
                result = GMRESSolveResult(x=result.x, residual_norm=jnp.asarray(residual_norm_true, dtype=jnp.float64))
                residual_vec = residual_vec_true
        except Exception:
            pass
        pas_fast_accept = _rhsmode1_pas_fast_accept(
            op=op,
            active_size=int(op.total_size),
            residual_norm=float(result.residual_norm),
            target=float(target),
            use_implicit=bool(use_implicit),
        )
        res_ratio = float(result.residual_norm) / max(float(target), 1e-300)
        strong_ratio_env = os.environ.get("SFINCS_JAX_RHSMODE1_STRONG_PRECOND_RATIO", "").strip()
        try:
            strong_ratio = float(strong_ratio_env) if strong_ratio_env else 1.0
        except ValueError:
            strong_ratio = 1.0
        strong_precond_trigger = bool(res_ratio > strong_ratio) if strong_ratio > 0 else True
        if (
            rhs1_precond_kind in {"pas_lite", "pas_hybrid", "pas_tz", "pas_schur", "pas_tokamak_theta"}
            and preconditioner_full is not None
            and _rhsmode1_pas_adaptive_smoother_allowed(
                op=op,
                active_size=int(op.total_size),
                residual_norm=float(result.residual_norm),
                target=float(target),
                use_implicit=bool(use_implicit),
            )
        ):
            smoother_max_env = os.environ.get("SFINCS_JAX_PAS_ADAPTIVE_SMOOTHER_SWEEPS", "").strip()
            smoother_omega_env = os.environ.get("SFINCS_JAX_PAS_ADAPTIVE_SMOOTHER_OMEGA", "").strip()
            try:
                smoother_max = int(smoother_max_env) if smoother_max_env else 3
            except ValueError:
                smoother_max = 3
            try:
                smoother_omega = float(smoother_omega_env) if smoother_omega_env else 1.0
            except ValueError:
                smoother_omega = 1.0
            smoother = adaptive_pas_smoother(
                matvec=mv,
                rhs=rhs,
                preconditioner=preconditioner_full,
                x0=result.x,
                target=float(target),
                omega=float(smoother_omega),
                max_sweeps=int(smoother_max),
            )
            if float(smoother.residual_norm) < float(result.residual_norm):
                if emit is not None:
                    emit(
                        1,
                        "solve_v3_full_system_linear_gmres: PAS adaptive smoother "
                        f"accepted {int(smoother.accepted_sweeps)} sweep(s), "
                        f"reason={smoother.stop_reason}, "
                        f"residual={float(result.residual_norm):.3e}->{float(smoother.residual_norm):.3e}",
                    )
                smoother_result = GMRESSolveResult(
                    x=smoother.x,
                    residual_norm=jnp.asarray(smoother.residual_norm, dtype=jnp.float64),
                )
                result, residual_vec, handoff_state, _accepted = rhs1_accept_candidate(
                    current_result=result,
                    candidate_result=smoother_result,
                    current_residual_vec=residual_vec,
                    candidate_residual_vec=rhs - mv(smoother_result.x),
                    matvec_fn=mv,
                    b_vec=rhs,
                    precond_fn=preconditioner_full,
                    x0_vec=smoother_result.x,
                    restart=restart,
                    maxiter=maxiter,
                    precond_side=gmres_precond_side,
                    solver_kind=_solver_kind("incremental")[0],
                )
                _apply_rhs1_handoff(handoff_state)
        if (
            float(result.residual_norm) > target
            and int(op.rhs_mode) == 1
            and (not bool(op.include_phi1))
            and rhs1_precond_kind == "point"
            and (op.fblock.fp is not None or op.fblock.pas is not None)
            and strong_precond_trigger
        ):
            if bicgstab_preconditioner_full is None:
                bicgstab_preconditioner_full = _build_rhsmode1_collision_preconditioner(op=op)
            if bicgstab_preconditioner_full is not None:
                if emit is not None:
                    emit(
                        0,
                        "solve_v3_full_system_linear_gmres: retry with collision preconditioner "
                        f"(residual={float(result.residual_norm):.3e} > target={target:.3e})",
                    )
                res_collision, residual_vec_collision = _solve_linear_with_residual(
                    matvec_fn=mv,
                    b_vec=rhs,
                    precond_fn=bicgstab_preconditioner_full,
                    x0_vec=result.x,
                    tol_val=tol,
                    atol_val=atol,
                    restart_val=restart,
                    maxiter_val=maxiter,
                    solve_method_val="incremental",
                    precond_side=gmres_precond_side,
                )
                result, residual_vec, handoff_state, _accepted = rhs1_accept_candidate(
                    current_result=result,
                    candidate_result=res_collision,
                    current_residual_vec=residual_vec,
                    candidate_residual_vec=residual_vec_collision,
                    matvec_fn=mv,
                    b_vec=rhs,
                    precond_fn=bicgstab_preconditioner_full,
                    x0_vec=res_collision.x,
                    restart=restart,
                    maxiter=maxiter,
                    precond_side=gmres_precond_side,
                    solver_kind=_solver_kind("incremental")[0],
                )
                _apply_rhs1_handoff(handoff_state)
        strong_precond_env = os.environ.get("SFINCS_JAX_RHSMODE1_STRONG_PRECOND", "").strip().lower()
        cs0_sparse_first = _rhsmode1_constraint0_sparse_first(
            op=op,
            solve_method_kind=solve_method_kind,
            sparse_precond_mode=sparse_precond_mode,
            active_size=int(active_size),
            sparse_max_size=int(sparse_max_size),
        )
        strong_control = rhs1_resolved_strong_preconditioner_control(
            strong_precond_env=strong_precond_env,
            has_extra_constraint_block=int(op.constraint_scheme) == 2 and int(op.extra_size) > 0,
            has_fp=op.fblock.fp is not None,
            has_pas=op.fblock.pas is not None,
            size=int(op.total_size),
            n_theta=int(op.n_theta),
            n_zeta=int(op.n_zeta),
            cs0_sparse_first=bool(cs0_sparse_first),
            pas_auto_skip=_pas_auto_skip_strong_retry(
                has_pas=op.fblock.pas is not None,
                strong_precond_env=strong_precond_env,
                rhs1_precond_kind=rhs1_precond_kind,
                residual_norm=float(result.residual_norm),
                target=float(target),
                ratio=float(pas_auto_strong_ratio),
            ),
            pas_fast_accept=bool(pas_fast_accept),
        )
        strong_precond_min = int(strong_control.min_size)
        strong_precond_disabled = bool(strong_control.disabled)
        strong_precond_auto = bool(strong_control.auto)
        if strong_control.reason_cs0_sparse_first and emit is not None:
            emit(
                1,
                "solve_v3_full_system_linear_gmres: constraintScheme=0 sparse-first "
                "auto mode -> defer strong preconditioner until after sparse ILU",
            )
        if strong_control.reason_pas_auto_skip and emit is not None:
            emit(
                1,
                "solve_v3_full_system_linear_gmres: PAS auto strong preconditioner skipped "
                f"after base={rhs1_precond_kind} "
                f"(residual={float(result.residual_norm):.3e} <= {float(pas_auto_strong_ratio):.1f}x target)",
            )
        if strong_control.reason_pas_fast_accept and emit is not None:
            emit(
                1,
                "solve_v3_full_system_linear_gmres: PAS fast-accept "
                f"(residual={float(result.residual_norm):.3e}) -> skip strong preconditioner tail",
            )
        strong_precond_kind: str | None = None
        strong_xblock_tz_lmax: int | None = None
        if strong_precond_disabled:
            strong_precond_kind = None
        else:
            strong_precond_kind = requested_rhs1_strong_preconditioner_kind(
                strong_precond_env,
                mode="full",
            )

        if strong_precond_kind is None and (not strong_precond_disabled) and strong_precond_auto:
            if int(op.constraint_scheme) == 2 and int(op.extra_size) > 0:
                if op.fblock.pas is not None:
                    auto_sel = auto_rhs1_full_strong_kind(
                        has_pas=True,
                        has_fp=False,
                        rhs1_precond_kind=rhs1_precond_kind,
                        total_size=int(op.total_size),
                        strong_precond_min=int(strong_precond_min),
                        n_theta=int(op.n_theta),
                        n_zeta=int(op.n_zeta),
                        max_l=int(np.max(nxi_for_x)) if nxi_for_x.size else 0,
                        shard_axis=_matvec_shard_axis(op),
                        device_count=int(jax.device_count()),
                    )
                    strong_precond_kind = auto_sel.kind
                else:
                    strong_precond_kind = "schur"
            else:
                auto_sel = auto_rhs1_full_strong_kind(
                    has_pas=op.fblock.pas is not None,
                    has_fp=op.fblock.fp is not None,
                    rhs1_precond_kind=rhs1_precond_kind,
                    total_size=int(op.total_size),
                    strong_precond_min=int(strong_precond_min),
                    n_theta=int(op.n_theta),
                    n_zeta=int(op.n_zeta),
                    max_l=int(np.max(nxi_for_x)) if nxi_for_x.size else 0,
                    shard_axis=_matvec_shard_axis(op),
                    device_count=int(jax.device_count()),
                )
                strong_precond_kind = auto_sel.kind
                strong_xblock_tz_lmax = auto_sel.xblock_tz_lmax

        auto_sel = adjust_rhs1_reduced_auto_kind(
            kind=strong_precond_kind,
            has_pas=op.fblock.pas is not None,
            geom_scheme=int(geom_scheme),
            n_zeta=int(op.n_zeta),
            strong_precond_trigger=True,
            max_l=int(np.max(nxi_for_x)) if nxi_for_x.size else 0,
            n_theta=int(op.n_theta),
        )
        strong_precond_kind = auto_sel.kind
        if auto_sel.xblock_tz_lmax is not None:
            strong_xblock_tz_lmax = auto_sel.xblock_tz_lmax

        auto_sel = adjust_rhs1_theta_line_auto_kind(
            kind=strong_precond_kind,
            n_theta=int(op.n_theta),
            nxi_for_x_sum=int(np.sum(nxi_for_x)) if nxi_for_x.size else 0,
        )
        strong_precond_kind = auto_sel.kind

        if strong_precond_kind is not None and _rhs1_residual_needs_rescue(
            float(result.residual_norm),
            float(target),
        ):
            dd_block_theta = _parse_rhs1_dd_block("theta")
            dd_overlap_theta = _parse_rhs1_dd_overlap("theta", default=1)
            dd_block_zeta = _parse_rhs1_dd_block("zeta")
            dd_overlap_zeta = _parse_rhs1_dd_overlap("zeta", default=1)
            sweeps_env = os.environ.get("SFINCS_JAX_RHSMODE1_ADI_SWEEPS", "").strip()
            try:
                adi_sweeps = int(sweeps_env) if sweeps_env else 2
            except ValueError:
                adi_sweeps = 2
            adi_sweeps = max(1, int(adi_sweeps))
            strong_precond_kind, strong_preconditioner_full = _build_rhs1_strong_preconditioner_full_from_kind(
                op=op,
                strong_precond_kind=strong_precond_kind,
                rhs1_precond_kind=rhs1_precond_kind,
                residual_norm=float(result.residual_norm),
                dd_block_theta=dd_block_theta,
                dd_overlap_theta=dd_overlap_theta,
                dd_block_zeta=dd_block_zeta,
                dd_overlap_zeta=dd_overlap_zeta,
                adi_sweeps=adi_sweeps,
            )
        if strong_precond_kind is not None and _rhs1_residual_needs_rescue(
            float(result.residual_norm),
            float(target),
        ):
            _mark("rhs1_strong_precond_build_start")
            if emit is not None:
                emit(
                    0,
                    "solve_v3_full_system_linear_gmres: strong preconditioner fallback "
                    f"kind={strong_precond_kind} (residual={float(result.residual_norm):.3e} > target={target:.3e})",
                )
            _mark("rhs1_strong_precond_build_done")

            strong_restart_env = os.environ.get("SFINCS_JAX_RHSMODE1_STRONG_PRECOND_RESTART", "").strip()
            strong_maxiter_env = os.environ.get("SFINCS_JAX_RHSMODE1_STRONG_PRECOND_MAXITER", "").strip()
            try:
                strong_restart = int(strong_restart_env) if strong_restart_env else max(120, int(restart))
            except ValueError:
                strong_restart = max(120, int(restart))
            try:
                strong_maxiter = int(strong_maxiter_env) if strong_maxiter_env else max(800, int(maxiter or 400) * 2)
            except ValueError:
                strong_maxiter = max(800, int(maxiter or 400) * 2)
            strong_timer = Timer()
            res_strong, residual_vec_strong = _solve_linear_with_residual(
                matvec_fn=mv,
                b_vec=rhs,
                precond_fn=strong_preconditioner_full,
                x0_vec=result.x,
                tol_val=tol,
                atol_val=atol,
                restart_val=strong_restart,
                maxiter_val=strong_maxiter,
                solve_method_val="incremental",
                precond_side=gmres_precond_side,
            )
            strong_elapsed_s = strong_timer.elapsed_s()
            result, residual_vec, handoff_state, _accepted = rhs1_accept_candidate(
                current_result=result,
                candidate_result=res_strong,
                current_residual_vec=residual_vec,
                candidate_residual_vec=residual_vec_strong,
                matvec_fn=mv,
                b_vec=rhs,
                precond_fn=strong_preconditioner_full,
                x0_vec=res_strong.x,
                restart=strong_restart,
                maxiter=strong_maxiter,
                precond_side=gmres_precond_side,
                solver_kind=_solver_kind("incremental")[0],
                candidate_metrics=_rhs1_solver_candidate_metrics(
                    name="strong_full",
                    result=res_strong,
                    target_value=target,
                    solve_s=strong_elapsed_s,
                ),
                baseline_metrics=_rhs1_solver_candidate_metrics(
                    name="current_full",
                    result=result,
                    target_value=target,
                ),
            )
            _apply_rhs1_handoff(handoff_state)
        if (
            int(op.rhs_mode) == 1
            and (not bool(op.include_phi1))
            and op.fblock.pas is not None
            and int(op.n_species) >= 2
            and np.isfinite(float(result.residual_norm))
        ):
            rescue_ratio_env = os.environ.get("SFINCS_JAX_RHSMODE1_PAS_SCHUR_RESCUE_RATIO", "").strip()
            rescue_max_env = os.environ.get("SFINCS_JAX_RHSMODE1_PAS_SCHUR_RESCUE_MAX", "").strip()
            try:
                rescue_ratio = float(rescue_ratio_env) if rescue_ratio_env else 1.0e4
            except ValueError:
                rescue_ratio = 1.0e4
            try:
                rescue_max = int(rescue_max_env) if rescue_max_env else 90000
            except ValueError:
                rescue_max = 90000
            if (
                rescue_ratio > 0.0
                and int(active_size) <= max(1, int(rescue_max))
                and float(result.residual_norm) > float(target) * float(rescue_ratio)
            ):
                if emit is not None:
                    emit(
                        0,
                        "solve_v3_full_system_linear_gmres: PAS Schur rescue "
                        f"(residual={float(result.residual_norm):.3e} > {float(target)*float(rescue_ratio):.3e})",
                    )
                try:
                    schur_precond = _build_rhsmode1_schur_preconditioner(op=op)
                    rescue_restart_env = os.environ.get("SFINCS_JAX_RHSMODE1_PAS_SCHUR_RESCUE_RESTART", "").strip()
                    rescue_maxiter_env = os.environ.get("SFINCS_JAX_RHSMODE1_PAS_SCHUR_RESCUE_MAXITER", "").strip()
                    try:
                        rescue_restart = int(rescue_restart_env) if rescue_restart_env else max(120, int(restart))
                    except ValueError:
                        rescue_restart = max(120, int(restart))
                    try:
                        rescue_maxiter = (
                            int(rescue_maxiter_env) if rescue_maxiter_env else max(1200, int(maxiter or 400) * 3)
                        )
                    except ValueError:
                        rescue_maxiter = max(1200, int(maxiter or 400) * 3)
                    res_schur, residual_vec_schur = _solve_linear_with_residual(
                        matvec_fn=mv,
                        b_vec=rhs,
                        precond_fn=schur_precond,
                        x0_vec=result.x,
                        tol_val=tol,
                        atol_val=atol,
                        restart_val=rescue_restart,
                        maxiter_val=rescue_maxiter,
                        solve_method_val="incremental",
                        precond_side=gmres_precond_side,
                    )
                    result, residual_vec, handoff_state, _accepted = rhs1_accept_candidate(
                        current_result=result,
                        candidate_result=res_schur,
                        current_residual_vec=residual_vec,
                        candidate_residual_vec=residual_vec_schur,
                        matvec_fn=mv,
                        b_vec=rhs,
                        precond_fn=schur_precond,
                        x0_vec=res_schur.x,
                        restart=rescue_restart,
                        maxiter=rescue_maxiter,
                        precond_side=gmres_precond_side,
                        solver_kind=_solver_kind("incremental")[0],
                    )
                    _apply_rhs1_handoff(handoff_state)
                except Exception as exc:  # noqa: BLE001
                    if emit is not None:
                        emit(1, f"solve_v3_full_system_linear_gmres: PAS Schur rescue failed ({type(exc).__name__}: {exc})")
        large_cpu_sparse_rescue_full = _rhsmode1_large_cpu_sparse_rescue_allowed(
            op=op,
            solve_method_kind=solve_method_kind,
            active_size=int(op.total_size),
            sparse_max_size=int(sparse_max_size),
            preconditioner_x=int(preconditioner_x),
            residual_norm=float(result.residual_norm),
            target=float(target),
        )

        sparse_exact_direct = _rhsmode1_host_sparse_direct_allowed(
            sparse_exact_lu=sparse_exact_lu,
            use_implicit=bool(use_implicit),
        )
        sparse_enabled = rhs1_sparse_enabled_initial(
            sparse_precond_mode=sparse_precond_mode,
            has_fp=op.fblock.fp is not None,
            has_pas=op.fblock.pas is not None,
            residual_norm=float(result.residual_norm),
            target=float(target),
            rhs_mode=int(op.rhs_mode),
            include_phi1=bool(op.include_phi1),
        )
        sparse_kind_use = rhs1_sparse_kind_use(sparse_precond_kind=sparse_precond_kind)
        sparse_jax_est_mb: float | None = None
        if sparse_enabled and sparse_kind_use == "jax" and int(op.total_size) <= int(sparse_max_size):
            precond_dtype = _precond_dtype(int(op.total_size))
            bytes_per = 4.0 if precond_dtype == jnp.float32 else 8.0
            sparse_jax_est_mb = (int(op.total_size) ** 2) * bytes_per / 1.0e6
        sparse_order = rhs1_resolved_sparse_rescue_ordering(
            sparse_enabled=bool(sparse_enabled),
            sparse_kind_use=sparse_kind_use,
            sparse_exact_direct=bool(sparse_exact_direct),
            size=int(op.total_size),
            sparse_max_size=int(sparse_max_size),
            large_cpu_sparse_rescue=bool(large_cpu_sparse_rescue_full),
            sparse_jax_est_mb=sparse_jax_est_mb,
            sparse_jax_max_mb=float(sparse_jax_max_mb),
            pas_fast_accept=bool(pas_fast_accept),
            gpu_sparse_skip=bool(
                _rhs1_gpu_sparse_fallback_skip_allowed(
                    op=op,
                    rhs1_precond_kind=rhs1_precond_kind,
                    use_active_dof_mode=False,
                    residual_norm=float(result.residual_norm),
                    target=float(target),
                )
            ),
        )
        sparse_enabled = bool(sparse_order.enabled)
        sparse_kind_use = str(sparse_order.kind_use)
        if sparse_order.reason_size_large_cpu:
            sparse_exact_lu = _rhsmode1_large_cpu_sparse_exact_lu_allowed(active_size=int(op.total_size))
            if emit is not None:
                emit(
                    0,
                    f"solve_v3_full_system_linear_gmres: large CPU sparse {'LU' if sparse_exact_lu else 'ILU'} rescue "
                    f"(size={int(op.total_size)} > max={int(sparse_max_size)})",
                )
        elif sparse_order.reason_size_exact_direct and emit is not None:
            emit(
                0,
                "solve_v3_full_system_linear_gmres: exact sparse LU rescue "
                f"(size={int(op.total_size)} > max={int(sparse_max_size)})",
            )
        elif sparse_order.reason_size_disabled and emit is not None:
            emit(1, f"sparse_ilu: disabled (size={int(op.total_size)} > max={int(sparse_max_size)})")
        if sparse_order.reason_sparse_jax_mem_disabled and sparse_jax_est_mb is not None and emit is not None:
            emit(
                1,
                "sparse_jax: disabled "
                f"(est_mem={sparse_jax_est_mb:.1f} MB > max_mb={sparse_jax_max_mb:.1f})",
            )

        dense_matrix_cache: np.ndarray | None = None
        host_sparse_direct_used = False
        if sparse_order.reason_pas_fast_accept and emit is not None:
            emit(
                1,
                "solve_v3_full_system_linear_gmres: PAS fast-accept "
                f"(residual={float(result.residual_norm):.3e}) -> skip sparse rescue tail",
            )
        if sparse_order.reason_gpu_sparse_skip and emit is not None:
            emit(
                1,
                "solve_v3_full_system_linear_gmres: GPU sparse fallback skipped after "
                f"{rhs1_precond_kind} accept (residual={float(result.residual_norm):.3e})",
            )
        if sparse_enabled and float(result.residual_norm) > target:
            if sparse_kind_use == "jax":
                try:
                    _mark("rhs1_sparse_precond_build_start")
                    cache_key = _rhsmode1_sparse_cache_key(
                        op,
                        kind="sparse_jax",
                        active_size=int(op.total_size),
                        use_active_dof_mode=False,
                        use_pas_projection=use_pas_projection,
                        drop_tol=sparse_drop_tol,
                        drop_rel=sparse_drop_rel,
                        ilu_drop_tol=sparse_ilu_drop_tol,
                        fill_factor=sparse_ilu_fill,
                    )
                    precond_dtype = _precond_dtype(int(op.total_size))
                    precond_sparse = _build_sparse_jax_preconditioner_from_matvec(
                        matvec=mv,
                        n=int(op.total_size),
                        dtype=precond_dtype,
                        cache_key=cache_key,
                        drop_tol=sparse_drop_tol,
                        drop_rel=sparse_drop_rel,
                        reg=sparse_jax_reg,
                        omega=sparse_jax_omega,
                        sweeps=sparse_jax_sweeps,
                        emit=emit,
                    )
                    _mark("rhs1_sparse_precond_build_done")
                    if emit is not None:
                        emit(
                            0,
                            "solve_v3_full_system_linear_gmres: sparse JAX Jacobi fallback "
                            f"(sweeps={int(sparse_jax_sweeps)} omega={float(sparse_jax_omega):.2f})",
                        )
                    sparse_retry_timer = Timer()
                    res_sparse, residual_vec_sparse = _solve_linear_with_residual(
                        matvec_fn=mv,
                        b_vec=rhs,
                        precond_fn=precond_sparse,
                        x0_vec=result.x,
                        tol_val=tol,
                        atol_val=atol,
                        restart_val=restart,
                        maxiter_val=maxiter,
                        solve_method_val="incremental",
                        precond_side=gmres_precond_side,
                    )
                    sparse_retry_elapsed_s = sparse_retry_timer.elapsed_s()
                    result, residual_vec, handoff_state, _accepted = rhs1_accept_candidate(
                        current_result=result,
                        candidate_result=res_sparse,
                        current_residual_vec=residual_vec,
                        candidate_residual_vec=residual_vec_sparse,
                        matvec_fn=mv,
                        b_vec=rhs,
                        precond_fn=precond_sparse,
                        x0_vec=res_sparse.x,
                        restart=restart,
                        maxiter=maxiter,
                        precond_side=gmres_precond_side,
                        solver_kind=_solver_kind("incremental")[0],
                        candidate_metrics=_rhs1_solver_candidate_metrics(
                            name="sparse_jax_full",
                            result=res_sparse,
                            target_value=target,
                            solve_s=sparse_retry_elapsed_s,
                        ),
                        baseline_metrics=_rhs1_solver_candidate_metrics(
                            name="current_full",
                            result=result,
                            target_value=target,
                        ),
                    )
                    _apply_rhs1_handoff(handoff_state)
                except Exception as exc:  # noqa: BLE001
                    if emit is not None:
                        emit(1, f"sparse_jax: failed ({type(exc).__name__}: {exc})")
            else:
                try:
                    _mark("rhs1_sparse_precond_build_start")
                    cache_key = _rhsmode1_sparse_cache_key(
                        op,
                        kind="sparse_lu" if sparse_exact_lu else "sparse_ilu",
                        active_size=int(op.total_size),
                        use_active_dof_mode=False,
                        use_pas_projection=use_pas_projection,
                        drop_tol=sparse_drop_tol,
                        drop_rel=sparse_drop_rel,
                        ilu_drop_tol=sparse_ilu_drop_tol,
                        fill_factor=sparse_ilu_fill,
                    )
                    host_sparse_direct_wanted = _rhsmode1_host_sparse_direct_allowed(
                        sparse_exact_lu=sparse_exact_lu,
                        use_implicit=bool(use_implicit),
                    )
                    if large_cpu_sparse_rescue_full and sparse_exact_lu:
                        host_sparse_direct_wanted = True
                    sparse_operator_preconditioned_rescue = _rhsmode1_sparse_operator_preconditioned_rescue_allowed(
                        op=op,
                        sparse_exact_lu=sparse_exact_lu,
                        host_sparse_direct_wanted=host_sparse_direct_wanted,
                    )
                    factor_dtype = _host_sparse_factor_dtype(
                        size=int(op.total_size),
                        factorization="lu" if sparse_exact_lu else "ilu",
                        use_implicit=bool(use_implicit),
                    ) if host_sparse_direct_wanted else np.dtype(np.float64)
                    sparse_factor_matvec = mv
                    if sparse_operator_preconditioned_rescue:
                        op_sparse_pc = _build_rhsmode1_preconditioner_operator_point(op)

                        def _mv_sparse_factor(v: jnp.ndarray, op_pc=op_sparse_pc) -> jnp.ndarray:
                            return apply_v3_full_system_operator_cached(op_pc, v)

                        sparse_factor_matvec = _mv_sparse_factor
                    cache_key_use = (
                        _sparse_factor_cache_key(cache_key, factor_dtype)
                        if host_sparse_direct_wanted
                        else cache_key
                    )
                    if sparse_operator_preconditioned_rescue:
                        cache_key_use = _sparse_factor_cache_key(
                            _rhsmode1_sparse_cache_key(
                                op,
                                kind="sparse_lu_pc_point",
                                active_size=int(active_size),
                                use_active_dof_mode=False,
                                use_pas_projection=use_pas_projection,
                                drop_tol=sparse_drop_tol,
                                drop_rel=sparse_drop_rel,
                                ilu_drop_tol=sparse_ilu_drop_tol,
                                fill_factor=sparse_ilu_fill,
                            ),
                            factor_dtype,
                        )
                    build_dense_factors = (
                        bool(use_implicit)
                        and (not host_sparse_direct_wanted)
                        and int(op.total_size) <= int(sparse_ilu_dense_max)
                    )
                    store_dense = int(op.total_size) <= int(sparse_dense_cache_max)
                    explicit_sparse_operator = None
                    explicit_sparse_factor = None
                    if host_sparse_direct_wanted and _rhsmode1_explicit_sparse_host_direct_allowed(
                        sparse_exact_lu=sparse_exact_lu,
                        use_implicit=bool(use_implicit),
                        active_size=int(op.total_size),
                    ):
                        explicit_sparse_pattern = _maybe_rhsmode1_full_sparse_pattern(op, emit=emit)
                        explicit_sparse_operator, explicit_sparse_factor = _build_host_sparse_direct_factor_from_matvec(
                            matvec=sparse_factor_matvec,
                            n=int(op.total_size),
                            dtype=rhs.dtype,
                            factor_dtype=factor_dtype,
                            pattern=explicit_sparse_pattern,
                            emit=emit,
                        )
                        a_csr_full = explicit_sparse_operator.matrix
                        _a_csr_drop = a_csr_full
                        ilu = explicit_sparse_factor.factor
                        a_dense_cache = None
                        l_dense = None
                        u_dense = None
                        l_unit_diag = False
                    else:
                        a_csr_full, _a_csr_drop, ilu, a_dense_cache, l_dense, u_dense, l_unit_diag = _build_sparse_ilu_from_matvec(
                            matvec=sparse_factor_matvec,
                            n=int(op.total_size),
                            dtype=rhs.dtype,
                            cache_key=cache_key_use,
                            factor_dtype=factor_dtype,
                            drop_tol=sparse_drop_tol,
                            drop_rel=sparse_drop_rel,
                            ilu_drop_tol=sparse_ilu_drop_tol,
                            fill_factor=sparse_ilu_fill,
                            build_dense_factors=build_dense_factors,
                            build_jax_factors=bool(use_implicit) and (not host_sparse_direct_wanted),
                            build_ilu=True,
                            store_dense=store_dense,
                            factorization="lu" if sparse_exact_lu else "ilu",
                            emit=emit,
                        )
                    dense_matrix_cache = a_dense_cache
                    _mark("rhs1_sparse_precond_build_done")
                    host_sparse_direct = host_sparse_direct_wanted
                    sparse_retry_timer = Timer()

                    if host_sparse_direct and ilu is not None:
                        if sparse_operator_preconditioned_rescue:
                            def _precond_sparse(v: jnp.ndarray) -> jnp.ndarray:
                                x_np = np.asarray(v, dtype=np.float64).reshape((-1,))
                                y_np = ilu.solve(x_np)
                                return jnp.asarray(y_np, dtype=jnp.float64)

                            sparse_pc_restart, sparse_pc_maxiter = rhs1_parse_polish_gmres_config(
                                restart_env_name="SFINCS_JAX_RHSMODE1_SPARSE_PC_GMRES_RESTART",
                                maxiter_env_name="SFINCS_JAX_RHSMODE1_SPARSE_PC_GMRES_MAXITER",
                                default_restart=max(120, int(restart)),
                                default_maxiter=max(800, int(maxiter or 400) * 2),
                            )
                            if emit is not None:
                                emit(
                                    0,
                                    "solve_v3_full_system_linear_gmres: sparse LU operator-preconditioned "
                                    f"GMRES fallback restart={int(sparse_pc_restart)} maxiter={int(sparse_pc_maxiter)}",
                                )
                            x_np, rn_sparse, _history = gmres_solve_with_history_scipy(
                                matvec=mv,
                                b=rhs,
                                preconditioner=_precond_sparse,
                                x0=result.x,
                                tol=tol,
                                atol=atol,
                                restart=sparse_pc_restart,
                                maxiter=sparse_pc_maxiter,
                                precondition_side=gmres_precond_side,
                            )
                            res_sparse = GMRESSolveResult(
                                x=jnp.asarray(x_np, dtype=jnp.float64),
                                residual_norm=jnp.asarray(rn_sparse, dtype=jnp.float64),
                            )
                            residual_vec_sparse = rhs - mv(res_sparse.x)
                            _mv_sparse = mv
                        else:
                            host_sparse_direct_used = True
                            if emit is not None:
                                emit(
                                    0,
                                    "solve_v3_full_system_linear_gmres: host sparse LU direct fallback "
                                    f"on backend={jax.default_backend()}",
                                )
                            if explicit_sparse_factor is not None and explicit_sparse_operator is not None:
                                x_np, residual_norm_sparse = _host_direct_solve_with_refinement(
                                    factor_solve=explicit_sparse_factor.solve,
                                    operator_matrix=explicit_sparse_operator.matrix,
                                    rhs_vec=rhs,
                                    factor_dtype=factor_dtype,
                                    refine_steps=_host_sparse_direct_refine_steps(
                                        "SFINCS_JAX_RHSMODE1_SPARSE_DIRECT_REFINE",
                                        default=2,
                                    ),
                                )
                            else:
                                x_np, residual_norm_sparse = _host_sparse_direct_solve_with_refinement(
                                    ilu=ilu,
                                    a_csr_full=a_csr_full,
                                    rhs_vec=rhs,
                                    factor_dtype=factor_dtype,
                                    refine_steps=_host_sparse_direct_refine_steps(
                                        "SFINCS_JAX_RHSMODE1_SPARSE_DIRECT_REFINE",
                                        default=2,
                                    ),
                                )
                            res_sparse = GMRESSolveResult(
                                x=jnp.asarray(x_np, dtype=jnp.float64),
                                residual_norm=jnp.asarray(residual_norm_sparse, dtype=jnp.float64),
                            )
                            if factor_dtype == np.dtype(np.float32) and float(res_sparse.residual_norm) > float(target):
                                if rhs1_polish_enabled(env_name="SFINCS_JAX_RHSMODE1_SPARSE_DIRECT_POLISH"):
                                    polish_restart, polish_maxiter = rhs1_parse_polish_gmres_config(
                                        restart_env_name="SFINCS_JAX_RHSMODE1_SPARSE_DIRECT_POLISH_RESTART",
                                        maxiter_env_name="SFINCS_JAX_RHSMODE1_SPARSE_DIRECT_POLISH_MAXITER",
                                        default_restart=min(int(restart), 40),
                                        default_maxiter=min(max(40, int(maxiter or 120)), 120),
                                    )
                                    if emit is not None:
                                        emit(
                                            0,
                                            "solve_v3_full_system_linear_gmres: host sparse direct polish "
                                            f"restart={polish_restart} maxiter={polish_maxiter}",
                                        )
                                    x_polish, residual_norm_polish = _host_sparse_direct_polish(
                                        matvec_fn=mv,
                                        rhs_vec=rhs,
                                        x0_np=x_np,
                                        ilu=ilu,
                                        factor_dtype=factor_dtype,
                                        tol=tol,
                                        atol=atol,
                                        restart=polish_restart,
                                        maxiter=polish_maxiter,
                                        precondition_side=gmres_precond_side,
                                    )
                                    if np.isfinite(residual_norm_polish) and residual_norm_polish < float(res_sparse.residual_norm):
                                        res_sparse = GMRESSolveResult(
                                            x=jnp.asarray(x_polish, dtype=jnp.float64),
                                            residual_norm=jnp.asarray(residual_norm_polish, dtype=jnp.float64),
                                        )
                            residual_vec_sparse = rhs - mv(res_sparse.x)
                            _mv_sparse = mv
                            _precond_sparse = None
                    elif use_implicit:
                        ilu_cache = _RHSMODE1_SPARSE_ILU_CACHE.get(cache_key)
                        perm_r = None if ilu_cache is None else ilu_cache.perm_r
                        inv_perm_c = None if ilu_cache is None else ilu_cache.inv_perm_c
                        lower_idx = None if ilu_cache is None else ilu_cache.lower_idx
                        lower_val = None if ilu_cache is None else ilu_cache.lower_val
                        upper_idx = None if ilu_cache is None else ilu_cache.upper_idx
                        upper_val = None if ilu_cache is None else ilu_cache.upper_val
                        upper_diag = None if ilu_cache is None else ilu_cache.upper_diag

                        precond_sparse = None
                        if (
                            l_dense is not None
                            and u_dense is not None
                            and perm_r is not None
                            and inv_perm_c is not None
                        ):
                            import jax.scipy.linalg as jla  # noqa: PLC0415

                            l_jnp = jnp.asarray(l_dense, dtype=jnp.float64)
                            u_jnp = jnp.asarray(u_dense, dtype=jnp.float64)

                            def _precond_sparse(v: jnp.ndarray) -> jnp.ndarray:
                                v = jnp.asarray(v, dtype=jnp.float64)
                                v_perm = v[perm_r]
                                y = jla.solve_triangular(l_jnp, v_perm, lower=True, unit_diagonal=l_unit_diag)
                                z = jla.solve_triangular(u_jnp, y, lower=False)
                                return z[inv_perm_c]

                            precond_sparse = _precond_sparse
                        elif (
                            perm_r is not None
                            and inv_perm_c is not None
                            and lower_idx is not None
                            and lower_val is not None
                            and upper_idx is not None
                            and upper_val is not None
                            and upper_diag is not None
                        ):
                            def _precond_sparse(v: jnp.ndarray) -> jnp.ndarray:
                                v = jnp.asarray(v, dtype=jnp.float64)
                                v_perm = v[perm_r]
                                y = _triangular_solve_lower_padded(
                                    lower_idx=lower_idx,
                                    lower_val=lower_val,
                                    b=v_perm,
                                )
                                z = _triangular_solve_upper_padded(
                                    upper_idx=upper_idx,
                                    upper_val=upper_val,
                                    upper_diag=upper_diag,
                                    b=y,
                                )
                                return z[inv_perm_c]

                            precond_sparse = _precond_sparse

                        if precond_sparse is None:
                            if emit is not None:
                                emit(
                                    1,
                                    f"{'sparse_lu' if sparse_exact_lu else 'sparse_ilu'}: "
                                    "implicit preconditioner factors unavailable; skipping",
                                )
                            res_sparse = None
                            residual_vec_sparse = None
                        else:
                            if emit is not None:
                                emit(
                                    0,
                                    "solve_v3_full_system_linear_gmres: "
                                    f"{'sparse LU' if sparse_exact_lu else 'sparse ILU'} (implicit) fallback",
                                )
                            res_sparse, residual_vec_sparse = _solve_linear_with_residual(
                                matvec_fn=mv,
                                b_vec=rhs,
                                precond_fn=precond_sparse,
                                x0_vec=result.x,
                                tol_val=tol,
                                atol_val=atol,
                                restart_val=restart,
                                maxiter_val=maxiter,
                                solve_method_val="incremental",
                                precond_side=gmres_precond_side,
                            )
                    else:
                        if ilu is None:
                            raise RuntimeError("sparse_ilu: ILU factors unavailable")

                        def _precond_sparse(v: jnp.ndarray) -> jnp.ndarray:
                            x_np = np.asarray(v, dtype=np.float64).reshape((-1,))
                            y_np = ilu.solve(x_np)
                            return jnp.asarray(y_np, dtype=jnp.float64)

                        if sparse_use_matvec:
                            def _mv_sparse(v: jnp.ndarray) -> jnp.ndarray:
                                x_np = np.asarray(v, dtype=np.float64).reshape((-1,))
                                y_np = a_csr_full @ x_np
                                return jnp.asarray(y_np, dtype=jnp.float64)
                        else:
                            _mv_sparse = mv

                        if emit is not None:
                            emit(
                                0,
                                "solve_v3_full_system_linear_gmres: "
                                f"{'sparse LU' if sparse_exact_lu else 'sparse ILU'} GMRES fallback",
                            )
                        x_np, rn_sparse, _history = gmres_solve_with_history_scipy(
                            matvec=_mv_sparse,
                            b=rhs,
                            preconditioner=_precond_sparse,
                            x0=result.x,
                            tol=tol,
                            atol=atol,
                            restart=restart,
                            maxiter=maxiter,
                            precondition_side=gmres_precond_side,
                        )
                        res_sparse = GMRESSolveResult(
                            x=jnp.asarray(x_np, dtype=jnp.float64),
                            residual_norm=jnp.asarray(rn_sparse, dtype=jnp.float64),
                        )
                        residual_vec_sparse = rhs - _mv_sparse(res_sparse.x)
                    if res_sparse is not None:
                        sparse_retry_elapsed_s = sparse_retry_timer.elapsed_s()
                        result, residual_vec, handoff_state, _accepted = rhs1_accept_candidate(
                            current_result=result,
                            candidate_result=res_sparse,
                            current_residual_vec=residual_vec,
                            candidate_residual_vec=residual_vec_sparse,
                            matvec_fn=mv if use_implicit else _mv_sparse,
                            b_vec=rhs,
                            precond_fn=_precond_sparse,
                            x0_vec=res_sparse.x,
                            restart=restart,
                            maxiter=maxiter,
                            precond_side=gmres_precond_side,
                            solver_kind=_solver_kind("incremental")[0],
                            candidate_metrics=_rhs1_solver_candidate_metrics(
                                name="sparse_full",
                                result=res_sparse,
                                target_value=target,
                                solve_s=sparse_retry_elapsed_s,
                            ),
                            baseline_metrics=_rhs1_solver_candidate_metrics(
                                name="current_full",
                                result=result,
                                target_value=target,
                            ),
                        )
                        _apply_rhs1_handoff(handoff_state)
                except Exception as exc:  # noqa: BLE001
                    if emit is not None:
                        emit(
                            1,
                            f"{'sparse_lu' if sparse_exact_lu else 'sparse_ilu'}: "
                            f"failed ({type(exc).__name__}: {exc})",
                        )
        residual_norm_check = float(result.residual_norm)
        residual_norm_true = residual_norm_check
        if ksp_precond is not None and ksp_precond_side == "left":
            try:
                if residual_vec is None:
                    residual_vec = rhs - mv(result.x)
                residual_norm_true = float(jnp.linalg.norm(residual_vec))
                if not np.isfinite(residual_norm_true):
                    residual_norm_true = float("inf")
                r_pc = ksp_precond(residual_vec)
                r_pc_norm = float(jnp.linalg.norm(r_pc))
                if np.isfinite(r_pc_norm):
                    residual_norm_check = r_pc_norm
            except Exception:
                pass
        dense_fallback_max = _rhsmode1_dense_fallback_max(op)
        dense_backend_allowed = _rhsmode1_dense_backend_allowed()
        host_dense_fallback_allowed = _rhsmode1_host_dense_fallback_allowed()
        dense_krylov_allowed = _rhsmode1_dense_krylov_allowed()
        if (not dense_backend_allowed) and (not host_dense_fallback_allowed) and (not dense_krylov_allowed):
            dense_fallback_max = 0
        dense_fallback_ratio_env = os.environ.get("SFINCS_JAX_RHSMODE1_DENSE_FALLBACK_RATIO", "").strip()
        try:
            dense_fallback_ratio = float(dense_fallback_ratio_env) if dense_fallback_ratio_env else 1.0e2
        except ValueError:
            dense_fallback_ratio = 1.0e2
        res_ratio = float(residual_norm_true) / max(float(target), 1e-300)
        dense_fallback_trigger = bool(res_ratio > dense_fallback_ratio) if dense_fallback_ratio > 0 else True
        if host_sparse_direct_used and jax.default_backend() != "cpu":
            host_sparse_skip_ratio = _rhsmode1_host_sparse_skip_dense_ratio()
            if host_sparse_skip_ratio > 0.0 and res_ratio <= float(host_sparse_skip_ratio):
                dense_fallback_trigger = False
                dense_fallback_max = 0
                if emit is not None:
                    emit(
                        0,
                        "solve_v3_full_system_linear_gmres: skipping dense fallback after host sparse LU "
                        f"(ratio={res_ratio:.3e} <= {float(host_sparse_skip_ratio):.1e})",
                    )
        fp_force_dense = (
            op.fblock.fp is not None
            and dense_fallback_max > 0
            and int(active_size) <= dense_fallback_max
            and float(residual_norm_true) > target
        )
        if fp_force_dense:
            dense_fallback_trigger = True
        force_dense_cs0 = bool(int(op.constraint_scheme) == 0 and (not cs0_sparse_first))
        if force_dense_cs0:
            dense_fallback_trigger = True
        if (
            dense_fallback_max > 0
            and int(op.rhs_mode) == 1
            and (not bool(op.include_phi1))
            and int(op.total_size) <= dense_fallback_max
            and dense_fallback_trigger
            and float(residual_norm_true) > target
        ):
            _mark("rhs1_dense_fallback_start")
            if emit is not None:
                emit(
                    0,
                    "solve_v3_full_system_linear_gmres: dense fallback "
                    f"(size={int(op.total_size)} residual={float(residual_norm_check):.3e} > target={target:.3e})",
                )
            try:
                dense_retry_timer = Timer()
                use_row_scaled = int(op.constraint_scheme) == 0
                if dense_backend_allowed:
                    dense_method = "dense_row_scaled" if use_row_scaled else "dense"
                    res_dense, residual_vec_dense = _solve_linear_with_residual(
                        matvec_fn=mv,
                        b_vec=rhs,
                        precond_fn=None,
                        x0_vec=None,
                        tol_val=tol,
                        atol_val=atol,
                        restart_val=restart,
                        maxiter_val=maxiter,
                        solve_method_val=dense_method,
                        precond_side="none",
                    )
                else:
                    if emit is not None and jax.default_backend() != "cpu":
                        emit(
                            0,
                            "solve_v3_full_system_linear_gmres: dense fallback using explicit dense Krylov "
                            f"on backend={jax.default_backend()}",
                        )
                    if dense_matrix_cache is not None:
                        a_dense = jnp.asarray(dense_matrix_cache, dtype=rhs.dtype)
                    else:
                        a_dense = assemble_dense_matrix_from_matvec(
                            matvec=mv, n=int(op.total_size), dtype=rhs.dtype
                        )
                    res_dense, residual_vec_dense = dense_krylov_solve_from_matrix_with_residual(
                        a=a_dense,
                        b=rhs,
                        x0=result.x,
                        preconditioner=None,
                        tol=tol,
                        atol=atol,
                        restart=restart,
                        maxiter=maxiter,
                        solve_method="incremental",
                        precondition_side="none",
                        row_scaled=use_row_scaled,
                    )
                dense_retry_elapsed_s = dense_retry_timer.elapsed_s()
                result, residual_vec, handoff_state, _accepted = rhs1_accept_candidate(
                    current_result=result,
                    candidate_result=res_dense,
                    current_residual_vec=residual_vec,
                    candidate_residual_vec=residual_vec_dense,
                    matvec_fn=mv,
                    b_vec=rhs,
                    precond_fn=None,
                    x0_vec=res_dense.x,
                    restart=restart,
                    maxiter=maxiter,
                    precond_side="none",
                    solver_kind="dense",
                    candidate_metrics=_rhs1_solver_candidate_metrics(
                        name="dense_full",
                        result=res_dense,
                        target_value=target,
                        solve_s=dense_retry_elapsed_s,
                    ),
                    baseline_metrics=_rhs1_solver_candidate_metrics(
                        name="current_full",
                        result=result,
                        target_value=target,
                    ),
                )
                _apply_rhs1_handoff(handoff_state)
            except Exception as exc:  # noqa: BLE001
                if emit is not None:
                    emit(1, f"solve_v3_full_system_linear_gmres: dense fallback failed ({type(exc).__name__}: {exc})")
            _mark("rhs1_dense_fallback_done")
    if int(op.rhs_mode) == 1:
        project_env = os.environ.get("SFINCS_JAX_RHSMODE1_PROJECT_NULLSPACE", "").strip().lower()
        if project_env in {"0", "false", "no", "off"}:
            project_rhs1 = False
        elif project_env in {"1", "true", "yes", "on"}:
            project_rhs1 = True
        else:
            # Default parity-first behavior: enforce constraintScheme=1 nullspace projection
            # for linear RHSMode=1 solves without Phi1.
            project_rhs1 = bool(int(op.constraint_scheme) == 1 and (not bool(op.include_phi1)))
        if project_rhs1:
            x_projected, residual_projected = _project_constraint_scheme1_nullspace_solution_with_residual(
                op=op,
                x_vec=result.x,
                rhs_vec=rhs,
                matvec_op=op,
                enabled_env_var="SFINCS_JAX_RHSMODE1_PROJECT_NULLSPACE",
                residual_vec=residual_vec if residual_vec is not None and residual_vec.shape == rhs.shape else None,
            )
            if not bool(jnp.allclose(x_projected, result.x)):
                residual_norm_projected = jnp.linalg.norm(residual_projected)
                result = GMRESSolveResult(x=x_projected, residual_norm=residual_norm_projected)
        if int(op.constraint_scheme) == 2 and int(op.extra_size) > 0:
            zero_env = os.environ.get("SFINCS_JAX_PAS_SOURCE_ZERO_TOL", "").strip()
            try:
                zero_tol = float(zero_env) if zero_env else 2e-9
            except ValueError:
                zero_tol = 2e-9
            if zero_tol > 0.0:
                extra = result.x[-int(op.extra_size) :]
                max_abs = jnp.max(jnp.abs(extra))
                extra = jnp.where(max_abs <= zero_tol, jnp.zeros_like(extra), extra)
                x_new = jnp.concatenate([result.x[: -int(op.extra_size)], extra], axis=0)
                result = GMRESSolveResult(x=x_new, residual_norm=result.residual_norm)
    if ksp_matvec is not None and ksp_b is not None:
        ksp_history = _emit_ksp_history(
            matvec_fn=ksp_matvec,
            b_vec=ksp_b,
            precond_fn=ksp_precond,
            x0_vec=ksp_x0,
            tol_val=tol,
            atol_val=atol,
            restart_val=int(ksp_restart),
            maxiter_val=ksp_maxiter,
            precond_side=ksp_precond_side,
            solver_kind=ksp_solver_kind,
            solve_method_val=str(solve_method),
        )
        _emit_ksp_iter_stats(
            matvec_fn=ksp_matvec,
            b_vec=ksp_b,
            precond_fn=ksp_precond,
            x0_vec=ksp_x0,
            tol_val=float(tol),
            atol_val=float(atol),
            restart_val=int(ksp_restart),
            maxiter_val=ksp_maxiter,
            precond_side=ksp_precond_side,
            solver_kind=ksp_solver_kind,
            history=ksp_history,
            solve_method_val=str(solve_method),
        )
    if emit is not None:
        emit(0, f"solve_v3_full_system_linear_gmres: residual_norm={float(result.residual_norm):.6e}")
        emit(1, f"solve_v3_full_system_linear_gmres: elapsed_s={t.elapsed_s():.3f}")
    return V3LinearSolveResult(op=op, rhs=rhs, gmres=result)


solve_v3_full_system_linear_gmres_jit = jax.jit(
    solve_v3_full_system_linear_gmres,
    static_argnames=("tol", "atol", "restart", "maxiter", "solve_method", "identity_shift"),
)


@jtu.register_pytree_node_class
@dataclass(frozen=True)
class V3NewtonKrylovResult:
    """Result of a simple Newton–Krylov solve for `residual_v3_full_system` (experimental)."""

    op: V3FullSystemOperator
    x: jnp.ndarray
    residual_norm: jnp.ndarray
    n_newton: int
    last_linear_residual_norm: jnp.ndarray

    def tree_flatten(self):
        children = (self.op, self.x, self.residual_norm, self.last_linear_residual_norm)
        aux = int(self.n_newton)
        return children, aux

    @classmethod
    def tree_unflatten(cls, aux, children):
        op, x, residual_norm, last_linear_residual_norm = children
        return cls(op=op, x=x, residual_norm=residual_norm, n_newton=int(aux), last_linear_residual_norm=last_linear_residual_norm)


def solve_v3_full_system_newton_krylov(
    *,
    nml: Namelist,
    x0: jnp.ndarray | None = None,
    tol: float = 1e-10,
    max_newton: int = 12,
    gmres_tol: float = 1e-10,
    gmres_restart: int = 80,
    gmres_maxiter: int | None = 400,
    solve_method: str = "batched",
    identity_shift: float = 0.0,
) -> V3NewtonKrylovResult:
    """Solve `residual_v3_full_system(op, x) = 0` using a basic Newton–Krylov iteration.

    This is intended for small parity fixtures and developer experimentation. It is **not**
    yet a stable API for production runs.
    """
    op = full_system_operator_from_namelist(nml=nml, identity_shift=identity_shift)
    _set_precond_size_hint(int(op.total_size))
    _set_precond_policy_hints(
        has_pas=getattr(op.fblock, "pas", None) is not None,
        has_fp=getattr(op.fblock, "fp", None) is not None,
        include_phi1=bool(op.include_phi1),
        rhs_mode=int(op.rhs_mode),
    )
    if x0 is None:
        x = jnp.zeros((op.total_size,), dtype=jnp.float64)
    else:
        x = jnp.asarray(x0, dtype=jnp.float64)
        if x.shape != (op.total_size,):
            raise ValueError(f"x0 must have shape {(op.total_size,)}, got {x.shape}")

    last_linear_resid = jnp.asarray(jnp.inf, dtype=jnp.float64)

    for k in range(int(max_newton)):
        # Compute residual and a *single* linearization for this Newton step that can be reused
        # by GMRES. This avoids applying JAX's autodiff transform inside every matvec call,
        # which is a major performance bottleneck for includePhi1 solves.
        r, jvp = jax.linearize(lambda xx: residual_v3_full_system(op, xx), x)
        rnorm = jnp.linalg.norm(r)
        if float(rnorm) < float(tol):
            return V3NewtonKrylovResult(
                op=op,
                x=x,
                residual_norm=rnorm,
                n_newton=k,
                last_linear_residual_norm=last_linear_resid,
            )

        # Solve J s = -r
        lin = _gmres_solve_dispatch(
            matvec=jvp,
            b=-r,
            tol=float(gmres_tol),
            restart=int(gmres_restart),
            maxiter=gmres_maxiter,
            solve_method=str(solve_method),
        )
        s = lin.x
        last_linear_resid = lin.residual_norm

        # Backtracking line search on ||r|| (very simple Armijo-style criterion).
        step = 1.0
        step_scale_env = os.environ.get("SFINCS_JAX_PHI1_STEP_SCALE", "").strip()
        try:
            step_scale = float(step_scale_env) if step_scale_env else 1.0
        except ValueError:
            step_scale = 1.0
        rnorm0 = float(rnorm)
        for _ in range(12):
            x_try = x + (step * step_scale) * s
            r_try = residual_v3_full_system(op, x_try)
            rnorm_try = float(jnp.linalg.norm(r_try))
            if rnorm_try <= 0.9 * rnorm0:
                x = x_try
                break
            step *= 0.5
        else:
            # If we fail to reduce the residual, still take a small step to avoid stalling.
            x = x + (1.0 / 64.0) * s

    r = residual_v3_full_system(op, x)
    return V3NewtonKrylovResult(
        op=op,
        x=x,
        residual_norm=jnp.linalg.norm(r),
        n_newton=int(max_newton),
        last_linear_residual_norm=last_linear_resid,
    )


def solve_v3_full_system_newton_krylov_history(
    *,
    nml: Namelist,
    x0: jnp.ndarray | None = None,
    tol: float = 1e-10,
    max_newton: int = 12,
    gmres_tol: float = 1e-10,
    gmres_restart: int = 80,
    gmres_maxiter: int | None = 400,
    solve_method: str = "batched",
    identity_shift: float = 0.0,
    nonlinear_rtol: float = 0.0,
    use_frozen_linearization: bool = False,
    emit: Callable[[int, str], None] | None = None,
) -> tuple[V3NewtonKrylovResult, list[jnp.ndarray]]:
    """Newton–Krylov solve that also returns the per-iteration accepted states.

    The returned history matches v3's convention of saving diagnostics for iteration numbers
    starting at 1, i.e. it includes the sequence of *accepted* Newton iterates and excludes
    the initial guess `x0`.

    Optionally, this routine can use a v3-parity-oriented solve path with a frozen
    (`whichMatrix=1`-like) linearization and relative residual stopping
    (`||F|| <= nonlinear_rtol * ||F_0||`) in addition to absolute `tol`.
    """
    op = full_system_operator_from_namelist(nml=nml, identity_shift=identity_shift)
    if emit is not None:
        emit(1, f"solve_v3_full_system_newton_krylov_history: total_size={int(op.total_size)}")
    fortran_stdout_env = os.environ.get("SFINCS_JAX_FORTRAN_STDOUT", "").strip().lower()
    if fortran_stdout_env in {"0", "false", "no", "off"}:
        fortran_stdout = False
    elif fortran_stdout_env in {"1", "true", "yes", "on"}:
        fortran_stdout = True
    else:
        fortran_stdout = emit is not None
    env_gmres_tol = os.environ.get("SFINCS_JAX_PHI1_GMRES_TOL", "").strip()
    if env_gmres_tol:
        gmres_tol = float(env_gmres_tol)

    if x0 is None:
        x = jnp.zeros((op.total_size,), dtype=jnp.float64)
    else:
        x = jnp.asarray(x0, dtype=jnp.float64)
        if x.shape != (op.total_size,):
            raise ValueError(f"x0 must have shape {(op.total_size,)}, got {x.shape}")

    active_env = os.environ.get("SFINCS_JAX_PHI1_ACTIVE_DOF", "").strip().lower()
    nxi_for_x = np.asarray(op.fblock.collisionless.n_xi_for_x, dtype=np.int32)
    has_reduced_modes = bool(np.any(nxi_for_x < int(op.n_xi)))
    use_active_dof_mode = phi1_use_active_dof_mode(
        rhs_mode=int(op.rhs_mode),
        include_phi1=bool(op.include_phi1),
        has_reduced_modes=has_reduced_modes,
        env_value=active_env,
    )

    active_idx_jnp: jnp.ndarray | None = None
    full_to_active_jnp: jnp.ndarray | None = None
    active_size = int(op.total_size)
    if use_active_dof_mode:
        active_idx_np = _transport_active_dof_indices(op)
        active_idx_jnp = jnp.asarray(active_idx_np, dtype=jnp.int32)
        full_to_active_np = np.zeros((int(op.total_size),), dtype=np.int32)
        full_to_active_np[np.asarray(active_idx_np, dtype=np.int32)] = np.arange(
            1, int(active_idx_np.shape[0]) + 1, dtype=np.int32
        )
        full_to_active_jnp = jnp.asarray(full_to_active_np, dtype=jnp.int32)
        active_size = int(active_idx_np.shape[0])
        if emit is not None:
            emit(
                1,
                "solve_v3_full_system_newton_krylov_history: active-DOF mode enabled "
                f"(size={active_size}/{int(op.total_size)})",
            )
    gmres_restart_use = phi1_gmres_restart(active_size=active_size, gmres_restart=int(gmres_restart))

    def _reduce_full(v_full: jnp.ndarray) -> jnp.ndarray:
        assert active_idx_jnp is not None
        return v_full[active_idx_jnp]

    def _expand_reduced(v_reduced: jnp.ndarray) -> jnp.ndarray:
        assert full_to_active_jnp is not None
        z0 = jnp.zeros((1,), dtype=v_reduced.dtype)
        padded = jnp.concatenate([z0, v_reduced], axis=0)
        return padded[full_to_active_jnp]

    preconditioner = None
    # Only enable block preconditioning in the PETSc-like parity mode that freezes the
    # Jacobian/linearization. For autodiff-linearized Newton steps, JAX's GMRES can
    # behave differently with an approximate preconditioner, which impacts iteration
    # histories and `sfincsOutput.h5` shape parity for linear Phi1 fixtures.
    pc_env = os.environ.get("SFINCS_JAX_PHI1_USE_PRECONDITIONER", "").strip().lower()
    use_preconditioner = pc_env not in {"0", "false", "no", "off"}
    dense_cutoff_env = os.environ.get("SFINCS_JAX_PHI1_NK_DENSE_CUTOFF", "").strip()
    try:
        dense_cutoff = int(dense_cutoff_env) if dense_cutoff_env else 5000
    except ValueError:
        dense_cutoff = 5000
    linear_size = active_size if use_active_dof_mode else int(op.total_size)
    solve_method_in = str(solve_method).strip().lower()
    use_sparse_direct_linear = solve_method_in == "sparse_direct"
    use_dense_linear = solve_method_in in {"dense", "dense_row_scaled"} or (
        use_frozen_linearization and int(linear_size) <= int(dense_cutoff)
    )
    if use_dense_linear or use_sparse_direct_linear:
        use_preconditioner = False
    preconditioner = build_phi1_newton_preconditioner(
        use_preconditioner=bool(use_preconditioner),
        use_frozen_linearization=bool(use_frozen_linearization),
        rhs_mode=int(op.rhs_mode),
        include_phi1=bool(op.include_phi1),
        use_active_dof_mode=bool(use_active_dof_mode),
        op=op,
        reduce_full=_reduce_full if use_active_dof_mode else None,
        expand_reduced=_expand_reduced if use_active_dof_mode else None,
        preconditioner_options=nml.group("preconditionerOptions"),
        collision_builder=_build_rhsmode1_collision_preconditioner,
        block_builder=_build_rhsmode1_block_preconditioner,
        emit=emit,
    )

    last_linear_resid = jnp.asarray(jnp.inf, dtype=jnp.float64)
    accepted: list[jnp.ndarray] = []
    rnorm_initial: float | None = None
    cached_jvp = None
    cached_jvp_iter = -1
    frozen_jac_policy = phi1_frozen_jacobian_policy(include_phi1=bool(op.include_phi1))
    use_frozen_jac_cache = bool(frozen_jac_policy.use_cache)
    frozen_jac_every = int(frozen_jac_policy.every)
    ksp_history_max_env = os.environ.get("SFINCS_JAX_KSP_HISTORY_MAX_SIZE", "").strip().lower()
    if ksp_history_max_env in {"none", "inf", "infinite", "unlimited"}:
        ksp_history_max_size = None
    else:
        try:
            ksp_history_max_size = int(ksp_history_max_env) if ksp_history_max_env else 800
        except ValueError:
            ksp_history_max_size = 800
    ksp_history_max_iter_env = os.environ.get("SFINCS_JAX_KSP_HISTORY_MAX_ITER", "").strip()
    try:
        ksp_history_max_iter = int(ksp_history_max_iter_env) if ksp_history_max_iter_env else 2000
    except ValueError:
        ksp_history_max_iter = 2000

    def _emit_ksp_history_nk(
        *,
        matvec_fn,
        b_vec: jnp.ndarray,
        precond_fn,
        x0_vec: jnp.ndarray | None,
        tol_val: float,
        atol_val: float,
        restart_val: int,
        maxiter_val: int | None,
        precond_side: str,
    ) -> None:
        if emit is None or not fortran_stdout:
            return
        size = int(b_vec.size)
        if ksp_history_max_size is not None and size > int(ksp_history_max_size):
            emit(1, f"fortran-stdout: KSP history skipped (size={size} > max={int(ksp_history_max_size)})")
            return
        if maxiter_val is not None and ksp_history_max_iter is not None:
            est_iters = int(maxiter_val) * max(1, int(restart_val))
            if est_iters > int(ksp_history_max_iter):
                emit(
                    1,
                    "fortran-stdout: KSP history skipped "
                    f"(estimated_iters={est_iters} > max={int(ksp_history_max_iter)})",
                )
                return
        try:
            _x_hist, _rn, history = gmres_solve_with_history_scipy(
                matvec=matvec_fn,
                b=b_vec,
                preconditioner=precond_fn,
                x0=x0_vec,
                tol=tol_val,
                atol=atol_val,
                restart=restart_val,
                maxiter=maxiter_val,
                precondition_side=precond_side,
            )
        except Exception as exc:  # noqa: BLE001
            emit(1, f"fortran-stdout: KSP history unavailable ({type(exc).__name__}: {exc})")
            return
        for k_hist, rn in enumerate(history):
            emit(0, f"{k_hist:4d} KSP Residual norm {rn: .12e} ")
        if history:
            emit(0, " Linear iteration (KSP) converged.  KSPConvergedReason =            2")
            emit(0, "   KSP_CONVERGED_RTOL: Norm decreased by rtol.")

    def _phi1_sparse_direct_solve(
        *,
        matvec_fn,
        b_vec: jnp.ndarray,
        n: int,
        cache_tag: tuple[object, ...],
        tol_val: float,
        atol_val: float,
        restart_val: int,
        maxiter_val: int | None,
    ) -> GMRESSolveResult:
        factor_dtype = _transport_sparse_factor_dtype(size=int(n), use_implicit=False)
        cache_key_use = _sparse_factor_cache_key(("phi1_nk_sparse_direct", *cache_tag), factor_dtype)
        a_csr_full, _a_csr_drop, ilu, _a_dense, _l_dense, _u_dense, _l_unit = _build_sparse_ilu_from_matvec(
            matvec=matvec_fn,
            n=int(n),
            dtype=jnp.float64,
            cache_key=cache_key_use,
            factor_dtype=factor_dtype,
            drop_tol=0.0,
            drop_rel=0.0,
            ilu_drop_tol=0.0,
            fill_factor=1.0,
            build_dense_factors=False,
            build_jax_factors=False,
            build_ilu=True,
            store_dense=False,
            factorization="lu",
            emit=emit,
        )
        if ilu is None:
            raise RuntimeError("phi1 sparse_direct: factors unavailable")
        x_np, residual_norm = _host_sparse_direct_solve_with_refinement(
            ilu=ilu,
            a_csr_full=a_csr_full,
            rhs_vec=b_vec,
            factor_dtype=factor_dtype,
            refine_steps=_host_sparse_direct_refine_steps("SFINCS_JAX_PHI1_SPARSE_DIRECT_REFINE", default=2),
        )
        target_true = max(float(atol_val), float(tol_val) * float(jnp.linalg.norm(b_vec)))
        if factor_dtype == np.dtype(np.float32) and residual_norm > target_true:
            polish_env = os.environ.get("SFINCS_JAX_PHI1_SPARSE_DIRECT_POLISH", "").strip().lower()
            if polish_env not in {"0", "false", "no", "off"}:
                polish_restart_env = os.environ.get("SFINCS_JAX_PHI1_SPARSE_DIRECT_POLISH_RESTART", "").strip()
                polish_maxiter_env = os.environ.get("SFINCS_JAX_PHI1_SPARSE_DIRECT_POLISH_MAXITER", "").strip()
                try:
                    polish_restart = int(polish_restart_env) if polish_restart_env else min(int(restart_val), 40)
                except ValueError:
                    polish_restart = min(int(restart_val), 40)
                try:
                    polish_maxiter = (
                        int(polish_maxiter_env)
                        if polish_maxiter_env
                        else min(max(40, int(maxiter_val or 120)), 120)
                    )
                except ValueError:
                    polish_maxiter = min(max(40, int(maxiter_val or 120)), 120)
                x_polish, residual_norm_polish = _host_sparse_direct_polish(
                    matvec_fn=matvec_fn,
                    rhs_vec=b_vec,
                    x0_np=x_np,
                    ilu=ilu,
                    factor_dtype=factor_dtype,
                    tol=tol_val,
                    atol=atol_val,
                    restart=max(5, int(polish_restart)),
                    maxiter=max(5, int(polish_maxiter)),
                    precondition_side="left",
                )
                if np.isfinite(residual_norm_polish) and residual_norm_polish < residual_norm:
                    x_np = x_polish
                    residual_norm = residual_norm_polish
        return GMRESSolveResult(
            x=jnp.asarray(x_np, dtype=jnp.float64),
            residual_norm=jnp.asarray(residual_norm, dtype=jnp.float64),
        )

    for k in range(int(max_newton)):
        if emit is not None:
            emit(1, f"newton_iter={k}: evaluateResidual called")
        op_use = op
        if bool(op.include_phi1):
            phi1_flat = x[op.f_size : op.f_size + op.n_theta * op.n_zeta]
            phi1 = phi1_flat.reshape((op.n_theta, op.n_zeta))
            op_use = replace(op, phi1_hat_base=phi1)

        r = apply_v3_full_system_operator_cached(op_use, x, include_jacobian_terms=False) - rhs_v3_full_system_jit(op_use)
        rnorm = jnp.linalg.norm(r)
        rnorm_f = float(rnorm)
        if rnorm_initial is None:
            rnorm_initial = max(rnorm_f, 1e-300)
        if emit is not None:
            emit(0, f"newton_iter={k}: residual_norm={rnorm_f:.6e}")
        if emit is not None and fortran_stdout:
            emit(0, f"{k:4d} SNES Function norm {rnorm_f: .12e} ")
        if not np.isfinite(rnorm_f):
            # Keep the latest finite iterate. This mirrors PETSc's behavior of
            # stopping when the nonlinear residual becomes invalid instead of
            # continuing with NaN/Inf states.
            x_return = accepted[-1] if accepted else x
            r_return = residual_v3_full_system(op, x_return)
            return (
                V3NewtonKrylovResult(
                    op=op,
                    x=x_return,
                    residual_norm=jnp.linalg.norm(r_return),
                    n_newton=k,
                    last_linear_residual_norm=last_linear_resid,
                ),
                accepted,
            )

        converged_abs = rnorm_f < float(tol)
        converged_rel = rnorm_f <= float(nonlinear_rtol) * float(rnorm_initial)
        if converged_abs or converged_rel:
            if not accepted:
                accepted.append(x)
            return (
                V3NewtonKrylovResult(
                    op=op,
                    x=x,
                    residual_norm=rnorm,
                    n_newton=k,
                    last_linear_residual_norm=last_linear_resid,
                ),
                accepted,
            )

        frozen_jac_mode = None
        if use_frozen_linearization:
            jac_mode = frozen_jac_policy.mode
            frozen_jac_mode = jac_mode

            if jac_mode == "frozen_rhs":
                # Keep the kinetic/collision operator frozen at the current iterate (op_use),
                # but let the RHS keep its explicit Phi1 dependence. This is closer to v3's
                # nonlinear Jacobian path for includePhi1 while retaining robust parity behavior.
                def residual_for_jac(xx: jnp.ndarray) -> jnp.ndarray:
                    if bool(op.include_phi1):
                        phi1_flat_x = xx[op.f_size : op.f_size + op.n_theta * op.n_zeta]
                        phi1_x = phi1_flat_x.reshape((op.n_theta, op.n_zeta))
                        op_rhs_x = replace(op, phi1_hat_base=phi1_x)
                    else:
                        op_rhs_x = op
                    return (
                        apply_v3_full_system_operator_cached(op_use, xx, include_jacobian_terms=True)
                        - rhs_v3_full_system_jit(op_rhs_x)
                    )

                reuse_cached = (
                    use_frozen_jac_cache
                    and cached_jvp is not None
                    and (k - cached_jvp_iter) < frozen_jac_every
                )
                if reuse_cached:
                    matvec = cached_jvp
                    if emit is not None:
                        emit(1, f"newton_iter={k}: evaluateJacobian reused (frozen_rhs cache)")
                else:
                    _r_lin, jvp = jax.linearize(residual_for_jac, x)
                    matvec = jvp
                    if use_frozen_jac_cache:
                        cached_jvp = jvp
                        cached_jvp_iter = k
                    if emit is not None:
                        emit(1, f"newton_iter={k}: evaluateJacobian called (frozen operator + dynamic RHS)")
            elif jac_mode == "frozen_op":
                # Keep RHS frozen at the current iterate, but let the operator
                # carry the Phi1 dependence. This emulates partial Jacobian updates
                # in upstream SNES paths.
                def residual_for_jac(xx: jnp.ndarray) -> jnp.ndarray:
                    if bool(op.include_phi1):
                        phi1_flat_x = xx[op.f_size : op.f_size + op.n_theta * op.n_zeta]
                        phi1_x = phi1_flat_x.reshape((op.n_theta, op.n_zeta))
                        op_mat_x = replace(op, phi1_hat_base=phi1_x)
                    else:
                        op_mat_x = op
                    return (
                        apply_v3_full_system_operator_cached(op_mat_x, xx, include_jacobian_terms=True)
                        - rhs_v3_full_system_jit(op_use)
                    )

                _r_lin, jvp = jax.linearize(residual_for_jac, x)
                matvec = jvp
                if emit is not None:
                    emit(1, f"newton_iter={k}: evaluateJacobian called (dynamic operator + frozen RHS)")
            else:
                matvec = lambda dx: apply_v3_full_system_jacobian_jit(op_use, x, dx)
                if emit is not None:
                    emit(1, f"newton_iter={k}: evaluateJacobian called (fully frozen linearization)")
        else:
            # Optional exact mode for debugging/experimentation.
            _r_lin, jvp = jax.linearize(lambda xx: residual_v3_full_system(op, xx), x)
            matvec = jvp
            if emit is not None:
                emit(1, f"newton_iter={k}: evaluateJacobian called (autodiff linearization)")

        solve_method_linear = str(solve_method)
        if use_frozen_linearization:
            if int(linear_size) <= int(dense_cutoff):
                solve_method_linear = "dense"

        lin, s, linear_resid_norm = solve_phi1_newton_linear_step(
            use_active_dof_mode=bool(use_active_dof_mode),
            solve_method_linear=solve_method_linear,
            matvec=matvec,
            residual_vec=r,
            preconditioner=preconditioner,
            gmres_tol=float(gmres_tol),
            gmres_restart=int(gmres_restart_use),
            gmres_maxiter=gmres_maxiter,
            sparse_direct_solve=_phi1_sparse_direct_solve,
            gmres_dispatch=_gmres_solve_dispatch,
            gmres_result_is_finite=_gmres_result_is_finite,
            emit_ksp_history=_emit_ksp_history_nk,
            emit=emit,
            newton_iter=int(k),
            reduce_full=_reduce_full if use_active_dof_mode else None,
            expand_reduced=_expand_reduced if use_active_dof_mode else None,
            active_size=int(active_size),
            total_size=int(op.total_size),
        )

        if emit is not None:
            emit(1, f"newton_iter={k}: gmres_residual={float(linear_resid_norm):.6e}")
        if not _gmres_result_is_finite(lin):
            x_return = accepted[-1] if accepted else x
            r_return = residual_v3_full_system(op, x_return)
            return (
                V3NewtonKrylovResult(
                    op=op,
                    x=x_return,
                    residual_norm=jnp.linalg.norm(r_return),
                    n_newton=k,
                    last_linear_residual_norm=last_linear_resid,
                ),
                accepted,
            )
        last_linear_resid = linear_resid_norm

        rnorm0 = float(rnorm)
        ls_policy = phi1_line_search_policy(
            use_frozen_linearization=bool(use_frozen_linearization),
            include_phi1=bool(op.include_phi1),
        )
        x = advance_phi1_newton_iterate(
            x=x,
            step_direction=s,
            residual_norm0=rnorm0,
            residual_fn=lambda x_try: residual_v3_full_system(op, x_try),
            accepted=accepted,
            mode=str(ls_policy.mode),
            step_scale=float(ls_policy.step_scale),
            factor=ls_policy.factor,
            c1=float(ls_policy.c1),
            maxiter=int(ls_policy.maxiter),
        )
        accepted.append(x)

    r = residual_v3_full_system(op, x)
    return (
        V3NewtonKrylovResult(
            op=op,
            x=x,
            residual_norm=jnp.linalg.norm(r),
            n_newton=int(max_newton),
            last_linear_residual_norm=last_linear_resid,
        ),
        accepted,
    )


@dataclass(frozen=True)
class V3TransportMatrixSolveResult:
    """Result of assembling a RHSMode=2/3 transport matrix by looping `whichRHS` solves."""

    op0: V3FullSystemOperator
    transport_matrix: jnp.ndarray  # (N,N) in mathematical (row, col) order
    state_vectors_by_rhs: dict[int, jnp.ndarray]
    residual_norms_by_rhs: dict[int, jnp.ndarray]
    # Diagnostics in the same normalized units as v3 `diagnostics.F90`.
    # Arrays are returned in mathematical axis order: (species, whichRHS).
    fsab_flow: jnp.ndarray  # (S, N)
    particle_flux_vm_psi_hat: jnp.ndarray  # (S, N)
    heat_flux_vm_psi_hat: jnp.ndarray  # (S, N)
    elapsed_time_s: jnp.ndarray  # (N,)
    transport_output_fields: dict[str, np.ndarray] | None = None
    rhs_norms_by_rhs: dict[int, jnp.ndarray] | None = None
    active_size: int | None = None
    use_active_dof_mode: bool | None = None
    solver_kinds_by_rhs: dict[int, str] | None = None
    solve_methods_by_rhs: dict[int, str] | None = None


def _rewrite_xla_flags(flags: str, *, cpu_threads: int | None, host_devices: int | None) -> str:
    parts = []
    for token in flags.split():
        if token.startswith("--xla_cpu_parallelism_threads="):
            continue
        if token.startswith("--xla_cpu_multi_thread_eigen_num_threads="):
            continue
        if token.startswith("--xla_cpu_multi_thread_eigen="):
            continue
        if token.startswith("--xla_force_host_platform_device_count="):
            continue
        parts.append(token)
    if cpu_threads is not None:
        parts.append("--xla_cpu_multi_thread_eigen=true")
        parts.append(f"--xla_cpu_multi_thread_eigen_num_threads={int(cpu_threads)}")
    if host_devices is not None:
        parts.append(f"--xla_force_host_platform_device_count={int(host_devices)}")
    return " ".join(parts).strip()


@contextlib.contextmanager
def _transport_parallel_worker_env(parallel_workers: int):
    with _transport_parallel_worker_env_impl(
        parallel_workers=int(parallel_workers),
        rewrite_xla_flags=_rewrite_xla_flags,
    ):
        yield


def _transport_parallel_worker(payload: dict[str, object]) -> dict[str, object]:
    """Worker entry point for parallel whichRHS transport solves."""
    input_path = Path(str(payload["input_path"]))
    which_rhs_values = [int(v) for v in payload["which_rhs_values"]]  # type: ignore[assignment]
    tol = float(payload.get("tol", 1e-10))
    atol = float(payload.get("atol", 0.0))
    restart = int(payload.get("restart", 80))
    maxiter = payload.get("maxiter")
    solve_method = str(payload.get("solve_method", "auto"))
    identity_shift = float(payload.get("identity_shift", 0.0))
    collect_transport_output_fields = bool(payload.get("collect_transport_output_fields", True))
    differentiable_payload = payload.get("differentiable", None)
    if differentiable_payload is not None:
        differentiable_payload = bool(differentiable_payload)
    phi1_hat_base = payload.get("phi1_hat_base")
    if phi1_hat_base is not None:
        phi1_hat_base = jnp.asarray(phi1_hat_base, dtype=jnp.float64)

    # Prevent recursive parallelism inside workers.
    os.environ["SFINCS_JAX_TRANSPORT_PARALLEL"] = "off"
    os.environ["SFINCS_JAX_TRANSPORT_PARALLEL_CHILD"] = "1"

    nml = read_sfincs_input(input_path)
    result = solve_v3_transport_matrix_linear_gmres(
        nml=nml,
        tol=tol,
        atol=atol,
        restart=restart,
        maxiter=maxiter,
        solve_method=solve_method,
        identity_shift=identity_shift,
        phi1_hat_base=phi1_hat_base,
        differentiable=differentiable_payload,
        input_namelist=input_path,
        which_rhs_values=which_rhs_values,
        force_stream_diagnostics=True,
        force_store_state=True,
        collect_transport_output_fields=False,
        parallel_workers=1,
    )
    return {
        "which_rhs_values": which_rhs_values,
        "state_vectors_by_rhs": {int(k): np.asarray(v) for k, v in result.state_vectors_by_rhs.items()},
        "residual_norms_by_rhs": {int(k): float(np.asarray(v)) for k, v in result.residual_norms_by_rhs.items()},
        "rhs_norms_by_rhs": {
            int(k): float(np.asarray(v))
            for k, v in (getattr(result, "rhs_norms_by_rhs", None) or {}).items()
        },
        "elapsed_time_s": np.asarray(result.elapsed_time_s, dtype=np.float64),
    }


